<script>

/* --- Chèn đoạn này vào cuối phần Script --- */

// Hàm xử lý vị trí tooltip thông minh (Smart Tooltip Positioning)
function initSmartTooltips() {
    // 1. Chọn tất cả các ô có chứa tooltip (trong code của bạn là .roll-item)
    const containers = document.querySelectorAll('.roll-item');

    containers.forEach(container => {
        container.addEventListener('mouseenter', () => {
            // 2. Tìm tooltip con bên trong ô đó (Dùng đúng class .tooltip-content)
            const tooltip = container.querySelector('.tooltip-content');
            if (!tooltip) return;

            // 3. Reset về vị trí chuẩn trước khi tính toán
            tooltip.style.transform = 'translateX(-50%)';
            tooltip.style.left = '50%';

            // 4. Lấy thông số vị trí thực tế
            const rect = tooltip.getBoundingClientRect();
            const viewportWidth = window.innerWidth;
            const padding = 10; // Khoảng cách an toàn so với mép màn hình

            // 5. Kiểm tra tràn bên PHẢI
            if (rect.right > viewportWidth - padding) {
                const overflow = rect.right - (viewportWidth - padding);
                // Dịch sang trái để không bị mất nội dung
                tooltip.style.transform = `translateX(calc(-50% - ${overflow}px))`;
            }

            // 6. Kiểm tra tràn bên TRÁI
            if (rect.left < padding) {
                const overflow = padding - rect.left;
                // Dịch sang phải
                tooltip.style.transform = `translateX(calc(-50% + ${overflow}px))`;
            }
        });
    });
}

