// [NEW] Hàm lấy màu dựa trên tên
function getRankColor(text) {
    if (!text) return "";
    // Kiểm tra xem text có chứa tên rank nào không
    for (const [rank, color] of Object.entries(rankColorMap)) {
        if (text.includes(rank)) return color;
    }
    return ""; // Không màu nếu không phải Giai
}

// [NEW] Hàm tô màu cho thẻ Select đã có sẵn (Hardcoded HTML)
function colorizeExistingSelects() {
    const ids = ['tamer-rank', 'pet-rank', 'beast-self-rank', 'master-rank'];
    ids.forEach(id => {
        const sel = document.getElementById(id);
        if (!sel) return;
        Array.from(sel.options).forEach(opt => {
            const color = getRankColor(opt.text);
            if (color) {
                opt.style.color = color;
                opt.style.fontWeight = "bold";
            }
        });
    });
}

