function updateBirthdayStr() {
    // Lấy giá trị từ các ô nhập liệu, nếu trống thì gán mặc định
    let age = parseInt(document.getElementById('char-age').value) || 16;
    let day = parseInt(document.getElementById('char-birth-day').value) || 1;
    let month = parseInt(document.getElementById('char-birth-month').value) || 1;

    // Mốc thời gian của thế giới
    const currentYear = 30001; 

    // Tính năm sinh
    let birthYear = currentYear - age;

    // Gán kết quả vào ô char-birthday (để hàm generateStartCommand lấy dữ liệu)
    document.getElementById('char-birthday').value = `Ngày ${day} tháng ${month} năm ${birthYear}`;
