// HÀM TỰ ĐỘNG NỐI HIỆU ỨNG VÀ TIÊU HAO VÀO MÔ TẢ THIÊN PHÚ
function injectEffectsIntoTalentDesc() {
    // Kiểm tra xem mảng dataTalents có tồn tại không
    if (typeof dataTalents === 'undefined' || !Array.isArray(dataTalents)) return;

    dataTalents.forEach(talent => {
        let descField = talent.desc ? 'desc' : (talent.description ? 'description' : null);

        if (descField) {
            let addText = "";

            // 1. Chèn Hiệu ứng Kích hoạt (nếu có)
            if (talent.active_effect && !talent[descField].includes("Hiệu ứng Kích hoạt")) {
                addText += `\n\n[Hiệu ứng Kích hoạt] ${talent.active_effect}`;
            }

            // 2. Chèn Hiệu ứng Bị động (nếu có, đề phòng các thiên phú khác có biến này)
            if (talent.passive_effect && !talent[descField].includes("Hiệu ứng Bị động")) {
                addText += `\n\n[Hiệu ứng Bị động] ${talent.passive_effect}`;
            }

            // 3. Chèn Tiêu hao (Cost)
            if (talent.cost && typeof talent.cost === 'object' && !talent[descField].includes("Cái giá phải trả")) {
                let costType = talent.cost.type || "Năng lượng";
                let costVal = talent.cost.value || 0;
                addText += `\n\n[Cái giá phải trả] Tiêu hao ${costVal} điểm ${costType}.`;
            }

            // Gộp toàn bộ vào mô tả gốc
            talent[descField] += addText;
        }
    });
}

// HÀM TỰ ĐỘNG NỐI KỸ NĂNG & ĐẶC ĐIỂM VÀO MÔ TẢ CHỦNG TỘC (ĐÃ FIX TÊN BIẾN)
function injectSkillsIntoRaceDesc() {
    if (typeof listBaseRaces === 'undefined' || !Array.isArray(listBaseRaces)) return;

    listBaseRaces.forEach(race => {
        // Đã đổi sang đúng tên biến trong data của bạn
        let skills = race.default_skills; 
        let features = race.features;

        let descField = race.desc ? 'desc' : (race.description ? 'description' : null);

        if (descField && !race[descField].includes("KỸ NĂNG CHỦNG TỘC")) {
            let addText = "";

            // Nối Kỹ năng chủng tộc
            if (skills && Array.isArray(skills) && skills.length > 0) {
                addText += "\n\n[KỸ NĂNG CHỦNG TỘC]:";
                skills.forEach(skill => {
                    let sName = skill.name || "Kỹ năng ẩn";
                    let sDesc = skill.desc || "Chưa có mô tả.";
                    addText += ` [${sName}]: ${sDesc}`;
                });
            }

            // Nối Đặc điểm sinh học (Features)
            if (features && Array.isArray(features) && features.length > 0) {
                addText += "\n\n[ĐẶC ĐIỂM SINH HỌC]:\n✦ " + features.join(" | ");
            }

            // Ép thẳng vào mô tả gốc
            race[descField] += addText;
        }
    });
}

function getElementClass(elementName) {
    if (!elementName) return { text: '', border: '' };
    const name = elementName.toLowerCase().split('(')[0].trim();

    // Nhận diện linh hoạt Hỏa/Lửa, Thủy/Nước...
    if (name.includes('hỏa') || name.includes('lửa')) return { text: 'text-fire', border: 'border-fire' };
    if (name.includes('thủy') || name.includes('nước')) return { text: 'text-water', border: 'border-water' };
    if (name.includes('băng')) return { text: 'text-ice', border: 'border-ice' };
    if (name.includes('tinh thần')) return { text: 'text-spirit', border: 'border-spirit' };
    if (name.includes('lôi')) return { text: 'text-lightning', border: 'border-lightning' };
    if (name.includes('phong')) return { text: 'text-wind', border: 'border-wind' };
    if (name.includes('thổ')) return { text: 'text-earth', border: 'border-earth' };
    if (name.includes('mộc')) return { text: 'text-wood', border: 'border-wood' };
    if (name.includes('kim')) return { text: 'text-metal', border: 'border-metal' };
    if (name.includes('độc')) return { text: 'text-poison', border: 'border-poison' };
    if (name.includes('nham thạch')) return { text: 'text-magma', border: 'border-magma' };
    if (name.includes('quang') || name.includes('ánh sáng') || name.includes('sáng tạo')) return { text: 'text-light', border: 'border-light' };
    if (name.includes('ám') || name.includes('bóng tối') || name.includes('hủy diệt')) return { text: 'text-dark', border: 'border-dark' };
    if (name.includes('cường hóa')) return { text: 'text-enhance', border: 'border-enhance' };
    if (name.includes('thời không')) return { text: 'text-time', border: 'border-time' };
    if (name.includes('khái niệm')) return { text: 'text-concept', border: 'border-concept' };

    return { text: '', border: '' };
}

