function getSmartDescription(selectedElements) {
    if (!selectedElements || selectedElements.length === 0) return "Chưa định hình năng lượng.";

    // 1. Lấy danh sách tên hệ sạch (xóa khoảng trắng)
    let names = selectedElements.map(s => s.name.trim());

    // 2. Kiểm tra trường hợp đặc biệt: TOÀN CHỨC (14 hệ trở lên)
    if (names.length >= 14 || names.some(n => n.includes("HỖN ĐỘN"))) {
        return dataSynergy["ALL_ELEMENTS"] || "Trạng thái khởi nguyên tối thượng.";
    }

    // 3. Nếu chỉ có 1 hệ: Trả về mô tả gốc của hệ đó
    if (names.length === 1) {
        const singleName = names[0];
        const info = dataElementsInfo.find(e => e.name === singleName);
        return info ? info.desc : "Sức mạnh nguyên tố cơ bản.";
    }

    // 4. Nếu có nhiều hệ: Sắp xếp theo bảng chữ cái để tra cứu Key Synergy
    let sortedNames = [...names].sort(); 
    let key = sortedNames.join('|');

    // Tra cứu trong kho dữ liệu thủ công
    if (dataSynergy[key]) {
        return dataSynergy[key];
    }

    // 5. Nếu không tìm thấy combo thủ công -> Sinh mô tả tự động dựa trên thành phần
    let baseDesc = `Sự cộng hưởng giữa ${names.length} dòng năng lượng (${names.join(' & ')}): `;
    let effects = [];
    if (key.includes("Lửa") || key.includes("Hỏa")) effects.push("nhiệt năng thiêu đốt");
    if (key.includes("Băng") || key.includes("Nước")) effects.push("hàn khí đóng băng");
    if (key.includes("Lôi")) effects.push("xung điện tê liệt");
    if (key.includes("Phong")) effects.push("áp suất cắt xẻ");
    if (key.includes("Độc")) effects.push("ăn mòn sinh học");
    if (key.includes("Tối") || key.includes("Hủy Diệt")) effects.push("tử khí xâm thực");
    if (key.includes("Quang") || key.includes("Sáng Tạo")) effects.push("quang năng tịnh hóa");
    if (key.includes("Thổ") || key.includes("Kim")) effects.push("vật chất kiên cố");

    return baseDesc + "Tạo ra một trường năng lượng hỗn hợp mang đặc tính " + (effects.join(', ') || "biến hóa") + ". Các nguyên tố bổ trợ lẫn nhau, triệt tiêu điểm yếu của từng hệ riêng lẻ.";
}

