        { name: "Ma Sát Tụ Hỏa", desc: "[Cơ chế] Tích lũy điện tích tĩnh hỏa qua mỗi bước chạy. [Hiệu ứng] Càng di chuyển nhiều không dừng lại, đòn đánh cận chiến đầu tiên (khi chạm trán) sẽ được cộng thêm Sát thương Hỏa bạo kích lên tới 50%.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Vật Lý"], range_type: "Bản thân (Bị động cộng dồn)", combo_tag: "Passive_Friction_Fire" },
        { name: "Trái Tim Lò Luyện", desc: "[Cơ chế] Cơ tâm nhĩ co bóp tạo nhiệt lượng thanh tẩy tủy sống. [Hiệu ứng] Miễn nhiễm tuyệt đối với các hiệu ứng khống chế Tê Cóng, Đóng Băng Dưới Chân của hệ Băng. Kẻ địch dùng hệ Băng không thể làm chậm tốc độ.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Bị động kháng Băng)", combo_tag: "Passive_Furnace_Heart" },
        { name: "Hỏa Thể Khinh Linh", desc: "[Cơ chế] Khí nóng bốc lên cao tự động đẩy nhẹ cơ thể. [Hiệu ứng] Trọng lượng cơ thể giảm đi 15%. Gia tăng khoảng cách bật nhảy và thời gian lơ lửng trên không trung, hỗ trợ cực tốt cho các đòn tập kích từ trên cao.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Phong"], range_type: "Bản thân (Bị động khinh công)", combo_tag: "Passive_Thermal_Lift" },
        { name: "Tia Lửa Phản Chấn", desc: "[Cơ chế] Lớp vảy tự động phóng tia lửa khi có va chạm lực mạnh. [Hiệu ứng] Khi Đỡ đòn (Block/Parry) thành công đòn đánh cận chiến, một chùm tia lửa sẽ bắn vào mắt địch, gây hiệu ứng Mù Lòa chớp nhoáng (0.5s) phá vỡ chuỗi combo của chúng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 2, unit: "Giây", display_text: "2 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Cận chiến (Bị động phản đòn)", combo_tag: "Passive_Spark_Parry" },
        { name: "Ánh Sáng Tàn Lửa", desc: "[Cơ chế] Ký sinh mầm lửa sinh học siêu nhỏ lên bề mặt da địch. [Hiệu ứng] Kẻ địch đang chịu trạng thái [Bỏng] sẽ phát ra ánh sáng lập lòe trong bóng tối, không thể tàng hình (Hệ Ám) hay trốn vào sương mù được nữa.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Quang"], range_type: "Mục tiêu (Bị động đánh dấu)", combo_tag: "Passive_Burn_Glow" },
        { name: "Hội Tụ Hỏa Lực", desc: "[Cơ chế] Nén ma lực hệ Hỏa vào tâm đan điền khi nhịp thở bình ổn. [Hiệu ứng] Nếu đứng yên không di chuyển trong 3 giây, đòn tấn công vật lý/kỹ năng kế tiếp sẽ được xuyên thấu 15% Phòng thủ (DEF) của mục tiêu.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Bị động xuyên giáp)", combo_tag: "Passive_Focus_Fire" },
        { name: "Viêm Trảo Xung Kích", desc: "[Cơ chế] Bọc móng vuốt/bàn tay bằng lửa ma sát. [Hiệu ứng] Cào một đường lửa rực sáng, phá vỡ thế phòng thủ của kẻ địch và đánh bật vũ khí của chúng nếu trúng tay. Sát thương vật lý lai Hỏa.", rank: "Phàm Giai", cost: { type: "Stamina", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Vật Lý"], range_type: "Cận Chiến", combo_tag: "Fire_Claw" },
        { name: "Hỏa Tinh Kích Nổ", desc: "[Cơ chế] Ném một tia lửa nhỏ không đáng chú ý lên áo giáp địch. [Hiệu ứng] Tia lửa bám chặt và phát nổ sau 3 giây, tạo lực xung kích hất văng địch ra khỏi vị trí và gây gián đoạn kỹ năng đang niệm.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tầm Trung (Đánh dấu nổ)", combo_tag: "Spark_Detonate" },
        { name: "Lá Chắn Bộc Hỏa", desc: "[Cơ chế] Dựng khiên lửa ngắn hạn ngay trước mặt khi nhận sát thương. [Hiệu ứng] Chặn 1 đòn tấn công vật lý vừa phải. Lập tức phản lại sát thương Hỏa vào kẻ tấn công ở cự ly gần làm mù mắt tạm thời 1s.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Phản đòn)", combo_tag: "Blast_Shield" },
        { name: "Hỏa Nhẫn Cắt Lướt", desc: "[Cơ chế] Vuốt ngọn lửa thành hình bán nguyệt sắc bén. [Hiệu ứng] Chém ra một sóng lửa bay ngang mặt đất. Cắt đứt chân quái vật nhỏ hoặc gân chân của lính canh, làm chậm di chuyển của chúng 30%.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "AoE Hình Cung Nhỏ", combo_tag: "Fire_Wave" },
        { name: "Mưa Lửa Thu Nhỏ", desc: "[Cơ chế] Phun mồi lửa lên không trung để phân tách thành chùm mảnh vụn lửa. [Hiệu ứng] Rơi xuống như mưa đạn shotgun. Gây sát thương lan nhỏ cho một nhóm địch (bán kính 3m), ép chúng phải tản ra phá đội hình.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "AoE Nhỏ", combo_tag: "Fire_Rain_Mini" },
        { name: "Viêm Cước Bạo Phá", desc: "[Cơ chế] Dồn nén năng lượng nổ ở gót chân. [Hiệu ứng] Tung cú đá thẳng mặt đối thủ kèm theo vụ nổ hỏa thuật. Đạp bay đối thủ nặng ký ra xa 5m, gây chấn động sọ não (Choáng 0.5s).", rank: "Thiết Giai", cost: { type: "Stamina", value: 45 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Vật Lý"], range_type: "Cận Chiến (Hất văng)", combo_tag: "Explosive_Kick" },
        { name: "Roi Lửa Càn Quét", desc: "[Cơ chế] Kéo dài ngọn lửa thành một sợi roi linh hoạt dính chặt. [Hiệu ứng] Quất roi vào mục tiêu, gây sát thương rát da và có thể quấn lấy chân kẻ địch giật ngã chúng xuống đất lập tức.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tầm Trung (Roi)", combo_tag: "Fire_Whip_Trip" },
        { name: "Hỏa Cầu Đuổi Bắt", desc: "[Cơ chế] Tạo hỏa cầu liên kết với thân nhiệt kẻ địch. [Hiệu ứng] Bắn một hỏa cầu tự động đổi hướng bám theo kẻ thù đang né tránh. Sát thương không cao nhưng chắc chắn trúng 100% gây Bỏng.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tầm Xa (Khóa mục tiêu)", combo_tag: "Homing_Fire" },
        { name: "Viêm Khí Trùng Kích", desc: "[Cơ chế] Phóng xuất sóng nhiệt xung kích từ lồng ngực. [Hiệu ứng] Thổi luồng khí nóng bỏng ra xung quanh bán kính 2m. Đẩy lùi vũ khí đâm tới và làm kẻ địch bị sặc khói ho rũ rượi, ngắt nhịp tấn công.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Khí"], range_type: "Xung quanh bản thân", combo_tag: "Heat_Pulse" },
        { name: "Hỏa Vực Hãm Trận", desc: "[Cơ chế] Dậm chân truyền ngọn lửa lan theo khe nứt trên mặt đất. [Hiệu ứng] Tạo một vùng đất cháy xém bán kính 4m. Bất kỳ ai bước vào đều bị thiêu đốt chân, giảm 20% Tốc độ di chuyển và liên tục trừ máu.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "AoE Nhỏ (Lĩnh vực)", combo_tag: "Fire_Ground" },
        { name: "Đạn Hỏa Huyết", desc: "[Cơ chế] Dùng chính giọt máu của bản thân làm chất dẫn nổ hỏa thuật. [Hiệu ứng] Bắn đạn máu rực lửa tốn ít MP nhưng tiêu hao sinh lực. Đạn gây sát thương cực kỳ sắc bén, xuyên thấu cả khiên năng lượng cơ bản.", rank: "Phàm Giai", cost: { type: "HP", value: 15 }, cooldown: { value: 3, unit: "Giây", display_text: "3 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Blood_Fireball" },
        { name: "Móng Vuốt Than Hồng", desc: "[Cơ chế] Làm móng vuốt đỏ rực như sắt nung lò. [Hiệu ứng] Sát thương cào xước không lở loét mà làm cháy xém tức thì, phá hủy dây thần kinh ngoại biên khiến chi bị cào tê liệt trong 3 giây.", rank: "Phàm Giai", cost: { type: "Stamina", value: 15 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Vật Lý"], range_type: "Cận Chiến", combo_tag: "Ember_Claw" },
        { name: "Hỏa Pháo Liên Phấn", desc: "[Cơ chế] Nén áp suất khí quản để bắn ba quả hỏa cầu nhỏ liên tiếp. [Hiệu ứng] Bắn dồn dập 3 viên đạn lửa phá vỡ phòng ngự giáp giật lùi. Hiệu quả tuyệt vời để ép góc kẻ địch phải lùi bước sát tường.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tầm Trung (Liên xạ)", combo_tag: "Fire_Barrage" },
        { name: "Tro Tàn Dẫn Nổ", desc: "[Cơ chế] Phun mây tro bụi dễ bắt lửa (Cấu trúc tương tự nổ bụi bột mì). [Hiệu ứng] Ném tro vào mặt địch gây che khuất. Nếu kẻ địch sử dụng kỹ năng ma sát hoặc Hỏa, hạt tro sẽ kích nổ văng ngược vào mắt chúng.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tầm Xa (Bẫy nổ)", combo_tag: "Ash_Detonator" },
        { name: "Chớp Lửa Tập Kích", desc: "[Cơ chế] Bùng nổ hỏa năng dưới gót giày để lao vọt đi. [Hiệu ứng] Lướt (Dash) về phía trước 5m bằng tốc độ tên lửa, đâm sầm vào đối thủ gây sát thương bạo kích và tiếp nối combo cận chiến dễ dàng.", rank: "Phàm Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Vật Lý"], range_type: "Cận Chiến (Lao tới)", combo_tag: "Flame_Charge" },
        { name: "Hỏa Lưu Tinh Trĩ", desc: "[Cơ chế] Ném một hòn đá được nung chảy với quỹ đạo vòng cung. [Hiệu ứng] Đá nung đỏ rơi từ góc chết (từ trên cao vòng xuống) vượt qua khiên chắn thẳng đứng của Tamer. Gây sát thương nặng nề nát mũ giáp.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Thổ"], range_type: "Tầm Xa (Góc khuất)", combo_tag: "Meteor_Toss" },
        { name: "Khí Nóng Ngạt Thở", desc: "[Cơ chế] Đốt cháy không khí tĩnh xung quanh mũi kẻ thù. [Hiệu ứng] Loại bỏ hoàn toàn oxy trong bán kính 1m quanh đầu đối thủ. Làm chúng nghẹn thở, choáng váng và gián đoạn mọi niệm chú phép thuật (Silence tức thời).", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Tầm Trung (Ngắt chiêu)", combo_tag: "Choke_Heat" },
        { name: "Tường Viêm Rút Ngắn", desc: "[Cơ chế] Kéo một vệt lửa mỏng ngăn cách không gian. [Hiệu ứng] Dựng hàng rào lửa mỏng dài 3m. Không cản được vật lý nhưng thiêu rụi đạn gỗ, độc sương mù và chặn tầm nhìn ngắm bắn của cung thủ địch.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tường Chắn Nhỏ", combo_tag: "Mini_Firewall" },
        { name: "Hỏa Thuẫn Giao Tranh", desc: "[Cơ chế] Bọc lửa quanh cẳng tay hoặc vũ khí để đỡ đòn. [Hiệu ứng] Giảm 30% sát thương từ cú chém của địch, đồng thời nhiệt độ nung đỏ vũ khí kẻ tấn công khiến chúng phải vứt bỏ vũ khí vì quá nóng.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Cận Chiến (Đỡ đòn)", combo_tag: "Fire_Parry" },
        { name: "Hỏa Cầu Bạo Phá", desc: "[Cơ chế] Nén ma lực hệ hỏa thành khối cầu mật độ cao. [Hiệu ứng] Khi chạm mục tiêu sẽ phát nổ, gây sát thương diện rộng bán kính 2m. Để lại trạng thái [Bỏng Cấp 1] thiêu đốt 1% Max HP mỗi giây trong 1 phút. [Tương tác] Bay chậm hơn trong sương mù.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "AoE Nhỏ (Tầm Xa)", combo_tag: "Burn_Activator" },
        { name: "Viêm Giáp Phản Đòn", desc: "[Cơ chế] Tạo một lớp màng lửa định hình sát bề mặt da. [Hiệu ứng] Tăng 30% DEF vật lý. Tự động kích nổ, phản lại 50% sát thương Hỏa lên bất kỳ kẻ nào tấn công cận chiến (khoảng cách < 1m). [Tác dụng phụ] Không thể che giấu thân nhiệt khỏi thiết bị dò tìm.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Buff/Phòng thủ)", combo_tag: "Fire_Shield" },
        { name: "Phun Lửa Áp Suất", desc: "[Cơ chế] Nén lửa trong khoang miệng/tay và phóng ra dưới dạng tia (Beam). [Hiệu ứng] Cột lửa tập trung như đèn khò với nhiệt độ 800°C. Xuyên qua giáp vật lý và thiêu rụi lá chắn ma pháp cấp thấp. Tầm bắn trực diện 10m. [Nhược điểm] Tamer/Thú phải đứng yên (Channelling) khi duy trì.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Đường thẳng (Beam)", combo_tag: "Armor_Melt" },
        { name: "Mưa Lưu Tinh", desc: "[Cơ chế] Kéo các khối đá từ tầng bình lưu, gia nhiệt ma sát để tạo thành vẫn thạch. [Hiệu ứng] Triệu hồi 5-10 viên đá rực lửa kích thước lớn nã xuống diện rộng (50x50m). Công phá đội hình, để lại hố dung nham gây sát thương địa hình.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Thổ"], range_type: "AoE Rộng (Tầm Xa)", combo_tag: "Meteor_Strike" },
        { name: "Hỏa Xà Truy Kích", desc: "[Cơ chế] Định hình ngọn lửa thành hình rắn và gán cho nó ý thức nhân tạo. [Hiệu ứng] Tạo ra con rắn lửa tự động bám theo mục tiêu đã khóa (bỏ qua vật cản đơn giản) cho đến khi trúng đích. Tỉ lệ trúng 90%.", rank: "Ngân Giai", cost: { type: "MP", value: 2500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Khóa mục tiêu (Tracking)", combo_tag: "Fire_Snake" },
        { name: "Tro Tàn Che Mắt", desc: "[Cơ chế] Đốt cháy không khí và ném hạt bụi than siêu nhỏ ra xung quanh. [Hiệu ứng] Tung mây tro nóng bán kính 10m. Gây mù lòa (Giảm 100% tầm nhìn) và ngạt thở cục bộ (Trừ 50 Stamina mỗi 5 giây). Rất hiệu quả để tháo chạy.", rank: "Thiết Giai", cost: { type: "MP", value: 120 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "AoE Nhỏ (Xung quanh bản thân)", combo_tag: "Blind_Ash" },
        { name: "Bạo Tẩu Viêm Mạch", desc: "[Cơ chế] Dùng ngọn lửa đốt trực tiếp vào kinh mạch bản thân để kích thích tế bào. [Hiệu ứng] Tăng 200% sát thương Hỏa và 50% AGI trong 15 giây. [Tác dụng phụ] Đốt cháy trực tiếp sinh lực. Hết thời gian nhận Debuff [Kiệt Quệ] giảm 50% toàn bộ chỉ số trong 24h.", rank: "Ngân Giai", cost: { type: "HP", value: 3000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Sinh Học"], range_type: "Bản thân (Buff cuồng nộ)", combo_tag: "Berserk_Fire" },
        { name: "Địa Hỏa Phun Trào", desc: "[Cơ chế] Truyền ma lực vào lòng đất, kích hoạt đun sôi mạch khoáng chất. [Hiệu ứng] Dòng dung nham phun trào đột ngột ngay tại vị trí kẻ địch đứng. Gây hất tung (Knock-up) và sát thương Hỏa cực mạnh. Khó né tránh nếu AGI thấp.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Thổ"], range_type: "AoE Nhỏ (Tầm Xa/Dưới chân)", combo_tag: "Knockup_Fire" },
        { name: "Hỏa Trảo Xé Xác", desc: "[Cơ chế] Bọc ngọn lửa nhiệt độ cao (600°C) vào móng vuốt vật lý. [Hiệu ứng] Đòn đánh kết hợp (Vật lý + Ma pháp). Vết cào tự động nướng chín mô mềm, gây hiệu ứng 'Vết thương khó lành' (Giảm 80% hiệu quả hồi phục từ kỹ năng/dược phẩm).", rank: "Thiết Giai", cost: { type: "Stamina", value: 100 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Vật Lý"], range_type: "Cận Chiến", combo_tag: "Grievous_Wounds" },
        { name: "Bếp Lò Dã Chiến (Sinh hoạt)", desc: "[Cơ chế] Vi điều khiển nhiệt lượng từ ngón tay. [Hiệu ứng] Kiểm soát nhiệt độ chính xác từ 40°C đến 250°C để nấu chín thức ăn, đun sôi nước mà tuyệt đối không tạo ra khói hay tia lửa, giúp giữ bí mật vị trí cắm trại.", rank: "Phàm Giai", cost: { type: "MP", value: 15 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Tiện ích)", combo_tag: "Utility_Cooking" },
        { name: "Hấp Thụ Nhiệt Năng", desc: "[Cơ chế] Nghịch đảo quá trình tỏa nhiệt, biến cơ thể thành hố đen hút năng lượng nhiệt. [Hiệu ứng] Hút nhiệt từ đám cháy xung quanh (hoặc dung nham) để chuyển hóa hồi phục 20% Thể Lực (Stamina) mỗi 5 giây, đồng thời làm nguội môi trường.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Hồi phục)", combo_tag: "Heat_Absorb" },
        { name: "Viêm Ma Tiễn", desc: "[Cơ chế] Nén lửa thành hình thoi, phủ lớp giáp năng lượng xuyên thấu bên ngoài. [Hiệu ứng] Bắn tiễn lửa xuyên phá giáp vật lý. Sau khi găm vào mục tiêu 2 giây sẽ kích nổ từ bên trong, gây sát thương Hỏa bỏ qua 50% DEF.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Armor_Pierce" },
        { name: "Hỏa Dực Phản Lực", desc: "[Cơ chế] Phun ngọn lửa áp suất cao từ lòng bàn chân hoặc xương bả vai. [Hiệu ứng] Tạo lực đẩy cực mạnh để bay lượn ở tầm thấp, lướt nhanh trên mặt đất hoặc né đòn đột ngột. Tăng 150% AGI khi kích hoạt.", rank: "Ngân Giai", cost: { type: "Stamina", value: 800 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Phong"], range_type: "Bản thân (Di chuyển)", combo_tag: "Fire_Dash" },
        { name: "Lốc Xoáy Lửa", desc: "[Cơ chế] Kết hợp năng lượng Hỏa và sự chênh lệch áp suất không khí. [Hiệu ứng] Tạo cơn lốc lửa đường kính 5m, hút toàn bộ kẻ địch (có CON thấp) vào tâm và nướng chín chúng bằng nhiệt độ 1000°C. Kéo dài 15 giây.", rank: "Kim Giai", cost: { type: "MP", value: 200000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Phong"], range_type: "AoE Trung (Tầm Trung)", combo_tag: "Fire_Tornado" },
        { name: "Dấu Ấn Thiêu Đốt", desc: "[Cơ chế] Gài một khối ma lực hệ hỏa nén siêu nhỏ vào cơ thể địch qua chạm tay. [Hiệu ứng] Gắn bom nhiệt. Kích nổ từ xa bằng ý nghĩ bất cứ lúc nào, gây sát thương chuẩn vào nội tạng. Không thể thanh tẩy trừ khi có phép cấp Thánh.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Cận Chiến (Gài ấn)", combo_tag: "Time_Bomb" },
        { name: "Sấy Khô Tức Thì (Sinh hoạt)", desc: "[Cơ chế] Bốc hơi nước cục bộ bằng sóng nhiệt nhẹ. [Hiệu ứng] Làm khô toàn bộ quần áo, trang bị ướt sũng trong 5 giây để tránh trạng thái [Sốc nhiệt] hoặc [Hạ thân nhiệt] trong môi trường Băng Giá/Đầm lầy.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Tiện ích)", combo_tag: "Utility_Dry" },
        { name: "Tường Lửa Chắn Lối", desc: "[Cơ chế] Dựng lên một rào cản ma lực thuần túy mang nhiệt lượng. [Hiệu ứng] Dựng tường lửa cao 3m, rộng 10m. Chặn đứng hoàn toàn đòn đánh vật lý cấp thấp, thiêu rụi mũi tên gỗ, chặn tầm nhìn và cản bước tiến quân địch.", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tường Chắn (Tầm Trung)", combo_tag: "Fire_Wall" },
        { name: "Dung Nham Trói Buộc", desc: "[Cơ chế] Hóa lỏng khoáng chất silic trong đất. [Hiệu ứng] Biến vùng đất (3x3m) dưới chân địch thành bùn nóng chảy 1200°C. Giữ chân (Root) chúng tại chỗ, mỗi giây vùng vẫy sẽ càng lún sâu và nhận sát thương thiêu đốt.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Thổ"], range_type: "AoE Nhỏ (Khống chế/Root)", combo_tag: "Magma_Root" },
        { name: "Niết Bàn (Nội tại)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Thức tỉnh huyết mạch Phượng Hoàng cổ đại. [Hiệu ứng] Khi HP về 0, hóa thành quả trứng tro tàn. Tái sinh sau 5 giây với 10% HP và bộc phát vụ nổ hạt nhân mặt trời bán kính 1km. [Tác dụng phụ cực lớn] Người dùng tụt 1 đại cảnh giới, rớt POT một bậc, suy yếu tuyệt đối 30 ngày.", rank: "Thánh Giai", cost: { type: "Bloodline_Energy", value: 100000 }, cooldown: { value: 1, unit: "Năm", display_text: "1 Năm" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Sinh Mệnh"], range_type: "Bản thân & AoE Rất Rộng", combo_tag: "Holy_Resurrect" },
        { name: "Khói Báo Hiệu (Sinh hoạt)", desc: "[Cơ chế] Trộn lẫn ma lực và hóa chất sinh lý. [Hiệu ứng] Tạo cột khói đặc bốc cao 500m với màu sắc tùy chỉnh. Dùng để truyền tin tình báo hoặc gọi cứu viện cho đồng đội ở khoảng cách xa mà không cần sóng radio.", rank: "Phàm Giai", cost: { type: "MP", value: 10 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tầm nhìn xa (Tiện ích)", combo_tag: "Utility_Signal" },
        { name: "Mắt Lửa", desc: "[Cơ chế] Chuyển đổi võng mạc để bắt phổ tia hồng ngoại. [Hiệu ứng] Nhìn xuyên qua màn đêm đen đặc, sương mù, mây mù hoặc ảo ảnh quang học bằng cách quét cảm biến thân nhiệt của vạn vật.", rank: "Thiết Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Buff Tầm nhìn)", combo_tag: "Thermal_Vision" },
        { name: "Thanh Tẩy Vết Thương", desc: "[Cơ chế] Hủy hoại mô tế bào bề mặt để phong bế mạch máu. [Hiệu ứng] Dùng nhiệt độ 300°C đốt miệng vết thương hở. Cầm máu ngay lập tức, chặn đứng sự lây lan của kịch độc. Gây đau đớn tột độ (Trừ 5 Sanity).", rank: "Thiết Giai", cost: { type: "HP", value: 50 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Cận Chiến (Đồng minh/Bản thân)", combo_tag: "Cauterize_Wound" },
        { name: "Hơi Thở Rồng", desc: "[Cơ chế] Khí quản khuếch đại dòng Hỏa nguyên tố nguyên thủy. [Hiệu ứng] Phun luồng nhiệt hình nón (Góc 60 độ, xa 15m). Thiêu rụi, làm tan chảy vũ khí kim loại của kẻ thù. Sát thương tăng 50% nếu có gen Rồng.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Hình Nón (AoE Tầm Trung)", combo_tag: "Dragon_Breath" },
        { name: "Vòng Nhiệt Sưởi Ấm", desc: "[Cơ chế] Tỏa nhiệt lượng tuần hoàn xung quanh bản thể. [Hiệu ứng] Duy trì nhiệt độ môi trường ở mức 25°C trong bán kính 5m. Bảo vệ toàn bộ tổ đội khỏi sát thương môi trường ở Lãnh nguyên Băng Giá hoặc Vùng chết lạnh.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "AoE Nhỏ (Xung quanh bản thân)", combo_tag: "Aura_Warmth" },
        { name: "Hỏa Tinh Khởi Nguyên (Sinh hoạt)", desc: "[Cơ chế] Tạo ra đốm lửa ma thuật không cần vật chất đốt. [Hiệu ứng] Tạo một ngọn lửa trại vĩnh cửu lơ lửng. Cháy bất diệt kể cả trong mưa bão cấp 5, dưới đáy hồ hoặc môi trường chân không, trừ khi người dùng tự tay dập tắt.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Tiện ích", combo_tag: "Eternal_Flame" },
        { name: "Bóng Ma Lửa", desc: "[Cơ chế] Uốn cong ánh sáng và khí nóng để tạo quang ảnh (Mirage). [Hiệu ứng] Tạo ra 3 ảo ảnh bằng lửa hình người/thú chạy theo các hướng khác nhau. Đánh lừa thị giác và cảm biến nhiệt của kẻ địch trong 10 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Ảo Giác"], range_type: "Phân thân/Ảo ảnh", combo_tag: "Fire_Mirage" },
        { name: "Kích Nổ Khí Gas", desc: "[Cơ chế] Nắn dòng Hỏa ma pháp thành tia lửa điện vi mô ở khoảng cách xa. [Hiệu ứng] Gây xúc tác kích nổ lập tức các túi khí độc, đầm lầy metan, hoặc kho đạn/nhiên liệu của quân địch từ cự ly an toàn (100m).", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Lôi"], range_type: "Tầm Rất Xa (Kích nổ)", combo_tag: "Remote_Detonate" },
        { name: "Viêm Đao Trảm", desc: "[Cơ chế] Nén lửa thành cấu trúc plasma lưỡi mỏng. [Hiệu ứng] Ngưng tụ lửa ở cạnh bàn tay thành lưỡi kiếm dài 1.5m. Chém đứt sắt thép, tạo vết cắt nhẵn thín và tự động hàn chết vết thương đối thủ (ngăn chúng dùng skill nổ máu).", rank: "Ngân Giai", cost: { type: "MP", value: 3200 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Cận Chiến", combo_tag: "Plasma_Blade" },
        { name: "Thiêu Đốt Oxy", desc: "[Cơ chế] Tăng tốc độ phản ứng cháy lên mức cực đoan vô hiệu hóa khí O2. [Hiệu ứng] Đốt sạch Oxy trong khu vực kín bán kính 20m. Khiến mọi sinh vật bên trong ngất xỉu vì ngạt sau 15 giây, tử vong sau 1 phút.", rank: "Kim Giai", cost: { type: "MP", value: 250000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "AoE Trung (Môi trường)", combo_tag: "Suffocate_Room" },
        { name: "Hóa Hình - Viêm Thể (Đặc Biệt)", desc: "[Cơ chế] Ép súc bản thể dị thú hệ hỏa khổng lồ ngụy trang thành nhân loại. [Hiệu ứng] Hình thành lớp vỏ bọc bằng da thịt nhân tạo. Tỏa ra nhiệt lượng nhàn nhạt. Giấu hoàn toàn sát khí và uy áp của Dị thú. Nếu lớp ngụy trang rách, lửa sẽ xì ra.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 50000 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 1, unit: "Phút", is_instant: false }, elements: ["Hệ Hỏa", "Sinh Học"], range_type: "Bản thân (Ngụy trang tuyệt đối)", combo_tag: "Beast_Human_Disguise" },
        { name: "Hỏa Cầu Bạo Phá (Dị Thú)", desc: "[Cơ chế] Phiên bản nguyên thủy của loài thú. Nén lửa sinh học từ dạ dày. [Hiệu ứng] Khạc khối cầu lửa khổng lồ, đường kính 3m. Gây nổ diện rộng, phá hủy mặt đường bê tông. Tầm bắn ngắn hơn bản Tamer nhưng uy lực vật lý mạnh hơn.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "AoE Nhỏ (Tầm Trung)", combo_tag: "Beast_Fireball" },
        { name: "Viêm Giáp", desc: "[Cơ chế] Vảy/lông tự động bốc cháy khi nhận sát thương. [Hiệu ứng] Phản sát thương hỏa cực mạnh (70% sát thương gốc) cho kẻ tiếp cận. Đốt cháy vũ khí của kẻ tấn công làm giảm độ bền (Durability) của trang bị đi 10 điểm mỗi lần chém trúng.", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Phòng thủ bị động)", combo_tag: "Beast_Fire_Armor" },
        { name: "Phun Lửa Liên Tục", desc: "[Cơ chế] Khoang chứa khí metan sinh học trong ngực phun trào. [Hiệu ứng] Cột lửa rộng 4m, nhiệt độ 1200°C. Thiêu rụi một cánh rừng trong vài giây. Duy trì liên tục gây sát thương DPS cực cao, nhưng dị thú không thể đổi hướng đầu quá nhanh.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Đường thẳng (Channelling)", combo_tag: "Breath_DPS" },
        { name: "Mưa Lưu Tinh (Tuyệt Kỹ)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Giao thoa ý chí với Tinh tú nguyên thủy, xé rách khí quyển. [Hiệu ứng] Triệu hồi bão Vẫn Thạch (Kích thước mỗi viên 20m) hủy diệt hoàn toàn một Thành phố. [Tác dụng phụ] Hút cạn MP, Sanity giảm về 0 (Rơi vào trạng thái Điên Loạn Berserk 24h), tàn phế 7 ngày.", rank: "Diệu Giai", cost: { type: "MP", value: 50000000 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Thổ", "Không Gian"], range_type: "AoE Rất Rộng (Cấp Thảm Họa)", combo_tag: "Divine_Meteor" },
        { name: "Hỏa Xà Vũ", desc: "[Cơ chế] Tách 5 dòng lửa từ đuôi/chân, múa lượn tự do. [Hiệu ứng] 5 con rắn lửa độc lập bao vây, truy kích và trói buộc mục tiêu thành kén lửa. Vừa gây sát thương thiêu đốt vừa khóa chặt hành động (Stun).", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Đa mục tiêu (Khống chế)", combo_tag: "Snake_Bind" },
        { name: "Tro Tàn Trất Tức", desc: "[Cơ chế] Rũ mạnh lông mao đang cháy để tạo bão bụi. [Hiệu ứng] Tung đám mây tro bụi bao phủ bán kính 30m. Kẻ địch hít phải sẽ bị bỏng phổi (Trừ 2% Max HP mỗi 5 giây), mù lòa hoàn toàn, vô hiệu hóa các cảm biến ma thuật.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "AoE Trung", combo_tag: "Ash_Storm" },
        { name: "Bạo Tẩu Viêm Mạch (Dị Thú)", desc: "[Cơ chế] Kích hoạt tuyến thượng thận kết hợp Hỏa ma pháp. [Hiệu ứng] Mắt đỏ ngầu, cơ bắp phình to. Đốt sinh lực để tăng 150% sát thương Hỏa và bỏ qua cảm giác đau đớn. Chỉ dừng lại khi địch chết hoặc bản thân cạn máu.", rank: "Ngân Giai", cost: { type: "HP", value: 5000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Sinh Học"], range_type: "Bản thân (Cuồng nộ sinh tồn)", combo_tag: "Beast_Berserk" },
        { name: "Địa Hỏa Phun Trào (Thiên Tai)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Kết nối bản nguyên Hỏa với lõi hành tinh, đánh thức siêu núi lửa. [Hiệu ứng] Gây chấn động địa mạch cấp độ 9. Dung nham trào lên như biển gầm, nuốt chửng vạn vật. [Tác dụng phụ] Tiêu hao 90% Tuổi thọ, hủy hoại hoàn toàn căn cơ (CCI giảm về 0), vĩnh viễn không thể thăng cấp.", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 1000000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Thổ"], range_type: "AoE Rất Rộng (Cấp Thảm Họa)", combo_tag: "Divine_Volcano" },
        { name: "Hỏa Trảo Xé Xác (Cận Chiến)", desc: "[Cơ chế] Vuốt dài thêm 20cm nhờ tinh thể lửa nén. [Hiệu ứng] Chém ra 3 đường kiếm khí lửa sắc lẹm hình lưỡi liềm bay xa 5m. Cắt đôi xe bọc thép dễ dàng.", rank: "Thiết Giai", cost: { type: "Stamina", value: 150 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Vật Lý"], range_type: "Cận Chiến (Tầm Ngắn)", combo_tag: "Fire_Slash" },
        { name: "Lá Chắn Hỏa Liên", desc: "[Cơ chế] Ngưng tụ ma lực thành hình hoa sen 9 cánh xoay tròn. [Hiệu ứng] Hấp thụ sát thương lên đến 20000 điểm. Mỗi lần một cánh sen vỡ, nó bắn một tia lửa truy kích kẻ tấn công. Khi vỡ hoàn toàn, đài sen nổ tung gây hất văng.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Phòng thủ bạo phát)", combo_tag: "Lotus_Shield" },
        { name: "Hấp Thụ Nhiệt (Dị Thú)", desc: "[Cơ chế] Há miệng nuốt ngọn lửa từ môi trường vào bụng. [Hiệu ứng] Miễn nhiễm sát thương hệ Hỏa dưới cấp Ngân. Hút năng lượng từ dung nham hoặc đám cháy rừng để hồi phục 10% Max HP mỗi 5 giây.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa"], range_type: "Bản thân (Hồi máu)", combo_tag: "Beast_Heat_Absorb" },
        { name: "Viêm Ma Tiễn (Bản Mưa)", desc: "[Cơ chế] Dựng lông nhím/vảy rực lửa và bắn ra xung quanh. [Hiệu ứng] Bắn hàng trăm mũi tên lửa bao phủ một khu vực lớn. Có khả năng găm vào và xuyên thấu các lớp khiên ma pháp hệ Thủy cấp thấp.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa"], range_type: "AoE Trung (Mưa Tiễn)", combo_tag: "Arrow_Rain" },
        { name: "Hỏa Dực Khinh Công", desc: "[Cơ chế] Biến đổi kết cấu lưng để mọc ra cánh chim lửa (Phoenix Wings). [Hiệu ứng] Giúp Dị thú (Kể cả loài 4 chân) bay lượn tự do với tốc độ Mach 1. Bay qua rải tro tàn thiêu đốt mặt đất bên dưới.", rank: "Ngân Giai", cost: { type: "Bloodline_Energy", value: 6000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Phong", "Sinh Học"], range_type: "Bản thân (Tiến hóa cánh)", combo_tag: "Wings_Of_Fire" },
        { name: "Lốc Xoáy Lửa (Bão Táp)", desc: "[Cơ chế] Chạy vòng tròn với tốc độ cực cao, cọ xát tạo ma sát hỏa. [Hiệu ứng] Tạo cơn lốc lửa đường kính 20m cuốn phăng cả một đội hình binh lính. Nướng chín và xé toạc chúng trên không trung.", rank: "Kim Giai", cost: { type: "Stamina", value: 150000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Phong", "Vật Lý"], range_type: "AoE Rộng (Di chuyển)", combo_tag: "Beast_Fire_Tornado" },
        { name: "Dấu Ấn Hỏa Thiêu", desc: "[Cơ chế] Phun một giọt máu chứa hỏa độc vào kẻ địch. [Hiệu ứng] Khắc ấn Hỏa Liên lên trán mục tiêu. Kẻ địch chịu thêm 30% sát thương từ mọi đòn Hỏa. Kích nổ từ xa tước đi 20% Max HP (Sát thương chuẩn).", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 80000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Huyết Mạch"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Blood_Mark" },
        { name: "Hơi Thở Rồng Lửa", desc: "[Cơ chế] Kỹ năng độc quyền của Á Long/Chân Long. Kích hoạt hạch rồng. [Hiệu ứng] Phun ngọn lửa đỏ thẫm mang Uy Áp Long Tộc. Kẻ địch có BLD thấp hơn bị tê liệt (Fear) trong lúc thiêu. Sát thương cực khủng.", rank: "Kim Giai", cost: { type: "MP", value: 800000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Tinh Thần"], range_type: "Hình Nón Rộng (Cấp độ Long Tộc)", combo_tag: "True_Dragon_Breath" },
        { name: "Tường Lửa Chắn Lối (Dị Thú)", desc: "[Cơ chế] Quật đuôi lửa xuống đất, tạo ra khe nứt. [Hiệu ứng] Dựng bức tường lửa kiên cố kết hợp với rào chắn vật lý từ đất đá. Chặn đứng đòn lao tới của xe tăng hoặc dị thú hạng nặng.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Thổ"], range_type: "Tường Chắn (Vật lý & Ma pháp)", combo_tag: "Beast_Wall" },
        { name: "Dung Nham Trói Buộc (Đầm Lầy)", desc: "[Cơ chế] Giậm chân, truyền nhiệt lượng phá vỡ liên kết phân tử đất. [Hiệu ứng] Biến vùng đất bán kính 10m thành đầm lầy dung nham. Bất kỳ sinh vật nào không bay đều bị lún chìm và tan chảy xương cốt trong 15 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Thổ"], range_type: "AoE Trung (Thay đổi địa hình)", combo_tag: "Lava_Swamp" },
        { name: "Niết Bàn (Bị Động - Dị Thú)", desc: "[Cơ chế] Bản năng sinh tồn tối thượng của loài Hỏa Điểu. [Hiệu ứng] Khi HP về 0, có 5% tỉ lệ sống sót với đúng 1 HP (Không hóa trứng). Lập tức bộc phát hỏa viêm đẩy lùi mọi kẻ địch xung quanh để có cơ hội bỏ chạy.", rank: "Kim Giai", cost: { type: "Sanity", value: 50 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Sinh Mệnh"], range_type: "Bản thân (Sinh tồn)", combo_tag: "Survival_Burst" }
    ],
  "Hệ Tinh Thần": [
        { name: "Hóa Hình - Minh Chủ Tinh Thần", desc: "[Cơ Chế Sinh Học] Dùng sóng não Lambda cưỡng ép DNA tái tổ hợp theo bản mẫu nhân loại. Tối ưu tốc độ não gấp 100 lần. [Hình Thái] Vẻ ngoài thanh thoát, đạt Disguise Quality tuyệt đối. Không dùng cơ bắp, mọi hành động dẫn dắt bởi niệm lực. [Tác dụng phụ] Sanity < 20, cơ thể rách nát lộ xúc tu.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Sinh Học"], range_type: "Bản thân (Chuyển đổi hình thái)", combo_tag: "Form_Mind" },
        { name: "Tinh Thần Thiết Bích", desc: "[Cơ chế] Sóng não tĩnh lặng đóng chặt mọi cửa ngõ tâm hồn. [Hiệu ứng] Kháng 100% các kỹ năng đọc tâm trí (Scan), soi mói thông tin cơ bản hay ý đồ chiến thuật từ kẻ địch cấp thấp hơn. Kẻ đọc sẽ bị ù tai nhẹ.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động kháng tình báo)", combo_tag: "Passive_Mind_Fortress" },
        { name: "Lục Giác Thần Thức", desc: "[Cơ chế] Tuyến tùng quả mở rộng cảm nhận sóng sinh học xung quanh. [Hiệu ứng] Cảnh báo nhói đau trong đầu trước khi bị tập kích bất ngờ 1 giây. Không bao giờ bị trạng thái [Surprised/Bị Đánh Lén] khiến choáng váng đầu giao tranh.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động linh cảm)", combo_tag: "Passive_Sixth_Sense" },
        { name: "Minh Kính Cố Tâm", desc: "[Cơ chế] Tự kỷ ám thị để tạo màng bọc bảo vệ não bộ khỏi hạt hắc ám. [Hiệu ứng] Sanity (Lý trí) bị trừ chậm hơn 50% khi chứng kiến các cảnh kinh dị, ở trong Vùng Zero tăm tối, hoặc khi dính các lời nguyền hệ Ám.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động bảo vệ Sanity)", combo_tag: "Passive_Firm_Sanity" },
        { name: "Vô Hình Trấn Áp", desc: "[Cơ chế] Não bộ liên tục tỏa ra sóng Alpha áp chế sinh vật yếu. [Hiệu ứng] Những quái vật hoang dã (Cấp Phàm) có trí tuệ thấp (INT nhỏ) tự động tránh xa bạn 10m, không dám chủ động tấn công trừ khi bị dồn vào chân tường.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "AoE Rộng (Bị động xua đuổi)", combo_tag: "Passive_Invisible_Pressure" },
        { name: "Ma Lực Cộng Hưởng", desc: "[Cơ chế] Đồng bộ hóa sóng não với nhịp đập của hạt Mana tự nhiên. [Hiệu ứng] Giảm 10% lượng MP tiêu hao (Cost) cho TẤT CẢ các kỹ năng (của mọi hệ) mà bạn đang sở hữu. Cực kỳ hữu ích cho Pháp sư.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động tiết kiệm)", combo_tag: "Passive_Mana_Resonance" },
        { name: "Tinh Thần Phản Phệ", desc: "[Cơ chế] Não bộ thiết lập phản xạ có điều kiện dạng phản đòn. [Hiệu ứng] Bất kỳ ai dùng kỹ năng Tâm Linh/Ảo Giác/Khống Chế Tinh Thần tấn công bạn sẽ lập tức nhận lại 10% sát thương tinh thần và bị nhức đầu (Trừ 2 AGI).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Mục tiêu tấn công (Bị động phản đòn)", combo_tag: "Passive_Mental_Spike" },
        { name: "Thấu Cảm Độc Tâm", desc: "[Cơ chế] Đọc những vi biểu cảm và ngôn ngữ cơ thể do não phát ra. [Hiệu ứng] Trong lúc giao tiếp với NPC, bạn luôn nhận biết được họ đang Nói Thối hay Nói Thật (Độ chính xác 80%). Tăng tỉ lệ thành công khi Đàm phán/Đe dọa.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Giao tiếp NPC (Bị động xã hội)", combo_tag: "Passive_Empathy_Read" },
        { name: "Huyễn Ảnh Mê Tung", desc: "[Cơ chế] Tự động phóng sóng não làm nhiễu loạn thị giác kẻ địch khi tấn công. [Hiệu ứng] Khi đòn đánh của bạn trượt (Miss), tự động để lại một cái bóng giả mờ ảo tại chỗ cũ, đánh lừa đòn phản công của đối phương trong 1 giây.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "Bản thân (Bị động đánh lạc hướng)", combo_tag: "Passive_Illusion_Blur" },
        { name: "Điện Não Thần Tốc", desc: "[Cơ chế] Xung thần kinh chạy nhanh gấp 3 lần tốc độ người thường. [Hiệu ứng] Giảm 20% Thời gian niệm chú (Cast time) của mọi kỹ năng. Phản ứng với các biến số trên chiến trường (như đạn nổ, bẫy) cực kỳ nhạy bén.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động rút ngắn niệm)", combo_tag: "Passive_Thought_Accel" },
        { name: "Đoạn Niệm Trấn Thống", desc: "[Cơ chế] Tự kỷ ám thị để chặn đường truyền tín hiệu đau lên vỏ não. [Hiệu ứng] Sát thương từ các đòn đánh trực tiếp bằng vật lý (Đâm, chém) không bao giờ làm bạn bị gián đoạn (Interrupt) khi đang niệm các phép thuật quan trọng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động kháng gián đoạn)", combo_tag: "Passive_Pain_Ignore" },
        { name: "Khủng Cụ Thôn Phệ", desc: "[Cơ chế] Hạch hạnh nhân biến năng lượng tiêu cực thành thức ăn cho não. [Hiệu ứng] Mỗi khi có một kẻ địch bị dính trạng thái [Sợ Hãi], [Hoảng Loạn] trong phạm vi 20m, bạn sẽ được hồi ngay 2% MP và 1 điểm Sanity.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "AoE Trung (Bị động hồi Mana)", combo_tag: "Passive_Fear_Absorb" },
        { name: "Tuệ Nhãn Mẫn Tiệp", desc: "[Cơ chế] Tế bào não được cấu trúc lại để lưu trữ khối lượng thông tin khổng lồ. [Hiệu ứng] Tăng vĩnh viễn 15% Chỉ số Trí tuệ (INT) và Tinh thần (SPI). Giúp mở rộng khoang chứa Hồn Ấn (Soul Capacity) để thu phục nhiều Pet hơn.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động tăng chỉ số)", combo_tag: "Passive_Sharp_Intellect" },
        { name: "Tinh Thần Phá Trận", desc: "[Cơ chế] Sóng não tự nhiên phát ra lệch pha với sóng phép thuật xung quanh. [Hiệu ứng] Kẻ địch đứng trong bán kính 5m quanh bạn sẽ bị tăng 10% lượng MP tiêu hao khi tung chiêu, đồng thời thỉnh thoảng bị hoa mắt.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "AoE Cận (Bị động phá rối)", combo_tag: "Passive_Mana_Jammer" },
        { name: "Linh Hồn Khế Ước", desc: "[Cơ chế] Ý thức chia sẻ thụ động qua đường truyền lượng tử với Sủng thú. [Hiệu ứng] Chỉ cần Sủng Thú của bạn còn sống trên chiến trường, bạn (Tamer) được chia sẻ 10% Sát thương nhận vào sang cho Sủng Thú (Giảm tải HP cho chủ).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân & Sủng thú (Bị động chia sẻ sát thương)", combo_tag: "Passive_Bond_Share" },
        { name: "Thuấn Tức Minh Tưởng", desc: "[Cơ chế] Đưa não vào trạng thái sóng Theta chỉ trong 1 giây nhắm mắt. [Hiệu ứng] Khi đứng yên ngoài giao tranh (Out of Combat) trong 5 giây, tốc độ hồi MP và Sanity lập tức tăng lên gấp 5 lần. Nạp đạn cực nhanh.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động hồi sức)", combo_tag: "Passive_Quick_Meditation" },
        { name: "Linh Thị Chi Nhãn", desc: "[Cơ chế] Mở rộng 'Mắt Tâm Linh' quét các vật thể ma thuật. [Hiệu ứng] Tự động phát hiện và đánh dấu đỏ mọi loại Bẫy Phép, Trận Pháp Hắc Ám ẩn dưới đất hoặc bám trên tường trong bán kính 10m mà mắt thường không thấy.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần", "Trinh Sát"], range_type: "AoE Nhỏ (Bị động dò bẫy)", combo_tag: "Passive_Mind_Sight" },
        { name: "Mộng Cảnh Kết Giới", desc: "[Cơ chế] Bức xạ tinh thần tự động ru ngủ các sinh vật nhỏ bé. [Hiệu ứng] Mọi loài côn trùng độc, muỗi, ruồi mang mầm bệnh Vùng Zero khi bay vào tầm 1m quanh bạn sẽ rơi vào trạng thái ngủ say và rớt xuống đất.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Xung quanh (Bị động sinh tồn)", combo_tag: "Passive_Dream_Aura" },
        { name: "Du Hồn Ám Dạ", desc: "[Cơ chế] Tiềm thức hoạt động như một hệ điều hành dự phòng khi não chính nghỉ ngơi. [Hiệu ứng] Nếu bạn bị dính trạng thái [Ngủ] (Sleep) bởi kỹ năng địch, bạn vẫn có thể di chuyển chầm chậm (Mộng du) và Né tránh được 50% đòn đánh thẳng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động phòng thủ giấc ngủ)", combo_tag: "Passive_Sleepwalker" },
        { name: "Kháng Cự Hư Vọng", desc: "[Cơ chế] Bộ não từ chối xử lý thông tin phi logic để bảo vệ vùng hải mã. [Hiệu ứng] Kháng 100% các loại Ảo ảnh (Mirage) phân thân vật lý. Trong mắt bạn, các phân thân giả của địch sẽ có màu nhạt hơn bản gốc rất nhiều.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động phá ảo giác)", combo_tag: "Passive_Reject_Illusion" },
        { name: "Tuyệt Trứ Phùng Sinh", desc: "[Cơ chế] Khi Sanity chạm đáy, năng lượng tinh thần tự đảo cực (Từ Âm sang Dương). [Hiệu ứng] Khi Sanity (Lý trí) rớt xuống dưới 20 (Ngưỡng Điên Loạn), bạn không bị mất kiểm soát mà ngược lại, toàn bộ Sát thương phép thuật tăng 50% trong 10 giây.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Bị động lật kèo điên loạn)", combo_tag: "Passive_Despair_Invert" },
        { name: "Roi Tâm Linh", desc: "[Cơ chế] Ngưng tụ niệm lực thành hạt vật lý ảo hình sợi roi. [Hiệu ứng] Quất xuyên qua giáp vật lý và khiên ma pháp, đánh trực tiếp vào hệ thần kinh (Tủy sống/Não). Gây đau đớn tột độ bậc 9, làm gián đoạn (Interrupt) mọi kỹ năng đang niệm của đối thủ.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Trung (Đơn mục tiêu)", combo_tag: "Mind_Whip" },
        { name: "Đạn Ý Niệm", desc: "[Cơ chế] Ngưng tụ sóng não thành đạn vô hình. [Hiệu ứng] Bắn xuyên không khí đánh thẳng vào tâm trí mục tiêu. Bỏ qua hoàn toàn giáp vật lý. Gây đau đầu dữ dội, làm chậm tốc độ niệm chú ma pháp của địch.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Mind_Bullet" },
        { name: "Cú Chạm Đau Đớn", desc: "[Cơ chế] Đẩy một xung thần kinh đau nhức mô phỏng lên tủy sống. [Hiệu ứng] Đặt tay lên đối thủ. Nạn nhân cảm nhận nỗi đau cháy da dù không xước một mảng thịt. Giảm lập tức 20% Lực công kích vì quá đau.", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Cận Chiến (Debuff Tấn công)", combo_tag: "Pain_Touch" },
        { name: "Gào Thét Não Bộ", desc: "[Cơ chế] Sóng xung kích siêu âm truyền vào thùy trán. [Hiệu ứng] Hét ra sóng tinh thần (AoE 3m). Mọi kẻ địch ôm đầu la hét, rớt vũ khí (Tước vũ khí 1s) và bị Choáng váng nhẹ.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Sóng Âm"], range_type: "AoE Nhỏ (Xung quanh)", combo_tag: "Brain_Scream" },
        { name: "Bóp Nghẹt Tinh Thần", desc: "[Cơ chế] Khóa chặt ý thức liên kết với cơ trơn. [Hiệu ứng] Nhìn thẳng địch, bóp nghẹt ý chí. Kẻ thù thấy như bị thắt cổ bằng tay ma, mất 10 điểm Sanity và ngạt thở lùi lại. (Ngắt chiêu cực đỉnh).", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Trung (Silence/Trừ Sanity)", combo_tag: "Mind_Choke" },
        { name: "Đẩy Lùi Ý Chí", desc: "[Cơ chế] Tạo khiên sóng não đẩy vật chất vô cơ. [Hiệu ứng] Dùng ý niệm tạo lực đẩy vô hình (Telekinesis nhẹ). Đẩy lùi 1 mục tiêu vừa/nhỏ hoặc đánh bật 1 quả bom nổ chậm bay ngược về chỗ cũ.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần", "Vật Lý"], range_type: "Tầm Trung (Đẩy lùi)", combo_tag: "Tele_Push" },
        { name: "Hoang Tưởng Kẻ Địch", desc: "[Cơ chế] Thả ảo ảnh sợ hãi vào góc nhìn ngoại vi của mắt. [Hiệu ứng] Địch bỗng thấy đồng đội mình mang gương mặt quỷ dữ. Gây hoảng loạn (Fear), chúng sẽ không dám lại gần hoặc Buff máu cho đồng minh trong 3 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "Tầm Xa (Debuff Sợ hãi)", combo_tag: "Paranoia_Illusion" },
        { name: "Khiên Ý Niệm Mỏng", desc: "[Cơ chế] Màng lọc điện não đồ cản ma pháp tinh thần. [Hiệu ứng] Trải một lớp khiên vô hình. Phản lại 1 đòn tấn công Hệ Tinh Thần/Ảo Giác cấp Phàm của đối thủ, bảo vệ não bộ khỏi việc tụt Sanity.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Phản đòn ma pháp não)", combo_tag: "Thin_Mind_Shield" },
        { name: "Đọc Ý Lướt Đứt", desc: "[Cơ chế] Scan bề mặt não lướt sóng thần kinh vỏ não. [Hiệu ứng] Không đọc được bí mật, nhưng dự đoán được Hướng tấn công tiếp theo của 1 kẻ địch (Trái/Phải/Phép/Vật lý). Tăng 100% Dodge cho đòn đánh đó.", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Trung (Đọc trước tương lai ngắn)", combo_tag: "Surface_Scan_Dodge" },
        { name: "Làm Dịu Tổn Thương", desc: "[Cơ chế] Tiết Serotonin ảo bằng ma pháp sóng Alpha. [Hiệu ứng] Vuốt ve đồng đội hoặc Sủng thú. Không hồi HP, nhưng làm chúng quên đi cảm giác đau, hồi phục 15 Sanity và gỡ bỏ trạng thái Sợ Hãi (Fear).", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Trị Liệu"], range_type: "Cận Chiến (Giải CC/Hồi Sanity)", combo_tag: "Soothe_Mind" },
        { name: "Ảo Ảnh Khúc Xạ", desc: "[Cơ chế] Bẻ cong nhận thức vị trí trong não bộ địch. [Hiệu ứng] Kẻ địch nhìn thấy bạn đang đứng cách chỗ thực tế 1 mét. Bắn cung/súng hay chém vật lý đều trượt hoàn toàn (Miss 100%) trong 2 lượt.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "Bản thân (Tàng hình vị trí)", combo_tag: "Displacement_Illusion" },
        { name: "Khiên Tâm Trí", desc: "[Cơ chế] Rải một lớp màng lọc tần số sóng não hình cầu. [Hiệu ứng] Tạo vỏ bọc vô hình. Hấp thụ 100% sát thương từ đòn đánh Tinh Thần cấp Thiết trở xuống. Kẻ địch dùng chiêu Đọc tâm trí (Scan) sẽ bị nhiễu sóng (Phản sát thương nhẹ).", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Phòng thủ Tâm trí)", combo_tag: "Mind_Shield" },
        { name: "Tiếng Thì Thầm Của Quỷ", desc: "[Cơ chế] Đồng bộ hóa sóng âm với nhịp đập hạch hạnh nhân của đối phương. [Hiệu ứng] Gieo ý nghĩ tiêu cực. Mục tiêu (SPI thấp) hoang mang, giảm 30% độ chính xác và có 20% tỉ lệ quay sang đánh đồng đội trong 5 giây tiếp theo.", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần", "Nguyền Rủa"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Mind_Corrupt" },
        { name: "Sóng Xung Kích Sọ Não", desc: "[Cơ chế] Nén ma lực tinh thần vào một điểm và giải phóng bằng sóng siêu âm cục bộ. [Hiệu ứng] Bán kính 10m. Mọi kẻ địch bị choáng váng (Stun) 1.5s, chảy máu thất khiếu (tai, mắt, mũi) và bị debuff Mất Thăng Bằng (AGI giảm 80%).", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "AoE Trung", combo_tag: "Mind_Stun" },
        { name: "Đọc Tâm Thuật (Scan)", desc: "[Cơ chế] Xâm nhập chuỗi điện não đồ hiện tại. [Hiệu ứng] Xem được bảng chỉ số cơ bản của mục tiêu, biết trước đòn đánh kế tiếp của chúng (100% né tránh đòn tiếp theo), hoặc moi móc 1 bí mật giấu kín. [Điều kiện] SPI phải lớn hơn mục tiêu.", rank: "Ngân Giai", cost: { type: "MP", value: 2500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Mind_Scan" },
        { name: "Mê Hồn Trận", desc: "[Cơ chế] Kích thích thùy chẩm, tạo tín hiệu thị giác giả. [Hiệu ứng] Bắn mục tiêu vào một vùng không gian ảo giác. Kẻ địch thấy đồng đội là quái vật, thấy vực sâu trước mặt. Kéo dài 15 giây, khiến đội hình địch rối loạn hoàn toàn.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "AoE Trung", combo_tag: "Illusion_Maze" },
        { name: "Thao Túng Vật Thể (Telekinesis)", desc: "[Cơ chế] Phóng niệm lực ôm trọn vật chất, chống lại trọng lực. [Hiệu ứng] Nâng vật nặng tối đa 5 tấn. Ném đá khổng lồ, bẻ gãy cổ địch từ xa, hoặc chặn đứng hàng trăm mũi tên bay tới. Càng nặng tốn càng nhiều MP.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Duy trì)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần", "Vật Lý"], range_type: "Tầm Trung (Thao tác vật lý)", combo_tag: "Telekinesis" },
        { name: "Kết Nối Thần Giao", desc: "[Cơ chế] Thiết lập mạng LAN sóng não nội bộ. [Hiệu ứng] Kết nối tối đa 6 đồng minh trong bán kính 1km. Giao tiếp siêu tốc bằng ý nghĩ, chia sẻ tầm nhìn, không thể bị nghe lén hay nhiễu bởi máy phá sóng điện từ.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "AoE Rộng (Đồng minh)", combo_tag: "Mind_Link" },
        { name: "Phong Ấn Ký Ức", desc: "[Cơ chế] Chặn lưu thông nơ-ron thần kinh tại một vùng ký ức cụ thể. [Hiệu ứng] Khiến mục tiêu tạm thời 'quên' cách sử dụng kỹ năng mạnh nhất của chúng trong 30 giây, hoặc quên lý do đang chiến đấu (Xóa Aggro - Ngừng tấn công).", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Memory_Seal" },
        { name: "Áp Chế Uy Lực", desc: "[Cơ chế] Phóng thích uy áp tinh thần thuần túy (Haki). [Hiệu ứng] Bán kính 50m. Kẻ địch có tổng Level/Rank thấp hơn sẽ lập tức sùi bọt mép, bất tỉnh hoặc quỳ gập xuống đất không thể ngẩng đầu. Diệt Mob cực kỳ hiệu quả.", rank: "Kim Giai", cost: { type: "MP", value: 80000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "AoE Rộng", combo_tag: "Conqueror_Haki" },
        { name: "Mượn Xác Tráo Hồn", desc: "[Cơ chế] Xuất hồn, đè bẹp và thay thế ý thức nguyên bản của vật chủ. [Hiệu ứng] Chiếm quyền điều khiển 1 kẻ địch (SPI thấp hơn) trong 30 giây. Dùng thân xác đó để tung chiêu, ném bom hoặc đỡ đòn. Cơ thể gốc rơi vào trạng thái ngủ say.", rank: "Kim Giai", cost: { type: "Sanity", value: 30 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Xa (Chiếm hữu)", combo_tag: "Mind_Possession" },
        { name: "Hào Quang Tĩnh Lặng", desc: "[Cơ chế] Lan tỏa sóng Alpha an thần. [Hiệu ứng] Xóa bỏ mọi trạng thái sợ hãi, hoảng loạn, điên cuồng (Berserk) cho toàn đội. Hồi phục 20 Sanity/người và tăng vĩnh viễn 10% INT trong suốt thời gian diễn ra trận đánh.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "AoE Trung (Buff/Hồi phục)", combo_tag: "Aura_Calm" },
        { name: "Nhãn Thuật: Định Thân", desc: "[Cơ chế] Dùng ánh mắt truyền virus điện não. [Hiệu ứng] Nhìn thẳng mắt kẻ địch (<5m). Khóa chặt hệ thần kinh vận động, đóng băng chúng tại chỗ trong 2 giây (Không thể di chuyển, nháy mắt). Tuyệt kỹ setup đòn kết liễu.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Cận Chiến (Khống chế)", combo_tag: "Eye_Paralysis" },
        { name: "Gai Tâm Linh (Passive)", desc: "[Cơ chế] Biến bề mặt khiên tâm trí thành cấu trúc gai phản xạ. [Hiệu ứng] Kẻ nào dùng kỹ năng hệ Tinh thần/Ảo giác tấn công bạn sẽ tự động bị phản phệ 50% sát thương gốc thẳng vào não bộ, kèm hiệu ứng Đau Nhức kéo dài.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Phản đòn bị động)", combo_tag: "Mind_Spike_Passive" },
        { name: "Đánh Cắp Giấc Mơ", desc: "[Cơ chế] Ký sinh vào pha ngủ REM của nạn nhân. [Hiệu ứng] Xâm nhập vào giấc mơ kẻ địch đang ngủ hoặc bị choáng. Rút cạn 50% MP của chúng và chuyển hóa thành HP cho bản thân.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Xa (Điều kiện: Đích đang ngủ/choáng)", combo_tag: "Dream_Steal" },
        { name: "Kẻ Ăn Tội Lỗi", desc: "[Cơ chế] Hấp thụ cảm xúc tiêu cực làm thức ăn. [Hiệu ứng] Hút năng lượng Sợ Hãi, Tuyệt Vọng tỏa ra trên chiến trường. Mỗi mục tiêu hoảng loạn sẽ hồi cho người dùng 5% HP và 2 Sanity.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động AoE)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "AoE Trung (Hút thụ động)", combo_tag: "Sin_Eater" },
        { name: "Vòng Lặp Thời Gian Ảo", desc: "[Cơ chế] Ép não bộ xử lý đi xử lý lại một khung hình duy nhất. [Hiệu ứng] Mục tiêu cảm thấy bị trúng 1 nhát chém hàng ngàn lần trong 1 giây thực tế. Gây sụp đổ tâm lý (Trừ 50 Sanity địch), đưa chúng vào trạng thái Đờ Đẫn.", rank: "Kim Giai", cost: { type: "MP", value: 200000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Izanami_Loop" },
        { name: "Ngôn Ngữ Vạn Vật", desc: "[Cơ chế] Dịch thuật sóng não trực tiếp, bỏ qua rào cản âm thanh. [Hiệu ứng] Hiểu và giao tiếp trôi chảy với mọi giống loài (Người ngoài hành tinh, Dị thú hoang dã, Thực vật bậc cao) miễn là chúng có linh hồn/ý thức.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Tiện ích giao tiếp)", combo_tag: "Universal_Language" },
        { name: "Bẻ Cong Ánh Sáng (Invisibility)", desc: "[Cơ chế] Thao túng vùng vỏ não thị giác của người xung quanh. [Hiệu ứng] Không tàng hình vật lý, nhưng khiến mọi sinh vật xung quanh 'tự động bỏ qua' sự hiện diện của bạn. Máy quay phim vẫn sẽ quay được bạn.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "AoE Trung (Thao túng nhận thức)", combo_tag: "Mind_Invisibility" },
        { name: "Lưới Điện Não", desc: "[Cơ chế] Rải các mìn ý niệm vô hình lên mặt đất. [Hiệu ứng] Tạo bãi mìn tâm linh 10x10m. Bất cứ ai dẫm vào sẽ bị kích giật hệ thần kinh trung ương, tê liệt toàn thân 3 giây và ngắt quãng mọi hành động.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Lôi"], range_type: "AoE Nhỏ (Đặt bẫy)", combo_tag: "Mind_Minefield" },
        { name: "Tẩy Não Hàng Loạt", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Phát dải tần số chép đè ý thức quy mô lớn. [Hiệu ứng] Bán kính 1km, xóa bỏ nhân cách/lý trí của mọi sinh vật (SPI thấp hơn). Biến đám đông/quân địch thành nô lệ vĩnh viễn. [Tác dụng phụ] Mù lòa 30 ngày, trừ 50% Max Sanity vĩnh viễn.", rank: "Diệu Giai", cost: { type: "Sanity", value: 80 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "AoE Rất Rộng (Cấp Thảm Họa)", combo_tag: "Divine_MindControl" },
        { name: "Linh Hồn Hộ Vệ", desc: "[Cơ chế] Phân tách một mảnh linh hồn, nhào nặn thành hình hài. [Hiệu ứng] Triệu hồi kỵ sĩ/ác quỷ tinh thần bán trong suốt. Có máu/sát thương vật lý độc lập (Bằng 50% chỉ số Tamer). Tự động chiến đấu bảo vệ chủ.", rank: "Kim Giai", cost: { type: "Soul_Force", value: 15 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Triệu Hồi"], range_type: "Triệu Hồi (Bên cạnh bản thân)", combo_tag: "Summon_SoulGuard" },
        { name: "Hơi Thở Ảo Giác", desc: "[Cơ chế] Phát tán pheromone kết hợp sóng gây ảo giác. [Hiệu ứng] Phun khói màu hồng. Kẻ địch hít phải rơi vào ảo giác cực lạc (Dopamine quá mức), cười điên dại, vứt vũ khí và nhảy múa cho đến chết vì kiệt sức.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 8, unit: "Phút", display_text: "8 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Khí Độc"], range_type: "Hình Nón (AoE Trung)", combo_tag: "Euphoria_Gas" },
        { name: "Truyền Tin Vạn Dặm", desc: "[Cơ chế] Đẩy sóng não qua Tầng điện ly (Ionosphere). [Hiệu ứng] Gửi đoạn tin nhắn thoại/hình ảnh trực tiếp vào đầu một người cụ thể dù ở cách xa hàng vạn kilomet hoặc ở chiều không gian khác.", rank: "Thiết Giai", cost: { type: "MP", value: 500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Toàn Cầu (Tiện ích)", combo_tag: "Global_Telepathy" },
        { name: "Tâm Cảnh: Tuyệt Vọng", desc: "[Cơ chế] Phủ một Lĩnh Vực (Domain) tâm lý lên thực tại. [Hiệu ứng] Bán kính 50m. Không gian xám xịt, tiếng khóc than vang vọng. Mọi kẻ địch bên trong Lĩnh vực bị giảm 50% Sát thương, 50% Tốc độ và trừ Sanity liên tục mỗi giây.", rank: "Kim Giai", cost: { type: "MP", value: 300000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Lĩnh Vực"], range_type: "AoE Rộng (Lĩnh Vực)", combo_tag: "Despair_Domain" },
        { name: "Đồng Hóa Ý Thức", desc: "[Cơ chế] Kết nối giao diện Não-Máy (BCI) bằng ma lực. [Hiệu ứng] Áp tay vào máy móc, tải ý thức vào hệ thống. Hack camera, mở cửa sắt, điều khiển xe tăng/Mecha của địch bằng ý nghĩ mà không cần mật khẩu.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Công Nghệ"], range_type: "Cận Chiến (Tương tác Máy móc)", combo_tag: "Cyber_Hack" },
        { name: "Nhìn Thấu Tương Lai (2s)", desc: "[Cơ chế] Xử lý siêu tốc xác suất hạt lượng tử. [Hiệu ứng] Kích hoạt trạng thái thần thánh cục bộ. Nhìn thấy trước quỹ đạo đạn, hướng kiếm trong 2 giây tới. Giúp né tránh 100% mọi đòn vật lý/ma pháp (trừ đòn khóa mục tiêu tuyệt đối).", rank: "Kim Giai", cost: { type: "Sanity", value: 10 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần", "Thời Gian"], range_type: "Bản thân (Buff Né tránh tuyệt đối)", combo_tag: "Future_Sight" },
        { name: "Cộng Hưởng Đau Đớn", desc: "[Cơ chế] Móc nối thụ thể cảm giác đau (Nociceptor) giữa 2 cơ thể. [Hiệu ứng] Trong 10 giây, mọi tổn thương vật lý/tinh thần bạn gánh chịu, kẻ địch cũng nhận cảm giác đau y hệt (Dù cơ thể không bị thương). Ép địch ngừng tấn công.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Nguyền Rủa"], range_type: "Tầm Xa (Khóa mục tiêu)", combo_tag: "Pain_Link" },
        { name: "Phân Thân Ý Niệm", desc: "[Cơ chế] Chiết xuất ma lực tạo ảnh ảo có khối lượng nhẹ. [Hiệu ứng] Phân tách thành 3 bản sao. Cầm vũ khí nhẹ chém xước da (10% damage gốc), ném đồ, đánh lạc hướng. Đòn vật lý của địch đi xuyên qua bản sao.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "Xung quanh bản thân", combo_tag: "Mind_Clones" },
        { name: "Hóa Hình - Ánh Sáng Trí Tuệ", desc: "[Cơ chế] Dạng tiến hóa tối thượng thú Tinh Thần. Não phát sáng sinh học. [Hiệu ứng] Vòng sáng (Halo) trên đầu. Hào quang khiến mọi sinh vật phàm tục nhìn vào bị tẩy não thụ động, cảm thấy tự ti, tội lỗi và sùng bái tột độ người dùng.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 40000 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Quang"], range_type: "Bản thân & AoE Rộng (Thụ động)", combo_tag: "Beast_Divine_Halo" },
        { name: "Bom Hạt Nhân Tinh Thần", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Kích nổ Không gian linh hồn, tạo Big Bang chiều 4. [Hiệu ứng] Hủy diệt mọi ý thức bán kính 1km. Biến mọi kẻ thù thành người thực vật (Não chết, tim đập). [Tác dụng phụ cực lớn] Rơi vào Hôn mê sâu 72 giờ, SPI giảm 80% vĩnh viễn, quên một nửa ký ức cuộc đời.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 100 }, cooldown: { value: 3650, unit: "Ngày", display_text: "10 Năm" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "AoE Rất Rộng (Hủy diệt tối hậu)", combo_tag: "Holy_MindWipe" },
        { name: "Mê Cung Ký Ức", desc: "[Cơ chế] Trích xuất ký ức rời rạc xây dựng Labyrinth. [Hiệu ứng] Giam cầm linh hồn địch vào vòng lặp không gian trong não chúng. Lang thang mãi giữa ký ức mà không tìm thấy lối ra. Thân xác bên ngoài thành cái xác không hồn.", rank: "Kim Giai", cost: { type: "MP", value: 500000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Memory_Labyrinth" },
        { name: "Huyết Mạch Thức Tỉnh: Thần Nhãn", desc: "[Cơ chế] Khai mở Thể Tùng quả (Con mắt thứ ba). [Hiệu ứng] Nhìn thấu thị tuyệt đối. Nhìn xuyên tường thép, lòng đất 100m, thấu lớp tàng hình quang học/ngụy trang ma pháp, và thấy dòng Mana để tìm điểm yếu chí mạng.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 150000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Huyết Mạch"], range_type: "Bản thân (Buff Nhãn thuật tối thượng)", combo_tag: "Divine_Eye" },
        { name: "Dây Xích Linh Hồn", desc: "[Cơ chế] Dùng dây xích ma lực xâu chuỗi bản nguyên sinh mệnh. [Hiệu ứng] Khóa chặt 2 hoặc nhiều mục tiêu. Trong 15 giây, sát thương 1 tên gánh chịu được phân bổ 100% sang toàn bộ những tên bị xích. Đòn chí mạng diệt đội.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Nguyền Rủa"], range_type: "AoE Trung (Liên kết)", combo_tag: "Soul_Chain" },
        { name: "Tái Tạo Ý Chí", desc: "[Cơ chế] Bơm trực tiếp ma lực thuần khiết vào vỏ não. [Hiệu ứng] Hồi phục ngay 50 điểm Sanity cho toàn tổ đội. Đưa những kẻ đang phát điên (Sanity = 0) trở lại trạng thái bình thường (Reset về 50).", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "AoE Trung (Hồi Sanity)", combo_tag: "Will_Restore" },
        { name: "Lệnh Bài Tuyệt Đối", desc: "[Cơ chế] Chèn dòng code thực thi tối cao vào não đối thủ. [Hiệu ứng] Đưa ra mệnh lệnh 1 từ (Quỳ, Dừng, Ngủ). Nếu SPI mục tiêu thấp hơn SPI người dùng * 1.5, chúng bắt buộc thực hiện ngay không thể kháng cự trong 5 giây.", rank: "Kim Giai", cost: { type: "MP", value: 250000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Xa (Khống chế tuyệt đối)", combo_tag: "Absolute_Command" },
        { name: "Cơn Ác Mộng Ban Ngày", desc: "[Cơ chế] Trích xuất nỗi sợ nguyên thủy và vật chất hóa bằng ectoplasm. [Hiệu ứng] Triệu hồi hiện thân thứ kẻ địch sợ nhất. Sinh vật này có sát thương vật lý thực (bằng 30% stats địch) và truy sát mục tiêu đến chết.", rank: "Ngân Giai", cost: { type: "MP", value: 6500 }, cooldown: { value: 20, unit: "Phút", display_text: "20 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Triệu Hồi", "Ảo Giác"], range_type: "Tầm Xa (Triệu hồi nhắm mục tiêu)", combo_tag: "Nightmare_Entity" },
        { name: "Trường Trọng Lực Tinh Thần", desc: "[Cơ chế] Ép sóng脑 tạo áp suất vật lý cục bộ. [Hiệu ứng] Đè nặng không gian bán kính 20m. Trọng lực x10 lần. Kẻ thù bị ép nằm rạp xuống đất, xương sườn gãy vụn, nội tạng tổn thương. Rất tốn MP duy trì.", rank: "Kim Giai", cost: { type: "MP", value: 80000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Vật Lý"], range_type: "AoE Trung (Đè nén/Trọng lực)", combo_tag: "Gravity_Mind" },
        { name: "Hơi Thở Của Thánh Thần", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Kết nối mạng lưới linh hồn tinh cầu (Gaia), ban phát ân trạch sinh mệnh. [Hiệu ứng] Thanh tẩy quy mô Lãnh Địa (10km). Rửa sạch mọi bệnh tật, nguyền rủa, ô nhiễm phóng xạ (Corruption), cứu sống hàng triệu sinh linh. [Tác dụng phụ] Tuổi thọ giảm 50 năm, SPI khóa ở mức Phàm Giai 1 năm.", rank: "Diệu Giai", cost: { type: "HP", value: 75000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Sinh Mệnh", "Quang"], range_type: "AoE Rất Rộng (Cấp Thần Tích)", combo_tag: "Divine_Heal" },
        { name: "Phá Hủy Logic", desc: "[Cơ chế] Gây rối loạn tín hiệu điện của tiểu não và cuống não. [Hiệu ứng] Nạn nhân quên cách hoạt động cơ bản: Quên cách hít thở (ngạt thở), quên cách đứng (ngã gục). Gây tử vong sinh học nếu không có đồng đội giải thuật.", rank: "Kim Giai", cost: { type: "Sanity", value: 20 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Nguyền Rủa"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Logic_Destroy" },
        { name: "Lá Chắn Gương Tâm Linh", desc: "[Cơ chế] Tạo mặt gương ma thuật phản xạ tuyệt đối ở không gian chiều 4. [Hiệu ứng] Phản 100% sát thương và hiệu ứng của BẤT KỲ kỹ năng hệ Tinh Thần/Nguyền rủa nào nhắm vào người dùng (Kể cả Diệu Giai) ngược lại cho kẻ tung chiêu. Tồn tại 5 giây.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Phản đòn tuyệt đối)", combo_tag: "Mirror_Shield" },
        { name: "Hỏa Ngục Tâm Linh", desc: "[Cơ chế] Mô phỏng tín hiệu đau đớn từ thụ thể nhiệt truyền thẳng lên não. [Hiệu ứng] Không có vết xước vật lý, nạn nhân cảm nhận rõ da thịt đang cháy, mỡ sôi dưới ngọn lửa 3000°C. Gây Hoảng Loạn tột độ và sát thương tinh thần khổng lồ.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Ảo Giác"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Mind_Hellfire" },
        { name: "Vùng Tĩnh Lặng Tuyệt Đối", desc: "[Cơ chế] Cắt đứt toàn bộ dây thần kinh cảm giác ngoại biên. [Hiệu ứng] Đẩy mục tiêu vào trạng thái Sensory Deprivation. Đen đặc, im lặng tuyệt đối. Rút 10 Sanity mỗi giây. Nếu ở quá 10s sẽ phát điên.", rank: "Kim Giai", cost: { type: "MP", value: 180000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Lĩnh Vực"], range_type: "AoE Nhỏ (Giam cầm tâm trí)", combo_tag: "Silent_Void" },
        { name: "Đánh Cắp Thiên Phú", desc: "[Cơ chế] Giải mã chuỗi DNA và cấu trúc ma thuật kẻ thù qua sóng não. [Hiệu ứng] Tạm copy 1 kỹ năng (Rank Kim trở xuống) của đối thủ. Có thể xuất chiêu đó ngay với sức mạnh 80% bản gốc. Kỹ năng copy biến mất sau 15 giây.", rank: "Kim Giai", cost: { type: "Sanity", value: 15 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Xa (Copy kỹ năng)", combo_tag: "Talent_Steal" },
        { name: "Cường Hóa Ý Chí (Buff)", desc: "[Cơ chế] Kích thích tuyến yên tiết hormone chiến đấu thần thánh. [Hiệu ứng] Tăng 50% chỉ số SPI cho toàn bộ đồng minh, đồng thời cấp trạng thái [Miễn nhiễm Khống Chế] (Chống choáng, ngủ, hoảng sợ, khiêu khích) trong 30 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Sinh Học"], range_type: "AoE Trung (Buff Đồng minh)", combo_tag: "Willpower_Buff" },
        { name: "Tâm Giao Hợp Nhất", desc: "[Cơ chế] Đồng bộ hóa sóng não Tamer và Sủng Thú mức 100% (Drift). [Hiệu ứng] Tamer chui vào không gian ý thức Pet, điều khiển cơ thể Pet với góc nhìn thứ nhất. Pet sở hữu trí tuệ, kinh nghiệm Tamer. Chỉ số chiến đấu x1.5.", rank: "Kim Giai", cost: { type: "MP", value: 100000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Kết nối Sủng thú)", combo_tag: "Drift_Sync" },
        { name: "Thao Túng Cảm Xúc (Berserk)", desc: "[Cơ chế] Ghi đè vào hạch hạnh nhân, xóa bỏ lý trí. [Hiệu ứng] Bắn tia đỏ vào quái/địch. Khiến chúng sùi bọt mép, nhận buff +100% STR nhưng mất phân biệt địch/ta, lao vào cấu xé đồng đội gần nhất của chúng.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Forced_Berserk" },
        { name: "Minh Kính Chỉ Thủy (Passive)", desc: "[Cơ chế] Cảnh giới tu luyện tâm trí thượng thừa. Tâm như mặt hồ tĩnh lặng. [Hiệu ứng] Miễn nhiễm vĩnh viễn mọi loại ảo ảnh môi trường (Illusion), lời nguyền loạn trí, sương mù độc (Tâm lý). Tốc độ hồi MP tự nhiên tăng gấp đôi.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần"], range_type: "Bản thân (Kháng tính bị động)", combo_tag: "Mind_Immunity" }
    ],
  "Hệ Thủy": [
        { name: "Hóa Hình - Thủy Tiên", desc: "[Cơ chế] Sử dụng áp lực thủy tĩnh để tạo hình khung xương mềm dẻo nhưng vững chắc (Hydro-skeleton). Tế bào da tái cấu trúc thành màng bán thấu. Hệ thần kinh chuyển sang dạng dẫn truyền qua chất lỏng ion hóa. [Hiệu ứng] Nhân dạng uyển chuyển, da trơn bóng. Có cả Phổi và Mang. Cơ thể có thể vặn xoắn kỳ dị chui qua khe hẹp đường kính 5cm. Miễn nhiễm 80% sát thương vật lý cùn (Búa, Chùy). [Tác dụng phụ] Sợ môi trường sa mạc nhiệt độ cực cao, mất nước sẽ giảm 50% toàn bộ chỉ số.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Sinh Học"], range_type: "Bản thân (Chuyển đổi hình thái)", combo_tag: "Form_Water" },
        { name: "Thủy Thể Uyển Chuyển", desc: "[Cơ chế] Xương khớp tự động lỏng ra như chất lỏng khi cảm nhận lưỡi đao bay tới. [Hiệu ứng] Tăng 15% tỉ lệ né tránh (Dodge) đối với các đòn chém ngang/chém dọc của vũ khí sắc bén.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Sinh Học"], range_type: "Bản thân (Bị động né tránh)", combo_tag: "Passive_Fluid_Dodge" },
        { name: "Hấp Thụ Hơi Ẩm", desc: "[Cơ chế] Lỗ chân lông hút sương và hạt mưa tinh khiết. [Hiệu ứng] Khi trời đang mưa, sương mù hoặc lội dưới nước, tự động hồi phục 1% Max HP mỗi 5 giây mà không cần tiêu hao bất kỳ tài nguyên nào.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Bị động hồi máu)", combo_tag: "Passive_Moisture_Heal" },
        { name: "Dòng Chảy Tuần Hoàn", desc: "[Cơ chế] Mô phỏng dòng chảy của sông suối, động năng sinh ra ma lực. [Hiệu ứng] Càng di chuyển liên tục, tốc độ hồi phục Năng lượng (MP) càng tăng nhanh (Lên tới x2 so với lúc đứng yên).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Bị động hồi MP)", combo_tag: "Passive_Flowing_Mana" },
        { name: "Thủy Áp Phản Lực", desc: "[Cơ chế] Da tiết ra đệm nước siêu áp suất khi bị va đập mạnh. [Hiệu ứng] Nhận đòn vật lý chí mạng sẽ tự động chuyển hóa lực ép thành phản lực, trượt cơ thể ra phía sau 5m một cách mượt mà để triệt tiêu 30% sát thương nhận vào.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Bản thân (Bị động giảm xóc)", combo_tag: "Passive_Water_Cushion" },
        { name: "Nhãn Quang Khúc Xạ", desc: "[Cơ chế] Cấu trúc con ngươi mọc thêm một màng lọc nước cực mỏng. [Hiệu ứng] Nhìn rõ ràng mọi vật thể dưới đáy biển sâu không bị mờ. Miễn nhiễm 100% với các hiệu ứng Gây mù quang học (Flashbang/Ánh sáng chói).", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Bị động thị giác)", combo_tag: "Passive_Refraction_Eye" },
        { name: "Màng Nước Tịnh Hóa", desc: "[Cơ chế] Nước sinh học tuần hoàn bao bọc da tự động rửa trôi tạp chất. [Hiệu ứng] Cứ mỗi 15 giây, nội tại tự động gột rửa và xóa bỏ 1 hiệu ứng xấu (Debuff Mù/Độc/Giảm giáp) đang mắc phải trên cơ thể.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Trị Liệu"], range_type: "Bản thân (Bị động giải hiệu ứng)", combo_tag: "Passive_Auto_Cleanse" },
        { name: "Tâm Tĩnh Như Thủy", desc: "[Cơ chế] Sóng não đồng điệu với mặt hồ phẳng lặng. [Hiệu ứng] Kháng hoàn toàn các đòn Khiêu khích (Taunt), Hoảng sợ (Fear) từ quái vật có xếp hạng Cảnh giới thấp hơn mình. Luôn giữ được cái đầu lạnh.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Tinh Thần"], range_type: "Bản thân (Bị động kháng Tinh thần)", combo_tag: "Passive_Calm_Mind" },
        { name: "Bàn Tay Thủy Linh", desc: "[Cơ chế] Lỗ chân lông tay tự động ngưng tụ ẩm đắp lên vũ khí. [Hiệu ứng] Các đòn đánh tay và chém vũ khí luôn kèm theo trạng thái [Ẩm Ướt]. Kẻ địch bị [Ẩm Ướt] sẽ chịu sát thương hệ Lôi x2 và hệ Băng x1.5.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Đòn đánh (Bị động gây Debuff)", combo_tag: "Passive_Wet_Strike" },
        { name: "Kháng Chấn Động Thủy Thể", desc: "[Cơ chế] Chất lỏng trong cơ thể hoạt động như phuộc nhún hấp thụ động năng. [Hiệu ứng] Giảm thiểu 25% sát thương từ mọi đòn tấn công bằng vũ khí cùn (Búa, Chùy, Nắm đấm, Đá đè). Khắc tinh của các Tamer hệ Thổ thiên về đập.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Bản thân (Bị động phòng thủ)", combo_tag: "Passive_Shock_Absorb" },
        { name: "Trực Giác Thủy Triều", desc: "[Cơ chế] Màng nhĩ cảm nhận rung động sóng âm cực nhỏ truyền qua phân tử nước. [Hiệu ứng] Khi lặn dưới nước, tự động phát hiện được phương hướng và tốc độ bơi của mọi sinh vật tàng hình/ẩn nấp trong bán kính 1km.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Môi trường nước (Bị động trinh sát)", combo_tag: "Passive_Tide_Radar" },
        { name: "Phổi Sinh Lưu", desc: "[Cơ chế] Tuyến nước bọt điện phân H2O thành Oxy và Nito trực tiếp. [Hiệu ứng] Khả năng nín thở và chiến đấu dưới nước kéo dài lên đến 2 giờ mà không bị giảm Stamina do ngạt thở. Bơi lội như cá.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Sinh Mệnh"], range_type: "Bản thân (Bị động sinh tồn)", combo_tag: "Passive_Water_Lung" },
        { name: "Dịch Chua Gỉ Sét", desc: "[Cơ chế] Nước bảo vệ cơ thể mang đặc tính oxy hóa kim loại cực mạnh. [Hiệu ứng] Kẻ địch dùng vũ khí kim loại (Kiếm, giáo) chém trúng bạn, vũ khí của chúng sẽ bị rỉ sét ngay lập tức (Giảm 10 điểm Durability/nhát chém).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Độc"], range_type: "Cận chiến (Bị động phá vũ khí)", combo_tag: "Passive_Rust_Sweat" },
        { name: "Hương Đầm Lầy", desc: "[Cơ chế] Tích tụ vi khuẩn nấm có lợi từ bùn nước. [Hiệu ứng] Khi chiến đấu ở khu vực ẩm thấp/đầm lầy, đòn đánh tay ngẫu nhiên mang theo hiệu ứng Độc nhẹ (Trừ 1% HP/giây) khiến kẻ thù suy kiệt.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Độc"], range_type: "Đòn đánh (Bị động môi trường)", combo_tag: "Passive_Swamp_Aura" },
        { name: "Da Trơn Trượt", desc: "[Cơ chế] Lỗ chân lông tiết ra lớp dầu thủy phân liên tục. [Hiệu ứng] Cơ thể như con lươn. Hoàn toàn miễn nhiễm với mọi kỹ năng Khóa siết (Grapple), Bắt lấy (Catch), hoặc Trói bằng dây thừng/xích thường.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Sinh Học"], range_type: "Bản thân (Bị động chống khống chế)", combo_tag: "Passive_Slippery_Skin" },
        { name: "Huyết Lệ Khát Máu", desc: "[Cơ chế] Ma lực Thủy cảm nhận và thao túng lượng nước trong máu kẻ địch. [Hiệu ứng] Gây thêm 15% sát thương chuẩn lên các mục tiêu đang mang trạng thái [Chảy máu] (Bleeding) do đồng đội hoặc bản thân gây ra.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Huyết Mạch"], range_type: "Mục tiêu (Bị động khuếch đại)", combo_tag: "Passive_Blood_Thirst" },
        { name: "Sức Ép Đại Dương", desc: "[Cơ chế] Không khí xung quanh bị đè nặng bởi độ ẩm đậm đặc mang ma lực. [Hiệu ứng] Bất cứ kẻ thù nào đứng trong bán kính 3m đều cảm thấy ngực bị ép chặt, tự động mất 5 Stamina mỗi giây (Gây kiệt sức nhanh chóng trong cận chiến).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Lĩnh Vực"], range_type: "AoE Nhỏ (Bị động trừ Thể lực)", combo_tag: "Passive_Ocean_Pressure" },
        { name: "Bọt Nước Ngưng Tụ", desc: "[Cơ chế] Hạt sương tự động đóng vảy thành màng bong bóng đàn hồi. [Hiệu ứng] Nếu không nhận sát thương trong 15 giây, cơ thể tự động sinh ra một lớp khiên Bọt nước hấp thụ 1 đòn đánh cơ bản bất kỳ của kẻ thù.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Bị động tạo khiên)", combo_tag: "Passive_Bubble_Shield" },
        { name: "Chuyển Hóa Băng Sương", desc: "[Cơ chế] Rã đông tức thời các hạt băng đâm vào cơ thể. [Hiệu ứng] Khắc chế Hệ Băng. Khi nhận sát thương từ ma pháp Hệ Băng, 30% lượng sát thương đó sẽ bị hóa lỏng và chuyển thành HP hồi phục cho bản thân.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Băng"], range_type: "Bản thân (Bị động hấp thụ)", combo_tag: "Passive_Frost_Melt" },
        { name: "Khúc Xạ Tàng Hình", desc: "[Cơ chế] Nước bẻ cong ánh sáng phản chiếu bóng hình. [Hiệu ứng] Khi đứng ngập từ thắt lưng trở xuống trong nước, hình bóng trở nên trong suốt, giảm 50% tầm nhìn phát hiện (Aggro) của quái vật xung quanh.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Ảo Giác"], range_type: "Môi trường nước (Bị động tàng hình)", combo_tag: "Passive_Water_Camouflage" },
        { name: "Lưu Thủy Dẫn Đường", desc: "[Cơ chế] Cắt đứt lực cản không khí cho những người đi phía sau dòng chảy ma pháp. [Hiệu ứng] Đồng đội di chuyển theo vết chân của bạn (trong phạm vi 5m) sẽ được tăng 10% Tốc độ di chuyển. Cực kỳ hữu dụng khi cả đội hình rút lui.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Đồng minh (Bị động hỗ trợ)", combo_tag: "Passive_Flowing_Path" },
        { name: "Thủy Tiễn Đột Phá", desc: "[Cơ chế] Nén nước thành hình mũi khoan xoắn ốc siêu nhỏ. [Hiệu ứng] Bắn đạn nước xuyên phá mọi vật cản mềm như gỗ/thịt, gây sát thương Thủy và làm chậm mục tiêu 10% do cơ thể bị ngấm nước.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Tầm Xa (Xuyên thấu)", combo_tag: "Water_Drill" },
        { name: "Dao Nước Xuyên Khấu", desc: "[Cơ chế] Vung cạnh bàn tay kéo theo dải áp lực nước 10.000 PSI. [Hiệu ứng] Chém đứt giáp da và để lại vết thương rách nát thấm đẫm ma lực Thủy, làm cho các đòn tấn công Lôi/Băng sau đó lên mục tiêu hiệu quả gấp đôi.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Cận Chiến (Tạo Combo)", combo_tag: "Water_Knife" },
        { name: "Bom Nước Áp Lực", desc: "[Cơ chế] Nén lượng lớn nước vào một quả cầu có vỏ bọc sức căng bề mặt cực đại. [Hiệu ứng] Ném cầu nước, khi va chạm sẽ nổ tung tạo sóng xung kích (Knockback) hất văng địch ra 3m và gây sát thương va đập vật lý cùn.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "AoE Nhỏ", combo_tag: "Water_Bomb" },
        { name: "Thủy Tráo Phản Chấn", desc: "[Cơ chế] Bọc cơ thể bằng lớp nước dày hấp thụ động năng. [Hiệu ứng] Hấp thụ 50% sát thương từ một cú chém hoặc đạn nổ. Khi khiên vỡ, nước bắn thẳng vào mắt địch ở gần gây Mù lòa (Blind) trong 1.5 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Phòng thủ nổ)", combo_tag: "Bubble_Shield" },
        { name: "Dòng Chảy Siết Chặt", desc: "[Cơ chế] Triệu hồi dòng nước quấn quanh tứ chi đối phương như rắn. [Hiệu ứng] Trói chân (Root) kẻ địch trong 2 giây. Nếu địch cố di chuyển sẽ bị ngã sấp mặt, cực kỳ hiệu quả chặn các đòn Lao Tới (Charge).", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tầm Trung (Khống chế mềm)", combo_tag: "Water_Bind" },
        { name: "Đạn Nước Liên Thanh", desc: "[Cơ chế] Bắn liên tục các giọt nước có khối lượng bằng sỏi cứng. [Hiệu ứng] Xả 5 viên đạn nước liên tiếp. Gây sát thương tích lũy làm rách bề mặt khiên ma thuật, ép kẻ địch phải ôm đầu phòng ngự.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Tầm Trung (Xả đạn)", combo_tag: "Water_Machinegun" },
        { name: "Thủy Trảo Xé Sóng", desc: "[Cơ chế] Bao bọc móng vuốt bằng dòng xoáy nước tốc độ cao. [Hiệu ứng] Cào cấu gây sát thương chém kết hợp ăn mòn, làm mềm giáp sắt của đối thủ (Giảm 10% DEF tạm thời).", rank: "Phàm Giai", cost: { type: "Stamina", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Cận Chiến (Debuff Giáp)", combo_tag: "Water_Claw" },
        { name: "Hơi Nước Sôi Bỏng", desc: "[Cơ chế] Đun sôi nước cực tốc thành hơi nước 150°C. [Hiệu ứng] Xịt luồng khí nóng vào mặt địch. Bỏ qua mọi giáp vật lý, gây bỏng cấp 2 và mù lòa 2s, làm kẹt các khớp máy móc do giãn nở nhiệt.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 14, unit: "Giây", display_text: "14 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Hỏa"], range_type: "Hình Nón Cận Chiến", combo_tag: "Steam_Burn" },
        { name: "Lốc Nước Cuốn Chân", desc: "[Cơ chế] Vẫy tay tạo dòng xoáy tụ dưới mặt đất. [Hiệu ứng] Tạo một hố xoáy nhỏ dưới chân mục tiêu, làm chúng mất thăng bằng ngã nhào và bị kéo lệch trọng tâm 2m, hủy hoàn toàn kỹ năng niệm chú.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tầm Trung (Ngã ngửa)", combo_tag: "Water_Trip" },
        { name: "Roi Nước Sắc Bén", desc: "[Cơ chế] Ngưng tụ nước thành sợi roi dài 3m với cạnh bén như cước. [Hiệu ứng] Quất roi tầm xa gây rách da tróc thịt. Có thể dùng để quấn lấy chân đối phương lôi chúng lại gần (Pull) phía bản thân.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Cận Chiến Xa (Kéo mục tiêu)", combo_tag: "Water_Whip_Pull" },
        { name: "Đinh Nước Đâm Xuyên", desc: "[Cơ chế] Bắn một giọt nước đóng băng một nửa. [Hiệu ứng] Kim đinh găm thẳng vào khớp gối hoặc cùi chỏ địch. Gây đau đớn nhói buốt, khiến đòn đánh vật lý của chúng bị giảm 20% sát thương vì không thể vung hết lực.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Băng"], range_type: "Tầm Xa (Debuff sát thương)", combo_tag: "Water_Nail" },
        { name: "Bọt Nước Nổ Chậm", desc: "[Cơ chế] Phun bóng nước lơ lửng gắn ma lực bất ổn. [Hiệu ứng] Bãi mìn trôi nổi. Bọt nước lơ lửng trên không trung, bất kỳ ai (kể cả đồng đội) chạm vào sẽ phát nổ gây hất văng và làm ướt sũng trang bị.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Đặt bẫy không gian", combo_tag: "Bubble_Mine" },
        { name: "Thủy Tường Trấn Áp", desc: "[Cơ chế] Kéo một mảng nước lớn dựng đứng lên như tấm khiên. [Hiệu ứng] Chặn hoàn toàn hỏa lực súng nhỏ, dập tắt lửa. Nếu kẻ địch lao qua màng nước này, tốc độ của chúng bị giảm 50% trong 2 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tường Chắn (Tầm Trung)", combo_tag: "Water_Wall_Slow" },
        { name: "Giọt Nước Xuyên Sọ", desc: "[Cơ chế] Nén toàn bộ 30 điểm MP vào đúng một giọt nước cực nặng (100kg). [Hiệu ứng] Ném thẳng vào trán mục tiêu. Không gây rách da mà gây Chấn thương sọ não bằng chấn động thủy lực (Stun 2s tuyệt đối).", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Tầm Trung (Đòn chí mạng)", combo_tag: "Heavy_Drop" },
        { name: "Sương Mù Ngạt Thở", desc: "[Cơ chế] Đẩy hơi ẩm đậm đặc bám dính vào khoang thở. [Hiệu ứng] Bao trùm đầu kẻ địch bằng lớp sương mù đặc quánh. Làm chúng không thể hít thở (Ngạt/Silence), buộc phải lùi lại phá bỏ trạng thái thay vì tấn công.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tầm Trung (Đơn mục tiêu)", combo_tag: "Suffocate_Mist" },
        { name: "Cột Nước Phá Trận", desc: "[Cơ chế] Ép nước trào lên từ lòng đất tại một điểm chỉ định. [Hiệu ứng] Phun cột nước cao 3m thẳng từ dưới đũng quần kẻ địch hất chúng văng lên không trung (Knock-up), phá vỡ hàng lá chắn bảo vệ.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Nhỏ (Dưới chân mục tiêu)", combo_tag: "Water_Geyser_Strike" },
        { name: "Trượt Nước Xung Phong", desc: "[Cơ chế] Trải thảm nước trơn trượt dưới chân để khử ma sát. [Hiệu ứng] Trượt lao về phía trước với tốc độ gấp 3 lần bình thường (Charge). Lấy đà đâm chùy/kiếm vào địch gây sát thương Xuyên Giáp khổng lồ.", rank: "Phàm Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Di chuyển"], range_type: "Đường thẳng (Lao tới)", combo_tag: "Water_Slide_Charge" },
        { name: "Màng Nước Phân Tán", desc: "[Cơ chế] Phủ lớp sương mỏng lên toàn bộ tổ đội. [Hiệu ứng] Buff AoE nhẹ. Giảm 10% sát thương phép nhận vào và miễn nhiễm với trạng thái [Bỏng] cho cả nhóm trong vòng 10 giây.", rank: "Phàm Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Rộng (Buff Đồng minh)", combo_tag: "AoE_Water_Coat" },
        { name: "Thủy Đao Cận Chiến", desc: "[Cơ chế] Nước đọng lại trên lưỡi kiếm vật lý. [Hiệu ứng] Tăng tầm chém thêm 20cm. Vết chém của kiếm xả ra dòng nước cắt đứt tĩnh mạch đối phương, gây chảy máu và Trọng Thương (Giảm khả năng hồi máu).", rank: "Thiết Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Cận Chiến (Buff vũ khí)", combo_tag: "Water_Enchant_Blade" },
        { name: "Mưa Sát Thương", desc: "[Cơ chế] Gọi đám mây nhỏ thả mưa rào ngay trên đỉnh đầu đội hình địch. [Hiệu ứng] Cơn mưa làm ướt sũng đạn pháo thuốc súng (Gây tịt ngòi), giảm tầm nhìn và liên tục gây sát thương nhỏ bào mòn sinh lực phe địch.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Trung", combo_tag: "Damage_Rain" },
        { name: "Thủy Pháo Cao Áp", desc: "[Cơ chế] Nén nước từ môi trường thành tia nhỏ li ti với áp suất 50.000 PSI. [Hiệu ứng] Bắn ra tia nước cắt đứt đôi bức tường bê tông cốt thép dày 50cm hoặc chẻ đôi khiên vật lý của xe bọc thép. Tầm bắn 20m, lực đẩy lùi (Knockback) cực mạnh. [Tương tác] Hiệu quả giảm khi bắn dưới nước.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Đường thẳng (Tầm Trung)", combo_tag: "Water_Cannon" },
        { name: "Màng Nước Hộ Thân", desc: "[Cơ chế] Phủ một lớp nước đàn hồi cao quanh cơ thể, chuyển động tuần hoàn liên tục. [Hiệu ứng] Phân tán động năng. Hấp thụ 40% sát thương từ đòn đánh vật lý và đạn xé. Tự động làm tắt lửa, kháng 60% sát thương hệ Hỏa. Duy trì trong 30 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Phòng thủ)", combo_tag: "Water_Shield" },
        { name: "Thủy Lao Giam Cầm", desc: "[Cơ chế] Rút độ ẩm không khí tạo thành quả cầu nước mật độ cao, bọc kín mục tiêu. [Hiệu ứng] Nhốt một kẻ địch (kích thước người/sói) lơ lửng giữa không trung. Đối phương không có điểm tựa để phá vỡ, bị ngạt thở (trừ HP mỗi giây) và vô hiệu hóa hoàn toàn di chuyển trong 15 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tầm Xa (Khống chế cứng)", combo_tag: "Water_Prison" },
        { name: "Thủy Tiễn Vô Hình", desc: "[Cơ chế] Chiết xuất nước siêu tinh khiết, lọc sạch tạp chất để đạt độ trong suốt 100%. [Hiệu ứng] Bắn mũi tên nước với vận tốc âm thanh. Bằng mắt thường không thể thấy. Xuyên thấu yết hầu kẻ thù không để lại tiếng động. Kỹ năng ám sát hoàn hảo.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tầm Xa (Ám sát)", combo_tag: "Invisible_Arrow" },
        { name: "Suối Nguồn Tươi Trẻ (Hồi phục)", desc: "[Cơ chế] Nước mang ma lực sự sống kích thích tế bào phân chia nhanh chóng. [Hiệu ứng] Rải một cơn mưa bụi màu xanh nhạt bán kính 10m. Rửa trôi mọi chất độc (Hóa học/Sinh học), hồi phục 30% HP cho toàn đội và làm liền miệng các vết thương hở sâu.", rank: "Kim Giai", cost: { type: "MP", value: 80000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Sinh Mệnh"], range_type: "AoE Trung (Hồi phục đồng minh)", combo_tag: "Healing_Spring" },
        { name: "Sương Mù Dày Đặc", desc: "[Cơ chế] Hóa hơi nước diện rộng ở nhiệt độ phòng. [Hiệu ứng] Phủ kín một khu vực 50x50m bằng sương mù đặc quánh. Tầm nhìn giảm xuống < 1m. Hơi ẩm cao làm thuốc súng địch tịt ngòi, cung nỏ dãn dây, giấy bùa ma thuật bị mủn.", rank: "Thiết Giai", cost: { type: "MP", value: 120 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Khí"], range_type: "AoE Rộng (Che khuất)", combo_tag: "Dense_Fog" },
        { name: "Thủy Phân Thân", desc: "[Cơ chế] Dùng nước làm khuôn đúc, đưa ma lực vào để điều khiển. [Hiệu ứng] Tạo 1 bản sao giống hệt 100%. Đánh lừa thị giác. Khi bị chém trúng, bản sao nổ tung thành sóng xung kích nước gây sát thương (Sát thương = 50% INT người dùng).", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Ảo Giác"], range_type: "Bản thân (Phân thân)", combo_tag: "Water_Clone" },
        { name: "Thủy Đao", desc: "[Cơ chế] Vòng xoáy nước siêu tốc quanh lưỡi dao vô hình hoặc cạnh bàn tay. [Hiệu ứng] Áp lực nước tạo ra vết cắt siêu bén, chém sắt như chém bùn. Đánh trúng sẽ làm nước xâm nhập vết thương, xé rách cơ bắp từ bên trong.", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Cận Chiến", combo_tag: "Water_Blade" },
        { name: "Sóng Thần Mini", desc: "[Cơ chế] Cuộn trào dòng chảy từ dưới mặt đất hoặc nguồn nước gần đó. [Hiệu ứng] Triệu hồi con sóng lớn cao 3m càn quét diện rộng trước mặt. Làm ngã toàn bộ kẻ địch có trọng lượng nhỏ/vừa, cuốn trôi chướng ngại vật và dập tắt lửa diện rộng.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Hình Nón Rộng (AoE Trung)", combo_tag: "Mini_Tsunami" },
        { name: "Hút Nước (Hủy diệt)", desc: "[Cơ chế] Đảo ngược thẩm thấu cấp độ tế bào. [Hiệu ứng] Hút cạn mọi chất lỏng (nước bọt, máu, dịch tủy) trong cơ thể sinh vật bán kính 10m. Kẻ địch khô quắt lại như xác ướp nghìn năm, nhận lượng sát thương chuẩn cực lớn bỏ qua giáp.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Nguyền Rủa"], range_type: "AoE Trung (Hủy diệt sinh học)", combo_tag: "Dehydrate" },
        { name: "Lọc Nước Sinh Tồn (Sinh hoạt)", desc: "[Cơ chế] Dùng màng lọc ma lực phân tách phân tử H2O. [Hiệu ứng] Biến nước đầm lầy độc hại, nước biển, nước tiểu thành nước uống tinh khiết ngọt ngào ngay lập tức. Cần thiết để sinh tồn trong Hoang Khu dài ngày.", rank: "Phàm Giai", cost: { type: "MP", value: 10 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tiện ích (Tiếp xúc)", combo_tag: "Purify_Water" },
        { name: "Mưa Axit", desc: "[Cơ chế] Bơm mana hệ Thủy kết hợp khí Sulfur trong không khí. [Hiệu ứng] Thay đổi độ pH của mưa. Gọi xuống cơn mưa màu xanh lục bán kính 20m. Ăn mòn giáp kim loại (Trừ 50 DEF mỗi 5 giây) và làm lở loét da thịt địch liên tục.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Độc"], range_type: "AoE Trung (Debuff Môi trường)", combo_tag: "Acid_Rain" },
        { name: "Lưới Nước Bắt Giữ", desc: "[Cơ chế] Trộn nước với ma lực tạo độ nhớt cao (như keo). [Hiệu ứng] Phóng tấm lưới nước đường kính 4m. Co giãn siêu dai, trói chặt mục tiêu. Kẻ thù dùng vũ khí chém vào chỉ lún xuống chứ không đứt. Giữ chân 10 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tầm Xa (Trói buộc)", combo_tag: "Water_Net" },
        { name: "Gương Thủy Cảnh", desc: "[Cơ chế] Kéo căng bề mặt nước tĩnh để phản xạ năng lượng quang học. [Hiệu ứng] Tạo tấm khiên phẳng trước mặt. Phản xạ lại 100% các đòn tấn công dạng chùm tia (Laser, Light Beam) hoặc phép thuật hệ Quang, bắn ngược về kẻ địch.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Quang"], range_type: "Bản thân (Khiên Phản Xạ)", combo_tag: "Water_Mirror" },
        { name: "Thủy Dực", desc: "[Cơ chế] Tạo kết cấu cánh khí động học từ nước áp suất cao. [Hiệu ứng] Mọc ra cánh nước trong suốt dài 3m sau lưng. Giúp bay lượn trên không trong 10 phút, hoặc bơi dưới đại dương với tốc độ tàu ngầm (Mach 0.5).", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Phong"], range_type: "Bản thân (Di chuyển)", combo_tag: "Water_Wings" },
        { name: "Cột Nước Thăng Thiên", desc: "[Cơ chế] Đảo ngược dòng chảy trọng lực của nước. [Hiệu ứng] Đẩy một cột nước khổng lồ từ dưới chân lên. Đưa toàn bộ đội hình vọt lên độ cao 50m. Dùng để vượt tường thành, né đòn diện rộng hoặc hất văng địch lên không.", rank: "Thiết Giai", cost: { type: "MP", value: 400 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Nhỏ (Dưới chân)", combo_tag: "Water_Geyser" },
        { name: "Bong Bóng Oxy (Hỗ trợ)", desc: "[Cơ chế] Tách O2 từ nước và nhốt vào màng bong bóng linh hoạt. [Hiệu ứng] Tạo mũ dưỡng khí bao quanh đầu đồng đội. Giúp hô hấp bình thường dưới đáy biển sâu hoặc trong môi trường khí gas độc hại trong 3 giờ.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Cận Chiến (Buff Đồng minh)", combo_tag: "O2_Bubble" },
        { name: "Đóng Băng Tạm Thời", desc: "[Cơ chế] Hút nhiệt lượng đột ngột từ khối nước dưới chân. [Hiệu ứng] Khi chân kẻ địch đang dẫm vào vũng nước, hạ nhiệt độ tức thời khiến vũng nước đông đá, khóa chặt chân chúng vào mặt đất trong 5 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Băng"], range_type: "Tầm Trung (Điều kiện: Có nước)", combo_tag: "Flash_Freeze" },
        { name: "Hòa Tan (Nội tại)", desc: "[Cơ chế] Đồng hóa chỉ số khúc xạ ánh sáng của cơ thể với nước. [Hiệu ứng] Tàng hình hoàn toàn 100% khi cơ thể ngập dưới nước hoặc đứng trong mưa to. Xóa bỏ nhiệt lượng và mùi cơ thể.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Ảo Giác"], range_type: "Bản thân (Tàng hình bị động)", combo_tag: "Water_Camouflage" },
        { name: "Cảm Biến Dòng Chảy", desc: "[Cơ chế] Cảm nhận rung động vi mô của phân tử H2O. [Hiệu ứng] Phát hiện chuyển động, vị trí của mọi kẻ thù trong bán kính 1km thông qua gợn sóng dưới nước, hoặc độ ẩm thay đổi trong không khí trên cạn (như mồ hôi địch).", rank: "Thiết Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Rộng (Định vị)", combo_tag: "Water_Radar" },
        { name: "Giặt Giũ Siêu Tốc (Sinh hoạt)", desc: "[Cơ chế] Tạo luồng xoáy vi mô bóc tách bụi bẩn khỏi sợi vải. [Hiệu ứng] Làm sạch bong quần áo, tẩy rửa sạch vết máu bám trên giáp, đánh bay mùi hôi trong 3 giây. Tránh bị quái vật khứu giác nhạy truy lùng.", rank: "Phàm Giai", cost: { type: "MP", value: 5 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Tiện ích)", combo_tag: "Cleanse_Odor" },
        { name: "Roi Nước", desc: "[Cơ chế] Nước đọng thành dây roi bện, đầu roi sắc như kim. [Hiệu ứng] Vũ khí tầm trung (5m). Quất xé rách da thịt gây đau đớn. Có thể linh hoạt quấn lấy vũ khí đối phương và giật mạnh để tước vũ khí.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Tầm Trung (Vũ khí ma thuật)", combo_tag: "Water_Whip" },
        { name: "Thuyền Nước", desc: "[Cơ chế] Cô đặc bề mặt nước thành bệ đỡ vững chắc. [Hiệu ứng] Tạo ván trượt/thuyền nhỏ bằng nước cứng. Di chuyển tự động trên sông, hồ với tốc độ cano cao tốc mà không cần mái chèo hay động cơ.", rank: "Phàm Giai", cost: { type: "MP", value: 80 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tiện ích (Di chuyển)", combo_tag: "Water_Boat" },
        { name: "Bơm Nước Cứu Hỏa", desc: "[Cơ chế] Hút nước từ không gian và xả ra diện rộng. [Hiệu ứng] Phun lượng lớn nước như vòi rồng. Dập tắt lập tức các đám cháy rừng lớn, phá vỡ trận pháp hệ Hỏa cấp thấp và dọn đường an toàn.", rank: "Phàm Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Hình Nón Rộng", combo_tag: "Fire_Extinguish" },
        { name: "Thủy Lực Nâng Đỡ", desc: "[Cơ chế] Áp dụng nguyên lý Pascal nâng vật nặng. [Hiệu ứng] Tạo các 'kích thủy lực' ma thuật dưới mặt đất. Dùng sức nước nâng tảng đá hàng chục tấn, xe cộ bị lật, hoặc mở các cánh cổng di tích siêu nặng.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Cận Chiến (Tương tác vật lý)", combo_tag: "Hydraulic_Lift" },
        { name: "Bom Hơi Nước", desc: "[Cơ chế] Đun sôi nước đột ngột rồi khóa kín trong màng nước lạnh, chờ nổ. [Hiệu ứng] Quả bom nổ tung thả ra hơi nước 500°C. Gây bỏng hô hấp diện rộng. Nướng chín kẻ thù mặc giáp kín vì hơi nóng lọt qua khe giáp.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Hệ Hỏa"], range_type: "AoE Trung (Ném)", combo_tag: "Steam_Bomb" },
        { name: "Hút Ẩm Sấy Khô", desc: "[Cơ chế] Hút sạch H2O lơ lửng trong không khí. [Hiệu ứng] Biến môi trường hang động ẩm mốc thành khô ráo tuyệt đối. Ngăn chặn nấm mốc bào tử Vùng Zero sinh sôi, bảo quản vũ khí không bị rỉ sét.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Trung (Tiện ích)", combo_tag: "Dehumidify" },
        { name: "Mực Nước Đánh Dấu", desc: "[Cơ chế] Phun chất lỏng có cấu trúc ma lực phát quang đặc biệt. [Hiệu ứng] Bắn chất lỏng có mùi/màu đặc trưng (Vô hình dưới ánh sáng thường). Đánh dấu lên người mục tiêu để thú săn dễ dàng truy vết từ khoảng cách 100km.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Tầm Trung (Đánh dấu)", combo_tag: "Water_Mark" },
        { name: "Điều Khiển Máu (Cấm thuật)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Huyết Thuật tối thượng. Thao túng trực tiếp phân tử nước (70%) bên trong cơ thể sinh vật sống. [Hiệu ứng] Bóp nghẹt hàng vạn trái tim cùng lúc. Rút máu kẻ thù qua lỗ chân lông tạo thành vũ khí, hoặc ép máu sôi lên nổ tung nội tạng. Giết chết mọi sinh vật có máu. [Tác dụng phụ cực lớn] Người dùng bị phản phệ huyết mạch. Max HP giảm 80% vĩnh viễn, máu bản thân trở nên độc hại. Mỗi lần dùng trừ 50 Sanity, rủi ro biến thành Huyết Quỷ (Mất nhân tính).", rank: "Thánh Giai", cost: { type: "Sanity", value: 50 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Sinh Mệnh", "Huyết Mạch"], range_type: "AoE Rất Rộng (Cấp Thảm Họa)", combo_tag: "Blood_Control" },
        { name: "Hóa Hình - Lưu Thủy (Đặc Biệt)", desc: "[Cơ chế] Thú hệ Thủy hòa tan xương thịt thành nước tinh khiết. [Hiệu ứng] Cơ thể tan chảy thành dòng nước trong suốt, len lỏi trên mặt đất rồi tái tạo lại dưới hình dáng con người. Uyển chuyển tuyệt đối, giấu giếm hoàn toàn sinh khí và nhịp tim. Lẻn vào pháo đài dễ dàng.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 50000 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Sinh Học"], range_type: "Bản thân (Ngụy trang)", combo_tag: "Beast_Liquid_Form" },
        { name: "Thủy Pháo Áp Suất", desc: "[Cơ chế] Nén nước trong khoang phổi thứ 2, dùng cơ hoành ép bắn ra. [Hiệu ứng] Tia nước đường kính lớn bắn với lực va chạm mạnh như xe tải (100 tấn). Xuyên thấu thủng cả thép tấm 5cm, đánh bay mục tiêu văng xa hàng chục mét.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Đường thẳng (Xuyên thấu)", combo_tag: "Pressure_Cannon" },
        { name: "Màng Nước Vô Hình", desc: "[Cơ chế] Da thú tiết ra chất nhờn thủy phân liên tục. [Hiệu ứng] Tạo lớp khiên nước trơn trượt bao bọc cơ thể. Đòn đánh vật lý có 30% tỉ lệ trượt (Miss). Hấp thụ 30% sát thương ma pháp nguyên tố.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Phòng thủ bị động)", combo_tag: "Slippery_Shield" },
        { name: "Dòng Chảy Xoáy", desc: "[Cơ chế] Xoay vòng đuôi/chân để tạo lốc nước tại chỗ. [Hiệu ứng] Tạo lốc xoáy nước khổng ngay dưới chân đội hình địch. Hút tất cả tụ lại một điểm, trói chân, làm ngạt thở và choáng váng trong 10 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Trung (Hút/Khống chế)", combo_tag: "Whirlpool_Trap" },
        { name: "Thủy Tiễn Đoạt Mạng", desc: "[Cơ chế] Phun ngầm từ miệng hoặc lỗ mũi thú. [Hiệu ứng] Bắn ra hàng loạt mũi tên nước vô hình với tốc độ siêu thanh. Xuyên phá điểm yếu (mắt, cổ họng) của kẻ thù. Gây chí mạng (Critical) nếu đánh lén.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "Tầm Xa (Đa mục tiêu)", combo_tag: "Lethal_Water_Arrow" },
        { name: "Trị Liệu Dòng Suối", desc: "[Cơ chế] Liếm vết thương bằng nước bọt mang ma lực Thủy mộc. [Hiệu ứng] Sử dụng dòng nước tinh khiết bao bọc đồng đội. Rửa trôi mọi hiệu ứng xấu (Debuff), hóa giải độc tố, khôi phục vết thương hở (10% HP mỗi 5 giây, kéo dài 15 giây).", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Sinh Mệnh"], range_type: "Cận Chiến (Hồi phục đồng đội)", combo_tag: "Stream_Heal" },
        { name: "Vũ Điệu Hơi Nước", desc: "[Cơ chế] Tăng nhiệt độ cơ thể để bốc hơi lượng nước bám trên lông vảy. [Hiệu ứng] Bốc hơi nước tạo thành sương mù nhiệt (Thermal fog) dày đặc. Che khuất tầm nhìn và làm nhiễu sóng radar/cảm biến nhiệt của máy bay UHA.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Khí"], range_type: "AoE Rộng (Ngụy trang)", combo_tag: "Thermal_Fog" },
        { name: "Thủy Phân Thân (Săn mồi)", desc: "[Cơ chế] Phun bọt nước đúc thành hình nộm con mồi hoặc chính mình. [Hiệu ứng] Bản sao tự động chạy tán loạn, phát ra tiếng động và mùi hương thu hút sự chú ý của kẻ địch. Tồn tại 5 phút làm mồi nhử hoàn hảo.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Ảo Giác"], range_type: "Triệu Hồi (Bản sao)", combo_tag: "Decoy_Clone" },
        { name: "Thủy Đao Phanh Thây", desc: "[Cơ chế] Vòi nước phun áp lực cực đại từ vuốt trước. [Hiệu ứng] Hoạt động như máy cắt kim loại bằng nước công nghiệp. Dùng vòi nước áp lực cực lớn như một lưỡi dao chém đứt bay đầu, cắt lìa tay chân địch sắc gọn.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Cận Chiến (Sát thương chuẩn)", combo_tag: "Water_Guillotine" },
        { name: "Sóng Thần", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Giao thoa ma lực với thủy triều đại dương/hồ lớn. [Hiệu ứng] Triệu hồi bức tường nước cao 100m, quét sạch vạn vật. Nhấn chìm thành trì, phá hủy hệ sinh thái. [Tác dụng phụ] Hút cạn 90% HP, bị nguyền rủa bởi oan hồn chết đuối (Giảm 30 Luck vĩnh viễn), đau nhức xương cốt mỗi khi trời mưa.", rank: "Diệu Giai", cost: { type: "HP", value: 65000 }, cooldown: { value: 60, unit: "Ngày", display_text: "60 Ngày" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Cực Rộng (Cấp Thảm Họa)", combo_tag: "Divine_Tsunami" },
        { name: "Hấp Thủy Hạch", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Nuốt chửng linh mạch hệ Thủy của vùng đất. [Hiệu ứng] Rút cạn hơi nước, biến Lãnh thổ bán kính 50km thành sa mạc chết. Mọi sinh vật bốc hơi thành cát bụi vì mất nước. [Tác dụng phụ] Rơi vào 'Siêu Đói Khát', nội tạng tổn thương, mất khả năng dùng kỹ năng hệ Thủy 3 tháng, giảm 20% Max HP vĩnh viễn.", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 2000000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Sinh Mệnh", "Thổ"], range_type: "AoE Cực Rộng (Thay đổi Địa hình)", combo_tag: "Desert_Maker" },
        { name: "Lệ Thủy Chấn Mộng", desc: "[Cơ chế] Ngưng tụ giọt nước bằng áp lực linh hồn (Thủy + Tinh thần). [Hiệu ứng] Bắn ra một giọt nước siêu nặng (1 tấn). Va chạm không nổ mà phát ra sóng siêu âm chấn động thẳng vào tinh thần. Trừ Sanity và gây câm lặng (Silence) trong 15 giây.", rank: "Kim Giai", cost: { type: "MP", value: 180000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Tinh Thần"], range_type: "Tầm Xa (Sát thương Tinh thần)", combo_tag: "Water_Mind_Shock" },
        { name: "Mưa Axi-Thủy", desc: "[Cơ chế] Phun nọc độc lên mây trời. [Hiệu ứng] Tạo cơn mưa màu tím nhạt diện rộng (100m). Tính axit ăn mòn áo giáp (Trừ 50 DEF mỗi 5 giây), làm tan chảy vũ khí và thiêu đốt da thịt mục tiêu chừng nào còn đứng dưới mưa.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Độc"], range_type: "AoE Rộng (Debuff Ăn mòn)", combo_tag: "Toxic_Rain" },
        { name: "Lưới Nước Tinh Cấp", desc: "[Cơ chế] Tuyến nhện nước tiết dịch siêu dính. [Hiệu ứng] Phun tấm lưới nước khổng lồ (10x10m) siêu dai. Dập lửa lập tức. Trói chặt nhóm mục tiêu, kẻ nào vùng vẫy càng mạnh lưới càng siết chặt làm gãy xương.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Nhỏ (Trói cứng)", combo_tag: "Super_Water_Net" },
        { name: "Gương Thủy Cảnh (Phản Chấn)", desc: "[Cơ chế] Nước tạo thành mặt cầu lồi hội tụ ánh sáng. [Hiệu ứng] Tạo mặt gương nước khổng lồ che chắn toàn đội. Phản xạ lại 100% sát thương của 1 đòn tấn công năng lượng tối thượng (Beam, Laser) thẳng vào mặt kẻ tấn công, sau đó gương vỡ.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy", "Quang"], range_type: "Bản thân & Đồng minh (Phản đòn tuyệt đối)", combo_tag: "Ultimate_Reflection" },
        { name: "Thủy Dực Tiên Phong", desc: "[Cơ chế] Biến đổi vây lưng/tay thành cấu trúc cánh rẽ nước. [Hiệu ứng] Lướt đi trong môi trường ẩm/nước với tốc độ cực quang. Xé toạc dòng chảy, lao thẳng vào đối phương với cú húc (Charge) gây choáng vật lý cực mạnh.", rank: "Ngân Giai", cost: { type: "Stamina", value: 1800 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Đường thẳng (Lao tới/Charge)", combo_tag: "Water_Charge" },
        { name: "Cột Nước Giáp Trận", desc: "[Cơ chế] Hút nước ngầm và phun trào như mạch nước phun cực mạnh. [Hiệu ứng] Cột nước đường kính 5m đột ngột bắn lên từ lòng đất. Hất văng mục tiêu hạng nặng (Voi, Mecha) lên không trung 30m, rơi xuống chịu sát thương vật lý (Fall Damage).", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy"], range_type: "AoE Nhỏ (Dưới chân mục tiêu)", combo_tag: "Heavy_Geyser" },
        { name: "Thủy Ngục Giam Cầm", desc: "[Cơ chế] Rút không khí ra khỏi khối nước, tăng áp suất cục bộ. [Hiệu ứng] Nhốt kẻ địch vào một khối cầu nước trôi nổi. Áp suất bên trong tăng lên mức dưới đáy rãnh Mariana, nghiền nát xương và nổ tung phổi kẻ địch sau 10 giây.", rank: "Kim Giai", cost: { type: "MP", value: 250000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Vật Lý"], range_type: "Tầm Xa (Tử hình)", combo_tag: "Water_Execution" },
        { name: "Ngưng Tụ Băng (Chuyển Hệ)", desc: "[Cơ chế] Đột ngột thay đổi nhiệt độ môi trường quanh khối nước. [Hiệu ứng] Giảm nhiệt độ dòng nước để đóng băng vũ khí hoặc chân kẻ thù khi chúng đang dẫm dưới nước. Chuyển hóa môi trường nước thành bẫy băng.", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thủy", "Băng"], range_type: "Môi trường nước (Khống chế)", combo_tag: "Water_to_Ice" },
        { name: "Hòa Tan Bản Thể (Bị Động)", desc: "[Cơ chế] Cơ thể chứa 99% là nước ma thuật. [Hiệu ứng] Khi lặn xuống nước, cơ thể lập tức hòa tan, vô hình 100% (Không thể bị target). Tốc độ phục hồi HP/MP tăng gấp 5 lần. Chỉ hiện hình khi tấn công hoặc rời khỏi nước.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thủy"], range_type: "Bản thân (Tàng hình/Hồi phục bị động)", combo_tag: "Beast_Water_Melt" }
    ],
  "Hệ Băng": [
        { name: "Hóa Hình - Băng Cơ", desc: "[Cơ chế] Ngừng quá trình trao đổi chất nóng, chuyển sang 'bảo quản lạnh'. Máu thay bằng tinh thể lỏng xanh nhạt. Tim rung động truyền xung lạnh. Não là mạng lưới băng tinh thể siêu dẫn. [Hiệu ứng] Da trắng bệch, lạnh như tử thi. Vết thương không chảy máu mà nứt vỡ như kính rồi tự hàn gắn. Miễn nhiễm đau đớn/sợ hãi. [Tác dụng phụ] Nhạy cảm với Hỏa, giảm 10% tốc độ ở môi trường nóng.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Sinh Học"], range_type: "Bản thân (Chuyển đổi hình thái)", combo_tag: "Form_Ice" },
        { name: "Phi Tiêu Băng Trác", desc: "[Cơ chế] Đóng băng hơi ẩm nén lại thành ngôi sao sắc lạnh. [Hiệu ứng] Phóng phi tiêu bằng băng. Gây sát thương vật lý lai ma pháp. Khi đâm trúng sẽ vỡ vụn làm khu vực vết thương tê cóng (Giảm 10% Tốc đánh).", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 4, unit: "Giây", display_text: "4 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Tầm Xa (Gây Tê nhẹ)", combo_tag: "Ice_Dart" },
        { name: "Máu Băng Sương", desc: "[Cơ chế] Huyết cầu mang tinh thể băng giá. Máu chảy chậm và cực lạnh. [Hiệu ứng] Không bao giờ bị trúng Độc lan truyền qua máu (Như nọc rắn/Ký sinh trùng) vì máu đông đặc lại ngay lập tức bao bọc lấy chất độc cản phát tán.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Sinh Học"], range_type: "Bản thân (Bị động kháng Độc máu)", combo_tag: "Passive_Frost_Blood" },
        { name: "Trái Tim Băng Giá", desc: "[Cơ chế] Cảm xúc bị phong bế cùng với nhịp đập trái tim. [Hiệu ứng] Trạng thái tinh thần (Sanity) không bao giờ bị giảm khi chứng kiến ảo cảnh máu me hay bị khiêu khích chửi bới. Luôn trong trạng thái tĩnh lặng sát thủ.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Tinh Thần"], range_type: "Bản thân (Bị động ổn định Lý trí)", combo_tag: "Passive_Cold_Heart" },
        { name: "Hàn Khí Bức Người", desc: "[Cơ chế] Nhiệt độ cơ thể phát ra âm độ tạo sương mờ. [Hiệu ứng] Bất kỳ sinh vật cấp Phàm Giai (Côn trùng, rắn rết hoang dã) đến gần bán kính 2m sẽ tự động chết cóng rụng lả tả. Ngăn chặn bầy đàn quấy rối.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Xung quanh (Bị động sát thương nhỏ)", combo_tag: "Passive_Chill_Aura" },
        { name: "Giáp Băng Tự Động", desc: "[Cơ chế] Hơi nước mồ hôi tự đóng băng tạo vảy sừng khi nhận đòn. [Hiệu ứng] Khi bị tập kích bất ngờ (Không kịp Đỡ/Parry), lớp da tự kết băng sương cực cứng ngay tại điểm chạm, hấp thụ 20% sát thương đòn đâm chém.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Bản thân (Bị động tạo giáp)", combo_tag: "Passive_Auto_Ice_Hide" },
        { name: "Dấu Chân Trơn Trượt", desc: "[Cơ chế] Bước đi để lại sương giá đọng tinh thể trơn như gương. [Hiệu ứng] Kẻ địch đuổi theo ngay sau lưng dẫm vào dấu chân sẽ bị mất thăng bằng ngã dập mặt, cực tốt cho việc chạy trốn hoặc câu giờ (Kiting).", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Đường đi (Bị động bẫy)", combo_tag: "Passive_Slick_Trail" },
        { name: "Đông Đặc Vết Thương", desc: "[Cơ chế] Máu lỏng rỉ ra tự đông đá thành khối băng bịt kín. [Hiệu ứng] Không bao giờ bị trạng thái [Chảy Máu Liên Tục]. Vết thương tự hàn kín ngay lập tức dù bị rìu chặt hay súng bắn xuyên thấu.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Sinh Học"], range_type: "Bản thân (Bị động cầm máu)", combo_tag: "Passive_Freeze_Wound" },
        { name: "Kháng Băng Thể", desc: "[Cơ chế] Cấu trúc tế bào chịu được nhiệt độ 0 tuyệt đối mà không vỡ. [Hiệu ứng] Giảm thiểu 50% mọi sát thương nhận vào từ các kỹ năng Băng Hệ. Đi giữa bão tuyết Lãnh nguyên không mất Thể lực/Máu.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Môi Trường"], range_type: "Bản thân (Bị động kháng thời tiết)", combo_tag: "Passive_Ice_Resist" },
        { name: "Hô Hấp Băng Hà", desc: "[Cơ chế] Thở ra sương giá, làm đông cứng hạt bụi bẩn thành tinh thể rớt xuống. [Hiệu ứng] Phổi lọc hoàn hảo các loại bụi mù che mắt (Hệ Thổ) và khí độc (Hệ Độc) bay trong không khí, vô hiệu hóa các trận pháp sương độc.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Khí"], range_type: "Bản thân (Bị động thanh lọc)", combo_tag: "Passive_Frost_Lung" },
        { name: "Mắt Kính Băng", desc: "[Cơ chế] Màng giác mạc đóng lớp băng siêu mỏng phân tán ánh sáng chói. [Hiệu ứng] Miễn nhiễm với trạng thái Mù lòa (Blind) bởi kỹ năng hệ Quang hoặc lựu đạn sáng. Nhìn rõ đường gân băng dưới lớp tuyết.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Quang"], range_type: "Bản thân (Bị động thị giác)", combo_tag: "Passive_Ice_Lens" },
        { name: "Lãnh Cảm Cơn Đau", desc: "[Cơ chế] Hệ thần kinh dẫn truyền đau đớn bị đóng băng. [Hiệu ứng] Nhận sát thương đứt tay chân mà khuôn mặt vẫn vô cảm. Không bị hoảng sợ lùi bước, luôn duy trì 100% Sức mạnh tấn công dù HP chỉ còn 1%.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Tinh Thần"], range_type: "Bản thân (Bị động vô cảm)", combo_tag: "Passive_Numb_Pain" },
        { name: "Nứt Gãy Nhiệt Độ", desc: "[Cơ chế] Chênh lệch nhiệt độ cực đại gây vỡ vụn vật chất. [Hiệu ứng] Khi kẻ địch đang mang trạng thái [Bỏng] (Hệ Hỏa), các đòn đánh thường hệ Băng của bạn gây thêm 30% Sát thương Bạo Kích Bẻ Gãy xương chúng.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Hỏa"], range_type: "Đòn đánh (Bị động kích nổ hiệu ứng)", combo_tag: "Passive_Thermal_Shock" },
        { name: "Sương Mù Che Giấu", desc: "[Cơ chế] Tản nhiệt độ âm ra môi trường nóng, tạo màn sương lạnh tự nhiên. [Hiệu ứng] Đứng im trong môi trường bình thường sẽ tự động tạo mây mù bao phủ, che giấu hoàn toàn thân nhiệt khỏi máy quét hồng ngoại quân sự.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Ảo Giác"], range_type: "Xung quanh (Bị động tàng hình)", combo_tag: "Passive_Frost_Fog" },
        { name: "Đông Cứng Vũ Khí", desc: "[Cơ chế] Hơi lạnh truyền qua vật lý tiếp xúc làm giòn kim loại. [Hiệu ứng] Vũ khí cận chiến của kẻ thù nếu chém trúng/chạm vào vũ khí của bạn quá 3 lần sẽ bị giòn gãy và giảm x2 độ bền (Durability) cực nhanh.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Đỡ đòn (Bị động phá binh khí)", combo_tag: "Passive_Weapon_Shatter" },
        { name: "Cốt Băng Bất Hoại", desc: "[Cơ chế] Khung xương hóa thạch anh băng. [Hiệu ứng] Xương cực kỳ cứng, không thể bị nghiền nát bởi các đòn Búa/Chùy đè bẹp hệ Thổ. Kháng hoàn toàn hiệu ứng Gãy Xương/Rạn Cốt.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Bản thân (Bị động kháng đập nát)", combo_tag: "Passive_Ice_Bone" },
        { name: "Tinh Thể Kháng Độc", desc: "[Cơ chế] Độc tính trong cơ thể bị ngưng đọng thành khối đá vô hại. [Hiệu ứng] Nếu lỡ ăn phải Độc Dược hay hít khí Gas Độc, tiến trình trừ Máu (HP) bị làm chậm lại gấp 5 lần (Câu giờ cực lâu để tìm thuốc giải).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Độc"], range_type: "Bản thân (Bị động câu giờ tử vong)", combo_tag: "Passive_Toxin_Delay" },
        { name: "Tuyết Tích Tụ", desc: "[Cơ chế] Các tinh thể tuyết bám dần lên bề mặt quần áo/lông thú như khiên phụ. [Hiệu ứng] Càng ở lâu trong trận chiến (không nhận sát thương 10s), tự đắp lên một lớp khiên Tuyết mỏng 500 HP ngăn đòn đánh lẻ.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Bản thân (Bị động lớp khiên)", combo_tag: "Passive_Snow_Layer" },
        { name: "Chóp Băng Phản Đòn", desc: "[Cơ chế] Áo giáp lông hóa sừng sắc nhọn. [Hiệu ứng] Kẻ địch lao vào Húc (Charge) hoặc Vật lộn (Grapple) sẽ bị các chóp băng nhọn hoắt đâm ngược vào bụng, nhận lại 10% Sát thương vật lý chuẩn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Cận chiến (Bị động phản sát thương)", combo_tag: "Passive_Ice_Spike_Armor" },
        { name: "Vũ Khí Băng Sương", desc: "[Cơ chế] Độ ẩm kết tinh trên bề mặt dao/kiếm. [Hiệu ứng] Các đòn đánh thường tự động kèm theo hiệu ứng [Tê Buốt], làm giảm 2% Tốc độ đánh và Tốc độ di chuyển của địch (Cộng dồn tối đa 10%).", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Đòn đánh (Bị động làm chậm)", combo_tag: "Passive_Frost_Strike" },
        { name: "Hàn Cốt Xâm Nhập", desc: "[Cơ chế] Khí lạnh thẩm thấu qua lỗ chân lông, len lỏi vào tủy sống. [Hiệu ứng] Kẻ địch đánh cận chiến với bạn trong thời gian dài sẽ bị run rẩy tay chân, tăng 10% tỉ lệ thi triển Kỹ năng (Cast) hoặc Bắn cung trượt do co rút cơ.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Nguyền Rủa"], range_type: "Xung quanh (Bị động run rẩy)", combo_tag: "Passive_Bone_Chill" },
        { name: "Hấp Thụ Tuyết Lạnh", desc: "[Cơ chế] Đồng hóa sinh mệnh lực từ Môi trường Băng Giá nguyên thủy. [Hiệu ứng] Khi đứng trên tuyết hoặc sông băng, tốc độ hồi Mana (MP) và Thể lực (Stamina) tự động nhân đôi (x2).", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Môi Trường"], range_type: "Bản thân (Bị động hồi phục)", combo_tag: "Passive_Snow_Regen" },
        { name: "Đóng Băng Vết Thương", desc: "[Cơ chế] Truyền khí lạnh trực tiếp làm đông cứng tiểu cầu. [Hiệu ứng] Đóng băng lập tức vết thương hở của đồng đội để ngăn chảy máu đến chết. (Chỉ cầm máu, không hồi HP). Có thể dùng đóng băng khóa mồm quái nhỏ.", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Hỗ Trợ"], range_type: "Cận Chiến (Tiện ích sinh tồn)", combo_tag: "Frost_Seal" },
        { name: "Giáp Băng Mỏng", desc: "[Cơ chế] Phủ một lớp sương giá đông kết ngoài da thịt. [Hiệu ứng] Tăng 30 DEF. Khi kẻ địch chém trúng giáp, hàn khí tỏa ngược ra làm chậm cánh tay kẻ tấn công 15% trong 3 giây.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Bản thân (Phòng ngự bị động)", combo_tag: "Thin_Ice_Armor" },
        { name: "Băng Cầu Nổ", desc: "[Cơ chế] Nén hơi lạnh vào quả bóng nước và ném đi. [Hiệu ứng] Chạm đất nổ tung thành miểng băng sắc nhọn (AoE 2m). Gây rách da và làm trơn trượt mặt đất khiến lính địch dễ vấp ngã.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tầm Trung (Đạn nổ/Trơn)", combo_tag: "Frost_Bomb" },
        { name: "Băng Trảo", desc: "[Cơ chế] Bọc bàn tay/móng vuốt bằng lớp băng dày sắc như dao. [Hiệu ứng] Cào xé đứt thịt địch. Khí lạnh luồn vào mạch máu gây hiệu ứng Hoại tử lạnh nhẹ (Mất máu dần dần theo thời gian).", rank: "Thiết Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Cận Chiến", combo_tag: "Ice_Claw" },
        { name: "Chông Băng Phục Kích", desc: "[Cơ chế] Dẫn hàn khí xuống đất để gai băng mọc trồi lên. [Hiệu ứng] Mọc một cọc băng nhọn hoắt ngay dưới chân đối phương. Xuyên thủng gót chân, gây Khóa chân (Root) trong 1 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tầm Xa (Bẫy nhọn)", combo_tag: "Ice_Spike_Trap" },
        { name: "Sương Khí Lạnh", desc: "[Cơ chế] Thổi hơi thở -20 độ C lan tỏa mặt đất. [Hiệu ứng] Phun luồng khí lạnh diện rộng (Hình nón 4m). Không gây sát thương nhưng làm Tê cóng (Giảm 40% Tốc chạy) mọi kẻ thù dính phải, cực tốt để chạy trốn.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Khí"], range_type: "Hình Nón Nhỏ (Làm chậm)", combo_tag: "Chill_Breath" },
        { name: "Kiếm Băng Khắc", desc: "[Cơ chế] Tụ hơi nước thành thanh kiếm băng dài 1 mét. [Hiệu ứng] Vũ khí tạm thời, rất cứng sắc nhưng sẽ vỡ sau 5 lần chém. Mỗi lần chém trúng địch để lại một tầng Dấu Ấn Cóng.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Bản thân (Triệu hồi Vũ khí)", combo_tag: "Frost_Sword" },
        { name: "Tường Tuyết Mỏng", desc: "[Cơ chế] Dựng một vách ngăn bằng tuyết nén và băng vụn. [Hiệu ứng] Chặn các đòn ám khí (Phi tiêu, đạn gió). Rất dễ vỡ nếu bị Hỏa thiêu hoặc đập mạnh, nhưng đủ che tầm nhìn ngắm bắn của địch.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tường Chắn (Phòng ngự tầm nhìn)", combo_tag: "Snow_Wall" },
        { name: "Đường Trượt Lạnh", desc: "[Cơ chế] Đóng băng nhanh đường đi ngay dưới chân mình. [Hiệu ứng] Trượt băng trên mặt đất liền với tốc độ x2 (Dash xa). Địch đuổi theo dẫm lên đường này sẽ lập tức ngã dập mặt vì trơn.", rank: "Thiết Giai", cost: { type: "Stamina", value: 35 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Bản thân (Di chuyển/Bẫy)", combo_tag: "Ice_Slide" },
        { name: "Đóng Băng Vũ Khí", desc: "[Cơ chế] Phun sương cực hàn vào tay cầm gươm/giáo đối thủ. [Hiệu ứng] Đóng băng vũ khí của địch dính chặt vào tay chúng. Hoặc làm giòn vũ khí bằng nhiệt độ âm, đòn chạm kiếm tiếp theo sẽ làm vũ khí địch gãy vụn.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tầm Trung (Phá trang bị)", combo_tag: "Freeze_Weapon" },
        { name: "Bụi Tuyết Mù", desc: "[Cơ chế] Quẫy đuôi/Tay áo hất tung tuyết mạt lên không. [Hiệu ứng] Tung một nắm tuyết lạnh giá thẳng vào mặt địch. Cực kỳ đau rát mắt, Mù lòa (Blind) 2s. Chiêu bẩn nhưng hiệu quả cực cao khi bị cận chiến.", rank: "Phàm Giai", cost: { type: "Stamina", value: 15 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Cận Chiến (Mù lòa)", combo_tag: "Snow_Blind" },
        { name: "Lá Chắn Băng Gương", desc: "[Cơ chế] Ép một tấm gương băng phẳng hoàn hảo trước mặt. [Hiệu ứng] Chặn sát thương ma pháp nguyên tố (Lửa, Nước). Phản xạ lại các tia sáng (Beam) yếu nhưng sẽ vỡ vụn ngay sau khi phản xạ 1 lần.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Quang"], range_type: "Bản thân (Phản đòn ma thuật)", combo_tag: "Ice_Mirror_Block" },
        { name: "Búa Băng Phá Trận", desc: "[Cơ chế] Tụ băng thành khối tạ khổng lồ trên đỉnh nắm đấm. [Hiệu ứng] Nện mạnh xuống đất. Gây sát thương nổ băng diện rộng nhỏ, hất ngã mọi kẻ địch xung quanh và làm chậm toàn bộ chúng.", rank: "Thiết Giai", cost: { type: "Stamina", value: 50 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "AoE Cận Chiến (Hất ngã)", combo_tag: "Ice_Hammer_Slam" },
        { name: "Giọt Nước Đá Cắm Mạch", desc: "[Cơ chế] Bắn một giọt nước siêu lạnh vào gáy địch. [Hiệu ứng] Hàn khí chui vào tủy sống, làm địch run lẩy bẩy. Cứ mỗi lần địch vận sức tấn công sẽ bị rớt 5% HP vì kinh mạch bị băng cắt.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tầm Xa (Debuff sát thương nội)", combo_tag: "Frost_Spine" },
        { name: "Lốc Tuyết Cắn Xé", desc: "[Cơ chế] Tạo vùng lốc xoáy nhỏ mang theo dao băng liti. [Hiệu ứng] Bao vây 1 mục tiêu, liên tục cắt xén da thịt (Sát thương duy trì DPS). Không khóa chân nhưng bắt mục tiêu phải chịu rát buốt bỏ chạy.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Phong"], range_type: "Tầm Trung (Sát thương xoáy)", combo_tag: "Snow_Vortex" },
        { name: "Cột Băng Đẩy Cao", desc: "[Cơ chế] Tạo khối băng nở phình to ngay dưới chân. [Hiệu ứng] Đẩy người dùng hoặc đồng đội vọt lên độ cao 4m ngay lập tức. Dùng để né bẫy sụt lún dưới mặt đất hoặc vượt qua bức tường cao.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Bản thân (Di chuyển dọc)", combo_tag: "Ice_Pillar_Lift" },
        { name: "Áo Choàng Sương Giá", desc: "[Cơ chế] Tỏa sương lạnh bao quanh người che giấu thân nhiệt. [Hiệu ứng] Tàng hình khỏi các máy quét hồng ngoại (Tầm nhiệt) của UHA. Kẻ địch đến gần cũng bị lạnh thấu xương mà không thấy bạn đâu.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 25, unit: "Giây", display_text: "25 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Khí"], range_type: "Bản thân (Ngụy trang)", combo_tag: "Frost_Cloak" },
        { name: "Khóa Lạnh Yết Hầu", desc: "[Cơ chế] Bóp cổ địch bằng đôi tay âm 50 độ C. [Hiệu ứng] Lao vào túm cổ họng. Không chỉ gây ngạt thở mà hàn khí đông cứng thanh quản. Địch câm lặng (Silence) tuyệt đối 3 giây và ngất lịm đi.", rank: "Thiết Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Cận Chiến (Khống chế cứng)", combo_tag: "Frost_Choke" },
        { name: "Ném Cầu Băng Tuyết", desc: "[Cơ chế] Nhào nặn quả cầu tuyết lớn có lõi đá cứng. [Hiệu ứng] Ném thẳng vào mặt địch (như chơi ném tuyết nhưng bạo lực). Gây sát thương vật lý mạnh, vỡ ra làm chậm và mù tầm nhìn ngắn.", rank: "Phàm Giai", cost: { type: "Stamina", value: 20 }, cooldown: { value: 4, unit: "Giây", display_text: "4 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Tầm Trung (Đạn vật lý)", combo_tag: "Snowball_Throw" },
        { name: "Tuyệt Đối Linh Độ (Phong Ấn Vĩnh Hằng)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Rút cạn động năng nguyên tử, đưa không gian về 0 Kelvin (-273.15°C). Thời gian vi mô ngưng đọng. [Hiệu ứng] Đóng băng tức thì, vô hiệu hóa mọi đòn đánh. Giam giữ MỌI THỨ (kể cả Thần Thú) bán kính 1km thành tượng băng bất hoại vĩnh viễn. [Tác dụng phụ cực lớn] Người dùng tụt 2 đại cảnh giới. Cơ thể vỡ nát thành băng vụn, cần ôn dưỡng 1 năm trong Hồn Ấn, tỉ lệ chết vĩnh viễn 10%.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 95 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Thời Gian", "Không Gian"], range_type: "AoE Rất Rộng (Đóng băng tuyệt đối)", combo_tag: "Absolute_Zero" },
        { name: "Băng Tiễn Liên Hoàn", desc: "[Cơ chế] Ngưng tụ hơi ẩm trong không khí thành gai nhọn tinh thể. [Hiệu ứng] Bắn hàng loạt gai băng sắc nhọn liên tiếp. Xuyên thủng giáp da, giáp nhẹ. Gây sát thương vật lý lai ma pháp và làm chậm (Slow) mục tiêu 10% mỗi hit.", rank: "Phàm Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tầm Xa (Liên hoàn)", combo_tag: "Ice_Arrow" },
        { name: "Giáp Băng Phản Kích", desc: "[Cơ chế] Hình thành một lớp khiên băng lục giác bao bọc thân thể. [Hiệu ứng] Tạo giáp băng dày (Tăng 100 DEF). Khi giáp chịu sát thương vỡ vụn, nó phát nổ, bắn hàng trăm mảnh miểng băng sắc như dao cạo vào mặt kẻ địch ở cự ly gần (Gây rách mặt/Mù lòa 10 giây).", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Bản thân (Phòng thủ/Phản đòn)", combo_tag: "Ice_Armor" },
        { name: "Hơi Thở Hàn Băng", desc: "[Cơ chế] Phun ra dòng khí lạnh -50°C từ cuống phổi. [Hiệu ứng] Tầm hoạt động 10m hình nón. Kẻ địch trúng chiêu bị đóng băng bề mặt cơ khớp. Giảm tốc độ di chuyển và tốc độ đánh 50% trong 15 giây. Chặn đứng các đòn Charge lao tới.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Hình Nón (Làm chậm)", combo_tag: "Frost_Breath" },
        { name: "Tường Băng Vĩnh Cửu", desc: "[Cơ chế] Hút độ ẩm ngầm và nén tinh thể nước đến độ cứng của kim cương. [Hiệu ứng] Dựng bức tường băng khổng lồ (Dày 2m, Cao 5m). Chịu được đạn pháo và hỏa lực mạnh. Tồn tại đến khi bị phá hủy hoặc người dùng thu hồi.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Thổ"], range_type: "Tường Chắn (Phòng thủ chiến thuật)", combo_tag: "Ice_Wall" },
        { name: "Băng Liên Trói Chân", desc: "[Cơ chế] Truyền hàn khí xuống đất, tạo cấu trúc rễ băng. [Hiệu ứng] Đóng băng mặt đất, mọc ra đóa sen/dây xích băng quấn chặt lấy đôi chân, đông cứng chúng vào mặt đất. Gây hiệu ứng Trói Buộc (Root) trong 10 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tầm Xa (Khống chế cứng/Root)", combo_tag: "Ice_Root" },
        { name: "Bão Tuyết Sa Mạc", desc: "[Cơ chế] Thao túng áp suất không khí cục bộ, tạo dòng xoáy lạnh. [Hiệu ứng] Triệu hồi bão tuyết mù mịt bán kính 30m ở bất cứ địa hình nào. Các lưỡi dao tuyết gây sát thương rách da liên tục, giảm tầm nhìn xuống 0, đóng băng vũ khí.", rank: "Kim Giai", cost: { type: "MP", value: 100000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Phong"], range_type: "AoE Rộng (Môi trường/DPS)", combo_tag: "Blizzard" },
        { name: "Đường Băng Tốc Độ", desc: "[Cơ chế] Phun một lớp băng mỏng ma sát cực thấp (-0.01) dưới mặt đất. [Hiệu ứng] Trải thảm băng dài 50m. Bản thân và đồng đội lướt trên đó tăng 200% AGI. Địch bước lên sẽ trượt ngã, mất thăng bằng (Choáng nhẹ 0.5s).", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Đường thẳng (Buff tốc độ/Bẫy)", combo_tag: "Ice_Path" },
        { name: "Tượng Băng Thế Thân", desc: "[Cơ chế] Phân tách vỏ bọc băng ngoại vi kết hợp ảo ảnh. [Hiệu ứng] Ngay trước khi nhận đòn tất sát, để lại một bản sao bằng băng chịu đòn thay. Bản thân lùi nhanh về sau 10m (Blink) an toàn. Bức tượng vỡ làm đóng băng vũ khí địch.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Ảo Giác"], range_type: "Bản thân (Né tránh tuyệt đối)", combo_tag: "Ice_Substitute" },
        { name: "Tim Lạnh (Nội tại)", desc: "[Cơ chế] Đóng băng toàn bộ hạch cảm xúc và dây thần kinh ngoại biên. [Hiệu ứng] Miễn nhiễm 100% với các hiệu ứng Tinh thần: Sợ Hãi, Khiêu Khích, Ảo Giác. Không cảm thấy đau đớn dù bị thương nặng đứt tay chân.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Bản thân (Kháng tính bị động)", combo_tag: "Cold_Heart" },
        { name: "Băng Đao Đoạt Mệnh", desc: "[Cơ chế] Ngưng tụ lưỡi kiếm băng ở nhiệt độ -100°C. [Hiệu ứng] Tạo lưỡi kiếm siêu sắc. Khi chém trúng, hàn khí xâm nhập mạch máu làm đông đặc hồng cầu, gây hiệu ứng Hoại Tử Lạnh (Trừ Max HP vĩnh viễn không thể hồi phục trong trận chiến).", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Cận Chiến (Vũ khí ma thuật)", combo_tag: "Frost_Blade" },
        { name: "Gương Băng Ảo Ảnh", desc: "[Cơ chế] Tạo các lăng kính đa diện để bẻ cong ánh sáng quang học. [Hiệu ứng] Dựng lên một mê cung gồm nhiều tấm gương băng xung quanh mục tiêu. Phản chiếu hàng chục hình ảnh ảo của người dùng, làm kẻ địch rối loạn phương hướng hoàn toàn.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Quang"], range_type: "AoE Trung (Ảo giác trận pháp)", combo_tag: "Ice_Mirror_Maze" },
        { name: "Hàn Khí Xâm Nhập", desc: "[Cơ chế] Khí lạnh vô hình chui qua lỗ chân lông, bám vào tủy sống. [Hiệu ứng] Làm lạnh tủy sống kẻ địch, khiến chúng rét run lẩy bẩy, mất kiểm soát cơ bắp. Tỉ lệ Niệm chú phép thuật thất bại (Interrupt) tăng lên 50%. Khắc chế Pháp sư.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Nguyền Rủa"], range_type: "AoE Trung (Debuff/Silence)", combo_tag: "Chill_Interrupt" },
        { name: "Búa Tạ Ngàn Cân", desc: "[Cơ chế] Tụ hơi nước trên cao, đông cứng thành khối băng trọng lượng 10 tấn. [Hiệu ứng] Tạo khối băng khổng lồ trên không trung rơi thẳng xuống. Nghiền nát xe tăng, phá vỡ khiên năng lượng và đập bẹp mục tiêu. Sát thương vật lý AoE cực lớn.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "AoE Nhỏ (Từ trên cao)", combo_tag: "Ice_Hammer" },
        { name: "Cầu Tuyết Lăn", desc: "[Cơ chế] Cuộn người vào trong tuyết, lợi dụng quán tính gia tăng khối lượng. [Hiệu ứng] Cuộn mình trong cầu tuyết, lăn với tốc độ cao cán qua địch. Càng lăn càng to (Tối đa đường kính 10m). Phá hủy chướng ngại vật, miễn nhiễm đạn tầm xa khi lăn.", rank: "Thiết Giai", cost: { type: "Stamina", value: 300 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Đường thẳng (Di chuyển/Sát thương)", combo_tag: "Snowball_Roll" },
        { name: "Vùng Chết Lạnh (Kỷ Băng Hà)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Đồng hóa năng lượng bản thể với địa mạch, tái tạo Lãnh nguyên băng giá. [Hiệu ứng] Biến vùng đất bán kính 20km thành Vùng Chết Lạnh (-100°C). Hạ thân nhiệt mọi kẻ địch, gây tử vong nếu ở quá lâu. Thay đổi vĩnh viễn hệ sinh thái bản đồ. [Tác dụng phụ] Rút cạn Max HP xuống 10%. Rơi vào trạng thái 'Ngủ Đông' bắt buộc trong Hồn ấn 6 tháng.", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 800000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Thổ", "Môi Trường"], range_type: "AoE Cực Rộng (Thay đổi Địa hình)", combo_tag: "Ice_Age_Domain" },
        { name: "Mũi Khoan Băng", desc: "[Cơ chế] Nén băng hình xoắn ốc và xoay với tốc độ 3000 vòng/phút quanh cánh tay. [Hiệu ứng] Tạo mũi khoan xoay siêu tốc. Lao thẳng vào phá vỡ mọi lớp khiên phòng thủ (Shield/Barrier) và xuyên thủng các bức tường đá kiên cố nhất. Sát thương xuyên giáp.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Cận Chiến (Xuyên thấu)", combo_tag: "Ice_Drill" },
        { name: "Tủ Lạnh Di Động (Sinh hoạt)", desc: "[Cơ chế] Tạo một không gian cách nhiệt ma thuật thu nhỏ. [Hiệu ứng] Tạo khoang chứa băng. Bảo quản thức ăn, thảo dược quý, hoặc xác quái vật tươi nguyên vĩnh viễn không phân hủy (Giữ nguyên phẩm chất vật phẩm đánh rơi).", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Bản thân (Tiện ích hòm đồ)", combo_tag: "Magic_Fridge" },
        { name: "Quan Tài Băng (Bảo vệ tuyệt đối)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Đóng băng chính dòng chảy sinh mệnh và thời gian quanh bản thể. [Hiệu ứng] Tự đóng băng bản thân (hoặc 1 đồng minh) trong khối băng kim cương bất hoại tối đa 7 ngày để né đòn tất sát (Kể cả đòn Thần Giai). Giữ mạng kẻ sắp chết. [Tác dụng phụ] Rơi vào Hôn mê, không thể tự hủy chiêu sớm. Kẻ địch có thể bê quan tài đi. Trừ 30 Sanity khi thức dậy do hội chứng buồng giam.", rank: "Diệu Giai", cost: { type: "HP", value: 50000 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Thời Gian", "Sinh Mệnh"], range_type: "Bản thân/Đồng minh (Vô địch)", combo_tag: "Ice_Coffin" },
        { name: "Cầu Băng Vượt Vực", desc: "[Cơ chế] Nối liền các tinh thể nước trong không khí tạo kết cấu cầu vòm chịu lực. [Hiệu ứng] Dựng cây cầu băng rộng 3m, dài tối đa 100m nối liền hai vách núi đứt gãy hoặc bắc qua sông nham thạch. Quan trọng để di chuyển địa hình Hoang Khu.", rank: "Thiết Giai", cost: { type: "MP", value: 350 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tầm Xa (Kiến tạo địa hình)", combo_tag: "Ice_Bridge" },
        { name: "Tạo Nước Đá (Sinh hoạt)", desc: "[Cơ chế] Rút nhiệt năng lỏng cấp tốc. [Hiệu ứng] Cung cấp những viên đá lạnh tinh khiết để giải khát giữa sa mạc, hoặc tạo túi chườm lạnh khẩn cấp để giảm sưng tấy vết thương do độc trùng.", rank: "Phàm Giai", cost: { type: "MP", value: 10 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Cận Chiến (Tiện ích)", combo_tag: "Make_Ice" },
        { name: "Gai Sàn Chông", desc: "[Cơ chế] Trích xuất hơi ẩm từ nền đất lên và đông cứng nhanh. [Hiệu ứng] Biến mặt sàn nhà (10x10m) thành bãi chông băng cao 50cm, cực kỳ sắc nhọn. Kẻ thù dẫm vào bị thủng bàn chân, làm chậm 80% tốc độ di chuyển và rỉ máu.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "AoE Nhỏ (Đặt bẫy)", combo_tag: "Ice_Spike_Trap" },
        { name: "Kính Lúp Băng", desc: "[Cơ chế] Đúc băng thấu kính lồi hoàn hảo ma thuật. [Hiệu ứng] Tạo thấu kính băng lơ lửng hội tụ ánh sáng mặt trời để đốt lửa/tấn công nhiệt, hoặc dùng như ống nhòm viễn vọng quan sát xa 5km.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Quang"], range_type: "Bản thân (Tiện ích/Tầm nhìn)", combo_tag: "Ice_Lens" },
        { name: "Hàn Gắn Vết Nứt", desc: "[Cơ chế] Nhét băng dẻo vào các khe hở và làm cứng lại thành kết cấu hàn. [Hiệu ứng] Phép thuật bảo trì cơ khí. Dùng băng vá tạm thời vỏ tàu, thân Mecha, xe bọc thép rách hoặc bình chứa bị thủng, ngăn rò rỉ trong 24 giờ.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Cận Chiến (Sửa chữa)", combo_tag: "Ice_Patch" },
        { name: "Bom Nổ Chậm Băng Giá", desc: "[Cơ chế] Gài khối ma lực băng nén với ngòi nổ cảm biến trọng lượng. [Hiệu ứng] Gài mìn băng tàng hình dưới đất. Khi có người dẫm phải, nổ tung gây sát thương miểng băng và đóng băng diện rộng chân nạn nhân.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "AoE Nhỏ (Mìn/Bẫy)", combo_tag: "Ice_Mine" },
        { name: "Sương Mù Ngụy Trang", desc: "[Cơ chế] Hạ nhiệt độ bề mặt để không khí xung quanh hóa sương lạnh. [Hiệu ứng] Tạo sương mù lạnh bám sát mặt đất. Che giấu hoàn toàn thân nhiệt tổ đội khỏi các loại máy quét hồng ngoại (Thermal Scanner) của máy bay UHA.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Khí"], range_type: "AoE Trung (Ngụy trang tàng hình)", combo_tag: "Cold_Fog" },
        { name: "Đóng Băng Máu (Cấp cứu khẩn cấp)", desc: "[Cơ chế] Can thiệp hồng cầu/tiểu cầu bằng hàn khí. [Hiệu ứng] Dùng khi đồng minh bị đứt lìa tay chân. Ngăn chặn chảy máu ồ ạt, đóng băng ngay lập tức vết thương diện rộng giữ lại sinh mạng (Cần rã đông và chữa trị sau đó).", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Sinh Mệnh"], range_type: "Cận Chiến (Cấp cứu y tế)", combo_tag: "Freeze_Bleed" },
        { name: "Nhà Lều Igloo", desc: "[Cơ chế] Tạo một mái vòm băng theo cấu trúc chịu lực vòm. [Hiệu ứng] Dựng lều tuyết kiên cố. Chống chịu gió bão cấp 12, cách nhiệt hoàn hảo, giữ ấm bên trong, che giấu ánh sáng lửa trại để trú ẩn an toàn qua đêm.", rank: "Phàm Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "AoE Nhỏ (Kiến tạo căn cứ)", combo_tag: "Ice_Igloo" },
        { name: "Trượt Băng Nghệ Thuật", desc: "[Cơ chế] Đóng băng ngay tại điểm chạm của gót chân trên chất lỏng. [Hiệu ứng] Kỹ năng di chuyển. Giúp nhân vật đi bộ hoặc trượt trên mặt nước, biển, sông như đi trên đất liền với tốc độ cực nhanh, không hề bị lún.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Bản thân (Di chuyển)", combo_tag: "Water_Walk" },
        { name: "Hóa Hình - Băng Tinh", desc: "[Cơ chế] Ép súc cơ thể khổng lồ của Dị Thú hệ Băng. [Hiệu ứng] Toàn thân đóng băng và vỡ nát thành hàng vạn mảnh tinh thể tuyết lấp lánh, xoáy tụ thành hình dáng một nhân loại. Khí chất lạnh lùng tột độ. Giấu đi toàn bộ yêu khí, tỏa ra hàn khí xua đuổi vi khuẩn.", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Sinh Học"], range_type: "Bản thân (Ngụy trang tuyệt đối)", combo_tag: "Beast_Ice_Form" },
        { name: "Tuyệt Đối Linh Độ (Bản chưa hoàn chỉnh)", desc: "[Cơ chế] Hạ nhiệt độ xuống -200°C trong bán kính hẹp của loài Thú hoang. [Hiệu ứng] Đóng băng vạn vật trong bán kính 5m thành tác phẩm đá tảng, làm chậm hệ thần kinh địch. Đóng băng cả kết cấu ma thuật. Giảm phòng thủ địch 50%.", rank: "Kim Giai", cost: { type: "MP", value: 200000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "AoE Nhỏ (Đóng băng cứng)", combo_tag: "Lesser_Absolute_Zero" },
        { name: "Băng Lăng Tiễn", desc: "[Cơ chế] Tạo ra gai băng mang theo độ cứng của Kim cương, không vỡ vụn khi va chạm. [Hiệu ứng] Bắn gai băng sắc nhọn liên hoàn. Xuyên thấu áo giáp hợp kim titan UHA. Cắm vào thịt sẽ hút máu địch để sinh trưởng thêm gai nhọn từ bên trong.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Huyết Mạch"], range_type: "Tầm Xa (Xuyên thấu/Ký sinh)", combo_tag: "Diamond_Ice_Arrow" },
        { name: "Băng Giáp Tàn Nhẫn", desc: "[Cơ chế] Bộ lông/vảy thú phủ một lớp sừng băng tinh khiết. [Hiệu ứng] Phủ lớp băng dày (Hấp thụ 5000 damage). Khi bị vỡ, không rơi xuống mà nổ văng miểng băng ra ngoài sát thương kẻ địch cận chiến (Gây rách mặt/Mù lòa 10 giây).", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Bản thân (Phòng thủ/Sát thương cận chiến)", combo_tag: "Cruel_Ice_Armor" },
        { name: "Hơi Thở Băng Hà", desc: "[Cơ chế] Mở hàm rộng, giải phóng khí gas siêu lạnh từ túi khí sinh học. [Hiệu ứng] Phun khí lạnh, giảm nhiệt độ môi trường gây Debuff suy yếu và tê cóng (AGI -70%). Phá hủy cơ cấu khớp nối kim loại của người máy chiến đấu.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Hình Nón Rộng (AoE Debuff)", combo_tag: "Glacier_Breath" },
        { name: "Tường Băng Chắn Lối", desc: "[Cơ chế] Dựng bức tường băng phủ lớp gương ma thuật phản xạ. [Hiệu ứng] Dựng lên bức tường băng cản đòn vật lý tốt, có khả năng phản xạ phép thuật hệ Hỏa (Nước đá hóa hơi sẽ hấp thụ hỏa) và phản xạ tia laser quang học.", rank: "Thiết Giai", cost: { type: "MP", value: 450 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng"], range_type: "Tường Chắn (Phòng thủ/Phản xạ)", combo_tag: "Ice_Wall_Reflect" },
        { name: "Băng Liên Trói Buộc (Tử Vong)", desc: "[Cơ chế] Hoa sen băng cắm rễ vào tủy sống nạn nhân. [Hiệu ứng] Đóa sen băng nở dưới chân địch, đóng băng đôi chân xuống mặt đất. Nếu không phá được băng trong 10 giây, hoa sen lan rộng lên cổ, đông cứng nội tạng và giết chết mục tiêu.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Nguyền Rủa"], range_type: "Tầm Xa (Khống chế/Tử vong)", combo_tag: "Death_Ice_Lotus" },
        { name: "Bão Tuyết Cuồng Loạn", desc: "[Cơ chế] Vỗ cánh/Vẫy đuôi tạo ra sự hỗn loạn dòng không khí cực lạnh. [Hiệu ứng] Gọi một trận bão tuyết xé rách da thịt (AoE DPS). Giảm tầm nhìn xuống 0, tiếng rít của gió làm nhiễu loạn liên lạc vô tuyến, chia cắt đội hình địch.", rank: "Kim Giai", cost: { type: "Stamina", value: 80000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Phong"], range_type: "AoE Rộng (Bão/DPS)", combo_tag: "Frenzy_Blizzard" },
        { name: "Đường Trượt Băng", desc: "[Cơ chế] Móng vuốt tiết hàn khí, làm đóng băng nền đất chớp mắt. [Hiệu ứng] Biến mặt đất thành băng trơn trượt dốc. Tăng tốc độ lao tới (Charge) của bản thân lên 300% và làm ngã địch hai chân để phơi bày nhược điểm (cổ/bụng).", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng"], range_type: "Đường thẳng (Cải tạo địa hình/Buff tốc độ)", combo_tag: "Beast_Ice_Charge" },
        { name: "Tượng Băng Thế Mạng", desc: "[Cơ chế] Lột xác một lớp da băng kết hợp ảo ảnh. [Hiệu ứng] Để lại một bức tượng băng chịu đòn thay thế và phát nổ hàn khí gây choáng. Thú lướt lùi về sau tàng hình 1s để setup đòn tập kích từ điểm mù.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Ảo Giác"], range_type: "Bản thân (Né tránh/Blink)", combo_tag: "Beast_Ice_Decoy" },
        { name: "Máu Lạnh (Bị động)", desc: "[Cơ chế] Tắt hoàn toàn hạch hạnh nhân (trung tâm cảm nhận đau đớn) của Thú săn mồi. [Hiệu ứng] Không cảm thấy đau đớn, miễn nhiễm các hiệu ứng hoảng sợ (Fear), khống chế tinh thần và miễn nhiễm Độc máu (Máu chảy chậm cản độc phát tán).", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Sinh Học"], range_type: "Bản thân (Kháng tính bị động tuyệt đối)", combo_tag: "Cold_Blooded_Predator" },
        { name: "Băng Đao Đoạt Mệnh (Bản Thú)", desc: "[Cơ chế] Bọc băng vào đuôi/sừng như lưỡi rìu tàn bạo. [Hiệu ứng] Ngưng tụ khí lạnh thành lưỡi đao chém đứt sinh khí mục tiêu. Cắt đứt chân tay, chặn đứng mọi kỹ năng hồi máu tại vết cắt (vết thương tím đen hoại tử).", rank: "Ngân Giai", cost: { type: "Stamina", value: 4500 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Cận Chiến (Sát thương trọng thương)", combo_tag: "Beast_Frost_Blade" },
        { name: "Gương Băng Ảo Ảnh (Phản Quang)", desc: "[Cơ chế] Lắp ghép hàng trăm vảy băng trên cơ thể tạo lăng kính di động. [Hiệu ứng] Tạo các lăng kính băng làm lệch hướng, đánh lừa hệ thống ngắm bắn Mecha. Phản xạ lại 1 đòn tấn công hệ Quang (Ánh sáng) về chủ của nó.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Quang"], range_type: "Bản thân (Phản đòn/Ảo ảnh)", combo_tag: "Prism_Armor" },
        { name: "Đóng Băng Nội Tạng", desc: "[Cơ chế] Truyền hàn khí độc hại thẳng qua miệng vết thương hở của kẻ thù. [Hiệu ứng] Khi dùng răng cắn trúng địch, truyền hàn khí trực tiếp, làm đóng băng máu. Máu đông đặc gây đột quỵ tim phổi, tử vong tức tì nếu không có ma pháp bảo vệ tâm mạch.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 65000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Nguyền Rủa", "Sinh Học"], range_type: "Cận Chiến (Điều kiện: Địch có vết thương hở)", combo_tag: "Internal_Freeze" },
        { name: "Băng Chùy Trấn Áp", desc: "[Cơ chế] Tạo quả cầu gai bằng băng lơ lửng trên không. [Hiệu ứng] Tạo một khối băng khổng lồ (kích thước xe bus) giáng từ trên cao xuống. Gây sát thương vật lý kết hợp nổ văng miểng băng sắc nhọn AoE.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "AoE Nhỏ (Tầm Trung/Từ trên cao)", combo_tag: "Ice_Mace_Drop" },
        { name: "Tuyết Cầu Lăn Tới", desc: "[Cơ chế] Thú co cụm cơ thể hình cầu, bọc tuyết và lao dốc. [Hiệu ứng] Cuộn tròn trong quả cầu tuyết khổng lồ lớn dần theo quỹ đạo lăn (Max 15m), cán nát mọi chướng ngại vật, lính gác, xe tải. Không thể chặn bằng sức mạnh vật lý.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Đường thẳng dài (Sát thương đè bẹp)", combo_tag: "Giant_Snowball" },
        { name: "Lãnh Khí Xâm Nhập", desc: "[Cơ chế] Tỏa ra trường không gian nhiệt độ âm, đóng băng chính các hạt Mana trôi nổi. [Hiệu ứng] Tạo vùng không gian (Bán kính 20m) trừ Mana (MP) của mọi kẻ địch đứng bên trong (Trừ 5% Max MP mỗi giây). Khắc tinh của lối đánh cấu rỉa ma pháp.", rank: "Kim Giai", cost: { type: "MP", value: 100000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Lĩnh Vực"], range_type: "AoE Trung (Lĩnh Vực Hút Mana)", combo_tag: "Mana_Freeze_Domain" },
        { name: "Mũi Khoan Băng Sương", desc: "[Cơ chế] Xoáy cơ thể (hoặc một chi) bọc băng với động năng xoắn. [Hiệu ứng] Tay/Chân/Sừng biến thành mũi khoan băng xoay tròn phá vỡ khiên phòng thủ (Shield/Barrier). Xuyên thẳng tắp vào thân thể mục tiêu xuyên qua mọi lớp giáp.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Vật Lý"], range_type: "Cận Chiến (Phá giáp/Xuyên khiên)", combo_tag: "Beast_Ice_Drill" },
        { name: "Tái Tạo Từ Băng", desc: "[Cơ chế] Hấp thụ nước đông lạnh ở môi trường thay thế mô thịt đứt lìa. [Hiệu ứng] Kỹ năng hồi phục dị biệt ở Lãnh nguyên tuyết. Hấp thụ tuyết hoặc băng xung quanh để hàn gắn các vết thương trên cơ thể, đắp lại chi giả bằng băng cho cánh tay/chân bị chặt đứt.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 12, unit: "Giờ", display_text: "12 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Sinh Mệnh"], range_type: "Bản thân (Tái tạo nhục thể)", combo_tag: "Ice_Regeneration" },
        { name: "Quan Tài Băng (Ngủ Đông)", desc: "[Cơ chế] Đóng băng chính lớp vỏ kén sinh học của thú. [Hiệu ứng] Khi bị săn đuổi dồn vào đường cùng (HP < 10%), tự phong ấn bản thân vào khối băng không thể phá hủy sâu dưới lòng đất trong 5 giây để né sát thương tất sát. Sẽ ngủ đông phục hồi trong nhiều năm nếu không bị giải trừ.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Sinh Học"], range_type: "Bản thân (Ngủ đông sinh tồn)", combo_tag: "Hibernation_Coffin" }
    ],
  "Hệ Lôi": [
        { name: "Hóa Hình - Lôi Thần", desc: "[Cơ Chế Sinh Học & Nguyên Lý] Tiến hóa hệ thần kinh trung ương thành mạng lưới siêu dẫn sinh học. Sợi cơ biến thành polymer phản ứng điện. Não bộ là máy phát điện sinh học tần số cao. [Cấu Tạo] Tim là tụ điện chính, phổi hấp thụ điện tích từ không khí. Máu chứa kim loại lỏng để dẫn điện. [Hình Thái & Hiệu ứng] Mắt phát sáng rực rỡ, tóc dựng đứng vì tĩnh điện. Dạng người sở hữu phản xạ thần kinh (AGI) nhanh gấp 10 lần. Bất kỳ ai (kể cả đồng minh) chạm trực tiếp vào da thịt sẽ bị giật tung, nhận hiệu ứng Tê Liệt (Paralyze) trong 1 phút. [Tác dụng phụ] Tốn năng lượng huyết mạch liên tục, mất ngủ triền miên do não bộ luôn ở trạng thái kích thích tột độ.", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Chuyển đổi hình thái)", combo_tag: "Form_Lightning" },
        { name: "Tĩnh Điện Phản Kháng", desc: "[Cơ chế] Da lông luôn tích tụ hàng triệu electron tự do chờ xả. [Hiệu ứng] Kẻ địch chém trúng bằng vũ khí kim loại sẽ bị giật tĩnh điện, tự động nhận lại 5% Sát thương chuẩn và bị khựng lại (Ngắt combo) trong 0.2 giây.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 2, unit: "Giây", display_text: "2 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Cận Chiến (Bị động phản đòn)", combo_tag: "Passive_Static_Shock" },
        { name: "Thần Kinh Tia Chớp", desc: "[Cơ chế] Xung điện truyền tín hiệu thần kinh thay vì hóa chất sinh học. [Hiệu ứng] Bộ não phản ứng với khống chế cực nhanh. Giảm thời gian chịu mọi trạng thái Làm Choáng (Stun), Tê Liệt (Paralyze) đi 50%.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Bị động kháng CC)", combo_tag: "Passive_Nerve_Lightning" },
        { name: "Hấp Thụ Ma Sát", desc: "[Cơ chế] Bước chạy tạo ra tĩnh điện được tủy sống hấp thụ lại. [Hiệu ứng] Càng chạy liên tục trên một đường thẳng, tốc độ di chuyển (AGI) càng tăng lên (Tối đa +30%). Reset ngay khi đổi hướng gắt hoặc dừng lại.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Bản thân (Bị động tăng tốc)", combo_tag: "Passive_Friction_Charge" },
        { name: "Sấm Truyền Giác Quan", desc: "[Cơ chế] Tóc và lông măng phản ứng với từ trường kim loại trong môi trường. [Hiệu ứng] Tự động 'nghe' được sự hiện diện của lính gác bọc giáp sắt, mìn chôn dưới đất, hoặc súng đạn đang ngắm bắn mình trong bán kính 20m.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Từ Trường"], range_type: "AoE Trung (Bị động trinh sát)", combo_tag: "Passive_Metal_Sense" },
        { name: "Từ Trường Hộ Thể", desc: "[Cơ chế] Tỏa ra từ trường trái dấu với vũ khí sắt thép phổ thông. [Hiệu ứng] Mọi mũi tên, phi tiêu, hoặc đạn súng trường (Cỡ nhỏ) bằng kim loại bay tới có 20% bị lệch quỹ đạo sượt qua cơ thể thay vì đâm trúng.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Từ Trường"], range_type: "Bản thân (Bị động né đạn)", combo_tag: "Passive_Magnetic_Deflect" },
        { name: "Cơ Bắp Kích Tốc", desc: "[Cơ chế] Dòng điện cưỡng chế co rút cơ bắp khi cơ thể rơi vào nguy kịch. [Hiệu ứng] Khi HP rớt xuống dưới 20%, hệ thần kinh được Overclock (Ép xung). Tốc độ tấn công và thi triển kỹ năng tăng gấp đôi (x2) để tử chiến lật kèo.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Bị động cuồng nộ)", combo_tag: "Passive_Overclock_Muscle" },
        { name: "Tích Điện Phản Chấn", desc: "[Cơ chế] Đệm thịt dưới chân tụ điện áp như một tấm tụ bù. [Hiệu ứng] Khi nhảy hoặc rơi từ độ cao trên 10m xuống đất, không những không mất máu mà còn phóng một vòng tròn sốc điện làm tê liệt mọi kẻ địch dưới chân.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "AoE Nhỏ (Bị động hạ cánh)", combo_tag: "Passive_Impact_Discharge" },
        { name: "Mắt Lôi Quang", desc: "[Cơ chế] Võng mạc chứa tinh thể lân quang phóng điện chớp nhoáng. [Hiệu ứng] Khi bị kẻ thù nhắm mắt nhìn chằm chằm (Ví dụ: Kỹ năng định thân, khiêu khích), đôi mắt sẽ lóe sáng cực mạnh dội ngược lại, gây Mù lòa (1s) cho kẻ nhìn.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Quang"], range_type: "Mục tiêu đối diện (Bị động phản kháng)", combo_tag: "Passive_Flash_Eye" },
        { name: "Ion Hóa Vũ Khí", desc: "[Cơ chế] Bàn tay rỉ ra ma lực điện truyền thẳng vào binh khí đang cầm. [Hiệu ứng] Mọi đòn đánh thường bằng vũ khí cận chiến có tỉ lệ 10% gây giật tung người (Khựng lại 0.5s) phá vỡ nhịp độ tấn công của đối thủ.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Đòn đánh (Bị động khống chế)", combo_tag: "Passive_Ion_Weapon" },
        { name: "Kháng Lôi Thể", desc: "[Cơ chế] Da bọc lớp keratin cách điện siêu việt. [Hiệu ứng] Cơ bản giảm 50% mọi sát thương nhận vào từ hệ Lôi của quái thú cấp thấp hoặc mìn điện do địch giăng ra.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Bản thân (Bị động phòng thủ)", combo_tag: "Passive_Rubber_Skin" },
        { name: "Xuyên Phá Cực Điện", desc: "[Cơ chế] Hồ quang điện sinh ra ở mũi vũ khí nung chảy kim loại. [Hiệu ứng] Đòn đánh thường tự động bỏ qua 15% chỉ số Phòng thủ (DEF) nếu kẻ địch đang mặc áo giáp kim loại, áo giáp lưới hoặc cầm khiên sắt.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Nhiệt"], range_type: "Đòn đánh (Bị động xuyên giáp)", combo_tag: "Passive_Arc_Pierce" },
        { name: "Hào Quang Tê Dại", desc: "[Cơ chế] Điện trường sinh học rò rỉ ra ngoài bán kính 2m quanh cơ thể. [Hiệu ứng] Kẻ địch dám đứng đánh cận chiến lâu dài với bạn sẽ bị nhiễm tĩnh điện, cứ mỗi giây trôi qua tốc độ đánh (AGI) bị giảm 2% (Tối đa giảm 20%).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "AoE Cận Chiến (Bị động Debuff)", combo_tag: "Passive_Numbing_Aura" },
        { name: "Chớp Nhoáng Phản Công", desc: "[Cơ chế] Tủy sống tích động năng từ cú xoay người né đòn. [Hiệu ứng] Ngay khi bạn Né tránh (Dodge) thành công một đòn đánh, đòn đánh trả lại ngay sau đó của bạn sẽ được cộng thêm 30% sát thương Bạo kích hệ Lôi.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Bản thân (Bị động tăng công)", combo_tag: "Passive_Counter_Flash" },
        { name: "Dẫn Lôi Thu Lôi", desc: "[Cơ chế] Cột thu lôi sống, chuyển hướng dòng chảy plasma. [Hiệu ứng] Bất kỳ đồng minh nào trong bán kính 10m bị nhắm mục tiêu bởi phép hệ Lôi, tia sét sẽ bẻ cong tự động đánh thẳng vào bạn (Người có kháng điện) thay vì đồng minh.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "AoE Trung (Bị động gánh vác)", combo_tag: "Passive_Lightning_Rod" },
        { name: "Sóng Não Điện Từ", desc: "[Cơ chế] Dịch não tủy cộng hưởng với tần số niệm chú của Pháp sư địch. [Hiệu ứng] Nhận được linh cảm nhói đau ở màng tang 1 giây trước khi kẻ địch hoàn tất một phép thuật AoE lớn, đủ thời gian để hô hoán đồng đội né tránh.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Tinh Thần"], range_type: "Bản thân (Bị động linh cảm)", combo_tag: "Passive_Danger_Sense" },
        { name: "Đảo Chiều Động Năng", desc: "[Cơ chế] Bọc cơ thể trong một bong bóng từ tính siêu đàn hồi. [Hiệu ứng] Khi bị trúng kỹ năng đẩy lùi (Knockback), cơ thể lướt lùi về sau nhưng năng lượng bị tích tụ. Nếu lập tức lao lên, tốc độ lao (Charge) sẽ nhanh gấp 3 lần bình thường.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Bản thân (Bị động phản hồi)", combo_tag: "Passive_Kinetic_Reversal" },
        { name: "Huyết Lôi Sinh Mệnh", desc: "[Cơ chế] Máu có tính kiềm điện phân cao. [Hiệu ứng] Máu rỉ ra từ vết thương hở khi chạm đất sẽ tạo thành các vũng tĩnh điện nhỏ. Quái vật dẫm vào vũng máu của bạn sẽ bị giật điện lộ vị trí.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Xung quanh vết thương (Bị động bẫy)", combo_tag: "Passive_Electric_Blood" },
        { name: "Lõi Từ Tính Trái Tim", desc: "[Cơ chế] Tim hoạt động như một máy phát điện Dynamo vi mô. [Hiệu ứng] Chừng nào nhịp tim còn đập trên 120 nhịp/phút (Đang trong Combat/Đang chạy), lượng MP tự động hồi phục 2% mỗi giây. Đứng yên sẽ mất hiệu ứng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Bị động hồi Mana)", combo_tag: "Passive_Dynamo_Heart" },
        { name: "Khứu Giác Ozone", desc: "[Cơ chế] Mũi cực kỳ nhạy bén với khí Ozone sinh ra trước khi sét đánh. [Hiệu ứng] Dự đoán chính xác thời tiết (Khi nào có bão sét ngầm). Đồng thời ngửi thấy mùi đặc trưng của các vũ khí năng lượng cao đang nạp đạn quanh mình.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Khí"], range_type: "Bản thân (Bị động dự báo)", combo_tag: "Passive_Ozone_Smell" },
        { name: "Bạo Lực Điện Tích", desc: "[Cơ chế] Khi tụ năng lượng vượt ngưỡng, hạt electron dư thừa tự động phóng ra kẽ hở. [Hiệu ứng] Bất cứ khi nào đòn đánh của bạn nhảy Bạo kích (Critical), sát thương sẽ thừa ra tạo thành một tia sét giật văng sang 1 kẻ thù đứng cạnh.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Đòn đánh (Bị động nảy mục tiêu)", combo_tag: "Passive_Crit_Spark" },
        { name: "Điện Tiễn Xuyên Mạch", desc: "[Cơ chế] Phóng tia sét thẳng như mũi tên. [Hiệu ứng] Bắn xuyên qua 2 kẻ địch liên tiếp. Sát thương Lôi chí mạng, khiến kẻ địch bị tê rần cánh tay, đánh rơi vũ khí đang cầm nếu trúng tay.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Đường thẳng (Xuyên thấu)", combo_tag: "Lightning_Arrow" },
        { name: "Tia Sét Giật Choáng", desc: "[Cơ chế] Bắn tia lửa điện áp cao nhưng dòng thấp. [Hiệu ứng] Đánh trúng mục tiêu lập tức gây Choáng (Stun) tuyệt đối 1 giây, phá vỡ hoàn toàn mọi kỹ năng đang niệm (Interrupt). Sát thương thấp.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Tầm Xa (Ngắt chiêu)", combo_tag: "Stun_Zap" },
        { name: "Lôi Trảo Tê Liệt", desc: "[Cơ chế] Tích điện âm ở vuốt, phóng vào cơ thể dương của địch. [Hiệu ứng] Cào xé bằng sấm sét. Kẻ địch bị đánh trúng sẽ bị tê liệt cơ bắp (Giảm 50% Tốc độ đánh và di chuyển) trong 3 giây.", rank: "Phàm Giai", cost: { type: "Stamina", value: 20 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Cận Chiến (Debuff)", combo_tag: "Paralyze_Claw" },
        { name: "Điện Tích Phản Kích", desc: "[Cơ chế] Tụ điện quanh áo giáp. [Hiệu ứng] Trong 5 giây, kẻ nào chém vật lý hoặc đụng vào người thi triển sẽ bị điện giật văng ngược ra sau 2m, chịu sát thương phản đòn tương đương 30% đòn đánh.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Bản thân (Phản đòn)", combo_tag: "Static_Counter" },
        { name: "Đạn Điện Liên Hoàn", desc: "[Cơ chế] Bắn quả cầu điện nảy liên tục qua lại. [Hiệu ứng] Bắn trúng mục tiêu đầu tiên, quả cầu sét nảy sang 2 mục tiêu lân cận. Sát thương chia đều. Cực kỳ hiệu quả khi địch đứng sát nhau.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tầm Trung (Lan truyền)", combo_tag: "Chain_Spark" },
        { name: "Roi Sét Vút Căng", desc: "[Cơ chế] Nắm giữ dòng plasma dạng sợi. [Hiệu ứng] Vung roi chém rách áo giáp Kevlar như tờ giấy. Bỏ qua 20% DEF vật lý. Tầm đánh vươn xa 4m tạo áp lực lớn.", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Cận Chiến Xa", combo_tag: "Lightning_Whip" },
        { name: "Cầu Lôi Áp Sát", desc: "[Cơ chế] Triệu hồi 3 quả cầu điện trôi nổi quanh người. [Hiệu ứng] Cầu tự động lao vào kích nổ bất cứ kẻ địch nào dám bước vào bán kính 2m quanh người thi triển. Bảo vệ tuyệt vời cho Pháp sư.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Bản thân (Phòng ngự chủ động)", combo_tag: "Lightning_Orbs" },
        { name: "Lôi Cước Sấm Chớp", desc: "[Cơ chế] Tụ lôi điện ở gót chân tạo lực đẩy từ trường. [Hiệu ứng] Tung cú đá vòng cầu bay với tốc độ siêu thanh. Kẻ địch trúng đòn bị hất văng cực xa (Knockback 5m) và tê rần toàn thân.", rank: "Thiết Giai", cost: { type: "Stamina", value: 35 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Cận Chiến (Hất văng)", combo_tag: "Thunder_Kick" },
        { name: "Tường Điện Đẩy Lùi", desc: "[Cơ chế] Dựng bức rào lưới điện phẳng. [Hiệu ứng] Không cản được đạn pháo, nhưng hất văng mọi mục tiêu thể rắn lao vào (Dị thú, Lính đánh thuê). Đốt cháy dây leo ma thuật của Hệ Mộc.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tường Chắn Nhỏ", combo_tag: "Electric_Fence" },
        { name: "Điện Cực Bạo Nổ", desc: "[Cơ chế] Gài một dấu ấn điện cực âm vào mục tiêu. [Hiệu ứng] Nếu đòn đánh tiếp theo mang điện cực dương (Hệ Lôi bất kỳ), dấu ấn sẽ phát nổ gây thêm 100% sát thương bạo kích chuẩn. Đòn mồi hoàn hảo.", rank: "Phàm Giai", cost: { type: "MP", value: 15 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Tầm Xa (Đánh dấu)", combo_tag: "Polarity_Mark" },
        { name: "Lưới Lôi Trói Buộc", desc: "[Cơ chế] Phóng ra mạng nhện dệt bằng tĩnh điện. [Hiệu ứng] Bọc chặt mục tiêu, gây co giật cơ bắp. Khóa chết (Root) mục tiêu trong 1.5 giây, mục tiêu nhận thêm 20% sát thương từ mọi nguồn trong lúc bị trói.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tầm Trung (Khống chế cứng)", combo_tag: "Lightning_Net" },
        { name: "Điện Giật Xuyên Não", desc: "[Cơ chế] Xuyên qua mũ giáp, chích điện trực tiếp vào tủy sống. [Hiệu ứng] Áp tay lên đầu địch, phóng điện. Gây sát thương cực lớn, trừ vĩnh viễn 5 điểm Sanity và gây nhầm lẫn (Tấn công nhầm đồng đội) 1 lượt.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Tinh Thần"], range_type: "Cận Chiến (Sát thương Tinh thần)", combo_tag: "Brain_Shock" },
        { name: "Lôi Pháo Đoạt Mạng", desc: "[Cơ chế] Nén hạt electron trong 2 giây rồi xả ra như súng laser. [Hiệu ứng] Bắn một chùm tia chớp dày đặc đâm xuyên toàn bộ tuyến đường 15m. Sát thương phá hủy đội hình dày đặc, nướng chín áo giáp kim loại.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Đường thẳng (Kênh truyền)", combo_tag: "Thunder_Cannon" },
        { name: "Sấm Động Phá Giáp", desc: "[Cơ chế] Sóng âm sấm rền đập nát kết cấu phân tử. [Hiệu ứng] Hét ra tiếng sấm hoặc đập vũ khí xuống đất. Sóng âm phá vỡ lá chắn ma thuật, giảm 30% Phòng thủ (DEF) của mọi kẻ địch xung quanh trong 5 giây.", rank: "Phàm Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Sóng Âm"], range_type: "AoE Nhỏ (Debuff)", combo_tag: "Thunder_Break" },
        { name: "Điện Từ Hút Khí", desc: "[Cơ chế] Từ trường hút mọi vũ khí bay (Tên, Phi tiêu) bằng kim loại. [Hiệu ứng] Bật hào quang hút. Toàn bộ đạn đạo kim loại bay về phía đồng minh sẽ bị bẻ cong quỹ đạo, hút hết vào người thi triển (Yêu cầu thi triển phải có Giáp xịn để tank).", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Từ Trường"], range_type: "Bản thân (Bảo vệ đồng đội)", combo_tag: "Magnet_Draw" },
        { name: "Tia Chớp Phá Tường", desc: "[Cơ chế] Đâm xuyên từ trường tạo động năng tuyệt đối. [Hiệu ứng] Lao sầm về phía trước (Charge) cắm vai/vũ khí vào tường đá, cửa sắt dày 20cm làm nát bấy tất cả. Đòn mở đường hoặc phá vây tuyệt hảo.", rank: "Thiết Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Đường thẳng (Phá rào cản)", combo_tag: "Lightning_Breach" },
        { name: "Giáp Lôi Cận Chiến", desc: "[Cơ chế] Bọc hai cánh tay trong ống tay áo plasma. [Hiệu ứng] Các đòn đấm tay không trở thành đòn ma pháp Hệ Lôi. Bỏ qua 50% Giáp vật lý, mỗi cú đấm có 10% tỷ lệ gây Choáng vi mô (0.1s).", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Bản thân (Buff vũ khí)", combo_tag: "Plasma_Fists" },
        { name: "Lôi Nhẫn Cắt Góc", desc: "[Cơ chế] Chém ra một lưỡi đao điện từ có thể bẻ cong đường bay. [Hiệu ứng] Phi tiêu điện bay vòng qua tảng đá/khiên chắn thẳng để chém vào lưng đối phương nấp phía sau. Bất ngờ và chí mạng.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Tầm Trung (Đạn đạo vòng cung)", combo_tag: "Curve_Spark" },
        { name: "Lôi Đạn Nảy Bật", desc: "[Cơ chế] Quả cầu sét đậm đặc nảy trên mọi bề mặt cứng. [Hiệu ứng] Bắn vào hầm ngầm, quả cầu nảy dội 5 lần liên tục vào các bức tường, tự động nổ văng sát thương vào những kẻ đang lẩn trốn trong phòng kín.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Đạn nảy (Góc hẹp)", combo_tag: "Bouncing_Shock" },
        { name: "Xung Điện Hủy Diệt", desc: "[Cơ chế] Áp hai tay vào ngực mục tiêu, xả thẳng toàn bộ tụ điện. [Hiệu ứng] Đòn cận chiến tất sát cấp thấp. Gây nổ tung buồng phổi và đốt cháy tim. Lượng HP mục tiêu càng cao, sát thương giật lùi càng lớn.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Cận Chiến (Dồn sát thương)", combo_tag: "Lethal_Discharge" },
        { name: "Lôi Kích Cửu Thiên", desc: "[Cơ chế] Tích tụ điện tích âm ở đám mây và điện tích dương ở mục tiêu, tạo đường dẫn ion hóa trong không khí. [Hiệu ứng] Triệu hồi một tia sét vĩ đại đánh thẳng từ bầu trời xuống đỉnh đầu mục tiêu. Bỏ qua mọi khiên chắn vật lý (như mái nhà, khiên gỗ). Gây sát thương Lôi cực mạnh và 80% tỷ lệ gây Choáng (Stun) trong 2 giây. [Tương tác] Sát thương x2 nếu trời đang mưa hoặc mục tiêu đứng dưới nước.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tầm Rất Xa (Đơn mục tiêu từ trên cao)", combo_tag: "Sky_Smite" },
        { name: "Thiểm Điện Tốc", desc: "[Cơ chế] Phân rã cơ thể thành các hạt electron trong khoảnh khắc và dịch chuyển theo đường dẫn điện từ. [Hiệu ứng] Hóa thành tia chớp di chuyển (Blink) tức thời một đoạn 20m. Bỏ qua mọi vật cản vật lý (tường, rào chắn, lưới). Để lại một vệt sét nhỏ gây sát thương giật cho kẻ nào đứng trên quỹ đạo di chuyển. [Tác dụng phụ] Gây chóng mặt nhẹ (Trừ 2 Sanity mỗi lần dùng liên tiếp).", rank: "Ngân Giai", cost: { type: "Stamina", value: 1500 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Không Gian"], range_type: "Bản thân (Dịch chuyển tức thời)", combo_tag: "Lightning_Blink" },
        { name: "Lưới Điện Phòng Thủ", desc: "[Cơ chế] Cắm các cọc ma lực mang điện tích lơ lửng xung quanh tạo thành mạng lưới plasma. [Hiệu ứng] Giăng bẫy điện diện rộng (15x15m). Kẻ địch hoặc quái vật bước vào sẽ bị điện giật liên tục (DPS), co rút cơ bắp dẫn đến tê liệt hoàn toàn (Không thể di chuyển, AGI giảm 90%). Dùng để bảo vệ căn cứ cắm trại.", rank: "Thiết Giai", cost: { type: "MP", value: 350 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "AoE Trung (Đặt bẫy trận địa)", combo_tag: "Electric_Grid" },
        { name: "Lôi Trảo Xuyên Tâm", desc: "[Cơ chế] Tụ điện áp lên tới 10.000 Volt vào năm đầu ngón tay/móng vuốt, tạo hiệu ứng cắt plasma vi mô. [Hiệu ứng] Đòn cận chiến chí mạng. Xuyên thủng mọi loại giáp kim loại (Kim loại càng dẫn điện sát thương càng lớn). Điện giật thẳng vào tim gây rối loạn nhịp tim (Trừ 10% Max HP ngay lập tức).", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Cận Chiến (Sát thương chuẩn)", combo_tag: "Heart_Shock_Claw" },
        { name: "Cầu Sét Truy Đuổi", desc: "[Cơ chế] Nén điện thành khối cầu plasma trôi nổi có khả năng cảm nhận từ trường sinh học. [Hiệu ứng] Bắn quả cầu điện di chuyển chậm (5m/s) nhưng tự động bám theo mục tiêu mang điện tích dương hoặc có thân nhiệt. Không thể né bằng cách chạy ziczac. Khi chạm vào sẽ nổ tung gây Tê Liệt 1 phút.", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tầm Xa (Đạn khóa mục tiêu)", combo_tag: "Tracking_Orb" },
        { name: "Từ Trường Vô Hiệu", desc: "[Cơ chế] Phóng thích một xung điện từ (EMP - Electromagnetic Pulse) cường độ cao bằng cách kích nổ tụ điện sinh học. [Hiệu ứng] Bán kính 50m. Không gây sát thương lên sinh vật nhưng lập tức làm chập mạch, đốt cháy bo mạch của toàn bộ máy móc, robot chiến đấu (Mecha), vô hiệu hóa súng laser và thiết bị liên lạc của UHA trong 1 giờ.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Từ Trường"], range_type: "AoE Rộng (Chống Công Nghệ)", combo_tag: "EMP_Blast" },
        { name: "Kích Thích Cơ Bắp", desc: "[Cơ chế] Dùng luồng điện siêu nhỏ chạy dọc tủy sống để bỏ qua giới hạn tự bảo vệ của cơ bắp. [Hiệu ứng] Buff cường hóa cực mạnh. Tăng 150% STR và 200% AGI trong 10 phút. Cơ thể phản ứng với tốc độ chớp giật. [Tác dụng phụ] Hết hiệu lực, các bó cơ bị rách vi mô do hoạt động quá tải, rơi vào trạng thái Kiệt Sức (Mất khả năng tấn công trong 4 phút tiếp theo).", rank: "Thiết Giai", cost: { type: "HP", value: 300 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Buff Cuồng nộ)", combo_tag: "Nerve_Stimulation" },
        { name: "Lôi Kiếm", desc: "[Cơ chế] Bọc vũ khí kim loại (Kiếm/Đao) trong trường tĩnh điện mật độ cao. [Hiệu ứng] Tăng tầm chém (do tia lửa điện phóng ra ở lưỡi kiếm). Mỗi đòn chém trúng địch sẽ tạo ra dòng sét lan (Chain Lightning) giật sang tối đa 2 kẻ địch lân cận trong bán kính 3m.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Cận Chiến (Lan truyền)", combo_tag: "Lightning_Blade" },
        { name: "Giáp Phản Xạ Điện", desc: "[Cơ chế] Dựng một lồng Faraday bao quanh cơ thể bằng điện năng thuần túy. [Hiệu ứng] Bật khiên điện. Chặn đứng và nướng chín các vật thể bay nhỏ (mũi tên, phi tiêu). Đẩy lùi (Knockback) ngay lập tức bất kỳ kẻ địch nào lao vào đánh cận chiến, đồng thời gây hiệu ứng Điện Giật (Trừ AGI).", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Bản thân (Phòng thủ/Hất văng)", combo_tag: "Static_Shield" },
        { name: "Bão Sét Diện Rộng", desc: "[Cơ chế] Trở thành cột thu lôi sống, xả toàn bộ điện tích tích tụ trong tế bào ra môi trường xung quanh. [Hiệu ứng] Bán kính 20m xung quanh người dùng ngập chìm trong hàng vạn tia chớp chằng chịt. Sát thương AoE liên tục trong 3 giây. Dọn dẹp tuyệt đối các đàn quái vật nhỏ (Mob).", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "AoE Rộng (Xung quanh bản thân)", combo_tag: "Thunder_Storm_AoE" },
        { name: "Kim Lôi Dẫn", desc: "[Cơ chế] Phóng một cây kim cấu tạo từ nam châm từ tính siêu mạnh găm sâu vào xương kẻ thù. [Hiệu ứng] Đóng dấu mục tiêu. Biến mục tiêu thành cột thu lôi di động. Mọi kỹ năng hệ Lôi (của người dùng và đồng minh) tung ra sau đó sẽ bỏ qua kiểm tra Độ chính xác (Accuracy), bay tự động tìm đến và trúng đích 100%.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Từ Trường"], range_type: "Tầm Xa (Đánh dấu khóa mục tiêu)", combo_tag: "Lightning_Rod_Mark" },
        { name: "Thương Sét", desc: "[Cơ chế] Nén hàng triệu Volt điện thành một mũi lao plasma định hình tĩnh. [Hiệu ứng] Ném lao sét với tốc độ siêu âm. Xuyên thủng nhiều mục tiêu trên một đường thẳng dài 50m. Phá vỡ hoàn toàn các bức tường đá và khiên phòng thủ kiên cố nhất. Gây bỏng điện từ từ vết thương.", rank: "Kim Giai", cost: { type: "MP", value: 95000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Đường thẳng dài (Xuyên thấu)", combo_tag: "Plasma_Spear" },
        { name: "Nhãn Lực Siêu Tốc", desc: "[Cơ chế] Đẩy nhanh tốc độ dẫn truyền nơ-ron thần kinh thị giác lên ngưỡng giới hạn sinh học. [Hiệu ứng] Kích hoạt trạng thái Bullet Time (Thời gian quay chậm). Mọi chuyển động của kẻ địch, quỹ đạo của viên đạn hay mũi tên bay tới đều trở nên cực kỳ chậm chạp. Giúp né tránh hoàn hảo 100% trong 2 phút.", rank: "Kim Giai", cost: { type: "Sanity", value: 15 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Buff Né Tránh Tối Thượng)", combo_tag: "Bullet_Time_Eye" },
        { name: "Sạc Pin (Sinh hoạt)", desc: "[Cơ chế] Vi điều chỉnh cường độ dòng điện (Ampe) và hiệu điện thế (Volt) qua đầu ngón tay. [Hiệu ứng] Nạp năng lượng trực tiếp cho ắc quy xe, điện thoại, bộ đàm, hoặc cung cấp năng lượng cho các loại chiến giáp (Mecha) của phe ta khi hết pin giữa Hoang Khu.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Chạm trực tiếp (Tiện ích)", combo_tag: "Utility_Charge" },
        { name: "Nam Châm Hút Đồ", desc: "[Cơ chế] Thao túng cực từ (Bắc/Nam) trên bàn tay để tạo lực hút/đẩy. [Hiệu ứng] Hút vũ khí kim loại (Kiếm, súng) giật tung khỏi tay kẻ địch, tước vũ khí của chúng. Hoặc dùng để lấy các vật phẩm, chìa khóa từ khoảng cách xa 15m mà không cần di chuyển.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Từ Trường"], range_type: "Tầm Trung (Thao túng vật lý)", combo_tag: "Magnetic_Pull" },
        { name: "Sốc Tim (Cấp cứu)", desc: "[Cơ chế] Mô phỏng hoạt động của máy khử rung tim (Defibrillator) bằng hai bàn tay. [Hiệu ứng] Phép thuật hồi sinh khẩn cấp. Dùng dòng điện chính xác kích tim đồng đội vừa tử vong (Trong vòng 2 phút) đập trở lại. Phục hồi 5% HP. Nếu dùng sai mục tiêu đang sống khỏe sẽ gây sát thương nội tạng.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Sinh Mệnh"], range_type: "Cận Chiến (Hồi Sinh Y Tế)", combo_tag: "Defibrillator_Shock" },
        { name: "Vũ Điệu Tia Chớp", desc: "[Cơ chế] Giảm thiểu ma sát không khí và kết hợp dòng điện vào cơ bắp chân/tay. [Hiệu ứng] Áp sát và tung ra chuỗi combo 5 đòn đánh liên tiếp trong đúng 1 giây thực tế. Đối phương hoàn toàn không thể nhìn rõ hay đỡ gạt. Gây sát thương vật lý lai Lôi cực mạnh.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2800 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Cận Chiến (Combo tốc độ)", combo_tag: "Lightning_Flurry" },
        { name: "Sét Lan Truyền", desc: "[Cơ chế] Lợi dụng độ ẩm của không khí và mồ hôi trên cơ thể địch để tạo cầu nối ion. [Hiệu ứng] Bắn một tia sét trúng một mục tiêu. Tia sét tự động tìm các vật dẫn điện lân cận, nảy (Bounce) sang 3 mục tiêu khác trong bán kính 5m. Sát thương giảm dần 20% qua mỗi lần nảy.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tầm Trung (Nảy mục tiêu)", combo_tag: "Chain_Lightning" },
        { name: "Cơ Thể Tích Điện (Nội tại)", desc: "[Cơ chế] Tế bào sinh học dung hợp hoàn toàn với hạt mang điện. Lỗ chân lông hoạt động như cổng sạc. [Hiệu ứng] Kháng 100% mọi loại sát thương Lôi/Điện (Kể cả bị sét đánh trúng). Khi bị tấn công bằng hệ Lôi, thay vì mất HP, cơ thể sẽ hấp thụ toàn bộ để chuyển hóa thành MP theo tỷ lệ 1:1.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Miễn nhiễm/Hút năng lượng)", combo_tag: "Electric_Immunity" },
        { name: "Hàn Điện (Sinh hoạt)", desc: "[Cơ chế] Hội tụ hồ quang điện nhiệt độ cao cực kỳ chuẩn xác. [Hiệu ứng] Phép thuật kỹ sư. Dùng tia lửa điện để hàn lại các vết đứt gãy của kim loại, sửa chữa các mảng giáp xe cộ, xe bọc thép, hoặc gắn lại vũ khí gãy trong điều kiện không có xưởng rèn.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Nhiệt"], range_type: "Cận Chiến (Sửa chữa)", combo_tag: "Arc_Welding" },
        { name: "Đuốc Plasma", desc: "[Cơ chế] Bắn dòng plasma ion hóa siêu nóng thông qua trường điện từ nhỏ. [Hiệu ứng] Không dùng để tấn công. Tạo nguồn sáng cực kỳ rực rỡ soi sáng hang động hắc ám, và phát ra nhiệt độ đủ sức cắt thủng các cánh cửa hầm ngầm bằng hợp kim titan của tàn tích thế giới cũ.", rank: "Thiết Giai", cost: { type: "MP", value: 120 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Plasma"], range_type: "Cận Chiến (Xuyên phá vật cản)", combo_tag: "Plasma_Torch" },
        { name: "Gây Nhiễu Sóng", desc: "[Cơ chế] Phát ra tín hiệu điện từ rác (Jamming) lấp đầy các dải băng tần phổ biến. [Hiệu ứng] Tác chiến điện tử. Trong bán kính 2km, chặn đứt toàn bộ liên lạc bộ đàm, sóng vô tuyến, sóng radar của máy bay quân sự địch. Biến đối phương thành những kẻ mù và điếc về mặt thông tin.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Sóng Âm"], range_type: "AoE Rất Rộng (Chiến tranh điện tử)", combo_tag: "Radio_Jammer" },
        { name: "Thang Máy Từ Tính", desc: "[Cơ chế] Thay đổi cực từ của cơ thể (từ tính trái dấu) với bề mặt kim loại. [Hiệu ứng] Kỹ năng di chuyển. Lợi dụng các lõi thép, đường ray kim loại, hoặc vỏ tàu vũ trụ cũ để lướt, bay lơ lửng, hoặc đi ngược lên các tòa nhà chọc trời một cách dễ dàng bất chấp trọng lực.", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Từ Trường"], range_type: "Bản thân (Di chuyển địa hình kim loại)", combo_tag: "Magnetic_Levitation" },
        { name: "Bão Điện Từ (Cấp Thảm Họa)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Kích nổ từ trường lõi hành tinh (Geomagnetic Storm). [Hiệu ứng] Tạo một cơn bão điện từ bao trùm toàn bộ một thành phố (bán kính 20km). Hủy diệt, thiêu rụi vĩnh viễn MỌI loại công nghệ, giáp Mecha, và xóa sạch dữ liệu số của đối phương. Bầu trời xuất hiện cực quang máu. [Tác dụng phụ] Rút cạn Max MP xuống còn 0 trong 7 ngày. Toàn bộ sủng thú hệ máy móc của Tamer bị ép rơi vào trạng thái Shutdown không thể triệu hồi.", rank: "Diệu Giai", cost: { type: "MP", value: 5000000 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Từ Trường", "Hủy Diệt"], range_type: "AoE Cực Rộng (Tận Thế Công Nghệ)", combo_tag: "Divine_EMP_Storm" },
        { name: "Bẫy Mìn Điện", desc: "[Cơ chế] Nén điện tích âm vào lòng đất, kích hoạt bằng cảm biến rung chấn. [Hiệu ứng] Đặt một quả mìn điện vô hình dưới đất. Khi kẻ địch dẫm vào sẽ kích hoạt dòng xả hàng chục ngàn Volt từ dưới chân lên. Gây cháy đen, co giật và ngất xỉu (Stun) ngay lập tức.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Thổ"], range_type: "AoE Nhỏ (Đặt bẫy tàng hình)", combo_tag: "Shock_Mine" },
        { name: "Thông Báo Khẩn", desc: "[Cơ chế] Đồng bộ mã Morse bằng xung điện thẳng vào vỏ não đồng minh. [Hiệu ứng] Không cần há miệng nói. Gửi một tín hiệu điện mang thông điệp mã hóa trực tiếp vào não đồng đội dù ở cách xa nhau hoặc đang trong môi trường câm lặng tuyệt đối/dưới nước.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Tinh Thần"], range_type: "Tầm Xa (Liên lạc nội bộ)", combo_tag: "Nerve_Comms" },
        { name: "Quá Tải Hệ Thống", desc: "[Cơ chế] Bơm cường độ dòng điện (Ampe) vượt mức chịu đựng vật liệu vào bộ vi xử lý đối phương. [Hiệu ứng] Ép các robot, máy bay không người lái, hoặc ụ súng tự động của UHA phải quay cuồng hoạt động trên 500% công suất. Dẫn đến nóng chảy cốt lõi và tự nổ tung gây sát thương AoE.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tầm Xa (Chống máy móc)", combo_tag: "Overload_Detonation" },
        { name: "Tốc Độ Ánh Sáng (Lôi Hóa Bản Nguyên)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Xóa bỏ hoàn toàn giới hạn vật lý của cấu trúc carbon. Biến 100% cơ thể thịt thành photon và điện tử thuần túy (Đạt tốc độ 299,792 km/s). [Hiệu ứng] Không thời gian dừng lại. Trong 3 giây chủ quan, người dùng có thể lướt qua mọi ngóc ngách chiến trường, tung hàng triệu đòn đánh, xuyên thủng trái tim của toàn bộ đội hình địch trước khi chúng kịp chớp mắt. [Tác dụng phụ cực lớn] Cơ thể vật lý bị nướng chín ở cấp độ nguyên tử. Sau khi dùng, 99% tỷ lệ cơ thể sụp đổ thành tro bụi (Chết vĩnh viễn). Nếu sống sót (1%), Max HP và toàn bộ các chỉ số giảm 90% vĩnh viễn, tàn phế không thể chữa trị bằng ma pháp thông thường.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 90 }, cooldown: { value: 3650, unit: "Ngày", display_text: "10 Năm" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Ánh Sáng", "Thời Gian"], range_type: "Toàn Bản Đồ (Tuyệt sát chân lý)", combo_tag: "Light_Speed_Annihilation" },
        { name: "Khởi Động Máy Móc", desc: "[Cơ chế] Giả lập chuỗi xung điện mật mã để bypass hệ thống bảo mật. [Hiệu ứng] Cấp nguồn và cưỡng chế kích hoạt khởi động các cỗ máy cổ đại ở tàn tích, cửa hầm bảo mật, xe tăng, trực thăng mà không cần có chìa khóa vật lý hay thẻ từ.", rank: "Thiết Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Chạm trực tiếp (Hack phần cứng)", combo_tag: "Machine_Bypass" },
        { name: "Hóa Hình - Lôi Quang (Đặc Biệt - Bản Thú)", desc: "[Cơ chế] Dị thú hệ Lôi khổng lồ giấu cơ thể vào một đám mây tích điện. [Hiệu ứng] Khi cần hạ phàm, cơ thể hóa thành một tia sét khổng lồ xé rách không gian, đánh ầm xuống mặt đất tạo hố thiên thạch, từ trong bụi mù ngưng tụ ra hình dáng con người. Sát khí bạo tàn, tỏa ra mùi Ozone nồng nặc.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 45000 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Ngụy trang xuất hiện bạo lực)", combo_tag: "Beast_Lightning_Form" },
        { name: "Lôi Kích Cửu Thiên (Bản Thú)", desc: "[Cơ chế] Dùng sừng/đuôi làm ăng-ten cộng hưởng sấm sét tự nhiên. [Hiệu ứng] Phóng tia sét tàn bạo từ trời xuống. Sát thương thuần túy cao hơn phiên bản Tamer, tỷ lệ Tê Liệt là 100% đối với kẻ địch có CON thấp. Âm thanh sấm rền gây điếc tạm thời cho toàn bộ chiến trường.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Sóng Âm"], range_type: "Tầm Xa (Trực tiếp từ trời)", combo_tag: "Beast_Thunder_Strike" },
        { name: "Thiểm Điện Hành", desc: "[Cơ chế] Bọc cơ thể trong một bong bóng plasma khí động học siêu trượt. [Hiệu ứng] Hóa thân thành vệt chớp di chuyển tức thời (Blink) liên tục 3 lần (mỗi lần 15m), chuyển hướng linh hoạt theo hình chữ Z. Rất khó để xạ thủ hoặc pháp sư khóa mục tiêu.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2000 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Không Gian"], range_type: "Bản thân (Di chuyển Ziczac)", combo_tag: "Lightning_Dash_Z" },
        { name: "Lưới Điện Sinh Tử", desc: "[Cơ chế] Nhả ra hàng trăm sợi tơ tẩm dung dịch dẫn điện, sau đó nạp điện cao áp. [Hiệu ứng] Tạo một vùng lưới mạng nhện khổng lồ. Mọi vật thể chạm vào không chỉ bị giật tung mà còn bị nướng chín, bốc mùi khét lẹt. Đóng vai trò phòng thủ sào huyệt (Nest Defense) tuyệt vời của loài nhện/sói lôi.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "AoE Rộng (Phòng thủ sào huyệt)", combo_tag: "Lethal_Web_Grid" },
        { name: "Lôi Trảo Xuyên Tâm (Bản Thú)", desc: "[Cơ chế] Móng vuốt xương tích tụ ion âm, phát sáng xanh lóa mắt. [Hiệu ứng] Cú vồ tàn khốc. Vuốt đâm xuyên các lớp áo giáp dày nhất. Điện truyền thẳng vào mạch máu, nấu sôi máu và giật tung nội tạng từ bên trong, gây xuất huyết trong nghiêm trọng.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3000 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Cận Chiến (Xuyên thấu chí mạng)", combo_tag: "Beast_Lightning_Claw" },
        { name: "Lôi Cầu Đuổi Mục Tiêu", desc: "[Cơ chế] Khạc ra quả cầu sét từ miệng, hoạt động như tên lửa tầm nhiệt. [Hiệu ứng] Bắn quả cầu điện tự động truy đuổi nguồn nhiệt (người sống, động cơ xe). Nổ diện rộng, tàn phá vật chất và gây tê liệt. Nếu mục tiêu chạy trốn xuống nước, quả cầu nổ lan tỏa sát thương xuống toàn bộ hồ nước.", rank: "Thiết Giai", cost: { type: "Stamina", value: 800 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tầm Xa (Truy đuổi nhiệt)", combo_tag: "Heat_Seeker_Orb" },
        { name: "Từ Trường Khống Chế", desc: "[Cơ chế] Biến sừng hoặc đuôi thành một nam châm điện từ khổng lồ. [Hiệu ứng] Bật từ trường mạnh. Cưỡng chế hút sạch gươm, giáo, súng ống bằng kim loại của toàn bộ binh lính trong bán kính 30m bay khỏi tay họ, dán chặt vào cơ thể thú, biến đối phương thành tay không tấc sắt.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Từ Trường"], range_type: "AoE Rộng (Tước vũ khí)", combo_tag: "Magnetic_Disarm" },
        { name: "Gia Tốc Dòng Điện (Bản Thú)", desc: "[Cơ chế] Bơm dòng điện thẳng vào tim để ép bơm máu với tốc độ 500 nhịp/phút. [Hiệu ứng] Tăng 300% Tốc Độ Né Tránh và tốc độ chạy trong 2 phút. Cơ thể mờ đi, để lại tàn ảnh trên đường chạy. Hoàn hảo để lao vào kết liễu Pháp sư hàng sau.", rank: "Ngân Giai", cost: { type: "HP", value: 2500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Buff Tốc độ cực hạn)", combo_tag: "Beast_Overclock" },
        { name: "Sét Đen (Thiên Phạt Hủy Diệt)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Trích xuất hạt phản vật chất kết hợp với ma lực Lôi tạo ra Hắc Lôi (Black Lightning). Đây là loại lôi điện của hình phạt tự nhiên. [Hiệu ứng] Bắn ra cột sét màu đen đặc. Sát thương Lôi x10 lần thông thường. Đặc biệt, nó có hiệu ứng ĂN MÒN cả ma pháp và vật chất: thiêu rụi khiên Tinh thần, bốc hơi giáp sắt, và đốt cháy MP của kẻ địch khiến chúng cạn kiệt năng lượng. [Tác dụng phụ] Hắc lôi ăn mòn cả người tung chiêu. Trừ 30% Max HP vĩnh viễn không thể hồi phục. Cánh tay/Bộ phận phóng sét bị hoại tử, đen kịt và mất cảm giác trong 3 tháng.", rank: "Diệu Giai", cost: { type: "HP", value: 55000 }, cooldown: { value: 90, unit: "Ngày", display_text: "90 Ngày" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Bóng Tối", "Hủy Diệt"], range_type: "Đường thẳng dài (Xuyên thấu tuyệt đối)", combo_tag: "Divine_Black_Lightning" },
        { name: "Lôi Quang Thuẫn", desc: "[Cơ chế] Cuộn mình lại, các vảy/lông mao phát ra trường lực tĩnh điện mạnh mẽ. [Hiệu ứng] Tạo khiên tròn bao bọc. Hấp thụ sát thương vật lý cực tốt. Mọi kẻ địch chạm vào khiên đều bị đẩy văng (Knockback) 10m và chịu sát thương phản đòn do giật điện.", rank: "Thiết Giai", cost: { type: "Stamina", value: 400 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi"], range_type: "Bản thân (Phòng thủ/Hất văng)", combo_tag: "Beast_Electric_Shield" },
        { name: "Phóng Điện Diện Rộng", desc: "[Cơ chế] Tụ điện tích âm ở chân và dương ở lưng, tạo ra vụ nổ điện tích không định hướng. [Hiệu ứng] Đứng bằng hai chân sau, đập mạnh chân trước xuống đất. Phát nổ toàn bộ năng lượng điện thành dạng sóng vòm (Dome) bán kính 30m. Thiêu cháy cây cối, dọn dẹp hàng ngàn lính tép riu/quái nhỏ xung quanh.", rank: "Ngân Giai", cost: { type: "Stamina", value: 5000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "AoE Rộng (Phát nổ xung quanh)", combo_tag: "Electric_Nova" },
        { name: "Lôi Dẫn Châm", desc: "[Cơ chế] Phóng vảy, lông tẩm từ tính hoặc gai nhọn găm vào da thịt địch. [Hiệu ứng] Đóng dấu ấn Lôi dẫn cực mạnh. Kẻ địch bị găm kim sẽ trở thành cột thu lôi cực lớn, hút mọi đòn sấm sét ngẫu nhiên trong môi trường hoặc kỹ năng Lôi diện rộng trút toàn bộ sát thương vào một mình hắn.", rank: "Thiết Giai", cost: { type: "Stamina", value: 300 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Tầm Xa (Đánh dấu/Thu lôi)", combo_tag: "Beast_Lightning_Rod" },
        { name: "Thương Sét Xuyên Phá", desc: "[Cơ chế] Nén điện thành hình chóp nón trên đầu sừng hoặc vuốt. [Hiệu ứng] Phóng ra với động năng khổng lồ. Thanh lao sét xuyên thủng nhiều kẻ địch xếp hàng dọc, phá hủy mọi loại lá chắn năng lượng chặn đường. Vết đâm bị cháy xém không thể cầm máu.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Đường thẳng (Xuyên thủng tuyến tính)", combo_tag: "Beast_Plasma_Spear" },
        { name: "Chớp Mắt Sinh Tử", desc: "[Cơ chế] Tuyến thượng thận bơm điện cực đại lên võng mạc, làm chậm nhận thức thời gian của thú. [Hiệu ứng] Bản năng dã thú tối thượng. Mọi chuyển động của thợ săn (Tamer, đạn, phép thuật) đều chậm lại rõ rệt. Giúp thú né được những đòn đánh chí mạng vào điểm yếu (Mắt, cổ).", rank: "Kim Giai", cost: { type: "Sanity", value: 10 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Học"], range_type: "Bản thân (Sinh tồn/Né đòn)", combo_tag: "Beast_Reflex" },
        { name: "Mạch Điện Cộng Hưởng", desc: "[Cơ chế] Chia sẻ một phần ion điện qua tiếp xúc vật lý hoặc dây leo dẫn điện. [Hiệu ứng] Kỹ năng kết hợp bầy đàn. Truyền điện sang các đồng minh không có hệ Lôi, bao bọc vũ khí/móng vuốt của chúng bằng một lớp sát thương Lôi bổ sung (+20% sát thương gốc) trong 3 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Cận Chiến (Buff Đồng minh)", combo_tag: "Lightning_Enchant" },
        { name: "Nhịp Tim Sấm Sét", desc: "[Cơ chế] Cơ hoành tự động co giật bằng điện khi tim ngừng đập. [Hiệu ứng] Kỹ năng sinh tồn ngoạn mục. Khi thú bị đánh gục (HP về 0), cơ thể tự phát ra luồng điện cực mạnh sốc lại nhịp tim, giúp nó hồi sinh tức khắc với 10% HP và đẩy văng mọi kẻ thù đứng gần đang định thu thập lõi quái.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 15000 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Sinh Mệnh"], range_type: "Bản thân (Hồi sinh bị động)", combo_tag: "Beast_Defibrillator" },
        { name: "Vũ Điệu Tia Chớp (Bản Thú)", desc: "[Cơ chế] Tận dụng sức bật cơ bắp 4 chân và gia tốc từ trường. [Hiệu ứng] Phóng tới mục tiêu, chém liên hoàn 5 đòn móng vuốt mang theo điện cao áp. Đòn đánh kết thúc kèm theo cú cắn chứa sấm sét, giật nát cơ thể mục tiêu. Gây sát thương đơn mục tiêu cực khủng.", rank: "Ngân Giai", cost: { type: "Stamina", value: 5000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Cận Chiến (Combo đơn mục tiêu)", combo_tag: "Beast_Lightning_Combo" },
        { name: "Sét Lan Truyền (Bầy Đàn)", desc: "[Cơ chế] Cấu trúc sừng vòm phân nhánh tia sét. [Hiệu ứng] Phóng tia sét từ sừng trúng kẻ địch đầu tiên, lập tức nảy sang 3 mục tiêu khác. Nếu đàn thú đứng cạnh nhau, chúng có thể nảy tia sét qua lại lẫn nhau để tăng khuếch đại sát thương trước khi bắn vào địch.", rank: "Thiết Giai", cost: { type: "Stamina", value: 1500 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi"], range_type: "Tầm Trung (Lan truyền sát thương)", combo_tag: "Beast_Chain_Lightning" },
        { name: "Lôi Điện Chân Ngã (Bị động)", desc: "[Cơ chế] Mọi tế bào đều ngậm điện. Ma sát không khí cũng sinh ra điện. [Hiệu ứng] Mọi đòn đánh tay, cắn xé cơ bản của Dị thú mặc định được cộng thêm 10% sát thương chuẩn hệ Lôi (bỏ qua giáp vật lý). Biến nó thành cỗ máy bào mòn giáp cực kỳ đáng sợ.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Vật Lý"], range_type: "Cận Chiến (Buff đòn đánh cơ bản)", combo_tag: "True_Lightning_Strike" }
    ],
  "Hệ Phong": [
        { name: "Hóa Hình - Phong Linh", desc: "[Cơ Chế Sinh Học & Nguyên Lý] Thay đổi mật độ xương thành dạng xốp rỗng rễ tre (giống cấu trúc xương chim) nhưng gia cường bằng ma lực. Nhiều túi khí mọc khắp khoang bụng giảm trọng lượng. Thanh quản tiến hóa tạo sóng âm siêu cao. [Hiệu ứng] Dáng người thanh mảnh, lơ lửng cách mặt đất 10cm. Ở dạng người, rơi tự do từ 1000m không hề hấn (như chiếc lá). Giọng nói truyền xa hàng chục kilomet. Tốc độ di chuyển cơ bản cực cao. [Tác dụng phụ] Cơ thể rất nhẹ, dễ bị đánh bay bởi các đòn tấn công vật lý diện rộng (Giảm 20% DEF vật lý).", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sinh Học"], range_type: "Bản thân (Chuyển đổi hình thái)", combo_tag: "Form_Wind" },
        { name: "Phong Đao Tốc Độ", desc: "[Cơ chế] Nén khí thành lưỡi đao vung tay không. [Hiệu ứng] Chém ra sóng gió cắt đứt da thịt từ khoảng cách 5m. Tốc độ vung nhanh, có thể chém 2 nhát liên tiếp trong 1 lượt đánh.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 3, unit: "Giây", display_text: "3 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Tầm Trung (Đạn đạo nhanh)", combo_tag: "Wind_Blade_Swift" },
        { name: "Cơ Thể Khí Động Học", desc: "[Cơ chế] Cấu trúc vảy/lông xẻ rãnh tự nhiên làm giảm hệ số cản gió xuống gần 0. [Hiệu ứng] Tốc độ chạy nước rút (Sprint) luôn nhanh hơn kẻ thù 15%. Không bao giờ bị đuối sức do lực gió cản ngược lại trên đồng bằng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Bản thân (Bị động tăng tốc)", combo_tag: "Passive_Aero_Body" },
        { name: "Cảm Nhận Áp Suất", desc: "[Cơ chế] Da nhạy cảm với luồng không khí bị dịch chuyển bởi vật thể bay. [Hiệu ứng] Nhận biết trước được mũi tên, phi tiêu hoặc dao găm đâm lén từ sau lưng thông qua tiếng gió xé hờ. Tăng 20% khả năng né đòn đánh lén.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Xung quanh (Bị động né tránh)", combo_tag: "Passive_Pressure_Sense" },
        { name: "Hô Hấp Tuần Hoàn", desc: "[Cơ chế] Hít thở theo nhịp xoáy gió giúp lấp đầy 100% dung tích phổi. [Hiệu ứng] Chạy việt dã hàng trăm kilomet mà không thở dốc. Tốc độ hồi phục Thể lực (Stamina) tăng x3 lần khi đang duy trì vận động/chạy.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Sinh Học"], range_type: "Bản thân (Bị động hồi sức)", combo_tag: "Passive_Cyclic_Breathing" },
        { name: "Màng Khí Chống Vật Thể", desc: "[Cơ chế] Quanh da tạo lớp đệm khí xoáy nhẹ 0.5cm. [Hiệu ứng] Các viên đạn súng lục hay mũi tên nhẹ khi chạm vào da sẽ bị lệch đi vài ly, làm giảm sát thương trực tiếp (Giảm 15% Sát thương đạn đạo).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Bản thân (Bị động đỡ đạn)", combo_tag: "Passive_Wind_Cushion" },
        { name: "Bước Chân Lưu Trọng", desc: "[Cơ chế] Gió cuốn nâng gót chân ngay trước khi chạm đất hoàn toàn. [Hiệu ứng] Trọng lượng đặt lên mặt đất là vô cùng nhỏ. Không để lại dấu chân trên cát, tuyết hay bùn lầy. Không kích nổ mìn cảm biến trọng lượng.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Dưới chân (Bị động tàng hình)", combo_tag: "Passive_Feather_Step" },
        { name: "Đệm Khí Phản Lực", desc: "[Cơ chế] Luồng khí hội tụ tự động bung ra khi rơi tự do tốc độ cao. [Hiệu ứng] Nhảy từ vách núi cao 100m hay máy bay trực thăng xuống đất mà không cần dù. Gió tự động nâng đỡ sát đất, triệt tiêu 100% sát thương rơi ngã.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Bị động bảo vệ rơi)", combo_tag: "Passive_Aero_Landing" },
        { name: "Âm Sát Triệt Tiêu", desc: "[Cơ chế] Hạt gió bao bọc bàn chân, triệt tiêu sóng âm lan truyền. [Hiệu ứng] Đi bộ, chạy nhảy hay leo trèo không phát ra một tiếng động nào dù là nhỏ nhất (như tiếng lá khô gãy). Sát thủ rừng rậm hoàn hảo.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Sóng Âm"], range_type: "Bản thân (Bị động câm lặng)", combo_tag: "Passive_Silent_Prowl" },
        { name: "Phong Tốc Liên Kích", desc: "[Cơ chế] Lưỡi đao mượn sức gió vung càng nhanh càng sắc. [Hiệu ứng] Càng chém liên tục trúng mục tiêu, tốc độ đánh (AGI) càng cộng dồn nhanh hơn (+5% mỗi nhát, tối đa 30%). Reset khi đổi mục tiêu.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Đòn đánh (Bị động cuồng nộ)", combo_tag: "Passive_Combo_Speed" },
        { name: "Khí Lưu Tàng Hình", desc: "[Cơ chế] Ánh sáng bị khúc xạ nhẹ bởi luồng khí nóng lạnh giao thoa quanh người. [Hiệu ứng] Đứng im lặng trong rừng gió thổi, bóng dáng cơ thể sẽ nhòa đi, tiệp màu vào phông nền phía sau (Tàng hình quang học 60%).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Ảo Giác"], range_type: "Bản thân (Bị động ngụy trang)", combo_tag: "Passive_Wind_Mirage" },
        { name: "Đao Gió Bám Đuôi", desc: "[Cơ chế] Sức mạnh cơ bắp xé toạc không khí, tạo sóng xung kích nối tiếp. [Hiệu ứng] Mọi đòn chém vật lý nặng sẽ tự động tạo ra một lưỡi đao gió mờ đi theo quỹ đạo chém. Tăng thêm tầm đánh (Reach) và gây lượng sát thương nhỏ phía sau địch.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Đòn đánh (Bị động tầm xa)", combo_tag: "Passive_Trailing_Blade" },
        { name: "Mắt Bão Tĩnh Lặng", desc: "[Cơ chế] Áp suất cực thấp quanh người làm vô hiệu các sóng xung kích gây choáng. [Hiệu ứng] Khi bị bao vây bởi 3 kẻ địch trở lên, kích hoạt trạng thái [Mắt Bão]: Hoàn toàn miễn nhiễm với Mọi loại Làm Choáng (Stun).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Bị động kháng khống chế)", combo_tag: "Passive_Eye_Of_Storm" },
        { name: "Gió Quẩn Chệch Hướng", desc: "[Cơ chế] Gió luôn thổi xoáy làm lệch các vật thể nhẹ. [Hiệu ứng] Khắc chế ám khí và độc trùng. Các loại phi tiêu có tẩm độc, gai độc hay phấn hoa bay tới sẽ bị luồng gió hất văng ngược lại, không thể chạm vào người.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Xung quanh (Bị động phòng thủ)", combo_tag: "Passive_Deflect_Dart" },
        { name: "Nhịp Đập Của Gió", desc: "[Cơ chế] Dẫn dắt luồng khí theo đội hình chữ V của đàn chim di cư. [Hiệu ứng] Đồng đội đi trong phạm vi 5m sau lưng bạn sẽ cảm thấy bước chân nhẹ bẫng. Toàn team nhận thêm 10% Tốc độ di chuyển, cực tốt cho hành quân.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "AoE Nhỏ (Bị động buff đồng minh)", combo_tag: "Passive_Tailwind_Aura" },
        { name: "Thoát Xác Khí Lưu", desc: "[Cơ chế] Cơ xương thu hẹp và bôi trơn bởi không khí. [Hiệu ứng] Khắc chế các chiêu trói buộc. Rễ cây, dây xích hay móng vuốt quái thú không bao giờ siết chặt được bạn. Tỉ lệ tẩu thoát khỏi đòn [Khóa/Grapple] thành công 100%.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Bị động giải trói)", combo_tag: "Passive_Slip_Grip" },
        { name: "Hút Oxy Phản Công", desc: "[Cơ chế] Cơ thể tạo áp suất âm, cướp đoạt oxy của kẻ thù lân cận. [Hiệu ứng] Trong trận chiến cận chiến áp sát mặt đối mặt, kẻ địch sẽ liên tục bị khó thở, trừ 1% Stamina mỗi giây, khiến vung kiếm chậm đi trông thấy.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Cận Chiến (Bị động trừ thể lực)", combo_tag: "Passive_O2_Thief" },
        { name: "Tàn Ảnh Gió", desc: "[Cơ chế] Bẻ cong ánh sáng bằng khí nén khi đổi hướng lướt đi. [Hiệu ứng] Mỗi lần thực hiện động tác Né Đòn (Dodge/Roll), sẽ để lại một cái bóng giả mờ ảo đứng yên trong 1 giây, thu hút sự chú ý của đạn pháo.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Ảo Giác"], range_type: "Bản thân (Bị động ảo ảnh)", combo_tag: "Passive_Wind_Decoy" },
        { name: "Hơi Thở Mang Mùi", desc: "[Cơ chế] Phân tích hạt mùi tử thi lơ lửng trong gió nhẹ. [Hiệu ứng] Khứu giác tuyệt đỉnh. Ngửi thấy mùi máu tươi từ cách xa 2km, xác định được kẻ địch đang bị thương lẩn trốn, không bao giờ mất dấu con mồi.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Bị động thợ săn)", combo_tag: "Passive_Scent_Tracker" },
        { name: "Bụi Xoáy Che Mắt", desc: "[Cơ chế] Bị đánh trúng văng ra lực gió xoáy hạt bụi mù dưới đất. [Hiệu ứng] Khi mất đi 10% HP trong 1 đòn, tự động tung lên 1 đám mù mây cát ngay trước mặt kẻ tấn công, làm chúng bị mất Tầm Nhìn (Mù lòa 1s).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Thổ"], range_type: "Bản thân (Bị động tung mù)", combo_tag: "Passive_Dust_Retaliate" },
        { name: "Gió Đẩy Chướng Khí", desc: "[Cơ chế] Tự động hình thành luồng gió ly tâm tản ra ngoài từ biểu bì. [Hiệu ứng] Làn gió vô hình đẩy lùi các loại khí gas ru ngủ, độc dược dạng sương mù cấp Phàm/Thiết. Đồng thời giữ cho quần áo không bao giờ bám bụi đất.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Khí"], range_type: "Xung quanh (Bị động thanh lọc)", combo_tag: "Passive_Push_Miasma" },
        { name: "Xoáy Khí Hộ Tâm", desc: "[Cơ chế] Lồng ngực chứa cơn lốc vô hình đẩy văng vũ khí cùn. [Hiệu ứng] Đỡ đòn bằng gió. Giảm 20% lượng sát thương của các đòn đấm trực diện, cú húc (Charge) của Cự thú. Tạo sức bật trả lại vị trí thăng bằng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Bản thân (Bị động giảm xóc)", combo_tag: "Passive_Tornado_Chest" },
        { name: "Lưỡi Gió Xuyên Không", desc: "[Cơ chế] Khí nén hình lưỡi cưa xoay tít đâm xuyên không khí. [Hiệu ứng] Phóng lưỡi cắt gió bỏ qua 40% giáp vật lý. Đường cắt nhẵn thín đứt lìa vũ khí phòng ngự làm bằng gỗ/đồng của đối phương.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Đường thẳng (Xuyên phá)", combo_tag: "Piercing_Gale" },
        { name: "Bão Khí Áp Đảo", desc: "[Cơ chế] Thổi luồng không khí nén từ lồng ngực/hai tay cực mạnh. [Hiệu ứng] Hình nón 5m trước mặt. Hất văng (Knockback) mọi lính nhỏ và đạn đạo vật lý. Ngắt niệm chú của kẻ thù ngay lập tức.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Hình Nón Cận Chiến (Hất văng)", combo_tag: "Gale_Push" },
        { name: "Phong Trảo Cắt Gân", desc: "[Cơ chế] Bọc gió vào móng vuốt để tăng độ bén và xóa ma sát. [Hiệu ứng] Cào 1 nhát cận chiến. Gió xoáy luồn vào vết thương làm đứt gân, giảm 30% tốc độ di chuyển và tốc độ đánh của kẻ thù trong 5s.", rank: "Phàm Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Cận Chiến (Debuff Tốc độ)", combo_tag: "Wind_Claw_Cripple" },
        { name: "Tường Gió Hất Văng", desc: "[Cơ chế] Dựng luồng đối lưu thẳng đứng từ dưới đất lên. [Hiệu ứng] Kẻ nào đâm đầu vào bức tường gió này sẽ bị hất ngược lên không trung (Knock-up) 3m, phơi mình làm bia tập bắn cho Xạ thủ.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Tường Chắn Nhỏ (Hất tung)", combo_tag: "Updraft_Wall" },
        { name: "Đạn Gió Khó Né", desc: "[Cơ chế] Nén hạt khí kích thước bằng viên bi sắt nhưng vô hình. [Hiệu ứng] Bắn đạn khí không tạo tiếng động. Kẻ thù không thể nhìn thấy để né, chịu sát thương va đập vật lý gây bầm dập nội tạng.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Tầm Xa (Tàng hình đạn)", combo_tag: "Invisible_Bullet" },
        { name: "Lốc Nhỏ Cản Bước", desc: "[Cơ chế] Ném lốc xoáy mini đường kính 1m. [Hiệu ứng] Lốc đứng yên tại một điểm. Kẻ nào bước qua sẽ bị xoay mòng mòng (Choáng nhẹ 1s) và đẩy lệch hướng đi gốc của chúng, phá vây cực tốt.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Đặt bẫy (Lốc xoáy)", combo_tag: "Mini_Tornado_Trap" },
        { name: "Phi Tiêu Gió Xoáy", desc: "[Cơ chế] Gió cuốn thành hình phi tiêu xoay tít. [Hiệu ứng] Ném trúng mục tiêu, phi tiêu không biến mất ngay mà ở lại khoan cắt thêm 2s, gây sát thương liên tục (DPS) trước khi tan thành gió.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Tầm Trung (Sát thương duy trì)", combo_tag: "Tornado_Shuriken" },
        { name: "Xung Phong Khí Động", desc: "[Cơ chế] Tạo túi khí nén sau lưng và tự kích nổ phản lực. [Hiệu ứng] Lao sầm tới phía trước 10m (Charge) với tốc độ tên lửa. Húc văng mọi kẻ địch ngáng đường, rất dễ chạy trốn hoặc mở giao tranh.", rank: "Thiết Giai", cost: { type: "Stamina", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Đường thẳng (Lao tới)", combo_tag: "Aero_Charge" },
        { name: "Gió Thắt Cổ", desc: "[Cơ chế] Điều khiển một sợi khí nén bám quanh cổ đối thủ. [Hiệu ứng] Khóa chặt thanh quản. Kẻ thù không thể nói/niệm chú (Silence) trong 3 giây và mất máu liên tục vì thiếu oxy cục bộ lên não.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Tầm Trung (Câm lặng/Ngạt)", combo_tag: "Wind_Choke" },
        { name: "Mũi Khoan Xé Gió", desc: "[Cơ chế] Gió bao bọc vũ khí đâm tới, loại bỏ mọi lực cản không khí. [Hiệu ứng] Đòn đâm của giáo/kiếm nhanh đến mức không kịp chớp mắt, sát thương Xuyên Giáp tăng mạnh, để lại lỗ thủng sắc lẹm trên khiên.", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vũ Khí"], range_type: "Cận Chiến (Buff vũ khí)", combo_tag: "Wind_Drill_Pierce" },
        { name: "Cú Đá Bão Táp", desc: "[Cơ chế] Cước pháp kết hợp lốc xoáy quanh ống chân. [Hiệu ứng] Tung cú đá bồi thêm sóng gió. Gây sát thương vật lý mạnh, nếu kẻ địch phòng ngự vẫn bị gió cắt rách cánh tay đang giơ lên đỡ.", rank: "Phàm Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Cận Chiến (Đá hất)", combo_tag: "Storm_Kick" },
        { name: "Đệm Khí Lướt Đi", desc: "[Cơ chế] Phun màng khí áp lực thấp dưới gót giày. [Hiệu ứng] Di chuyển trơn tru trên mọi địa hình (bùn lầy, gai nhọn, nước) không bị lún, tăng 50% tốc độ chạy trong 10 giây thoát khỏi vùng vây bắt.", rank: "Phàm Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Buff Di chuyển)", combo_tag: "Hover_Dash" },
        { name: "Lá Trà Khúc Xạ", desc: "[Cơ chế] Thổi bay bụi và lá cây xung quanh làm rối loạn tầm nhìn địch. [Hiệu ứng] Tung một màn gió bụi. Đánh lừa thị giác kẻ địch khiến chúng giảm 30% Độ chính xác trong các đòn đánh vật lý ở 2 lượt tới.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "AoE Hình Cung Nhỏ (Debuff mù)", combo_tag: "Wind_Dust_Blind" },
        { name: "Gió Dội Lại", desc: "[Cơ chế] Tạo một túi khí rỗng hấp thụ động năng. [Hiệu ứng] Kẻ địch ném phi tiêu/bắn tên vào bạn, túi khí sẽ lập tức dội ngược vũ khí đó lại với 50% lực ban đầu vào mặt chúng (Phản đòn tầm xa cơ bản).", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Phản đòn nhỏ)", combo_tag: "Aero_Deflect" },
        { name: "Hơi Thở Cuồng Phong", desc: "[Cơ chế] Nén khí trong buồng phổi và thổi ra dồn dập. [Hiệu ứng] Thổi văng mọi chất độc dạng khí, sương mù, bào tử nấm hệ Độc quanh bán kính 10m. Khắc tinh dọn dẹp môi trường cho cả team thở.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "AoE Trung (Dọn dẹp khí độc)", combo_tag: "Wind_Blow_Clear" },
        { name: "Không Gian Tĩnh Lặng", desc: "[Cơ chế] Hút sạch không khí xung quanh tai mục tiêu. [Hiệu ứng] Địch bị điếc hoàn toàn trong 5 giây, không nghe được hiệu lệnh của Chỉ huy, dễ dàng bị đồng đội áp sát đánh lén từ sau lưng.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sóng Âm"], range_type: "Tầm Xa (Debuff điếc)", combo_tag: "Deafening_Vacuum" },
        { name: "Quạt Gió Sắc", desc: "[Cơ chế] Múa vũ khí/cánh quạt rộng tạo liên hoàn sóng gió. [Hiệu ứng] Đẩy lùi nhóm 3-4 kẻ địch giáp lá cà, mỗi lần quạt tạo ra sát thương rách da nhỏ nhưng cản trở hoàn toàn hướng tiến công của chúng.", rank: "Thiết Giai", cost: { type: "Stamina", value: 45 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Hình Nón Tầm Ngắn (Đẩy lùi liên tục)", combo_tag: "Fan_Blade_Push" },
        { name: "Khí Nén Đập Bàn", desc: "[Cơ chế] Tụ không khí dưới lòng bàn tay và đập mạnh xuống đất. [Hiệu ứng] Phá vỡ mặt đất, tạo bụi mù mịt và làm ngã mọi kẻ địch bán kính 2m quanh bản thân. Rất tốt để phá thế vây hãm cận chiến.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Xung quanh bản thân (Hất ngã)", combo_tag: "Aero_Smash" },
        { name: "Cú Hích Không Khí", desc: "[Cơ chế] Bắn khối không khí nén cực nhỏ nhưng đậm đặc vào khớp chân. [Hiệu ứng] Kẻ địch đang chạy nhanh bị hích trúng khớp gối sẽ vấp ngã tự do lăn lộn lộn cổ trên đất do chính quán tính của chúng.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Tầm Trung (Ngáng chân)", combo_tag: "Air_Trip" },
        { name: "Phong Nhẫn", desc: "[Cơ chế] Nén các hạt không khí thành một dải áp suất cực mỏng ở rìa (dày < 0.1mm), tạo hiệu ứng cắt vật lý học. [Hiệu ứng] Phóng lưỡi dao gió vô hình với tốc độ 200m/s. Gây sát thương cắt xuyên giáp da/giáp vải, tạo vết thương hở rỉ máu liên tục. Không nhìn thấy bằng mắt thường, rất khó né.", rank: "Phàm Giai", cost: { type: "MP", value: 80 }, cooldown: { value: 3, unit: "Giây", display_text: "3 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Đường thẳng (Tầm Trung)", combo_tag: "Wind_Slash" },
        { name: "Mắt Bão Hút Quái", desc: "[Cơ chế] Tạo vùng áp suất thấp cực mạnh ở trung tâm, chênh lệch áp suất tạo ra lực hút hướng tâm. [Hiệu ứng] Ném ra một lốc xoáy nhỏ. Trong bán kính 15m, mọi quái vật nhỏ (Mob), rác rưởi, đất đá đều bị cuốn mạnh vào một điểm (Gom quái). Giữ chân chúng trong 2 phút để đồng đội dùng chiêu AoE xả sát thương.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "AoE Trung (Gom mục tiêu)", combo_tag: "Vacuum_Pull" },
        { name: "Tường Gió Đẩy Lùi", desc: "[Cơ chế] Dựng bức tường khí nén chuyển động tịnh tiến ngược chiều với đòn tấn công. [Hiệu ứng] Cản phá hoàn toàn tên, đạn thực thể, phi tiêu bay tới. Đẩy văng (Knockback mạnh) bất kỳ kẻ địch nào định lao vào giáp lá cà, làm chúng mất thăng bằng ngã ngửa ra sau.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Tường Chắn (Bảo vệ phía trước)", combo_tag: "Wind_Wall" },
        { name: "Khinh Công Lướt Gió", desc: "[Cơ chế] Tạo các lớp đệm khí ma thuật nhỏ xíu dưới gót chân để chống lại trọng lực. [Hiệu ứng] Kỹ năng di chuyển. Giảm 90% trọng lượng cơ thể, giúp nhảy cao gấp 5 lần người thường, chạy thoăn thoắt trên mặt nước, lá cây mỏng, hay chạy dọc theo vách tường dựng đứng mà không rơi.", rank: "Thiết Giai", cost: { type: "Stamina", value: 150 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Khinh công)", combo_tag: "Wind_Walk" },
        { name: "Bão Táp Xé Xác", desc: "[Cơ chế] Triệu hồi dòng xoáy đối lưu mang theo hàng vạn cấu trúc khí nén siêu nhỏ hình răng cưa. [Hiệu ứng] Gọi một cơn lốc bán kính 20m. Kẻ thù bên trong bị hàng ngàn lưỡi dao gió nhỏ cắt rách da thịt liên tục (Sát thương DPS diện rộng). Bào mòn nhanh chóng độ bền (Durability) của giáp kim loại, xé rách giáp vải.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "AoE Rộng (Sát thương duy trì)", combo_tag: "Shredding_Storm" },
        { name: "Âm Sát (Giai Điệu Tử Thần)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Thao túng tuyệt đối mọi rung động phân tử trong không khí. Tạo ra sóng hạ âm (Infrasound) và sóng siêu âm cộng hưởng phá hủy kết cấu tế bào. [Hiệu ứng] Bán kính 5km. Môi trường chìm vào tĩnh lặng chết chóc. Sóng âm thanh vô hình đi xuyên qua mọi lớp khiên ma pháp/vật lý, trực tiếp làm rung nát nội tạng, vỡ não bộ của hàng vạn sinh vật. Kẻ thù chảy máu thất khiếu và chết trong sự câm lặng. [Tác dụng phụ] Hủy hoại màng nhĩ và dây thanh quản của người dùng. Câm điếc vĩnh viễn (Phải giao tiếp bằng thần giao cách cảm). Rút cạn 90% Sanity, dễ rơi vào trầm cảm/điên loạn.", rank: "Diệu Giai", cost: { type: "Sanity", value: 90 }, cooldown: { value: 60, unit: "Ngày", display_text: "60 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sóng Âm", "Hủy Diệt"], range_type: "AoE Cực Rộng (Cấp Thảm Họa Sinh Học)", combo_tag: "Divine_Sound_Death" },
        { name: "Khuếch Tán Độc/Thuốc", desc: "[Cơ chế] Điều khiển hướng gió vi mô để đưa các hạt vật chất lơ lửng đi theo quỹ đạo mong muốn. [Hiệu ứng] Kỹ năng kết hợp (Combo). Dùng gió quạt phấn độc, bào tử nấm, khí gas hoặc thuốc mê bay xa bao trùm toàn bộ doanh trại địch mà không sợ gió thổi ngược lại phe mình.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Hình Nón Rộng (Hỗ trợ phát tán)", combo_tag: "Toxic_Breeze" },
        { name: "Chân Không Tịch Diệt (Ngục Tù Tuyệt Đối)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Rút sạch 100% hỗn hợp khí (Oxy, Nito...) khỏi một vùng không gian, phá vỡ định luật khuếch tán khí. Tạo ra môi trường chân không tuyệt đối của vũ trụ ngay trên mặt đất. [Hiệu ứng] Bán kính 2km. Toàn bộ sinh vật bị rút sạch không khí khỏi phổi gây xẹp phổi tức thì. Nước trong cơ thể sôi lên vì áp suất bằng 0, nhãn cầu nổ tung, máu trào ra từ lỗ chân lông. Hủy diệt ngay lập tức mọi thực thể sống cần hô hấp (Kể cả Diệu Nhật cảnh giới nếu không có phép bảo vệ). [Tác dụng phụ cực lớn] Người tung chiêu bị nguyền rủa bởi quy luật không gian. Phổi của bản thân xẹp lép, thủng vô số lỗ. Rớt 3 đại cảnh giới, tụt Sanity về 0 (Rơi vào điên loạn 1 năm). Phải sống bằng máy thở/ma pháp sinh mệnh phần đời còn lại.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 95 }, cooldown: { value: 3650, unit: "Ngày", display_text: "10 Năm" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Không Gian", "Hủy Diệt"], range_type: "AoE Rất Rộng (Hủy Diệt Không Gian)", combo_tag: "Absolute_Vacuum_Death" },
        { name: "Mũi Tên Xuyên Phá", desc: "[Cơ chế] Bọc mũi tên/viên đạn trong một lớp khí nén hình chóp nhọn, giảm lực cản không khí xuống 0. [Hiệu ứng] Buff vũ khí. Tăng tầm bắn lên gấp 3 lần (Sniping). Đạn bay không có tiếng xé gió, xuyên phá mạnh mẽ các lớp giáp tấm cứng và khiên năng lượng bằng lực xoắn của gió.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Buff Vũ khí (Tầm siêu xa)", combo_tag: "Wind_Sniper_Arrow" },
        { name: "Giáp Khí Lưu", desc: "[Cơ chế] Quấn quanh cơ thể một dòng khí đối lưu tốc độ cao liên tục. [Hiệu ứng] Lớp giáp vô hình. Không chặn đòn đánh, nhưng sẽ làm lệch quỹ đạo (Deflect) của các mũi tên, phi tiêu, hay đạn súng trường bắn tới. Tránh được 80% sát thương vật lý tầm xa.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Bản thân (Phòng thủ thụ động)", combo_tag: "Aero_Armor" },
        { name: "Bước Nhảy Không Gian (Double Jump)", desc: "[Cơ chế] Nén đặc không khí ngay dưới lòng bàn chân trong 0.1s tạo thành một khối rắn làm điểm tựa. [Hiệu ứng] Kỹ năng lẩn tránh. Đạp lên không khí để nhảy tiếp lần thứ 2, thứ 3 giữa không trung. Giúp đổi hướng đột ngột khi đang bay, né đòn diện rộng hoặc leo lên vách đá trơn trượt.", rank: "Thiết Giai", cost: { type: "Stamina", value: 100 }, cooldown: { value: 2, unit: "Giây", display_text: "2 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Né tránh trên không)", combo_tag: "Double_Jump" },
        { name: "Xóa Dấu Vết (Sinh tồn)", desc: "[Cơ chế] Thổi những luồng gió siêu nhỏ làm tơi đất, thổi bay mùi hương phân tử. [Hiệu ứng] Che giấu hành tung. Thổi bay hoàn toàn mùi mồ hôi, mùi máu, là phẳng các dấu chân trên cát/bùn. Ngăn chặn tuyệt đối các loài chó săn (Dị thú Khuyển) hoặc cảm biến mùi của quân địch truy đuổi.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "AoE Nhỏ (Xung quanh lộ trình)", combo_tag: "Erase_Tracks" },
        { name: "Vòi Rồng Hủy Diệt (Tận Thế Cuồng Phong)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Tạo ra sự chênh lệch áp suất quy mô tầng đối lưu, giao thoa khối không khí nóng lạnh cường độ cực đại. [Hiệu ứng] Triệu hồi một siêu lốc xoáy (Tornado) cấp F5 đường kính 1km. Càn quét, nhổ bật gốc cổ thụ, hút mọi xe bọc thép, Mecha, và binh lính lên không trung rồi xé nát chúng ra từng mảnh. Tàn phá tan tành hệ sinh thái/kiến trúc chiến trường. [Tác dụng phụ] Hao tổn 80% HP và toàn bộ MP. Mất quyền điều khiển vòi rồng (Nó có thể càn quét trúng cả đồng minh nếu không kịp sơ tán). Kinh mạch đứt đoạn, suy yếu 3 tháng.", rank: "Diệu Giai", cost: { type: "MP", value: 2500000 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Thiên Tai"], range_type: "AoE Cực Rộng (Càn quét Lãnh thổ)", combo_tag: "Divine_Tornado" },
        { name: "Lọc Khí Độc (Hỗ trợ)", desc: "[Cơ chế] Màng lọc phân tử khí bằng ma pháp hệ Phong tạo áp suất dương. [Hiệu ứng] Tạo một vùng không khí sạch tinh khiết luôn bao quanh mũi miệng của tổ đội (Tối đa 5 người). Giúp hô hấp an toàn đi qua các khu rừng chứa chướng khí độc, vùng đầm lầy Vùng Zero, hoặc hang động nấm bào tử.", rank: "Phàm Giai", cost: { type: "MP", value: 60 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Bản thân & Đồng minh (Bảo vệ hô hấp)", combo_tag: "Air_Purify" },
        { name: "Gia Tốc Đồng Đội", desc: "[Cơ chế] Tạo dòng đối lưu thuận chiều phía sau lưng, giảm lực cản không khí phía trước. [Hiệu ứng] Buff tốc độ diện rộng. Thổi gió thuận chiều giúp toàn bộ đồng đội tăng 30% tốc độ di chuyển (AGI) và giảm hao tổn Stamina khi hành quân đường dài hoặc rút lui khẩn cấp.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "AoE Trung (Buff Tốc độ hành quân)", combo_tag: "Tailwind_Buff" },
        { name: "Cú Đá Chân Không", desc: "[Cơ chế] Tốc độ tung cước vượt qua rào cản âm thanh, tạo sóng xung kích (Sonic Boom). [Hiệu ứng] Đứng từ xa đá vào không khí. Tạo ra một lưỡi đao xung kích khổng lồ bay thẳng về phía trước, xẻ đôi tảng đá lớn và chém đứt đôi người mục tiêu ở khoảng cách 15m.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2500 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Đường thẳng (Cận Chiến xuất Tầm Xa)", combo_tag: "Sonic_Kick" },
        { name: "Hồi Phục Thể Lực", desc: "[Cơ chế] Đưa lượng lớn Oxy tinh khiết vào máu, thanh lọc Acid Lactic trong cơ bắp cực nhanh. [Hiệu ứng] Kỹ thuật hô hấp đặc biệt. Hít sâu điều hòa, lập tức phục hồi 30% Thể lực (Stamina) đã mất. Rất quan trọng để duy trì khả năng chiến đấu bền bỉ khi bị bao vây.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sinh Mệnh"], range_type: "Bản thân (Hồi Stamina)", combo_tag: "Breath_Recovery" },
        { name: "Cảm Nhận Gió (Trinh sát)", desc: "[Cơ chế] Da và lông tơ phản ứng với những biến động áp suất cực nhỏ trong không khí. [Hiệu ứng] Radar sinh học. Phát hiện kẻ địch tàng hình (Kể cả hệ Tinh thần bẻ cong ánh sáng hay sát thủ), nhận biết vị trí bẫy rập, dự đoán trước đường kiếm đâm lén sau lưng nhờ sự thay đổi của dòng khí.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Xung quanh bản thân (Phát hiện Tàng hình)", combo_tag: "Wind_Radar" },
        { name: "Đạn Khí Nén", desc: "[Cơ chế] Nén không khí thành những viên bi nhỏ với áp suất vỏ cực lớn, không có cạnh sắc. [Hiệu ứng] Bắn đạn khí vô hình liên thanh. Không gây đứt lìa hay chảy máu, nhưng lực va chạm tương đương búa tạ. Gây bầm dập, gãy xương sườn, đẩy lùi mạnh (Trấn áp bạo động, bắt sống).", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Tầm Xa (Sát thương cùn)", combo_tag: "Air_Bullet" },
        { name: "Bay Lượn (Flight)", desc: "[Cơ chế] Thao túng các dòng khí lưu nâng đỡ cơ thể, bất chấp trọng lực. [Hiệu ứng] Khả năng bay thực sự (Không cần cánh). Có thể lơ lửng, đổi hướng bay tự do trên bầu trời, giúp di chuyển vượt địa hình vực thẳm và trinh sát trận địa từ trên cao.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Duy trì)" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Bản thân (Di chuyển bay)", combo_tag: "True_Flight" },
        { name: "Tai Thính (Nghe trộm)", desc: "[Cơ chế] Dùng gió mang theo sóng âm thanh hội tụ vào màng nhĩ. [Hiệu ứng] Kỹ năng tình báo. Đứng cách xa 1km vẫn có thể nghe rõ mồn một tiếng thì thầm, bàn bạc chiến thuật trong lều trại của chỉ huy địch. Yêu cầu tập trung tinh thần cao độ.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sóng Âm"], range_type: "Tầm Siêu Xa (Thu thập tình báo)", combo_tag: "Wind_Eavesdrop" },
        { name: "Làm Mát/Làm Khô", desc: "[Cơ chế] Tạo luồng gió hanh khô hút nhiệt độ và độ ẩm nhanh chóng. [Hiệu ứng] Tiện ích sinh tồn. Hạ nhiệt độ cơ thể khi đi qua núi lửa sa mạc, thổi khô quần áo ướt để tránh nhiễm lạnh, hoặc hong khô thảo dược thu thập được.", rank: "Phàm Giai", cost: { type: "MP", value: 10 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Tiện ích)", combo_tag: "Cool_Dry_Breeze" },
        { name: "Cắt Cỏ Dọn Đường", desc: "[Cơ chế] Vung một dải gió hình cung tầm thấp sát mặt đất. [Hiệu ứng] Dao gió phát quang bụi rậm. Phát nát cỏ gianh, dây leo gai góc cản đường trong rừng rậm nguyên sinh. Tránh bị rắn độc hay bẫy gai ẩn giấu dưới lớp cỏ cắn phải.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Hình Cung Nhỏ (Dọn chướng ngại)", combo_tag: "Clear_Path_Wind" },
        { name: "Loa Phóng Thanh", desc: "[Cơ chế] Hội tụ không khí thành dạng ống nón để định hướng và khuếch đại sóng âm. [Hiệu ứng] Dùng gió mang theo giọng nói vang xa hàng cây số. Rất hữu ích để ra lệnh cho đội quân lớn trên chiến trường ồn ào, hoặc khiêu khích dụ quái thú ra khỏi sào huyệt.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Sóng Âm"], range_type: "Tầm Xa (Khuếch đại âm)", combo_tag: "Wind_Megaphone" },
        { name: "Nhặt Đồ Từ Xa", desc: "[Cơ chế] Tạo một vòng xoáy gió thu nhỏ có tính định hướng để ôm trọn vật thể. [Hiệu ứng] 'Bàn tay vô hình'. Cuốn một vũ khí đánh rơi, một túi vàng, hoặc bình thuốc từ cách xa 10m bay thẳng về lòng bàn tay. Không thể nâng vật quá nặng (>5kg).", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Tầm Trung (Lấy vật phẩm)", combo_tag: "Wind_Fetch" },
        { name: "Khiên Phản Hồi", desc: "[Cơ chế] Nén khí thành khối đàn hồi cao ngay trước mặt mục tiêu. [Hiệu ứng] Tạo đệm khí như bạt nhún. Nếu kẻ địch ném đá, bom mìn hay phóng lựu đạn tới, đệm khí sẽ nảy ngược toàn bộ quỹ đạo vật thể bay trả về thẳng mặt kẻ ném.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Tường Chắn (Phản đòn vật lý)", combo_tag: "Bounce_Shield" },
        { name: "Gió Ru Ngủ", desc: "[Cơ chế] Gió thổi mang theo tần số âm thanh Alpha và hương thảo dược tự nhiên. [Hiệu ứng] Làn gió êm dịu thổi qua. Khiến đám quái vật hoang dã (Cấp thấp, INT thấp) mất đi ý chí chiến đấu, mí mắt nặng trĩu và chìm vào giấc ngủ sâu trong 3 giờ. Phá giải nếu bị nhận sát thương.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Tinh Thần"], range_type: "AoE Trung (Ngủ/CC)", combo_tag: "Lullaby_Wind" },
        { name: "Cắt Đứt Liên Lạc", desc: "[Cơ chế] Tạo vùng nhiễu động không khí liên tục (Turbulence) phá vỡ tính đồng nhất của môi trường dẫn âm. [Hiệu ứng] Bán kính 50m. Không một âm thanh nào có thể lọt ra ngoài hoặc truyền vào trong (Tiếng súng, tiếng kêu cứu bị nuốt chửng). Cách ly hoàn toàn một khu vực để phục kích.", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sóng Âm"], range_type: "AoE Rộng (Câm lặng môi trường)", combo_tag: "Sound_Barrier_Zone" },
        { name: "Tự Do (Nội tại)", desc: "[Cơ chế] Bản nguyên của gió là không thể nắm bắt. Cơ thể được bao bọc bởi dòng chảy lưu động vĩnh cửu. [Hiệu ứng] Miễn nhiễm 100% với các hiệu ứng khống chế vật lý: Trói chân (Root), Làm chậm (Slow), Đóng băng (Freeze) hoặc sa lầy dưới bùn. Bước chân luôn uyển chuyển lướt qua mọi cạm bẫy trói buộc.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Kháng tính bị động)", combo_tag: "Freedom_Immunity" },
        { name: "Hóa Hình - Vô Hình Phong", desc: "[Cơ chế] Thú hệ Phong giải phóng nhục thể thành hạt lơ lửng, tan vào cuồng phong. [Hiệu ứng] Từ một cỗ máy chiến đấu khổng lồ, tan biến hoàn toàn thành cơn gió hú. Lướt qua bầu trời tàng hình 100%. Khi đáp xuống, không khí xoáy tụ nén lại thành hình dạng một nhân loại phiêu dật, giấu nhẹm mọi khí tức dị thú.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 40000 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sinh Học"], range_type: "Bản thân (Ngụy trang tàng hình)", combo_tag: "Beast_Wind_Form" },
        { name: "Phong Nhẫn (Bản Thú)", desc: "[Cơ chế] Vung đuôi hoặc vuốt tạo màng cắt bằng không khí vi mô. [Hiệu ứng] Dao gió vô hình chém ngang. Cắt đứt mục tiêu từ xa một cách êm ái, lưỡi cắt mang theo tính hoang dã xé toạc vết thương rộng hơn bản Tamer. Không nhìn thấy, chỉ có thể né theo bản năng.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 3, unit: "Giây", display_text: "3 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Đường thẳng (Cắt từ xa)", combo_tag: "Beast_Wind_Slash" },
        { name: "Mắt Bão Hút Ngạt", desc: "[Cơ chế] Thú há miệng xoáy lốc, tạo vùng chân không khắc nghiệt. [Hiệu ứng] Hút mạnh kẻ thù vào trung tâm lốc xoáy nhỏ dưới đất. Rút cạn toàn bộ Oxy trong bán kính đó, khiến kẻ địch vừa bị xoay vòng lảo đảo vừa ngạt thở (Trừ máu liên tục). Bất tỉnh sau 2 phút nếu không có người cứu.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "AoE Nhỏ (Khống chế cứng/Ngạt)", combo_tag: "Suffocate_Vortex" },
        { name: "Tường Gió Đẩy Lùi (Bão Tường)", desc: "[Cơ chế] Vỗ đôi cánh khổng lồ tạo luồng phản lực gió tịnh tiến ngang. [Hiệu ứng] Dựng bức tường lốc xoáy (Cao 10m). Hất văng mọi loại tên lửa, đạn pháo cỡ lớn và thổi bay cả xe tăng hạng nhẹ dạt sang hai bên. Lá chắn vật lý tuyệt đối cho đàn thú phía sau.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Tường Chắn Lớn (Bảo vệ quy mô)", combo_tag: "Beast_Storm_Wall" },
        { name: "Thuận Phong Khinh Công (Thú Chạy Nước)", desc: "[Cơ chế] Màng đệm khí bao phủ lòng bàn chân 4 chi, phân tán trọng lượng dàn đều bề mặt. [Hiệu ứng] Con thú (dù nặng 5 tấn) vẫn có thể bước đi trên không trung (tạo các bậc thang gió), lướt như bay trên mặt sông, hồ mà không tạo ra gợn sóng hay bị chìm.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Di chuyển địa hình)", combo_tag: "Beast_Air_Tread" },
        { name: "Bão Táp Xé Rách", desc: "[Cơ chế] Hú dài gọi cuồng phong, không khí bị xé tơi thành hàng vạn mảnh gai gió sắc nhọn. [Hiệu ứng] Gọi một trận bão lớn bao trùm chiến trường. Hàng vạn lưỡi cắt nhỏ len lỏi qua khe giáp của kỵ binh, xé nát da thịt địch thành huyết nhục vụn vỡ. Tàn bạo và khó phòng ngự bằng khiên vật lý.", rank: "Kim Giai", cost: { type: "MP", value: 90000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "AoE Rộng (DPS tàn bạo)", combo_tag: "Tearing_Gale" },
        { name: "Âm Sát Phong (Sư Tử Hống)", desc: "[Cơ chế] Nén toàn bộ không khí trong lồng ngực vào khoang thanh quản và gầm lên với tần số cộng hưởng đứt gãy. [Hiệu ứng] Tạo một cơn sóng âm xung kích hình nón rộng. Đánh thẳng vào màng nhĩ và não bộ kẻ thù. Gây chảy máu tai, choáng (Stun) 2 phút và giảm 50% INT vĩnh viễn trong trận chiến.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sóng Âm"], range_type: "Hình Nón Rộng (Choáng/Phá giáp tinh thần)", combo_tag: "Sonic_Roar" },
        { name: "Gió Độc Lan Tỏa", desc: "[Cơ chế] Kiểm soát luồng sinh khí, tạo hiệu ứng đối lưu lan truyền xa. [Hiệu ứng] Kỹ năng kết hợp bầy đàn (đặc biệt với thú hệ Độc/Thực vật). Quạt màng cánh gió siêu mạnh để khuếch tán phấn độc, nọc sương mù đi xa gấp 3 lần, bao phủ cả một doanh trại quân đội UHA nhanh chóng.", rank: "Thiết Giai", cost: { type: "Stamina", value: 300 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "AoE Rộng (Khuếch tán)", combo_tag: "Spread_Toxin" },
        { name: "Lốc Xoáy Bế Tắc", desc: "[Cơ chế] Tạo ra 4 luồng gió xoáy ngược chiều đan xen tạo thành lồng giam động lực học. [Hiệu ứng] Nhốt 1 kẻ thù mạnh vào tâm một lốc xoáy thu nhỏ. Gió xoáy với tốc độ máy cắt, nếu mục tiêu cố tình giẫy giụa chạm vào thành lốc sẽ bị cắt rách thịt. Nhốt cứng mục tiêu trong 3 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Tầm Xa (Giam cầm đơn mục tiêu)", combo_tag: "Tornado_Cage" },
        { name: "Phong Tiễn Xuyên Vân (Bản Thú)", desc: "[Cơ chế] Phun từ miệng một kim khí nén có tính xoắn ốc cực cao. [Hiệu ứng] Mũi tên gió siêu tốc độ xé gió không phát ra tiếng động. Uy lực xuyên phá sọ não của các loài thú có lớp da sừng thép (Rhino/Rùa) dễ dàng. Đòn bắn lén chết chóc trong rừng sâu.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Tầm Xa (Bắn tỉa ám sát)", combo_tag: "Beast_Wind_Snipe" },
        { name: "Giáp Khí Lưu (Chống đâm chém)", desc: "[Cơ chế] Bao bọc cơ thể bằng các dòng khí lưu xoáy quanh thân (Tornadic armor). [Hiệu ứng] Làm trượt quỹ đạo (Deflect) của mọi đòn đâm chém cận chiến (Kiếm, giáo) và mũi tên. Sát thương nhận vào bị trượt góc, giảm đi 70% uy lực thực tế.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Bản thân (Giáp phản xạ góc)", combo_tag: "Deflecting_Armor" },
        { name: "Bước Nhảy Không Gian (Đạp Gió)", desc: "[Cơ chế] Bơm nổ không khí dưới móng vuốt tạo phản lực vi mô. [Hiệu ứng] Thú có thể đạp chân vào khoảng không nhảy lên cao liên tục (Double/Triple Jump) giữa trời để vồ mồi từ góc khuất, hoặc tránh né lưới bẫy dưới đất một cách ảo diệu.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Di chuyển dọc)", combo_tag: "Air_Step" },
        { name: "Gió Cắt Đứt Dấu Vết", desc: "[Cơ chế] Phe phẩy đuôi liên tục tạo luồng gió xới tung đất mịn và thổi đi pheromone. [Hiệu ứng] Kỹ năng lẩn trốn bản năng. Thổi bay sạch sẽ mùi máu từ vết thương, mùi đặc trưng của giống loài, và che lấp dấu chân. Đánh lừa hoàn toàn lũ Dị thú Khuyển đánh hơi.", rank: "Phàm Giai", cost: { type: "Stamina", value: 100 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Xung quanh (Xóa dấu chân)", combo_tag: "Beast_Erase_Scent" },
        { name: "Vòi Rồng Phá Hoại (Cuồng Phong Bạo Chúa)", desc: "[Cơ chế] Chạy vòng tròn với tốc độ siêu thanh tạo tâm lốc xoáy chết chóc. [Hiệu ứng] Triệu hồi vòi rồng khổng lồ càn quét toàn bộ chiến trường. Nhấc bổng hàng chục xe tăng lên không trung, đập chúng vào nhau tơi tả. Hủy diệt cả một trạm phòng thủ UHA cỡ vừa.", rank: "Kim Giai", cost: { type: "Stamina", value: 120000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Vật Lý"], range_type: "AoE Rộng (Càn quét)", combo_tag: "Beast_Tornado_Destroyer" },
        { name: "Thanh Lọc Không Khí (Hô Hấp Thuần Khiết)", desc: "[Cơ chế] Phổi sinh học lọc hạt nano vi mô độc hại qua màng nhầy đặc biệt. [Hiệu ứng] Hút không khí sạch bao quanh mặt, cô lập khí độc. Miễn nhiễm 100% với các đòn đánh bằng sương mù độc (Poison Gas), nọc độc hô hấp của Dị thú côn trùng.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong"], range_type: "Bản thân (Miễn nhiễm khí độc)", combo_tag: "Pure_Breathing" },
        { name: "Lưỡi Cắt Cực Tốc", desc: "[Cơ chế] Bọc không khí nén vào móng vuốt, giảm lực ma sát đến mức zero. [Hiệu ứng] Tốc độ vung trảo tăng lên gấp 3 lần bình thường (AGI vung tay bùng nổ). Chém hàng chục nhát vào một điểm trên giáp đối phương trong 1 giây, tạo ra hiệu ứng Xuyên Giáp cực mạnh.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2800 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Cận Chiến (Combo tốc độ chém)", combo_tag: "Speed_Claw_Flurry" },
        { name: "Cú Đá Cuồng Phong", desc: "[Cơ chế] Đuôi hoặc chi sau mượn lực xoáy của cơn lốc tự thân. [Hiệu ứng] Tung một cú đá/vụt đuôi chứa động năng gió lốc. Chặt đứt đôi tảng đá nặng 10 tấn, đập vỡ nát Mecha thành phế liệu. Gây hất văng (Knockback) cực mạnh.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Cận Chiến (Sát thương nặng/Hất văng)", combo_tag: "Tornado_Kick" },
        { name: "Hơi Thở Phục Hồi", desc: "[Cơ chế] Thú há miệng hít luồng sinh khí tự nhiên khổng lồ, bão hòa oxy trong máu lập tức. [Hiệu ứng] Lấy lại sức bền ngay giữa trận đánh. Hồi phục 20% Thể Lực (Stamina), xóa bỏ trạng thái thở dốc (Mệt mỏi) để tiếp tục duy trì nhịp độ tấn công điên cuồng.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Sinh Học"], range_type: "Bản thân (Hồi Stamina khẩn cấp)", combo_tag: "Beast_Wind_Breath" },
        { name: "Cảm Nhận Gió (Bị động - Thú Săn Mồi)", desc: "[Cơ chế] Hệ thống râu/lông xúc giác nhạy cảm với từng biến động áp suất cực nhỏ ở môi trường. [Hiệu ứng] Nhắm mắt lại vẫn 'thấy' đường. Dự đoán chính xác quỹ đạo đòn đánh lén từ điểm mù sau lưng, phát hiện tàng hình, miễn nhiễm hoàn toàn với các kỹ năng đâm lén (Backstab).", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong"], range_type: "Bản thân (Kháng đâm lén bị động)", combo_tag: "Beast_Sensory_Whiskers" },
        { name: "Phong Tốc Kích (Charge)", desc: "[Cơ chế] Mượn luồng gió thổi từ sau lưng tạo động lượng khổng lồ. [Hiệu ứng] Lao thẳng vào mục tiêu theo một đường thẳng (Charge) với tốc độ ngang đạn bắn súng trường. Sừng hoặc đầu cứng va chạm gây sát thương Xuyên Thấu tàn bạo, hất tung nạn nhân lên trời.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4000 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Vật Lý"], range_type: "Đường thẳng (Lao tới/Charge)", combo_tag: "Gale_Charge" }
    ],
  "Hệ Thổ": [
        { name: "Hóa Hình - Thạch Cốt", desc: "[Cơ Chế Sinh Học] Chuyển đổi cơ sở sự sống từ Carbon sang Silicon. Tế bào da hóa sừng thành lớp đá thạch anh siêu cứng. Cơ bắp là các sợi khoáng chất đàn hồi. [Cấu Tạo] Dạ dày như máy nghiền đá, tim là khối thạch anh, phổi lọc bụi mịn. [Hình Thái] Da nhám sạn, gam màu xám tro. Ở dạng người, sở hữu lớp giáp tự nhiên không thể bị đâm thủng bởi dao thường. [Tác dụng phụ] Cơ thể nặng nề, giảm 30% tốc độ di chuyển cơ bản.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Sinh Học"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Earth" },
        { name: "Cốt Thạch Bất Hoại", desc: "[Cơ chế] Tủy xương cô đặc khoáng chất dưới áp lực ngàn cân. [Hiệu ứng] Nội tại Tanker đỉnh cao. Khi lượng máu (HP) rớt xuống dưới 50%, phòng thủ vật lý (DEF) tự động tăng 50%, da thịt hóa xám cứng như đá hoa cương.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Sinh Học"], range_type: "Bản thân (Bị động phòng thủ)", combo_tag: "Passive_Stone_Bone" },
        { name: "Chân Đạp Trọng Lực", desc: "[Cơ chế] Lòng bàn chân luân chuyển trọng lực kết nối với lõi từ trái đất. [Hiệu ứng] Tăng trọng lượng phần thân dưới. Tuyệt đối không bị hất văng (Knock-up) lên trời bởi lốc xoáy hệ Phong hay đòn đá hất của võ sĩ.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Bản thân (Bị động kháng khống chế)", combo_tag: "Passive_Heavy_Feet" },
        { name: "Mạch Đất Trinh Sát", desc: "[Cơ chế] Bàn chân cảm nhận tần số rung cơ học truyền qua lớp trầm tích. [Hiệu ứng] Nhắm mắt lại đứng yên, đếm được chính xác có bao nhiêu sinh vật/lính đang bước đi trên mặt đất trong bán kính 100m. Không tác dụng với chim bay.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Sóng Âm"], range_type: "AoE Rộng (Bị động dò thám)", combo_tag: "Passive_Tremor_Sense" },
        { name: "Da Sừng Thạch Anh", desc: "[Cơ chế] Lớp sừng biểu bì đan chéo cấu trúc lục giác của thạch anh. [Hiệu ứng] Da cực kỳ trơn cứng, khiến mọi đòn đâm (Piercing) như Thương, Mũi tên, Đạn nhọn bị trượt góc, giảm sát thương đâm xuyên đi 30%.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Bị động kháng Đâm)", combo_tag: "Passive_Quartz_Hide" },
        { name: "Cộng Hưởng Đại Địa", desc: "[Cơ chế] Hệ thống kinh mạch tự động hút linh khí tinh khiết từ đất mẹ. [Hiệu ứng] Chừng nào hai chân còn chạm trên nền đất tự nhiên (Không phải nền gạch/bê tông), sinh lực (HP) từ từ hồi phục 1% mỗi 10 giây.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Sinh Mệnh"], range_type: "Bản thân (Bị động hồi máu)", combo_tag: "Passive_Earth_Regen" },
        { name: "Bụi Mù Ngụy Trang", desc: "[Cơ chế] Lông tơ liên tục tản ra một lớp cát mỏng tĩnh điện. [Hiệu ứng] Cơ thể luôn được bao phủ bởi một lớp sương bụi lờ mờ. Kẻ thù dùng súng ngắm hoặc cung tên ngắm từ xa sẽ bị hoa mắt, giảm 15% độ chính xác.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Khí"], range_type: "Bản thân (Bị động ngụy trang)", combo_tag: "Passive_Dust_Shroud" },
        { name: "Sức Nặng Thái Sơn", desc: "[Cơ chế] Gia tăng khối lượng vi mô vào tay/vũ khí khi tung đòn. [Hiệu ứng] Mọi đòn đánh tay/cắn xé/chùy đập đều mang sức nặng ngàn cân. Có 10% tỉ lệ khiến kẻ thù nát xương gối, ngã quỵ xuống đất (Knock-down 1s).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Đòn đánh (Bị động khống chế)", combo_tag: "Passive_Mountain_Weight" },
        { name: "Hóa Thạch Vết Thương", desc: "[Cơ chế] Bụi khoáng hòa lẫn với tiểu cầu máu tạo xi măng sinh học. [Hiệu ứng] Khi bị chém một vết thương hở sâu, vết cắt tự động hóa đá lấp miệng lại. Miễn nhiễm tuyệt đối với hiệu ứng [Chảy Máu] (Bleeding).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Sinh Học"], range_type: "Bản thân (Bị động cầm máu)", combo_tag: "Passive_Fossil_Wound" },
        { name: "Bám Rễ Sinh Tồn", desc: "[Cơ chế] Ngón chân mọc vuốt phụ ghim chặt xuống bùn đất. [Hiệu ứng] Khi chọn tư thế Phòng ngự (Đứng yên đỡ đòn), lượng Thể lực (Stamina) tiêu hao cho việc chịu đòn giảm đi 50%. Rất dẻo dai trong các trận càn quét.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Bị động trụ vững)", combo_tag: "Passive_Rooted_Stance" },
        { name: "Đất Mẹ Nuôi Dưỡng", desc: "[Cơ chế] Miễn dịch cơ địa với các loại nấm mốc/vi khuẩn mùn đất. [Hiệu ứng] Hoàn toàn không bị nhiễm độc từ đất bẩn, không bị rát da khi bơi qua đầm lầy chứa axit nhẹ của Vùng Zero. Sinh tồn đỉnh cao.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Sinh Học"], range_type: "Bản thân (Bị động kháng Độc)", combo_tag: "Passive_Earth_Nourish" },
        { name: "Tinh Thể Xương", desc: "[Cơ chế] Tái cấu trúc canxi thành khoáng chất kim cương học. [Hiệu ứng] Chịu đòn búa tạ rơi trúng vai cũng không nát xương. Kháng 100% các trạng thái [Gãy Xương], [Rạn Nứt] (Những debuff làm phế tay chân vĩnh viễn).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Bản thân (Bị động kháng thương tật)", combo_tag: "Passive_Crystal_Bone" },
        { name: "Thổ Tức Phản Chấn", desc: "[Cơ chế] Da bụng/ngực nén khí như một khối cao su đàn hồi bọc đá. [Hiệu ứng] Kẻ địch đấm tay không hoặc đá trực tiếp vào người bạn sẽ bị đau điếng. Phản lại 10% sát thương đòn đánh vật lý cận chiến thẳng vào xương chúng.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Bị động phản sát thương)", combo_tag: "Passive_Earth_Rebound" },
        { name: "Áp Suất Chân Trụ", desc: "[Cơ chế] Bước đi đè nén mặt đất đến mức phá vỡ kết cấu xốp. [Hiệu ứng] Mọi bước chạy đều làm lún đất 1cm. Đè bẹp và phá hủy tàng hình mọi loại mìn nổ, dây bẫy gai chôn ngầm trước khi chúng kịp kích hoạt hoàn hảo.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Dưới chân (Bị động dò mìn)", combo_tag: "Passive_Pressure_Step" },
        { name: "Cát Mài Lưỡi Đao", desc: "[Cơ chế] Quanh cơ thể cuộn xoáy một lớp cát thạch anh siêu mài mòn. [Hiệu ứng] Khắc chế binh khí lính UHA. Gươm, giáo, lưỡi lê chém vào người nhiều lần sẽ bị mài cùn nhẵn thín. Mất đi 50% chỉ số Sát thương vũ khí.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Bị động bào mòn đồ)", combo_tag: "Passive_Sand_Grind" },
        { name: "Trầm Tích Niên Đại", desc: "[Cơ chế] Sinh mệnh tích tụ vôi hóa như lớp trầm tích triệu năm. [Hiệu ứng] Càng đánh lâu càng trâu. Cứ mỗi 1 phút ở trong trạng thái Giao tranh (Combat), lượng Máu Tối Đa (Max HP) tự động tăng 5%, cộng dồn tối đa 30%.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Sinh Mệnh"], range_type: "Bản thân (Bị động tăng máu)", combo_tag: "Passive_Sediment_Vitality" },
        { name: "Vuốt Đá Mài", desc: "[Cơ chế] Móng vuốt tự mọc lại và mài sắc bởi khoáng silic trong đất. [Hiệu ứng] Không bao giờ lo vũ khí sinh học bị cùn. Đào hang, chém giáp sắt thoải mái, Độ bén và Sát thương của Móng/Răng luôn ở mức 100%.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Bị động bảo trì)", combo_tag: "Passive_Self_Sharpen" },
        { name: "Kháng Dung Nham Xâm Nhập", desc: "[Cơ chế] Lỗ chân lông đóng vảy cản nhiệt truyền qua bùn lỏng. [Hiệu ứng] Lội dưới dung nham hoặc bùn sôi sục cũng chỉ như tắm nước nóng. Giảm 80% mọi sát thương môi trường do núi lửa sinh ra.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Hỏa"], range_type: "Bản thân (Bị động kháng địa hình)", combo_tag: "Passive_Magma_Resist" },
        { name: "Đồng Hóa Nham Thạch", desc: "[Cơ chế] Nhịp tim chậm lại, màu da chuyển xám trắng ngụy trang. [Hiệu ứng] Nằm cuộn tròn im lặng dưới đất, hệ thống máy quét ma lực, quét thân nhiệt của quân thù sẽ nhận diện bạn là một Tảng Đá Vô Tri. Tàng hình tĩnh.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Ảo Giác"], range_type: "Bản thân (Bị động ngụy trang tĩnh)", combo_tag: "Passive_Stone_Camouflage" },
        { name: "Bùn Lầy Trì Trệ", desc: "[Cơ chế] Cơ thể tỏa ra ma lực vô hình biến không khí thành dạng keo nhớp. [Hiệu ứng] Bất kỳ kẻ địch nào áp sát bạn trong phạm vi 1 mét để chém, chúng sẽ có cảm giác vung kiếm trong vũng bùn. Tốc độ đánh cận chiến của chúng giảm 15%.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Xung quanh (Bị động trừ tốc)", combo_tag: "Passive_Mud_Aura" },
        { name: "Phổi Lọc Cát", desc: "[Cơ chế] Khí quản mọc hệ thống lưới mao mạch cản bụi tuyệt hảo. [Hiệu ứng] Đi giữa cơn bão cát tàn khốc, lốc xoáy sa mạc mà không hề bị ho sặc sụa, nghẹt thở hay bụi lọt vào làm giảm tầm nhìn. Tầm nhìn sa mạc luôn 100%.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Sinh Học"], range_type: "Bản thân (Bị động sinh tồn)", combo_tag: "Passive_Sand_Lung" },
        { name: "Đạn Đá Phá Giáp", desc: "[Cơ chế] Bắn một tảng đá nhọn xoay tít như mũi khoan. [Hiệu ứng] Đập nát khiên năng lượng và xé toạc giáp vật lý. Làm giảm 20% DEF của mục tiêu trong 5 giây sau khi bị trúng đòn.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Rock_Drill" },
        { name: "Thổ Trảo Nghiền Nát", desc: "[Cơ chế] Đắp một lớp đá tảng lên đôi bàn tay, tăng trọng lượng lên 50kg mỗi tay. [Hiệu ứng] Vung tay đập nát xương sườn đối thủ, đòn đánh có xác suất 30% gây hiệu ứng Mất Vũ Khí do lực chấn động quá mạnh.", rank: "Phàm Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Cận Chiến (Sát thương cùn)", combo_tag: "Stone_Fists" },
        { name: "Cọc Đất Chọc Trờ", desc: "[Cơ chế] Gọi một cột đá nhọn đâm thẳng từ dưới mặt đất lên. [Hiệu ứng] Xiên thủng đùi kẻ thù đang chạy, gây Chảy máu và Trói chân (Root) 1.5 giây. Rất khó dự đoán nếu không cảm nhận được địa mạch.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tầm Trung (Đột kích gầm)", combo_tag: "Earth_Spike" },
        { name: "Tường Đá Phản Lực", desc: "[Cơ chế] Dựng một vách đá có độ cong nhẹ như lò xo. [Hiệu ứng] Chặn các đòn lao tới (Charge) của kỵ binh hoặc dị thú. Kẻ nào húc vào tường sẽ bị dội ngược lại (Knockback) 3m và Choáng váng tự thân.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tường Chắn Nhỏ", combo_tag: "Bounce_Rock_Wall" },
        { name: "Búa Đất Giáng Xuống", desc: "[Cơ chế] Tạo một khối đá hình búa lơ lửng trên không trung và ném mạnh xuống. [Hiệu ứng] Gõ bẹp dí kẻ địch, gây sát thương AoE diện hẹp (2m). Hiệu quả cực cao lên những mục tiêu đã bị đánh ngã xuống đất.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tầm Trung (Từ trên không)", combo_tag: "Earth_Hammer" },
        { name: "Gai Đất Rải Đường", desc: "[Cơ chế] Phủ gai nhọn tàng hình lên một dải đất. [Hiệu ứng] Rải bãi mìn chông dài 5m. Bất kỳ ai dẫm phải đều bị thủng giày, mất 30% Tốc độ di chuyển liên tục khi băng qua vùng này.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Đặt bẫy", combo_tag: "Spike_Trail" },
        { name: "Thổ Cước Trấn Áp", desc: "[Cơ chế] Dậm mạnh chân xuống đất truyền chấn động tập trung. [Hiệu ứng] Tạo một vết nứt chạy thẳng tới mục tiêu. Sát thương không cao nhưng chắc chắn làm ngã nhào bất kỳ kẻ địch nào đứng trên đường nứt đó.", rank: "Thiết Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Đường thẳng (Hất ngã)", combo_tag: "Fissure_Stomp" },
        { name: "Cát Bay Mù Mắt", desc: "[Cơ chế] Tung một nắm cát tẩm ma lực phong hóa. [Hiệu ứng] Cát dính chặt vào võng mạc, gây Mù lòa (Giảm 100% tỷ lệ trúng) trong 3 giây. Đòn chắp vá cực kỳ hiểm độc trong cận chiến.", rank: "Phàm Giai", cost: { type: "Stamina", value: 15 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Hình Nón Cận Chiến", combo_tag: "Pocket_Sand" },
        { name: "Hố Đất Sụt Lún", desc: "[Cơ chế] Hóa lỏng kết cấu đất dưới chân địch trong tích tắc. [Hiệu ứng] Làm sụt lún chân địch xuống độ sâu nửa mét, kẹp chặt lấy gót chân khiến chúng không thể né tránh đòn tất sát tiếp theo của đồng đội.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tầm Trung (Khóa chân)", combo_tag: "Sinkhole" },
        { name: "Áo Giáp Đá Cuội", desc: "[Cơ chế] Hút sỏi đá xung quanh đính vào lớp áo vải/da. [Hiệu ứng] Tạm thời tăng 100 DEF. Hấp thụ 3 đòn đánh vật lý đầu tiên mà không hề mất máu (HP), nhưng sẽ vỡ vụn sau 3 đòn đó.", rank: "Phàm Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Bản thân (Buff giáp)", combo_tag: "Pebble_Armor" },
        { name: "Phi Tiêu Thạch Anh", desc: "[Cơ chế] Nén đất sét thành hình dạng ngôi sao 4 cánh mỏng dính sắc lẹm. [Hiệu ứng] Phóng ra 3 phi tiêu đá bay với tốc độ cao. Cắt đứt yết hầu và găm chặt vào tường, gây Chảy máu dai dẳng.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Tầm Xa", combo_tag: "Quartz_Dart" },
        { name: "Đá Tảng Lăn Cán", desc: "[Cơ chế] Đẩy một hòn đá to tròn như bánh xe với gia tốc ma lực. [Hiệu ứng] Đá lăn đè bẹp mọi chướng ngại vật trên đường thẳng 15m. Húc tung khiên, gãy chân kỵ binh. Không thể bị cản lại bằng vũ khí nhẹ.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Đường thẳng (Gây choáng ngã)", combo_tag: "Boulder_Roll" },
        { name: "Cát Nén Sát Thương", desc: "[Cơ chế] Vo cục cát ướt siêu cứng đập vào ngực mục tiêu. [Hiệu ứng] Cục cát nổ tung ngay khi va chạm, sát thương xuyên thấu qua giáp làm tức ngực, khó thở (Giảm Hồi phục Stamina địch trong 5s).", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Tầm Trung", combo_tag: "Sand_Blast" },
        { name: "Bẫy Chông Đất Nhọn", desc: "[Cơ chế] Ủ ma lực dưới lòng đất chờ phát động. [Hiệu ứng] Đặt một bẫy tàng hình. Kẻ địch bước lên sẽ bị đinh đá đâm xuyên thủng bàn chân, gây Trói Buộc cứng ngắc tại chỗ trong 2 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Đặt bẫy", combo_tag: "Hidden_Earth_Spike" },
        { name: "Thổ Bạo Xung Kích", desc: "[Cơ chế] Bao bọc toàn thân bằng giáp đá và lao tới húc càn. [Hiệu ứng] Biến thành quả pháo đất (Charge). Húc tung bét mọi đội hình địch, không chịu phản chấn vật lý. Gây choáng nhẹ diện rộng khi va chạm.", rank: "Thiết Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Đường thẳng (Lao tới)", combo_tag: "Earth_Charge" },
        { name: "Đá Nhọn Kẹp Chặt", desc: "[Cơ chế] Hai mảng đá trồi lên từ hai bên mục tiêu. [Hiệu ứng] Ép chặt đối phương ở giữa như cái kìm khổng lồ. Vừa gây sát thương bóp nát xương sườn, vừa kẹp cứng không cho cử động trong 1 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tầm Trung (Khống chế cứng)", combo_tag: "Stone_Vise" },
        { name: "Đất Mềm Khóa Chân", desc: "[Cơ chế] Hóa bùn dính dấp bùn lầy cục bộ. [Hiệu ứng] Hất bãi bùn vào chân kẻ địch. Đất sét khô lại ngay lập tức đóng thành xi măng, biến giày của địch thành cục tạ 10kg, giảm thê thảm AGI.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Tầm Xa (Debuff)", combo_tag: "Mud_Cement" },
        { name: "Thổ Đạn Nổ Mảnh", desc: "[Cơ chế] Ném viên sỏi nén khí ma thuật. [Hiệu ứng] Đạn bay lượn vòng, đâm vào chướng ngại vật sẽ phát nổ tơi tả thành bụi mảnh vỡ như đạn hoa cải, găm mù mắt kẻ địch nấp sau tường.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "AoE Nhỏ (Đạn nổ)", combo_tag: "Frag_Rock" },
        { name: "Thạch Đao Chẻ Củi", desc: "[Cơ chế] Ngưng tụ một thanh đại đao bằng đá tảng ngay trên tay. [Hiệu ứng] Vung một nhát chém từ trên xuống, với sức nặng ngàn cân, bổ đôi khiên gỗ và chém gãy vũ khí đỡ đòn của kẻ địch (Giảm độ bền vũ khí địch mạnh).", rank: "Thiết Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Cận Chiến (Phá vũ khí)", combo_tag: "Heavy_Stone_Cleaver" },
        { name: "Gạch Nén Đập Đầu", desc: "[Cơ chế] Dùng tay không rút viên gạch/khối đất cứng khỏi mặt đất trong chớp mắt. [Hiệu ứng] Đập thẳng vào gáy kẻ thù. Gây Choáng (Stun) 2s và Sát thương chí mạng. Vũ khí thô sơ nhưng cực kỳ tàn bạo trong cận chiến.", rank: "Phàm Giai", cost: { type: "Stamina", value: 15 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Cận Chiến (Đánh lén)", combo_tag: "Brick_Smash" },
        { name: "Địa Chấn", desc: "[Cơ chế] Truyền ma lực qua gót chân, tạo sóng xung kích địa chấn lan truyền bề mặt. [Hiệu ứng] Làm mặt đất rung lắc dữ dội bán kính 15m. Gây choáng (Stun) 1.5s và hất ngã toàn bộ kẻ địch đang đứng trên mặt đất, ngắt quãng niệm chú. [Tương tác] Không có tác dụng với mục tiêu bay.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "AoE Trung (Xung quanh)", combo_tag: "Earthquake_Stun" },
        { name: "Tường Đất Chắn", desc: "[Cơ chế] Nâng các mảng kiến tạo nhỏ, nén chặt đất đá thành khối vuông vức. [Hiệu ứng] Dựng bức tường dày 1m, cao 3m. Chặn đứng hoàn toàn đạn pháo vật lý, chia cắt đội hình địch. Tường có lượng máu (HP) bằng 300% DEF của người dùng.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tường chắn (Tầm Trung)", combo_tag: "Earth_Wall" },
        { name: "Thiên Thạch Rơi", desc: "[Cơ chế] Ngưng tụ bụi và đá cuội trên không trung, nén lại thành tảng đá khổng lồ. [Hiệu ứng] Triệu hồi một tảng đá nặng 5 tấn đè bẹp mục tiêu từ trên cao. Gây sát thương vật lý cực lớn và hiệu ứng Đè Bẹp (Giảm 50% AGI địch trong 3 giờ).", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "AoE Nhỏ (Từ trên không)", combo_tag: "Rock_Crush" },
        { name: "Giáp Đá", desc: "[Cơ chế] Hút khoáng chất từ đất phủ lên da thịt. [Hiệu ứng] Tăng 200% phòng thủ vật lý (DEF). Cực kỳ cứng cáp trước các đòn chém, đâm. Khi giáp vỡ, nó rụng xuống thành cát. [Nhược điểm] Dễ bị phá vỡ bởi các đòn tấn công bằng búa tạ hoặc Hệ Thủy (làm mềm đất).", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Bản thân (Buff)", combo_tag: "Stone_Armor" },
        { name: "Độn Thổ Đột Kích", desc: "[Cơ chế] Hóa lỏng đất xung quanh cơ thể để bơi trong lòng đất. [Hiệu ứng] Lặn xuống đất tàng hình hoàn toàn, tăng 150% tốc độ di chuyển ngầm. Đột ngột trồi lên hất tung kẻ địch. Đòn tấn công mang yếu tố bất ngờ, tăng tỉ lệ chí mạng 50%.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Di chuyển & Cận chiến", combo_tag: "Burrow_Strike" },
        { name: "Chông Đá", desc: "[Cơ chế] Cấu trúc lại tinh thể đá thành dạng mũi nhọn. [Hiệu ứng] Biến mặt đất bán kính 10m thành rừng chông nhọn hoắt đâm lên từ dưới lên. Xuyên thủng bàn chân địch, gây Chảy máu và Trói chân (Root) 2 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "AoE Trung", combo_tag: "Spike_Trap" },
        { name: "Sa Lầy", desc: "[Cơ chế] Bơm Mana hệ Thổ phá vỡ liên kết rắn của đất liền. [Hiệu ứng] Hóa lỏng khu vực 5x5m thành đầm lầy sâu không đáy. Hút kẻ địch chìm xuống, làm ngạt thở và chôn sống chúng nếu không có ai kéo lên sau 3 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Nước"], range_type: "AoE Nhỏ (Khống chế cứng)", combo_tag: "Quicksand" },
        { name: "Bão Cát Mù Mịt", desc: "[Cơ chế] Quạt bay lớp bụi mặt đất kết hợp ma lực phong thủy. [Hiệu ứng] Tung bão bụi dày đặc bán kính 20m. Che mắt địch (Mù 100%), làm hỏng súng ống cơ khí (Kẹt đạn) và liên tục gây sát thương ma sát nhỏ.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Phong"], range_type: "AoE Trung (Mù lòa)", combo_tag: "Sand_Storm" },
        { name: "Đạn Đá Liên Thanh", desc: "[Cơ chế] Nén sỏi nhỏ và bắn bằng áp lực ma pháp. [Hiệu ứng] Bắn ra hàng trăm viên sỏi sắc nhọn liên tục như súng máy Gatling. Tầm bắn 30m. Chuyên dùng để đè bẹp khiên ma pháp hoặc cào nát giáp da của dị thú.", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Hình nón (Xả đạn)", combo_tag: "Stone_Gatling" },
        { name: "Trọng Lực Đè Nén", desc: "[Cơ chế] Thao túng từ trường và hạt Graviton cục bộ. [Hiệu ứng] Tăng trọng lực khu vực (10x10m) lên gấp 5 lần. Kẻ địch di chuyển chậm chạp như rùa (Giảm 80% AGI), vũ khí trên tay trở nên quá nặng để vung lên.", rank: "Kim Giai", cost: { type: "MP", value: 90000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Từ Trường"], range_type: "AoE Trung (Lĩnh vực)", combo_tag: "Gravity_Zone" },
        { name: "Bàn Tay Khổng Lồ", desc: "[Cơ chế] Nặn đất sét và bùn thành hình bàn tay khổng lồ có khớp nối. [Hiệu ứng] Trồi lên từ lòng đất, tóm chặt mục tiêu (Stun) bóp nghẹt, hoặc nhẹ nhàng nâng đồng đội lên cao để tránh sát thương mặt đất.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tầm Trung (Triệu hồi vật lý)", combo_tag: "Earth_Hand" },
        { name: "Golem Hộ Vệ", desc: "[Cơ chế] Chèn ý thức nhân tạo vào cấu trúc đá vô tri. [Hiệu ứng] Tạo một người đá cao 3m chiến đấu tự động. Golem có HP siêu cao, taunt (khiêu khích) kẻ thù tấn công nó thay vì chủ nhân. Tồn tại 10 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Triệu Hồi"], range_type: "Bên cạnh bản thân", combo_tag: "Summon_Golem" },
        { name: "Lều Trú Ẩn (Sinh tồn)", desc: "[Cơ chế] Ép khối đất đá thành dạng bán cầu rỗng ruột. [Hiệu ứng] Dựng lô cốt đá kiên cố (sức chứa 5 người) có lỗ thông hơi. Chống thú dữ, mưa axit và giữ ấm. Nơi nghỉ ngơi an toàn tuyệt đối trong Hoang Khu.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tiện ích (Sinh tồn)", combo_tag: "Utility_Bunker" },
        { name: "Gia Cố Công Trình", desc: "[Cơ chế] Truyền ma lực lấp đầy các vi nứt trong cấu trúc vật chất. [Hiệu ứng] Phép thuật hỗ trợ. Làm cứng đất đá mềm thành bê tông cốt thép. Sửa chữa cầu gãy, vá lại vách hầm trú ẩn đang rỉ nước chỉ bằng một cái chạm tay.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tiện ích (Sửa chữa)", combo_tag: "Utility_Fortify" },
        { name: "Cảm Nhận Rung Động (Radar)", desc: "[Cơ chế] Đồng bộ sóng não với dao động cơ học của vỏ trái đất. [Hiệu ứng] Đặt tay xuống đất. Phát hiện chính xác vị trí, số lượng, kích thước (trọng lượng) của mọi kẻ địch đang di chuyển trong bán kính 500m. Không thể phát hiện kẻ thù bay.", rank: "Thiết Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Bản thân (Tình báo)", combo_tag: "Seismic_Sense" },
        { name: "Đào Hầm Siêu Tốc", desc: "[Cơ chế] Làm đất tơi xốp và đẩy sang hai bên liên tục. [Hiệu ứng] Tạo đường hầm ngầm rộng 2m với tốc độ 10m/giây. Giúp cả đội xâm nhập căn cứ địch từ dưới lòng đất hoặc tẩu thoát hoàn hảo không để lại dấu vết trên bề mặt.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Đường thẳng (Hỗ trợ di chuyển)", combo_tag: "Tunnel_Dig" },
        { name: "Vũ Khí Đá", desc: "[Cơ chế] Ngưng tụ khoáng silic thành vũ khí sắc bén. [Hiệu ứng] Tạo dao, thương, hoặc búa tạ bằng đá tảng ngay tức khắc. Giải pháp hoàn hảo khi Tamer bị tước vũ khí hoặc rơi mất đồ. Độ bền vũ khí tương đương vũ khí Thép.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Vũ khí)", combo_tag: "Stone_Weapon" },
        { name: "Hấp Thụ Khoáng Chất", desc: "[Cơ chế] Dạ dày chuyển hóa chất vô cơ thành năng lượng. [Hiệu ứng] Ăn trực tiếp đất đá, sỏi, khoáng thạch để hồi phục Thể lực (Stamina) và chữa lành các vết gãy xương. Ăn quặng quý (như quặng sắt/vàng) sẽ hồi máu nhiều hơn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Bản thân (Hồi phục)", combo_tag: "Eat_Minerals" },
        { name: "Bất Hoại (Nội tại)", desc: "[Cơ chế] Nối liền khí tức với Đại Địa, trọng tâm cơ thể hạ xuống mức tuyệt đối. [Hiệu ứng] Kháng 100% các đòn đánh hất văng (Knock-back), hất tung (Knock-up) và Kéo (Pull). Tamer/Thú trở thành một pháo đài không thể bị xê dịch.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Kháng hiệu ứng)", combo_tag: "Unstoppable" },
        { name: "Làm Phẳng Địa Hình", desc: "[Cơ chế] Bào mòn và lấp đầy các bề mặt mấp mô bằng phép thuật. [Hiệu ứng] San bằng đá tảng, hố bom, chướng ngại vật thành một con đường bằng phẳng. Cho phép xe cơ giới UHA tiến công dễ dàng qua Hoang Khu.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "AoE Nhỏ (Tiện ích)", combo_tag: "Pave_Road" },
        { name: "Cát Lún Bẫy", desc: "[Cơ chế] Tạo một hố không khí ẩn dưới lớp cát bề mặt. [Hiệu ứng] Tạo bẫy ngụy trang 3x3m. Bất cứ vật nặng nào (Xe tăng, Quái thú) dẫm lên sẽ lập tức sụt hố sâu 5m. Khóa chặt mục tiêu cho đến khi người dùng giải thuật.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Đặt bẫy", combo_tag: "Sand_Trap" },
        { name: "Pháo Đài Cát (Hấp thụ nổ)", desc: "[Cơ chế] Cát rời rạc có khả năng phân tán động năng cực tốt. [Hiệu ứng] Dựng lô cốt bằng cát khô. Kẻ địch bắn pháo, ném bom hoặc dùng phép hệ Hỏa nổ mạnh vào pháo đài sẽ bị cát hấp thụ 80% sát thương, bảo vệ hoàn hảo người bên trong.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tường chắn/Phòng thủ", combo_tag: "Sand_Bunker" },
        { name: "Thạch Anh Sắc Bén", desc: "[Cơ chế] Nén phân tử cát thành Thạch Anh (Quartz) nguyên chất. [Hiệu ứng] Biến lớp đất mặt thành lưỡi dao tinh thể siêu mỏng. Đủ sắc bén để rạch thủng lốp xe bọc thép, cắt đứt gân chân thú săn mồi hoặc phản xạ tia laser.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "AoE Nhỏ (Vật lý/Bẫy)", combo_tag: "Quartz_Blade" },
        { name: "Đổi Vị Trí Địa Lý", desc: "[Cơ chế] Trượt các mảng đất bề mặt như trò chơi xếp hình. [Hiệu ứng] Bí mật dịch chuyển các tảng đá lớn, cây cổ thụ, hoặc cột mốc đánh dấu đường đi. Khiến toàn bộ trinh sát quân địch mất phương hướng và đi lạc vào ổ phục kích.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Ảo Giác"], range_type: "AoE Rộng (Môi trường)", combo_tag: "Terrain_Shift" },
        { name: "Ném Bùn", desc: "[Cơ chế] Trộn đất với nước tạo hỗn hợp bám dính. [Hiệu ứng] Ném một cục bùn nhão nhoét với độ chính xác cao. Bịp kín mắt quái thú (Gây Mù) hoặc bịt chặt ống ngắm, nòng súng địch khiến súng phát nổ khi bóp cò.", rank: "Phàm Giai", cost: { type: "MP", value: 15 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Nước"], range_type: "Tầm Trung (Đơn mục tiêu)", combo_tag: "Mud_Throw" },
        { name: "Thổ Khí Trị Liệu", desc: "[Cơ chế] Dùng khoáng chất hút từ tính sinh học lỗi. [Hiệu ứng] Chôn bản thân hoặc đồng đội dưới đất sạch. Đất sẽ từ từ hút độc tố (kể cả phóng xạ nhẹ) ra ngoài, giảm đau nhức xương khớp và nối liền gân cốt trong 1 giờ.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Trị Liệu"], range_type: "Cận chiến (Hỗ trợ)", combo_tag: "Earth_Heal" },
        { name: "Bậc Thang Đá", desc: "[Cơ chế] Rút các khối đá nhỏ từ vách núi nhô ra. [Hiệu ứng] Tạo ra một chuỗi các bậc thang đá vững chắc bám vào vách núi dựng đứng 90 độ. Giúp toàn đội leo lên các địa hình bất khả thi mà không cần dây thừng.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tiện ích (Di chuyển)", combo_tag: "Stone_Stairs" },
        { name: "Khóa Cứng Khớp", desc: "[Cơ chế] Truyền hạt bụi ma thuật xâm nhập vào dịch khớp xương địch. [Hiệu ứng] Đòn cận chiến nguy hiểm. Khi chạm tay vào khớp gối/cùi chỏ địch, hóa đá hoàn toàn dịch khớp. Nạn nhân không thể co duỗi chân tay, biến thành bia đỡ đạn.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Cận Chiến", combo_tag: "Joint_Petrify" },
        { name: "Sụp Đổ Hang Động", desc: "[Cơ chế] Phá hủy điểm chịu lực (Keystone) của cấu trúc vòm. [Hiệu ứng] Đánh sập hoàn toàn trần hang động hoặc tầng hầm. Chôn vùi hàng trăm kẻ địch dưới hàng tấn đất đá. [Tác dụng phụ] Dễ dàng bóp chết cả team mình nếu không tính toán lối thoát.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "AoE Rộng (Phá hủy môi trường)", combo_tag: "Cave_Collapse" },
        { name: "Lục Địa Trầm Luân (Đại Thánh Giai)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Cưỡng ép can thiệp vào lõi magma của hành tinh, đảo lộn mảng kiến tạo lục địa. [Hiệu ứng] Đánh chìm một Lục địa hoặc Đảo quốc khổng lồ xuống đáy biển sâu. Xóa sổ hàng tỷ sinh linh, viết lại bản đồ thế giới. Không thể né tránh. [Tác dụng phụ cực lớn] Rút cạn sinh mệnh, người tung chiêu hóa thành Tượng Đá phong hóa vĩnh viễn (Game Over/Chết thực). Kỹ năng chỉ dùng để hy sinh cứu nhân loại hoặc tự sát đồng quy ư tận.", rank: "Thánh Giai", cost: { type: "HP", value: 9999999 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Hủy Diệt"], range_type: "Cấp Thế Giới", combo_tag: "Holy_Continents_Fall" },
        { name: "Hóa Hình - Thổ Độn", desc: "[Cơ chế] Dị thú hóa lỏng cơ thể vào cát, ngưng tụ lại thành người. [Hiệu ứng] Chìm xuống lòng đất và trồi lên dưới hình dạng một con người đắp từ cát vàng, sau đó da thịt mới biến hóa thành hình. Che giấu yêu khí tuyệt vời. Trọng lượng cực nặng dù mang hình dáng nhỏ bé.", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Sinh Học"], range_type: "Bản thân (Ngụy trang)", combo_tag: "Beast_Sand_Form" },
        { name: "Trùng Kích Đại Địa", desc: "[Cơ chế] Phiên bản hoang dã của Địa Chấn. Dậm mạnh chi trước mang sức nặng chục tấn. [Hiệu ứng] Tạo chấn động cực gắt bán kính 20m. Làm choáng 2s toàn bộ kẻ địch xung quanh. Lực vỡ nát mặt đường, hất tung các xe cơ giới nhỏ lật ngửa.", rank: "Thiết Giai", cost: { type: "Stamina", value: 300 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "AoE Trung", combo_tag: "Beast_Stomp" },
        { name: "Tường Đất Phân Cách", desc: "[Cơ chế] Húc sừng hoặc cào đất tạo vách núi nhân tạo. [Hiệu ứng] Dựng lên bức tường đất kiên cố khổng lồ (Dài 20m, cao 10m) chắn ngang chiến trường. Chia cắt hoàn toàn đội hình địch làm đôi, cô lập chủ lực để dễ bề làm thịt.", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tường chắn Rộng", combo_tag: "Beast_Wall_Split" },
        { name: "Đá Lở Đè Bẹp", desc: "[Cơ chế] Gầm rống tạo cộng hưởng âm thanh làm nứt đá trên cao. [Hiệu ứng] Kích hoạt lở đá tảng khổng lồ từ vách núi rơi xuống nghiền nát mục tiêu. Gây sát thương vật lý chí mạng nếu ở môi trường đồi núi, vô dụng ở đồng bằng.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "AoE Phụ thuộc địa hình", combo_tag: "Rockslide" },
        { name: "Giáp Nham Thạch Trơ", desc: "[Cơ chế] Lớp da sừng hấp thụ tinh hoa đất rữa. [Hiệu ứng] Biến lớp da thành đá tảng, tăng giáp vật lý lên cực hạn (Miễn nhiễm sát thương của súng trường đạn xuyên giáp). Tuy nhiên làm thú di chuyển cực chậm, mất khả năng né tránh.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Bản thân (Buff tanker)", combo_tag: "Beast_Heavy_Armor" },
        { name: "Mũi Khoan Lòng Đất", desc: "[Cơ chế] Vuốt trước tạo thành mũi khoan xoay, vảy vuốt ngược ra sau. [Hiệu ứng] Xoáy cơ thể chui xuống đất, bơi ngầm tốc độ cao. Đâm lên tấn công nhắm vào yết hầu hoặc bụng dưới kẻ thù (Điểm yếu chí mạng) với lực xuyên thấu kinh hoàng.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Đột kích (Tầm Xa/Cận chiến)", combo_tag: "Drill_Strike" },
        { name: "Cọc Đất Xiên Thấu", desc: "[Cơ chế] Giậm chân, truyền xung lực đâm xuyên mảng kiến tạo dưới chân địch. [Hiệu ứng] Hàng loạt gai đá nhọn khổng lồ (Dài 2m) đâm phọt lên từ ngay dưới bụng mục tiêu. Xuyên thủng giáp gầm xe tăng hoặc đâm ruột kẻ thù.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "AoE Nhỏ (Tầm Trung)", combo_tag: "Earth_Impale" },
        { name: "Bãi Lầy Sa Lầy", desc: "[Cơ chế] Tiết dịch nhầy hòa với đất. [Hiệu ứng] Biến bán kính 10m đất cứng thành đầm lầy dính nhớp. Hút chân kẻ thù chìm xuống, vô hiệu hóa hoàn toàn độ cơ động của kỵ binh hoặc xe cộ.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Nước"], range_type: "AoE Trung (Khống chế/Làm chậm)", combo_tag: "Beast_Swamp" },
        { name: "Cát Bụi Che Mắt (Bản năng)", desc: "[Cơ chế] Quẫy đuôi hất tung đất cát. [Hiệu ứng] Tung bão cát mù mịt tầm ngắn. Làm mù các thiết bị ngắm bắn quang học của lính UHA, giúp dị thú tẩu thoát khi bị hội đồng.", rank: "Phàm Giai", cost: { type: "Stamina", value: 50 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Hình Nón Nhỏ", combo_tag: "Dirt_Kick" },
        { name: "Đạn Thạch Cao Tốc", desc: "[Cơ chế] Ngậm sỏi vào miệng, nén khí sinh học và khạc ra. [Hiệu ứng] Nhả viên đá cuội với sơ tốc đầu nòng 800m/s (Ngang súng trường Sniper). Xuyên táo sọ người hoặc vỡ nát khiên ma pháp từ khoảng cách 1km.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3200 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Đơn mục tiêu (Siêu xa)", combo_tag: "Beast_Sniper" },
        { name: "Trọng Lực Đè Nén (Điểm Kỳ Dị - Hố Đen)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Bóp méo không gian - thời gian bằng khối lượng siêu đặc ảo. [Hiệu ứng] Tạo một hố đen trọng lực nhỏ. Hút mọi thứ (vật chất, ánh sáng, ma pháp) vào tâm điểm và nghiền nát thành hạt nguyên tử. Sát thương vô cực với kẻ địch ở tâm lõi. [Tác dụng phụ] Hao tổn 80% Max HP. Không gian bị xé rách sẽ nuốt luôn một phần linh hồn người tung chiêu, gây mất 50% INT vĩnh viễn, Sanity giảm về ngưỡng điên loạn cục bộ.", rank: "Diệu Giai", cost: { type: "HP", value: 65000 }, cooldown: { value: 90, unit: "Ngày", display_text: "3 Tháng" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Không Gian"], range_type: "AoE Rộng (Sức hút tử thần)", combo_tag: "Divine_Blackhole" },
        { name: "Bàn Tay Khổng Lồ (Bản hoang dã)", desc: "[Cơ chế] Dùng đất bùn tạo hình chi phụ tàng hình. [Hiệu ứng] Bàn tay đất tóm chặt lấy sủng thú của đối phương lôi tuột xuống lòng đất (Chôn sống), loại bỏ ngay lập tức 1 kẻ địch khỏi chiến trường trong 30 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Tầm Trung (Bắt cóc)", combo_tag: "Buried_Alive" },
        { name: "Golem Hóa", desc: "[Cơ chế] Dung hợp bản thể thịt với khoáng chất vô cơ. [Hiệu ứng] Thú hấp thụ đất đá xung quanh để phình to thành một Cự Nhân Đá khổng lồ (Cao 15m) trong 2 giờ. HP x5, STR x3, đòn đánh gây chấn động diện rộng. Sau khi hết giờ sẽ kiệt sức.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 75000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Sinh Học"], range_type: "Bản thân (Tiến hóa siêu cấp)", combo_tag: "Giant_Form" },
        { name: "Đất Mẹ Che Chở", desc: "[Cơ chế] Bản năng phòng ngự cuộn tròn của thú có mai/vảy. [Hiệu ứng] Cuộn tròn cơ thể thành một quả cầu, bọc thêm lớp đá dày 1m. Đóng kín mọi kẽ hở. Miễn nhiễm 90% mọi loại sát thương để an toàn hồi máu (Hồi 20% HP/phút). Tuy nhiên không thể tấn công.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ"], range_type: "Bản thân (Phòng thủ tuyệt đối)", combo_tag: "Earth_Cocoon" },
        { name: "Thạch Anh Sắc Lẹm", desc: "[Cơ chế] Thú gầm lên, chuyển hóa móng vuốt và gai lưng thành tinh thể. [Hiệu ứng] Các đòn cào, vả chém rách bươm màng bảo vệ phép thuật (Magic Shield) như chém giấy. Khắc tinh cứng của Pháp sư/Ngự Thú Sư núp sau khiên.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Cận Chiến (Phá Khiên)", combo_tag: "Shield_Breaker" },
        { name: "Rung Chấn Địa Mạch (Thiên Tai)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Gây đứt gãy đới đứt gãy kiến tạo sâu 10km. [Hiệu ứng] Hủy diệt từ gốc rễ. Phá hủy hoàn toàn cấu trúc địa chất, gây sập đổ hàng loạt Thành Phố ngầm, Vòm sinh thái UHA. Vết nứt nuốt chửng hàng vạn sinh mạng. [Tác dụng phụ] Hút cạn MP, Sanity giảm sâu. Cánh tay/Chân thi triển chiêu thức vỡ nát thành bụi đất, vĩnh viễn mất đi chi đó (Không thể tái tạo bằng phép mộc).", rank: "Diệu Giai", cost: { type: "MP", value: 45000000 }, cooldown: { value: 180, unit: "Ngày", display_text: "Nửa Năm" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Sóng Âm"], range_type: "AoE Rất Rộng (Hủy diệt ngầm)", combo_tag: "Divine_Faultline" },
        { name: "Đá Mài Răng Cưa", desc: "[Cơ chế] Phủ vụn đá sắc cạnh lên móng/răng. [Hiệu ứng] Tăng ma sát và độ xé rách. Cú cắn/cào gây vết thương nham nhở tột độ, chảy máu không ngừng (Trừ 2% HP mỗi phút) và gây nhiễm trùng (Khó hồi máu).", rank: "Thiết Giai", cost: { type: "Stamina", value: 180 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Vật Lý"], range_type: "Cận chiến (Cường hóa)", combo_tag: "Bleeding_Claws" },
        { name: "Thổ Khí Hồi Phục", desc: "[Cơ chế] Rễ sinh học vô hình dưới lòng bàn chân hút sinh khí đất. [Hiệu ứng] Chỉ cần đứng trên mặt đất tự nhiên (Không phải bê tông), thú sẽ liên tục hồi phục thể lực (Stamina) và sinh lực (HP) chậm rãi mà không tốn năng lượng duy trì.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Hồi máu thụ động)", combo_tag: "Earth_Regen" },
        { name: "Vững Chãi Lòng Đất (Bị động)", desc: "[Cơ chế] Móng vuốt ghim chặt sâu 3m vào nền đá. [Hiệu ứng] Cơ thể như mọc rễ. Miễn nhiễm hoàn toàn với các kỹ năng hất văng (Knock-back), đẩy lùi hoặc gió bão cuốn đi. Sẵn sàng đỡ đòn làm Tanker chính cho đội.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ"], range_type: "Bản thân (Kháng Khống chế)", combo_tag: "Rooted_Stance" }
    ],
  "Hệ Mộc": [
        { name: "Hóa Hình - Mộc Tinh", desc: "[Cơ Chế Sinh Học] Dung hợp tế bào thực vật và động vật. Máu là nhựa cây lục, da chứa diệp lục. Hệ tuần hoàn mạch rây/gỗ, tim là hạt giống. Không bài tiết. [Hình Thái] Da hồng hào, tóc là dây leo tỏa hương. Ở dạng người tự liền vết thương thần tốc khi có nắng. [Tác dụng phụ] Sợ lửa cực độ, dính sát thương hệ Hỏa x2, ở trong hang tối lâu sẽ héo úa (Giảm max HP).", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Sinh Học"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Wood" },
        { name: "Vỏ Sồi Bất Hoại", desc: "[Cơ chế] Lớp biểu bì sừng hóa thành vỏ cây cổ thụ khi nhận sát thương liên tục. [Hiệu ứng] Mỗi lần bị đánh trúng, nhận 1 lớp [Vỏ Sồi] (+2% DEF, cộng dồn 10 lần). Lớp vỏ sẽ tự bong ra sau 5s nếu không bị đánh tiếp.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Bản thân (Bị động cộng dồn giáp)", combo_tag: "Passive_Oak_Bark" },
        { name: "Rễ Bám Trụ", desc: "[Cơ chế] Bàn chân mọc rễ ma thuật cắm sâu vào lòng đất mỗi khi đứng yên. [Hiệu ứng] Đứng im quá 2 giây, không thể bị hất văng hay kéo lê (Kháng 100% Knockback). Nhấc chân lên di chuyển sẽ mất hiệu ứng.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Thổ"], range_type: "Bản thân (Bị động thế đứng)", combo_tag: "Passive_Root_Stance" },
        { name: "Gai Độc Vô Hình", desc: "[Cơ chế] Lông tơ trên da cứng lại thành gai mộc tẩm nhựa độc. [Hiệu ứng] Kẻ địch đánh cận chiến (đấm/cào) vào người bạn sẽ tự động bị dính gai, nhận hiệu ứng Độc nhẹ làm chậm 5% tốc độ đánh trong 3s.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Độc"], range_type: "Bản thân (Bị động phản sát thương/debuff)", combo_tag: "Passive_Toxic_Thorns" },
        { name: "Tái Tạo Diệp Lục", desc: "[Cơ chế] Máu chứa diệp lục phân giải năng lượng ánh sáng. [Hiệu ứng] Khi đứng dưới ánh nắng mặt trời, vết thương hở tự động ngừng chảy máu và tốc độ hồi phục HP cơ bản tăng 20%.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Quang"], range_type: "Bản thân (Bị động hồi máu)", combo_tag: "Passive_Chlorophyll_Heal" },
        { name: "Hương Báo Động", desc: "[Cơ chế] Tuyến mồ hôi tiết mùi hương đặc trưng khi hoảng sợ hoặc đau đớn. [Hiệu ứng] Khi lượng HP của bạn rớt xuống dưới 30%, cơ thể tỏa mùi hương lan xa 1km. Các đồng minh ngửi thấy sẽ được tăng 10% Tốc chạy khi chạy về phía bạn.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Khí"], range_type: "Tầm xa (Bị động gọi cứu viện)", combo_tag: "Passive_Alarm_Scent" },
        { name: "Nhựa Kháng Ma Phép", desc: "[Cơ chế] Máu chảy ra cô đặc thành màng nhựa dẻo bọc lấy vết thương. [Hiệu ứng] Nhựa cây này có tính cách ly ma lực. Giảm 15% Sát thương phép từ mọi kỹ năng nguyên tố (Lửa, Nước, Sét) trúng vào người.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Bản thân (Bị động kháng phép)", combo_tag: "Passive_Resin_Barrier" },
        { name: "Lĩnh Vực Rêu Phong", desc: "[Cơ chế] Dấu chân gieo rắc hạt rêu ma thuật phát triển siêu tốc. [Hiệu ứng] Những nơi bạn vừa đứng qua sẽ mọc rêu trơn trượt. Kẻ địch đuổi theo dẫm phải rêu có 20% tỉ lệ trượt ngã, mất thăng bằng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Đường đi (Bị động bẫy trượt)", combo_tag: "Passive_Moss_Trail" },
        { name: "Sức Sống Vạn Cổ", desc: "[Cơ chế] Tế bào thực vật có khả năng đình chỉ quá trình lão hóa/hoại tử. [Hiệu ứng] Mọi hiệu ứng gây sát thương theo thời gian (DoT) như Bỏng, Chảy Máu, Độc sẽ bị giảm 50% thời gian tác dụng trên cơ thể bạn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Sinh Mệnh"], range_type: "Bản thân (Bị động kháng DoT)", combo_tag: "Passive_Ancient_Vitality" },
        { name: "Dây Leo Ký Sinh", desc: "[Cơ chế] Hạt mầm trong móng vuốt cắm vào da thịt địch sau mỗi cú cào. [Hiệu ứng] Đòn đánh thường có tỉ lệ 10% cấy hạt giống vào mục tiêu. Hạt giống sẽ hút một lượng nhỏ MP của địch và hồi cho bạn.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Hút Năng Lượng"], range_type: "Đòn đánh (Bị động hút MP)", combo_tag: "Passive_Parasite_Strike" },
        { name: "Lá Chắn Bào Tử", desc: "[Cơ chế] Các túi bào tử nấm mọc ẩn dưới lớp lông/quần áo. [Hiệu ứng] Khi nhận một đòn sát thương vật lý mạnh (>15% Max HP), tự động xịt ra một đám mây bào tử làm giảm 20% Tầm nhìn của kẻ thù trước mặt trong 2s.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Bản thân (Bị động che mắt)", combo_tag: "Passive_Spore_Shield" },
        { name: "Hút Huyết Thổ", desc: "[Cơ chế] Rễ sinh học có thể hút dinh dưỡng từ xác chết phân hủy. [Hiệu ứng] Nếu đứng gần xác quái vật/kẻ địch bị hạ gục (bán kính 3m), tự động hấp thụ sinh khí tàn dư để hồi phục 2% HP và 2% Stamina.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Hắc Ám"], range_type: "Xung quanh (Bị động hồi phục)", combo_tag: "Passive_Corpse_Bloom" },
        { name: "Mộc Mạch Chống Độc", desc: "[Cơ chế] Lọc các chất gây hại như cách cây xanh lọc kim loại nặng. [Hiệu ứng] Kháng 100% các loại khí gas ru ngủ, độc tố làm tê liệt thần kinh cấp Phàm. Đảm bảo luôn tỉnh táo trong khu vực khí đầm lầy.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Độc"], range_type: "Bản thân (Bị động kháng độc)", combo_tag: "Passive_Wood_Filter" },
        { name: "Xúc Tu Dưới Đất", desc: "[Cơ chế] Rễ non luôn bò ngầm dưới mặt đất theo bước chân. [Hiệu ứng] Kẻ địch tàng hình (Hệ Ám/Phong) vô tình dẫm lên mạng lưới rễ tàng hình dưới đất sẽ bị lộ vị trí (Hiện viền đỏ) trong 3 giây cho toàn đội thấy.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Trinh Sát"], range_type: "AoE Nhỏ (Bị động phát hiện)", combo_tag: "Passive_Root_Radar" },
        { name: "Phân Tán Động Năng Gỗ", desc: "[Cơ chế] Cơ bắp dẻo dai và có độ đàn hồi như cành liễu trước gió. [Hiệu ứng] Các đòn tấn công bằng vũ khí chùy, búa đập (Sát thương cùn) sẽ bị trượt đi hoặc giảm sát thương 20%. Tuy nhiên dễ bị vũ khí Rìu chém đứt.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Bản thân (Bị động kháng chùy)", combo_tag: "Passive_Willow_Bend" },
        { name: "Sương Mù Phấn Hoa", desc: "[Cơ chế] Phấn hoa tự nhiên tản ra liên tục như một lớp sương mờ. [Hiệu ứng] Tăng 10% Tỉ lệ Né tránh (Dodge) với tất cả các đòn tấn công. Đồng thời khiến những kẻ địch đứng gần hắt hơi liên tục (Ngắt quãng niệm chú Phép thuật).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Khí"], range_type: "AoE Cận chiến (Bị động né tránh/Làm phiền)", combo_tag: "Passive_Pollen_Cloud" },
        { name: "Kháng Lôi Thụ", desc: "[Cơ chế] Cấu trúc cơ thể hoạt động như gỗ khô cách điện. [Hiệu ứng] Giảm 40% sát thương từ các kỹ năng Hệ Lôi và hoàn toàn không bị Tê Liệt khi giẫm phải bẫy điện hay bị sét đánh lan.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Lôi"], range_type: "Bản thân (Bị động kháng sét)", combo_tag: "Passive_Rubber_Wood" },
        { name: "Khí Tức Rừng Rậm", desc: "[Cơ chế] Trở thành một phần của hệ sinh thái Mộc nguyên thủy. [Hiệu ứng] Khi chiến đấu trong rừng, mọi kỹ năng Hệ Mộc của bạn được giảm 10% lượng MP tiêu hao và tăng 10% hiệu quả (Hồi máu/Sát thương).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Môi Trường"], range_type: "Bản thân (Bị động môi trường)", combo_tag: "Passive_Forest_Affinity" },
        { name: "Gai Gỗ Phản Thương", desc: "[Cơ chế] Khớp xương tay tự đẩy trồi các dằm gỗ cực nhọn khi vung đấm. [Hiệu ứng] Kẻ địch dùng tay không hoặc lá chắn gỗ đỡ đòn đánh của bạn sẽ bị dằm đâm ngược vào tay, chịu sát thương vật lý rỉ máu liên tục.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Đòn đánh (Bị động phản sát thương)", combo_tag: "Passive_Splinter_Strike" },
        { name: "Sinh Trưởng Kích Thích", desc: "[Cơ chế] Auxin tràn ngập mạch máu mỗi khi cơ thể kiệt quệ. [Hiệu ứng] Khi Stamina (Thể lực) rớt xuống dưới 20%, tốc độ hồi phục Stamina tự động nhân đôi (x2) để duy trì khả năng chạy trốn hoặc đánh trả.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Bản thân (Bị động hồi sức)", combo_tag: "Passive_Growth_Spurt" },
        { name: "Âm Thanh Mộc Linh", desc: "[Cơ chế] Lắng nghe sự xào xạc của lá cây cảnh báo. [Hiệu ứng] Không bao giờ bị [Bất ngờ/Surprised] bởi các cuộc tập kích. Dù kẻ địch có tàng hình kỹ đến đâu, cây cối xung quanh cũng sẽ báo động bằng sự chuyển động bất thường của lá.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Sóng Âm"], range_type: "Xung quanh (Bị động chống tập kích)", combo_tag: "Passive_Leaf_Whisper" },
        { name: "Dây Leo Gai Nhỏ", desc: "[Cơ chế] Bắn mầm cây xuống đất mọc dây leo lên. [Hiệu ứng] Trói nhẹ đôi chân đối thủ trong 1 giây, gây xước da rỉ máu nhẹ. Thường dùng để ngắt nhịp chạy của kẻ thù đang bỏ trốn.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Tầm Xa (Trói chân)", combo_tag: "Vine_Trip" },
        { name: "Quất Roi Gỗ", desc: "[Cơ chế] Vươn dài cổ tay thành nhánh mộc linh dẻo dai. [Hiệu ứng] Vung roi quất vào mặt địch. Cực kỳ đau rát, để lại vết lằn bầm tím làm giảm 10% sát thương của địch do đau đớn.", rank: "Phàm Giai", cost: { type: "Stamina", value: 15 }, cooldown: { value: 4, unit: "Giây", display_text: "4 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Tầm Trung (Đánh roi)", combo_tag: "Wood_Whip_Strike" },
        { name: "Phóng Gai Nhọn", desc: "[Cơ chế] Bắn hàng chục gai gỗ cứng như đinh từ lòng bàn tay. [Hiệu ứng] Mưa gai găm vào da thịt quái thú không mặc giáp. Gai cắm sâu làm địch di chuyển rất khó chịu (Trừ 20% AGI).", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Hình Nón Nhỏ", combo_tag: "Wood_Spike_Volley" },
        { name: "Đạn Gỗ Cứng", desc: "[Cơ chế] Ép súc nhựa cây và mùn cưa thành viên đạn tròn xoe. [Hiệu ứng] Bắn đạn gỗ (tốc độ súng trường). Sát thương vật lý cùn, đập vào ngực địch làm lùi lại 1 bước, hụt hơi ngắt quãng niệm chú.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Tầm Xa (Sát thương cùn)", combo_tag: "Wood_Bullet" },
        { name: "Mộc Thuẫn Nhẹ", desc: "[Cơ chế] Đan chéo rễ cây tạo thành khiên gỗ mục. [Hiệu ứng] Chặn đứng được 2 mũi tên hoặc đòn cào của tiểu yêu. Sau đó khiên vỡ. Rất tốn ít MP để dùng liên tục phòng ngự cá nhân.", rank: "Phàm Giai", cost: { type: "MP", value: 15 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Bản thân (Lá chắn)", combo_tag: "Bark_Buckler" },
        { name: "Hạt Giống Ký Sinh Yếu", desc: "[Cơ chế] Thổi phấn hoa bám vào vết thương hở của địch. [Hiệu ứng] Hút trộm máu mục tiêu với tốc độ cực chậm (1% HP/giây) và hồi cho bản thân. Duy trì 5 giây hoặc bị rửa bằng nước.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Hút Máu"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Parasite_Spore" },
        { name: "Gỗ Lim Phản Chấn", desc: "[Cơ chế] Cứng hóa cẳng tay thành gỗ Lim (Ironwood) xù xì. [Hiệu ứng] Dùng tay đỡ dao/kiếm. Gươm chém vào tay không bị đứt mà bị kẹt lại trong thớ gỗ, khiến kẻ địch bị tước vũ khí.", rank: "Thiết Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Cận Chiến (Khóa vũ khí)", combo_tag: "Ironwood_Parry" },
        { name: "Hồi Máu Cấp Cứu", desc: "[Cơ chế] Truyền nhựa cây xanh trực tiếp vào mạch máu đồng minh. [Hiệu ứng] Hồi 15% HP ngay lập tức và dán liền vết thương hở chống mất máu. Bắt buộc phải áp sát sờ vào người mục tiêu.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Trị Liệu"], range_type: "Cận Chiến (Hỗ trợ)", combo_tag: "Quick_Heal_Sap" },
        { name: "Lá Ngụy Trang", desc: "[Cơ chế] Áo khoác biến đổi màu sắc đồng bộ với thảm thực vật. [Hiệu ứng] Đứng im trong bụi cỏ sẽ tàng hình hoàn toàn khỏi mắt thường (Không giấu được mùi hoặc cảm biến nhiệt). Giúp né các cuộc tuần tra.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Bản thân (Ẩn nấp)", combo_tag: "Leaf_Camo" },
        { name: "Vũng Lầy Rêu Xanh", desc: "[Cơ chế] Thúc rêu phát triển cực lẹ làm bề mặt siêu trơn. [Hiệu ứng] Trải thảm rêu bán kính 3m. Ai dẫm lên sẽ ngã lộn nhào (Choáng 1s). Nếu là đồng minh biết trước sẽ dùng nó để trượt đi nhanh hơn.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Đặt Bẫy Bề Mặt", combo_tag: "Moss_Trap" },
        { name: "Mộc Phân Thân Nhỏ", desc: "[Cơ chế] Đẽo gọt một khúc gỗ tạo hình nhân đóng thế. [Hiệu ứng] Ném khúc gỗ ra hứng chịu một đòn chém chí mạng. Kẻ địch chém gỗ vỡ đôi, tưởng đã giết được nhưng người thi triển đã né lùi ra sau 2m.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 25, unit: "Giây", display_text: "25 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Không Gian"], range_type: "Bản thân (Né tuyệt sát)", combo_tag: "Log_Substitution" },
        { name: "Độc Phấn Kích Ứng", desc: "[Cơ chế] Ném túm phấn hoa mang tính axit nhẹ. [Hiệu ứng] Bay vào mặt địch gây ngứa ngáy điên cuồng, ho sặc sụa và Mù lòa tạm thời. Bắt đối thủ phải buông vũ khí gãi mắt gãi mũi.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Độc"], range_type: "Hình Nón Nhỏ", combo_tag: "Itch_Pollen" },
        { name: "Tường Rễ Cản Phá", desc: "[Cơ chế] Đẩy rễ cây đội đất trồi lên cản đường. [Hiệu ứng] Dựng rào cản dày 1m làm vướng chân xe ngựa, xe bọc thép hoặc bộ binh. Tường không kiên cố nhưng đủ để câu giờ 3 giây trước khi bị đập nát.", rank: "Phàm Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Tường Chắn Rộng", combo_tag: "Root_Barricade" },
        { name: "Bàn Tay Lá Nắm Lấy", desc: "[Cơ chế] Hội tụ lá cây thành cánh tay ảo. [Hiệu ứng] Tóm chặt vũ khí của địch từ xa hoặc giật túi đồ của chúng mang về cho mình (Phạm vi 5m). Không thể nâng vật quá nặng.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Tầm Trung (Thao túng)", combo_tag: "Leaf_Grip" },
        { name: "Rễ Cây Trích Máu", desc: "[Cơ chế] Rễ mọc nhọn đâm ngược từ dưới đất lên gan bàn chân. [Hiệu ứng] Xuyên thủng gót, gây chảy máu rút 3% HP/lượt. Không khóa chân nhưng bắt mục tiêu phải chịu đau khi chạy trốn.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Hút Máu"], range_type: "Đánh lén dưới đất", combo_tag: "Bleed_Root" },
        { name: "Hương Trầm Ru Ngủ", desc: "[Cơ chế] Tỏa mùi hương hoa cúc thôi miên. [Hiệu ứng] Kẻ địch và thú hoang cấp thấp ngửi thấy sẽ ngáp ngủ, giảm 30% sát thương đòn đánh và phản xạ cực kỳ lờ đờ (Giảm AGI).", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Tinh Thần"], range_type: "AoE Trung", combo_tag: "Sleep_Scent" },
        { name: "Chồi Non Giải Độc", desc: "[Cơ chế] Cho đồng đội ăn chồi cây mang dược tính mạnh. [Hiệu ứng] Giải trừ ngay lập tức các Độc tố cấp Phàm/Thiết (Nọc độc nhện, Ong, Bỏng lửa nhẹ). Phải nhai nát mới có tác dụng.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Trị Liệu"], range_type: "Cận Chiến (Giải buff xấu)", combo_tag: "Herb_Sprout_Cure" },
        { name: "Đại Thụ Giao Tranh", desc: "[Cơ chế] Cánh tay hóa khổng lồ thành thân gỗ Sồi vung đòn. [Hiệu ứng] Nện một đòn vòng cung đập văng toàn bộ kẻ thù đứng trước mặt lùi lại 3m. Đòn Knockback càn quét giữ khoảng cách cho Pháp sư.", rank: "Thiết Giai", cost: { type: "Stamina", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Hình Nón Nhỏ (Hất văng)", combo_tag: "Oak_Trunk_Swing" },
        { name: "Cọ Xát Đốt Lửa", desc: "[Cơ chế] Hai nhánh gỗ ma thuật ma sát tốc độ siêu thanh. [Hiệu ứng] Tạo tia lửa điện/Hỏa mồi ném thẳng vào đống dầu hoặc kẻ địch đang đứng trong khí gas (Hệ Hỏa). Kỹ năng combo mồi nổ cháy rừng.", rank: "Phàm Giai", cost: { type: "Stamina", value: 15 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Hệ Hỏa"], range_type: "Tầm Xa Cực Ngắn (Mồi lửa)", combo_tag: "Friction_Ignite" },
        { name: "Lá Bay Sắc Chứa Độc", desc: "[Cơ chế] Bắn chiếc lá có gai độc ở viền. [Hiệu ứng] Chém xước qua da, để lại độc tính làm ngứa ran, sưng tấy cơ bắp (Giảm 15% STR của kẻ địch). Cấu rỉa khó chịu từ xa.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Độc"], range_type: "Tầm Xa (Cấu rỉa/Debuff)", combo_tag: "Toxic_Leaf_Cutter" },
        { name: "Hồi Phục Sự Sống", desc: "[Cơ chế] Kích thích tế bào phân chia cấp tốc bằng mộc năng thuần khiết. [Hiệu ứng] Phát sóng năng lượng xanh bán kính 10m. Hồi 10% Max HP mỗi phút cho toàn bộ đồng đội. Chữa lành các vết rách cơ, gãy xương kín nhanh chóng.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Trị Liệu"], range_type: "AoE Trung (Hồi máu)", combo_tag: "AoE_Heal" },
        { name: "Dây Leo Trói Buộc", desc: "[Cơ chế] Thúc đẩy sinh trưởng hạt giống gai cực tốc. [Hiệu ứng] Từ dưới đất mọc lên dây leo gai siết chặt chân và tay địch. Khóa di chuyển (Root) 2 phút. Càng vùng vẫy gai càng cắm sâu gây chảy máu (Trừ 2% HP/phút).", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Tầm Trung (Khống chế cứng)", combo_tag: "Vine_Bind" },
        { name: "Hạt Giống Ký Sinh", desc: "[Cơ chế] Bắn mầm mộc hóa vào mạch máu nạn nhân. [Hiệu ứng] Hạt giống cắm vào da thịt nảy mầm. Hút 5% HP và MP của địch mỗi giây truyền thẳng về cho người tung chiêu. Kéo dài cho đến khi mục tiêu chết hoặc hạt giống bị đốt cháy.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Hút Máu"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Leech_Seed" },
        { name: "Quang Hợp (Hồi mana)", desc: "[Cơ chế] Da hấp thụ trực tiếp quang tử (Photon) biến thành năng lượng sinh học. [Hiệu ứng] Đứng dưới ánh nắng gắt mặt trời. Hồi phục 20% MP và Stamina mỗi giờ. Miễn nhiễm say nắng. Không có tác dụng vào ban đêm hoặc bị che khuất.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Quang"], range_type: "Bản thân (Hồi phục thụ động)", combo_tag: "Photosynthesis" },
        { name: "Phi Tiêu Lá", desc: "[Cơ chế] Bơm mana làm cứng rìa lá cây đạt độ sắc của thép carbon. [Hiệu ứng] Phóng hàng chục chiếc lá xoay tròn với tốc độ cực cao. Cắt đứt cổ họng địch không gây tiếng động. Tuyệt kỹ ám sát hoàn hảo trong rừng rậm.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Tầm Trung (Đạn đạo)", combo_tag: "Leaf_Shuriken" },
        { name: "Tường Gai Độc", desc: "[Cơ chế] Đan xen cây bụi và tẩm dịch nhầy tê liệt. [Hiệu ứng] Dựng hàng rào gai cao 4m. Ngăn cản địch tiếp cận. Kẻ nào cố tình phá hoặc leo qua sẽ bị gai đâm chích độc (Tê liệt cơ bắp, giảm 50% AGI và STR).", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Độc"], range_type: "Tường chắn (Phòng ngự/Bẫy)", combo_tag: "Poison_Wall" },
        { name: "Rừng Cây Bảo Hộ", desc: "[Cơ chế] Cộng hưởng từ trường sinh học của thảm thực vật xung quanh. [Hiệu ứng] Kỹ năng nội tại/Buff môi trường. Khi chiến đấu trong rừng, mọi kỹ năng Mộc giảm 50% MP tiêu hao, tăng 30% uy lực, và bản thân nhận thêm lớp khiên lá 500 HP.", rank: "Ngân Giai", cost: { type: "MP", value: 1500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "AoE Rộng (Lĩnh vực thụ động)", combo_tag: "Forest_Buff" },
        { name: "Thanh Tẩy Độc Tố", desc: "[Cơ chế] Ép mọc ra một loại nấm/thảo dược kháng nguyên đặc hiệu từ lòng bàn tay. [Hiệu ứng] Vắt nước thảo dược cho đồng đội uống hoặc đắp lên vết thương. Giải trừ 99% các loại độc tố, nọc rắn, nọc nhện cấp độ Ngân Giai trở xuống ngay lập tức.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Trị Liệu"], range_type: "Cận chiến (Hỗ trợ)", combo_tag: "Detox_Herb" },
        { name: "Bom Bào Tử", desc: "[Cơ chế] Nén bào tử nấm độc vào quả mọng rồi ném đi. [Hiệu ứng] Nổ tung tạo đám mây bào tử bán kính 5m. Kẻ địch hít phải sẽ bị mù lòa, nổi mẩn ngứa gãi rách da thịt, và ho sặc sụa (Interrupt kỹ năng niệm chú).", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Độc"], range_type: "Tầm Xa (AoE Nhỏ)", combo_tag: "Spore_Bomb" },
        { name: "Khởi Nguyên Thế Giới Thụ (Yggdrasil)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Hiến tế sinh mệnh lực kích hoạt Hạt giống cội nguồn, cưỡng ép ghi đè quy luật sinh thái lên thực tại. [Hiệu ứng] Mọc ra một Cây Thế Giới khổng lồ (Cao 10,000m) bao trùm cả một Vùng Lãnh Thổ. Rễ cây cắm thẳng vào tâm lõi hành tinh hút sạch dung nham. Tán lá thanh tẩy mọi ô nhiễm, phóng xạ (Corruption = 0) vĩnh viễn, đè bẹp và tiêu hóa mọi đội quân/dị thú phe địch trong cự ly 100km làm phân bón. Tạo ra một 'Thánh Địa' mới bất khả xâm phạm. [Tác dụng phụ cực lớn] Rút cạn Max HP của người dùng còn đúng 1 giọt máu. Xóa bỏ vĩnh viễn toàn bộ kỹ năng của người dùng (Trở thành phế nhân cấp Phàm không thể tu luyện lại). Gắn chặt linh hồn người dùng vào gốc cây không thể rời đi bán kính 1km cho đến hết đời.", rank: "Thánh Giai", cost: { type: "HP", value: 9999999 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 300, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Sinh Mệnh", "Không Gian"], range_type: "Cấp Thế Giới (Tái tạo thực tại)", combo_tag: "Holy_World_Tree" },
        { name: "Ngụy Trang Rừng Rậm", desc: "[Cơ chế] Da và quần áo biến đổi sắc tố và cấu trúc như Tắc kè hoa hệ mộc. [Hiệu ứng] Đứng áp lưng vào cây/Bụi rậm, cơ thể hoàn toàn đồng hóa vào kết cấu gỗ lá. Tàng hình 100%, xóa mùi cơ thể. Chỉ bị lộ nếu bị tấn công hệ Hỏa hoặc di chuyển nhanh.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Ảo Giác"], range_type: "Bản thân (Tàng hình)", combo_tag: "Camouflage" },
        { name: "Nhựa Dính Siêu Cấp", desc: "[Cơ chế] Tiết nhựa thông cô đặc cực nhanh. [Hiệu ứng] Phóng cục nhựa dẻo. Dán chặt hai chân địch xuống đất (Không thể nhảy/di chuyển), bịt kín mắt (Mù), hoặc bắn trúng nòng súng khiến súng tắc nghẽn nổ tung khi bắn.", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Tầm Trung (Đơn mục tiêu)", combo_tag: "Resin_Glue" },
        { name: "Trái Cây Hồi Sức (Sinh hoạt)", desc: "[Cơ chế] Ép ma lực tụ lại thành đường fructose sinh học và vitamin. [Hiệu ứng] Mọc ra quả táo/đào phát sáng. Ăn vào lập tức no bụng (Xóa trạng thái Hunger), hồi phục 30% Thể lực và 10% MP. Cứu đói hoàn hảo cho tổ đội đi lạc.", rank: "Phàm Giai", cost: { type: "MP", value: 80 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Tiện ích (Tiếp tế)", combo_tag: "Utility_Food" },
        { name: "Cầu Thang Dây Leo", desc: "[Cơ chế] Thúc hạt giống mọc leo theo hướng chỉ định. [Hiệu ứng] Tạo thang dây cực kỳ dẻo dai thả từ vách đá xuống, hoặc vươn qua miệng vực để cả đội bám sang. Chịu lực được 5 tấn mà không đứt.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Tiện ích (Di chuyển)", combo_tag: "Vine_Ladder" },
        { name: "Nhà Cây Trú Ẩn", desc: "[Cơ chế] Kích thích cây cổ thụ giãn nở thớ gỗ tạo hang rỗng. [Hiệu ứng] Biến một cây cổ thụ to thành ngôi nhà ấm áp bên trong thân cây, cửa tự khép kín không để lộ khe hở. An toàn tuyệt đối khỏi bão tuyết và ánh mắt của quái thú.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Tiện ích (Trú ẩn)", combo_tag: "Tree_House" },
        { name: "Giáp Vỏ Cây", desc: "[Cơ chế] Lớp biểu bì sừng hóa thành vỏ cây Sồi ngàn năm. [Hiệu ứng] Phủ lớp vỏ gỗ cứng cáp lên da. Tăng 150% DEF vật lý, chặn đạn súng lục. [Nhược điểm] Làm bản thân dễ bắt lửa, dính sát thương Hỏa sẽ bị cháy lan khó dập.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Bản thân (Buff phòng ngự)", combo_tag: "Bark_Armor" },
        { name: "Cảm Nhận Thực Vật (Radar)", desc: "[Cơ chế] Kết nối ý thức với mạng lưới rễ cây chằng chịt dưới đất (Mycorrhizal network). [Hiệu ứng] Hỏi cây cối xung quanh để xem lại 'băng ghi hình' ký ức của chúng. Biết chính xác diện mạo kẻ thù, đi hướng nào, cách đây bao lâu trong bán kính 2km.", rank: "Ngân Giai", cost: { type: "MP", value: 2000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Tinh Thần"], range_type: "AoE Rộng (Tình báo)", combo_tag: "Nature_Radar" },
        { name: "Tái Tạo Chi", desc: "[Cơ chế] Phân bào tế bào gốc thực vật thay thế tế bào động vật. [Hiệu ứng] Đắp một khúc gỗ lên vết thương cụt tay/chân. Trong 10 phút, gỗ sẽ mọc rễ hòa làm một với mạch máu, tái tạo thành cánh tay/chân giả bằng gỗ linh hoạt như chi thật.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 600, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Trị Liệu"], range_type: "Cận chiến (Hồi phục bộ phận)", combo_tag: "Limb_Regrow" },
        { name: "Cỏ Mềm Giảm Chấn", desc: "[Cơ chế] Trồng thảm rêu/cỏ siêu đàn hồi mặt đất cực nhanh. [Hiệu ứng] Rải bãi cỏ dày 1m ngay dưới vị trí rơi. Hấp thụ hoàn toàn động năng, cứu mạng Tamer/Đồng đội khi bị hất văng từ trên vách núi/trực thăng rơi xuống đất.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Tầm Xa (Bảo vệ rơi)", combo_tag: "Cushion_Grass" },
        { name: "Hương Hoa Mê Hoặc", desc: "[Cơ chế] Nở hoa huệ độc trên vai, tỏa hương pheromone. [Hiệu ứng] Hương thơm gây ảo giác êm dịu. Kẻ thù hít phải sẽ mất hết chiến ý, vũ khí rớt khỏi tay, đứng đờ đẫn mỉm cười như đang trong mơ. Khống chế đám đông tuyệt vời.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Ảo Giác"], range_type: "AoE Trung", combo_tag: "Charm_Scent" },
        { name: "Mộc Nhân Thế Mạng", desc: "[Cơ chế] Tráo đổi vị trí lượng tử với một khúc gỗ định sẵn ma lực. [Hiệu ứng] Khi bị trúng đòn chí mạng, bản thể hóa thành sương khói và bị chém đứt là một khúc gỗ. Tamer dịch chuyển ra xa 10m an toàn hoàn toàn không mất máu.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Không Gian"], range_type: "Bản thân (Né tránh tuyệt đối)", combo_tag: "Wood_Substitution" },
        { name: "Cầu Treo Tự Nhiên", desc: "[Cơ chế] Ra lệnh cho các tán cây giao nhau tết lại thành đường đi. [Hiệu ứng] Tạo đường đi bộ trên không bám vào các vòm cây cổ thụ. Di chuyển nhanh chóng trong rừng, hoàn toàn tránh được thú săn mồi, bãi mìn hoặc đầm lầy độc bên dưới mặt đất.", rank: "Phàm Giai", cost: { type: "MP", value: 80 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Tiện ích (Xây dựng)", combo_tag: "Canopy_Bridge" },
        { name: "Phân Bón Xác Chết", desc: "[Cơ chế] Rễ cây tiết enzyme phân hủy xác thịt cấp tốc. [Hiệu ứng] Ghim rễ vào xác chết địch (Người/Thú). Hút sạch dinh dưỡng chỉ chừa lại xương khô trong 5 giây. Hồi 50% MP và 20% HP. Dùng dọn xác, phi tang chứng cứ cực sạch.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Hắc Ám"], range_type: "Cận chiến (Hồi phục/Tế bần)", combo_tag: "Corpse_Fertilizer" },
        { name: "Gậy Gộc Vũ Khí", desc: "[Cơ chế] Ép súc linh mộc mọc thành hình dạng vũ khí. [Hiệu ứng] Tạo gậy, thương, cung tên bằng gỗ Thiết Sam (cứng hơn sắt) có sẵn tính đàn hồi cực cao. Vũ khí tuy nhẹ nhưng có sát thương vật lý đáng nể cho Tamer.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Bản thân (Vũ khí)", combo_tag: "Wood_Weapon" },
        { name: "Lọc Không Khí", desc: "[Cơ chế] Tăng cường lỗ khí khổng của thực vật hút khí độc. [Hiệu ứng] Trồng chậu cây ma thuật giữa hầm/phòng kín. Hấp thụ toàn bộ khí gas độc, khói mù mịt, nhả ra lượng lớn Oxy tinh khiết. Cứu team khỏi chết ngạt.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "AoE Nhỏ (Tiện ích)", combo_tag: "Air_Filter" },
        { name: "Nấm Phát Sáng", desc: "[Cơ chế] Cấy gen phát quang sinh học (Bioluminescence) vào nấm. [Hiệu ứng] Rải nấm dạ quang xanh/đỏ dọc đường đi. Đánh dấu lối về trong sương mù Vùng Zero, hoặc dùng làm đèn chiếu sáng không hắt nhiệt (để né quái vật cảm biến nhiệt).", rank: "Phàm Giai", cost: { type: "MP", value: 10 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Tiện ích (Đánh dấu)", combo_tag: "Glow_Mushroom" },
        { name: "Gỗ Mục Đánh Lừa", desc: "[Cơ chế] Giảm nhịp tim về 0, lớp da bong tróc sần sùi. [Hiệu ứng] Nằm gục xuống giả chết, thân thể nguội ngắt giống hệt một khúc gỗ mục rữa. Đánh lừa được hầu hết Dị thú săn mồi dùng khứu giác hoặc thính giác.", rank: "Thiết Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Bản thân (Giả chết)", combo_tag: "Play_Dead_Wood" },
        { name: "Kích Thích Sinh Trưởng", desc: "[Cơ chế] Bơm hoocmon Auxin ma thuật vào thực vật. [Hiệu ứng] Làm một hạt giống cỏn con lớn bùng lên thành cây cao 20m chỉ trong 2 giây. Che chắn hỏa lực địch, hoặc dùng thân cây bật tung hất văng xe cộ đang đỗ phía trên.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Tầm Trung (Biến đổi địa hình)", combo_tag: "Growth_Surge" },
        { name: "Cửu U Ma Thụ (Rễ Cây Địa Ngục - Bản tối thượng)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Hiến tế máu tươi đánh thức loài cây quỷ dữ thời Thượng Cổ ngủ sâu trong Vùng Zero. [Hiệu ứng] Đất đai nứt toác bán kính 1km. Hàng vạn xúc tu rễ cây đẫm máu trồi lên như rắn khổng lồ. Cuốn chặt, xé xác và nuốt chửng hàng vạn binh lính/quái vật phe địch kéo xuống cửu tuyền. Hồi máu tràn trề cho người dùng. [Tác dụng phụ] Cây quỷ có ý thức phản phệ. Sau khi giết hết địch, nếu người dùng có Sanity < 80, Ma Thụ sẽ quay sang ăn thịt luôn cả đồng đội và người tung chiêu. Trừ 30% Max HP vĩnh viễn.", rank: "Diệu Giai", cost: { type: "HP", value: 50000 }, cooldown: { value: 90, unit: "Ngày", display_text: "3 Tháng" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Hắc Ám"], range_type: "AoE Rất Rộng (Cấp Thảm Họa)", combo_tag: "Divine_Hell_Roots" },
        { name: "Hóa Hình - Rụng Lá Vi Nhai (Dị Thú)", desc: "[Cơ chế] Phân rã cấu trúc liên kết tế bào thành hàng triệu mảnh lá. [Hiệu ứng] Khi bị vây khốn, cơ thể dị thú tan biến thành một cơn lốc lá rụng bay tứ tung (Miễn nhiễm sát thương). Sau đó các chiếc lá cuốn vào nhau ở khoảng cách xa tái tạo lại hình dáng con người/hoặc hình cũ. Tốc độ tẩu thoát tuyệt đỉnh.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 38000 }, cooldown: { value: 3, unit: "Ngày", display_text: "3 Ngày" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Không Gian"], range_type: "Bản thân (Chạy trốn/Ngụy trang)", combo_tag: "Leaf_Swarm_Form" },
        { name: "Trị Liệu Ba Động (Dị Thú)", desc: "[Cơ chế] Rống lên âm thanh vang dội xen lẫn Mộc ma lực. [Hiệu ứng] Phát sóng sinh mệnh màu xanh lục gợn sóng bán kính 30m. Hồi 15% HP ngay lập tức và tăng 50% tốc độ di chuyển cho toàn bộ bầy đàn/đồng minh trong 3 giờ.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Sóng Âm"], range_type: "AoE Rộng (Buff bầy đàn)", combo_tag: "Beast_Roar_Heal" },
        { name: "Đằng Tiên Mộc Trói", desc: "[Cơ chế] Đuôi/Sừng biến thành bó dây leo thép. [Hiệu ứng] Phóng ra dây leo đầy gai độc quất mạnh vào địch (Sát thương vật lý cao). Trói chặt, nhấc bổng mục tiêu lên không, gai đâm ngập da hút máu truyền về cho Thú.", rank: "Thiết Giai", cost: { type: "Stamina", value: 300 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Tầm Trung (Bắt cóc)", combo_tag: "Whip_Bind" },
        { name: "Hạt Giống Ký Sinh (Bom Huyết)", desc: "[Cơ chế] Khạc hạt giống từ miệng xuyên thủng da thịt. [Hiệu ứng] Hạt giống cắm vào bụng địch. Nó không hút MP mà hút cạn máu địch cực nhanh để phình to. Sau 3 phút, nó nổ tung từ bên trong xé nát cơ thể nạn nhân (Sát thương chuẩn tàn nhẫn).", rank: "Kim Giai", cost: { type: "MP", value: 75000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Ký Sinh"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Blood_Seed_Bomb" },
        { name: "Quang Hợp (Dị Thú Tăng Cường)", desc: "[Cơ chế] Lớp vảy mở ra hứng trọn quang năng. [Hiệu ứng] Ngủ dưới nắng. Hồi phục 50% HP, Stamina, MP mỗi giờ. Xóa bỏ mọi vết sẹo, tái tạo móng vuốt bị gãy rụng và giải mọi độc tố tích tụ.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Bản thân (Ngủ hồi phục)", combo_tag: "Beast_Sun_Bath" },
        { name: "Lá Sắc Như Dao", desc: "[Cơ chế] Rũ mạnh lông bờm/cánh làm bằng lá. [Hiệu ứng] Bắn hàng ngàn chiếc lá gia cố mộc năng tản mác như súng hoa cải. Xé nát đội hình lính bộ binh giáp nhẹ. Phạm vi phủ sóng rộng khó né tránh.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Hình Nón Rộng", combo_tag: "Leaf_Storm" },
        { name: "Bức Tường Gai Tường Vi", desc: "[Cơ chế] Nhổ nước bọt chứa hạt giống xuống đất rống gọi. [Hiệu ứng] Tạo bức tường gai (Hoa hồng đen) cao 5m, dày đặc. Ngăn cản vật lý và ma pháp. Kẻ địch lao vào hoặc chém vỡ tường sẽ bị gai độc bắn ngược lại làm tê liệt dây thần kinh.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Độc"], range_type: "Tường chắn (Phòng thủ/Phản công)", combo_tag: "Rose_Thorn_Wall" },
        { name: "Mộc Linh Trận Pháp", desc: "[Cơ chế] Cắm 4 móng vuốt xuống 4 góc, truyền linh mộc tạo kết giới. [Hiệu ứng] Cây cối lớn nhanh bọc thành lồng. Bên trong trận pháp, Dị thú tăng 100% tốc độ hồi phục, skill Hệ Mộc không tốn Cost. Kẻ địch bước vào bị giảm 50% AGI và liên tục trúng độc.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Lĩnh Vực"], range_type: "AoE Rộng (Kết giới)", combo_tag: "Wood_Domain" },
        { name: "Hơi Thở Rừng Thẳm", desc: "[Cơ chế] Phun sương mù xanh nhạt mang tính kiềm ma thuật. [Hiệu ứng] Rửa trôi mọi trạng thái bất lợi (Debuff, Bỏng, Rỉ máu, Độc, Sợ hãi) cho Tamer (Ký chủ) và đồng đội. Kỹ năng hỗ trợ giải khống chế cực mạnh cho team.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Hình Nón (AoE Hỗ trợ)", combo_tag: "Forest_Cleanse" },
        { name: "Quả Cầu Nổ Bào Tử", desc: "[Cơ chế] Khạc từ miệng quả mọng căng phồng khí nén. [Hiệu ứng] Ném quả bóng nổ như pháo cối. Va chạm gây sát thương nổ vật lý, đồng thời giải phóng bào tử gây choáng váng (Stun) 2s cho mọi kẻ địch trúng vụn vỡ.", rank: "Thiết Giai", cost: { type: "Stamina", value: 280 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Tầm Xa (Đạn nổ)", combo_tag: "Spore_Mortar" },
        { name: "Rễ Cây Khổng Lồ", desc: "[Cơ chế] Giậm chân, truyền ý chí đánh thức linh mộc dưới sâu. [Hiệu ứng] Triệu hồi rễ cây cổ thụ to bằng thân người trồi lên quật mạnh như roi da. Đập nát xe bọc thép, phá vỡ đội hình khiên giáo. Có thể dùng để quét ngã hàng chục mục tiêu.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "AoE Trung (Hất văng)", combo_tag: "Giant_Root_Smash" },
        { name: "Ngụy Trang Rừng Rậm (Thú Săn Mồi)", desc: "[Cơ chế] Bản năng dung nhập hoàn toàn, vảy lông tự đổi màu diệp lục. [Hiệu ứng] Ngồi im trong bụi cây/rừng rậm tàng hình tuyệt đối 100%. Ánh mắt không phát ra tia sáng mồi. Đòn tấn công đầu tiên từ trạng thái tàng hình này được +200% Sát thương Crit.", rank: "Ngân Giai", cost: { type: "Stamina", value: 150 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Bản thân (Tàng hình sát thủ)", combo_tag: "Predator_Stealth" },
        { name: "Nhựa Cây Bám Dính (Khóa mõm)", desc: "[Cơ chế] Khạc cục đờm nhựa thông đặc quánh. [Hiệu ứng] Bắn trúng đầu dị thú khác để dính chặt hai hàm chúng lại (Khóa mõm - Câm lặng không thể khạc lửa/phun độc), hoặc dán chặt kiếm/khiên địch vào thân cây.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc"], range_type: "Tầm Trung (Đơn mục tiêu)", combo_tag: "Muzzle_Glue" },
        { name: "Cây Ăn Thịt Hiện Hình", desc: "[Cơ chế] Cấy gen hoa ăn thịt (Venus flytrap) khổng lồ vào đất. [Hiệu ứng] Biến mặt đất dưới chân địch thành cái miệng khổng lồ đầy răng nhọn. Ngoạm chặt lấy kẻ địch lơ đễnh, nhai nát áo giáp và nhỏ axit tiêu hóa (Trừ máu liên tục).", rank: "Kim Giai", cost: { type: "MP", value: 95000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Đặt Bẫy (Tầm Trung)", combo_tag: "Flytrap_Ambush" },
        { name: "Lá Giáp Hộ Thể", desc: "[Cơ chế] Nam châm sinh học hút lá rụng xung quanh bọc lấy người. [Hiệu ứng] Xếp hàng ngàn chiếc lá gia cố ma lực thành vảy giáp. Cực kỳ nhẹ không làm chậm tốc độ, chống đâm xuyên (Xuyên giáp của hệ Kim/Băng) vô cùng hiệu quả.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc"], range_type: "Bản thân (Buff linh hoạt)", combo_tag: "Leaf_Scale_Armor" },
        { name: "Mạng Lưới Sinh Mệnh Tinh Cầu (Liên kết vạn vật)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Chuyển đổi linh hồn thành giao thức Mạng Lưới Rễ Tinh Cầu. [Hiệu ứng] Buff bất tử AoE vô tiền khoáng hậu. Liên kết sinh mệnh của Tamer, Sủng thú, và toàn bộ đồng đội với toàn bộ cây cối trong bán kính 10km. Chừng nào rừng chưa bị chặt hết, phe ta KHÔNG THỂ chết (Máu về 1 tự động hút HP rừng bù vào). [Tác dụng phụ] Khi kết thúc chiêu, người tung chiêu sẽ gánh toàn bộ 'Cộng Hưởng Nỗi Đau' của khu rừng tàn lụi. Trừ thẳng 80 điểm Sanity (Gây điên loạn) và giảm 50% chỉ số CON vĩnh viễn.", rank: "Diệu Giai", cost: { type: "Soul_Force", value: 70 }, cooldown: { value: 180, unit: "Ngày", display_text: "Nửa Năm" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Sinh Mệnh", "Lĩnh Vực"], range_type: "AoE Rất Rộng (Bất tử cục bộ)", combo_tag: "Divine_Life_Link" },
        { name: "Giao Tiếp Thảo Mộc", desc: "[Cơ chế] Bản năng Thú rừng gầm gừ nhẹ giao thoa sóng âm diệp lục. [Hiệu ứng] Nghe cây cỏ 'kể chuyện'. Trinh sát vô hình. Biết được chính xác số lượng lính, loại vũ khí và hướng chạy trốn của kẻ thù trong rừng rậm.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Tinh Thần"], range_type: "Bản thân (Tình báo)", combo_tag: "Plant_Whisper" },
        { name: "Hồi Sinh Nhánh Cây", desc: "[Cơ chế] Cắt đứt cảm giác đau, vùi gốc chi đứt xuống đất sét/đất mùn. [Hiệu ứng] Nếu bị chém đứt chân/đuôi/cánh, Thú trồng rễ xuống đất. Tái tạo lại hoàn toàn bộ phận sinh học thực sự (Không phải chi giả) trong 1 ngày ngủ vùi. Tuyệt đỉnh sinh tồn.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 100000 }, cooldown: { value: 30, unit: "Ngày", display_text: "1 Tháng" }, cast_time: { value: 86400, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Sinh Mệnh"], range_type: "Bản thân (Hồi sinh chi)", combo_tag: "True_Limb_Regrow" },
        { name: "Thảm Thực Vật Độc", desc: "[Cơ chế] Dịch dạ dày biến đổi tính chất thảm cỏ. [Hiệu ứng] Đi qua đâu, cỏ chỗ đó hóa tím đen. Tiết ra khí độc (Miang) gây chóng mặt, buồn nôn, trừ HP liên tục với kẻ địch đuổi theo. Đồng minh và bản thân đi vào không bị ảnh hưởng.", rank: "Ngân Giai", cost: { type: "Stamina", value: 1500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Độc"], range_type: "Đường đi (Để lại dấu vết độc)", combo_tag: "Toxic_Trail" },
        { name: "Gỗ Cứng Tác Chiến", desc: "[Cơ chế] Sừng hóa sinh học lớp da tay/cánh thành gỗ lim nguyên khối. [Hiệu ứng] Cứng hóa cánh tay thành chùy gỗ. Dùng để đập nát khiên kẻ địch, đập vỡ khiên ma pháp hoặc chống đỡ đòn gươm giáo chém thẳng vào tay mà không đứt thịt.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Vật Lý"], range_type: "Cận chiến (Buff sát thương/Đỡ đòn)", combo_tag: "Ironwood_Strike" },
        { name: "Sinh Mệnh Bất Diệt (Bị động)", desc: "[Cơ chế] Gen đột biến của Dị thú thực vật. Cây cối khi bị phạt ngang luôn mọc chồi mới mãnh liệt hơn. [Hiệu ứng] Nội tại chí tôn của dòng Tanker. Máu (HP) càng xuống thấp, tốc độ hồi phục HP tự nhiên và Chỉ số Phòng thủ (DEF) nhân lên càng cao (Tối đa x5 ở mức 10% HP).", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Sinh Mệnh"], range_type: "Bản thân (Nội tại sinh tồn)", combo_tag: "Undying_Will" }
    ],
"Hệ Kim Loại": [
        { name: "Hóa Hình - Kim Thân", desc: "[Cơ Chế Sinh Học] Hấp thụ phân tử kim loại mạ lên khung xương và khớp. Tế bào máu bọc sắt từ. Vận hành như cỗ máy sinh học. [Cấu Tạo] Tim bơm thủy lực, dạ dày là lò nung axit, mắt thấu kính đa phổ. [Hình Thái] Da lạnh lẽo ánh kim, móng sắc. Dạng người xương không gãy, tay không đỡ đạn. [Tác dụng phụ] Trọng lượng cơ thể tăng gấp 3, mất khả năng nổi trên nước (chìm như tảng đá). Rất dễ bị sét đánh (Hệ Lôi).", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Metal" },
        { name: "Da Thép Xước", desc: "[Cơ chế] Tế bào biểu bì liên kết với hạt kim loại siêu nhỏ. [Hiệu ứng] Kháng hoàn toàn các đòn tấn công gây xước xát, cào cấu của thú hoang cấp thấp. Miễn nhiễm với trạng thái [Chảy máu ngoài da].", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Bị động phòng thủ)", combo_tag: "Passive_Steel_Skin" },
        { name: "Lõi Từ Tính Trái Dấu", desc: "[Cơ chế] Cơ thể tỏa ra từ trường đẩy lùi kim loại. [Hiệu ứng] Mọi mũi tên, phi tiêu có đầu bịt sắt bắn về phía bạn sẽ bị lệch quỹ đạo bay khoảng 10 độ, giảm 20% Tỉ lệ trúng đích (Accuracy) của cung thủ địch.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Từ Trường"], range_type: "Bản thân (Bị động né đạn)", combo_tag: "Passive_Magnetic_Repel" },
        { name: "Phản Chấn Kim Khí", desc: "[Cơ chế] Mật độ cơ bắp rắn chắc như thép khối. [Hiệu ứng] Kẻ thù dùng đòn đánh tay không (đấm/đá) vào người bạn sẽ bị dội ngược lực lại, tự gãy xương tay/chân và nhận 10% sát thương phản đòn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận chiến (Bị động phản đòn)", combo_tag: "Passive_Metal_Rebound" },
        { name: "Trọng Lượng Đầm (Bất Khả Xâm Phạm)", desc: "[Cơ chế] Chân truyền ma lực kim loại xuống đất tạo điểm neo vững chắc. [Hiệu ứng] Tăng mạnh trọng lượng cơ thể khi bị tấn công. Giảm 50% khoảng cách bị đẩy lùi (Knockback) bởi các chiêu thức húc/đẩy.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Bị động kháng đẩy)", combo_tag: "Passive_Heavy_Weight" },
        { name: "Lưỡi Cắt Tự Nhiên", desc: "[Cơ chế] Sừng, móng và gờ xương sắc như dao cạo. [Hiệu ứng] Đòn đánh thường (Basic Attack) có tỉ lệ 15% gọt đi một mảnh giáp của địch, làm giảm vĩnh viễn 2% DEF của chúng trong suốt trận chiến.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Đòn đánh (Bị động bào mòn)", combo_tag: "Passive_Natural_Blade" },
        { name: "Hấp Thụ Ma Sát Sắt", desc: "[Cơ chế] Chuyển hóa tia lửa ma sát thành năng lượng. [Hiệu ứng] Khi dùng vũ khí kim loại chặn đòn (Parry) thành công đao kiếm của địch, tự động hồi phục 2% MP từ tia lửa điện sinh ra.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Hỏa"], range_type: "Đỡ đòn (Bị động hồi Mana)", combo_tag: "Passive_Spark_Absorb" },
        { name: "Khung Xương Titan", desc: "[Cơ chế] Tủy xương bao bọc bởi lớp titan sinh học cực cứng. [Hiệu ứng] Miễn nhiễm 100% với các trạng thái Gãy Xương, Nát Cốt. Sức chịu tải của cơ thể tăng gấp đôi, có thể vác vũ khí hạng nặng mà không bị giảm AGI.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Bị động kháng thương tật)", combo_tag: "Passive_Titan_Skeleton" },
        { name: "Kháng Xuyên Thấu Cơ Khí", desc: "[Cơ chế] Màng cơ đan chéo như lớp lưới Kevlar chống đạn. [Hiệu ứng] Giảm thiểu 30% sát thương từ các loại đạn súng trường, đạn súng máy và vũ khí ám khí có thuộc tính Xuyên Thấu.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Bị động chống đạn)", combo_tag: "Passive_Kevlar_Tissue" },
        { name: "Mũi Nhọn Áp Lực", desc: "[Cơ chế] Tập trung khối lượng vào một điểm đâm duy nhất. [Hiệu ứng] Khi dùng thương hoặc vũ khí có mũi đâm, sát thương sẽ tự động tăng thêm 20% nếu kẻ địch đang mặc Giáp Hạng Nặng (Heavy Armor).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Vũ khí đâm (Bị động xuyên giáp nặng)", combo_tag: "Passive_Pressure_Point" },
        { name: "Giáp Gỉ Sét Bị Động", desc: "[Cơ chế] Tuyết mồ hôi mang tính kiềm ăn mòn nhẹ. [Hiệu ứng] Những kẻ địch khóa siết (Grapple) bạn hoặc áp sát quá lâu sẽ bị ăn mòn vũ khí/giáp, giảm 5 độ bền (Durability) mỗi giây tiếp xúc.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Nước"], range_type: "Cận chiến (Bị động phá trang bị)", combo_tag: "Passive_Rust_Aura" },
        { name: "Bước Chân Từ Trường", desc: "[Cơ chế] Tạo lực hút nhẹ với quặng sắt dưới lòng đất. [Hiệu ứng] Chân bám dính cực chắc trên mặt đất. Không bao giờ bị trượt ngã trên băng, bùn lầy hay các bề mặt ma sát thấp.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Từ Trường"], range_type: "Bản thân (Bị động kháng trượt)", combo_tag: "Passive_Magnetic_Grip" },
        { name: "Dẫn Điện Lõi Đất", desc: "[Cơ chế] Cơ thể như một cột thu lôi truyền thẳng dòng điện xuống rễ. [Hiệu ứng] Kháng hoàn toàn (100%) hiệu ứng Tê Liệt (Paralyze) từ các đòn đánh Hệ Lôi cấp thấp. Sát thương Lôi nhận vào bị giảm 40%.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Thổ"], range_type: "Bản thân (Bị động kháng Lôi)", combo_tag: "Passive_Grounding_Wire" },
        { name: "Huyết Cầu Lọc Độc", desc: "[Cơ chế] Máu chứa hàm lượng sắt cao tự động kết tủa khi gặp chất độc. [Hiệu ứng] Giảm 50% tốc độ trừ máu của mọi loại Độc tố/Ký sinh trùng xâm nhập vào đường máu. Kéo dài thời gian sống sót để tìm thuốc giải.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Sinh Mệnh"], range_type: "Bản thân (Bị động kháng độc)", combo_tag: "Passive_Iron_Blood" },
        { name: "Đồng Hóa Binh Khí", desc: "[Cơ chế] Bàn tay chảy ra chất kim loại lỏng hòa làm một với chuôi kiếm. [Hiệu ứng] Vũ khí kim loại đang cầm trên tay không bao giờ bị đánh rơi (Disarm). Sát thương vũ khí tăng 10% do truyền trực tiếp ma lực không qua trung gian.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Vũ khí (Bị động cường hóa)", combo_tag: "Passive_Weapon_Merge" },
        { name: "Móng Vuốt Xé Giáp", desc: "[Cơ chế] Móng vuốt bọc hợp kim Wolfram ma sát cao. [Hiệu ứng] Mỗi cú cào/đánh trúng một mục tiêu sẽ dán lên chúng 1 điểm cộng dồn [Xé Giáp]. Mỗi điểm làm giảm 5% DEF, tối đa 5 điểm (Giảm 25%).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Đòn đánh (Bị động cộng dồn)", combo_tag: "Passive_Shred_Armor" },
        { name: "Nặng Tựa Thái Sơn", desc: "[Cơ chế] Mật độ vật chất tăng cao khi rơi tự do. [Hiệu ứng] Sát thương từ các đòn nhảy đập từ trên cao xuống (Plunge Attack) được nhân đôi (x2). Gây chấn động nhỏ làm chậm địch xung quanh 1s.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Thổ"], range_type: "Tấn công từ trên cao (Bị động)", combo_tag: "Passive_Meteor_Slam" },
        { name: "Từ Trường Hút Đạn (Hộ Vệ)", desc: "[Cơ chế] Phát ra từ trường nam châm diện hẹp hút các vật thể bay nhẹ. [Hiệu ứng] Nội tại Tanker. Bất kỳ mũi tên hay đạn bay sượt qua đồng đội trong bán kính 2m sẽ bị bẻ cong quỹ đạo, bay thẳng vào bạn để bạn đỡ thay.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Từ Trường"], range_type: "AoE Nhỏ (Bị động bảo vệ đồng minh)", combo_tag: "Passive_Bullet_Magnet" },
        { name: "Khóa Khớp Cơ Học", desc: "[Cơ chế] Khớp xương hãm khóa vật lý khi vung đòn tới hạn. [Hiệu ứng] Tuyệt đối không bị trật khớp hay rách cơ khi tung các đòn đánh dùng lực cực đại. Xóa bỏ hoàn toàn sát thương phản lực khi chém trúng vật cứng hơn vũ khí.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Bị động ổn định)", combo_tag: "Passive_Joint_Lock" },
        { name: "Bề Mặt Trơn Trượt", desc: "[Cơ chế] Da bọc lớp hợp kim đánh bóng loáng. [Hiệu ứng] Các đòn đánh từ quái vật có xúc tu, giác hút (Hệ Thủy/Độc) sẽ bị trượt khỏi cơ thể. Dễ dàng luồn lách thoát khỏi vòng vây chật hẹp.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Bị động né khống chế)", combo_tag: "Passive_Slick_Metal" },
        { name: "Phản Quang Lõi Thép", desc: "[Cơ chế] Lớp giáp ngực đánh bóng phản xạ hạt Photon. [Hiệu ứng] Giảm 40% sát thương từ các kỹ năng Hệ Quang/Laser chiếu trực diện. Tự động phản chiếu tia sáng gây chói mắt ngược lại kẻ bắn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Quang"], range_type: "Bản thân (Bị động kháng Quang)", combo_tag: "Passive_Mirror_Deflect" },
        { name: "Đạn Mạt Sắt", desc: "[Cơ chế] Hút vụn sắt từ đất đá và bắn ra bằng áp lực từ trường nhỏ. [Hiệu ứng] Bắn đám mạt sắt như đạn hoa cải. Tầm bắn ngắn nhưng xé rách da và găm mảnh vụn kim loại vào cơ bắp, khiến địch cử động sẽ đau đớn tột độ.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Hình Nón Cận Chiến", combo_tag: "Iron_Dust_Shot" },
        { name: "Dao Găm Thép", desc: "[Cơ chế] Ngưng tụ nguyên tố kim loại thành phi tiêu/dao găm sắc bén. [Hiệu ứng] Ném dao găm với quỹ đạo thẳng tắp, xuyên qua áo giáp da. Vũ khí này sau khi đâm trúng có thể hòa tan thu hồi lại làm MP.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 4, unit: "Giây", display_text: "4 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Tầm Xa (Xuyên thấu nhẹ)", combo_tag: "Steel_Dagger" },
        { name: "Mạ Kim Cục Bộ", desc: "[Cơ chế] Cứng hóa biểu bì tay hoặc chân thành hợp kim Titan trong 2s. [Hiệu ứng] Đỡ tay không vào thanh kiếm đang chém tới mà không sứt mẻ, hoặc tạo ra cú đấm nặng ngàn cân gõ vỡ sọ đối phương.", rank: "Thiết Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Phòng ngự phản công)", combo_tag: "Metal_Plating" },
        { name: "Răng Cưa Nhỏ", desc: "[Cơ chế] Mọc một đĩa cưa nhỏ xoay tít ở mu bàn tay. [Hiệu ứng] Tấn công cận chiến xẻ thịt. Cưa đứt dây leo trói buộc (Hệ Mộc), phá khiên gỗ, để lại vết chém cưa răng cưa không thể tự cầm máu.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Phá giáp mềm)", combo_tag: "Mini_Saw" },
        { name: "Trảo Thép Trắng", desc: "[Cơ chế] Bao bọc 5 ngón tay bằng sắt thép siêu cứng (Vuốt Wolverine). [Hiệu ứng] Chém đứt kim loại thường, cào thủng vỏ xe bọc thép mỏng. Cận chiến cực kỳ đẫm máu mang thuộc tính Xuyên Giáp.", rank: "Thiết Giai", cost: { type: "Stamina", value: 35 }, cooldown: { value: 6, unit: "Giây", display_text: "6 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Xuyên giáp)", combo_tag: "Steel_Claws" },
        { name: "Lá Chắn Sắt Nếp Gấp", desc: "[Cơ chế] Rút sắt từ đất lên tạo thành tấm khiên xếp lớp trước mặt. [Hiệu ứng] Chặn hoàn toàn hỏa lực súng bộ binh, tên bắn. Khiên rất nặng, làm giảm Tốc chạy của người dùng đi 50% trong lúc duy trì.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Tường Chắn (Phòng ngự trước)", combo_tag: "Folded_Iron_Shield" },
        { name: "Đinh Tán Xuyên Chân", desc: "[Cơ chế] Cấy đinh sắt tàng hình mọc ngược từ dưới đất lên. [Hiệu ứng] Kẻ địch dẫm phải sẽ bị thủng bàn chân, đinh xòe ra như ngạnh mũi tên không thể rút (Trừ máu khi di chuyển). Làm chậm 40% AGI.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Đặt Bẫy Cục Bộ", combo_tag: "Iron_Caltrop" },
        { name: "Nam Châm Hút Nhẹ", desc: "[Cơ chế] Phát từ trường âm hút kim loại từ tay phải. [Hiệu ứng] Giật phăng vũ khí nhỏ (dao găm, súng lục) của kẻ địch văng khỏi tay chúng. Vô hiệu hóa khả năng tấn công tầm xa của bọn yếu.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Từ Trường"], range_type: "Tầm Trung (Tước vũ khí)", combo_tag: "Magnet_Pull_Mini" },
        { name: "Nam Châm Đẩy Lùi", desc: "[Cơ chế] Phát từ trường dương cực mạnh từ tay trái. [Hiệu ứng] Bẻ cong quỹ đạo đạn súng bắn tới hoặc đẩy văng một hiệp sĩ mặc giáp toàn thân văng ngược ra sau 5 mét (Khắc chế bọn mặc giáp sắt).", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Từ Trường"], range_type: "Hình Nón Nhỏ (Đẩy lùi)", combo_tag: "Magnet_Repel" },
        { name: "Quả Cân Chì", desc: "[Cơ chế] Tụ một khối chì nặng 50kg trên không và ném thẳng xuống. [Hiệu ứng] Nện bẹp đầu mục tiêu từ trên cao, hoặc buộc gông chì vào chân địch để khóa chặt không cho chúng bay nhảy trốn thoát.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Tầm Trung (Ném tạ)", combo_tag: "Lead_Weight_Drop" },
        { name: "Dây Cáp Siết Cổ", desc: "[Cơ chế] Bắn ra một sợi tơ thép nhỏ bén như dao cạo. [Hiệu ứng] Sợi tơ quấn quanh cổ hoặc cổ chân mục tiêu. Kéo giật mạnh sẽ cắt rách tĩnh mạch (Gây Trọng thương) hoặc thắt nghẹt đường thở.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Tầm Trung (Khống chế cứng)", combo_tag: "Steel_Wire_Choke" },
        { name: "Mạ Rỉ Sét", desc: "[Cơ chế] Phát tán bào tử kim loại mang tính oxy hóa cực mạnh. [Hiệu ứng] Bám vào vũ khí/giáp của đối phương. Làm vũ khí địch mẻ mẻ, giảm 30% Damage và giáp bị giòn dễ vỡ (Giảm 30% DEF).", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Độc"], range_type: "Tầm Xa (Debuff trang bị)", combo_tag: "Rust_Curse" },
        { name: "Bọc Thép Nắm Đấm", desc: "[Cơ chế] Hình thành găng tay gấu bằng đồng đặc (Knuckle Duster). [Hiệu ứng] Đấm tay không nhưng mang sức công phá như dùng búa tạ. Đấm vỡ xương gò má, đập nát sừng dị thú cản đường.", rank: "Phàm Giai", cost: { type: "Stamina", value: 20 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Bản thân (Buff vũ khí)", combo_tag: "Brass_Knuckles" },
        { name: "Phi Đao Gắn Mìn", desc: "[Cơ chế] Phóng đao thép rỗng ruột chứa thuốc nổ ma pháp. [Hiệu ứng] Đao găm vào tường hoặc thân thể mục tiêu. Sau 2 giây sẽ phát nổ, bắn các mảnh đao vụn ra găm vào mắt/mặt địch xung quanh.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Hỏa"], range_type: "Tầm Xa (Đạn nổ)", combo_tag: "Explosive_Kunai" },
        { name: "Gai Đồng Xiên Phổi", desc: "[Cơ chế] Dựng một cây giáo đồng sắc từ dưới đất đâm chéo lên. [Hiệu ứng] Ngay lúc địch lao tới (Charge), mũi giáo đâm xuyên ngược vào ngực/phổi. Gây sát thương chí mạng kết hợp hiệu ứng phản đòn động năng.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Cận Chiến Phía Trước (Đỡ đòn lao)", combo_tag: "Copper_Spear_Block" },
        { name: "Phản Quang Giáp", desc: "[Cơ chế] Đánh bóng lớp mạ kim loại đến mức tuyệt đối. [Hiệu ứng] Bất kỳ tia sáng (Hệ Quang) hay laser nào chiếu vào người bạn sẽ bị phân tán, giảm 50% sát thương ánh sáng.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Bản thân (Kháng Quang học)", combo_tag: "Polished_Armor" },
        { name: "Đập Đe Thép", desc: "[Cơ chế] Khóa chặt tay mục tiêu vào một khối đe kim loại gọi ra. [Hiệu ứng] Vận sức nện đòn búa trời giáng xuống tay địch đang bị khóa. Đập nát vụn xương tay, tàn phế vĩnh viễn cánh tay cầm vũ khí của kẻ thù.", rank: "Thiết Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Tàn phế nhục thể)", combo_tag: "Anvil_Smash" },
        { name: "Bụi Kim Loại Lưỡng Tính", desc: "[Cơ chế] Tung đám sương mù kim loại (Alkali). [Hiệu ứng] Khi chạm vào sấm sét (Hệ Lôi) nó dẫn điện giật lan cả team địch. Khi gặp Lửa (Hệ Hỏa) nó bùng cháy như bom nhiệt áp bột nhôm. Tuyệt kỹ Combo.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "AoE Trung (Setup môi trường)", combo_tag: "Reactive_Dust" },
        { name: "Mỏ Neo Cố Định", desc: "[Cơ chế] Cắm ngàm thép tàng hình chốt chặt gót giày vào nền đá. [Hiệu ứng] Biến thành ngọn núi không thể bị xê dịch. Kháng 100% mọi kỹ năng hất văng, hút vào (Gió lốc, Lực hút). Đứng ra chắn đòn cho đồng đội.", rank: "Phàm Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Kháng hất văng)", combo_tag: "Anchor_Legs" },
        { name: "Mưa Vỏ Đạn Cũ", desc: "[Cơ chế] Hút phế liệu súng đạn gỉ sét chiến trường bắn ra như đại bác. [Hiệu ứng] Bắn hàng rào mảnh vụn phế liệu dồn dập vào quân địch. Gây sát thương liên hoàn và làm xước rách mặt mũi, khiến địch không thể tập trung.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Hình Nón Rộng (Xả đạn)", combo_tag: "Scrap_Rain" },
        { name: "Vuốt Thép Xé Xác", desc: "[Cơ chế] Cấu trúc lại keratin ở móng tay thành hợp kim Tungsten (Wolfram). [Hiệu ứng] Chém đứt giáp Kevlar, khiên gỗ và vỏ xe bọc thép mỏng nhẹ như chém bùn. Đòn đánh bỏ qua 30% DEF vật lý của mục tiêu.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến", combo_tag: "Steel_Claw" },
        { name: "Mình Đồng Da Sắt", desc: "[Cơ chế] Kích hoạt từ trường sinh học, ép các mảnh kim loại dưới da nổi lên đan vào nhau. [Hiệu ứng] Cơ thể cứng như thép tảng. Đạn súng trường bắn vào nảy ra (Miễn nhiễm sát thương đạn đạo cỡ nhỏ). Tăng 150% DEF trong 15 phút.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Bản thân (Buff phòng thủ)", combo_tag: "Iron_Skin" },
        { name: "Mưa Tên Kim Loại", desc: "[Cơ chế] Ngưng tụ mạt sắt trong không khí và bắn ra bằng áp lực từ trường. [Hiệu ứng] Bắn hàng trăm mảnh kim loại sắc nhọn như đạn ria (Shotgun) ra phía trước. Xé nát đội hình giáp nhẹ, gây sát thương diện rộng và hiệu ứng Chảy Máu.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Hình Nón Trung", combo_tag: "Shrapnel_Rain" },
        { name: "Kiếm Khí", desc: "[Cơ chế] Vung tay tốc độ cao, kéo theo các hạt phân tử kim loại nén dẹt. [Hiệu ứng] Tạo lưỡi đao vô hình (hoặc có ánh bạc) bay xa 10m. Cắt đứt đôi thân cây hoặc đầu kẻ địch từ xa mà không cần áp sát.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Đường thẳng (Tầm Trung)", combo_tag: "Metal_Slash" },
        { name: "Nam Châm Hút Vũ Khí", desc: "[Cơ chế] Bàn tay phát ra xung điện từ (EMP) đảo ngược từ tính. [Hiệu ứng] Giật phăng mọi vũ khí kim loại (Kiếm, Súng, Giáo) khỏi tay toàn bộ kẻ địch trong bán kính 10m bay thẳng vào tay (hoặc túi) của người dùng. Tước vũ khí hoàn hảo.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Từ Trường"], range_type: "AoE Trung (Khống chế/Tước vũ khí)", combo_tag: "Magnet_Disarm" },
        { name: "Đè Bẹp", desc: "[Cơ chế] Đột ngột tăng mật độ phân tử kim loại trong cơ thể lên hàng nghìn lần. [Hiệu ứng] Hóa thân thành khối tạ thép nặng 10 tấn, nhảy lên và giáng thẳng xuống đầu mục tiêu. Nghiền nát xương cốt, phá vỡ mọi thế phòng ngự vật lý.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Sát thương cực lớn)", combo_tag: "Anvil_Crush" },
        { name: "Lưới Gai Thép", desc: "[Cơ chế] Phun tơ kim loại lỏng từ cổ tay, gặp không khí lập tức đông cứng. [Hiệu ứng] Phóng tấm lưới thép gai siết chặt mục tiêu (Root 2 phút). Kẻ địch càng giãy giụa hoặc dùng sức (STR) để xé, lưới càng siết chặt và cứa sâu vào tận xương.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Tầm Trung (Khống chế cứng)", combo_tag: "Barbed_Net" },
        { name: "Phản Chiếu Laser", desc: "[Cơ chế] Sắp xếp lại cấu trúc bề mặt giáp thành dạng gương phẳng hoàn hảo. [Hiệu ứng] Đánh bóng cơ thể. Phản xạ lại 100% sát thương của các đòn tấn công dạng chùm sáng (Ánh sáng, Laser quân đội, Nhiệt tuyến) ngược về nguồn phát.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Quang"], range_type: "Bản thân (Phản đòn ma pháp)", combo_tag: "Mirror_Armor" },
        { name: "Cưa Máy", desc: "[Cơ chế] Biến đổi xương cẳng tay thành trục xoay có gắn răng cưa hợp kim. [Hiệu ứng] Cánh tay xoay với tốc độ 5000 vòng/phút kèm tiếng rít chói tai. Cắt đứt cổng sắt pháo đài UHA, phá khiên ma pháp hệ Thổ/Băng trong vài giây. Sát thương DPS cận chiến cực khủng.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Kênh truyền/Channelling)", combo_tag: "Chainsaw_Arm" },
        { name: "Khiên Thép Di Động", desc: "[Cơ chế] Kéo giãn lớp giáp ở tay thành bản rộng 2x2m. [Hiệu ứng] Dựng khiên thép khổng lồ (Tower Shield) cắm xuống đất. Chặn đứt hỏa lực súng máy, che chở cho 3 đồng đội nấp phía sau an toàn tiến lên.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Bản thân (Bảo vệ đội hình)", combo_tag: "Tower_Shield" },
        { name: "Mảnh Bom Sát Thương", desc: "[Cơ chế] Nạp ma lực quá tải vào lớp vỏ thép ngoài cùng, tạo áp suất làm nứt gãy. [Hiệu ứng] Kích nổ lớp giáp ngoài thành hàng ngàn miểng văng sắc lẹm (AoE 10m). Xuyên thủng kẻ địch xung quanh. Đổi lại, người dùng bị giảm 50% DEF trong 45 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "AoE Trung (Tự nổ giáp)", combo_tag: "Armor_Detonate" },
        { name: "Gỉ Sét (Debuff)", desc: "[Cơ chế] Phát tán bào tử ma thuật kích thích quá trình oxy hóa kim loại siêu tốc. [Hiệu ứng] Làm vũ khí, áo giáp, và khớp nối của Mecha/Robot địch rỉ sét đỏ quạch ngay lập tức. Giảm 50% sát thương của vũ khí đó và làm kẹt khớp (Giảm AGI).", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Nước"], range_type: "Tầm Xa (Debuff trang bị)", combo_tag: "Rust_Curse" },
        { name: "Thương Xuyên Táo", desc: "[Cơ chế] Kéo dài và vuốt nhọn xương bàn tay thành khối thạch anh kim loại dài 3m. [Hiệu ứng] Đâm một cú cực mạnh xuyên thủng 3-4 kẻ địch đứng thẳng hàng (Đòn đâm xuyên Line). Sát thương chí mạng cao nếu trúng tim.", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Đường thẳng (Cận chiến xa)", combo_tag: "Spear_Pierce" },
        { name: "Trật Tự Tuyệt Đối (Cảnh Giới Kim Khí)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Đồng hóa linh hồn với lõi từ trường hành tinh, nắm quyền kiểm soát mọi nguyên tố kim loại trên thế giới. [Hiệu ứng] Bán kính 5km. Tước đoạt quyền sử dụng mọi vũ khí, xe cộ, pháo đài của nhân loại (UHA). Biến hàng vạn tấn thép xung quanh thành một cỗ máy chém khổng lồ nghiền nát mọi kẻ thù. Bất kể là đạn bay, Mecha hay giáp trụ đều bị bóp nát bấy. [Tác dụng phụ cực lớn] Người dùng bị 'Cơ khí hóa' hoàn toàn, mất đi cảm xúc, nhân tính và Sanity bị khóa ở mức 0. Trở thành một bạo chúa vô hồn vĩnh viễn không thể tu luyện thêm. Hút cạn 99% HP.", rank: "Thánh Giai", cost: { type: "HP", value: 9999999 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Từ Trường"], range_type: "Cấp Thế Giới (Tước vũ khí tuyệt đối)", combo_tag: "Holy_Metal_Order" },
        { name: "Chông Sắt Rải Đường", desc: "[Cơ chế] Đổ mạt sắt xuống đất và dùng từ trường định hình chúng thành đinh Caltrop. [Hiệu ứng] Rải bãi đinh 3 cạnh tàng hình. Làm thủng lốp xe cơ giới quân sự, đâm nát đệm chân quái thú. Gây Chảy Máu liên tục và giảm 30% tốc chạy.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Đặt bẫy (AoE Nhỏ)", combo_tag: "Caltrops_Trap" },
        { name: "Ăn Quặng (Hồi phục)", desc: "[Cơ chế] Tuyến tiêu hóa tiết axit siêu mạnh hòa tan kim loại. [Hiệu ứng] Nhai nuốt kim loại phế liệu, súng ống hỏng, vách pháo đài để hàn gắn vết thương trên cơ thể và khôi phục thanh giáp (Armor).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Bản thân (Hồi máu/Giáp)", combo_tag: "Eat_Scrap" },
        { name: "Hàm Răng Titan", desc: "[Cơ chế] Cấu trúc răng hàm bọc lớp Titan cacbua (TiC) siêu cứng. [Hiệu ứng] Đòn cắn có lực nghiền 50.000 PSI. Cắn đứt nòng súng pháo, nhai nát xích sắt khóa chân tay dễ như ăn kẹo. Rất tốt để phá giải khống chế vật lý.", rank: "Thiết Giai", cost: { type: "MP", value: 120 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Phá vật thể)", combo_tag: "Titan_Bite" },
        { name: "Lõi Năng Lượng", desc: "[Cơ chế] Lắp đặt bộ vi phản ứng ma thuật thay thế dạ dày sinh học. [Hiệu ứng] Nội tại. Nhân vật/Thú không bao giờ biết Đói (Hunger luôn = 0). Dùng các viên tinh thể ma lực (Crystal) làm pin nạp năng lượng thay thế cho thức ăn.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Công Nghệ"], range_type: "Bản thân (Nội tại sinh tồn)", combo_tag: "Energy_Core" },
        { name: "Mỏ Neo", desc: "[Cơ chế] Biến đôi chân thành khối chì nặng chục tấn và cắm ngàm sâu vào đá. [Hiệu ứng] Chống lại mọi lực hút/đẩy. Không thể bị thổi bay bởi Lốc xoáy (Hệ Phong), không bị cuốn trôi bởi Sóng thần (Hệ Thủy). Tuyệt đối đứng vững bảo vệ team.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Bản thân (Kháng Không chế đẩy)", combo_tag: "Anchor_Stance" },
        { name: "Khung Xương Trợ Lực", desc: "[Cơ chế] Mọc ra bộ xương ngoài (Exoskeleton) bám quanh cơ bắp. [Hiệu ứng] Buff tăng 300% sức mạnh vật lý (STR) và sức nâng. Vác đồng đội bị thương, nâng tảng đá kẹt cửa hoặc quật ngã quái thú to lớn hơn mình gấp 5 lần.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Bản thân (Buff sức mạnh)", combo_tag: "Exoskeleton" },
        { name: "Chìa Khóa Vạn Năng (Utility)", desc: "[Cơ chế] Ngón tay chảy lỏng, luồn vào ổ khóa và cứng lại lấy dấu ruột khóa. [Hiệu ứng] Mở mọi loại khóa cơ khí (Két sắt, còng tay, cửa phòng giam) trong 3 giây mà không gây ra tiếng động hay làm hỏng ổ khóa.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Cận Chiến (Tiện ích thâm nhập)", combo_tag: "Master_Key" },
        { name: "Mài Sắc (Hỗ trợ)", desc: "[Cơ chế] Dùng ngón tay mạ một lớp màng Carbon vi mô lên cạnh vũ khí. [Hiệu ứng] Vuốt tay qua đao kiếm của đồng đội. Tạm thời tăng 50% độ sắc bén (Damage) và hồi phục 100% Độ Bền (Durability) cho vũ khí đó trong trận đánh.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Cận Chiến (Buff đồng đội)", combo_tag: "Weapon_Sharpen" },
        { name: "Lồng Faraday", desc: "[Cơ chế] Dựng một mạng lưới điện từ bằng lồng thép bao quanh khu vực. [Hiệu ứng] Bảo vệ tuyệt đối cả đội hình (5x5m) khỏi Sét đánh, bão điện từ và đòn tấn công Hệ Lôi. Mọi dòng điện sẽ truyền thẳng xuống mặt đất vô hại.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Từ Trường"], range_type: "AoE Trung (Phòng ngự Hệ Lôi)", combo_tag: "Faraday_Cage" },
        { name: "Cầu Tạm Thời", desc: "[Cơ chế] Dung hợp kim loại vụn hoặc chính các đốt sống nối dài rỗng ruột. [Hiệu ứng] Tạo một cây cầu thép dài 20m vượt qua vực sâu, sông nham thạch hoặc bãi mìn. Chịu tải trọng siêu lớn cho cả xe bọc thép đi qua.", rank: "Thiết Giai", cost: { type: "MP", value: 350 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Tiện ích (Di chuyển)", combo_tag: "Metal_Bridge" },
        { name: "Dây Cáp Cứu Hộ", desc: "[Cơ chế] Bắn sợi tơ thép bện chặt từ cổ tay kèm mũi ngàm cắm ngập vào đá. [Hiệu ứng] Dùng như súng bắn móc (Grappling hook). Kéo đồng đội đang rơi khỏi vách núi, hoặc đu người bay qua các tòa nhà trong thành phố như Spider-man.", rank: "Phàm Giai", cost: { type: "MP", value: 80 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Tầm Xa (Cứu hộ/Di chuyển)", combo_tag: "Grappling_Cable" },
        { name: "Hàn Gắn Máy Móc", desc: "[Cơ chế] Đun chảy kim loại từ ngón tay để tạo mối hàn hồ quang chuẩn xác. [Hiệu ứng] Sửa chữa nhanh chóng xe cộ hư hỏng, drone trinh sát đứt mạch, hoặc gắn lại tay chân cho sủng thú dạng Robot/Cơ khí ngay giữa chiến trường.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Lôi"], range_type: "Cận Chiến (Sửa chữa)", combo_tag: "Machine_Repair" },
        { name: "Đại Pháo Thiên Diệt (Vệ Tinh Không Gian)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Hack quyền điều khiển và triệu hồi một bệ phóng quỹ đạo của nền văn minh cổ đại (Từ ngoài không gian). [Hiệu ứng] Bắn một chùm tia Ion kim loại nặng siêu hội tụ từ vệ tinh xuống mặt đất. Thổi bay một vùng núi non rộng lớn thành bình địa, nung chảy vạn vật thành thủy tinh rực sáng. [Tác dụng phụ] Phá vỡ lõi ma lực Hệ Kim của người tung chiêu, không thể sử dụng bất kỳ kỹ năng Hệ Kim nào trong 1 năm. Max MP giảm 70% vĩnh viễn.", rank: "Diệu Giai", cost: { type: "MP", value: 40000000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Quang", "Không Gian"], range_type: "AoE Rất Rộng (Đòn Quỹ Đạo)", combo_tag: "Divine_Orbital_Strike" },
        { name: "Cảm Biến Kim Loại", desc: "[Cơ chế] Dùng từ trường vi mô quét địa hình như máy dò mìn. [Hiệu ứng] Phát hiện vũ khí ám sát giấu trong người kẻ địch, tìm mìn chống tăng chôn dưới đất, hoặc dò ra mỏ quặng quý hiếm sâu 100m để khai thác.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Từ Trường"], range_type: "AoE Rộng (Trinh sát)", combo_tag: "Metal_Detector" },
        { name: "Hộp Đựng An Toàn", desc: "[Cơ chế] Mở một khoang chứa bọc chì/thép dày đặc bên trong lồng ngực. [Hiệu ứng] Nuốt vật phẩm quan trọng (Chip dữ liệu, Lõi quái quý) vào bụng để cất giấu. Khoang này chống tia X, chống máy quét ma lực, bảo vệ vật phẩm khỏi cháy nổ.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Bản thân (Kho đồ bí mật)", combo_tag: "Safe_Vault" },
        { name: "Hóa Hình - Kim Loại Lỏng (Đặc Biệt - Dị Thú)", desc: "[Cơ chế] Thú cơ khí hóa phá vỡ liên kết tinh thể cứng thành thể lỏng (Như Terminator T-1000). [Hiệu ứng] Biến thành khối kim loại lỏng màu bạc, chảy qua các khe nứt, uốn éo né đạn hoàn hảo. Sau đó tái định hình thành cấu trúc nhân dạng cơ khí lạnh lẽo. Vô nhiễm vật lý hoàn toàn khi ở dạng lỏng.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 55000 }, cooldown: { value: 3, unit: "Ngày", display_text: "3 Ngày" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Nước"], range_type: "Bản thân (Ngụy trang/Chạy trốn)", combo_tag: "Beast_Liquid_Metal" },
        { name: "Cương Trảo Xé Xác", desc: "[Cơ chế] Phiên bản hoang dã. Tụ khí kim loại sắc lạnh vào bộ vuốt đồ sộ. [Hiệu ứng] Chém đứt đôi người lính bọc giáp hợp kim UHA trong chớp mắt. Đòn cào phá vỡ mọi loại khiên năng lượng cấp thấp.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Sát thương cực cao)", combo_tag: "Beast_Iron_Claw" },
        { name: "Thiết Giáp Biến", desc: "[Cơ chế] Lớp vảy/lông tự động cứng lại như vảy rồng thép khi nhận sát thương. [Hiệu ứng] Biến da thành kim loại đặc. Phản đạn súng lục, đạn tiểu liên. Miễn nhiễm hoàn toàn sát thương vật lý nhẹ và chống rách da.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim"], range_type: "Bản thân (Buff bị động phòng thủ)", combo_tag: "Beast_Steel_Hide" },
        { name: "Kim Tiễn Hào Vũ", desc: "[Cơ chế] Rũ mạnh bộ lông nhím bằng sắt thép. [Hiệu ứng] Bắn ra hàng loạt lông gai cứng như thép bay tản mác với tốc độ đạn súng máy. Đâm thủng cơ thể nhóm lính vây hãm xung quanh. Kẻ địch trúng gai bị giảm tốc chạy.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Vật Lý"], range_type: "AoE Trung (Tầm Xa/Nổ gai)", combo_tag: "Iron_Quill_Rain" },
        { name: "Bàn Tay Hủy Diệt (Bàn Tay Thần)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Khống chế khối lượng sắt khổng lồ từ lòng đất (Hàng triệu tấn quặng). [Hiệu ứng] Trồi lên một bàn tay thép vĩ đại bao trùm bầu trời. Ép chết, nghiền vụn một đạo quân viễn chinh hoặc một Thú Vương chỉ bằng cú siết tay. Lực ép đứt gãy không gian. [Tác dụng phụ] Tiêu hao 90% Bloodline Energy. Sanity giảm 60 điểm. Xương cốt toàn thân nứt gãy, Dị thú mất khả năng di chuyển trong 30 ngày.", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 800000 }, cooldown: { value: 90, unit: "Ngày", display_text: "3 Tháng" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Thổ"], range_type: "AoE Rất Rộng (Cấp Thảm Họa)", combo_tag: "Divine_Iron_Hand" },
        { name: "Nam Châm Hấp Lực (Từ trường quái thú)", desc: "[Cơ chế] Dạ dày từ tính gầm gừ phát ra lực hút mạnh. [Hiệu ứng] Giật tung mọi vũ khí, giáp của UHA văng thẳng vào miệng thú để nhai. Lôi kéo các Mecha kim loại lại sát gần để cấu xé.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Từ Trường"], range_type: "AoE Nhỏ (Kéo mục tiêu)", combo_tag: "Beast_Magnetic_Pull" },
        { name: "Khối Sắt Rơi Xuống", desc: "[Cơ chế] Dồn nén cấu trúc phân tử, tăng trọng lượng đột biến khi đang nhảy cao. [Hiệu ứng] Từ trên không giáng xuống như quả thiên thạch sắt. Gây chấn động vỡ nát mặt đường, đè bẹp xe thiết giáp thành đống sắt vụn.", rank: "Kim Giai", cost: { type: "Stamina", value: 80000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Vật Lý"], range_type: "AoE Nhỏ (Sát thương hủy diệt)", combo_tag: "Beast_Iron_Meteor" },
        { name: "Lưới Thép Gai (Thú săn mồi)", desc: "[Cơ chế] Khạc tơ kim loại từ tuyến nước bọt. [Hiệu ứng] Phun tấm lưới sắc nhọn trùm lên con mồi. Kẻ thù càng cựa quậy, sợi thép càng siết chặt cắt đứt cơ gân, gây chảy máu đến chết mà thú không cần tốn công đánh.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Tầm Trung (Khống chế cứng)", combo_tag: "Beast_Wire_Net" },
        { name: "Phản Quang Cảnh Điện", desc: "[Cơ chế] Lớp vảy sừng kim loại mài nhẵn như gương nhờ ma sát gió. [Hiệu ứng] Đỡ đòn trực tiếp. Phản lại 1 đòn tấn công tia sáng (Beam/Laser) của pháp sư hệ Quang hoặc súng cao xạ UHA.", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Quang"], range_type: "Bản thân (Phản đòn)", combo_tag: "Beast_Mirror_Deflect" },
        { name: "Cưa Xích Huyết Nhục", desc: "[Cơ chế] Cẳng tay mọc ra xương bánh chè bọc kim loại xoay tít. [Hiệu ứng] Biến móng vuốt thành cưa xích máy. Chuyên trị cưa nát phòng thủ siêu cứng của các Cự thú hệ Thổ hoặc cửa hầm quân sự (Sát thương DPS phá giáp).", rank: "Kim Giai", cost: { type: "Stamina", value: 50000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Xuyên giáp tuyệt đối)", combo_tag: "Flesh_Chainsaw" },
        { name: "Ăn Mòn Gỉ Sét (Phun Axit kim loại)", desc: "[Cơ chế] Nước bọt pha trộn dịch vị phân hủy kim loại. [Hiệu ứng] Phun sương màu nâu gỉ. Làm rỉ sét mục nát vũ khí, áo giáp, khóa chốt của đối phương ngay lập tức. Giảm 50% DEF của mọi xe cộ/người máy.", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Độc"], range_type: "Hình Nón Nhỏ (Debuff Giáp)", combo_tag: "Beast_Rust_Breath" },
        { name: "Thương Đâm Xuyên Táo", desc: "[Cơ chế] Sừng hoặc đuôi mọc dài ra như ngọn giáo thép. [Hiệu ứng] Lao sầm vào đội hình địch, đâm xiên 3-4 mục tiêu như xâu chả. Xuyên thủng khiên năng lượng và khiên vật lý, hất văng những kẻ đứng sau.", rank: "Thiết Giai", cost: { type: "Stamina", value: 350 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Đường thẳng (Lao tới)", combo_tag: "Beast_Lance_Charge" },
        { name: "Đinh Tán Mặt Đất", desc: "[Cơ chế] Vẩy đuôi, rụng vảy nhọn cắm thẳng xuống bùn đất. [Hiệu ứng] Rải bãi mìn đinh sinh học. Ai dẫm phải thủng chân, tốc độ di chuyển giảm 50%, chảy máu liên tục. Đinh tự động hoại tử nếu cố rút ra.", rank: "Phàm Giai", cost: { type: "Stamina", value: 100 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Kim"], range_type: "Đặt bẫy", combo_tag: "Beast_Spike_Trap" },
        { name: "Răng Cưa Nghiền Nát", desc: "[Cơ chế] Răng hàm tiến hóa kép đan chéo bọc Titan. [Hiệu ứng] Nhát cắn kinh hoàng. Cắn vỡ nát khiên năng lượng, nghiền nát xương đầu Dị thú hệ Thổ. Gây hiệu ứng Trọng Thương (Không thể hồi máu).", rank: "Ngân Giai", cost: { type: "Stamina", value: 3000 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Vật Lý"], range_type: "Cận Chiến (Đòn kết liễu)", combo_tag: "Crushing_Jaws" },
        { name: "Lõi Năng Lượng Máy (Tiến Hóa Sinh Cơ)", desc: "[Cơ chế] Dị thú dung hợp thành công với rác công nghệ Vùng Zero. [Hiệu ứng] Trái tim trở thành lò phản ứng hồ quang mini. MP được thay bằng Năng lượng cơ khí, x2 lượng max. Không bao giờ kiệt sức khi chạy đường dài.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 75000 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Nội tại" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim", "Công Nghệ"], range_type: "Bản thân (Tiến hóa bị động)", combo_tag: "Cyborg_Heart" }
    ],
  "Hệ Độc Dược": [
        { name: "Hóa Hình - Độc Nhân", desc: "[Cơ Chế Sinh Học] Biến đổi hệ bạch huyết. Mọi dịch cơ thể (nước bọt, mồ hôi) hóa thành dung môi độc. Gan/Thận phát triển cực đại. Túi mật chứa nọc cô đặc. [Hình Thái] Da tái nhợt, môi thâm, hơi thở mùi hạnh nhân đắng. Dạng người miễn nhiễm bệnh tật. [Tác dụng phụ] Không thể che giấu hoàn toàn mùi độc. Một nụ hôn hay chạm tay vô tình có thể giết chết người bình thường/đồng đội yếu.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Poison" },
        { name: "Huyết Độc Ngưng Đọng", desc: "[Cơ chế] Hệ bạch huyết chuyển hóa mọi kháng nguyên thành nọc độc. [Hiệu ứng] Kẻ địch chém bạn chảy máu sẽ bị dính hiệu ứng [Nhiễm Trùng]. Máu văng vào mắt chúng gây Mù Lòa 2 giây và trừ máu liên tục.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Bản thân (Bị động phản đòn)", combo_tag: "Passive_Toxic_Blood" },
        { name: "Hủ Cốt Độc Trảo", desc: "[Cơ chế] Da tiết mồ hôi chứa axit loãng liên tục. [Hiệu ứng] Bất kỳ sinh vật nào dùng xúc tu, dây thừng hay tay ôm chặt lấy bạn (Khóa siết - Grapple) sẽ bị bỏng rát, tự động buông tay sau 2s vì đau đớn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Axit"], range_type: "Cận chiến (Bị động thoát thân)", combo_tag: "Passive_Corrosive_Touch" },
        { name: "Xuyên Cốt Độc Kích", desc: "[Cơ chế] Độc tính của bạn có khả năng phá vỡ lớp màng bảo vệ ma pháp. [Hiệu ứng] Mọi Kỹ năng Độc và đòn đánh tẩm Độc của bạn sẽ bỏ qua 20% Kháng Phép (Magic Resist) của kẻ thù. Rất hiệu quả khi đối đầu với Tanker.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Đòn đánh (Bị động xuyên kháng)", combo_tag: "Passive_Toxin_Pierce" },
        { name: "Độc Vụ Hộ Thể", desc: "[Cơ chế] Lỗ chân lông tỏa ra pheromone độc nhẹ. [Hiệu ứng] Kẻ địch đứng trong phạm vi 2m quanh bạn sẽ liên tục bị ho, chảy nước mắt, giảm 10% Tốc độ đánh (AGI) và giảm Tỉ lệ chính xác.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Khí"], range_type: "Xung quanh (Bị động Debuff)", combo_tag: "Passive_Noxious_Aura" },
        { name: "Hủ Bại Độc Nhẫn", desc: "[Cơ chế] Ma lực Độc vô hình bám dính lên bất cứ thứ gì bạn cầm. [Hiệu ứng] Các đòn đánh thường (Basic Attack) có 15% tỉ lệ gây hiệu ứng [Thối Rữa] - ngăn chặn kẻ địch hồi HP bằng phép thuật hoặc thuốc trong 5 giây.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Mệnh"], range_type: "Đòn đánh (Bị động khắc chế hồi máu)", combo_tag: "Passive_Infect_Weapon" },
        { name: "Thi Khí Thôn Phệ", desc: "[Cơ chế] Dạ dày sản sinh vi khuẩn hoại sinh hấp thụ khí đầm lầy. [Hiệu ứng] Nếu đứng gần xác chết đang phân hủy hoặc ở môi trường ô nhiễm, tốc độ hồi MP và HP tăng gấp đôi. Biến bãi tha ma thành thánh địa hồi phục.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Hắc Ám"], range_type: "Bản thân (Bị động hồi sức môi trường)", combo_tag: "Passive_Corpse_Nourish" },
        { name: "Tiềm Phục Độc Phát", desc: "[Cơ chế] Độc tính không phát tác ngay mà tích tụ trong nội tạng địch. [Hiệu ứng] Cứ mỗi đòn đánh trúng địch, tích 1 điểm [Ủ Độc]. Khi đạt 5 điểm, mục tiêu sẽ nổ độc mất ngay 10% Max HP và bị Choáng (Stun) 1s.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Mục tiêu (Bị động cộng dồn nổ)", combo_tag: "Passive_Delayed_Poison" },
        { name: "Độc Chướng Ẩn Thể", desc: "[Cơ chế] Sương mù sinh học làm nhiễu sóng và ánh sáng. [Hiệu ứng] Khi bạn đang ở trạng thái [Tàng Hình] hoặc lẩn trốn trong bụi rậm, bạn không thể bị quét trúng bởi các kỹ năng Định vị (Radar/Scan) từ Pháp sư địch.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Ảo Giác"], range_type: "Bản thân (Bị động tàng hình tuyệt đối)", combo_tag: "Passive_Miasma_Cloak" },
        { name: "Tuyệt Ôn Kháng Thể", desc: "[Cơ chế] Hệ miễn dịch siêu việt tiêu diệt virus từ lúc xâm nhập. [Hiệu ứng] Kháng hoàn toàn các trạng thái [Bệnh Tật], [Dịch Hạch], [Ký Sinh Trùng]. Tránh được việc Sanity bị giảm do môi trường dơ bẩn.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Mệnh"], range_type: "Bản thân (Bị động kháng bệnh)", combo_tag: "Passive_Bio_Immunity" },
        { name: "Hủ Khí Độc Bì", desc: "[Cơ chế] Làn da mang vi khuẩn ăn kim loại. [Hiệu ứng] Bất kỳ mũi tên hay vũ khí sắt nào cắm vào cơ thể bạn sẽ bị gỉ sét và vỡ vụn sau 2 giây, không thể rút ra để tái sử dụng hay cắm sâu thêm.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Kim"], range_type: "Bản thân (Bị động phá hủy vật lý)", combo_tag: "Passive_Necrotic_Rust" },
        { name: "Mị Hoặc Độc Hương", desc: "[Cơ chế] Độc tính ngụy trang thành pheromone hoa hồng/thảo dược. [Hiệu ứng] Quái vật hoang dã đánh hơi thấy bạn sẽ tưởng bạn là một cái cây không nguy hiểm. Giảm 50% tỉ lệ bị tấn công chủ động (Aggro) khi đi qua rừng.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Khí"], range_type: "Bản thân (Bị động giảm đe dọa)", combo_tag: "Passive_Sweet_Scent" },
        { name: "Bách Độc Thức Giác", desc: "[Cơ chế] Lưỡi/Mũi tự động phân tích cấu trúc hóa học của môi trường. [Hiệu ứng] Biết ngay lập tức nguồn nước, thức ăn hay cái cây trước mặt có chứa độc hay không. Tránh hoàn toàn việc tổ đội bị hạ độc qua ẩm thực.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Môi trường (Bị động kiểm tra)", combo_tag: "Passive_Toxin_Sense" },
        { name: "Cuồng Độc Huyết Sát", desc: "[Cơ chế] Nọc độc hòa vào Adrenaline ép tim đập cực mạnh. [Hiệu ứng] Khi lượng HP của bạn giảm xuống dưới 20%, toàn bộ đòn đánh thường của bạn sẽ tự động gây thêm trạng thái [Trúng Độc Nặng] khiến địch mất máu siêu tốc.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Bản thân (Bị động buff sinh tử)", combo_tag: "Passive_Toxic_Berserk" },
        { name: "Cổ Trùng Thể Phách", desc: "[Cơ chế] Trao đổi chất mô phỏng loài gián/bọ cạp Vùng Zero. [Hiệu ứng] Thể lực (Stamina) tiêu hao cho việc chạy nước rút (Sprint) và leo trèo giảm đi 50%. Có thể sống sót 1 tuần không cần thức ăn nhờ trao đổi chất chậm.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Tồn"], range_type: "Bản thân (Bị động bền bỉ)", combo_tag: "Passive_Insect_Stamina" },
        { name: "Tê Ma Độc Kích", desc: "[Cơ chế] Phủ một lớp nọc vô hình lên găng tay/vũ khí. [Hiệu ứng] Mỗi nhát chém trúng địch có 5% tỉ lệ gây hiệu ứng [Tê Liệt Bán Phần], làm chúng bị khựng lại (Interrupt) và mất kỹ năng đang niệm chú.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Đòn đánh (Bị động ngắt chiêu)", combo_tag: "Passive_Neuro_Strike" },
        { name: "Xà Độc Thôn Phệ", desc: "[Cơ chế] Huyết quản như một kho chứa các chuỗi Protein độc. [Hiệu ứng] Bất kỳ đòn sát thương hệ Độc nào đánh vào bạn sẽ không làm bạn mất HP, mà tự động chuyển 50% lượng sát thương đó thành năng lượng (MP) cho bản thân.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Bản thân (Bị động hấp thụ sát thương)", combo_tag: "Passive_Venom_Absorb" },
        { name: "Hủ Luyện Độc Dịch", desc: "[Cơ chế] Acid lactic ma thuật tự động văng ra theo mỗi cú xoay người. [Hiệu ứng] Mỗi khi bạn thực hiện động tác Né Tránh (Dodge) sát một kẻ địch, chúng sẽ bị tạt một giọt axit, giảm vĩnh viễn 1% DEF (Cộng dồn vô hạn).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Axit"], range_type: "Né tránh (Bị động bào mòn)", combo_tag: "Passive_Corrosive_Dodge" },
        { name: "Huyễn Độc Bào Tử", desc: "[Cơ chế] Quần áo/lông mao mang theo bào tử nấm gây ảo giác. [Hiệu ứng] Kẻ thù dùng đòn Vật lộn (Khóa siết) với bạn sẽ bị hít phải bào tử, lập tức rơi vào ảo ảnh và tự động buông tay ra trong sợ hãi.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Ảo Giác"], range_type: "Cận chiến (Bị động thoát khống chế)", combo_tag: "Passive_Shroom_Escape" },
        { name: "Bất Dũ Độc Thương", desc: "[Cơ chế] Bơm chất chống đông máu (Heparin sinh học) vào đòn đánh. [Hiệu ứng] Những kẻ địch bị bạn làm chảy máu sẽ không thể tự cầm máu bằng phương pháp băng bó thông thường, hiệu ứng [Chảy Máu] duy trì lâu gấp 3 lần.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Mục tiêu (Bị động cường hóa DoT)", combo_tag: "Passive_Anti_Coagulant" },
        { name: "Phi Tiêu Tẩm Độc", desc: "[Cơ chế] Nhúng mũi dao/phi tiêu vào nọc cóc độc (Bufotoxin). [Hiệu ứng] Phi tiêu cắm vào thịt, gây Sát thương độc rút 2% HP/giây trong 3 giây. Đầu óc nạn nhân bị choáng váng nhẹ làm chậm đòn đánh.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Tầm Xa (Cấu rỉa/DoT)", combo_tag: "Poison_Dart" },
        { name: "Bãi Nhầy Ăn Mòn", desc: "[Cơ chế] Khạc bãi đờm axit dạ dày đậm đặc. [Hiệu ứng] Phun bãi axit xuống đất (2x2m). Kẻ địch chạy qua bị ănn mòn mỏng lớp giáp gầm, giảm 20% Phòng thủ (DEF) và lở loét lòng bàn chân.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Nước"], range_type: "Đặt Bẫy Bề Mặt", combo_tag: "Acid_Spit_Trap" },
        { name: "Khí Độc Tầm Gần", desc: "[Cơ chế] Bóp vỡ túi nấm độc phun khói xám. [Hiệu ứng] Phun mây mù có mùi trứng thối. Gây ho sặc sụa tột độ, làm mù (Blind) mắt và Ngắt (Interrupt) mọi niệm chú của kẻ địch phía trước mặt.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Khí"], range_type: "Hình Nón Cận Chiến (Khống chế cứng)", combo_tag: "Stink_Gas_Cone" },
        { name: "Vuốt Nhiễm Trùng", desc: "[Cơ chế] Móng vuốt phủ dầy vi khuẩn hoại tử thịt. [Hiệu ứng] Cào xé địch. Vết thương lập tức nổi mủ sưng tấy xanh lè. Gây trạng thái Trọng Thương (Giảm 50% mọi hiệu ứng Hồi Máu từ ma pháp hay thuốc của phe địch).", rank: "Thiết Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Vật Lý"], range_type: "Cận Chiến (Anti-Heal)", combo_tag: "Infection_Claw" },
        { name: "Răng Nọc Rắn", desc: "[Cơ chế] Nanh giả mọc nhọn bơm nọc thần kinh (Neurotoxin). [Hiệu ứng] Cắn ngập nanh. Kẻ địch bị tê dại tay chân tức khắc (Giảm 40% AGI) và không thể chạy trốn. Sát thương cắn vật lý khá thấp.", rank: "Phàm Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Cận Chiến (Làm chậm)", combo_tag: "Snake_Fang_Bite" },
        { name: "Mồ Hôi Khắc Hệ", desc: "[Cơ chế] Cơ thể rịn ra chất nhờn có gốc Amoniac kịch độc. [Hiệu ứng] Khi bị kẻ địch đấm, chém sáp lá cà, mồ hôi bắn lên tay và mắt chúng. Làm hỏng vũ khí (Giảm Độ Bền) và gây rát mắt (Giảm tỷ lệ trúng).", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Bản thân (Phản đòn bị động)", combo_tag: "Toxic_Sweat_Armor" },
        { name: "Bụi Phấn Gây Ngứa", desc: "[Cơ chế] Tung phấn hoa bám lông. [Hiệu ứng] Ném đám bụi li ti bám chặt vào khe giáp/cơ thể địch. Gây ngứa ngáy điên cuồng đến mức địch phải buông vũ khí gãi, làm phân tâm và Mất Kỹ Năng 1 Lượt.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Tầm Trung (Phá rối)", combo_tag: "Itching_Powder" },
        { name: "Máu Độc Phun Trào", desc: "[Cơ chế] Ép máu mang tính axit bắn tung tóe từ vết thương. [Hiệu ứng] Tự rạch tay hoặc đợi bị chém. Máu bắn ra gây sát thương Hóa Học cực gắt lên mặt kẻ tấn công, đổi máu lấy máu vô cùng hung hãn.", rank: "Thiết Giai", cost: { type: "HP", value: 20 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Mệnh"], range_type: "Cận Chiến (Sát thương đền mạng)", combo_tag: "Acid_Blood_Spray" },
        { name: "Cọc Độc Cắm Đất", desc: "[Cơ chế] Cắm một cây nấm độc khổng lồ xuống đất. [Hiệu ứng] Nấm xả khí độc liên tục. Mỗi 1 giây xả 1 vòng sóng khí độc yếu bán kính 4m. Ép phe địch không dám đứng tụm lại một chỗ để buff máu.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc"], range_type: "Triệu Hồi Bẫy (AoE phát tán)", combo_tag: "Poison_Totem" },
        { name: "Mũi Tên Tê Có Cứng", desc: "[Cơ chế] Mũi tên tẩm nọc Nhện Lóa (Cứng cơ). [Hiệu ứng] Bắn trúng bắp chân hoặc tay. Cơ bắp tại đó lập tức co rút cứng đờ như đá (Root cục bộ 1 chi), làm địch ngã quỵ xuống đất không thể giữ thăng bằng.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Vật Lý"], range_type: "Tầm Xa (Tê liệt cơ)", combo_tag: "Paralyze_Arrow" },
        { name: "Xịt Khói Đen Mù", desc: "[Cơ chế] Vòi phun túi mực sinh học (như bạch tuộc). [Hiệu ứng] Xịt mây mực đen đặc quánh dính chặt vào mắt kính Mecha, mắt lính gác. Mù tuyệt đối 100% trong 2 giây để tẩu thoát hoàn hảo khỏi vòng vây.", rank: "Phàm Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Ảo Giác"], range_type: "Xung quanh (Che khuất)", combo_tag: "Ink_Smoke_Escape" },
        { name: "Khí Nôn Mửa", desc: "[Cơ chế] Thổi khí Metan trộn lưu huỳnh. [Hiệu ứng] Gây thối rữa môi trường. Kẻ địch hít phải sẽ nôn mửa lịm đi. Rút cạn thể lực (Stamina) của chúng khiến chúng không thể vung kiếm đánh trả.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Khí"], range_type: "AoE Trung (Debuff Stamina)", combo_tag: "Vomit_Gas" },
        { name: "Roi Độc Xé Rách", desc: "[Cơ chế] Sợi roi làm từ gân thú ngâm nọc độc. [Hiệu ứng] Quất roi để lại những vết hằn tím đen nhức nhối. Độc ăn sâu vào xương cốt, mỗi nhát quất cộng dồn thêm 1 Tầng Độc (Stack Poison) chờ kích nổ.", rank: "Thiết Giai", cost: { type: "Stamina", value: 35 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Vật Lý"], range_type: "Cận Chiến Xa (Tích lũy ấn)", combo_tag: "Poison_Whip_Stack" },
        { name: "Cấy Nấm Ký Sinh", desc: "[Cơ chế] Vỗ vào vai địch, nhét mầm nấm ma. [Hiệu ứng] Nấm hút MP của đối thủ để phình to. Sau 5 giây, nấm bung nở làm suy yếu toàn bộ ma pháp phòng ngự (Xóa khiên Ánh sáng/Nước) của nạn nhân.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Mộc"], range_type: "Cận Chiến (Phá Khiên Phép)", combo_tag: "Fungus_Parasite_Armor" },
        { name: "Kích Nổ Độc Tố", desc: "[Cơ chế] Vận ma lực, xúc tác toàn bộ nọc độc đã tiêm vào người mục tiêu. [Hiệu ứng] Hấp thụ toàn bộ các tầng Độc đang có trên người địch và phát nổ từ bên trong nội tạng. Sát thương cực lớn (Bỏ qua giáp).", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc"], range_type: "Tầm Xa (Kết liễu Combo)", combo_tag: "Toxic_Detonation_Mini" },
        { name: "Chích Độc Giải Đau (Hỗ trợ)", desc: "[Cơ chế] Tiêm liều Morphine ma thuật độc nhẹ. [Hiệu ứng] Đâm kim vào đồng đội, gây mất 5% HP nhưng lập tức Tăng 50% Tốc chạy và Xóa mọi trạng thái làm chậm/sợ hãi. Phép Buff dị biệt.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Trị Liệu"], range_type: "Cận Chiến (Buff tốc/Giải hiệu ứng)", combo_tag: "Toxic_Stimulant" },
        { name: "Vỏ Bọc Nọc Độc", desc: "[Cơ chế] Bơm nọc độc ra quanh da, đóng vảy thành giáp nhọn. [Hiệu ứng] Kẻ nào đánh cận chiến hoặc vật lộn (Grapple) với bạn sẽ bị gai độc đâm thủng tay, gây Độc rút máu liên tục. Tăng 10% DEF.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc"], range_type: "Bản thân (Phòng ngự phản đòn)", combo_tag: "Poison_Scale_Armor" },
        { name: "Chướng Khí Ảo Giác", desc: "[Cơ chế] Thổi phấn hoa anh túc biến thể. [Hiệu ứng] Địch hít phải sẽ thấy đầu óc lảo đảo, hoa mắt (Sanity giảm 5 điểm). Mọi hành động tung chiêu đều có xác suất 30% bị Trượt (Miss).", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Tinh Thần"], range_type: "AoE Nhỏ (Debuff mù lòa/Ảo giác)", combo_tag: "Hallucinogen_Smog" },
        { name: "Lá Thuốc Giải Rắn", desc: "[Cơ chế] Mộc năng bài tiết chất giải độc cục bộ. [Hiệu ứng] Nhai nát lá đắp lên vết cắn. Giải trừ ngay 1 lớp Độc/Chảy máu cấp Phàm Giai cho bản thân hoặc đồng đội. Cấp cứu khẩn cấp.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Mộc"], range_type: "Cận Chiến (Giải debuff cơ bản)", combo_tag: "Basic_Antidote" },
        { name: "Hơi Thở Ăn Rỉ Sét", desc: "[Cơ chế] Phun hơi axit Clohydric nồng độ đặc. [Hiệu ứng] Phun thẳng vào khiên kim loại, khóa cửa sắt, hoặc bộ giáp. Axit làm giòn rụm vật chất ngay lập tức, đòn chém kế tiếp sẽ đập vỡ nát bộ giáp địch.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Kim Loại"], range_type: "Hình Nón Cận Chiến (Phá giáp tuyệt đối)", combo_tag: "Corrosive_Rust_Breath" },
        { name: "Sương Mù Tử Thần", desc: "[Cơ chế] Bốc hơi dịch độc qua lỗ chân lông hòa vào không khí. [Hiệu ứng] Tỏa khói độc màu lục diện rộng (Bán kính 20m). Giảm tầm nhìn, ăn mòn lớp niêm mạc phổi. Gây sát thương liên tục (Trừ 2% Max HP/giây) cho kẻ địch hít phải. Đồng minh cần thuốc giải trước khi vào.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Phong"], range_type: "AoE Trung (Đám mây độc)", combo_tag: "Death_Smog" },
        { name: "Tê Liệt Thần Kinh", desc: "[Cơ chế] Tiết nọc nhện tàng hình chặn liên kết synapse nơ-ron thần kinh. [Hiệu ứng] Phóng kim độc cực nhỏ hoặc cắn sượt. Nạn nhân lập tức cứng đờ, tê liệt hoàn toàn (Paralyzed) không thể cử động hay niệm chú trong 3 phút. Ý thức vẫn tỉnh táo để nếm trải nỗi sợ.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Tầm Xa/Cận Chiến (Khống chế cứng)", combo_tag: "Neuro_Paralyze" },
        { name: "Máu Axit", desc: "[Cơ chế] Duy trì nồng độ pH trong máu ở mức 1 (như axit Fluoroantimonic). [Hiệu ứng] Nội tại phản kích. Khi bị chém chảy máu, máu văng ra như đạn pháo ăn mòn thủng lỗ chỗ vũ khí cận chiến và làm loét da thịt kẻ chém. (Giảm độ bền vũ khí địch mạnh).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Nước"], range_type: "Bản thân (Phản đòn bị động)", combo_tag: "Acid_Blood" },
        { name: "Bom Mụn Rộp", desc: "[Cơ chế] Nặn dịch bạch huyết tạo thành một khối u chứa đầy vi khuẩn tụ cầu. [Hiệu ứng] Ném khối u nổ tung thành bãi chất nhầy dính (AoE 5m). Địch dẫm phải bị lây nhiễm khuẩn sinh học, nổi mụn mủ làm giảm 30% STR và AGI. Có tính lây lan khi địch chạm vào nhau.", rank: "Ngân Giai", cost: { type: "HP", value: 800 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Sinh Học"], range_type: "AoE Nhỏ (Đạn nổ/Lây nhiễm)", combo_tag: "Plague_Bomb" },
        { name: "Mưa Axit Cục Bộ", desc: "[Cơ chế] Bơm chất xúc tác độc học thẳng lên đám mây sương. [Hiệu ứng] Gọi mưa axit lục đậm trút xuống bán kính 15m. Tan chảy giáp thiết giáp, làm hỏng hoàn toàn công trình phòng thủ gỗ/đá. Địch không có ô chắn ma pháp sẽ bị nấu chảy đến xương.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Nước"], range_type: "AoE Trung (Sát thương ăn mòn cực mạnh)", combo_tag: "Acid_Rain" },
        { name: "Hương Thơm Ru Ngủ", desc: "[Cơ chế] Tỏa Pheromone hoa anh túc đậm đặc. [Hiệu ứng] Mùi hương ngọt ngào lan tỏa. Kẻ địch hít phải sẽ nhòa mắt, buồn ngủ và gục xuống ngủ say như chết trong 5 giờ (Sleep). Đánh thức chúng bằng sát thương sẽ lập tức làm chúng tỉnh.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Tinh Thần"], range_type: "AoE Nhỏ (Khống chế mềm)", combo_tag: "Sleep_Spore" },
        { name: "Đầu Độc Nguồn Nước", desc: "[Cơ chế] Nhỏ 1 giọt độc tố cô đặc dạng Botulinum siêu cấp. [Hiệu ứng] Phép tiện ích ám sát diện rộng. Giọt độc hòa tan vô hình vô vị vào bể nước thành phố, dòng suối. Kẻ nào uống phải sẽ chết lặng lẽ sau 24h vì suy đa tạng. Rất khó truy dấu.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Nước"], range_type: "Tầm Xa (Tương tác môi trường)", combo_tag: "Water_Poisoning" },
        { name: "Ký Sinh Trùng Hút Tủy", desc: "[Cơ chế] Nuôi dưỡng giun sán ma pháp trong dạ dày và nhổ chúng ra. [Hiệu ứng] Bắn giun độc chui tọt qua da kẻ thù. Ký sinh trùng gặm nhấm nội tạng, gây đau đớn cuộn trào (Trừ HP mỗi giây) và ăn cắp MP của địch truyền về cho Ký chủ.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Parasite_Leech" },
        { name: "Gai Độc Tàng Hình", desc: "[Cơ chế] Phóng châm nhọn chứa độc nấm ma thuật (Hallucinogen). [Hiệu ứng] Gai cắm vào cổ địch (Rất khó phát hiện). Kẻ trúng độc bị ảo giác nặng, thấy đồng đội biến thành quái vật, nổi điên quay súng bắn giết lẫn nhau (Friendly Fire).", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Ảo Giác"], range_type: "Tầm Xa (Đơn mục tiêu/Gây loạn)", combo_tag: "Hallucination_Dart" },
        { name: "Vũng Lầy Axit", desc: "[Cơ chế] Khạc ra khối dịch vị siêu axit. [Hiệu ứng] Trải một vũng chất nhầy sôi sùng sục trên sàn (3x3m). Kẻ nào vô tình dẫm vào sẽ bị ăn mòn rụng đôi chân trong 3 giây, mất khả năng di chuyển và mất máu trầm trọng.", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Nước"], range_type: "Đặt bẫy", combo_tag: "Acid_Puddle" },
        { name: "Xúc Tu Tiêm Thuốc", desc: "[Cơ chế] Biến đổi cánh tay thành xúc tu cơ bắp với kim tiêm ở đầu mút. [Hiệu ứng] Quất xúc tu trói chặt mục tiêu, đâm kim thẳng vào động mạch cổ bơm nọc độc liều cao. Gây Sát thương chuẩn (Bỏ qua giáp) cực lớn và kết liễu nhanh.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 4, unit: "Phút", display_text: "4 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Cận Chiến (Khóa & Kết liễu)", combo_tag: "Venom_Inject" },
        { name: "Sôi Máu", desc: "[Cơ chế] Kích hoạt xúc tác với các độc tố đã ủ sẵn trong người địch. [Hiệu ứng] Nếu kẻ thù đang mang bất kỳ hiệu ứng Độc nào, kích hoạt kỹ năng này sẽ làm độc tố phản ứng đun sôi máu. Gây Nổ Sát Thương cực gắt (Dựa trên số lượt độc đã tích tụ).", rank: "Kim Giai", cost: { type: "MP", value: 95000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Lôi"], range_type: "Tầm Xa (Kích nổ độc)", combo_tag: "Toxic_Detonation" },
        { name: "Kháng Độc (Hỗ trợ)", desc: "[Cơ chế] Dùng cơ thể làm bọt biển hút lọc chất độc. [Hiệu ứng] Đặt tay lên đồng đội, hút toàn bộ độc tố, nguyền rủa, nọc rắn tẩu hỏa nhập ma sang cơ thể mình. Vì bản thân miễn nhiễm độc, kỹ năng này cứu sống đồng đội mà mình không hề hấn gì.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Trị Liệu"], range_type: "Cận chiến (Giải độc)", combo_tag: "Toxin_Absorb" },
        { name: "Vạn Độc Tế Lễ (Bệnh Dịch Ngày Tận Thế)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Giải phóng chủng Virus nguyên thủy bị phong ấn từ Kỷ Nguyên Hắc Ám. [Hiệu ứng] Lây nhiễm siêu cấp trong bán kính 1 Thành Phố. Virus vượt qua mọi màng lọc, giáp bảo hộ, kháng thể. Gây cái chết đen hàng loạt, biến nạn nhân thành xác sống mang bệnh lây cho người khác. [Tác dụng phụ cực lớn] Cơ thể người dùng tự phân rã thành dịch đen hôi thối. Giảm 90% HP, biến thành một phế nhân đi lại gieo rắc sự ghê tởm, bị vạn vật trên đời xa lánh (Charisma = 0 vĩnh viễn), các thế lực thiện/ác đều ra lệnh truy nã cấp SSS.", rank: "Thánh Giai", cost: { type: "HP", value: 8000000 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Sinh Mệnh", "Hắc Ám"], range_type: "Cấp Thế Giới (Bệnh dịch)", combo_tag: "Holy_Pandemic" },
        { name: "Khí Gây Cười/Khóc", desc: "[Cơ chế] Thao túng hệ thống chất dẫn truyền thần kinh Dopamine/Serotonin bằng khí gas. [Hiệu ứng] Địch hít phải sẽ mất kiểm soát cơ mặt và hô hấp. Hoặc cười sằng sặc đến mức chuột rút bụng, không thể vung vũ khí. Hoặc gào khóc thảm thiết ném vũ khí đầu hàng.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Tinh Thần"], range_type: "AoE Nhỏ (Khống chế mềm)", combo_tag: "Emotion_Gas" },
        { name: "Độc Cô Lập (Bệnh Lây Nhiễm)", desc: "[Cơ chế] Chủng độc có từ tính đẩy lùi sinh học. [Hiệu ứng] Kẻ trúng độc biến thành 'trái bom nổ chậm'. Hắn không mất nhiều máu, nhưng bất cứ đồng minh nào đứng gần hắn (<3m) sẽ bị nhiễm phóng xạ nôn mửa chết. Ép đội hình địch phải tự cô lập nhau phá vỡ trận pháp.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Nguyền Rủa"], range_type: "Tầm Xa (Phá đội hình)", combo_tag: "Isolation_Plague" },
        { name: "Thuốc Giải Độc (Crafting)", desc: "[Cơ chế] Vắt máu chứa kháng thể vạn năng pha chế thảo dược. [Hiệu ứng] Kỹ năng chế tạo ngoài chiến đấu. Tạo ra 5 lọ Huyết Thanh vạn năng. Đồng đội uống vào sẽ giải mọi độc, hoặc bôi lên vũ khí để có thêm hiệu ứng độc nhẹ khi chém địch.", rank: "Phàm Giai", cost: { type: "HP", value: 50 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Độc"], range_type: "Chế tạo (Tiện ích)", combo_tag: "Antidote_Craft" },
        { name: "Hủy Diệt Thực Vật (Khắc Mộc)", desc: "[Cơ chế] Phun thuốc diệt cỏ mang ma lực tử vong cường độ cao. [Hiệu ứng] Quét tay một cái, toàn bộ cây cổ thụ, thảm cỏ, dây leo (kể cả yêu thú hệ Mộc) trong bán kính 20m lập tức khô héo, chuyển màu đen và vỡ vụn thành cát bụi. Phá tan chỗ ẩn nấp.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc"], range_type: "AoE Trung (Phá hủy môi trường)", combo_tag: "Defoliant_Agent" },
        { name: "Làm Mềm Kim Loại (Khắc Kim)", desc: "[Cơ chế] Tiết axit Fluoroantimonic biến thể ăn mòn liên kết phân tử sắt. [Hiệu ứng] Phun axit vào song sắt nhà tù, khóa két sắt hoặc vũ khí địch. Kim loại sôi bọt và mềm nhũn ra như kẹo dẻo, dễ dàng bẻ gãy bằng tay không.", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Nước"], range_type: "Cận chiến (Phá vật thể)", combo_tag: "Metal_Melt" },
        { name: "Xác Bom", desc: "[Cơ chế] Bơm khí gas sinh học sinh mủ vào tử thi. [Hiệu ứng] Nhồi chất độc vào 1 xác chết trên chiến trường. Biến cái xác thành quả mìn. Địch lại gần dọn xác hoặc vô ý dẫm trúng, xác chết nổ tung bắn xương thịt dính độc tưa tủa vào mặt chúng.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Hắc Ám"], range_type: "Đặt bẫy (AoE Nhỏ)", combo_tag: "Corpse_Bomb" },
        { name: "Độc Ăn Mòn Mana", desc: "[Cơ chế] Ký sinh trùng năng lượng ăn hạt Mana trong đan điền. [Hiệu ứng] Trúng đòn này, địch không mất máu nhưng lượng MP bị trừ thẳng 5% mỗi giây. Pháp sư hay Tamer hết MP coi như phế nhân, không thể niệm chú hay duy trì Khiên.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Tinh Thần"], range_type: "Tầm Xa (Debuff Năng lượng)", combo_tag: "Mana_Burn_Poison" },
        { name: "Dịch Nhầy Trơn Trượt", desc: "[Cơ chế] Khạc bãi đờm polymer siêu nhớt. [Hiệu ứng] Phủ lên đường đi/cầu thang lớp dịch nhầy. Ma sát bằng 0. Kẻ địch lao tới hoặc bỏ chạy dẫm vào sẽ trượt ngã đập mặt gãy răng, xe cộ sẽ mất lái đâm vào tường.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Nước"], range_type: "Đặt bẫy bề mặt", combo_tag: "Slime_Trap" },
        { name: "Thuốc Kích Thích (Rủi ro)", desc: "[Cơ chế] Tiêm Adrenaline kết hợp ma túy độc hại lừa vỏ não. [Hiệu ứng] Tiêm cho đồng đội. Buff +200% STR, AGI và miễn nhiễm Đau Đớn trong 30 phút để lật kèo. [Nhược điểm] Hết 30 phút, đồng đội bị Trúng Độc Nặng, ói máu, giảm 80% stats (Kiệt sức). Dùng để tử chiến.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Cận chiến (Buff con dao hai lưỡi)", combo_tag: "Toxic_Adrenaline" },
        { name: "Địa Ngục Sương Mù (Tổ Của Bọ Cạp Ác Quỷ)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Mở cổng không gian nhỏ liên kết với Dạ Dày Cự Quái, xả lượng khí thải tử vong. [Hiệu ứng] Phủ một đám mây màu tím sậm khổng lồ bao trùm chiến trường. Bất cứ thứ gì ở bên trong (Trừ người dùng) đều mục rữa. Không khí hóa axit ăn phổi, cây cối héo rũ, chim rơi lộp bộp. [Tác dụng phụ] Hút 80% HP và MP. Hủy hoại giác quan người dùng, dẫn đến điếc/mù tạm thời trong 7 ngày, mất khả năng ăn đồ ăn bình thường (chỉ uống được máu).", rank: "Diệu Giai", cost: { type: "MP", value: 5000000 }, cooldown: { value: 60, unit: "Ngày", display_text: "2 Tháng" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Không Gian"], range_type: "AoE Rất Rộng (Diệt Vong)", combo_tag: "Divine_Miasma" },
        { name: "Hóa Hình - Độc Nhân Yêu", desc: "[Cơ chế] Tái tổ hợp bùn độc và xác chết thành cấu trúc nhân dạng. [Hiệu ứng] Rỉ ra từ vũng chất lỏng lục/tím, tụ lại thành hình nhân kiều diễm (mùi hương cực thơm nhưng chết chóc). Khả năng quyến rũ con người, một nụ hôn sẽ biến nạn nhân thành vũng máu loãng.", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 3, unit: "Ngày", display_text: "3 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Bản thân (Ngụy trang chết chóc)", combo_tag: "Beast_Toxic_Form" },
        { name: "Độc Vụ Sương Nhiễm (Khạc Khói)", desc: "[Cơ chế] Dạ dày nén khí gas kịch độc và khạc qua kẽ răng. [Hiệu ứng] Phun khói độc màu tím. Ăn mòn phổi, gây ho ra máu và trừ HP liên tục trong 2 giờ. Khói luồn lách qua khe hở giáp của lính UHA.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Phong"], range_type: "Hình Nón Trung", combo_tag: "Toxic_Breath" },
        { name: "Nọc Độc Thần Kinh", desc: "[Cơ chế] Cắn bằng nanh tẩm nọc (Như rắn/nhện). [Hiệu ứng] Đâm thủng da và bơm nọc. Làm tê liệt hệ thần kinh vận động. Địch cứng đờ, không thể ra chiêu vật lý hay bỏ chạy. Sát thương cắn không lớn nhưng khống chế cực mạnh.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Sinh Học"], range_type: "Cận Chiến (Khống chế cứng)", combo_tag: "Beast_Neurotoxin" },
        { name: "Quả Bom Bào Tử Nhọt", desc: "[Cơ chế] Khạc cục mủ nhọt tụ dưới cổ họng. [Hiệu ứng] Ném quả bóng nước đầy dịch hạch. Nổ tung văng dịch bệnh tứ tung, gây mù lòa và lở loét (Trừ máu theo % thời gian). Rất tởm lợm phá vỡ tâm lý lính đánh thuê.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Độc"], range_type: "Tầm Xa (Đạn nổ/AoE Nhỏ)", combo_tag: "Pus_Bomb" },
        { name: "Mưa Axit Khắc Cốt (AoE Hoang Dã)", desc: "[Cơ chế] Rống lên bầu trời, bắn tuyến nọc độc lên mây để tạo mưa nhân tạo. [Hiệu ứng] Thay đổi khí hậu khu vực hẹp. Mưa axit xối xả thiêu rụi thảm thực vật, nấu chảy lính canh gác trên tháp canh đến tận xương cốt.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 80000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Nước"], range_type: "AoE Rộng (Sát thương hủy diệt)", combo_tag: "Beast_Acid_Rain" },
        { name: "Độc Thủy Độn (Tàn Sát Ngầm)", desc: "[Cơ chế] Lặn xuống hồ nước/mạch nước ngầm và xả van nọc độc ở bụng. [Hiệu ứng] Trộn lẫn độc tố không màu không mùi vào nguồn nước. Giết chết mọi sinh vật/quân lính uống phải từ xa (Hàng km). Gây tử vong hàng loạt âm thầm.", rank: "Ngân Giai", cost: { type: "Stamina", value: 5000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Nước"], range_type: "Đầu độc môi trường", combo_tag: "Water_Contaminate" },
        { name: "Xúc Tu Tiết Dịch (Bắt mồi)", desc: "[Cơ chế] Phóng đuôi/lưỡi hình xúc tu. [Hiệu ứng] Quấn chặt con mồi lôi về phía mình, các giác hút trên xúc tu liên tục bơm axit dạ dày phân hủy mạch máu khiến con mồi mềm nhũn ra trước khi bị nuốt.", rank: "Thiết Giai", cost: { type: "Stamina", value: 300 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Vật Lý"], range_type: "Tầm Trung (Bắt cóc/Trói)", combo_tag: "Tentacle_Acid" },
        { name: "Khuếch Tán Độc Tố (Nổ Xác)", desc: "[Cơ chế] Kích thích phản ứng enzyme trên xác quái vật đã nhiễm độc. [Hiệu ứng] Làm nổ tung cái xác phình to, lây lan độc tính chết chóc sang toàn bộ bầy đàn quái vật/đồng minh đang xúm lại dọn xác. Bẫy xác hoàn hảo.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Sinh Học"], range_type: "AoE Trung (Kích nổ bẫy)", combo_tag: "Toxic_Corpse_Burst" },
        { name: "Kháng Dược Thể (Nội Tại)", desc: "[Cơ chế] Gen đã tiến hóa vượt bậc qua hàng ngàn thế hệ ăn nọc độc. [Hiệu ứng] Miễn nhiễm tuyệt đối với mọi loại độc tố, khí gas nấm, nọc nhện của thế giới hoang dã. Bơi trong hồ axit như bơi trong suối nước nóng.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc"], range_type: "Bản thân (Kháng tính tuyệt đối)", combo_tag: "Absolute_Poison_Resist" },
        { name: "Móng Vuốt Tử Thi", desc: "[Cơ chế] Vuốt dài tiết ra hợp chất hoại tử thịt (Necrotizing fasciitis). [Hiệu ứng] Đòn vả xé rách da. Vết thương lập tức bốc mùi thối rữa, không bao giờ cầm được máu và không thể hồi phục bằng phép trị liệu ánh sáng. Trừ HP max vĩnh viễn.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3800 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Độc", "Vật Lý"], range_type: "Cận Chiến (Debuff Vết thương trầm trọng)", combo_tag: "Necrotic_Claw" },
        { name: "Chướng Khí Ăn Sanity", desc: "[Cơ chế] Hơi thở mang sóng ma lực tâm linh kết hợp hạt độc. [Hiệu ứng] Phun khói xám. Không trừ máu (HP) nhưng ăn mòn trực tiếp Lý Trí (Sanity). Kẻ hít phải sẽ thấy ảo ảnh kinh dị, hoảng loạn, nếu Sanity về 0 sẽ hóa điên cắn xé đồng đội.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 65000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Tinh Thần"], range_type: "AoE Trung (Tấn công Tâm Trí)", combo_tag: "Sanity_Eater_Gas" },
        { name: "Giải Độc Cắn Ngược", desc: "[Cơ chế] Răng mang hai ống tiết: Một ống hút, một ống bơm nọc. [Hiệu ứng] Cắn vào đồng đội để hút hết nọc độc, lưu trữ trong má. Sau đó cắn kẻ thù và bơm x2 lượng nọc độc đó sang chúng. Phép hỗ trợ lật kèo kinh điển.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Độc", "Trị Liệu"], range_type: "Cận Chiến (Hỗ trợ/Phản công)", combo_tag: "Venom_Transfer" }
    ],

  "Hệ Cường Hóa": [
        { name: "Hóa Hình - Chiến Thần", desc: "[Cơ Chế Sinh Học] Viết lại mã gen, loại bỏ gen ức chế cơ bắp (Myostatin). Tăng mật độ xương và sợi cơ đỏ lên gấp 5 lần. [Cấu Tạo] Tim to khỏe bơm máu áp lực cao, phổi lọc oxy tuyệt đối. Giác quan nhạy bén. [Hình Thái] Vạm vỡ, tỉ lệ vàng, cơ bắp cuồn cuộn. [Hiệu ứng] Sức mạnh thể chất áp đảo, có thể tay không bẻ gãy sắt thép. [Tác dụng phụ] Cần lượng thức ăn khổng lồ mỗi ngày để duy trì cơ bắp, nếu Hunger > 50 sẽ mất 50% sức mạnh.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Warrior" },
        { name: "Đồng Bì Thiết Cốt", desc: "[Cơ chế] Mật độ canxi và mô liên kết cơ được nén chặt vĩnh viễn. [Hiệu ứng] Tăng 20% Chỉ số Phòng thủ (DEF) vật lý vĩnh viễn. Giảm 50% tỉ lệ bị các hiệu ứng đứt lìa chi (Chặt tay/chân) bởi vũ khí sắc bén.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Bị động tăng giáp)", combo_tag: "Passive_Iron_Bone" },
        { name: "Chiến Thần Chi Tâm", desc: "[Cơ chế] Cơ tâm nhĩ dày gấp đôi người thường, bơm oxy cực đại. [Hiệu ứng] Tốc độ hồi phục Thể lực (Stamina) tăng 30% trong chiến đấu. Tuyệt đối không bao giờ bị Nhồi máu cơ tim hay ngất xỉu vì kiệt sức đột ngột.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Bị động hồi sức)", combo_tag: "Passive_Warrior_Heart" },
        { name: "Kim Cang Bất Hoại", desc: "[Cơ chế] Lớp mỡ và cơ bắp đan chéo phân tán động năng. [Hiệu ứng] Nhảy từ tầng 3 xuống đất hoặc bị một con Lợn Rừng Húc trúng cũng không mất máu. Miễn nhiễm 100% Sát thương rơi ngã (Fall damage) và giảm sát thương va đập cùn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Bản thân (Bị động giảm xóc)", combo_tag: "Passive_Impact_Resist" },
        { name: "Khai Sơn Phách Lực", desc: "[Cơ chế] Kích hoạt 100% sợi cơ đỏ mà não bộ vốn dĩ khóa lại. [Hiệu ứng] Các đòn đánh thường (Basic Attack) bằng tay không/vũ khí đập có 20% tỉ lệ phá vỡ Thế Phòng Ngự (Block/Guard) của kẻ địch, làm chúng lảo đảo.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Đòn đánh (Bị động phá thủ)", combo_tag: "Passive_Overwhelm_Force" },
        { name: "Cự Kình Thôn Tức", desc: "[Cơ chế] Phổi có khả năng giãn nở và nén không khí siêu việt. [Hiệu ứng] Có thể nín thở dưới nước hoặc trong môi trường khí độc lên tới 30 phút mà không hề suy giảm chỉ số. Tốc độ phục hồi khi hít thở lại tăng x2.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Sinh Tồn"], range_type: "Bản thân (Bị động hô hấp)", combo_tag: "Passive_Whale_Lung" },
        { name: "Huyết Chiến Cuồng Nộ", desc: "[Cơ chế] Adrenaline sinh học đặc chế tiết ra khi cận kề cái chết. [Hiệu ứng] Khi HP rớt xuống dưới 20%, Tốc độ đánh (AGI) và Sức mạnh (STR) lập tức tăng thêm 40%. Không bị ảnh hưởng bởi nỗi đau.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Bị động tử chiến)", combo_tag: "Passive_Survival_Berserk" },
        { name: "Đạn Lực Cân Cốt", desc: "[Cơ chế] Dây chằng và gân đạt độ đàn hồi của sợi carbon. [Hiệu ứng] Tăng 30% khoảng cách nhảy xa/nhảy cao. Mọi đòn lao tới (Charge) sẽ gây thêm sát thương vật lý tỉ lệ thuận với khoảng cách đã lấy đà.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Bản thân (Bị động bật nhảy/Động năng)", combo_tag: "Passive_Spring_Tendon" },
        { name: "Thôn Phệ Vạn Vật", desc: "[Cơ chế] Axit dạ dày phân giải mọi chất hữu cơ sống/chết. [Hiệu ứng] Ăn thịt sống, thịt thối rữa, lá độc không bao giờ bị Trúng Độc. Chuyển hóa 100% thức ăn rác thành Máu (HP) và Năng lượng (MP) hoàn hảo.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Bị động sinh tồn)", combo_tag: "Passive_Iron_Gut" },
        { name: "Tái Tạo Huyết Mạch", desc: "[Cơ chế] Tiểu cầu và bạch cầu siêu nhân hóa hoạt động không ngừng. [Hiệu ứng] Bất kỳ vết thương hở nào (bị chém, đâm) sẽ tự động ngưng chảy máu sau 3 giây. Hồi máu tự nhiên (HP Regen) ngoài giao tranh cực nhanh.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Bị động cầm máu)", combo_tag: "Passive_Blood_Regen" },
        { name: "Bất Động Như Sơn", desc: "[Cơ chế] Cảm nhận tiền đình hoàn hảo, luôn giữ thăng bằng. [Hiệu ứng] Kháng 80% mọi hiệu ứng Làm Ngã (Knock-down), Vấp ngã. Không bị lảo đảo khi bước trên băng trơn trượt hay môi trường rung lắc (Động đất).", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Bản thân (Bị động thăng bằng)", combo_tag: "Passive_Solid_Stance" },
        { name: "Thiên Cân Cự Quyền", desc: "[Cơ chế] Nén cơ bắp tay tới giới hạn trước khi bung lực. [Hiệu ứng] Nắm đấm tay không (Unarmed) của bạn gây sát thương tương đương với khi cầm một chiếc Búa tạ sắt. Không cần vũ khí vẫn đấm vỡ sọ quái thú.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Cận Chiến tay không (Bị động)", combo_tag: "Passive_Heavy_Fist" },
        { name: "Tiên Thiên Kháng Thể", desc: "[Cơ chế] Hệ miễn dịch tiến hóa chống lại sự biến đổi ma lực ngoại lai. [Hiệu ứng] Giảm 20% thời gian tác dụng của mọi kỹ năng Khống chế (Stun, Freeze, Paralyze) và Debuff (Trừ giáp, Trừ công) từ đối phương.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Bị động giảm CC)", combo_tag: "Passive_Natural_Resist" },
        { name: "Chiến Thần Uy Áp", desc: "[Cơ chế] Cơ bắp nở nang và sát khí chiến trận tỏa ra vô hình. [Hiệu ứng] Kẻ địch hình người (Humanoid/Lính) nhìn thấy cơ thể bạn sẽ sinh ra sự e dè. Đòn đánh đầu tiên của chúng vào bạn luôn bị giảm 15% Sát thương vì run tay.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Tinh Thần"], range_type: "Xung quanh (Bị động áp chế)", combo_tag: "Passive_Intimidating_Presence" },
        { name: "Sinh Tử Bản Năng", desc: "[Cơ chế] Dây thần kinh tủy sống tự động kích hoạt né đòn mà không cần qua não. [Hiệu ứng] Tăng 10% Tỉ lệ Né (Dodge) đối với các đòn đánh lén từ điểm mù hoặc đạn bay siêu tốc. Cơ thể tự nghiêng để tránh tử huyệt.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Bị động né tránh)", combo_tag: "Passive_Death_Reflex" },
        { name: "Thiết Trảo Tử Khóa", desc: "[Cơ chế] Gân ngón tay khóa chặt như mỏ lết thủy lực. [Hiệu ứng] Một khi đã dùng kỹ năng Khóa/Ôm (Grapple) hay đu bám lên thân quái vật khổng lồ, kẻ địch dù giẫy giụa mạnh đến đâu cũng không thể hất văng bạn xuống.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận chiến (Bị động bám dính)", combo_tag: "Passive_Iron_Grip" },
        { name: "Cuồng Bạo Liên Kích", desc: "[Cơ chế] Nhịp tim đồng điệu với nhịp đấm, tạo đà quán tính. [Hiệu ứng] Càng đánh liên tục trúng cùng 1 mục tiêu, sát thương vật lý của bạn càng tăng (+2% mỗi hit, cộng dồn vô hạn). Reset ngay khi bạn trượt hoặc đổi mục tiêu.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Đòn đánh (Bị động sát thương)", combo_tag: "Passive_Combo_Violence" },
        { name: "Man Ngưu Cự Lực", desc: "[Cơ chế] Cột sống thẳng và chịu lực nén tuyệt đối. [Hiệu ứng] Tăng gấp 3 lần giới hạn trọng lượng hành trang (Inventory Weight Limit). Vác thêm 2 đồng đội bị thương trên vai vẫn chạy nước rút được bình thường.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Bị động hành trang)", combo_tag: "Passive_Mule_Strength" },
        { name: "Cương Bì Thiết Giáp", desc: "[Cơ chế] Ma sát lâu ngày biến biểu bì thành lớp giáp chai sần siêu cứng. [Hiệu ứng] Giảm 100% Sát thương từ các đòn cào cấu, cắt nhẹ (như gai độc, ám khí). Mũi tên gỗ không bọc thép bắn vào chỉ gãy làm đôi chứ không thủng da.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Bị động kháng vật lý nhẹ)", combo_tag: "Passive_Callous_Armor" },
        { name: "Hồi Toàn Phản Kích", desc: "[Cơ chế] Cấu trúc cơ đùi hấp thụ lực đẩy của mặt đất. [Hiệu ứng] Ngay sau khi thực hiện động tác Lộn Vòng (Roll) để né đòn, đòn chém trả lại ngay tức khắc sẽ được Xuyên 15% Giáp (Armor Penetration) của mục tiêu.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Sau né tránh (Bị động đâm xuyên)", combo_tag: "Passive_Roll_Strike" },
        { name: "Dục Huyết Cuồng Ma", desc: "[Cơ chế] Chuyển đổi tín hiệu đau từ dây thần kinh thành Dopamine hưng phấn. [Hiệu ứng] Bị thương càng nặng, bạn càng kháng khống chế tốt. Mỗi 10% HP mất đi, Kháng Hiệu Ứng (Tenacity) tăng thêm 5%. Gần như miễn khống khi kề chết.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Bị động miễn khống)", combo_tag: "Passive_Pain_Enjoyer" },
        { name: "Cú Đấm Lực Sĩ", desc: "[Cơ chế] Gồng bắp tay dồn máu, loại bỏ chốt an toàn cơ học. [Hiệu ứng] Tung cú đấm vật lý thuần túy. Xé rách khiên mộc, đập vỡ xương sườn địch. Lực đẩy (Knockback) làm kẻ thù lùi lại 2 bước ngắt niệm chú.", rank: "Phàm Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 4, unit: "Giây", display_text: "4 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Ngắt chiêu/Đẩy)", combo_tag: "Heavy_Punch" },
        { name: "Tăng Tốc Nhất Thời", desc: "[Cơ chế] Bơm Adrenaline làm tăng nhịp tim kích thích cơ bắp chân đùi. [Hiệu ứng] Tốc độ chạy (AGI) tăng vọt 50% trong 5 giây. Đủ để lướt né đòn đại pháo nổ hoặc lao vào bắt gọn Pháp sư đối phương.", rank: "Phàm Giai", cost: { type: "Stamina", value: 20 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Buff Tốc độ)", combo_tag: "Burst_Sprint" },
        { name: "Gồng Cơ Bắp Đá", desc: "[Cơ chế] Căng cứng toàn bộ 600 múi cơ, ép chặt lớp mỡ và da. [Hiệu ứng] Tăng 100 DEF vật lý trong 10 giây. Đạn cung tên, đao kiếm chém sượt qua chỉ rách da ngoài không chạm được tới tủy.", rank: "Thiết Giai", cost: { type: "Stamina", value: 35 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Buff Chống chịu)", combo_tag: "Muscle_Armor" },
        { name: "Vả Trọng Thương", desc: "[Cơ chế] Cú tát vòng cung bằng má bàn tay mang sức nặng ngàn cân. [Hiệu ứng] Tát vào mang tai địch. Gây Choáng (Stun) nửa giây và Chấn động não (Giảm 20% khả năng dùng phép trong 3 giây tới).", rank: "Thiết Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Choáng/Debuff não)", combo_tag: "Concussion_Slap" },
        { name: "Cước Lực Cực Đại", desc: "[Cơ chế] Dồn động năng vặn hông tung cú đá tạt (Roundhouse Kick). [Hiệu ứng] Đạp bay một con sói lớn văng vào tường nát xương. Xuyên thủng phòng ngự khiên gỗ/sắt mỏng. Khắc tinh của bọn cầm khiên.", rank: "Thiết Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Hất văng Xuyên Giáp)", combo_tag: "Breaker_Kick" },
        { name: "Gào Thét Chiến Trận", desc: "[Cơ chế] Hét lớn mở rộng phế nang, bơm oxy bùng nổ. [Hiệu ứng] Buff AoE. Xóa sạch mọi hiệu ứng Sợ Hãi (Fear) cho 3 đồng đội. Tăng 10% sát thương đòn đánh cơ bản của cả team trong 10 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Sóng Âm"], range_type: "AoE Trung (Giải CC/Buff ST)", combo_tag: "Battle_Cry_Rally" },
        { name: "Bước Nhảy Khổng Lồ", desc: "[Cơ chế] Nhún gập đầu gối bùng nổ lực chân như lò xo. [Hiệu ứng] Nhảy xa 10m trên không trung hoặc vọt thẳng lên nóc nhà. Vượt chướng ngại vật cực kỳ linh hoạt (Blink theo chiều dọc/ngang).", rank: "Phàm Giai", cost: { type: "Stamina", value: 25 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Di chuyển dọc)", combo_tag: "Giant_Leap" },
        { name: "Khóa Xiết Cổ", desc: "[Cơ chế] Kẹp tay hình kìm, ép nghẹt động mạch cảnh. [Hiệu ứng] Chồm tới ôm cổ địch. Cả 2 đều đứng yên (Stun), nhưng địch sẽ liên tục nghẹt thở, mất HP. Phép ma thuật bị Câm Lặng (Silence) do không thể thở.", rank: "Thiết Giai", cost: { type: "Stamina", value: 35 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Khống chế cứng/1-đổi-1)", combo_tag: "Chokehold_Pin" },
        { name: "Giậm Chân Chấn Động", desc: "[Cơ chế] Dậm gót giáng uy lực ngàn cân xuống mảng đất. [Hiệu ứng] Sàn nhà nứt toác. Mọi kẻ địch trong bán kính 2m sẽ bị hất ngã lộn nhào (Choáng 1s). Hủy nhịp độ tấn công của đám đông vây quanh.", rank: "Thiết Giai", cost: { type: "Stamina", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Thổ"], range_type: "AoE Nhỏ (Hất ngã AoE)", combo_tag: "Stomp_Quake" },
        { name: "Lì Lợm Đỡ Đòn", desc: "[Cơ chế] Khóa cảm giác đau, gồng vai đỡ thẳng đao kiếm. [Hiệu ứng] Giảm 50% sát thương của 1 đòn vật lý chí mạng sắp tới. Nhân vật không lùi bước, sẵn sàng vung tay trả đòn lập tức.", rank: "Phàm Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Phòng ngự chủ động)", combo_tag: "Face_Tank" },
        { name: "Ném Đạn Người", desc: "[Cơ chế] Kéo bắp tay tóm lấy vật thể nặng 100kg và ném đi. [Hiệu ứng] Bắt lấy tên lính yếu hoặc quái vật nhỏ ném sầm vào quân địch. Sát thương va đập ngã rạp 3-4 mục tiêu như ném tạ bowling.", rank: "Thiết Giai", cost: { type: "Stamina", value: 50 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Tầm Trung (Ném vật thể)", combo_tag: "Throw_Body" },
        { name: "Vai Húc Mở Đường", desc: "[Cơ chế] Hạ thấp trọng tâm, chĩa vai ra phía trước như xe bò đụng. [Hiệu ứng] Lao vọt đi (Charge). Cày nát đội hình lính bộ binh giáp nhẹ, húc văng chúng sang hai bên, phá tan chướng ngại vật mở đường cho Xạ thủ.", rank: "Thiết Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Đường thẳng (Charge mở đường)", combo_tag: "Shoulder_Bash" },
        { name: "Thở Dốc Hồi Lực", desc: "[Cơ chế] Kỹ thuật hít thở 3 nhịp sâu ép thanh lọc Axit Lactic. [Hiệu ứng] Đứng im nửa giây hít thở. Lập tức hồi phục 40 điểm Stamina. Kỹ năng thiết yếu để đánh dai dẳng không bị kiệt sức.", rank: "Phàm Giai", cost: { type: "MP", value: 15 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Sinh Mệnh"], range_type: "Bản thân (Hồi Stamina)", combo_tag: "Second_Wind" },
        { name: "Đập Kiếm Bằng Tay", desc: "[Cơ chế] Dùng hai lòng bàn tay kẹp chặt vũ khí đang chém tới. [Hiệu ứng] Tay không bắt bạch đao. Chặn 100% đòn chém thẳng. Làm đối phương khựng lại, mở góc chết để đồng đội thọc sườn.", rank: "Thiết Giai", cost: { type: "Stamina", value: 35 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Cận Chiến (Đỡ đòn tuyệt đối)", combo_tag: "Blade_Catch" },
        { name: "Ngụy Trang Yếu Ớt", desc: "[Cơ chế] Co cụm cơ bắp, ép xương lồng ngực thụp xuống giả lả. [Hiệu ứng] Tỏa ra khí tức của một con thú yếu ớt sắp chết. Kẻ địch mạnh hơn sẽ coi thường không muốn đánh, hoặc dụ địch áp sát để lật kèo phản công.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Ảo Giác"], range_type: "Bản thân (Đánh lừa Aggro)", combo_tag: "Fake_Weakness" },
        { name: "Đầu Thiết Công", desc: "[Cơ chế] Cứng hóa sọ trán dồn lực cắm sừng/đầu về phía trước. [Hiệu ứng] Đánh cận chiến cực gắt cự ly 10cm. Làm móp mũ giáp, đập vỡ mũi địch khiến chúng Choáng váng nặng, chảy máu ròng ròng.", rank: "Thiết Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Chấn thương)", combo_tag: "Headbutt_Smash" },
        { name: "Treo Cổ Mạo Hiểm", desc: "[Cơ chế] Quặp hai chân ngang cổ địch vặn xoắn. [Hiệu ứng] Nhảy bám lên đầu một Cự thú hoặc tên lính to xác. Đu bám gây sát thương nghẹt thở. Cực kỳ nguy hiểm nếu địch có chiêu hất văng gai góc.", rank: "Thiết Giai", cost: { type: "Stamina", value: 45 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Cận Chiến (Đu bám/Khống chế)", combo_tag: "Neck_Scissors" },
        { name: "Phản Xạ Hoang Dã", desc: "[Cơ chế] Mở khóa tủy sống tự động né đòn không qua não. [Hiệu ứng] Tăng 30% tỷ lệ Né tránh (Dodge) đối với đạn bay, cung tên nấp bắn lén. Rất thích hợp khi lao qua mưa đạn của UHA.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Buff Né tránh)", combo_tag: "Feral_Reflex_Lite" },
        { name: "Cào Rách Đất Cát", desc: "[Cơ chế] Dùng tay/vuốt cào mạnh xuống nền đá. [Hiệu ứng] Văng sỏi cát tung tóe thẳng mặt địch. Chiêu hèn hạ nhưng làm Mù lòa (Blind) mắt 1s, cắt đứt đà lao tới của kỵ binh.", rank: "Phàm Giai", cost: { type: "Stamina", value: 15 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Thổ"], range_type: "Hình Nón Cận Chiến (Gây Mù)", combo_tag: "Dirt_Scratch" },
        { name: "Cắn Xé Khát Máu", desc: "[Cơ chế] Trương hàm vồ xé con mồi để hít mùi máu tươi. [Hiệu ứng] Đòn kết liễu. Nếu kẻ địch có HP < 20%, cú cắn xé này x2 sát thương vật lý và hồi cho bản thân 10 điểm Sanity vì hưng phấn.", rank: "Thiết Giai", cost: { type: "Stamina", value: 50 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Cận Chiến (Kết liễu/Hồi Sanity)", combo_tag: "Blood_Rend" },
        { name: "Đấm Nghiền Nát", desc: "[Cơ chế] Tụ lực xoắn cơ bắp từ gót chân lên hông và vung tay với tốc độ xé gió. [Hiệu ứng] Cú đấm vật lý thuần túy. Phá vỡ giáp Kevlar, gây nứt xương sườn và tạo sóng xung kích nhỏ đẩy lùi mục tiêu phía sau lưng kẻ bị đấm.", rank: "Thiết Giai", cost: { type: "Stamina", value: 150 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến", combo_tag: "Crush_Punch" },
        { name: "Tốc Biến (Dash)", desc: "[Cơ chế] Dồn lực ép co thắt tối đa vào cơ đùi và bắp chân. [Hiệu ứng] Lướt đi cực nhanh về phía trước một khoảng 15m, để lại tàn ảnh. Dùng để né đòn hoặc áp sát Xạ thủ/Pháp sư đối phương trong chớp mắt.", rank: "Thiết Giai", cost: { type: "Stamina", value: 180 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Phong"], range_type: "Bản thân (Di chuyển)", combo_tag: "Muscle_Dash" },
        { name: "Cơ Thể Kim Cương", desc: "[Cơ chế] Gồng cứng toàn bộ bó cơ, loại bỏ bọt khí giữa các thớ thịt. [Hiệu ứng] Chặn đứng mọi đòn tấn công vật lý chém/đâm cấp thấp. Giảm 80% sát thương vật lý nhận vào trong 10 phút. Cơ thể không thể bị đẩy lùi.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Buff phòng thủ)", combo_tag: "Diamond_Body" },
        { name: "Hồi Phục Siêu Tốc", desc: "[Cơ chế] Kích thích tuyến yên, ép tế bào phân chia với tốc độ ung thư nhưng có kiểm soát. [Hiệu ứng] Vết chém sâu tự khép miệng, đạn bị đẩy ra khỏi thịt. Hồi 30% Max HP trong 5 giây. [Nhược điểm] Cực kỳ tốn thể lực và gây đói (Tăng 20 Hunger).", rank: "Ngân Giai", cost: { type: "Stamina", value: 4000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Hồi máu)", combo_tag: "Hyper_Regen" },
        { name: "Tiếng Gầm Chiến Trận", desc: "[Cơ chế] Lấy hơi sâu đẩy qua thanh quản cấu trúc đặc biệt. [Hiệu ứng] Gầm lên tiếng rống áp đảo. Làm choáng (Stun) 1 giây kẻ địch xung quanh có STR thấp hơn. Đồng thời buff +30% STR và AGI cho toàn bộ đồng đội đang nghe thấy.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Sóng Âm"], range_type: "AoE Trung (Buff/Khống chế)", combo_tag: "Battle_Cry" },
        { name: "Nhảy Vọt", desc: "[Cơ chế] Biến đôi chân thành lò xo sinh học vĩ đại. [Hiệu ứng] Nhảy xa hàng trăm mét hoặc vọt thẳng lên nóc tòa nhà cao 10 tầng. Vượt địa hình đứt gãy, thoát khỏi vòng vây hoặc phục kích từ trên không.", rank: "Thiết Giai", cost: { type: "Stamina", value: 300 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Di chuyển dọc/ngang)", combo_tag: "Super_Jump" },
        { name: "Vật Lộn (Grapple)", desc: "[Cơ chế] Sử dụng kỹ thuật khóa siết (Jiu-jitsu) kết hợp sức mạnh cơ bắp tuyệt đối. [Hiệu ứng] Lao vào ôm chặt đối phương. Khóa tay chân, bóp cổ gây ngạt thở. Ép mục tiêu nhận sát thương nghẹt thở mỗi giây và không thể dùng ấn chú ma pháp (Khóa tay).", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Khống chế 1-1)", combo_tag: "Death_Grapple" },
        { name: "Dậm Chân Sóng Xung Kích", desc: "[Cơ chế] Dậm mạnh bàn chân chứa sức mạnh ngàn cân xuống mặt đất. [Hiệu ứng] Tạo làn sóng chấn động vật lý mặt đất hình vòng tròn bán kính 10m. Phá vỡ thế đứng, hất văng mọi kẻ địch và hủy diệt bẫy rập dưới đất.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3800 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Thổ"], range_type: "AoE Trung (Hất văng)", combo_tag: "Shockwave_Stomp" },
        { name: "Bàn Tay Hủy Diệt (Mở Khóa Giới Hạn Gene)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Xóa bỏ hoàn toàn 'Chốt an toàn' của não bộ bảo vệ cơ thể, kích hoạt 100% sợi cơ đỏ. [Hiệu ứng] Đạt sức mạnh xé rách không gian bằng tay không. Tung ra 1000 cú đấm trong 1 giây (như Star Platinum), đập nát một Cự Thú Lãnh Chúa thành vũng máu, hoặc đấm sập cả một ngọn núi ngăn đường. [Tác dụng phụ] Cơ bắp hai cánh tay nổ tung thành sương máu vì vượt quá sức chịu đựng của vật chất. Vĩnh viễn tàn phế hai tay (Giảm 80% STR) cho đến khi tìm được thần dược tái tạo cấp Thánh.", rank: "Diệu Giai", cost: { type: "Stamina", value: 5000000 }, cooldown: { value: 180, unit: "Ngày", display_text: "Nửa Năm" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Sát thương Tối Hậu)", combo_tag: "Divine_Limit_Break" },
        { name: "Đánh Vào Điểm Yếu", desc: "[Cơ chế] Áp dụng kiến thức giải phẫu học sinh vật vào thực chiến. [Hiệu ứng] Nhãn lực tự động đánh dấu các khớp nối giáp, huyệt đạo, gân mạch đối thủ. Đòn đánh tiếp theo chắc chắn là Bạo Kích (Critical Hit) và bỏ qua 50% DEF.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Trí Tuệ"], range_type: "Bản thân (Buff Xuyên Giáp)", combo_tag: "Weakpoint_Strike" },
        { name: "Kháng Phép (Thể Phách Tiên Thiên)", desc: "[Cơ chế] Rung động cơ bắp tần số siêu cao để tán xé năng lượng ma pháp. [Hiệu ứng] Gồng mình đánh tan mọi tác động của ma pháp trói buộc (Rễ cây, Băng phong, Đất lún). Giảm 50% sát thương từ kỹ năng nguyên tố.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Giải khống chế)", combo_tag: "Magic_Resist_Flex" },
        { name: "Húc Đầu", desc: "[Cơ chế] Cường hóa hộp sọ độ cứng tương đương kim cương. [Hiệu ứng] Nắm cổ áo địch và tung cú 'Thiết Đầu Công' hoặc lấy đà húc như tê giác. Làm vỡ nát khiên năng lượng, đập móp mũ bảo hiểm, gây Choáng (Stun) nặng cho địch.", rank: "Thiết Giai", cost: { type: "Stamina", value: 120 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến", combo_tag: "Headbutt_Breaker" },
        { name: "Đạp Gãy Xương", desc: "[Cơ chế] Nhảy lên cao và dồn toàn bộ trọng lượng vào gót chân (Cú Dropkick). [Hiệu ứng] Đạp từ trên không trung xuống ngực hoặc khớp gối kẻ thù. Sát thương nhân lên theo độ cao rơi. Đạp gãy chân mục tiêu, vô hiệu hóa hoàn toàn AGI của chúng.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3200 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Tấn công từ trên cao)", combo_tag: "Bone_Break_Kick" },
        { name: "Không Biết Đau (Passive)", desc: "[Cơ chế] Adrenaline ngập tràn, tự động khóa hoàn toàn thụ thể cảm giác đau. [Hiệu ứng] Bị chém đứt nửa thân vẫn giữ nguyên 100% chỉ số sức mạnh và tốc độ. Không lùi bước, không bị hoảng sợ bởi sát thương. Chỉ gục ngã khi HP = 0.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Sinh Mệnh"], range_type: "Bản thân (Nội tại chiến đấu)", combo_tag: "Pain_Immunity" },
        { name: "Khát Máu (Cuồng Chiến Sĩ)", desc: "[Cơ chế] Ngửi thấy mùi máu sẽ kích thích nhịp tim và tiết hormone bạo lực. [Hiệu ứng] Càng đánh càng hăng. Cứ mỗi 10% HP mục tiêu mất đi, sức tấn công (STR) của bản thân tăng thêm 5%. Cực kỳ mạnh trong các trận kéo dài.", rank: "Ngân Giai", cost: { type: "Stamina", value: 2000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Buff cộng dồn)", combo_tag: "Bloodthirst_Stack" },
        { name: "Vác Nặng (Utility)", desc: "[Cơ chế] Thay đổi kết cấu cột sống để chịu tải trọng phi lý. [Hiệu ứng] Khả năng khuân vác (Inventory Weight Limit) tăng gấp 10 lần. Vác xe tải, khiêng tảng đá khổng lồ chắn đường, hoặc cõng 4 đồng đội trên vai chạy bộ xuyên rừng không biết mệt.", rank: "Phàm Giai", cost: { type: "Stamina", value: 50 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Tiện ích (Logistics/Di chuyển)", combo_tag: "Heavy_Lifter" },
        { name: "Phá Khóa Thủ Công", desc: "[Cơ chế] Kẹp tay và vận dụng lực đòn bẩy. [Hiệu ứng] Không cần chìa khóa ma thuật, dùng tay không vặn gãy cổ khóa sắt, bẻ cong song sắt cửa sổ nhà tù như bẻ đũa tre.", rank: "Phàm Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Cận Chiến (Tiện ích)", combo_tag: "Manual_Breach" },
        { name: "Dạ Dày Sắt", desc: "[Cơ chế] Axit dạ dày mạnh hóa ngang ngửa loài kền kền. [Hiệu ứng] Sinh tồn đỉnh cao. Ăn được thịt thối, đồ ôi thiu, cỏ dại, vỏ cây, côn trùng độc mà không bị đau bụng hay Trúng Độc. Chuyển hóa mọi thứ thành Calories.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Sinh tồn)", combo_tag: "Iron_Stomach" },
        { name: "Leo Trèo", desc: "[Cơ chế] Bơm máu tăng cường cơ ngón tay và móng chân. [Hiệu ứng] Bám ngón tay vào các khe nứt nhỏ xíu trên vách núi thẳng đứng. Leo trèo bề mặt kính/tòa nhà trọc trời thoăn thoắt như loài thằn lằn.", rank: "Phàm Giai", cost: { type: "Stamina", value: 20 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Di chuyển địa hình)", combo_tag: "Climb_Wall" },
        { name: "Ném Xa", desc: "[Cơ chế] Động tác ném chuẩn xác áp dụng lực ly tâm tuyệt đối. [Hiệu ứng] Ném một viên đá cuội hoặc ngọn giáo với lực và độ chính xác ngang ngửa súng ngắm. Có thể bắn hạ chim đang bay hoặc ném đá thủng đầu địch cách xa 300m.", rank: "Thiết Giai", cost: { type: "Stamina", value: 100 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Tầm Xa (Tấn công)", combo_tag: "Sniper_Throw" },
        { name: "Nín Thở", desc: "[Cơ chế] Làm chậm nhịp tim, ngâm oxy vào từng tế bào cơ bắp. [Hiệu ứng] Nhịn thở liên tục trong 30 phút. Giúp lặn sâu xuống đáy biển không cần bình dưỡng khí, hoặc bình an vô sự đi xuyên qua đám mây khí độc hệ Độc Dược.", rank: "Phàm Giai", cost: { type: "Stamina", value: 50 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Sinh tồn)", combo_tag: "Hold_Breath" },
        { name: "Sưởi Ấm", desc: "[Cơ chế] Kích hoạt rung động sợi cơ vi mô (Thermogenesis). [Hiệu ứng] Rung cơ bắp liên tục tạo ra nhiệt lượng khổng lồ. Chống lại cái lạnh -50°C của Vùng Băng Giá mà không cần áo ấm. Có thể ôm đồng đội để truyền nhiệt.", rank: "Phàm Giai", cost: { type: "Stamina", value: 40 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Chống rét)", combo_tag: "Muscle_Heat" },
        { name: "Bắt Đạn", desc: "[Cơ chế] Tốc độ phản xạ thần kinh vượt qua tốc độ âm thanh. [Hiệu ứng] Tay không bắt gọn mũi tên đang bay tới, hoặc bắt được đạn súng lục. Giảm 100% sát thương tầm xa nếu kích hoạt kịp thời.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3800 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Phản Xạ"], range_type: "Bản thân (Phòng ngự phản công)", combo_tag: "Bullet_Catch" },
        { name: "Đào Hầm Tay Không", desc: "[Cơ chế] Bàn tay cứng như cuốc chim, vục đất liên tục không mệt. [Hiệu ứng] Đào giao thông hào, hầm trú ẩn hoặc moi tìm nước ngầm dưới sa mạc cực kỳ nhanh nhẹn mà không cần dụng cụ.", rank: "Phàm Giai", cost: { type: "Stamina", value: 80 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa"], range_type: "Tiện ích (Đào bới)", combo_tag: "Bare_Hand_Dig" },
        { name: "Tái Thiết Nguyên Thần (Trọng Sinh Chi Huyết)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Kích hoạt giọt máu Chân Tổ (Primal Blood) ẩn trong tủy, cưỡng ép cơ thể tiến hóa thành hình thái hoàn mỹ bất diệt trong chốc lát. [Hiệu ứng] Khi đã chết (HP=0, tim ngừng đập), lập tức Hồi Sinh với 100% HP, STR và AGI x10 lần. Miễn nhiễm mọi khống chế/sát thương trong 1 giờ để đồ sát toàn bộ kẻ thù (Vô địch tuyệt đối). [Tác dụng phụ cực lớn] Đốt cháy toàn bộ Tuổi thọ. Sau Lượt vô địch đó, người tung chiêu sẽ chết già ngay lập tức, hóa thành cát bụi, không thể hồi sinh bằng bất kỳ kỹ năng/vật phẩm nào khác (Xóa Save/Xóa Nhân vật).", rank: "Thánh Giai", cost: { type: "HP", value: 9999999 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Sinh Mệnh"], range_type: "Bản thân (Hồi sinh tối hậu)", combo_tag: "Holy_Rebirth_Sacrifice" },
        { name: "Hóa Hình - Nhục Thể Biến", desc: "[Cơ chế] Cơ bắp thú hoang gãy gập, nén ép và tổ hợp lại một cách bạo lực kinh hoàng. [Hiệu ứng] Ép cơ thể Cự thú cao 10m thành một hình dáng loài người siêu cơ bắp cao 2m5. Tỏa ra sát khí hoang dã. Dù mang dạng người nhưng sức mạnh vật lý được nén lại gấp 10 lần, vung tay tạo cuồng phong.", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Ngụy trang lực sĩ)", combo_tag: "Beast_Muscle_Form" },
        { name: "Cự Lực Oanh Kích", desc: "[Cơ chế] Dồn Bloodline Energy vào vuốt/tay. [Hiệu ứng] Bùng nổ sức mạnh cơ bắp. Đấm một cú thẳng tắp. Đủ sức đấm nát bấy hộp sọ của một Dị thú cùng cấp, đấm thủng khiên năng lượng cấp Kim Giai.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4800 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Xuyên phá)", combo_tag: "Beast_Mega_Punch" },
        { name: "Gia Tốc Khí Huyết (Thú Săn Mồi)", desc: "[Cơ chế] Tăng nhịp tim lên 400 nhịp/phút, bơm oxy đến chân. [Hiệu ứng] Mạch máu nổi đỏ rực ngoài da. Di chuyển cực nhanh như một bóng mờ trong 3 phút (Tăng 300% AGI). Săn đuổi mục tiêu chạy trốn hoặc luồn lách qua làn mưa đạn pháo.", rank: "Ngân Giai", cost: { type: "Stamina", value: 3500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Buff tốc độ)", combo_tag: "Beast_Blood_Speed" },
        { name: "Cuồng Hống Trấn Áp", desc: "[Cơ chế] Rống lên âm thanh vang vọng bằng nội lực buồng phổi khổng lồ. [Hiệu ứng] Tiếng gầm mang theo Uy áp Huyết mạch. Mọi sinh vật có BLD thấp hơn trong bán kính 100m đều bị Tê Liệt (Fear) 3 giây, mất kiểm soát cơ thắt ruột (sợ tiểu ra quần).", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 80000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Sóng Âm"], range_type: "AoE Rộng (Khống chế Tâm lý)", combo_tag: "Beast_King_Roar" },
        { name: "Khóa Họng Sinh Tử (Đòn săn mồi)", desc: "[Cơ chế] Cắn ngập nanh vào yết hầu và khóa cằm. [Hiệu ứng] Tung đòn vật lộn hoang dã. Khóa cứng con mồi (Stun cả 2). Nếu con mồi không có STR cao hơn để vùng ra, nó sẽ bị siết gãy cổ hoặc tắt thở sau 2 phút.", rank: "Thiết Giai", cost: { type: "Stamina", value: 280 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Cận Chiến (Khống chế chết chóc)", combo_tag: "Beast_Bite_Hold" },
        { name: "Đuôi Sam Quật Ngã", desc: "[Cơ chế] Vận lực toàn thân dồn vào đuôi/chi sau. [Hiệu ứng] Quật một đường cung quét ngang (AoE 5m). Lực ngàn cân đánh gãy giò các cự thú lớn, quật ngã đám đông lính gác, tạo khoảng trống thoát vây.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Vật Lý"], range_type: "Hình Nón Cận Chiến (Hất ngã)", combo_tag: "Tail_Whip" },
        { name: "Phản Xạ Thú Tính", desc: "[Cơ chế] Dây thần kinh được nối thẳng tới tủy sống, bỏ qua quy trình xử lý của não. [Hiệu ứng] Nội tại lẩn tránh đòn chí mạng. Tự động lùi lại/nghiêng đầu khi bị sát thủ đánh lén từ điểm mù hoặc đạn bắn tỉa bay tới.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa"], range_type: "Bản thân (Phòng ngự bị động)", combo_tag: "Feral_Reflex" },
        { name: "Hóa Khổng Lồ (Gigantification)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Tế bào hấp thụ điên cuồng vật chất xung quanh để phình to kích thước vạn lần. [Hiệu ứng] Biến thành Cự Nhân khổng lồ cao hàng trăm mét. Đi lại dẫm nát thành phố, đấm sập núi non. STR và HP nhân lên 50 lần. [Tác dụng phụ] Não bộ bị ép nhỏ, hoàn toàn mất đi Lý trí (Sanity=0). Tamer/Thú trở thành quái vật điên cuồng vĩnh viễn tàn phá mọi thứ kể cả đồng loại cho đến khi bị thế giới tiêu diệt.", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 800000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Sinh Học"], range_type: "Bản thân (Tiến hóa hủy diệt)", combo_tag: "Divine_Titan_Form" }
    ],
  "Hệ Ánh Sáng": [
        { name: "Hóa Hình - Quang Thể", desc: "[Cơ Chế Sinh Học] Sắp xếp hạt photon mật độ cao thành vật chất giả lập (Hard Light). Vận hành bằng năng lượng quang học, không có trọng lượng. [Hình Thái] Vẻ đẹp hoàn mỹ, không có bóng, cơ thể phát sáng nhẹ. [Hiệu ứng] Dạng người có thể lơ lửng, đi xuyên qua kính và vật thể trong suốt, không cần ăn uống (Chỉ cần phơi nắng). [Tác dụng phụ] Sợ tuyệt đối bóng tối đặc, vào Vùng Zero thiếu sáng sẽ bị trừ HP/MP liên tục.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Quang"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Light" },
        { name: "Tịnh Hóa Quang Luân", desc: "[Cơ chế] Cơ thể luôn phát ra sóng tia cực tím sinh học nhẹ nhàng. [Hiệu ứng] Liên tục thanh tẩy các bào tử nấm mốc, vi khuẩn Vùng Zero bám lên người. Miễn nhiễm 100% với trạng thái [Nhiễm Trùng] từ vết thương hở.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Sinh Mệnh"], range_type: "Bản thân (Bị động thanh tẩy)", combo_tag: "Passive_UV_Cleansing" },
        { name: "Lưu Ly Quang Cảnh", desc: "[Cơ chế] Lớp vảy/da bóng loáng tạo góc phản xạ ngẫu nhiên khi bị tấn công quang học. [Hiệu ứng] Giảm 15% mọi loại sát thương từ Hệ Ánh Sáng. Các tia laser/beam yếu bắn vào sẽ trượt ra xung quanh gây thiệt hại cho môi trường.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Bị động kháng sáng)", combo_tag: "Passive_Mirror_Scale" },
        { name: "Huyễn Quang Khúc Xạ", desc: "[Cơ chế] Nhiệt lượng từ quang năng làm méo mó không khí bao quanh cơ thể. [Hiệu ứng] Đòn đánh xa (Cung, Nỏ, Súng) của kẻ địch nhắm vào bạn có 15% tỉ lệ bắn hụt (Miss) do hình ảnh của bạn trong mắt chúng bị lệch đi vài centimet.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Ảo Giác"], range_type: "Bản thân (Bị động né tránh)", combo_tag: "Passive_Refract_Mirage" },
        { name: "Quang Năng Súc Tích", desc: "[Cơ chế] Da hấp thụ ánh sáng môi trường tích trữ vào tế bào. [Hiệu ứng] Cứ mỗi 10 giây đứng dưới ánh sáng mặt trời hoặc nguồn sáng mạnh, đòn đánh kế tiếp của bạn được cộng thêm 10% Sát thương Bạo kích hệ Quang.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Bị động tích lũy damage)", combo_tag: "Passive_Photon_Store" },
        { name: "Quang Lăng Hộ Thể", desc: "[Cơ chế] Ánh sáng hội tụ tạo thành một màng chắn năng lượng vi mô. [Hiệu ứng] Khi HP đầy 100%, bạn luôn có một Lớp khiên Ánh sáng mỏng tương đương 5% Max HP. Khiên này sẽ tự tái tạo sau 15 giây không nhận sát thương.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Bị động tạo khiên)", combo_tag: "Passive_Prism_Shield" },
        { name: "Thánh Quang Sinh Mệnh", desc: "[Cơ chế] Hạt quang năng kích thích ti thể tái tạo tế bào lỗi. [Hiệu ứng] Tốc độ hồi phục vết thương tự nhiên (HP Regen) tăng thêm 30% chừng nào bạn còn đứng ở khu vực có ánh sáng chiếu rọi (Bất kể là nắng hay đèn).", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Sinh Mệnh"], range_type: "Bản thân (Bị động hồi máu)", combo_tag: "Passive_Light_Life" },
        { name: "Thiểm Quang Phản Chấn", desc: "[Cơ chế] Khi nhận sát thương bạo kích, cơ thể phóng thích chớp sáng tự vệ. [Hiệu ứng] Bất kỳ kẻ thù cận chiến nào gây sát thương Bạo Kích (Critical) lên bạn sẽ bị lóe mắt, mất 100% tầm nhìn (Mù lòa) trong 1 giây.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Cận chiến (Bị động gây mù)", combo_tag: "Passive_Flash_Counter" },
        { name: "Phá Vọng Quang Nhãn", desc: "[Cơ chế] Võng mạc phân tích quang phổ của vật chất ngụy trang. [Hiệu ứng] Hoàn toàn bỏ qua các loại Ảo ảnh (Mirage/Clone) cấp Phàm Giai của kẻ địch. Nhìn thấu bản thể thật của chúng để không tấn công nhầm.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Bị động phá ảo giác)", combo_tag: "Passive_True_Sight" },
        { name: "Thánh Quang Lạc Ấn", desc: "[Cơ chế] Mọi đòn đánh đều phủ bụi phát sáng lên mục tiêu. [Hiệu ứng] Kẻ địch bị bạn đánh trúng sẽ phát sáng nhẹ trong bóng tối suốt 5 giây. Không thể tàng hình (Hệ Ám) hay trốn vào bụi rậm cắt đuôi được.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Mục tiêu (Bị động đánh dấu)", combo_tag: "Passive_Glow_Mark" },
        { name: "Lưu Quang Vô Ảnh", desc: "[Cơ chế] Hóa giải khối lượng cơ thể bằng cách đồng bộ hóa với hạt photon. [Hiệu ứng] Trọng lượng cơ thể lúc chạy nước rút gần như bằng 0. Tăng 15% Tốc độ di chuyển và hoàn toàn không để lại dấu vết trên bùn lầy.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Phong"], range_type: "Bản thân (Bị động tốc độ)", combo_tag: "Passive_Light_Step" },
        { name: "Thái Dương Thôn Phệ", desc: "[Cơ chế] Cơ thể biến đổi bức xạ mặt trời thành rào cản cách nhiệt. [Hiệu ứng] Kháng 100% hiệu ứng [Say nắng], [Kiệt sức do nhiệt] khi đi lại trên sa mạc. Lượng nước tiêu thụ của cơ thể giảm đi một nửa.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Sinh Tồn"], range_type: "Bản thân (Bị động sinh tồn sa mạc)", combo_tag: "Passive_Solar_Absorb" },
        { name: "Bất Khuất Quang Luân", desc: "[Cơ chế] Năng lượng ánh sáng trong tim xua tan bóng tối của sự sợ hãi. [Hiệu ứng] Nội tại duy trì Sanity (Lý trí) cực mạnh. Miễn nhiễm với các kỹ năng [Khủng Bố Tinh Thần], [Đe Dọa] của thú hoang cấp thấp. Không lùi bước.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Tinh Thần"], range_type: "Bản thân (Bị động kháng sợ hãi)", combo_tag: "Passive_Holy_Courage" },
        { name: "Dẫn Lộ Minh Quang", desc: "[Cơ chế] Bản năng tìm kiếm nguồn sáng mạnh nhất / hoặc sự an toàn. [Hiệu ứng] Không bao giờ bị lạc đường trong bóng đêm, ảo cảnh hay sương mù. Luôn nhận biết được chính xác hướng Bắc và vị trí của nguồn nước gần nhất.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Bị động dẫn đường)", combo_tag: "Passive_Guiding_Light" },
        { name: "Phá Ám Quang Tinh", desc: "[Cơ chế] Ánh sáng luôn đi ngược lại sự xâm thực của hạt Hắc ám. [Hiệu ứng] Sát thương từ các đòn đánh, kỹ năng hệ Bóng Tối (Hệ Ám) nhắm vào bạn sẽ tự động giảm đi 25%. Kẻ địch hệ Ám bị giảm 5% uy lực khi đứng gần bạn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Khắc Chế"], range_type: "Bản thân (Bị động khắc Ám)", combo_tag: "Passive_Dark_Bane" },
        { name: "Lưu Ly Quang Thể", desc: "[Cơ chế] Da chuyển hóa thành dạng thủy tinh quang học đặc biệt. [Hiệu ứng] Miễn nhiễm với các hiệu ứng Độc dạng Axit ăn mòn (Acid/Corrosion). Axit chảy trên da như chảy trên thủy tinh, trượt đi mà không gây bỏng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Kháng Độc"], range_type: "Bản thân (Bị động kháng Axit)", combo_tag: "Passive_Glass_Body" },
        { name: "Huyễn Quang Ba Động", desc: "[Cơ chế] Phát ra tần số ánh sáng gây nhiễu loạn thị giác ngoại vi của kẻ thù. [Hiệu ứng] Khi kẻ thù đông hơn, chúng càng khó tập trung vào bạn. Nếu có từ 3 kẻ địch trở lên, tỉ lệ Đỡ đòn (Parry) và Né tránh (Dodge) của bạn tăng 15%.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Ảo Giác"], range_type: "Quần chiến (Bị động phòng thủ đám đông)", combo_tag: "Passive_Dazzle_Wave" },
        { name: "Già Thiên Quang Mạc", desc: "[Cơ chế] Mắt phủ lớp màng lọc UV và ánh sáng chói. [Hiệu ứng] Hoạt động hoàn hảo giữa trưa sa mạc nắng gắt nhất mà không cần kính râm. Không bị giảm độ chính xác khi ngắm bắn ngược ánh nắng mặt trời.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Bị động quang học)", combo_tag: "Passive_UV_Filter" },
        { name: "Thẩm Phán Chi Nhãn", desc: "[Cơ chế] Nhãn quang chứa áp lực của ánh sáng thuần khiết. [Hiệu ứng] Khi nhìn chằm chằm vào 1 kẻ địch (Khóa mục tiêu), giảm 10% Tốc độ hồi MP và Sanity của kẻ đó do chúng cảm thấy bị áp lực vô hình đè nặng.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Tinh Thần"], range_type: "Mục tiêu (Bị động Debuff)", combo_tag: "Passive_Judgment_Gaze" },
        { name: "Tàng Quang Ẩn Ảnh", desc: "[Cơ chế] Bóng râm của cơ thể tự động chứa hạt photon triệt tiêu ma sát. [Hiệu ứng] Đòn đánh lén từ sau lưng hoặc từ trong bóng tối (Backstab) bị giảm đi 30% Sát thương bạo kích. Bảo vệ hoàn hảo khỏi Sát thủ Hệ Ám.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Bị động kháng đánh lén)", combo_tag: "Passive_Shadow_Guard" },
        { name: "Quang Điểm Bạo Phá", desc: "[Cơ chế] Bơm mana vào mũi vũ khí tạo điểm sáng cường độ cao. [Hiệu ứng] Mỗi 3 đòn đánh liên tiếp trúng cùng 1 mục tiêu, đòn thứ 4 sẽ tự động phát nổ hạt ánh sáng, gây thêm 10% sát thương chuẩn.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Vật Lý"], range_type: "Đòn đánh (Bị động combo)", combo_tag: "Passive_Focus_Point" },
        { name: "Tia Sáng Đâm Thấu", desc: "[Cơ chế] Bắn chùm photon mỏng cực nóng. [Hiệu ứng] Xuyên qua kẽ hở của giáp trụ, đốt cháy da thịt bên trong mà không làm hỏng áo giáp ngoài. Sát thương bỏ qua 50% DEF.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Đường thẳng", combo_tag: "Light_Pierce" },
        { name: "Pháo Quang Gây Lóa", desc: "[Cơ chế] Hội tụ hạt sáng ngay trên không trung và kích nổ. [Hiệu ứng] Nổ bùng ánh sáng chói lòa bán kính 5m. Làm Mù lòa (Blind) mọi kẻ thù đang mở mắt, xóa bỏ hoàn toàn khả năng ngắm bắn của xạ thủ địch trong 3 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "AoE Trung", combo_tag: "Flash_Burst" },
        { name: "Ánh Sáng Tụ Điểm", desc: "[Cơ chế] Dùng hai bàn tay như thấu kính hội tụ. [Hiệu ứng] Bắn luồng tia nhiệt (Laser nhẹ) liên tục vào một điểm duy nhất trên giáp kẻ thù. Càng giữ lâu sát thương càng nhân lên, nung chảy giáp sắt thành chất lỏng.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hỏa"], range_type: "Tầm Xa (Kênh truyền)", combo_tag: "Focus_Beam" },
        { name: "Quang Đao Chém Nhanh", desc: "[Cơ chế] Ngưng tụ ánh sáng thành lưỡi dao lướt qua gió. [Hiệu ứng] Vung 3 nhát chém quang học từ khoảng cách 5m. Ánh sáng nhẹ không có trọng lượng nên tốc độ vung chiêu là Tức thì, rất khó phòng ngự.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Tầm Trung (Đa mục tiêu)", combo_tag: "Light_Slash" },
        { name: "Lá Chắn Quang Cực", desc: "[Cơ chế] Trải màng ánh sáng phẳng bảo vệ diện hẹp. [Hiệu ứng] Chặn các đòn tấn công bằng năng lượng Bóng Tối (Hệ Ám) cực kỳ hiệu quả (Hấp thụ 200% damage). Các vật thể rắn xuyên qua bị giảm tốc độ 50%.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Tường Chắn (Tầm Trung)", combo_tag: "Holy_Barrier" },
        { name: "Mưa Hạt Sáng", desc: "[Cơ chế] Bắn một khối sáng lên trời, phân rã thành trăm giọt nhỏ. [Hiệu ứng] Đổ cơn mưa ánh sáng gây bỏng rát lên bán kính 4m. Kẻ địch tàng hình (Hệ Phong, Hệ Ám) bước vào sẽ bị hạt sáng bám lên người, làm hiện nguyên hình.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "AoE Nhỏ (Chống tàng hình)", combo_tag: "Reveal_Rain" },
        { name: "Quang Trảo Phá Ma", desc: "[Cơ chế] Bọc tay bằng năng lượng Thánh tinh khiết. [Hiệu ứng] Cào trực tiếp vào linh hồn địch. Bỏ qua giáp vật lý. Nếu địch đang có Buff (Tăng sức mạnh, Tăng khiên), đòn này sẽ xóa bỏ (Dispel) 1 hiệu ứng Buff của chúng.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Cận Chiến (Giải Buff)", combo_tag: "Purge_Claw" },
        { name: "Đạn Sáng Phản Xạ", desc: "[Cơ chế] Bắn đạn quang học nảy bật trên các bề mặt nhẵn. [Hiệu ứng] Bắn vào vách đá hoặc gương, viên đạn nảy góc 90 độ đâm thẳng vào gáy kẻ thù đang nấp sau chỗ mù. Sát thương nhân lên sau mỗi lần nảy.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Đạn đạo nảy", combo_tag: "Bounce_Light" },
        { name: "Vòng Sáng Đốt Trí", desc: "[Cơ chế] Tạo vòng đai ánh sáng bao vây mục tiêu thu hẹp dần. [Hiệu ứng] Vòng sáng siết chặt. Nếu kẻ địch chạm vào vòng, chúng bị thiêu đốt cả HP lẫn MP (Trừ 2% MP/giây). Ép đối phương phải đứng yên trong vòng đó 2 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Khống Chế"], range_type: "Tầm Xa (Trói buộc)", combo_tag: "Halo_Bind" },
        { name: "Sóng Sáng Đẩy Lùi", desc: "[Cơ chế] Phát tỏa một vòng hào quang xung kích từ bản thể. [Hiệu ứng] Ánh sáng bung ra hất văng (Knockback) toàn bộ Dị thú, kẻ thù áp sát ra xa 3m. Tuyệt kỹ cứu mạng khi bị hội đồng bao vây.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Xung quanh bản thân (Hất văng)", combo_tag: "Light_Nova" },
        { name: "Mũi Tên Thanh Tẩy", desc: "[Cơ chế] Bắn cung tên ánh sáng có chứa thuộc tính thanh tẩy. [Hiệu ứng] Khi bắn trúng đồng đội, không gây sát thương mà hồi cho họ 10% HP và xóa Độc. Khi bắn trúng kẻ địch Bóng Tối, gây gấp đôi sát thương.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Trị Liệu"], range_type: "Tầm Xa (Đa dụng)", combo_tag: "Holy_Arrow" },
        { name: "Ảo Ảnh Ánh Sáng", desc: "[Cơ chế] Bẻ cong hạt photon tạo ra một bản sao không trọng lượng. [Hiệu ứng] Tạo một tàn ảnh của chính mình chạy về hướng khác để thu hút đạn pháo. Kẻ địch bắn vào sẽ làm tàn ảnh nổ tung gây lóa mắt (Blind) tầm gần.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Ảo Giác"], range_type: "Bản sao (Đánh lạc hướng)", combo_tag: "Light_Decoy" },
        { name: "Dấu Ấn Chói Lòa", desc: "[Cơ chế] Bắn một tia sáng nhỏ ghim vào trán mục tiêu. [Hiệu ứng] Mục tiêu bị đánh dấu sẽ rực sáng như ngọn đuốc, không thể tàng hình. Mọi đồng đội đánh vào mục tiêu này đều được +10% Tỷ lệ Chí mạng (Crit Rate).", rank: "Thiết Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Tầm Xa (Đánh dấu / Buff team)", combo_tag: "Beacon_Mark" },
        { name: "Lưỡi Cưa Chớp Nhoáng", desc: "[Cơ chế] Ném một vòng đĩa ánh sáng xoay với tốc độ kinh hoàng. [Hiệu ứng] Đĩa bay cắt đứt cỏ, cây và tay chân quái vật nhỏ trên đường bay 10m rồi tự động quay trở lại tay chủ nhân như Boomerang.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Đường thẳng (Boomerang)", combo_tag: "Light_Chakram" },
        { name: "Cầu Ánh Sáng Rơi", desc: "[Cơ chế] Tụ cầu sáng trên không, thả rơi chậm rãi. [Hiệu ứng] Quả cầu rơi xuống, ai đứng dưới đó sẽ bị trừ dần Tốc độ di chuyển và Sanity do áp lực chói lóa. Chạm đất sẽ nổ gây sát thương diện rộng.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "AoE Trung (Nổ chậm)", combo_tag: "Falling_Star" },
        { name: "Ngụy Trang Ánh Sáng", desc: "[Cơ chế] Bẻ cong ánh sáng quang học quanh thân thể. [Hiệu ứng] Trở nên hoàn toàn vô hình trong 5 giây (Tàng hình quang học). Mất hiệu lực ngay lập tức khi tấn công hoặc thi triển phép thuật khác.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Ảo Giác"], range_type: "Bản thân (Tàng hình)", combo_tag: "Optic_Camo" },
        { name: "Quang Vũ Hỗ Trợ", desc: "[Cơ chế] Vẩy hạt ánh sáng lên vết thương đồng minh. [Hiệu ứng] Cầm máu ngay lập tức và tăng tốc độ hồi phục Stamina cho 1 đồng minh trong 10 giây. Không hồi nhiều HP nhưng đủ để giữ mạng.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Trị Liệu"], range_type: "Cận Chiến (Hỗ trợ)", combo_tag: "Light_Patch" },
        { name: "Bước Nhảy Quang Học", desc: "[Cơ chế] Chuyển thể phân tử sang hạt ánh sáng lướt đi trong môi trường sáng. [Hiệu ứng] Dịch chuyển tức thời (Blink) 5m về phía trước. Không thể dùng đòn này xuyên qua bóng tối đen đặc hoặc tường kín.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Di chuyển"], range_type: "Bản thân (Blink)", combo_tag: "Light_Dash" },
        { name: "Gương Đánh Lừa", desc: "[Cơ chế] Đặt các tấm gương tàng hình giữa không trung. [Hiệu ứng] Đánh lừa mắt kẻ thù khiến chúng bắn trượt mục tiêu 2m. Kẻ thù dùng cung tên/súng sẽ bị mất 50% độ chính xác khi ngắm vào bạn.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Buff Né Tránh)", combo_tag: "Mirror_Dodge" },
        { name: "Bàn Tay Ánh Sáng", desc: "[Cơ chế] Tụ ánh sáng thành hình bàn tay khổng lồ. [Hiệu ứng] Nắm lấy cổ áo kẻ địch từ xa 10m (Pull), kéo mạnh chúng giật lùi về phía mình để tạo góc cận chiến cho Đấu Sĩ đội nhà làm thịt.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Tầm Xa (Kéo mục tiêu)", combo_tag: "Holy_Grip" },
        { name: "Tịnh Hóa (Cleansing)", desc: "[Cơ chế] Chiếu tia cực tím/quang học chuyên biệt tiêu diệt vi khuẩn và phân rã nguyền rủa. [Hiệu ứng] Xóa bỏ ngay lập tức 100% mọi trạng thái xấu (Trúng Độc, Chảy máu, Sợ hãi, Lời nguyền Hắc Ám) cho 1 mục tiêu đồng đội. Chữa lành tinh thần.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Trị Liệu"], range_type: "Tầm Xa (Hỗ trợ)", combo_tag: "Holy_Cleanse" },
        { name: "Pháo Sáng Gây Mù", desc: "[Cơ chế] Nén hạt photon và giải phóng như lựu đạn Flashbang. [Hiệu ứng] Cầu sáng nổ tung cường độ 10.000 Lumen. Làm mù mắt toàn bộ kẻ thù (Giảm 100% độ chính xác trong 30 giây) và làm hỏng mọi camera/cảm biến quang học của Mecha.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "AoE Trung", combo_tag: "Flashbang" },
        { name: "Kiếm Ánh Sáng", desc: "[Cơ chế] Tụ năng lượng quang học thành lưỡi kiếm plasma cực nóng (Lightsaber). [Hiệu ứng] Vũ khí cận chiến thuần túy. Trọng lượng bằng 0 nên tốc độ vung kiếm (AGI) cực nhanh. Cắt xuyên giáp hợp kim, làm bay hơi máu ngay khi chém (Vết thương không chảy máu nhưng cháy khét).", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hỏa"], range_type: "Cận Chiến (Vũ khí)", combo_tag: "Light_Saber" },
        { name: "Tia Laser Hủy Diệt", desc: "[Cơ chế] Bắn chùm tia Gamma hội tụ nhiệt độ cao. [Hiệu ứng] Bắn tia sáng xuyên thấu theo đường thẳng dài 50m. Xuyên lủng mọi chướng ngại vật (Gỗ, Đá, Thịt người), thiêu rụi kẻ địch đứng trên cùng một đường thẳng.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Đường thẳng (Xuyên thấu)", combo_tag: "Laser_Beam" },
        { name: "Khiên Quang Năng", desc: "[Cơ chế] Dựng bức tường hạt ánh sáng (Hard light) ngăn chặn vật chất. [Hiệu ứng] Tạo lá chắn rực rỡ trước mặt. Hấp thụ 5000 sát thương ma pháp. Khắc chế tuyệt đối và làm bốc hơi các đòn tấn công bằng Bóng tối (Hệ Ám).", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Phòng thủ)", combo_tag: "Light_Shield" },
        { name: "Dịch Chuyển Ánh Sáng", desc: "[Cơ chế] Biến thân thể thành hạt photon, di chuyển qua lăng kính quang học. [Hiệu ứng] Dịch chuyển tức thời (Blink) đến bất kỳ vị trí nào có ánh sáng chiếu tới trong bán kính 30m. Tốc độ ánh sáng không thể bị đánh chặn.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Không Gian"], range_type: "Bản thân (Di chuyển cực tốc)", combo_tag: "Light_Blink" },
        { name: "Hồi Máu Diện Rộng", desc: "[Cơ chế] Mưa ánh sáng mang năng lượng sống khôi phục tế bào. [Hiệu ứng] Tỏa hào quang vàng ấm áp bán kính 15m. Hồi 15% Max HP cho mọi đồng minh đứng trong vòng sáng mỗi phút (Kéo dài 30 phút). Cứu nguy trong giao tranh tổng.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Trị Liệu"], range_type: "AoE Trung (Hồi máu AoE)", combo_tag: "Holy_Aura_Heal" },
        { name: "Mưa Quang Tiễn", desc: "[Cơ chế] Kéo ánh sáng từ trên tầng mây, ngưng tụ thành cung tên. [Hiệu ứng] Triệu hồi hàng trăm mũi tên ánh sáng giáng từ trên không xuống. Gây sát thương ma pháp xuyên giáp, ghim bóng đối thủ xuống đất làm giảm 50% AGI.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "AoE Rộng (Từ trên không)", combo_tag: "Light_Rain" },
        { name: "Ảo Ảnh", desc: "[Cơ chế] Bẻ cong ánh sáng quang học như Mirage trên sa mạc. [Hiệu ứng] Tạo ra 3 phân thân giả cực kỳ sống động (Có bóng râm). Đánh lừa mắt thường và camera, chạy tán loạn thu hút hỏa lực. Phân thân vỡ ngay khi bị chạm vào.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Ảo Giác"], range_type: "Bản thân (Đánh lạc hướng)", combo_tag: "Optical_Illusion" },
        { name: "Thánh Phán Quyết (Nhật Thực Tàn Lụi)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Nuốt chửng nguồn sáng của thực tại, tụ năng lượng của một 'Mặt Trời' và kích nổ. [Hiệu ứng] Bầu trời chuyển sang Nhật Thực mờ mịt. Sau đó một cột sáng khổng lồ đường kính 5km giáng từ vũ trụ xuống. Bốc hơi MỌI THỨ vật chất, linh hồn, không gian thành tro bụi sáng. Sát thương Vô Cực. [Tác dụng phụ cực lớn] Người tung chiêu bị ngọn lửa thần thánh thiêu mù đôi mắt vĩnh viễn (Mù lòa 100%), cánh tay thi triển đứt gãy thành ánh sáng tan biến (Mất 1 tay), vĩnh viễn không thể sử dụng Quang hệ nữa.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 100 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Không Gian"], range_type: "Cấp Thế Giới (Hủy diệt tuyệt đối)", combo_tag: "Holy_Solar_Eclipse" },
        { name: "Giam Cầm Ánh Sáng", desc: "[Cơ chế] Dựng rào chắn photon cường độ cao hình khối lập phương. [Hiệu ứng] Nhốt kẻ thù vào lồng ánh sáng (3x3m). Kẻ nào chạm vào thành lồng sẽ bị bỏng rát cực nặng (Trừ 10% HP). Khóa cứng mục tiêu cho đến khi lồng bị bắn vỡ.", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Tầm Xa (Khống chế/Giam cầm)", combo_tag: "Light_Prison" },
        { name: "Đánh Dấu Mục Tiêu", desc: "[Cơ chế] Bắn một hạt photon bám vĩnh viễn vào linh hồn địch. [Hiệu ứng] Gắn vệt sáng chói lòa lên đầu mục tiêu. Dù chúng chạy vào bóng tối, tàng hình (Hệ Mộc/Hệ Ám) hay chui xuống đất, vị trí vẫn hiện rành rành cho cả team nhìn thấy.", rank: "Thiết Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Tầm Xa (Trinh sát/Chống tàng hình)", combo_tag: "Target_Mark" },
        { name: "Buff Sức Mạnh", desc: "[Cơ chế] Ánh sáng kích thích hệ thần kinh giao cảm, bơm dũng khí. [Hiệu ứng] Hào quang tỏa ra, buff +50% Sát thương và phục hồi 20 Sanity (Xóa sợ hãi) cho 1 đồng minh. Biến một kẻ nhát gan thành chiến binh dũng cảm.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Cận Chiến (Buff)", combo_tag: "Holy_Blessing" },
        { name: "Gương Phản Xạ", desc: "[Cơ chế] Dựng lăng kính không gian đa chiều. [Hiệu ứng] Tạo tấm gương lơ lửng. Khi đạn ma pháp (Lửa, Nước, Độc) bắn tới, gương phản đòn 100% quỹ đạo ngược lại thẳng vào mặt kẻ bắn. Sau 1 lần phản đòn, gương vỡ.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 4, unit: "Phút", display_text: "4 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Tầm Ngắn (Phản đòn ma pháp)", combo_tag: "Magic_Mirror" },
        { name: "Cầu Sáng Soi Đường (Tiện ích)", desc: "[Cơ chế] Tụ hạt photon thành dạng Plasma lạnh. [Hiệu ứng] Tạo ra một (hoặc nhiều) quả cầu sáng lơ lửng đi theo chủ nhân. Xua tan bóng đêm đen đặc dưới hang động hoặc Vùng Zero, đuổi các sinh vật bóng tối yếu ớt.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Xung quanh bản thân (Chiếu sáng)", combo_tag: "Orb_Light" },
        { name: "Tia Xuyên Thấu", desc: "[Cơ chế] Chuyển đổi quang phổ mắt sang tia X-Ray. [Hiệu ứng] Mắt phát sáng. Nhìn xuyên qua tường gạch, thùng gỗ, giáp sắt để biết trước kẻ địch núp bên trong (Thấy kết cấu xương cốt). Tình báo hoàn hảo trước khi đột kích.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Tình báo xuyên tường)", combo_tag: "X_Ray_Vision" },
        { name: "Kháng Ám (Nội Tại)", desc: "[Cơ chế] Năng lượng ánh sáng trong huyết quản tự động trung hòa hạt Dark Matter. [Hiệu ứng] Giảm thiểu 50% mọi sát thương vật lý/ma pháp từ kỹ năng thuộc Hệ Bóng Tối. Khắc tinh thiên địch của các loài quái vật hắc ám.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Phòng ngự bị động)", combo_tag: "Dark_Resist" },
        { name: "Sạc Năng Lượng Mặt Trời", desc: "[Cơ chế] Da có cấu tạo vi mô như tấm pin Solar Cell sinh học. [Hiệu ứng] Chỉ cần đứng dưới nắng gắt, tốc độ hồi MP và Stamina nhân đôi (x2). Nhân vật cũng không cần ăn thức ăn vật chất mà vẫn no bụng (Giảm Hunger = 0).", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Hồi phục thụ động)", combo_tag: "Solar_Charge" },
        { name: "Hologram", desc: "[Cơ chế] Chiếu ánh sáng đa phổ tạo mô hình 3D. [Hiệu ứng] Phóng hình ảnh 3D chân thực của bản đồ, sơ đồ tòa nhà hoặc một đoạn tin nhắn bằng hình người ra không trung. Dùng để họp bàn chiến thuật hoặc truyền tin tình báo phức tạp.", rank: "Phàm Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Tiện ích (Trình chiếu)", combo_tag: "Hologram_Map" },
        { name: "Tia Cắt Kim Loại (Laser Mini)", desc: "[Cơ chế] Tụ ánh sáng nhỏ vào một điểm duy nhất (Kính lúp ma pháp). [Hiệu ứng] Dùng ngón tay phát ra laser công suất thấp siêu nóng. Cắt ổ khóa thép, cắt kính cường lực phòng thí nghiệm một cách im lặng để đột nhập.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Cận Chiến (Tiện ích phá hoại)", combo_tag: "Mini_Laser_Cut" },
        { name: "Hóa Hình - Quang Ảnh Tập", desc: "[Cơ chế] Dị thú hệ quang phân rã thành chùm sáng tán xạ. [Hiệu ứng] Mượn ánh sáng mặt trời để bẻ cong thị giác, cơ thể khổng lồ tụ lại thành hình bóng một con người chói lóa tỏa hào quang như thiên sứ giáng trần. Khiến người đời nhầm tưởng là Thần linh để thờ phụng.", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "Bản thân (Ngụy trang Tôn giáo)", combo_tag: "Beast_Angel_Form" },
        { name: "Quang Kiếm Phán Quyết (Dị Thú Đột Kích)", desc: "[Cơ chế] Vuốt hoặc đuôi phủ lớp plasma ánh sáng cực hạn. [Hiệu ứng] Đòn chém vòng cung rực rỡ. Cắt đứt vật chất vật lý (Áo giáp/Núi đá). Đặc biệt gây x2 Sát thương chuẩn khi đánh trúng kẻ địch mang hệ Bóng Tối/Hắc Ám.", rank: "Ngân Giai", cost: { type: "Stamina", value: 4200 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Vật Lý"], range_type: "Cận Chiến (Sát thương bạo kích)", combo_tag: "Holy_Saber" },
        { name: "Thánh Giá Giam Cầm", desc: "[Cơ chế] Bắn cọc ánh sáng định vị ghim chặt Không - Thời gian. [Hiệu ứng] Bắn 4 cọc sáng đóng đinh bóng râm của kẻ thù xuống mặt đất. Bóng bị ghim khiến cơ thể thực cũng bị khóa chặt tại chỗ (Khống chế cứng), phơi thây cho đồng đội xả đạn.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Bóng Tối"], range_type: "Tầm Xa (Khống chế đặc biệt)", combo_tag: "Crucifix_Bind" },
        { name: "Hào Quang Chữa Lành (Bản Năng)", desc: "[Cơ chế] Nhịp tim Thú tỏa ra sóng sinh mệnh quang học. [Hiệu ứng] Không cần niệm chú, cơ thể thú luôn tỏa ánh sáng dịu nhẹ. Tự động phục hồi từ từ (5% HP/giờ) cho Ký chủ (Ngự Thú Sư) và bản thân Thú khi đứng gần nhau.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Trị Liệu"], range_type: "Bản thân & Ký chủ (Hồi phục bị động)", combo_tag: "Passive_Holy_Heal" },
        { name: "Lăng Kính Phân Tách", desc: "[Cơ chế] Thú khạc ra một khối pha lê ma thuật lơ lửng. [Hiệu ứng] Khi bắn tia Laser vào lăng kính này, tia sáng bị phân tách làm 7 tia nhỏ (nhiều màu) dội vào 7 mục tiêu khác nhau. Đòn dọn dẹp đám đông cực kỳ hiệu quả của xạ thủ.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "AoE Phân tán (Kỹ năng combo)", combo_tag: "Prism_Split" },
        { name: "Supernova (Siêu Tân Tinh Giáng Thế)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Ép bản thể tiến vào trạng thái phân hạch hạt nhân (Fission) như một vì sao hấp hối. [Hiệu ứng] Biến thành mặt trời nhân tạo ngay giữa chiến trường. Sóng nhiệt chói lòa thiêu rụi toàn bộ thành phố, nung chảy mọi hợp kim vô cực. Xóa sổ bóng tối của cả đại lục. [Tác dụng phụ] Rút cạn 90% HP và Bloodline Energy. Thú rơi vào trạng thái 'Sập Nguồn' (Ngủ đông sâu) trong 1 năm, mất toàn bộ khả năng chiến đấu và lột xác về cấp Linh Thú yếu ớt.", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 900000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hỏa"], range_type: "AoE Rất Rộng (Cấp Thảm Họa)", combo_tag: "Divine_Supernova" },
        { name: "Cổng Thiên Đàng (Ascension Gate)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Xé rách không gian, mở đường hầm năng lượng thuần khiết nối với tầng bình lưu. [Hiệu ứng] Dịch chuyển toàn bộ Đồng đội/Người dân (Không giới hạn số lượng) từ một chiến trường đang chết chắc đến bất kỳ vị trí an toàn nào trên Thế giới trong chớp mắt. [Tác dụng phụ] Trừ 70 Sanity của người dùng (Rơi vào hoảng loạn). Năng lượng xé rách không gian sẽ ăn mòn tuổi thọ (Giảm 20 năm), và phong ấn kỹ năng Hệ Quang trong 3 tháng.", rank: "Diệu Giai", cost: { type: "MP", value: 4500000 }, cooldown: { value: 90, unit: "Ngày", display_text: "3 Tháng" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Không Gian"], range_type: "AoE Siêu Rộng (Cứu Hộ Tối Hậu)", combo_tag: "Divine_Heaven_Gate" },
        { name: "Pháo Sáng Phục Kích", desc: "[Cơ chế] Tích tụ mầm sáng dưới cổ họng và bắn lên trời. [Hiệu ứng] Bắn quả cầu sáng treo lơ lửng trên không như mặt trời giả (Tồn tại 10 phút). Xóa bỏ hiệu ứng Tàng hình/Bóng tối của kẻ thù lén lút, soi sáng toàn bộ trận địa để xạ thủ UHA nã đạn.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng"], range_type: "AoE Rộng (Phát hiện tàng hình)", combo_tag: "Flare_Ambush" },
        { name: "Giáp Quang Chói (Gây Nhiễu)", desc: "[Cơ chế] Cơ thể thú phát xạ ánh sáng chớp tắt tần số cao liên tục. [Hiệu ứng] Kẻ địch áp sát cận chiến sẽ bị lóa mắt, chóng mặt buồn nôn (Hiệu ứng Động kinh). Khiến đòn đánh vật lý của chúng có 50% tỉ lệ Trượt (Miss).", rank: "Ngân Giai", cost: { type: "Stamina", value: 3000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Ảo Giác"], range_type: "Bản thân (Phòng ngự gây nhiễu)", combo_tag: "Strobe_Armor" }
    ],
  "Hệ Bóng Tối": [
        { name: "Hóa Hình - Ảnh Ma", desc: "[Cơ Chế Sinh Học] Chuyển đổi cơ thể sang trạng thái bán vật chất (Semi-matter) hoặc dạng bóng 2D. Tế bào hấp thụ ánh sáng tuyệt đối. [Cấu Tạo] Nội tạng mô phỏng từ bóng tối đặc quánh, không nhịp tim. [Hình Thái] Đường nét mờ ảo, hòa lẫn vào bóng đêm. [Hiệu ứng] Ẩn nấp tuyệt đối, không bị phát hiện bởi thiết bị tầm nhiệt hoặc Radar. [Tác dụng phụ] Giảm 50% Sát thương vật lý cơ bản, nếu bị chiếu đèn cường độ cao sẽ bị hiện hình và giảm tốc chạy.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Không Gian"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Shadow" },
        { name: "Dạ Hành Ẩn Thể", desc: "[Cơ chế] Cơ thể tự động đồng hóa với các mảng tối của môi trường. [Hiệu ứng] Khi đứng hoặc di chuyển trong bóng râm, hang động, cơ thể mờ đi 70% (Tàng hình bán phần). Rất khó bị nhắm mục tiêu bởi xạ thủ/pháp sư.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Ảo Giác"], range_type: "Bản thân (Bị động ngụy trang)", combo_tag: "Passive_Night_Walk" },
        { name: "Ám Dạ Thôn Phệ", desc: "[Cơ chế] Lỗ chân lông hút hạt Dark Matter thay vì Oxy. [Hiệu ứng] Vào ban đêm hoặc ở khu vực Vùng Zero không có ánh sáng, tốc độ hồi phục Năng lượng (MP) và Thể lực (Stamina) được tăng gấp đôi.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Bản thân (Bị động hồi phục)", combo_tag: "Passive_Dark_Absorb" },
        { name: "Hư Không Ám Mạc", desc: "[Cơ chế] Lớp sương đen vi mô luôn xoay quanh cơ thể. [Hiệu ứng] Hấp thụ và làm triệt tiêu mọi phép thuật thám thính (Scan), Đánh dấu (Mark), và các loại Bào tử phát sáng dính lên người. Luôn giữ bí mật thông tin chỉ số.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Bản thân (Bị động kháng trinh sát)", combo_tag: "Passive_Void_Cloak" },
        { name: "Thâm Uyên Chi Nhãn", desc: "[Cơ chế] Màng mạch chuyển sang cấu trúc mắt mèo, thu nhận 100% photon sót lại. [Hiệu ứng] Tầm nhìn hoàn hảo trong bóng tối tuyệt đối (như ban ngày). Kháng hiệu ứng hoảng loạn khi bị mất thị giác đột ngột.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Bản thân (Bị động thị giác)", combo_tag: "Passive_Abyss_Eye" },
        { name: "Vô Trọng Ám Bộ", desc: "[Cơ chế] Bóng râm đỡ lấy một phần sức nặng cơ thể. [Hiệu ứng] Khi bước đi, hoàn toàn không phát ra một tiếng động nào (triệt tiêu sóng âm). Khắc tinh của các dị thú có thính giác nhạy bén hay Radar hệ Thổ.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Sóng Âm"], range_type: "Bản thân (Bị động câm lặng)", combo_tag: "Passive_Weightless_Step" },
        { name: "Ám Ảnh Trấn Áp", desc: "[Cơ chế] Khí tức hắc ám tự động bám vào kẻ thù xung quanh. [Hiệu ứng] Bất kỳ kẻ địch nào đứng trong bán kính 3m quanh bạn sẽ bị cảm giác ớn lạnh sống lưng, giảm 10% Tốc chạy (AGI) và 5% Tốc độ đánh.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "AoE Cận chiến (Bị động Debuff)", combo_tag: "Passive_Shadow_Press" },
        { name: "Hư Vô Ám Giáp", desc: "[Cơ chế] Cơ thể có một lớp khiên ảo giác chuyển một phần động năng sang không gian khác. [Hiệu ứng] Nếu bạn đang ở trạng thái đầy máu (100% HP), đòn đánh đầu tiên của kẻ thù sẽ bị giảm 50% Sát thương nhận vào.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Không Gian"], range_type: "Bản thân (Bị động chống sốc dame)", combo_tag: "Passive_Void_Armor" },
        { name: "Tu La Ám Khí", desc: "[Cơ chế] Tỏa ra năng lượng tiêu cực chết chóc của Vùng Zero. [Hiệu ứng] Kẻ địch (hoặc thú hoang) có Cảnh Giới thấp hơn khi nhìn thẳng vào bạn sẽ bị trừ dần Sanity (Lý trí) 1 điểm mỗi giây, dễ dàng hoảng loạn bỏ chạy.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "Tầm nhìn (Bị động đe dọa)", combo_tag: "Passive_Dark_Aura" },
        { name: "Tàn Ảnh Mê Tung", desc: "[Cơ chế] Ánh sáng chiếu vào cơ thể bị phân tán tạo thành nhiều ảo ảnh chồng chéo. [Hiệu ứng] Tăng 10% Tỉ lệ né tránh (Dodge) với mọi đòn đánh. Nếu bị đánh trúng, có 5% tỉ lệ đòn đó xuyên qua người (như chém vào không khí).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Ảo Giác"], range_type: "Bản thân (Bị động né tránh ảo)", combo_tag: "Passive_Shadow_Blur" },
        { name: "Cực Dạ Ám Nhẫn", desc: "[Cơ chế] Vũ khí được bao bọc bởi vật chất tối tĩnh lặng. [Hiệu ứng] Đòn đánh thường từ phía sau lưng (Backstab) hoặc khi bạn đang tàng hình sẽ được tăng 50% Sát thương chí mạng (Crit Damage). Tuyệt kỹ của sát thủ.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Vật Lý"], range_type: "Đòn đánh lén (Bị động sát thủ)", combo_tag: "Passive_Night_Blade" },
        { name: "Yểm Mục Ám Khí", desc: "[Cơ chế] Ma thuật hắc ám tự động nuốt chửng ánh lửa từ vũ khí phe mình. [Hiệu ứng] Bất kỳ tia lửa từ súng đạn, ánh sáng từ việc thi triển ma pháp của bạn sẽ bị che giấu 80%. Địch không thể nhìn thấy chớp lửa để đoán vị trí bắn.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Khí"], range_type: "Bản thân (Bị động che giấu)", combo_tag: "Passive_Hide_Flash" },
        { name: "Huyết Ám Thôn Phệ", desc: "[Cơ chế] Hút một phần linh hồn vụn vỡ của kẻ thù bị chém đứt. [Hiệu ứng] Mỗi đòn đánh cận chiến trúng đích, hồi phục một lượng Máu (HP) bằng 2% sát thương gây ra. Giúp duy trì khả năng trụ lane lâu dài.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Sinh Mệnh"], range_type: "Đòn đánh (Bị động hút máu)", combo_tag: "Passive_Dark_Blood" },
        { name: "Hư Ảnh Phản Phệ", desc: "[Cơ chế] Bóng râm dưới chân tự động bảo vệ chủ nhân. [Hiệu ứng] Nếu bạn bị dính hiệu ứng Khống chế cứng (Stun, Paralyze), cái bóng của bạn sẽ phát nổ, gây sát thương Hắc ám nhỏ và làm Chậm 50% kẻ địch xung quanh.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Bản thân (Bị động trả đũa khống chế)", combo_tag: "Passive_Shadow_Counter" },
        { name: "Ngự Quang Ám Mạc", desc: "[Cơ chế] Da tiết ra lớp màng melanin ma thuật hấp thụ cực tím. [Hiệu ứng] Giảm thiểu 30% sát thương từ các kỹ năng Hệ Ánh Sáng. Không bị trừ chỉ số hay Suy yếu khi phải chiến đấu dưới trời nắng gắt giữa sa mạc.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Quang"], range_type: "Bản thân (Bị động kháng Quang)", combo_tag: "Passive_Sun_Block" },
        { name: "Vạn Ám Bất Xâm", desc: "[Cơ chế] Cơ thể đã quen với sự mục rữa và tà ác. [Hiệu ứng] Kháng 50% mọi hiệu ứng giảm chỉ số (Debuff), ăn mòn Lý Trí (Sanity), hay Lời nguyền mục nát từ quái vật Vùng Zero và ma thuật hắc ám.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Nguyền Rủa"], range_type: "Bản thân (Bị động kháng hiệu ứng)", combo_tag: "Passive_Curse_Resist" },
        { name: "Ám Ảnh Truy Hồn", desc: "[Cơ chế] Khóa chặt sinh khí của mục tiêu vào hư không. [Hiệu ứng] Một khi đã đánh trúng mục tiêu, bạn sẽ được tăng 15% Tốc độ di chuyển khi hướng mặt đuổi theo kẻ đó. Tốc độ này mất đi nếu quay lưng bỏ chạy.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Mục tiêu (Bị động săn đuổi)", combo_tag: "Passive_Ghost_Pursuit" },
        { name: "Khủng Cụ Thôn Phệ", desc: "[Cơ chế] Cơ thể hút sức sống từ sự sợ hãi của nạn nhân. [Hiệu ứng] Sát thương đánh vào những kẻ địch đang dính hiệu ứng [Sợ Hãi], [Hoảng Loạn] hoặc [Mù Lòa] sẽ tăng thêm 20% sát thương chuẩn.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "Đòn đánh (Bị động khuếch đại sát thương)", combo_tag: "Passive_Fear_Eater" },
        { name: "Vô Hình Ám Trận", desc: "[Cơ chế] Bóng tối tự động che phủ các vật thể nhỏ của người dùng. [Hiệu ứng] Bất kỳ bẫy nào bạn đặt ra (Bẫy sập, mìn, dây gai) đều được phủ lớp tàng hình nhẹ, tăng gấp đôi độ khó phát hiện đối với kẻ thù.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Vật phẩm/Bẫy (Bị động hỗ trợ)", combo_tag: "Passive_Hidden_Trap" },
        { name: "Tuyệt Âm Ám Giới", desc: "[Cơ chế] Một trường không gian 5cm quanh da nuốt mọi rung động. [Hiệu ứng] Áo giáp kim loại, vũ khí va chạm vào nhau khi bạn chạy không hề phát ra tiếng leng keng. Rút gươm khỏi vỏ cũng hoàn toàn câm lặng.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Sóng Âm"], range_type: "Bản thân (Bị động trang bị)", combo_tag: "Passive_Muffle_Sound" },
        { name: "Không Gian Ám Khúc", desc: "[Cơ chế] Làm méo mó hình học không gian trong bán kính rất hẹp. [Hiệu ứng] Kẻ địch chém vào bạn sẽ có cảm giác cự ly bị sai lệch. Vũ khí của chúng luôn ngắn đi khoảng 5cm, khiến các đòn chém sát sạt đều bị hụt (Miss).", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không (Bị động)" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Không Gian"], range_type: "Cận chiến (Bị động giảm chính xác địch)", combo_tag: "Passive_Space_Warp" },
        { name: "Đạn Bóng Đêm", desc: "[Cơ chế] Nén hắc ám thành viên đạn hút quang học. [Hiệu ứng] Bắn trúng ngực đối thủ gây sát thương tà ác, để lại dấu ấn đen làm giảm 10% Tầm nhìn và Phản xạ của chúng trong 3 giây.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Shadow_Bolt" },
        { name: "Vuốt Hắc Ám", desc: "[Cơ chế] Bọc tay bằng năng lượng bóng tối ăn mòn vật chất. [Hiệu ứng] Chém xuyên qua giáp vật lý nhẹ (Bỏ qua 30% DEF). Vết thương không chảy máu nhưng thịt bị thối rữa đen kịt, không thể tự hồi phục.", rank: "Thiết Giai", cost: { type: "Stamina", value: 35 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Nguyền Rủa"], range_type: "Cận Chiến (Xuyên Giáp)", combo_tag: "Dark_Claw" },
        { name: "Bóng Ma Che Mắt", desc: "[Cơ chế] Triệu hồi một bóng ma nhảy bổ vào mặt kẻ thù. [Hiệu ứng] Con ma ôm chặt mặt đối thủ che khuất hoàn toàn tầm nhìn (Blind 100%) trong 1.5 giây, khiến chúng hoảng sợ chém loạn xạ vào không khí.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Ảo Giác"], range_type: "Tầm Xa (Khống chế nhìn)", combo_tag: "Ghost_Blind" },
        { name: "Ảo Ảnh Đen", desc: "[Cơ chế] Phân tách cái bóng của mình thành hình người 3D. [Hiệu ứng] Tàn ảnh đứng yên hoặc chạy theo đường thẳng để đánh lừa kẻ địch xả đạn. Nếu bị bắn trúng, ảo ảnh tan thành khói đen gây ho sặc sụa.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Ảo Giác"], range_type: "Bản sao (Đánh lừa)", combo_tag: "Shadow_Decoy" },
        { name: "Màn Đêm Thu Nhỏ", desc: "[Cơ chế] Xóa bỏ các hạt photon ở khu vực nhỏ hẹp. [Hiệu ứng] Tạo quả cầu bóng tối bán kính 2m. Bên trong tối đen như mực. Ném vào đầu lính canh UHA để chúng không thể kêu cứu hay nhìn thấy nhau.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Lĩnh Vực"], range_type: "AoE Nhỏ (Tạo Vùng Tối)", combo_tag: "Mini_Darkness_Zone" },
        { name: "Hút Máu Bề Mặt", desc: "[Cơ chế] Cắn bằng răng tẩm tà khí. [Hiệu ứng] Cắn ngập răng vào thịt địch, hút đi 5% máu (HP) của chúng và truyền sang cho người dùng. Khắc phục điểm yếu máu giấy của Sát thủ hệ Ám.", rank: "Thiết Giai", cost: { type: "Stamina", value: 30 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Sinh Mệnh"], range_type: "Cận Chiến (Lifesteal)", combo_tag: "Vampiric_Bite" },
        { name: "Bóng Dính Dưới Chân", desc: "[Cơ chế] Kéo cái bóng của mình nối liền với bóng kẻ địch. [Hiệu ứng] Trói hai bóng lại với nhau. Kẻ thù không thể bước ra khỏi vòng tròn bán kính 3m quanh người dùng (Khóa di chuyển/Root). Rất hợp để ép đánh cận chiến.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Tầm Trung (Khóa chân/Kéo)", combo_tag: "Shadow_Tether" },
        { name: "Gai Đen Đâm Gót", desc: "[Cơ chế] Ngưng tụ hắc ám dưới mặt đất thành đinh. [Hiệu ứng] Đâm xiên gót chân từ cái bóng. Sát thương cực nhỏ nhưng tạo hiệu ứng Chảy máu (Bleed) và làm giảm 15% AGI của mục tiêu khi chúng di chuyển.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Tầm Trung (Gây Bleed)", combo_tag: "Dark_Heel_Spike" },
        { name: "Tiếng Thì Thầm Tà Ác", desc: "[Cơ chế] Đưa giọng nói ma quỷ truyền thẳng vào vỏ não. [Hiệu ứng] Mục tiêu nghe thấy tiếng rỉ tai đòi giết chóc. Trừ đi 10 điểm Sanity (Lý trí) lập tức, khiến chúng phân tâm đánh trượt (Miss) đòn tiếp theo.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "Tầm Xa (Tấn công Sanity)", combo_tag: "Evil_Whisper" },
        { name: "Áo Choàng Bóng Tối Nhẹ", desc: "[Cơ chế] Khoác bóng đêm lên bờ vai làm giảm độ tương phản ánh sáng. [Hiệu ứng] Khi đứng sát vào một bức tường hoặc trong góc tối, cơ thể trở nên trong suốt 80%. Bước ra ánh sáng sẽ tự động bị lộ diện.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Ẩn Nấp"], range_type: "Bản thân (Tàng hình bán phần)", combo_tag: "Shadow_Cloak_Light" },
        { name: "Bàn Tay Hắc Ám Cào Xé", desc: "[Cơ chế] Tụ 3 cánh tay quỷ bằng khí đen trên không. [Hiệu ứng] Tát mạnh vào người mục tiêu đẩy lùi chúng ra xa (Knockback) 2m. Kéo dãn khoảng cách để bỏ chạy hoặc dùng phép tầm xa.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Vật Lý"], range_type: "Tầm Trung (Đẩy lùi)", combo_tag: "Dark_Hand_Push" },
        { name: "Nguyền Rủa Đau Đớn", desc: "[Cơ chế] Bắn nguyền chú xâm nhập vào tủy xương. [Hiệu ứng] Kẻ địch trúng chiêu không nhận sát thương ngay, nhưng mỗi khi chúng Vận sức tấn công hoặc Niệm chú, chúng sẽ bị nhói đau và mất 3% Max HP.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Nguyền Rủa"], range_type: "Tầm Xa (Debuff Kích hoạt)", combo_tag: "Pain_Curse_Mark" },
        { name: "Bóng Đêm Thẩm Thấu", desc: "[Cơ chế] Ép một khối bóng tối nhỏ vào khiên ma pháp địch. [Hiệu ứng] Ăn mòn giáp/Khiên phép (Hệ Quang, Thủy). Làm mỏng lá chắn, giảm 20% lượng hấp thụ sát thương của mọi loại Khiên đối phương đang có.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Tầm Xa (Phá Khiên Nhẹ)", combo_tag: "Shield_Corrosion" },
        { name: "Sương Mù Sợ Hãi", desc: "[Cơ chế] Hơi thở mang khí lạnh của nghĩa địa. [Hiệu ứng] Thổi sương đen ra trước mặt. Kẻ địch hít phải sẽ run rẩy sợ hãi (Fear), tự động quay lưng bỏ chạy theo hướng ngược lại trong 1.5 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 45 }, cooldown: { value: 18, unit: "Giây", display_text: "18 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "Hình Nón Cận Chiến (Sợ hãi/CC)", combo_tag: "Fear_Breath" },
        { name: "Bước Nhảy Bóng Đêm Cục Bộ", desc: "[Cơ chế] Lặn ngụp vào trong vũng bóng râm gần nhất. [Hiệu ứng] Biến mất và trồi lên (Blink) ở một góc tối khác cách đó tối đa 5 mét. Tuyệt chiêu để vòng ra sau lưng (Backstab) chém gáy đối phương.", rank: "Thiết Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Không Gian"], range_type: "Bản thân (Blink/Ám sát)", combo_tag: "Shadow_Step_Short" },
        { name: "Cái Nhìn Vực Thẳm", desc: "[Cơ chế] Đôi mắt rực đỏ mang ảo ảnh hắc ám. [Hiệu ứng] Nhìn thẳng vào mắt địch. Kẻ địch có SPI thấp hơn sẽ bị thôi miên đứng đờ đẫn (Stun) trong 1 giây, đủ thời gian vung đao kết liễu.", rank: "Phàm Giai", cost: { type: "MP", value: 25 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Ảo Giác"], range_type: "Cận Chiến (Khống chế cứng nhanh)", combo_tag: "Abyssal_Stare" },
        { name: "Hắc Thuẫn Bảo Vệ", desc: "[Cơ chế] Gọi khối sương mù đen đặc cứng lại thành lá chắn trước mặt. [Hiệu ứng] Hấp thụ 2 đòn đánh vật lý cơ bản hoặc đạn đạo. Nếu trúng đòn Ánh Sáng (Hệ Quang), khiên sẽ vỡ ngay tức khắc mà không chặn được.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 12, unit: "Giây", display_text: "12 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Tường Chắn (Phòng ngự trước)", combo_tag: "Dark_Barrier" },
        { name: "Gặm Nhấm Năng Lượng", desc: "[Cơ chế] Đàn nhện bóng tối cắn xé Đan Điền. [Hiệu ứng] Bắn bầy nhện đen li ti lên người địch. Không trừ máu, nhưng trừ thẳng 10% lượng MP tối đa của Pháp sư địch, làm chúng cạn kiệt năng lượng để đánh trả.", rank: "Thiết Giai", cost: { type: "MP", value: 35 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Tầm Xa (Trừ MP địch)", combo_tag: "Mana_Muncher" },
        { name: "Dao Đen Cắm Phổi", desc: "[Cơ chế] Tụ dao găm bằng hắc khí. [Hiệu ứng] Ném đao cắm ngập ngực kẻ thù. Gây sát thương bình thường nhưng làm Giảm Hồi Máu (Trọng thương) của chúng đi 50% trong 5 giây tới.", rank: "Thiết Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Nguyền Rủa"], range_type: "Tầm Xa (Giảm Trị Liệu)", combo_tag: "Anti_Heal_Dagger" },
        { name: "Bóng Dáng Tội Đồ", desc: "[Cơ chế] Bơm sát khí giả mạo lên cực hạn. [Hiệu ứng] Đứng im và tỏa ra Uy Áp đen kịt của một Dị thú Lãnh Chúa cấp cao giả mạo. Dọa lũ quái thú tôm tép hoặc bọn lính nhát gan sợ hãi bỏ chạy không dám tấn công.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "Bản thân (Thổi phồng sát khí)", combo_tag: "Fake_Aura_Intimidate" },
        { name: "Vuốt Bóng Tối", desc: "[Cơ chế] Ngưng tụ Dark Matter (Vật chất tối) vào đầu ngón tay. [Hiệu ứng] Tấn công xuyên thấu vật lý. Bỏ qua 100% Giáp và Khiên năng lượng, gây sát thương trực tiếp vào linh hồn. Để lại hiệu ứng [Nguyền Rủa] làm mục tiêu mất dần HP trong 10 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Nguyền Rủa"], range_type: "Cận Chiến", combo_tag: "Shadow_Claw" },
        { name: "Lặn Vào Bóng", desc: "[Cơ chế] Đồng bộ hóa tần số cơ thể với chiều không gian 2D của bóng râm. [Hiệu ứng] Nhảy tọt vào cái bóng của một vật thể (cây cối) hoặc một sinh vật (đồng đội/kẻ địch). Di chuyển hoàn toàn không tiếng động, trinh sát hoặc tiếp cận mục tiêu để ám sát.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Bản thân (Di chuyển lén lút)", combo_tag: "Shadow_Dive" },
        { name: "Hố Đen Mini", desc: "[Cơ chế] Tạo ra một điểm kỳ dị kích thước nhỏ hút vật chất. [Hiệu ứng] Mở ra một lỗ hổng đen ngòm trước mặt. Nuốt chửng mọi mũi tên, đạn pháo vật lý hoặc đạn phép thuật bay tới và chuyển chúng vào hư vô. Tồn tại trong 3 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Không Gian"], range_type: "Bản thân (Phòng thủ đa hướng)", combo_tag: "Mini_Blackhole" },
        { name: "Lời Nguyền Suy Yếu", desc: "[Cơ chế] Yểm khí tức hắc ám làm tắc nghẽn kinh mạch và rũ liệt cơ bắp. [Hiệu ứng] Bắn một tia đen vào ngực kẻ địch. Lập tức giảm 40% Sức mạnh công kích (STR/INT) và 40% Tốc độ di chuyển (AGI) của mục tiêu trong 30 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Nguyền Rủa"], range_type: "Tầm Xa (Debuff)", combo_tag: "Curse_Weaken" },
        { name: "Gai Bóng Tối", desc: "[Cơ chế] Điều khiển cái bóng dưới mặt đất mọc lên thành tinh thể rắn sắc bén. [Hiệu ứng] Đột ngột phóng hàng loạt gai nhọn đâm xuyên từ cái bóng của chính kẻ địch hoặc từ góc khuất. Sát thương cấu rỉa liên tục, cực khó né tránh.", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "AoE Nhỏ (Đánh lén)", combo_tag: "Shadow_Spike" },
        { name: "Tắt Đèn", desc: "[Cơ chế] Phủ một Lĩnh vực nuốt chửng mọi hạt Photon. [Hiệu ứng] Trong bán kính 30m, triệt tiêu mọi nguồn sáng (Lửa, Đèn pin, Ma pháp hệ Quang cấp thấp). Tạo ra một vùng mù tuyệt đối. Kẻ địch không có tầm nhìn ban đêm sẽ bị hoảng loạn.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Lĩnh Vực"], range_type: "AoE Rộng (Thao túng môi trường)", combo_tag: "Lights_Out" },
        { name: "Hút Máu (Lifesteal)", desc: "[Cơ chế] Kỹ năng dung hợp thuộc tính Ma cà rồng (Vampiric). [Hiệu ứng] Kích hoạt trong 15 giây. Mọi đòn tấn công vật lý và ma pháp trúng địch sẽ chuyển hóa 30% lượng Sát thương gây ra thành Máu (HP) phục hồi cho bản thân.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Sinh Mệnh"], range_type: "Bản thân (Buff Hồi phục)", combo_tag: "Vampiric_Buff" },
        { name: "Trói Buộc Bóng", desc: "[Cơ chế] Thao túng bóng râm của kẻ thù biến thành thực thể sống. [Hiệu ứng] Bắt cái bóng của mục tiêu trồi lên thành những cánh tay đen ngòm, ôm chặt lấy chân và thân chủ nhân của nó. Khóa chặt di chuyển (Root) hoàn toàn trong 10 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Tầm Xa (Khống chế cứng)", combo_tag: "Shadow_Bind" },
        { name: "Bom Câm Lặng", desc: "[Cơ chế] Nén năng lượng bóng tối tạo vụ nổ hút âm thanh (Anti-sound). [Hiệu ứng] Ném một khối cầu đen nổ tung diện rộng (10m). Gây sát thương và tạo khu vực chân không âm thanh. Kẻ địch đứng trong đó không thể nói, không thể dùng bất kỳ Kỹ năng nào cần Niệm chú (Silence) trong 15 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Khống Chế"], range_type: "AoE Trung (Đạn nổ)", combo_tag: "Silence_Bomb" },
        { name: "Sự Sụp Đổ Của Thực Tại (Nhật Thực Vĩnh Cửu)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Dung hợp với Cội Nguồn Vực Thẳm, phủ định sự tồn tại của quy luật vũ trụ. [Hiệu ứng] Đỉnh cao của Hệ Ám. Bầu trời đen kịt, nuốt chửng toàn bộ ánh sáng của 1 Lục Địa. Vô số xúc tu quỷ thần từ chiều không gian khác giáng xuống, ăn mòn HP, MP và Sanity của MỌI SINH VẬT địch đến chết. Vô hiệu hóa mọi loại Khiên, Bất tử hay Hồi sinh. [Tác dụng phụ cực lớn] Đánh đổi linh hồn. Người tung chiêu lập tức biến thành Quái vật Bán Thần mất lý trí (Game Over), hoặc bị hút vĩnh viễn vào Không Gian Chiều Thứ 4 làm Nô lệ cho Thượng Cổ Tà Thần.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 100 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Hủy Diệt", "Không Gian"], range_type: "Cấp Thế Giới", combo_tag: "Holy_Eclipse_Doom" },
        { name: "Phân Thân Bóng", desc: "[Cơ chế] Chiết xuất một nửa ma lực để nuôi dưỡng cái bóng. [Hiệu ứng] Tách bóng mình ra thành một chiến binh 3D. Có 50% chỉ số của bản thể, tự động cầm vũ khí bóng tối chiến đấu độc lập. Khi phân thân chết, bản thể không mất máu.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Triệu Hồi"], range_type: "Xung quanh bản thân", combo_tag: "Shadow_Clone" },
        { name: "Hoán Đổi Vị Trí", desc: "[Cơ chế] Đồng bộ tọa độ không gian qua đường hầm lượng tử bóng râm. [Hiệu ứng] Lập tức đổi chỗ với bóng của chính mình (Phân Thân) hoặc đổi chỗ với cái bóng của kẻ thù. Dùng để né đòn tất sát trong tấc tắc hoặc kéo Pháp sư địch vào giữa đội hình phe ta.", rank: "Kim Giai", cost: { type: "MP", value: 80000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Không Gian"], range_type: "Bản thân & Mục tiêu", combo_tag: "Shadow_Swap" },
        { name: "Ăn Mòn Lý Trí", desc: "[Cơ chế] Tỏa ra khí tức của Thượng Cổ Tà Thần (Eldritch). [Hiệu ứng] Tiếng thì thầm điên rợn vang lên trong đầu mục tiêu. Không trừ HP, nhưng rút 5 điểm Sanity (Lý trí) mỗi giây trong 20 giây. Khiến địch hoảng loạn, nếu Sanity < 20, chúng sẽ vứt vũ khí tự cào cấu mặt mình.", rank: "Kim Giai", cost: { type: "MP", value: 100000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "Tầm Xa (Tấn công Tâm thần)", combo_tag: "Sanity_Corrosion" },
        { name: "Ký Sinh Bóng Đêm", desc: "[Cơ chế] Đưa một con giun bóng tối bám vào đan điền địch. [Hiệu ứng] Gài bẫy. Kẻ địch không hề hay biết. Ngay khi chúng niệm một chiêu thức tốn MP, mầm mống này sẽ hút lượng MP đó để nổ tung từ bên trong bụng chúng (Gây sát thương nội tạng nghiêm trọng).", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Bẫy"], range_type: "Tầm Xa (Debuff ẩn)", combo_tag: "Shadow_Parasite" },
        { name: "Mạng Nhện Đen", desc: "[Cơ chế] Dệt các sợi hắc ám ngăn chặn sóng vô tuyến. [Hiệu ứng] Phóng lưới bóng tối bám vào trần hang hoặc lối đi. Không chỉ trói chân kẻ thù mà còn hấp thụ hoàn toàn sóng Radar, sóng hồng ngoại và liên lạc vô tuyến của đội hình UHA đi qua.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Đặt Bẫy (Tầm Trung)", combo_tag: "Dark_Web" },
        { name: "Vực Thẳm (Lãnh Vực Cô Lập)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Xé rách ranh giới thực tại, kéo mục tiêu vào một Không Gian Tối do chính mình làm chủ. [Hiệu ứng] Kéo 1 kẻ địch (Dù mạnh đến đâu) biến mất khỏi chiến trường, rơi vào Vực Thẳm để Solo 1vs1. Trong này, toàn bộ chỉ số của người dùng x3, đối thủ bị mù và điếc một nửa. [Tác dụng phụ] Hút 80% Max MP và 50 điểm Sanity. Nếu không giết được địch trong 10 phút, Lĩnh vực vỡ, người dùng rơi vào trạng thái Kiệt sức suy kiệt (Giảm 90% stats) trong 3 ngày.", rank: "Diệu Giai", cost: { type: "MP", value: 5000000 }, cooldown: { value: 30, unit: "Ngày", display_text: "1 Tháng" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Không Gian", "Lĩnh Vực"], range_type: "Cận Chiến (Khóa mục tiêu tuyệt đối)", combo_tag: "Divine_Abyss_Domain" },
        { name: "Nhìn Trong Đêm (Passive)", desc: "[Cơ chế] Đồng tử phủ lớp màng hắc diện thạch, phân tích vật chất bằng sóng hắc ám. [Hiệu ứng] Mắt sáng rực màu đỏ/tím. Thị giác hoàn hảo trong bóng tối đen đặc như mực. Có thể nhìn thấy rõ các dòng chảy năng lượng giấu sau tường.", rank: "Phàm Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Bản thân (Tình báo)", combo_tag: "Dark_Vision" },
        { name: "Hồi Phục Trong Bóng Tối", desc: "[Cơ chế] Tế bào quang hợp ngược, biến bóng tối thành dưỡng chất. [Hiệu ứng] Nội tại sinh tồn. Đứng trong bóng râm, hang động hoặc vào ban đêm, tốc độ hồi máu (HP) và năng lượng (MP) tự nhiên được tăng gấp 4 lần.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám"], range_type: "Bản thân (Hồi phục)", combo_tag: "Shadow_Regen" },
        { name: "Giấu Khí (Stealth)", desc: "[Cơ chế] Bọc cơ thể bằng lớp màng hấp thụ nhịp tim và sóng não. [Hiệu ứng] Xóa bỏ hoàn toàn sát khí, thân nhiệt và hiện diện. Tamer/Thú có thể thản nhiên đi ngang qua bầy thú dữ cấp cao mà chúng tưởng đó chỉ là một luồng gió mát.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Bản thân (Tàng hình sát khí)", combo_tag: "Conceal_Aura" },
        { name: "Kho Chứa Đồ Bóng Tối (Utility)", desc: "[Cơ chế] Mở rộng không gian của chiếc bóng thành túi đồ không đáy. [Hiệu ứng] Cất giấu mọi vật phẩm (kể cả xác chết, súng pháo) vào cái bóng của mình. Sức chứa vô hạn, không bị máy quét sân bay/pháo đài phát hiện. Tuyệt kỹ buôn lậu.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Không Gian"], range_type: "Tiện ích (Túi đồ)", combo_tag: "Shadow_Inventory" },
        { name: "Cắt Bóng (Voodoo)", desc: "[Cơ chế] Ma thuật lời nguyền cao cấp: Bóng và Hình là một. [Hiệu ứng] Lướt ra sau mục tiêu và chém đứt cái bóng dưới đất của chúng. Kẻ thù lập tức chịu vết thương y hệt trên cơ thể thực (Đứt tay/Đứt cổ) mà không hiểu tại sao. Sát thương bỏ qua Giáp Vật Lý.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Nguyền Rủa"], range_type: "Tầm Trung (Chém Bóng)", combo_tag: "Shadow_Sever" },
        { name: "Áo Choàng Bóng Đêm", desc: "[Cơ chế] Kéo dãn màn đêm bao phủ vật thể sống. [Hiệu ứng] Rải Áo choàng tàng hình lên toàn bộ 5 đồng đội. Che giấu cả team trong bóng tối để cùng di chuyển bí mật, rút lui an toàn khỏi vòng vây mà không ai hay biết.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Ảo Giác"], range_type: "AoE Trung (Tàng hình tập thể)", combo_tag: "Cloak_of_Night" },
        { name: "Thì Thầm Hư Không", desc: "[Cơ chế] Truyền sóng âm qua hạt hắc ám. [Hiệu ứng] Gửi tin nhắn giọng nói bí mật thẳng vào não đồng minh (hoặc đe dọa vào não địch) ở khoảng cách 5km mà không tạo ra bất kỳ tiếng động nào ở môi trường ngoài.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "Tầm Xa (Tiện ích)", combo_tag: "Void_Whisper" },
        { name: "Bẫy Hố", desc: "[Cơ chế] Chuyển đổi mặt đất cứng thành cánh cổng Không Gian Ám. [Hiệu ứng] Tạo một vòng tròn đen đặc dưới chân địch. Làm chúng rơi tụt xuống dưới (Stun 2 giây), sau đó hố nhả chúng ra, gây sát thương va đập ngột ngạt.", rank: "Thiết Giai", cost: { type: "MP", value: 280 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Không Gian"], range_type: "Đặt Bẫy (Tầm Trung)", combo_tag: "Dark_Pitfall" },
        { name: "Ngủ Mê", desc: "[Cơ chế] Xâm nhập vào tiềm thức, đưa giấc mơ ác mộng đè lên não bộ. [Hiệu ứng] Kéo kẻ địch vào giấc ngủ sâu. Trong lúc ngủ, chúng liên tục mất MP và Sanity vì hoảng sợ. Khó bị đánh thức hơn các phép ngủ hệ Quang/Độc.", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Tinh Thần"], range_type: "Tầm Xa (Khống chế)", combo_tag: "Nightmare_Sleep" },
        { name: "Bảo Vệ Khỏi Ánh Sáng", desc: "[Cơ chế] Tạo lớp kem chống nắng bằng hạt bóng tối. [Hiệu ứng] Phủ lên các sinh vật (hoặc Dị thú Bóng tối) lớp màng mỏng. Giúp chúng đi lại tự do vào buổi trưa nắng gắt mà không bị thiêu đốt hay giảm sức mạnh.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Cận Chiến (Buff tiện ích)", combo_tag: "Sun_Blocker" },
        { name: "Mở Khóa Bóng Tối", desc: "[Cơ chế] Chuyển vật chất tay thành bóng, luồn vào khe hở nhỏ nhất. [Hiệu ứng] Đút ngón tay bóng tối vào ổ khóa, định hình lại cấu trúc bên trong. Mở tung mọi két sắt, cửa nhà giam vật lý trong 1 giây.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 5, unit: "Giây", display_text: "5 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Cận Chiến (Tiện ích)", combo_tag: "Shadow_Key" },
        { name: "Hấp Thụ Thi Thể", desc: "[Cơ chế] Mở mồm rộng như rắn khổng lồ, nuốt chửng vào không gian bóng. [Hiệu ứng] Dọn dẹp hiện trường. Nhấn chìm hoàn toàn xác chết địch (hoặc quái vật) xuống bóng tối. Phi tang không để lại một giọt máu, không thể bị điều tra.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ám"], range_type: "Cận Chiến (Phi tang)", combo_tag: "Corpse_Devour" },
        { name: "Lưỡi Hái Tử Thần", desc: "[Cơ chế] Triệu hồi Thần Chết mang theo pháp tắc Tước Đoạt. [Hiệu ứng] Vung một nhát chém bằng hắc ám. Nếu kẻ địch hiện tại đang có HP dưới 15% (Ngưỡng máu tử hình), nhát chém này sẽ bỏ qua mọi lớp khiên/bất tử và kết liễu chúng ngay lập tức (Execute).", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Sinh Mệnh"], range_type: "Cận Chiến (Tuyệt sát)", combo_tag: "Reaper_Execute" },
        { name: "Khủng Bố Tinh Thần (Tiếng Thét Đêm Đen)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Kéo giãn màng chắn giữa Thế Giới Thực và Vùng Zero, thả ra tiếng gầm của các Entitiy tà ác. [Hiệu ứng] Sóng âm kết hợp ảo giác kinh hoàng. Toàn bộ Lính đánh thuê/Thú hoang trong bán kính 2km lập tức phát điên, Sanity tụt về 0. Chúng sẽ tự cắn xé nhau hoặc tự sát vì không chịu nổi ảo ảnh. [Tác dụng phụ] Hút cạn Sanity của Ký chủ. Ký chủ sẽ mắc chứng Rối loạn nhân cách, ngẫu nhiên tấn công đồng đội trong 7 ngày, giảm 50% INT vĩnh viễn.", rank: "Diệu Giai", cost: { type: "Sanity", value: 80 }, cooldown: { value: 60, unit: "Ngày", display_text: "2 Tháng" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Ám", "Tinh Thần", "Sóng Âm"], range_type: "AoE Rất Rộng (Cấp Thảm Họa)", combo_tag: "Divine_Terror_Scream" }
    ],
    "Mixed": [
        { name: "Lôi Hỏa Liên Kích", desc: "[Cơ chế] Tích hợp năng lượng Hỏa vào dòng điện cao thế. [Hiệu ứng] Bắn ra luồng điện lửa gây sát thương kép. Mục tiêu bị choáng trong 3 giây và nhận hiệu ứng [Bỏng Phóng Điện] trừ 2% HP mỗi giây trong 10 giây. [Tương tác] Sát thương tăng 20% nếu mục tiêu đang ướt.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Hệ Lôi"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Electrified_Burn" },
        { name: "Thanh Lam Băng Chùy", desc: "[Cơ chế] Nén nước áp suất cao rồi đông cứng đột ngột thành khối nhọn. [Hiệu ứng] Phóng đại băng chùy mang động năng lớn. Xuyên phá giáp vật lý và gây trạng thái [Lạnh Thấu Xương] làm giảm 40% tốc độ di chuyển trong 15 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Nước", "Hệ Băng"], range_type: "Tầm Xa (Xuyên thấu)", combo_tag: "Hydro_Freeze" },
        { name: "Huyền Thổ Hộ Thân", desc: "[Bị động] [Cơ chế] Lớp da được cường hóa bởi tinh thể khoáng vật địa mạch. [Hiệu ứng] Khi HP xuống dưới 30%, tự động tạo lớp giáp đá dày hấp thụ 5000 sát thương vật lý. Lớp giáp duy trì trong 60 giây hoặc đến khi bị phá vỡ.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Hệ Cường Hóa"], range_type: "Bản thân (Bị động)", combo_tag: "Stone_Skin_Passive" },
        { name: "Phong Lôi Toàn Vũ", desc: "[Cơ chế] Tạo cơn lốc xoáy mang điện tích nồng độ cao. [Hiệu ứng] Cuốn bay mọi mục tiêu trong bán kính 15m lên không trung trong 5 giây, gây sát thương lôi điện liên tục. [Tác dụng phụ] Giảm 20% chính xác của đồng đội trong vùng ảnh hưởng.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Hệ Lôi"], range_type: "AoE Trung", combo_tag: "Storm_CC" },
        { name: "Mộc Độc U Linh", desc: "[Cơ chế] Dùng linh lực hệ Mộc nuôi dưỡng bào tử độc từ Hệ Độc. [Hiệu ứng] Phát tán phấn hoa trong bán kính 20m. Kẻ địch hít phải sẽ bị [Ảo Giác Thực Vật], thấy dây leo quấn quanh người và nhận sát thương độc 3% HP mỗi giây trong 20 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Hệ Độc Dược"], range_type: "AoE Trung (Môi trường)", combo_tag: "Toxic_Flora" },
        { name: "Quang Ảnh Thuật", desc: "[Bị động] [Cơ chế] Thao túng các hạt photon xung quanh bản thể. [Hiệu ứng] Khi đứng dưới ánh sáng mặt trời, nhận hiệu ứng [Mờ Ảo] tăng 25% tỉ lệ né tránh. Khi đứng trong bóng tối, hồi phục 1% MP mỗi 5 giây.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Hệ Bóng Tối"], range_type: "Bản thân (Bị động)", combo_tag: "Light_Dark_Balance" },
        { name: "Kim Cương Bất Hoại Thân", desc: "[Diệu Giai] [Cơ chế] Tái cấu trúc phân tử cơ thể sang dạng liên kết carbon-kim loại thần thánh. [Hiệu ứng] Miễn nhiễm hoàn toàn với mọi sát thương vật lý và ma pháp cấp bậc Kim Giai trở xuống trong 30 giây. [Tác dụng phụ lớn] Sau khi kết thúc, toàn bộ cơ bắp bị tê liệt, giảm 90% AGI trong 1 giờ. Tiêu hao sạch Stamina.", rank: "Diệu Giai", cost: { type: "MP", value: 1200000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Kim Loại", "Hệ Cường Hóa"], range_type: "Bản thân (Buff Tuyệt Đối)", combo_tag: "Invincible_Diamond" },
        { name: "Minh Sát Thời Không", desc: "[Cơ chế] Mở rộng ý thức ra ngoài chiều thời gian tuyến tính để quan sát quá khứ gần. [Hiệu ứng] Nhìn thấy bóng ma của mục tiêu trong 10 giây trước đó, cho phép truy vết chính xác vị trí tàng hình hoặc các đòn bẫy đã đặt.", rank: "Kim Giai", cost: { type: "Sanity", value: 15 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Hệ Thời Không"], range_type: "Bản thân (Do thám)", combo_tag: "Time_Echo" },
        { name: "Vạn Vật Quy Hủy", desc: "[Thánh Giai] [Cơ chế] Giải phóng hạt phân rã khái niệm lên vật chất thực tại. [Hiệu ứng] Xóa sổ sự tồn tại của mọi vật thể trong bán kính 100m. Không để lại dấu vết, bỏ qua mọi cấp độ phòng ngự. [Tác dụng phụ cực lớn] Giảm vĩnh viễn 10 điểm SPI. Người dùng rơi vào trạng thái [Vô Hồn] trong 3 ngày, không thể nhận thức xung quanh.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 85 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Hệ Khái Niệm"], range_type: "AoE Rộng (Hủy diệt vĩnh viễn)", combo_tag: "Conceptual_Erasure" },
        { name: "Sinh Mệnh Sáng Tạo Chi Chú", desc: "[Thánh Giai] [Cơ chế] Thao túng khái niệm 'Sự Sống' để kiến tạo thực thể từ hư không. [Hiệu ứng] Tái tạo hoàn toàn một đồng minh đã chết (trong vòng 1 giờ) với 100% HP/MP và nâng cấp vĩnh viễn 1 bậc POT cho họ. [Tác dụng phụ cực lớn] Người dùng mất vĩnh viễn 20% Max HP. Tuổi thọ bị cắt giảm 10 năm.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 100 }, cooldown: { value: 10, unit: "Năm", display_text: "10 Năm" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Hệ Khái Niệm"], range_type: "Đơn mục tiêu (Hồi sinh tối thượng)", combo_tag: "Genesis_Revive" },
        { name: "Hỏa Độc Phệ Tâm", desc: "[Cơ chế] Truyền chất độc cháy bỏng vào huyết quản đối thủ qua vết thương hở. [Hiệu ứng] Gây sát thương hỏa liên tục. Độc tố khiến mục tiêu bị giảm 50% hiệu quả hồi máu trong 60 giây. Nếu không giải độc, mỗi 10 giây sẽ bộc phát một vụ nổ nội tạng nhỏ.", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Hệ Độc Dược"], range_type: "Cận chiến (Gài độc)", combo_tag: "Infernal_Toxin" },
        { name: "Băng Ảnh Phân Thân", desc: "[Cơ chế] Tạo ra các bản sao từ băng tinh có chứa một phần ý thức Bóng Tối. [Hiệu ứng] Tạo 3 phân thân. Khi phân thân bị tiêu diệt, chúng sẽ nổ tung gây trạng thái [Đóng Băng] trong 3 giây và [Mù Lòa] trong 5 giây cho kẻ phá hủy chúng.", rank: "Kim Giai", cost: { type: "MP", value: 12000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Hệ Bóng Tối"], range_type: "Xung quanh bản thân", combo_tag: "Frozen_Shadow" },
        { name: "Thiên Địa Lôi Đình Ấn", desc: "[Diệu Giai] [Cơ chế] Mượn uy áp của trời đất nén vào lòng bàn tay. [Hiệu ứng] Giáng xuống một cột sét mang theo áp lực của Hệ Thổ. Gây 1,000,000 sát thương lôi điện và đè bẹp mục tiêu xuống đất, khiến chúng không thể di chuyển trong 10 giây.", rank: "Diệu Giai", cost: { type: "MP", value: 2500000 }, cooldown: { value: 3, unit: "Giờ", display_text: "3 Giờ" }, cast_time: { value: 8, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Hệ Thổ"], range_type: "Tầm Xa (AoE Nhỏ)", combo_tag: "Heavenly_Thunder_Crush" },
        { name: "Mộc Linh Quang Hồi", desc: "[Bị động] [Cơ chế] Tế bào thực vật trong cơ thể hấp thụ quang năng để tái tạo. [Hiệu ứng] Khi đứng dưới ánh sáng mặt trời hoặc các nguồn sáng mạnh, tốc độ hồi phục HP tự nhiên tăng 500%. Tự động thanh tẩy các loại độc tố cấp thấp sau mỗi 30 giây.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Hệ Ánh Sáng"], range_type: "Bản thân (Bị động)", combo_tag: "Solar_Regen" },
        { name: "Không Gian Liệt Trảm", desc: "[Cơ chế] Cường hóa cạnh tay bằng năng lượng không gian để xé rách thực tại. [Hiệu ứng] Đòn chém bỏ qua 100% DEF của mục tiêu, cắt đứt cả các liên kết ma pháp. Có thể cắt xuyên qua các lớp khiên không gian của đối thủ.", rank: "Kim Giai", cost: { type: "MP", value: 25000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Hệ Thời Không"], range_type: "Cận chiến", combo_tag: "Space_Cutter" },
        { name: "Độc Phong Loạn Vũ", desc: "[Cơ chế] Tạo ra các lưỡi đao gió mang theo kịch độc ăn mòn. [Hiệu ứng] Tung ra 10 lưỡi đao gió bay ngẫu nhiên. Mỗi lưỡi đao trúng địch gây vết thương sâu và hiệu ứng [Ăn Mòn Giáp] giảm 5% DEF vĩnh viễn (tối đa 30%) trong trận chiến.", rank: "Ngân Giai", cost: { type: "MP", value: 3600 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Hệ Độc Dược"], range_type: "AoE Trung (Ngẫu nhiên)", combo_tag: "Corrosive_Wind" },
        { name: "Hủy Diệt Lôi Nhãn", desc: "[Diệu Giai] [Cơ chế] Tập trung năng lượng hủy diệt vào con mắt thứ ba. [Hiệu ứng] Bắn ra tia sét đen phá hủy mọi liên kết nguyên tử của mục tiêu. Sát thương cực lớn, có 10% tỉ lệ xóa sổ hoàn toàn một kỹ năng bị động của đối phương trong 1 giờ.", rank: "Diệu Giai", cost: { type: "MP", value: 3500000 }, cooldown: { value: 12, unit: "Giờ", display_text: "12 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Hệ Hủy Diệt"], range_type: "Tầm Xa (Chùm tia)", combo_tag: "Annihilation_Beam" },
        { name: "Bóng Tối Tê Liệt", desc: "[Bị động] [Cơ chế] Hào quang bóng tối bao quanh sủng thú gây nhiễu loạn thần kinh. [Hiệu ứng] Kẻ địch trong bán kính 5m quanh người dùng sẽ bị giảm 20% AGI và có 5% tỉ lệ bị [Tê Liệt] trong 2 giây sau mỗi 10 giây tiếp xúc.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Bóng Tối", "Hệ Tinh Thần"], range_type: "AoE Nhỏ (Xung quanh bản thân)", combo_tag: "Shadow_Aura" },
        { name: "Thời Không Phản Nguyên", desc: "[Diệu Giai] [Cơ chế] Đảo ngược thời gian của một vùng không gian nhỏ về trạng thái 5 giây trước. [Hiệu ứng] Phục hồi toàn bộ HP/MP và vị trí của bản thân về trạng thái của 5 giây trước đó. Xóa bỏ mọi debuff nhận được trong khoảng thời gian này.", rank: "Diệu Giai", cost: { type: "Sanity", value: 40 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không", "Hệ Sáng Tạo"], range_type: "Bản thân", combo_tag: "Time_Reverse" },
        { name: "Kim Ma Thể", desc: "[Bị động] [Cơ chế] Da thịt hấp thụ kim loại và năng lượng Bóng Tối. [Hiệu ứng] Tăng 50% DEF vật lý. Khi bị tấn công bởi vũ khí kim loại, có 15% tỉ lệ hút 10 MP từ đối thủ.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim Loại", "Hệ Bóng Tối"], range_type: "Bản thân (Bị động)", combo_tag: "Metal_Dark_Body" },
        { name: "Thủy Quang Tịnh Hóa", desc: "[Cơ chế] Kết hợp tính tẩy rửa của Nước và tính thanh khiết của Ánh Sáng. [Hiệu ứng] Thanh tẩy hoàn toàn mọi debuff, nguyền rủa và trạng thái [Ô Nhiễm] cho tối đa 5 đồng đội. Hồi phục 15% HP cho mỗi mục tiêu.", rank: "Ngân Giai", cost: { type: "MP", value: 6500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Nước", "Hệ Ánh Sáng"], range_type: "AoE Trung", combo_tag: "Holy_Wash" },
        { name: "Thổ Mộc Cộng Sinh", desc: "[Bị động] [Cơ chế] Rễ cây cộng sinh với địa mạch dưới chân sủng thú. [Hiệu ứng] Khi đứng trên mặt đất tự nhiên (rừng, núi), tăng 30% CON và hồi phục 2% Stamina mỗi 10 giây. Tăng khả năng kháng hất tung thêm 50%.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Hệ Mộc"], range_type: "Bản thân (Bị động)", combo_tag: "Nature_Roots" },
        { name: "Hủy Diệt Hỏa Diệm", desc: "[Cơ chế] Ngọn lửa mang theo đặc tính phân rã vật chất. [Hiệu ứng] Phun ra luồng lửa đen không thể dập tắt bằng nước thông thường. Gây sát thương chuẩn và ngăn chặn mục tiêu hồi phục trong 15 giây.", rank: "Kim Giai", cost: { type: "MP", value: 45000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Hệ Hủy Diệt"], range_type: "Hình Nón (Tầm Trung)", combo_tag: "Black_Fire" },
        { name: "Cường Hóa Ảnh Trảo", desc: "[Cơ chế] Bao phủ móng vuốt bằng lớp vật chất bóng tối cô đặc. [Hiệu ứng] Đòn đánh cận chiến tăng 40% STR. Có 30% tỉ lệ gây hiệu ứng [Mù Lòa] trong 2 giây. Đòn đánh có thể chạm vào các thực thể linh hồn.", rank: "Ngân Giai", cost: { type: "MP", value: 1200 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Hệ Bóng Tối"], range_type: "Cận chiến", combo_tag: "Shadow_Claw" },
        { name: "Tâm Tinh Thạch Ấn", desc: "[Cơ chế] Dùng năng lượng Tinh Thần để điều khiển các khối đá bao vây mục tiêu. [Hiệu ứng] Giam cầm mục tiêu trong một khối đá hình cầu. Mục tiêu bị khóa chặt và liên tục nhận sát thương tinh thần 1% Sanity mỗi giây trong 10 giây.", rank: "Kim Giai", cost: { type: "MP", value: 18000 }, cooldown: { value: 8, unit: "Phút", display_text: "8 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Hệ Thổ"], range_type: "Tầm Xa (Khống chế)", combo_tag: "Mental_Stone_Prison" },
        { name: "Quang Minh Lôi Kích", desc: "[Cơ chế] Chùm tia sáng nồng độ cao mang theo điện tích mạnh. [Hiệu ứng] Bắn ra tia laser chớp nhoáng. Gây sát thương cực lớn và tước bỏ toàn bộ các trạng thái buff hệ Bóng Tối của mục tiêu.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hệ Lôi"], range_type: "Đường thẳng (Beam)", combo_tag: "Holy_Laser" },
        { name: "Khái Niệm Trường Thọ", desc: "[Bị động] [Cơ chế] Ghi đè khái niệm 'Bất hủ' vào cấu trúc tế bào mộc. [Hiệu ứng] Tăng vĩnh viễn tuổi thọ thêm 50 năm. Giảm 30% tốc độ lão hóa và tăng 20% kháng các loại hiệu ứng [Tử Vong] hoặc [Héo Úa].", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Hệ Khái Niệm"], range_type: "Bản thân (Bị động)", combo_tag: "Eternal_Life" },
        { name: "Huyết Độc Cường Hóa", desc: "[Cơ chế] Kích thích tủy xương sản sinh ra máu độc mang theo năng lượng cường hóa. [Hiệu ứng] Tăng 50% STR và 30% AGI trong 120 giây. Mỗi khi tấn công, có 50% tỉ lệ làm mục tiêu bị nhiễm kịch độc trừ 2% HP mỗi giây.", rank: "Ngân Giai", cost: { type: "HP", value: 1000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Độc Dược", "Hệ Cường Hóa"], range_type: "Bản thân (Buff)", combo_tag: "Toxic_Blood_Rush" },
        { name: "Thời Không Hủy Diệt", desc: "[Diệu Giai] [Cơ chế] Phá vỡ sự ổn định của thời gian tại một điểm cụ thể. [Hiệu ứng] Tạo ra một lỗ hổng thời gian nuốt chửng mọi vật chất xung quanh. Mục tiêu trúng đòn bị loại bỏ khỏi thực tại trong 10 giây và nhận sát thương hủy diệt bằng 40% Max HP sau khi trở lại.", rank: "Diệu Giai", cost: { type: "MP", value: 4500000 }, cooldown: { value: 12, unit: "Giờ", display_text: "12 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Hệ Hủy Diệt"], range_type: "Tầm Xa (Hố đen)", combo_tag: "Time_Collapse" },
        { name: "Sáng Tạo Kim Thân", desc: "[Cơ chế] Kiến tạo một lớp giáp kim loại từ hư không bao phủ cơ thể. [Hiệu ứng] Tăng 200% DEF trong 300 giây. Lớp giáp có khả năng tự phục hồi độ bền sau mỗi 10 giây chiến đấu.", rank: "Kim Giai", cost: { type: "MP", value: 35000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 8, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Hệ Kim Loại"], range_type: "Bản thân (Buff)", combo_tag: "Created_Armor" },
        { name: "Hỏa Lưu Thủy", desc: "[Cơ chế] Dung hợp nhiệt lượng của lửa vào sự linh hoạt của nước. [Hiệu ứng] Phun ra dòng nước sôi 2000°C. Vừa gây sát thương Hỏa (Bỏng), vừa gây sát thương Nước (Lực đẩy). Có thể dập tắt lửa của kẻ thù mà không làm giảm nhiệt độ vùng chiến sự.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Hệ Nước"], range_type: "Hình Nón (Tầm Trung)", combo_tag: "Boiling_Stream" },
        { name: "Phong Sát Kim Đao", desc: "[Cơ chế] Gắn hàng ngàn mảnh kim loại siêu nhỏ vào cơn lốc gió. [Hiệu ứng] Tạo bão đao gió cắt nát mọi vật cản. Mục tiêu bị giảm 40% DEF vật lý do bị bào mòn bề mặt giáp liên tục trong 20 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Hệ Kim Loại"], range_type: "AoE Trung", combo_tag: "Metallic_Storm" },
        { name: "Băng Lôi Tàn Diệp", desc: "[Cơ chế] Tích điện vào các bông tuyết rơi. [Hiệu ứng] Khi tuyết chạm vào mục tiêu, chúng nổ tung giải phóng tia điện làm tê liệt đối thủ trong 1 giây. Mỗi bông tuyết nổ gây sát thương Băng và Lôi cộng dồn.", rank: "Thiết Giai", cost: { type: "MP", value: 600 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Hệ Lôi"], range_type: "AoE Nhỏ", combo_tag: "Frost_Bolt" },
        { name: "Thổ Độc Chướng Khí", desc: "[Cơ chế] Kích hoạt các túi khí độc nằm sâu trong lòng đất. [Hiệu ứng] Làm mặt đất nứt ra, phun khí độc và bụi đá gây mù lòa và trúng độc [Thối Rữa] giảm 5% STR mỗi 10 giây, kéo dài trong 60 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 800 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Hệ Độc Dược"], range_type: "AoE Nhỏ (Vị trí địch)", combo_tag: "Earthy_Toxin" },
        { name: "Quang Minh Cường Hóa", desc: "[Bị động] [Cơ chế] Ánh sáng tích hợp vào mô cơ bắp. [Hiệu ứng] Tăng 15% AGI. Mỗi khi kích hoạt kỹ năng hệ Ánh Sáng, nhận thêm 10% sát thương vật lý trong 10 giây.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Ánh Sáng", "Hệ Cường Hóa"], range_type: "Bản thân (Bị động)", combo_tag: "Light_Strength" },
        { name: "Bóng Tối Khái Niệm", desc: "[Cơ chế] Áp đặt khái niệm 'Sự hư vô' vào vùng bóng tối. [Hiệu ứng] Biến mục tiêu thành một bóng ma thực sự trong 20 giây. Trong thời gian này mục tiêu không thể gây sát thương và cũng không thể nhận sát thương (Dùng để cô lập kẻ mạnh).", rank: "Kim Giai", cost: { type: "MP", value: 20000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Bóng Tối", "Hệ Khái Niệm"], range_type: "Tầm Xa (Khống chế khái niệm)", combo_tag: "Void_State" },
        { name: "Mộc Thần Hồi Xuân", desc: "[Diệu Giai] [Cơ chế] Triệu hồi ý chí của Thần Mộc đại lục. [Hiệu ứng] Hồi phục 80% HP cho toàn bộ đồng đội trong bán kính 1km. Hồi sinh các vùng đất bị ô nhiễm, biến hoang mạc thành rừng rậm trong 10 phút.", rank: "Diệu Giai", cost: { type: "MP", value: 1800000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Hệ Sáng Tạo"], range_type: "AoE Cực Rộng", combo_tag: "Nature_Genesis" },
        { name: "Tâm Linh Hủy Diệt", desc: "[Cơ chế] Tấn công trực diện vào gốc rễ linh hồn bằng năng lượng hủy diệt. [Hiệu ứng] Gây sát thương cực lớn lên Sanity của mục tiêu (Trừ 30 Sanity ngay lập tức). Nếu mục tiêu có Sanity < 20, chúng sẽ bị [Điên Loạn] vĩnh viễn cho đến khi được đại sư chữa trị.", rank: "Kim Giai", cost: { type: "Sanity", value: 25 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Hệ Hủy Diệt"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Soul_Shatter" },
        { name: "Thời Không Cường Hóa", desc: "[Bị động] [Cơ chế] Cơ thể tồn tại giữa các khe hở thời gian. [Hiệu ứng] Tăng vĩnh viễn 40% tỉ lệ né tránh đạn tầm xa. Mỗi khi di chuyển 100m, tự động giảm 1 giây hồi chiêu cho toàn bộ kỹ năng.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không", "Hệ Cường Hóa"], range_type: "Bản thân (Bị động)", combo_tag: "Time_Agility" },
        { name: "Băng Độc Thần Công", desc: "[Cơ chế] Độc tố được bảo quản trong các hạt băng siêu nhỏ. [Hiệu ứng] Phun luồng khí băng chứa độc. Mục tiêu bị đóng băng vết thương, độc tố thấm sâu vào tủy. Gây tê liệt tứ chi trong 120 giây và sát thương độc tăng dần theo thời gian.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Hệ Độc Dược"], range_type: "Hình Nón (Tầm Trung)", combo_tag: "Frost_Venom" },
        { name: "Kim Loại Khái Niệm", desc: "[Diệu Giai] [Cơ chế] Định nghĩa lại thuộc tính 'Độ cứng' của kim loại trên quy mô lớn. [Hiệu ứng] Biến toàn bộ vũ khí và giáp kim loại của kẻ địch trong bán kính 200m thành cát bụi hoặc biến chúng thành mềm nhũn như nước trong 60 giây.", rank: "Diệu Giai", cost: { type: "MP", value: 3200000 }, cooldown: { value: 6, unit: "Giờ", display_text: "6 Giờ" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Kim Loại", "Hệ Khái Niệm"], range_type: "AoE Trung", combo_tag: "Metal_Logic_Break" },
        { name: "Hỏa Lôi Hỗn Độn", desc: "[Cơ chế] Trộn lẫn lửa và sét tạo thành năng lượng hỗn độn không ổn định. [Hiệu ứng] Bắn ra quả cầu năng lượng nổ tung gây 200,000 sát thương hỗn hợp. Có 50% tỉ lệ gây hiệu ứng [Quá Tải] làm nổ tung các thiết bị công nghệ quanh mục tiêu.", rank: "Kim Giai", cost: { type: "MP", value: 30000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Hệ Lôi"], range_type: "AoE Nhỏ (Tầm Xa)", combo_tag: "Chaos_Burst" },
        { name: "Thanh Lam Thủy Mộc", desc: "[Bị động] [Cơ chế] Dòng nước mang sự sống của rừng già chảy trong cơ thể. [Hiệu ứng] Tăng 40% khả năng hồi phục từ mọi nguồn. Khi ở dưới nước, nhận thêm hiệu ứng [Thở Bằng Da] và tăng 20% SPI.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Nước", "Hệ Mộc"], range_type: "Bản thân (Bị động)", combo_tag: "Hydro_Nature" },
        { name: "Phong Ảnh Thuật", desc: "[Cơ chế] Dùng gió bẻ cong ánh sáng xung quanh bóng tối của sủng thú. [Hiệu ứng] Tàng hình hoàn toàn trong 180 giây. Trong trạng thái này, tốc độ di chuyển tăng 50% và đòn tấn công đầu tiên từ trạng thái này gây thêm 100% sát thương chuẩn.", rank: "Ngân Giai", cost: { type: "MP", value: 2000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Hệ Bóng Tối"], range_type: "Bản thân (Tàng hình)", combo_tag: "Stealth_Wind" },
        { name: "Thổ Cường Hóa Trảm", desc: "[Cơ chế] Tăng trọng lượng vũ khí bằng năng lượng thổ nén. [Hiệu ứng] Đòn chém gây sát thương vật lý gấp 3 lần bình thường. Có 100% tỉ lệ gây [Choáng] trong 2 giây nếu mục tiêu đang đứng trên mặt đất.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Hệ Cường Hóa"], range_type: "Cận chiến", combo_tag: "Heavy_Strike" },
        { name: "Băng Hỏa Lưỡng Nghi", desc: "[Cơ chế] Duy trì sự cân bằng mong manh giữa nhiệt độ tuyệt đối và lạnh giá tuyệt đối. [Hiệu ứng] Tạo ra một vùng không gian 10m liên tục thay đổi nhiệt độ từ -100°C sang 1000°C mỗi giây. Gây sốc nhiệt, phá hủy cấu trúc vật chất của mọi kẻ địch bên trong.", rank: "Kim Giai", cost: { type: "MP", value: 65000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Băng", "Hệ Hỏa"], range_type: "AoE Nhỏ (Vị trí đặt)", combo_tag: "Thermal_Shock" },
        { name: "Quang Minh Sáng Tạo", desc: "[Cơ chế] Dùng ánh sáng đặc tạo ra các vật thể vật lý. [Hiệu ứng] Tạo ra các loại vũ khí, khiên hoặc cầu thang bằng ánh sáng tồn tại trong 600 giây. Các vật thể này có độ bền tương đương thép Lam Ngọc.", rank: "Ngân Giai", cost: { type: "MP", value: 8000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hệ Sáng Tạo"], range_type: "Tiện ích", combo_tag: "Solid_Light" },
        { name: "Bóng Tối Hủy Diệt", desc: "[Cơ chế] Ngọn hắc hỏa mang ý chí xóa sổ. [Hiệu ứng] Bắn ra chùm tia tối đen. Nếu giết chết mục tiêu, mục tiêu sẽ biến thành tro bụi và không thể hồi sinh bằng các kỹ năng dưới cấp Diệu Giai.", rank: "Kim Giai", cost: { type: "MP", value: 55000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Bóng Tối", "Hệ Hủy Diệt"], range_type: "Đường thẳng (Beam)", combo_tag: "Eraser_Ray" },
        { name: "Tâm Linh Thời Không", desc: "[Bị động] [Cơ chế] Ý thức tồn tại đa chiều. [Hiệu ứng] Miễn nhiễm hoàn toàn với các kỹ năng làm chậm thời gian hoặc ngưng đọng thời gian dưới cấp Kim Giai. Tăng 20% INT và 20% SPI.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Tinh Thần", "Hệ Thời Không"], range_type: "Bản thân (Bị động)", combo_tag: "Multidimensional_Mind" },
        { name: "Độc Dược Khái Niệm", desc: "[Cơ chế] Gán khái niệm 'Cái Chết' vào chất lỏng ma pháp. [Hiệu ứng] Một giọt chất lỏng này chạm vào bất kỳ vật gì cũng sẽ bắt đầu quá trình phân rã sinh học không thể ngăn cản. Trừ 10% HP hiện tại mỗi giây trong 15 giây.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Độc Dược", "Hệ Khái Niệm"], range_type: "Cận chiến (Chạm)", combo_tag: "Ultimate_Poison" },
        { name: "Thủy Lôi Hỗn Hợp", desc: "[Cơ chế] Dẫn điện qua dòng nước áp suất cao. [Hiệu ứng] Phun ra luồng nước tích điện cực mạnh. Gây sát thương kép và lan truyền tia sét sang tất cả kẻ địch trong bán kính 10m quanh mục tiêu chính.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Nước", "Hệ Lôi"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Electrified_Water" },
        { name: "Kim Loại Mộc Linh", desc: "[Bị động] [Cơ chế] Kim loại trong cơ thể được cấu trúc như thớ gỗ linh hoạt. [Hiệu ứng] Tăng 30% HP và 30% DEF. Khi bị tấn công bởi kỹ năng hệ Lôi, sát thương nhận vào giảm 50% nhờ đặc tính cách điện của mộc.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim Loại", "Hệ Mộc"], range_type: "Bản thân (Bị động)", combo_tag: "Metal_Nature_Alloy" },
        { name: "Phong Hỏa Hợp Thể", desc: "[Cơ chế] Dùng gió cường hóa ngọn lửa bản nguyên. [Hiệu ứng] Tăng 100% phạm vi của các kỹ năng hệ Hỏa và tăng 50% sát thương cho chúng trong 300 giây. Bản thân tỏa ra nhiệt lượng cực lớn đẩy lùi mũi tên vật lý.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Hệ Hỏa"], range_type: "Bản thân (Buff)", combo_tag: "Fire_Storm_Buff" },
        { name: "Thổ Ánh Sáng Chấn", desc: "[Cơ chế] Gây địa chấn mang theo các xung quang năng. [Hiệu ứng] Làm nổ tung mặt đất, phát ra ánh sáng chói lòa gây [Mù Lòa] trong 10 giây và sát thương chấn động mạnh mẽ làm giảm 30% DEF mục tiêu.", rank: "Thiết Giai", cost: { type: "MP", value: 1200 }, cooldown: { value: 40, unit: "Giây", display_text: "40 Giây" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Hệ Ánh Sáng"], range_type: "AoE Trung (Xung quanh)", combo_tag: "Solar_Quake" },
        { name: "Băng Bóng Tối Kết", desc: "[Bị động] [Cơ chế] Hơi lạnh tỏa ra từ hố đen nội tại. [Hiệu ứng] Mỗi khi kẻ địch tấn công cận chiến bạn, chúng có 20% tỉ lệ bị [Đóng Băng] trong 1 giây và bị hút 5 Sanity.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Hệ Bóng Tối"], range_type: "Bản thân (Bị động)", combo_tag: "Frozen_Shadow_Touch" },
        { name: "Cường Hóa Tâm Linh", desc: "[Cơ chế] Dùng ý chí sắt đá để cường hóa từng tế bào. [Hiệu ứng] Tăng 100% STR, AGI và CON trong 60 giây. Trong thời gian này, nhân vật không cảm thấy đau đớn và miễn nhiễm các hiệu ứng choáng váng.", rank: "Ngân Giai", cost: { type: "Sanity", value: 10 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Cường Hóa", "Hệ Tinh Thần"], range_type: "Bản thân (Buff)", combo_tag: "Mind_Over_Body" },
        { name: "Hủy Diệt Sáng Tạo Ấn", desc: "[Diệu Giai] [Cơ chế] Cân bằng lực lượng hủy diệt và kiến tạo để tạo ra vật chất hỗn mang. [Hiệu ứng] Tạo ra một vùng không gian 50m liên tục phân rã và tái tạo vật chất. Mọi kẻ địch bên trong nhận sát thương chuẩn khổng lồ mỗi giây.", rank: "Diệu Giai", cost: { type: "MP", value: 5000000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Hệ Sáng Tạo"], range_type: "AoE Trung", combo_tag: "Creation_Destruction_Field" },
        { name: "Khái Niệm Thời Không Chiến", desc: "[Diệu Giai] [Cơ chế] Áp đặt quy luật 'Sự vĩnh hằng' vào một khoảnh khắc. [Hiệu ứng] Ngưng đọng thời gian hoàn toàn trong bán kính 1km trong vòng 30 giây thực tế. Chỉ người dùng và đồng đội được đánh dấu mới có thể hành động.", rank: "Diệu Giai", cost: { type: "Soul_Force", value: 30 }, cooldown: { value: 12, unit: "Giờ", display_text: "12 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Hệ Thời Không"], range_type: "AoE Cực Rộng", combo_tag: "Eternal_Moment" },
        { name: "Lôi Độc Ma Châm", desc: "[Cơ chế] Kim kim loại tích điện mang theo chất độc thần kinh. [Hiệu ứng] Phóng ra hàng ngàn cây kim nhỏ. Gây sát thương Lôi diện rộng và làm mục tiêu bị [Liệt Hệ Thần Kinh] khiến chúng không thể sử dụng kỹ năng trong 15 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Hệ Độc Dược"], range_type: "Hình Nón (Tầm Xa)", combo_tag: "Thunder_Toxin_Needles" },
        { name: "Mộc Kim Thiết Giáp", desc: "[Bị động] [Cơ chế] Thân cây bọc lớp vỏ hợp kim tự nhiên. [Hiệu ứng] Tăng 100% DEF vật lý. Khi bị tấn công bởi kỹ năng hệ Hỏa, giáp không cháy mà chỉ nóng lên, gây lại sát thương Hỏa cho kẻ địch đứng gần.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Mộc", "Hệ Kim Loại"], range_type: "Bản thân (Bị động)", combo_tag: "Nature_Steel_Bark" },
        { name: "Hỏa Khái Niệm Thiêu", desc: "[Cơ chế] Ghi đè khái niệm 'Nhiệt lượng cực đại' lên ngọn lửa thông thường. [Hiệu ứng] Ngọn lửa có thể thiêu cháy cả những thứ không thể cháy như Nước, Đá và thậm chí là Ma Lực. Mỗi giây đốt cháy 2% MP tối đa của đối thủ.", rank: "Kim Giai", cost: { type: "MP", value: 90000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Hệ Khái Niệm"], range_type: "AoE Nhỏ", combo_tag: "Conceptual_Flame" },
        { name: "Thủy Băng Tế Bào", desc: "[Bị động] [Cơ chế] Chất lỏng trong cơ thể luôn ở trạng thái cận đông. [Hiệu ứng] Tăng 50% kháng mọi hiệu ứng bất lợi. Khi nhận sát thương vật lý, cơ thể tự đông cứng tại điểm chạm để giảm 40% sát thương.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Nước", "Hệ Băng"], range_type: "Bản thân (Bị động)", combo_tag: "Cryo_Liquid_Cell" },
        { name: "Phong Cường Hóa Bộ", desc: "[Cơ chế] Nén gió dưới lòng bàn chân để gia tốc di chuyển. [Hiệu ứng] Tăng 300% tốc độ di chuyển trong 30 giây. Tạo ra các dư ảnh ảo khiến kẻ thù khó lòng ngắm trúng đòn tầm xa.", rank: "Thiết Giai", cost: { type: "Stamina", value: 150 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Hệ Cường Hóa"], range_type: "Bản thân (Buff)", combo_tag: "Wind_Sprint" },
        { name: "Thổ Bóng Tối Pháo", desc: "[Cơ chế] Bắn ra các khối đá chứa năng lượng bóng tối nén. [Hiệu ứng] Quả cầu đá nổ tung tạo ra vùng tối không gian. Kẻ địch bên trong bị [Trọng Lực Đen] đè nặng, giảm 80% AGI và nhận sát thương bóng tối liên tục.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Hệ Bóng Tối"], range_type: "Tầm Xa (Đạn pháo)", combo_tag: "Dark_Stone_Blast" },
        { name: "Quang Minh Hủy Diệt Tia", desc: "[Cơ chế] Ánh sáng mang tần số rung động phân rã. [Hiệu ứng] Bắn ra chùm sáng trắng xuyên thấu mọi vật chất. Phá hủy 20% DEF vật lý và 20% DEF ma pháp của mục tiêu vĩnh viễn trong trận đấu.", rank: "Ngân Giai", cost: { type: "MP", value: 7000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hệ Hủy Diệt"], range_type: "Đường thẳng (Beam)", combo_tag: "White_Disintegration" },
        { name: "Tâm Linh Sáng Tạo Cảnh", desc: "[Cơ chế] Biến suy nghĩ thành hiện thực khách quan. [Hiệu ứng] Tạo ra một vùng ảo ảnh có thật trong 300 giây. Người dùng có thể sáng tạo ra địa hình, bẫy hoặc quân đội ảo nhưng có khả năng gây sát thương thật.", rank: "Kim Giai", cost: { type: "Sanity", value: 20 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Hệ Sáng Tạo"], range_type: "AoE Trung", combo_tag: "Thought_Manifest" },
        { name: "Độc Dược Thời Không", desc: "[Cơ chế] Chất độc tồn tại vĩnh cửu trong dòng thời gian của nạn nhân. [Hiệu ứng] Gây sát thương độc 1% HP mỗi giây. Hiệu ứng độc này không thể bị xóa bỏ bởi bất kỳ kỹ năng nào ngoại trừ việc quay ngược thời gian.", rank: "Kim Giai", cost: { type: "MP", value: 110000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Độc Dược", "Hệ Thời Không"], range_type: "Cận chiến (Gài độc)", combo_tag: "Eternal_Venom" },
        { name: "Hủy Diệt Khái Niệm Quyền", desc: "[Diệu Giai] [Cơ chế] Cú đấm mang theo khái niệm 'Sự tan biến'. [Hiệu ứng] Đòn đánh cận chiến tiêu diệt ngay lập tức bất kỳ vật thể hoặc sủng thú nào dưới cấp Ngân Giai. Với mục tiêu mạnh hơn, gây sát thương bằng 50% HP hiện tại.", rank: "Diệu Giai", cost: { type: "Stamina", value: 5000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Hệ Khái Niệm"], range_type: "Cận chiến", combo_tag: "God_Slaying_Fist" },
        { name: "Sáng Tạo Thời Không Kén", desc: "[Cơ chế] Kiến tạo một vùng không gian độc lập nơi thời gian trôi chậm hơn. [Hiệu ứng] Tạo kén bảo vệ cho đồng đội. Bên trong kén 1 giây bằng 10 giây bên ngoài, giúp đồng đội hồi phục và chuẩn bị kỹ năng nhanh gấp 10 lần.", rank: "Kim Giai", cost: { type: "MP", value: 200000 }, cooldown: { value: 4, unit: "Giờ", display_text: "4 Giờ" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Hệ Thời Không"], range_type: "AoE Nhỏ", combo_tag: "Time_Cocoon" },
        { name: "Lôi Hỏa Cường Hóa Trảo", desc: "[Cơ chế] Bọc móng vuốt bằng plasma và điện tích. [Hiệu ứng] Đòn cào xé mục tiêu gây nổ plasma. Trừ 10% DEF và gây trạng thái [Tê Liệt] trong 1 giây. Mỗi đòn đánh tích lũy một tầng [Quá Tải Nhiệt].", rank: "Ngân Giai", cost: { type: "MP", value: 1500 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Lôi", "Hệ Hỏa", "Hệ Cường Hóa"], range_type: "Cận chiến", combo_tag: "Plasma_Claw" },
        { name: "Thủy Mộc Bóng Tối Trói", desc: "[Cơ chế] Dây leo bằng nước đen mọc ra từ bóng của mục tiêu. [Hiệu ứng] Trói chặt mục tiêu trong 15 giây. Dây leo liên tục hút MP của mục tiêu (50 MP/giây) và truyền về cho người dùng.", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Nước", "Hệ Mộc", "Hệ Bóng Tối"], range_type: "Tầm Xa (Khống chế)", combo_tag: "Shadow_Vine_Siphon" },
        { name: "Phong Băng Kim Loại Tiễn", desc: "[Cơ chế] Mũi tên kim loại được bọc băng và bắn đi bởi cuồng phong. [Hiệu ứng] Tốc độ bay cực nhanh, sát thương xuyên thấu cao. Khi găm vào mục tiêu sẽ đóng băng khu vực vết thương, ngăn chặn việc di chuyển chi bị trúng.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 15, unit: "Giây", display_text: "15 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Phong", "Hệ Băng", "Hệ Kim Loại"], range_type: "Tầm Xa (Xuyên thấu)", combo_tag: "Triple_Element_Arrow" },
        { name: "Thổ Quang Cường Hóa Khiên", desc: "[Cơ chế] Khiên đất đá được gia cố bởi năng lượng ánh sáng nén. [Hiệu ứng] Tạo lá chắn cực dày. Khi bị tấn công, lá chắn phát ra ánh sáng chói mắt làm giảm 50% chính xác của kẻ địch trong 5 giây.", rank: "Thiết Giai", cost: { type: "MP", value: 1500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Hệ Ánh Sáng", "Hệ Cường Hóa"], range_type: "Bản thân (Phòng thủ)", combo_tag: "Luminous_Bulwark" },
        { name: "Tâm Linh Độc Dược Sát", desc: "[Cơ chế] Chất độc tinh thần được truyền qua sóng não. [Hiệu ứng] Làm mục tiêu cảm thấy cơ thể đang thối rữa (dù thực tế không có). Gây sát thương Sanity 2% mỗi giây và khiến chúng tự tấn công bản thân.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Hệ Độc Dược"], range_type: "Tầm Xa (Nguyền rủa)", combo_tag: "Mental_Toxic_Decay" },
        { name: "Thời Không Sáng Tạo Hồi", desc: "[Cơ chế] Kiến tạo lại cấu trúc sinh học dựa trên bản thiết kế quá khứ. [Hiệu ứng] Hồi phục ngay lập tức một bộ phận cơ thể bị mất cho đồng đội (tay, chân, nội tạng). Không để lại sẹo và tăng 10% CON vĩnh viễn.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Hệ Sáng Tạo"], range_type: "Cận chiến (Hồi phục)", combo_tag: "Anatomical_Restoration" },
        { name: "Khái Niệm Hủy Diệt Giới", desc: "[Diệu Giai] [Cơ chế] Áp đặt khái niệm 'Sự mục nát' lên toàn bộ lãnh địa. [Hiệu ứng] Trong bán kính 500m, mọi công trình, vũ khí và sinh vật bắt đầu phân rã. Giảm 80% DEF vật lý và 80% độ bền trang bị của toàn bộ kẻ địch.", rank: "Diệu Giai", cost: { type: "MP", value: 4800000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Hệ Hủy Diệt"], range_type: "AoE Rộng (Lãnh địa)", combo_tag: "Conceptual_Decay_Zone" },
        { name: "Hỏa Lôi Phong Bạo", desc: "[Cơ chế] Kết hợp lốc xoáy, lửa và sét thành thảm họa tự nhiên. [Hiệu ứng] Tạo ra cơn bão lửa điện rộng 100m. Gây sát thương hỗn hợp liên tục. Mọi kẻ địch bên trong bị [Quá Tải] và [Thiêu Đốt] chồng chất.", rank: "Kim Giai", cost: { type: "MP", value: 180000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Hệ Lôi", "Hệ Phong"], range_type: "AoE Rộng", combo_tag: "Elemental_Apocalypse" },
        { name: "Thủy Băng Ánh Sáng Kết", desc: "[Bị động] [Cơ chế] Cơ thể phản chiếu ánh sáng qua lớp băng tuyết. [Hiệu ứng] Tăng 30% kháng ma pháp. Khi bị tấn công bởi kỹ năng hệ Bóng Tối, tự động phát ra xung quang năng gây sát thương và đẩy lùi đối thủ.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Nước", "Hệ Băng", "Hệ Ánh Sáng"], range_type: "Bản thân (Bị động)", combo_tag: "Prismatic_Refraction" },
        { name: "Thổ Kim Loại Cường Hóa Thể", desc: "[Bị động] [Cơ chế] Cấu trúc xương và da được bọc bởi hợp kim đá ma thuật. [Hiệu ứng] Tăng vĩnh viễn 1000 HP và 200 DEF. Giảm 20% sát thương nhận vào từ các đòn đánh vật lý xuyên thấu.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Hệ Kim Loại", "Hệ Cường Hóa"], range_type: "Bản thân (Bị động)", combo_tag: "Titanium_Skin" },
        { name: "Mộc Độc Bóng Tối Chưởng", desc: "[Cơ chế] Đòn đánh lòng bàn tay mang theo mầm bệnh bóng tối. [Hiệu ứng] Đánh trúng địch sẽ gieo rắc hạt giống [Hắc Mộc]. Hạt giống hút 1% HP mỗi giây và chuyển hóa thành năng lượng che khuất tầm nhìn của địch trong 30 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 3200 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Hệ Độc Dược", "Hệ Bóng Tối"], range_type: "Cận chiến", combo_tag: "Dark_Nature_Parasite" },
        { name: "Tâm Linh Thời Không Phá", desc: "[Cơ chế] Bẻ gãy cấu trúc không gian bằng sức mạnh ý chí thuần túy. [Hiệu ứng] Tạo ra một vết nứt không gian tại vị trí mục tiêu. Mục tiêu bị hút vào hư không và nhận sát thương tinh thần cực lớn trước khi bị đẩy trở lại sau 5 giây.", rank: "Kim Giai", cost: { type: "Sanity", value: 30 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Hệ Thời Không"], range_type: "Tầm Xa (Vết nứt)", combo_tag: "Mind_Void_Fracture" },
        { name: "Khái Niệm Sáng Tạo Giới", desc: "[Diệu Giai] [Cơ chế] Định nghĩa một quy luật vật lý mới cho vùng không gian. [Hiệu ứng] Trong 600 giây, người dùng có thể thay đổi một quy luật (VD: lửa không nóng, đá bay lơ lửng, độc hồi máu). Chỉ có tác dụng trong bán kính 100m.", rank: "Diệu Giai", cost: { type: "Soul_Force", value: 25 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Hệ Sáng Tạo"], range_type: "AoE Trung (Luật lệ)", combo_tag: "Reality_Rewrite" },
        { name: "Hủy Diệt Cường Hóa Kích", desc: "[Cơ chế] Tập trung năng lượng hủy diệt vào một đòn đánh vật lý cực đoan. [Hiệu ứng] Đòn đánh đơn mục tiêu gây sát thương chuẩn và có 100% tỉ lệ phá hủy hoàn toàn một món trang bị ngẫu nhiên trên người mục tiêu.", rank: "Kim Giai", cost: { type: "Stamina", value: 3000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Hệ Cường Hóa"], range_type: "Cận chiến", combo_tag: "Item_Breaker" },
        { name: "Hỏa Băng Khái Niệm Chưởng", desc: "[Cơ chế] Đòn đánh mang theo khái niệm 'Sự đối lập'. [Hiệu ứng] Khi chạm vào mục tiêu, gây ra sự giãn nở và co lại đột ngột của vật chất. Làm mục tiêu bị [Vỡ Vụn Thể Xác], nhận sát thương bằng 30% HP hiện tại.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hỏa", "Hệ Băng", "Hệ Khái Niệm"], range_type: "Cận chiến", combo_tag: "Molecular_Rupture" },
        { name: "Thanh Lam Thủy Lôi Phong", desc: "[Cơ chế] Kết hợp nước, gió và sét thành dòng chảy cao thế. [Hiệu ứng] Phun ra một vòi rồng nước tích điện. Sát thương lan tỏa cực nhanh qua các mục tiêu đứng gần nhau, gây choáng diện rộng trong 3 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Nước", "Hệ Lôi", "Hệ Phong"], range_type: "Đường thẳng (Vòi rồng)", combo_tag: "Triple_Storm_Blast" },
        { name: "Thổ Mộc Kim Loại Hợp", desc: "[Bị động] [Cơ chế] Cơ thể là một hệ sinh thái quặng sắt và rừng rậm. [Hiệu ứng] Tăng 40% DEF và 40% kháng các hiệu ứng khống chế. Khi bị tấn công, có 20% tỉ lệ mọc ra gai sắt gỗ phản lại 30% sát thương vật lý.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Hệ Mộc", "Hệ Kim Loại"], range_type: "Bản thân (Bị động)", combo_tag: "Living_Fortress" },
        { name: "Quang Bóng Tối Tinh Thần Xung", desc: "[Cơ chế] Phóng ra luồng sóng não mang lưỡng tính sáng tối. [Hiệu ứng] Làm mục tiêu bị [Mâu Thuẫn Ý Thức], khiến chúng rơi vào trạng thái ngủ say nhưng liên tục nhận sát thương tinh thần cực lớn trong 10 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 6500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hệ Bóng Tối", "Hệ Tinh Thần"], range_type: "Tầm Xa (Ngắt quãng)", combo_tag: "Consciousness_Conflict" },
        { name: "Độc Dược Cường Hóa Hủy Diệt", desc: "[Cơ chế] Cường hóa chất độc bằng năng lượng hủy diệt cấp độ phân tử. [Hiệu ứng] Vũ khí được tẩm loại độc này sẽ gây sát thương chuẩn. Mục tiêu bị nhiễm độc sẽ bị giảm 10% toàn bộ chỉ số stats vĩnh viễn trong trận đấu.", rank: "Kim Giai", cost: { type: "MP", value: 80000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Độc Dược", "Hệ Cường Hóa", "Hệ Hủy Diệt"], range_type: "Cận chiến (Buff vũ khí)", combo_tag: "Death_Enchant" },
        { name: "Thời Không Sáng Tạo Khái Niệm", desc: "[Diệu Giai] [Cơ chế] Kiến tạo một thế giới nhỏ trong khe hở thời gian. [Hiệu ứng] Đưa toàn bộ đội hình vào một vùng không gian an toàn tuyệt đối trong 60 giây. Bên trong, mọi người được hồi phục 100% HP/MP/Sanity và Stamina.", rank: "Diệu Giai", cost: { type: "Soul_Force", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Hệ Sáng Tạo", "Hệ Khái Niệm"], range_type: "Bản thân (Cứu trợ tối cao)", combo_tag: "Sanctuary_Creation" },
        { name: "Vạn Kiếp Lôi Hỏa", desc: "[Cơ chế] Triệu hồi lôi hỏa từ chín tầng trời. [Hiệu ứng] Trong 60 giây, liên tục giáng xuống các cột sét lửa bán kính 200m. Mỗi cột sét gây sát thương khổng lồ và thiêu cháy mana của địch thủ.", rank: "Kim Giai", cost: { type: "MP", value: 500000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Lôi", "Hệ Hỏa"], range_type: "AoE Rộng (Mưa thiên tai)", combo_tag: "Heavenly_Fire_Thunder" },
        { name: "Thủy Băng Linh Hồn", desc: "[Bị động] [Cơ chế] Linh hồn được bảo quản trong băng vĩnh cửu. [Hiệu ứng] Miễn nhiễm hoàn toàn với các kỹ năng hút linh hồn hoặc thao túng linh hồn dưới cấp Diệu Giai. Tăng 30% SPI.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Nước", "Hệ Băng", "Hệ Tinh Thần"], range_type: "Bản thân (Bị động)", combo_tag: "Soul_Freeze_Immunity" },
        { name: "Thổ Mộc Cường Hóa Thể", desc: "[Bị động] [Cơ chế] Cơ thể tích hợp tinh hoa địa mạch và sinh mệnh mộc. [Hiệu ứng] Mỗi 30 giây đứng im trên mặt đất, nhận thêm 1% Max HP vĩnh viễn (tối đa cộng thêm 2000 HP). Tăng 50% khả năng kháng độc.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thổ", "Hệ Mộc", "Hệ Cường Hóa"], range_type: "Bản thân (Bị động)", combo_tag: "Earth_Life_Armor" },
        { name: "Phong Ảnh Bóng Tối Bộ", desc: "[Cơ chế] Di chuyển bằng cách lướt giữa các bóng của cơn gió. [Hiệu ứng] Tốc độ di chuyển tăng 500% trong 10 giây. Trong thời gian này, nhân vật có thể đi xuyên qua vật chất rắn và miễn nhiễm sát thương vật lý.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Hệ Bóng Tối"], range_type: "Bản thân (Di chuyển tối thượng)", combo_tag: "Void_Dash" },
        { name: "Quang Minh Khái Niệm Phạt", desc: "[Diệu Giai] [Cơ chế] Áp đặt quy luật 'Sự phán xét' bằng ánh sáng thánh khiết. [Hiệu ứng] Kẻ địch có chỉ số Karma thấp (giết nhiều NPC/Player) sẽ nhận sát thương gấp 10 lần. Kẻ địch có Wanted Status sẽ bị giam giữ vĩnh viễn trong lồng ánh sáng.", rank: "Diệu Giai", cost: { type: "MP", value: 5500000 }, cooldown: { value: 48, unit: "Giờ", display_text: "48 Giờ" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hệ Khái Niệm"], range_type: "AoE Trung (Trừng phạt)", combo_tag: "Holy_Judgment" },
        { name: "Độc Dược Hủy Diệt Xung", desc: "[Cơ chế] Giải phóng sóng chấn động mang theo chất phân rã sinh học. [Hiệu ứng] Bán kính 30m. Mọi sinh vật nhận sát thương chuẩn và bị nhiễm [Dịch Bệnh Diệt Vong] lây lan sang các đồng minh khác của chúng khi tiếp xúc.", rank: "Kim Giai", cost: { type: "MP", value: 95000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Độc Dược", "Hệ Hủy Diệt"], range_type: "AoE Trung", combo_tag: "Plague_Burst" },
        { name: "Hủy Diệt Sáng Tạo Quyền", desc: "[Cơ chế] Một tay mang năng lượng hủy diệt, một tay mang năng lượng sáng tạo. [Hiệu ứng] Đòn đánh trái phá hủy giáp, đòn đánh phải tái tạo sát thương thành vụ nổ nội tại. Gây 500,000 sát thương hỗn hợp đơn mục tiêu.", rank: "Kim Giai", cost: { type: "Stamina", value: 5000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Hệ Sáng Tạo"], range_type: "Cận chiến", combo_tag: "Binary_Fist" },
        { name: "Kim Loại Thời Không Thân", desc: "[Bị động] [Cơ chế] Nguyên tử kim loại trong cơ thể dao động ở tần số thời gian khác. [Hiệu ứng] Tăng 40% DEF. Khi bị tấn công, có 25% tỉ lệ vật thể tấn công bị [Làm Chậm Thời Gian] khiến sát thương nhận vào giảm 90%.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Kim Loại", "Hệ Thời Không"], range_type: "Bản thân (Bị động)", combo_tag: "Temporal_Metal_Body" },
        { name: "Tâm Linh Khái Niệm Hợp", desc: "[Cơ chế] Đồng nhất ý chí với một khái niệm trừu tượng. [Hiệu ứng] Chọn một khái niệm (VD: 'Sức mạnh', 'Né tránh', 'Bất tử'). Trong 30 giây, nhân vật đạt được trạng thái tối thượng của khái niệm đó (VD: Né tránh 100%).", rank: "Kim Giai", cost: { type: "Sanity", value: 40 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Tinh Thần", "Hệ Khái Niệm"], range_type: "Bản thân", combo_tag: "Conceptual_Ascension" },
        { name: "Mộc Linh Thời Không Phục", desc: "[Cơ chế] Dùng năng lượng mộc để tái sinh và thời không để tua ngược vết thương. [Hiệu ứng] Hồi phục toàn bộ HP cho bản thân và xóa bỏ mọi hiệu ứng bất lợi tích lũy trong 1 giờ qua. Tăng vĩnh viễn 5% CON.", rank: "Kim Giai", cost: { type: "MP", value: 250000 }, cooldown: { value: 12, unit: "Giờ", display_text: "12 Giờ" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Hệ Thời Không"], range_type: "Bản thân (Tái tạo tối cao)", combo_tag: "Nature_Time_Restoration" },
        { name: "Thổ Hủy Diệt Địa Chấn", desc: "[Cơ chế] Sóng chấn động mang năng lượng phân rã địa mạch. [Hiệu ứng] Biến mặt đất thành vùng hố đen nuốt chửng mọi vật chất. Kẻ địch rơi xuống hố sẽ bị xóa sổ khỏi trận chiến vĩnh viễn.", rank: "Kim Giai", cost: { type: "MP", value: 400000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Thổ", "Hệ Hủy Diệt"], range_type: "AoE Trung", combo_tag: "Abyssal_Quake" },
        { name: "Ánh Sáng Sáng Tạo Cung", desc: "[Cơ chế] Tạo ra một cây cung từ ánh sáng đặc bắn ra các mũi tên kiến tạo. [Hiệu ứng] Mũi tên trúng đồng đội sẽ tạo lớp giáp hồi phục, trúng kẻ địch sẽ tạo ra các xiềng xích ánh sáng trói buộc chúng trong 20 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hệ Sáng Tạo"], range_type: "Tầm Xa (Đa năng)", combo_tag: "Holy_Archery" },
        { name: "Bóng Tối Độc Dược Phủ", desc: "[Cơ chế] Bao phủ một vùng không gian bằng bóng tối nhiễm độc kịch độc. [Hiệu ứng] Tầm nhìn giảm về 0. Mỗi giây kẻ địch bên trong nhận 4% sát thương độc và bị giảm 20% SPI mỗi 10 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 7500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Bóng Tối", "Hệ Độc Dược"], range_type: "AoE Rộng (Môi trường)", combo_tag: "Shadow_Toxic_Mist" },
        { name: "Cường Hóa Khái Niệm Thân", desc: "[Bị động] [Cơ chế] Khái niệm'Vững chãi' được ghi sâu vào cơ bắp. [Hiệu ứng] Không thể bị hất tung, đẩy lùi hoặc thay đổi vị trí cưỡng bức bởi các kỹ năng dưới cấp Diệu Giai. Tăng 40% DEF vật lý.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Cường Hóa", "Hệ Khái Niệm"], range_type: "Bản thân (Bị động)", combo_tag: "Immovable_Concept" },
        { name: "Hủy Diệt Thời Không Kiếm", desc: "[Cơ chế] Lưỡi kiếm tồn tại ở mọi thời điểm của mục tiêu. [Hiệu ứng] Một nhát chém gây sát thương lên mục tiêu ở cả Quá khứ, Hiện tại và Tương lai. Sát thương nhân 3 và không thể né tránh.", rank: "Kim Giai", cost: { type: "MP", value: 180000 }, cooldown: { value: 3, unit: "Giờ", display_text: "3 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Hệ Thời Không"], range_type: "Cận chiến (Tối thượng)", combo_tag: "Tridimension_Slash" },
        { name: "Sáng Tạo Tinh Thần Giới", desc: "[Cơ chế] Kiến tạo một cõi mộng tinh thần hoàn hảo. [Hiệu ứng] Giam cầm ý thức kẻ địch trong một thế giới tươi đẹp, khiến chúng không còn muốn chiến đấu. Hiệu ứng kéo dài cho đến khi mục tiêu nhận sát thương từ bên ngoài.", rank: "Ngân Giai", cost: { type: "MP", value: 12000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Hệ Tinh Thần"], range_type: "AoE Trung", combo_tag: "Peaceful_Dream" },
        { name: "Khái Niệm Hỏa Thần Thể", desc: "[Bị động] [Cơ chế] Trở thành hiện thân của khái niệm 'Lửa'. [Hiệu ứng] Miễn nhiễm 100% sát thương hệ Hỏa. Mọi đòn đánh cận chiến tự động kèm sát thương thiêu đốt 5% HP mục tiêu mỗi giây.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hỏa", "Hệ Khái Niệm"], range_type: "Bản thân (Bị động)", combo_tag: "Fire_God_Concept" },
        { name: "Thời Không Thủy Lưu", desc: "[Cơ chế] Dòng nước chảy ngược dòng thời gian. [Hiệu ứng] Phun nước vào mục tiêu, khiến các vết thương của chúng bị tua ngược về trạng thái tệ nhất trong 24 giờ qua. Gây sát thương tích lũy khổng lồ.", rank: "Ngân Giai", cost: { type: "MP", value: 8500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Nước", "Hệ Thời Không"], range_type: "Tầm Xa", combo_tag: "Reverse_Injury" },
        { name: "Băng Lôi Cường Hóa Kích", desc: "[Cơ chế] Cú đấm mang theo hàn khí tuyệt đối và lôi điện cao thế. [Hiệu ứng] Đóng băng và tê liệt mục tiêu ngay lập tức trong 5 giây. Phá hủy hoàn toàn lớp giáp ma pháp bảo vệ của đối phương.", rank: "Thiết Giai", cost: { type: "Stamina", value: 500 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Băng", "Hệ Lôi", "Hệ Cường Hóa"], range_type: "Cận chiến", combo_tag: "Cryo_Electric_Punch" },
        { name: "Phong Thổ Bóng Tối Bộ", desc: "[Bị động] [Cơ chế] Bước chân tan biến vào cát bụi và gió đêm. [Hiệu ứng] Tăng 100% tốc độ di chuyển khi không ở trong vùng an toàn. Tuyệt đối không để lại dấu chân, mùi hương hay vết tích ma lực khi di chuyển.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Thường trực", display_text: "Thường trực" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Phong", "Hệ Thổ", "Hệ Bóng Tối"], range_type: "Bản thân (Bị động)", combo_tag: "Ghost_Walk" },
        { name: "Quang Minh Độc Dược Tẩy", desc: "[Cơ chế] Ánh sáng phản phản ứng với độc tố tạo thành thuốc hồi phục. [Hiệu ứng] Khi mục tiêu đang bị trúng độc, sử dụng kỹ năng này sẽ biến toàn bộ sát thương độc thành hiệu ứng hồi phục HP gấp 2 lần giá trị gốc.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Ánh Sáng", "Hệ Độc Dược"], range_type: "Tầm Xa (Thanh tẩy đặc biệt)", combo_tag: "Toxic_Light_Reverse" },
        { name: "Mộc Kim Loại Sáng Tạo", desc: "[Cơ chế] Tạo ra các thực thể sinh-cơ học (Cyborg) từ gỗ và sắt. [Hiệu ứng] Triệu hồi 3 thủ vệ cơ khí tồn tại trong 1 giờ. Các thủ vệ có khả năng tự sửa chữa và phản lại sát thương hệ Lôi.", rank: "Kim Giai", cost: { type: "MP", value: 55000 }, cooldown: { value: 4, unit: "Giờ", display_text: "4 Giờ" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Mộc", "Hệ Kim Loại", "Hệ Sáng Tạo"], range_type: "Triệu hồi", combo_tag: "Bio_Mech_Summon" },
        { name: "Hủy Diệt Tinh Thần Ba", desc: "[Cơ chế] Phát ra sóng não mang tần số hủy diệt các nơ-ron thần kinh. [Hiệu ứng] Tấn công AoE diện rộng. Mỗi giây trừ 5 Sanity của toàn bộ kẻ địch trong tầm ảnh hưởng. Nếu Sanity về 0, mục tiêu chết ngay lập tức.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Hệ Tinh Thần"], range_type: "AoE Trung", combo_tag: "Neural_Annihilation" },
        { name: "Khái Niệm Sáng Tạo Vũ Khí", desc: "[Cơ chế] Gán khái niệm 'Chí mạng' vào vật thể được kiến tạo. [Hiệu ứng] Tạo ra một thanh kiếm ánh sáng cho đồng đội. Mọi đòn đánh từ thanh kiếm này chắc chắn gây chí mạng (x3 sát thương) trong 120 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 15000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Hệ Sáng Tạo"], range_type: "Cận chiến (Buff vũ khí)", combo_tag: "Sure_Crit_Weapon" },
        { name: "Thời Không Hủy Diệt Nhãn", desc: "[Diệu Giai] [Cơ chế] Nhìn thấu điểm chết của mục tiêu trong tương lai và xóa bỏ nó ngay bây giờ. [Hiệu ứng] Tấn công đơn mục tiêu. Sát thương bằng 99% HP hiện tại của mục tiêu. Không thể né tránh, không thể phòng ngự. [Tác dụng phụ] Người dùng bị mù trong 24 giờ.", rank: "Diệu Giai", cost: { type: "Sanity", value: 60 }, cooldown: { value: 48, unit: "Giờ", display_text: "48 Giờ" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Hệ Hủy Diệt"], range_type: "Tầm Xa (Nhãn thuật)", combo_tag: "Death_Vision_Strike" }
    ],
    "Rare": [
        { name: "Hóa Hình - Sinh Chủ", desc: "[Cơ Chế Sinh Học] Cơ thể cấu thành từ 100% Tế bào gốc vạn năng (Stem Cells). Liên tục phân chia, không bao giờ lão hóa. [Cấu Tạo] Nội tạng tươi trẻ, tủy xương sản sinh máu truyền được cho mọi loài. [Hình Thái] Trẻ mãi không già, hào quang sự sống. [Hiệu ứng] Tự tái tạo chi đứt, máu và nước mắt là thần dược (hồi máu cực khủng). [Tác dụng phụ] Không có khả năng chiến đấu vật lý, máu thịt trở thành 'Đường Tăng' thu hút sự thèm khát của mọi Dị Thú cấp cao muốn ăn thịt.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Sinh Mệnh"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Creator" },
        { name: "Phấn Hoa Hồi Sinh", desc: "[Cơ chế] Tế bào gốc kết hợp hạt mana dạng bụi siêu mịn. [Hiệu ứng] Thổi phấn hoa vàng lấp lánh vào vết thương. Lập tức cầm máu, nối liền gân cốt và khép miệng các vết thương chí mạng (như rách bụng, lòi ruột). Hồi phục 50% Max HP ngay lập tức.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Trị Liệu"], range_type: "Cận Chiến (Cấp cứu)", combo_tag: "Pollen_Heal" },
        { name: "Kết Nối Sinh Mệnh", desc: "[Cơ chế] Dệt dây thừng ma thuật vô hình liên kết các trái tim đồng đội. [Hiệu ứng] Chia đều mọi sát thương nhận vào cho cả tổ đội (tối đa 5 người). Nếu Tanker bị trúng đòn 10.000 damage, nó sẽ chia đều mỗi người chịu 2.000 damage. Chống bị sốc chết cực hiệu quả.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo"], range_type: "AoE Đồng minh (Buff phòng thủ)", combo_tag: "Life_Link" },
        { name: "Tái Sinh (Resurrection)", desc: "[Cơ chế] Cưỡng ép linh hồn quay lại thể xác và khởi động lại tim bằng xung điện sinh mệnh. [Hiệu ứng] Hồi sinh 1 đồng đội vừa tử vong trong vòng 5 phút (Chưa phân hủy). Sống lại với 30% HP và MP. [Nhược điểm] Người dùng bị Rút cạn 80% Thể lực và MP, thở dốc không ra hơi.", rank: "Kim Giai", cost: { type: "HP", value: 50000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Sinh Mệnh"], range_type: "Cận Chiến (Hồi Sinh)", combo_tag: "True_Resurrect" },
        { name: "Triệu Hồi Lính Cây", desc: "[Cơ chế] Thổi linh hồn nhân tạo vào hạt giống khổng lồ. [Hiệu ứng] Ném hạt giống xuống đất, mọc lên 3 Vệ sĩ Treent cao 3m. Treent có HP cực trâu, biết đấm vật lý và Taunt (Khiêu khích) địch đánh nó. Tồn tại 15 phút bảo vệ Ký chủ.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Triệu Hồi"], range_type: "Tầm Trung (Gọi đệ)", combo_tag: "Summon_Treant" },
        { name: "Vùng Bất Tử", desc: "[Cơ chế] Cắm cọc tạo Lĩnh Vực cấm tử vong của Thần Sinh Mệnh. [Hiệu ứng] Tạo vòng sáng 10x10m trong 15 giây. Bất kỳ ai (Kể cả ĐỊCH hay TA) đứng trong vòng này, thanh HP tuyệt đối không thể rớt xuống dưới 1 điểm. Nơi diễn ra những cuộc khô máu tàn bạo nhất.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Lĩnh Vực"], range_type: "AoE Trung (Bất tử cục bộ)", combo_tag: "Immortal_Zone" },
        { name: "Tạo Vũ Khí Thảo Mộc", desc: "[Cơ chế] Kích thích sừng hóa thực vật đạt độ cứng của thép. [Hiệu ứng] Mọc ra từ tay các loại khiên gai, gươm lá, hoặc cung gỗ Thiết Sam. Trang bị ngay lập tức cho đồng đội tay không. Sát thương tương đương vũ khí Bạch Ngân.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Mộc"], range_type: "Cận Chiến (Hỗ trợ Vũ khí)", combo_tag: "Plant_Weapons" },
        { name: "Giải Trừ Nguyền Rủa", desc: "[Cơ chế] Rửa trôi sự vặn vẹo cấu trúc vật chất bằng máu tinh khiết. [Hiệu ứng] Xóa bỏ vĩnh viễn mọi bùa chú Hắc Ám, phong ấn skill, hoặc các hiệu ứng debuff vĩnh viễn từ Boss. Khôi phục trạng thái hoàn hảo cho 1 mục tiêu.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Trị Liệu"], range_type: "Tầm Xa (Hỗ trợ)", combo_tag: "Curse_Breaker" },
        { name: "Hồi Thể Lực (Stamina)", desc: "[Cơ chế] Bơm Glucose ma thuật thẳng vào cơ bắp. [Hiệu ứng] Tỏa làn khói xanh lá. Lập tức hồi đầy 100% Thanh Thể Lực (Stamina) cho toàn đội. Giúp đội hình chạy bộ xuyên rừng không biết mệt hoặc tiếp tục vung kiếm sau nhiều giờ chiến đấu.", rank: "Thiết Giai", cost: { type: "MP", value: 500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo"], range_type: "AoE Rộng (Buff Hồi sức)", combo_tag: "Stamina_Surge" },
        { name: "Lá Chắn Máu", desc: "[Cơ chế] Rút máu bản thân, cô đặc thành tường rào huyết ngọc. [Hiệu ứng] Hy sinh 20% HP của người dùng để tạo ra một Lớp Khiên cực dày (HP Khiên = 300% lượng máu đã hiến tế) bọc lên người đồng đội, che chở họ khỏi cái chết.", rank: "Ngân Giai", cost: { type: "HP", value: 2000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Sinh Mệnh"], range_type: "Tầm Xa (Buff Phòng thủ)", combo_tag: "Blood_Shield" },
        { name: "Sáng Thế Kỷ (Khởi Nguyên Vạn Vật)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Trở thành Đấng Sáng Tạo, bẻ cong Định luật bảo toàn Khối lượng. [Hiệu ứng] Hồi sinh toàn bộ 1 Lục địa hoặc 1 Thành phố đã bị hủy diệt (Kể cả người chết, nhà cửa đổ nát, hệ sinh thái) trở về trạng thái hoàn hảo trước thảm họa. Phép thuật Thần Thánh vĩ đại nhất. [Tác dụng phụ cực lớn] Rút cạn toàn bộ Sinh mệnh, Linh hồn và Ký ức của người dùng. Tan biến vĩnh viễn khỏi dòng thời gian (Chết thực, không ai còn nhớ đến sự tồn tại của nhân vật). Chấp nhận Xóa Save để tạo kỳ tích.", rank: "Thánh Giai", cost: { type: "HP", value: 9999999 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 300, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Sinh Mệnh", "Thời Gian"], range_type: "Cấp Thế Giới (Tái tạo thực tại)", combo_tag: "Holy_Genesis_Sacrifice" },
        { name: "Tinh Linh Dẫn Đường", desc: "[Cơ chế] Nặn ra một tinh linh ánh sáng có tri giác nhỏ bé. [Hiệu ứng] Tạo đốm sáng (Wisp) bay lơ lửng. Nó tự động biết đường dẫn ra khỏi Mê cung ngầm, tìm rương báu vật ẩn, hoặc dẫn đội hình né tránh bãi mìn Vùng Zero.", rank: "Phàm Giai", cost: { type: "MP", value: 100 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo"], range_type: "Tiện ích (Chỉ đường)", combo_tag: "Wisp_Guide" },
        { name: "Cây Ăn Thịt", desc: "[Cơ chế] Gieo hạt nắp ấm siêu tốc độ dưới chân địch. [Hiệu ứng] Đất nứt ra, đóa hoa khổng lồ ngoạm lấy mục tiêu. Nhai nát áo giáp bằng răng cưa và tiết axit tiêu hóa. Nhai xong nó nhả đồ đạc của địch ra cho Ký chủ lượm.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Mộc"], range_type: "Đặt Bẫy (Tầm Trung)", combo_tag: "Flytrap_Maw" },
        { name: "Ru Ngủ Diện Rộng", desc: "[Cơ chế] Giải phóng phấn hoa chứa Melatonin nồng độ cực cao. [Hiệu ứng] Gió cuốn phấn hoa bay đi. Khiến toàn bộ quái vật (kể cả bầy đàn) trong bán kính 30m chìm vào giấc ngủ ngáy pho pho trong 1 phút. An toàn đi qua mà không tốn giọt máu nào.", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Tinh Thần"], range_type: "AoE Rộng (Khống chế mềm)", combo_tag: "Mass_Sleep" },
        { name: "Nối Xương", desc: "[Cơ chế] Tiết ra keo sinh học giàu canxi từ ngón tay. [Hiệu ứng] Kỹ năng phẫu thuật chiến trường. Nắn lại xương gãy lìa (Gãy tay/Chân), bôi keo dính lại. Trong 10 giây, xương liền hoàn toàn, bệnh nhân có thể chạy nhảy chiến đấu như thường.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Trị Liệu"], range_type: "Cận Chiến (Cấp cứu thương tật)", combo_tag: "Bone_Mend" },
        { name: "Thanh Tẩy Vùng Đất", desc: "[Cơ chế] Đảo ngược quá trình ô nhiễm phóng xạ (Corruption) của Vùng Zero. [Hiệu ứng] Áp tay xuống đất, tỏa năng lượng ấm áp. Biến một mảnh đất chết, sình lầy độc hại (AoE 20m) thành đồng cỏ xanh mướt, hoa nở rộ, xua tan chướng khí.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Mộc"], range_type: "AoE Rộng (Làm sạch môi trường)", combo_tag: "Purify_Land" },
        { name: "Hiến Tế", desc: "[Cơ chế] Chuyển nhượng lõi sinh mệnh của bản thân thay thế cái chết của chủ. [Hiệu ứng] Kỹ năng thụ động của Sủng Thú Sáng Tạo. Khi Tamer nhận Đòn Chết Chắc, Thú tự động chết thay, Tamer hồi 100% Máu. (Sủng thú có thể được hồi sinh sau nếu tìm được Thần Dược).", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Nội tại" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Sáng Tạo", "Sinh Mệnh"], range_type: "Bản thân (Chết thay)", combo_tag: "Martyr_Sacrifice" },
        { name: "Hơi Thở Sự Sống", desc: "[Cơ chế] Thổi Ma lực chứa xung nhịp tim điện từ. [Hiệu ứng] Thổi vào một cái cây khô héo, nó mọc lá ngay. Thổi vào lồng ngực người vừa chết lâm sàng (Tim ngừng đập dưới 1 phút), kích tim họ đập trở lại. CPR phiên bản Phép thuật.", rank: "Thiết Giai", cost: { type: "MP", value: 500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Sinh Mệnh"], range_type: "Cận Chiến (Cứu sống)", combo_tag: "Breath_of_Life" },
        { name: "Kén Bảo Vệ", desc: "[Cơ chế] Nhả tơ sinh học bọc kén, ngâm bệnh nhân vào dung dịch ối. [Hiệu ứng] Bọc người bị thương cực nặng vào cái kén treo lơ lửng. Thời gian bên trong bị đóng băng, vết thương không thể nặng thêm. Bảo vệ an toàn tuyệt đối trong 24h chờ xe cứu thương UHA tới.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo"], range_type: "Cận Chiến (Đóng băng thương tật)", combo_tag: "Healing_Cocoon" },
        { name: "Sửa Chữa DNA (Đảo Ngược Đột Biến)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Thâm nhập và thiết kế lại bộ gen (Genetics) cấp độ nguyên tử. [Hiệu ứng] Khép lại những dị biến quái thai. Cứu sống một Sủng thú bị Đột biến thất bại (Mutation Deformity), trả nó về trạng thái hoàn hảo, tăng vĩnh viễn 1 bậc Tiềm Năng (POT). [Tác dụng phụ] Hút 80% Max HP. Phản phệ gen khiến Ngoại hình của người dùng trở nên già nua, xấu xí (Charisma giảm mạnh), Tuổi thọ trừ 30 năm.", rank: "Diệu Giai", cost: { type: "HP", value: 65000 }, cooldown: { value: 90, unit: "Ngày", display_text: "3 Tháng" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Sinh Mệnh"], range_type: "Cận Chiến (Chữa quái thai)", combo_tag: "Divine_Gene_Fix" },
        { name: "Trái Cây Mana", desc: "[Cơ chế] Cô đặc hạt mana tự do trong không khí thành chất rắn. [Hiệu ứng] Mọc ra quả táo xanh lấp lánh. Ai ăn vào sẽ hồi phục lập tức 30% MP và xóa tan cảm giác đau đầu do cạn kiệt tinh thần (Overload).", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo"], range_type: "Tiện ích (Vật phẩm tiêu hao)", combo_tag: "Mana_Fruit" },
        { name: "Hào Quang Hộ Mệnh (Passive)", desc: "[Cơ chế] Năng lượng sống tràn trề tự rò rỉ ra ngoài cơ thể. [Hiệu ứng] Tỏa ra ánh sáng nhẹ. Mọi đồng minh đứng gần bán kính 10m được tự động hồi máu x2 tốc độ bình thường và có thêm 1 lớp Giáp Mỏng 100 HP.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Sáng Tạo"], range_type: "Xung quanh bản thân (Buff bị động)", combo_tag: "Aura_Guardian" },
        { name: "Tạo Thực Phẩm (Sinh hoạt)", desc: "[Cơ chế] Bẻ cong không khí, nước và ánh sáng thành Carbs và Protein. [Hiệu ứng] Tạo ra bánh mì, thịt nướng, rau củ từ hư không rớt xuống đĩa. Nuôi sống cả Đội quân/Bầy đàn Dị thú trong nhiều tháng mắc kẹt giữa Hoang Khu.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo"], range_type: "Tiện ích (Hậu cần/Sinh tồn)", combo_tag: "Food_Create" },
        { name: "Lọc Nước Sạch", desc: "[Cơ chế] Tách các chất độc hại và vi khuẩn khỏi phân tử H2O. [Hiệu ứng] Đặt tay xuống vũng vũng lầy hôi thối hoặc độc hại, biến nó thành Suối nước Thánh thơm ngọt, uống vào chữa bệnh nhẹ và giải khát hoàn hảo.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Nước"], range_type: "Tiện ích (Cung cấp nước)", combo_tag: "Water_Purify" },
        { name: "Tăng Trưởng Gia Súc", desc: "[Cơ chế] Thúc đẩy chu kỳ sinh học của thú nuôi ở nông trại. [Hiệu ứng] Vuốt ve Sủng thú hoặc gia súc. Khiến con non lớn lên thành con trưởng thành chỉ trong 1 ngày thay vì vài năm. Khỏe mạnh cường tráng, sản lượng cao.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo"], range_type: "Cận Chiến (Chăn nuôi/Nuôi thú)", combo_tag: "Pet_Growth_Spur" },
        { name: "Sửa Chữa Đồ Vật", desc: "[Cơ chế] Đảo ngược chiều thời gian vi mô tại vật thể bị vỡ. [Hiệu ứng] Chạm tay vào một thanh kiếm gãy đôi, mảnh giáp nát, hoặc bộ đàm bị đập nát. Nó lập tức tự ghép lại hoàn chỉnh như mới mua ở cửa hàng.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Thời Gian"], range_type: "Cận Chiến (Sửa trang bị)", combo_tag: "Item_Repair" },
        { name: "Nhà Sinh Học", desc: "[Cơ chế] Gieo hạt giống và điều khiển rễ/cành đan xen theo bản vẽ kiến trúc. [Hiệu ứng] Mọc ra ngôi nhà bằng gỗ sống đầy đủ tiện nghi (Giường êm, bàn ghế, cửa sổ) trong 1 phút. Cách nhiệt tốt, chống thú dữ. Sáng mai nhà tự héo đi phi tang dấu vết.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 12, unit: "Giờ", display_text: "12 Giờ" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Mộc"], range_type: "Tiện ích (Xây dựng căn cứ)", combo_tag: "Bio_House" },
        { name: "Cầu Nối Tâm Linh", desc: "[Cơ chế] Dệt sợi tơ não kết nối thần kinh giao cảm. [Hiệu ứng] Chạm tay đồng đội. Từ giờ cả đội không cần mở miệng, có thể suy nghĩ truyền thẳng cho nhau chiến thuật. Đặc biệt hữu ích khi lặn dưới nước hay trong môi trường Câm lặng.", rank: "Thiết Giai", cost: { type: "MP", value: 150 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Tinh Thần"], range_type: "AoE Trung (Tiện ích Giao tiếp)", combo_tag: "Mind_Bridge" },
        { name: "Xua Đuổi Tà Ma", desc: "[Cơ chế] Lan tỏa năng lượng Dương thuần khiết, rực rỡ và nóng bỏng. [Hiệu ứng] Đuổi các sinh vật bóng tối, yêu ma và ký sinh trùng biến dị sợ hãi bỏ chạy xa 100m. Không gây sát thương, nhưng là Vòng bảo vệ an toàn khi cắm trại.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Quang"], range_type: "AoE Rộng (Bảo vệ Lãnh thổ)", combo_tag: "Evil_Repel" },
        { name: "Kiến Tạo Lục Địa (Phép Lạ Ultimate)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Hội tụ quyền năng tạo hóa, nắm bắt và nhào nặn cấu trúc lõi hành tinh. [Hiệu ứng] Nâng một Lục địa hoặc một Quần Đảo khổng lồ từ dưới đáy biển sâu lên. Tạo ra Lãnh Thổ mới, đồi núi, sông suối theo ý muốn. Thay đổi bản đồ địa lý Ngự Thú Đại Lục vĩnh viễn. [Tác dụng phụ] Hút cạn 90% MP. Cơ thể người dùng bị Hóa Đá một nửa (Bán Thân Bất Toại), vĩnh viễn mất khả năng di chuyển bình thường, phải ngồi xe lăn ma thuật suốt đời.", rank: "Diệu Giai", cost: { type: "MP", value: 4500000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 120, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Thổ", "Nước"], range_type: "Cấp Thế Giới (Tạo môi trường)", combo_tag: "Divine_Continent_Forge" },
        { name: "Hóa Hình - Sinh Trưởng Dịch Dung", desc: "[Cơ chế] Mượn sức sống ép tế bào phân chia điên cuồng. [Hiệu ứng] Đắp nặn lại từ một con thú hung tợn thành một hình hài nhân loại hoàn hảo, đẹp không tì vết. Da thịt thơm mùi thảo mộc. Khả năng ngoại giao và sức hút (Charisma) tăng max.", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Sáng Tạo", "Sinh Học"], range_type: "Bản thân (Ngụy trang nhan sắc)", combo_tag: "Beast_Perfect_Human_Form" },
        { name: "Hóa Hình - Tử Linh", desc: "[Cơ Chế Sinh Học] Cưỡng ép cơ thể vào trạng thái 'chết lâm sàng'. Tế bào không phân chia, bảo quản bằng Necrotic Energy. Không có trao đổi chất. [Cấu Tạo] Nội tạng ngừng đập, không cần oxy. [Hình Thái] Gầy gò, hốc hác, da lạnh toát. [Hiệu ứng] Không biết mệt, không cần ngủ, đâm thủng tim/phổi cũng không chết. [Tác dụng phụ] Nhận x2 sát thương từ Hệ Ánh Sáng/Sáng Tạo. Mọi phép Hồi máu thông thường bơm vào người sẽ biến thành Sát thương Độc cực mạnh.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sinh Học"], range_type: "Bản thân (Chuyển đổi)", combo_tag: "Form_Undead" },
        { name: "Hút Máu", desc: "[Cơ chế] Tước đoạt sinh lực trực tiếp qua ma thuật tà ác. [Hiệu ứng] Bắn một chùm tia đỏ sậm. Rút 10% Max HP của mục tiêu và hồi phục lập tức 10% Max HP cho bản thân. Dùng liên tục để cấu rỉa đến chết.", rank: "Thiết Giai", cost: { type: "MP", value: 180 }, cooldown: { value: 8, unit: "Giây", display_text: "8 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sinh Mệnh"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Life_Drain" },
        { name: "Dịch Bệnh", desc: "[Cơ chế] Mở một vết nứt nhỏ triệu hồi vi khuẩn từ Địa ngục. [Hiệu ứng] Phun đám mây màu xanh ốm yếu. Kẻ địch hít phải bị ho lao, giảm 30% mọi chỉ số và mất máu 1% mỗi giây (Kéo dài 20 giây). Bệnh lây lan nếu chúng đứng gần nhau.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Độc"], range_type: "AoE Trung (Debuff Lây nhiễm)", combo_tag: "Plague_Spread" },
        { name: "Đoạt Mệnh (Execute)", desc: "[Cơ chế] Cắt đứt sợi dây sinh mệnh liên kết linh hồn và thể xác. [Hiệu ứng] Chỉ điểm một ngón tay. Nhìn thanh máu địch, nếu HP của chúng < 15%, kỹ năng này lập tức nghiền nát linh hồn (Chết ngay tắp lự). Bỏ qua Bất tử, Bỏ qua Khiên chắn.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sinh Mệnh"], range_type: "Tầm Xa (Tuyệt sát ngưỡng máu)", combo_tag: "Death_Finger" },
        { name: "Tay Hủy Diệt", desc: "[Cơ chế] Truyền năng lượng Entropy (Sự phân rã vũ trụ). [Hiệu ứng] Bàn tay xám xịt. Chạm vào áo giáp xịn, súng ống, xe tăng, vật phẩm đó lập tức gỉ sét tàn tạ, vỡ vụn thành bột (Độ bền = 0). Phá hủy hoàn toàn đồ đạc đắt tiền của kẻ địch.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Kim"], range_type: "Cận Chiến (Phá trang bị)", combo_tag: "Entropy_Touch" },
        { name: "Mắt Tử Thần", desc: "[Cơ chế] Khai nhãn âm dương kết nối Sổ Sinh Tử. [Hiệu ứng] Cặp mắt hóa đen nhánh. Nhìn thấy trên đỉnh đầu mọi sinh vật (Đồng minh/Kẻ địch) một đồng hồ đếm ngược báo chính xác thời gian sống còn lại của chúng. Tình báo chiến thuật thần thánh.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Thời Gian"], range_type: "Bản thân (Buff Nhãn thuật)", combo_tag: "Death_Vision" },
        { name: "Vết Thương Hoại Tử", desc: "[Cơ chế] Phủ một lớp tà khí khóa tế bào gốc quanh miệng vết thương. [Hiệu ứng] Đòn chém bằng vũ khí hắc ám. Vết chém chuyển màu đen sùi bọt. Phong ấn 100% khả năng hồi máu từ thuốc/Phép thuật của mục tiêu trong 30 giây. Rỉ máu tới chết.", rank: "Thiết Giai", cost: { type: "Stamina", value: 250 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Vật Lý"], range_type: "Cận Chiến (Khắc chế Trị Liệu)", combo_tag: "Necrotic_Wound" },
        { name: "Tịch Diệt Vạn Vật (Sự Im Lặng Cuối Cùng)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Gọi ra 'Khoảng Không Hư Vô' - Trạng thái kết thúc của vũ trụ, nơi vạn vật đều trở về tro bụi tĩnh lặng. [Hiệu ứng] Ánh chớp xám tro quét qua. Toàn bộ sinh vật, phép thuật, cấu trúc không gian trong bán kính 10km lập tức phân rã thành cát bụi vi mô không một tiếng động. Không vụ nổ, không máu me, chỉ có sự bay hơi tĩnh lặng. Xóa sổ mọi khái niệm tồn tại. [Tác dụng phụ cực lớn] Đánh đổi cái giá thảm khốc: Linh hồn người dùng cũng bị phân rã theo, xóa bỏ vĩnh viễn sự tồn tại (Chết thực tế, Xóa Nhân Vật). Không một phép thuật tái sinh nào có thể cứu vãn.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 100 }, cooldown: { value: 0, unit: "Vĩnh viễn", display_text: "Chỉ 1 lần" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Không Gian"], range_type: "Cấp Thế Giới (Xóa sổ tuyệt đối)", combo_tag: "Holy_Void_Annihilation" },
        { name: "Suy Nhược", desc: "[Cơ chế] Tăng tốc độ lão hóa telomere trong chuỗi DNA. [Hiệu ứng] Phóng tia lão hóa. Kẻ địch trúng chiêu lập tức già đi 30 tuổi, tóc bạc trắng, da nhăn nheo, tốc độ di chuyển và sức mạnh giảm 80% (Suy nhược cực điểm) trong 1 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Thời Gian"], range_type: "Tầm Xa (Debuff Già hóa)", combo_tag: "Curse_Ageing" },
        { name: "Nổ Xác", desc: "[Cơ chế] Bơm khí gas nén Necrotic vào tử thi trên chiến trường. [Hiệu ứng] Phép thuật kinh dị. Búng tay, xác chết của địch nổ tung như bom C4. Bắn mảnh xương và ruột độc hại tứ tung, gây sát thương AoE khủng khiếp. Dùng chính đồng đội chúng làm mìn.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sinh Mệnh"], range_type: "AoE Trung (Kích nổ bẫy)", combo_tag: "Corpse_Explosion" },
        { name: "Hút Mana", desc: "[Cơ chế] Kéo sợi liên kết vào bể ma lực của mục tiêu. [Hiệu ứng] Hút cạn sạch thanh Năng lượng (MP) của Xạ thủ/Pháp sư đối phương và nạp đầy cho bản thân mình. Biến kẻ thù thành bao cát không có phép thuật phòng thân.", rank: "Ngân Giai", cost: { type: "Sanity", value: 10 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Tinh Thần"], range_type: "Tầm Xa (Cướp tài nguyên)", combo_tag: "Mana_Drain" },
        { name: "Tra Tấn", desc: "[Cơ chế] Can thiệp thần kinh, nhân khuếch đại ngưỡng đau đớn lên 1000%. [Hiệu ứng] Yểm bùa Tra Tấn. Kẻ địch chỉ bị chém xước một vệt nhỏ ngoài da, nhưng não bộ cảm nhận đau đớn như bị cưa đứt chân sống. Khiến chúng gào thét hoảng loạn mất kiểm soát.", rank: "Ngân Giai", cost: { type: "MP", value: 4200 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Tinh Thần"], range_type: "Tầm Xa (Debuff Cảm giác)", combo_tag: "Agony_Curse" },
        { name: "Xích Linh Hồn", desc: "[Cơ chế] Quăng xích địa ngục móc thẳng vào Tinh Thạch/Linh hồn. [Hiệu ứng] Trói buộc linh hồn đối thủ. Nếu chúng chết trong lúc bị xích, linh hồn bị bóp nát, không thể được Đầu thai, không thể dùng phép Phục Sinh hay đồ vật hồi sinh (Xóa sổ vĩnh viễn).", rank: "Kim Giai", cost: { type: "MP", value: 95000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Tinh Thần"], range_type: "Tầm Xa (Khóa Hồi Sinh)", combo_tag: "Soul_Chain_Lock" },
        { name: "Mưa Ký Sinh", desc: "[Cơ chế] Mở cổng chiều không gian nhỏ thả bầy côn trùng hắc ám. [Hiệu ứng] Kéo đám mây đen đổ cơn mưa giun bọ háu đói (Bán kính 20m). Chúng đáp xuống, chui qua áo giáp, gặm nhấm da thịt và đẻ trứng vào mắt kẻ thù. Sát thương DoT siêu tởm lợm.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sinh Học"], range_type: "AoE Rộng (Bão sát thương)", combo_tag: "Parasite_Rain" },
        { name: "Cướp Buff", desc: "[Cơ chế] Tách rời các dòng code Ma pháp buff của kẻ thù. [Hiệu ứng] Nhìn thấy Boss/Địch vừa buff khiên, buff sát thương, hoặc buff tốc độ chạy. Chỉ một cái búng tay, cướp sạch toàn bộ hiệu ứng có lợi đó chuyển sang cho mình, địch mất trắng.", rank: "Kim Giai", cost: { type: "MP", value: 70000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt"], range_type: "Tầm Xa (Thao túng trạng thái)", combo_tag: "Buff_Stealer" },
        { name: "Hiến Tế Đệ Tử (Sủng Thú)", desc: "[Cơ chế] Khế ước Hồn Ấn bạo chúa, coi sủng thú như pin sạc dự phòng. [Hiệu ứng] Khi sắp chết, Tamer tàn nhẫn bóp nát Hồn Ấn của 1 Sủng thú phe mình. Sủng thú nổ tung chết thảm, đổi lại Tamer hồi đầy 100% HP và MP. (Giảm uy tín và Tăng Wanted Status bạo lực).", rank: "Kim Giai", cost: { type: "Sanity", value: 50 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Hắc Ám"], range_type: "Bản thân (Hồi sức đổi mạng)", combo_tag: "Sacrifice_Pet" },
        { name: "Ngày Phán Xét Cuối Cùng (Triệu Hồi Tứ Kỵ Sĩ)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Dùng máu tươi vẽ trận pháp cổ đại, triệu gọi hiện thân của Chiến Tranh, Dịch Bệnh, Nạn Đói và Tử Vong. [Hiệu ứng] 4 bóng ma khổng lồ càn quét toàn cõi chiến trường. Chém giết, thả độc, làm khô héo mùa màng và hút máu mọi kẻ địch. Dọn dẹp bản đồ một cách tàn bạo nhất. [Tác dụng phụ] Hút cạn 90% Tuổi thọ của người dùng. Ký chủ mất khả năng kiểm soát Sủng thú (Toàn bộ Loyalty của Sủng thú về 0, dễ bề phản chủ), chịu rủi ro bị chính Tứ Kỵ Sĩ quay lại ăn thịt.", rank: "Diệu Giai", cost: { type: "HP", value: 800000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 20, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Triệu Hồi", "Nguyền Rủa"], range_type: "AoE Cực Rộng (Cấp Thảm Họa)", combo_tag: "Divine_Apocalypse" },
        { name: "Ngừng Tim", desc: "[Cơ chế] Sóng xung kích siêu âm đánh lệch nhịp nút xoang nhĩ. [Hiệu ứng] Nhìn thẳng vào mắt địch. Khiến trái tim của chúng lỡ nhịp, ngừng đập hoàn toàn trong 2 giây. Gây Choáng (Stun) cực mạnh, đứt đoạn hô hấp, ngã gục ngay tại chỗ chờ bị chém.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Sinh Mệnh"], range_type: "Tầm Xa (Khống chế cứng)", combo_tag: "Cardiac_Arrest" },
        { name: "Phá Giáp", desc: "[Cơ chế] Giải phóng tia Entropy chuyên phá vỡ cấu trúc ma thuật. [Hiệu ứng] Bắn tia sáng xám. Làm tan chảy mọi loại Giáp Năng Lượng (Shield) và Giáp Vật Lý hạng nặng (Armor) của Boss về 0. Đồng đội lao vào chém gây Sát Thương Chuẩn.", rank: "Thiết Giai", cost: { type: "MP", value: 250 }, cooldown: { value: 45, unit: "Giây", display_text: "45 Giây" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt"], range_type: "Tầm Xa (Hỗ trợ tấn công)", combo_tag: "Armor_Melt_Beam" },
        { name: "Sương Mù Chết", desc: "[Cơ chế] Hơi thở của cái chết làm héo úa cấu trúc carbon. [Hiệu ứng] Thổi sương mù xám bán kính 30m. Giết chết ngay lập tức mọi thực vật, cây cỏ, vi khuẩn, côn trùng và phá hỏng các kỹ năng Hệ Mộc. Rất tốt để diệt quái vật Ẩn nấp trong rừng.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt"], range_type: "AoE Rộng (Phá hủy môi trường)", combo_tag: "Death_Fog" },
        { name: "Vết Cắt Không Lành", desc: "[Cơ chế] Lưỡi đao tẩm độc tố chống đông máu cực hạn. [Hiệu ứng] Chém một nhát. Mục tiêu bị chảy máu thành vòi xối xả liên tục mãi mãi. Mọi phép Hồi máu đều vô hiệu. Chỉ có thể chặn đứng bằng cách dùng 'Thanh Tẩy Vết Thương' đốt cháy chỗ đứt.", rank: "Thiết Giai", cost: { type: "Stamina", value: 200 }, cooldown: { value: 20, unit: "Giây", display_text: "20 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Vật Lý"], range_type: "Cận Chiến (DoT Vĩnh viễn)", combo_tag: "Bleed_Forever" },
        { name: "Sát Khí (Passive)", desc: "[Cơ chế] Cơ thể như bọt biển hút năng lượng Sợ Hãi và Máu từ kẻ chết. [Hiệu ứng] Tích tụ oán khí. Mỗi khi giết được 1 kẻ địch, Sức mạnh Công kích (STR/INT) của bản thân tăng thêm 2% (Cộng dồn tối đa 100%). Càng giết chóc ở bãi chiến trường càng mạnh như quỷ thần.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt"], range_type: "Bản thân (Buff Snowball)", combo_tag: "Killing_Intent_Stack" },
        { name: "Phân Hủy Rác (Sinh hoạt)", desc: "[Cơ chế] Đẩy nhanh quá trình Oxi hóa đồ vật về dạng bụi. [Hiệu ứng] Tiêu hủy hoàn toàn rác thải sinh hoạt, xác thú nhỏ, xương vụn hoặc chướng ngại vật cản đường. Giúp dọn dẹp sạch bong điểm cắm trại không để thú săn mồi ngửi thấy.", rank: "Phàm Giai", cost: { type: "MP", value: 30 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt"], range_type: "Cận Chiến (Tiện ích sinh tồn)", combo_tag: "Trash_Disposal" },
        { name: "Thu Hoạch Linh Hồn", desc: "[Cơ chế] Đốt cháy ma trảo bằng ngọn lửa U Minh hút hồn. [Hiệu ứng] Bóp cổ kẻ thù vừa chết. Xé rách linh hồn hắn khỏi xác và nhốt vào Đèn lồng ma thuật. Có thể dùng hồn để tra khảo tình báo bí mật hoặc làm nhiên liệu luyện đan.", rank: "Kim Giai", cost: { type: "MP", value: 75000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Tinh Thần"], range_type: "Cận Chiến (Tiện ích hắc ám)", combo_tag: "Soul_Reap" },
        { name: "Diệt Thế Long Tức (Hơi Thở Hủy Diệt)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Dung hợp sức mạnh của Tử Long Cổ Đại, nén hạt phản vật chất. [Hiệu ứng] Phun ra chùm tia đen đỏ vĩ đại phá vỡ không gian. Thổi bay một sườn núi thành tro, bốc hơi hàng ngàn thiết giáp UHA, xóa sổ mọi dấu vết trên đường đi. Sát thương AoE càn quét khủng khiếp. [Tác dụng phụ] Hút 80% Max HP. Cổ họng và phổi của thú thi triển bị đốt cháy thành than, vĩnh viễn không thể khạc lửa/phun phép nữa (Câm lặng kỹ năng hơi thở trọn đời).", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 750000 }, cooldown: { value: 180, unit: "Ngày", display_text: "Nửa Năm" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Vật Lý"], range_type: "Đường thẳng cực rộng (Cấp Thảm Họa)", combo_tag: "Divine_Doom_Breath" },
        { name: "Hủy Diệt Oxy", desc: "[Cơ chế] Đảo ngược quá trình quang hợp, chuyển Oxy thành CO2 siêu tốc. [Hiệu ứng] Rút cạn toàn bộ Oxy trong một hang động đóng kín. Đội quân địch bên trong chết ngạt hàng loạt sau 2 phút vì không có dưỡng khí hô hấp.", rank: "Kim Giai", cost: { type: "MP", value: 90000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Phong"], range_type: "AoE Rộng (Bẫy môi trường)", combo_tag: "Oxygen_Void" },
        { name: "Ăn Mòn Kết Cấu", desc: "[Cơ chế] Phát hạt rung động phá vỡ cấu trúc chịu lực Keystone. [Hiệu ứng] Áp tay vào trụ cầu thép, chân vách đá hoặc tường nhà. Trong 5 giây, toàn bộ công trình to lớn sụp đổ rầm rập, đè bẹp kẻ thù bên dưới. Trí tuệ phá hoại.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt"], range_type: "Cận Chiến (Phá hoại công trình)", combo_tag: "Structure_Collapse" },
        { name: "Gây Ung Thư", desc: "[Cơ chế] Bắn tia Gamma đột biến cấu trúc DNA ác tính cực nhanh. [Hiệu ứng] Đánh trúng đối phương. Tạo ra khối u ác tính khổng lồ phát triển mọc tủa trên tay/chân chúng ngay lập tức. Khối u gây vướng víu, giảm 50% chỉ số CON và ăn mòn máu.", rank: "Kim Giai", cost: { type: "MP", value: 110000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sinh Học"], range_type: "Tầm Xa (Debuff cực độc)", combo_tag: "Cancer_Curse" },
        { name: "Tiếng Hét Tử Vong", desc: "[Cơ chế] Sóng siêu âm tần số dị biệt cộng hưởng với hộp sọ. [Hiệu ứng] Thét lên âm thanh chói tai (Banshee Scream). Kẻ địch (Level thấp hơn người dùng) nghe thấy sẽ lập tức nổ vỡ mạch máu não, chảy máu tai, chết đứng ngay tại chỗ.", rank: "Ngân Giai", cost: { type: "MP", value: 6500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sóng Âm"], range_type: "AoE Trung (Quét lính yếu)", combo_tag: "Banshee_Wail" },
        { name: "Vùng Đất Chết", desc: "[Cơ chế] Lan truyền khí Necrotic thâm nhập vào mạch nước ngầm. [Hiệu ứng] Giậm chân, biến 1 khu vực rừng rậm/đồng cỏ tươi tốt (100x100m) thành hoang mạc cằn cỗi, xương xẩu trắng ởn trong 10 giây. Đất đai không bao giờ mọc lại được cây.", rank: "Kim Giai", cost: { type: "MP", value: 130000 }, cooldown: { value: 4, unit: "Giờ", display_text: "4 Giờ" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Thổ"], range_type: "AoE Rộng (Phá hủy hệ sinh thái)", combo_tag: "Deadland_Aura" },
        { name: "Tước Đoạt Giác Quan", desc: "[Cơ chế] Đánh thẳng vào dây thần kinh sọ não số 2, 8, 1. [Hiệu ứng] Bắn bùa chú. Tước đi ngẫu nhiên 2 giác quan của kẻ thù (Gây mù, gây điếc, hoặc mất vị giác/khứu giác hoàn toàn) trong 5 phút. Vô hiệu hóa khả năng định hướng của chúng.", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Tinh Thần"], range_type: "Tầm Xa (Debuff Cảm quan)", combo_tag: "Sense_Deprive" },
        { name: "Cấm Chữa Trị", desc: "[Cơ chế] Bức xạ phản quang khóa chặt nguyên tố Sáng Tạo. [Hiệu ứng] Rải màng không gian màu xám. Mọi phép thuật Hồi máu (Heal) hoặc Dược phẩm cứu thương tung ra trong khu vực này lập tức bị phản tác dụng, biến thành sát thương độc.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Lời Nguyền"], range_type: "AoE Trung (Khắc chế Trị Liệu)", combo_tag: "Anti_Heal_Zone" },
        { name: "Hóa Hình - Bì Nhục Khâu Vá (Đặc Biệt - Dị Thú)", desc: "[Cơ chế] Lột da người chết để tự bọc lấy thân thể quái thú mục nát (Giống quỷ Wendigo). [Hiệu ứng] Ăn cắp da thịt của con người đã chết và mặc lên người làm lớp ngụy trang. Mùi xác thối luôn thoang thoảng. Lớp da này cung cấp Giáp máu thêm, khi bị chém vỡ sẽ hiện nguyên hình kinh dị.", rank: "Kim Giai", cost: { type: "Bloodline_Energy", value: 50 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 60, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sinh Học"], range_type: "Bản thân (Ngụy trang tà ác)", combo_tag: "Skin_Walker_Form" },
        { name: "Huyết Quỷ Hấp Huyết", desc: "[Cơ chế] Kích hoạt enzyme hoại tử ở tuyến nước bọt, cắn ngập răng vào động mạch đối thủ. [Hiệu ứng] Rút cạn sinh mệnh lực và tế bào máu của con mồi. Gây sát thương vật lý xuyên giáp và hồi lại 50% HP tối đa cho bản thân trong vòng 10 giây. [Tác dụng phụ] Máu nạp vào mang theo tạp chất, giảm 5 Sanity mỗi lần sử dụng.", rank: "Ngân Giai", cost: { type: "Stamina", value: 300 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Sinh Học"], range_type: "Cận Chiến (Đơn mục tiêu)", combo_tag: "Vampiric_Bite" },
        { name: "Khuẩn Ôn Dịch Lây Lan", desc: "[Cơ chế] Nuôi cấy virus phân hủy tế bào hạch bạch huyết và rải vào không khí. [Hiệu ứng] Gieo rắc mầm bệnh bán kính 5m. Kẻ địch nhiễm bệnh bị hoại tử, mất 2% Max HP mỗi giây trong 60 giây. Nếu kẻ địch chạm vào đồng minh của chúng, virus sẽ lây lan theo cấp số nhân. [Tương tác] Dễ bị thanh tẩy bởi ma pháp hệ Quang/Nước nhiệt độ cao.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Khí Độc"], range_type: "AoE Khởi điểm (Lây lan)", combo_tag: "Plague_Seed" },
        { name: "Tước Đoạt Tuổi Thọ", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Chạm trực tiếp vào bản nguyên sinh mệnh, phá hủy chuỗi Telomere ở đầu nhiễm sắc thể của nạn nhân. [Hiệu ứng] Đòn đánh không gây sát thương máu thông thường mà làm lão hóa toàn bộ tế bào của kẻ địch đi 20 năm ngay lập tức. Vĩnh viễn trừ 30% HP tối đa của chúng không thể phục hồi. [Tác dụng phụ] Luật nhân quả phản phệ: Bản thân người dùng cũng bị giảm 5 năm tuổi thọ và mất 20% Max HP vĩnh viễn.", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 500000 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Nguyền Rủa"], range_type: "Cận Chiến (Khóa mục tiêu)", combo_tag: "Age_Steal" },
        { name: "Bàn Tay Hủy Diệt", desc: "[Cơ chế] Tích tụ hạt năng lượng phản vật chất mỏng lên móng vuốt hoặc bàn tay. [Hiệu ứng] Phá vỡ liên kết phân tử của vật chất vô cơ. Bất kỳ trang bị (Kiếm, Giáp, Súng) nào chạm vào bàn tay này đều lập tức bị rỉ sét, mục nát và giảm độ bền (Durability) về 0 trong 3 giây. Phế võ công của các Tamer phụ thuộc trang bị.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt"], range_type: "Bản thân (Buff vũ khí)", combo_tag: "Decay_Touch" },
        { name: "Mắt Nhìn Cái Chết", desc: "[Cơ chế] Đồng bộ nhãn cầu với tần số suy tàn của tử thần. [Hiệu ứng] Nhìn chằm chằm vào mục tiêu. Nếu HP của mục tiêu đang ở dưới ngưỡng 15%, nhãn thuật sẽ kích hoạt hiệu ứng 'Đột Tử', bóp nát trái tim chúng từ xa mà không cần chạm vào. Nếu HP > 15%, kỹ năng thất bại và người dùng bị mù 5 giây.", rank: "Kim Giai", cost: { type: "Sanity", value: 15 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Tinh Thần"], range_type: "Tầm Xa (Kết Liễu)", combo_tag: "Death_Gaze" },
        { name: "Gieo Rắc Hoại Tử", desc: "[Cơ chế] Phủ một lớp năng lượng chết mang tính ức chế sinh trưởng lên vũ khí/móng vuốt. [Hiệu ứng] Kỹ năng bị động. Bất kỳ vết thương hở nào do thú này gây ra đều bị ám khí đen, tuyệt đối không thể được chữa lành bằng kỹ năng hệ Mộc, hệ Quang hay Thuốc hồi phục trong vòng 24 giờ. Nạn nhân chỉ có thể chờ chết vì mất máu.", rank: "Kim Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt"], range_type: "Bản thân (Bị động)", combo_tag: "Anti_Heal" },
        { name: "Khí Tức Suy Nhược", desc: "[Cơ chế] Phát tán một loại khí gas phá hủy khả năng dẫn truyền thần kinh vận động. [Hiệu ứng] Phun ra luồng khí màu xám đục bán kính 15m. Mọi sinh vật hít phải (kể cả đồng minh nếu không có kháng) lập tức bị trừ 50% Tốc Độ (AGI), 50% Lực Đánh (STR) và chậm chạp phản xạ trong 3 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Khí Độc"], range_type: "AoE Trung", combo_tag: "Weakness_Aura" },
        { name: "Bom Huyết Nhục", desc: "[Cơ chế] Bơm ma lực hủy diệt vào tàn dư sinh học, biến áp suất máu thành thuốc nổ. [Hiệu ứng] Phát nổ toàn bộ xác chết dị thú/người nằm trên chiến trường trong bán kính 30m. Xương cốt vỡ vụn văng tứ tung như mảnh đạn găm vào đối phương, máu độc gây sát thương ăn mòn diện rộng cực kỳ khủng khiếp.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Vật Lý"], range_type: "AoE Rộng (Dựa trên Xác chết)", combo_tag: "Corpse_Explosion" },
        { name: "Hút Cạn Mana", desc: "[Cơ chế] Kéo dài một xúc tu năng lượng tàng hình cắm thẳng vào vỏ não mục tiêu. [Hiệu ứng] Chọc vòi vào não địch, tước đoạt toàn bộ MP (Mana) của chúng với tốc độ 10% Max MP mỗi giây. Số MP hút được sẽ được tinh lọc và chuyển thẳng về hồi phục cho Ký chủ/Tamer. Địch cạn MP sẽ rơi vào trạng thái Ngất Xỉu.", rank: "Kim Giai", cost: { type: "Stamina", value: 500 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Tinh Thần"], range_type: "Tầm Trung (Khóa mục tiêu kéo dài)", combo_tag: "Mana_Drain" },
        { name: "Đánh Đắp Đau Đớn", desc: "[Cơ chế] Can thiệp trực tiếp vào thụ thể Nociceptor của hệ thần kinh trung ương. [Hiệu ứng] Khuếch đại mọi cảm giác đau đớn vật lý của kẻ địch lên gấp 10 lần trong 5 phút. Một vết xước nhỏ cũng mang lại cảm giác như bị cưa cụt tay. Địch (nếu có CON và SPI thấp) sẽ gục ngã, co giật vì sốc phản vệ thần kinh.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 8, unit: "Phút", display_text: "8 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Nguyền Rủa"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Pain_Amplifier" },
        { name: "Xiềng Xích Rút Cốt", desc: "[Cơ chế] Bắn ra các sợi xích cấu tạo từ khí hắc ám, có khả năng đi xuyên da thịt để bám vào vật chất canxi cứng. [Hiệu ứng] Sợi xích móc chặt vào xương sống kẻ thù. Cưỡng ép kéo giật chúng lại gần phía mình bất chấp kích thước. Nếu kẻ địch cố kháng cự, xích sẽ xé rách xương cột sống gây bại liệt vĩnh viễn.", rank: "Kim Giai", cost: { type: "MP", value: 75000 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Vật Lý"], range_type: "Tầm Xa (Kéo mục tiêu)", combo_tag: "Bone_Hook" },
        { name: "Cơn Mưa Ký Sinh Xấu", desc: "[Cơ chế] Nhả ra hàng vạn nang bào tử sinh học chứa giun hắc ám. [Hiệu ứng] Bắn lên trời, rơi xuống như mưa (Bán kính 20m). Giun ký sinh lọt qua khe giáp, đục khoét hộp sọ và chui vào não bộ mục tiêu. Trong vòng 1 phút, kẻ địch chịu sát thương nội tạng liên tục và mất kiểm soát cơ thể (chạy tán loạn).", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Sinh Học"], range_type: "AoE Trung", combo_tag: "Parasite_Rain" },
        { name: "Nuốt Chửng Hy Vọng", desc: "[Cơ chế] Kích hoạt từ trường phân giải ma pháp, nhắm vào các chuỗi buff tích cực. [Hiệu ứng] Cắn nuốt mọi hiệu ứng Buff (Tăng sức mạnh, Tạo khiên, Tăng tốc, Hồi máu tay) đang có trên người 1 kẻ địch. Xóa sổ buff của chúng và biến toàn bộ các chỉ số cộng thêm đó áp dụng ngược lại cho bản thân trong 3 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Buff_Steal" },
        { name: "Nghi Thức Hiến Tế", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Trận pháp cổ xưa chuyển hóa 100% sinh mệnh lực và linh hồn thành năng lượng tinh khiết. [Hiệu ứng] Tự tay giết chết một đồng minh hoặc sủng thú cấp thấp của mình. Ngay lập tức hồi đầy 100% HP, 100% MP cho Ký chủ, đồng thời xóa mọi Debuff. [Tác dụng phụ] Pet bị hiến tế sẽ CHẾT VĨNH VIỄN (Xóa khỏi Beast Roster). Điểm Karma/Reputation giảm cực sâu, bị UHA liệt vào danh sách Truy nã cấp S vì tội ác tà giáo.", rank: "Diệu Giai", cost: { type: "Sanity", value: 50 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Nghi Thức"], range_type: "Cận Chiến (Đồng minh)", combo_tag: "Sacrifice_Ritual" },
        { name: "Tim Đập Lỗi Nhịp", desc: "[Cơ chế] Bóp méo tần số điện tim của mục tiêu thông qua cộng hưởng từ trường đen. [Hiệu ứng] Can thiệp từ xa, ép nhịp tim kẻ địch ngừng đập hoàn toàn trong 1 giây. Gây choáng váng (Stun) ngay lập tức, ngắt quãng mọi hành động niệm chú, và gây hoảng loạn tột độ khi máu không lên não.", rank: "Thiết Giai", cost: { type: "MP", value: 300 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt", "Sinh Học"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Heart_Stop" },
        { name: "Ám Dịch Ăn Mòn Giáp", desc: "[Cơ chế] Tuyết nước bọt biến đổi thành siêu axit đậm đặc chứa ma lực hủy diệt. [Hiệu ứng] Phun ra chất lỏng đen ngòm. Làm bốc hơi ngay lập tức mọi loại giáp vật lý (Titan/Thép) và xuyên thủng khiên năng lượng, biến chúng thành vũng nước hôi thối. Kẻ địch hoàn toàn trần trụi trước đòn tiếp theo.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Độc"], range_type: "Hình Nón (Tầm Ngắn)", combo_tag: "Armor_Melt" },
        { name: "Sương Mù Tử Vong (Kỷ Nguyên Sụp Đổ)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Triệu hồi hiện thân của cõi chết, mở rách khe nứt tới Vực Thẳm, để không khí của Minh Giới tràn vào hiện thực. [Hiệu ứng] Che phủ toàn bộ một chiến trường/thành phố (Bán kính 5km) bằng khí chết đen đặc. Mọi thực vật lập tức khô héo hóa tro bụi. Bất kỳ sinh vật, Dị thú hay con người nào dưới cấp Vương Thú/Bạch Kim hít phải sẽ LẬP TỨC TỬ VONG (Instant Kill) bị rút cạn sinh hồn. Vùng đất này biến thành tử địa cằn cỗi trong 100 năm. [Tác dụng phụ cực lớn] Rút cạn toàn bộ Soul_Force. Người dùng bị nguyền rủa bởi hàng vạn oán linh: Giảm 50% Max HP vĩnh viễn, Sanity tụt về 10 (Ám ảnh ảo giác suốt đời), và mất khả năng dùng hệ Mộc/Quang vĩnh viễn.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 100 }, cooldown: { value: 3650, unit: "Ngày", display_text: "10 Năm" }, cast_time: { value: 30, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Vong Linh"], range_type: "AoE Rất Rộng (Thảm Họa Bậc S)", combo_tag: "Death_Mist_Wipe" },
        { name: "Vết Thương Xé Rách", desc: "[Cơ chế] Thao túng áp lực máu tại vị trí da bị hở. [Hiệu ứng] Kích hoạt từ xa. Bất kỳ vết xước nhỏ nào trên người kẻ địch (kể cả do gai đâm) sẽ đột ngột bị xé toạc ra thành một vết thương sâu hoắm lộ xương. Gây xuất huyết ồ ạt, trừ HP theo % mỗi giây trong 1 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt"], range_type: "Tầm Xa (Yêu cầu địch đang chảy máu)", combo_tag: "Wound_Tear" },
        { name: "Bản Chất Tàn Độc (Bị động)", desc: "[Cơ chế] Tế bào sinh học cộng hưởng với mùi máu và sự hoảng loạn của con mồi. [Hiệu ứng] Kỹ năng bị động. Hưởng lợi từ sát khí. Cứ mỗi 10% lượng máu của toàn chiến trường bị mất đi (kể cả địch lẫn ta), sức mạnh tấn công (STR) và tốc độ (AGI) của người dùng tăng lên 5%. Đánh càng lâu, càng đẫm máu thì càng mạnh.", rank: "Thiết Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Hủy Diệt"], range_type: "Bản thân (Buff bị động)", combo_tag: "Bloodlust_Passive" },
        { name: "Sợi Chỉ Đoạt Mệnh", desc: "[Cơ chế] Rút tơ nhện tử vong tàng hình đan thành bẫy. [Hiệu ứng] Rải các sợi tơ cực bén không thể nhìn thấy bằng mắt thường (Bán kính 10m). Kẻ thù di chuyển qua sẽ bị cắt đứt gân kheo, đứt động mạch cổ, chịu sát thương chảy máu chí mạng mà không hề biết nguồn gốc đòn đánh.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt", "Vật Lý"], range_type: "AoE Khống Chế (Bẫy tàng hình)", combo_tag: "Death_Wire" },
        { name: "Chuyển Hóa Cấu Trúc (Phân rã)", desc: "[Cơ chế] Bắn chùm tia hạt làm phá vỡ liên kết nguyên tử khối. [Hiệu ứng] Bắn một luồng năng lượng đen. Mọi vật thể rắn như đá tảng, xe bọc thép, tường thành chắn ngang tia này sẽ phân rã thành cát bụi mịn trong 3 giây. Mở đường tiến công tuyệt đối cho đội hình.", rank: "Kim Giai", cost: { type: "MP", value: 100000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Hủy Diệt"], range_type: "Đường thẳng (Xuyên thấu phá hủy)", combo_tag: "Matter_Decay" },
        { name: "Hóa Hình - Không Ảnh", desc: "[Cơ Chế Sinh Học & Nguyên Lý] Dùng năng lượng không gian nén bản thể quái vật khổng lồ vào 'khuôn đúc' con người. Cơ thể tồn tại như một sự nhiễu loạn thực tại. [Cấu Tạo] Nội tạng là các túi không gian nhỏ kết nối qua cổng dịch chuyển vi mô. [Hình Thái] Hình ảnh hay bị chập chờn (glitch), giọng nói vang vọng đa chiều. Có thể chứa vật phẩm vào dạ dày như túi không gian. [Tác dụng phụ] Khi nhận sát thương lớn, khuôn đúc sẽ nứt gãy khiến cơ thể gốc bị rỉ máu ra ngoài không gian.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Sinh Học"], range_type: "Bản thân (Chuyển đổi hình thái)", combo_tag: "Form_Space" },
        { name: "Dịch Chuyển Tức Thời (Teleport)", desc: "[Cơ chế] Gấp khúc không gian 3 chiều để nối liền hai điểm A và B. [Hiệu ứng] Di chuyển ngay lập tức bản thân đến bất cứ đâu trong tầm mắt (Tối đa 500m) mà không mất thời gian di chuyển. Giúp né tránh đòn tất sát hoặc áp sát ám sát. [Tác dụng phụ] Nếu bị làm mù hoặc mất tầm nhìn, dịch chuyển mù có thể khiến cơ thể kẹt vào trong bức tường (Tử vong).", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 10, unit: "Giây", display_text: "10 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Tầm Xa (Di chuyển)", combo_tag: "Blink_Assassinate" },
        { name: "Lưỡi Dao Không Gian", desc: "[Cơ chế] Bẻ cong mép của thực tại tạo thành một khe hở không gian hình lưỡi liềm mỏng cỡ nguyên tử. [Hiệu ứng] Vung tay chém ra nhát cắt vô hình. Nhát cắt này không tương tác với vật chất mà chém đứt chính 'không gian' chứa vật chất đó. Bỏ qua 100% Giáp phòng ngự, Khiên ma pháp. Cắt đứt đôi cơ thể kẻ địch dễ như cắt bơ.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tầm Trung (Đường thẳng)", combo_tag: "Space_Sever" },
        { name: "Tăng Tốc Thời Gian", desc: "[Cơ chế] Tạo một màng bong bóng thời gian bao quanh đồng minh, làm thời gian bên trong trôi nhanh hơn bên ngoài. [Hiệu ứng] Giúp bản thân và toàn bộ đồng đội trong bán kính 10m di chuyển, xuất chiêu, và niệm chú nhanh gấp đôi (Tăng 100% AGI, giảm 50% Cast Time) trong vòng 30 giây.", rank: "Kim Giai", cost: { type: "MP", value: 90000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "AoE Trung (Buff Đồng minh)", combo_tag: "Time_Haste" },
        { name: "Ngưng Đọng Thời Gian (Stasis)", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Can thiệp vào dòng chảy Entropi, cưỡng ép mọi hạt vật chất ngừng dao động hoàn toàn. [Hiệu ứng] Đóng băng thời gian toàn bộ chiến trường (Bán kính 200m) trong đúng 10 giây. Mọi kẻ địch, mũi tên bay, vụ nổ, ma pháp đều bị dừng cứng ngắc. Chỉ người dùng và đồng minh được chỉ định mới có thể di chuyển và tàn sát. [Tác dụng phụ] Tiêu hao 10 năm tuổi thọ mỗi lần dùng. Toàn thân chảy máu vi mạch do áp lực chênh lệch thời không. Sanity giảm mạnh 30 điểm.", rank: "Diệu Giai", cost: { type: "HP", value: 50000 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "AoE Rất Rộng (Đóng băng tuyệt đối)", combo_tag: "World_Stop" },
        { name: "Túi Không Gian (Inventory)", desc: "[Cơ chế] Mở một lỗ hổng vĩnh viễn tới một chiều không gian trống không có sự sống. [Hiệu ứng] Kỹ năng tiện ích. Tạo kho chứa đồ vô hạn (Slot không giới hạn, không có trọng lượng đè lên người). Thời gian bên trong bằng 0, bảo quản vật phẩm, thức ăn, thảo dược vĩnh viễn không hư hỏng hay ôi thiu.", rank: "Phàm Giai", cost: { type: "MP", value: 50 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Tiện ích)", combo_tag: "Void_Storage" },
        { name: "Hoán Đổi", desc: "[Cơ chế] Đánh tráo tọa độ không gian 3 chiều của 2 khối vật chất có khối lượng tương đương. [Hiệu ứng] Đổi vị trí của mình với một hòn đá, một đồng minh hoặc chính kẻ địch ngay trước khi luồng sát thương ập tới. Gây rối loạn đội hình địch, khiến chúng tự bắn lầm vào nhau.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Tầm Xa (Khóa tọa độ)", combo_tag: "Position_Swap" },
        { name: "Trì Hoãn Sát Thương", desc: "[Cơ chế] Bắt giữ sát thương trong một rãnh thời gian trước khi nó tác động vào cơ thể. [Hiệu ứng] Kích hoạt trước khi ăn đòn. Toàn bộ sát thương kinh hoàng nhận vào (ví dụ 100,000 HP) sẽ không trừ ngay, mà chia đều ra mỗi giây trừ 10,000 HP trong 10 giây tiếp theo. Chống sốc sát thương chết yểu, câu thời gian chờ healer hồi máu.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Phòng thủ)", combo_tag: "Damage_Delay" },
        { name: "Vòng Lặp (Loop)", desc: "[Cơ chế] Cắt một đoạn thời gian 3 giây và ghép đuôi nó vào đầu đoạn đó. [Hiệu ứng] Bắt 1 kẻ địch (SPI thấp) rơi vào vòng lặp vô nghĩa. Chúng sẽ lặp lại hành động vừa làm (Ví dụ: Chạy tới rồi lại lùi về điểm cũ, vung kiếm vào không khí) liên tục trong 30 giây. Khống chế cứng cực kỳ khó chịu.", rank: "Kim Giai", cost: { type: "MP", value: 85000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Tinh Thần"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Time_Loop" },
        { name: "Triệu Hồi Bản Thân", desc: "[Cơ chế] Bẻ cong dòng thời gian để tạo giao điểm giữa Quá Khứ, Hiện Tại và Tương Lai. [Hiệu ứng] Gọi 2 phiên bản của chính mình (Từ 1 tiếng trước và 1 tiếng sau) đến hỗ trợ chiến đấu trong vòng 60 giây. Bản thân có 3 người cùng xuất chiêu, tạo hỏa lực gấp 3 lần. [Tác dụng phụ] Hết giờ, MP cạn kiệt, kiệt sức cực độ.", rank: "Kim Giai", cost: { type: "MP", value: 250000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Triệu hồi)", combo_tag: "Past_Future_Sync" },
        { name: "Lỗ Đen", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Nén vật chất đến mật độ vô hạn, xé thủng chân không tạo Điểm Kỳ Dị (Singularity). [Hiệu ứng] Bắn ra một viên bi đen nhánh. Nó lập tức phình to thành Lỗ Đen đường kính 10m. Hút toàn bộ đòn tấn công, ánh sáng, quái vật, địa hình xung quanh vào cõi hư vô (Xóa sổ vĩnh viễn khỏi game). Lực hút vô phương chống đỡ. [Tác dụng phụ] Người dùng bị mất vĩnh viễn 1 tay hoặc 1 chân do lực hấp dẫn cắn xé lúc niệm chú. Sanity giảm 40.", rank: "Diệu Giai", cost: { type: "Bloodline_Energy", value: 800000 }, cooldown: { value: 365, unit: "Ngày", display_text: "1 Năm" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Vật Lý"], range_type: "AoE Rộng (Hủy diệt diện rộng)", combo_tag: "Singularity_Wipe" },
        { name: "Tiên Tri (Né đòn)", desc: "[Cơ chế] Nhìn xuyên qua bức màn xác suất lượng tử của 2 giây kế tiếp. [Hiệu ứng] Kích hoạt trạng thái thần thánh cục bộ. Mắt phát sáng, nhìn thấy chính xác quỹ đạo đạn bay, hướng chém của đối thủ trước khi chúng ra đòn 2 giây. Giúp cơ thể tự động né tránh hoàn hảo 100% mọi đòn vật lý/ma pháp trong 30 giây.", rank: "Kim Giai", cost: { type: "Sanity", value: 15 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Né tránh tối thượng)", combo_tag: "Future_Vision" },
        { name: "Tàng Hình Không Gian", desc: "[Cơ chế] Lách cơ thể vào chiều không gian thứ 4 (Chiều giữa các thực tại). [Hiệu ứng] Hình bóng mờ nhạt đi. Xóa bỏ hoàn toàn sự hiện diện vật lý. Vũ khí, tia laser, sóng siêu âm, đòn đánh AOE đều đi xuyên qua cơ thể bạn như xuyên qua không khí. Không một ai có thể chạm vào bạn trong 15 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 6500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Bất khả xâm phạm)", combo_tag: "Dimension_Hide" },
        { name: "Lão Hóa", desc: "[Cơ chế] Bắn một tia dòng chảy thời gian cục bộ tập trung gia tốc sự tàn lụi. [Hiệu ứng] Đánh trúng kẻ thù sẽ khiến cơ thể chúng già đi 50 năm trong nháy mắt. Tóc bạc trắng, cơ bắp teo tóp, HP tối đa giảm 80%. Hoặc dùng lên vũ khí/Mecha địch để làm chúng rỉ sét, mục nát vỡ vụn ngay lập tức.", rank: "Kim Giai", cost: { type: "MP", value: 180000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tầm Trung (Đơn mục tiêu)", combo_tag: "Time_Decay" },
        { name: "Chấn Động Không Gian", desc: "[Cơ chế] Cộng hưởng tần số phá vỡ màng không gian 3 chiều. [Hiệu ứng] Nắm chặt tay đấm vào hư không. Màn không gian nứt vỡ như kính thủy tinh bán kính 20m. Mọi kẻ địch nằm trong vùng rạn nứt bị xé nát cơ thể bởi các khe nứt không gian, sát thương chuẩn bỏ qua giáp không thể phòng ngự.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Vật Lý"], range_type: "AoE Trung (Sát thương chuẩn)", combo_tag: "Space_Shatter" },
        { name: "Trọng Lực Đảo Ngược", desc: "[Cơ chế] Thay đổi véc-tơ của lực hấp dẫn (Graviton) quanh một điểm chỉ định. [Hiệu ứng] Chọn một vùng bán kính 30m. Kích hoạt khiến lực hút Trái Đất quay ngược 180 độ. Toàn bộ kẻ địch, xe tăng, quái vật trong vùng đó sẽ 'rơi' ngược lên trời với tốc độ cực nhanh. Khi tắt skill, chúng rơi tự do xuống đất nát bấy.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Vật Lý"], range_type: "AoE Rộng (Khống chế địa hình)", combo_tag: "Reverse_Gravity" },
        { name: "Bóng Chậm", desc: "[Cơ chế] Trải Lĩnh vực nén đặc cấu trúc không gian (như ma trận gel). [Hiệu ứng] Tạo vùng không gian bán kính 15m. Mọi mũi tên, đạn pháo, ánh sáng ma pháp hay kẻ địch bay vào vùng này lập tức bị làm chậm lại như bò (Tốc độ giảm 99%). Bạn có thể ung dung bước né đạn như trong phim Matrix.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "AoE Trung (Lĩnh vực phòng thủ)", combo_tag: "Time_Matrix" },
        { name: "Kho Phản Hồi", desc: "[Cơ chế] Mở cổng không gian (Wormhole) nuốt sát thương và mở cổng nhả ra. [Hiệu ứng] Tạo một vòng tròn đen trước mặt. Hút toàn bộ đạn vật lý, hỏa cầu, tia laser của địch vào kho không gian. Lượt tiếp theo, mở vòng tròn đó ngay sau lưng kẻ địch, bắn trả lại toàn bộ sát thương chúng vừa tung ra.", rank: "Kim Giai", cost: { type: "MP", value: 110000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tường Phản Đòn", combo_tag: "Portal_Return" },
        { name: "Xuyên Vật Thể", desc: "[Cơ chế] Làm mờ dao động nguyên tử của cơ thể, không tương tác với các hạt nguyên tử khác. [Hiệu ứng] Kích hoạt trạng thái Ghost. Cho phép bản thân đi xuyên qua mọi bức tường sắt thép, boongke phòng thủ ngầm, núi đá vững chãi nhất trong vòng 60 giây. Cực kỳ bá đạo để đột nhập căn cứ UHA.", rank: "Ngân Giai", cost: { type: "MP", value: 3800 }, cooldown: { value: 8, unit: "Phút", display_text: "8 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Di chuyển xuyên thấu)", combo_tag: "Ghost_Walk" },
        { name: "Dấu Ấn Dịch Chuyển (Waypoint)", desc: "[Cơ chế] Đóng đinh một tọa độ cố định vào cấu trúc không gian nền của thế giới. [Hiệu ứng] Đặt một ấn chú ẩn dưới mặt đất tại Căn cứ an toàn. Dù đang ở tận cùng thế giới (Hoang Khu sâu thẳm), chỉ cần niệm chú 10 giây, lập tức xé rách không gian đưa cả tổ đội biến về nhà ngay lập tức.", rank: "Kim Giai", cost: { type: "MP", value: 100000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Toàn Bản Đồ (Biến về)", combo_tag: "Town_Portal" },
        { name: "Cắt Đứt (Telefrag)", desc: "[Cơ chế] Vi phạm định luật bài trừ Pauli bằng cách dịch chuyển 2 khối vật chất vào cùng 1 tọa độ. [Hiệu ứng] Dịch chuyển một vật thể cứng (Hòn đá tảng, hoặc thanh sắt) vào thẳng BÊN TRONG cơ thể (tim/não) của kẻ địch. Gây sát thương nổ nát bét từ trong ra ngoài. Cực kỳ tàn bạo, bỏ qua mọi loại giáp.", rank: "Kim Giai", cost: { type: "MP", value: 180000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Vật Lý"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Telefrag_Kill" },
        { name: "Làm Mới (Cooldown)", desc: "[Cơ chế] Tua ngược dòng thời gian cục bộ áp dụng lên chính hệ thống kinh mạch và ma lực của bản thân. [Hiệu ứng] Kích hoạt sẽ lập tức RESET toàn bộ thời gian hồi chiêu (Cooldown) của MỌI kỹ năng (trừ kỹ năng cấp Diệu/Thánh). Cho phép tung ra 2 combo hủy diệt liên tiếp.", rank: "Kim Giai", cost: { type: "Sanity", value: 20 }, cooldown: { value: 1, unit: "Ngày", display_text: "1 Ngày" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Tiện ích Combat)", combo_tag: "Cooldown_Reset" },
        { name: "Bảo Quản Thực Phẩm", desc: "[Cơ chế] Vi thao tác khóa thời gian vật thể vô tri. [Hiệu ứng] Đưa một bát súp nóng hoặc một miếng thịt nướng vào túi không gian. 10 năm sau lấy ra nó vẫn đang bốc khói nghi ngút và giữ nguyên hương vị. Kỹ năng sinh tồn vô giá trong Hoang Khu.", rank: "Phàm Giai", cost: { type: "MP", value: 10 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tiện ích Túi đồ", combo_tag: "Stasis_Food" },
        { name: "Cánh Cửa Thần Kỳ", desc: "[Cơ chế] Tạo Wormhole kết nối bề mặt 2 vật chất dạng phẳng. [Hiệu ứng] Vẽ hai vòng tròn lên 2 bức tường cách nhau tối đa 1km. Biến chúng thành lối đi tắt. Mở cửa bên này sẽ bước ra ở cửa bên kia. Có thể duy trì 1 giờ để chuyển quân lén lút.", rank: "Ngân Giai", cost: { type: "MP", value: 6500 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 1, unit: "Phút", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tầm Xa (Tạo lối tắt)", combo_tag: "Wormhole_Door" },
        { name: "Phòng Cách Ly", desc: "[Cơ chế] Cắt rời một khối lập phương không gian (3x3m) và giấu nó ra ngoài thực tại. [Hiệu ứng] Tạo một căn phòng vô hình giữa hư không. Ký chủ và đồng minh chui vào đó nghỉ ngơi, nướng thịt, trị thương. Cấm địa tuyệt đối, bên ngoài dù là Thần thú cũng không thể tìm thấy hoặc đánh vỡ.", rank: "Kim Giai", cost: { type: "MP", value: 200000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 3, unit: "Phút", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tạo Không Gian (Nơi Trú Ẩn)", combo_tag: "Safe_Room" },
        { name: "Dọn Dẹp Siêu Tốc", desc: "[Cơ chế] Hút vật chất kích thước vi mô vào khe nứt thứ nguyên. [Hiệu ứng] Hút sạch mọi bụi bẩn, máu me, rác rưởi, dấu chân trong phòng hoặc trên chiến trường vào hư không. Xóa bỏ hoàn toàn dấu vết hiện trường để chống lại sự điều tra/truy vết bằng khứu giác.", rank: "Phàm Giai", cost: { type: "MP", value: 20 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "AoE Nhỏ (Xóa dấu vết)", combo_tag: "Clean_Trace" },
        { name: "Tách Rời Cơ Thể", desc: "[Cơ chế] Tạo các cổng không gian nhỏ tại vị trí các khớp xương. [Hiệu ứng] Có thể tự tháo rời cánh tay, con mắt ném qua tường để nhặt đồ hoặc thám thính. Phần cơ thể bị tháo vẫn kết nối với hệ thần kinh qua không gian vô hình, hoạt động bình thường và không hề đau đớn/chảy máu.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Tiện ích)", combo_tag: "Portal_Limbs" },
        { name: "Quan Sát Từ Xa", desc: "[Cơ chế] Gấp khúc ánh sáng từ khoảng cách xa chiếu thẳng vào võng mạc. [Hiệu ứng] Mở một lăng kính không gian nhỏ cỡ bàn tay tàng hình. Nhìn trộm, nghe lén mọi cuộc họp kín của kẻ thù ở cách xa hàng dặm mà không bị hàng rào ma pháp phát hiện.", rank: "Ngân Giai", cost: { type: "MP", value: 2500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tầm Xa (Tình báo)", combo_tag: "Remote_Spy" },
        { name: "Chống Dịch Chuyển", desc: "[Cơ chế] Khóa cứng các dao động hạt không gian trong một khu vực, biến nó thành bùn đặc. [Hiệu ứng] Phong tỏa không gian (Bán kính 500m) trong 30 phút. Không một ai (kể cả người dùng) có thể xài kỹ năng Dịch chuyển, Biến về hay Đi xuyên tường. Nhốt chặt con mồi để chém giết bằng tay bo.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 4, unit: "Giờ", display_text: "4 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "AoE Rất Rộng (Cấm thuật không gian)", combo_tag: "Dimensional_Lock" },
        { name: "Reset (Kỷ Nguyên Đảo Ngược)", desc: "[Thánh Giai - Tối Hậu] [Cơ chế] Giao thức cấm kỵ: Can thiệp trực tiếp vào Bánh Răng Thời Gian của Trật Tự Vĩnh Hằng. Bẻ ngược dòng sông thời gian cục bộ. [Hiệu ứng] Quay ngược thời gian toàn bộ một khu vực lãnh thổ lại chính xác 1 PHÚT TRƯỚC. Hồi sinh đồng đội vừa chết, xóa bỏ mọi sai lầm, khôi phục lại lâu đài vừa bị nổ. Kẻ địch không giữ ký ức, chỉ mình bạn nhớ. [Tác dụng phụ cực lớn] Đánh đổi 50 năm tuổi thọ. Sanity bị xóa sạch về 0 ngay lập tức (Rơi vào trạng thái Hôn mê hoặc Điên loạn Berserk). Linh hồn bị Trật Tự Vĩnh Hằng đánh dấu, trừ 50% HP Max vĩnh viễn.", rank: "Thánh Giai", cost: { type: "Soul_Force", value: 100 }, cooldown: { value: 3650, unit: "Ngày", display_text: "10 Năm" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Toàn Lãnh Thổ (Đảo ngược thực tại)", combo_tag: "Holy_Time_Reversal" },
        { name: "Hóa Hình - Vết Nứt Đa Chiều", desc: "[Cơ chế] Thú hệ Thời không lấy mảnh vỡ không gian làm da thịt. [Hiệu ứng] Bọc lại hình hài quái vật khổng lồ, hiển thị ra ngoài là ảo ảnh hình dáng con người cực kỳ hoàn mỹ. Tuy nhiên, nếu bị quay phim lại, băng hình sẽ bị nhiễu sóng hoặc chỉ thấy một hố đen hình người. Che giấu chân thân hoàn hảo trước mọi thiết bị dò tìm UHA.", rank: "Kim Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Ảo Giác"], range_type: "Bản thân (Ngụy trang tối thượng)", combo_tag: "Glitch_Disguise" },
        { name: "Thuấn Di Hư Không", desc: "[Cơ chế] Đi vào cõi hư không và bước ra ngay lập tức ở thế giới thực. [Hiệu ứng] Dịch chuyển tức thời tới bất kỳ điểm nào ngắm bắn được (Kể cả sau bức tường dày hàng chục mét). Bỏ qua mọi chướng ngại vật vật lý. Khoảng cách tối đa 1km. Hoàn hảo để chạy trốn hoặc thọc sườn.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 1, unit: "Phút", display_text: "1 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Tầm Xa (Di chuyển tức thời)", combo_tag: "Void_Blink" },
        { name: "Lưỡi Đao Không Gian (Xé Rách)", desc: "[Cơ chế] Dùng móng vuốt cào thẳng vào màng không gian. [Hiệu ứng] Bẻ cong không gian tạo 3 nhát chém vô hình khổng lồ. Bỏ qua 100% Giáp vật lý và Khiên năng lượng, chém làm đôi núi đá và xe tăng. Vết thương không thể lành bằng thuốc (vì thịt đã bị nuốt vào không gian khác).", rank: "Kim Giai", cost: { type: "MP", value: 140000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Vật Lý"], range_type: "Tầm Trung (Đường thẳng)", combo_tag: "Space_Rend" },
        { name: "Gia Tốc Thời Gian (Cuồng Bạo)", desc: "[Cơ chế] Bơm năng lượng tăng tần số rung động của bản thân cực đại. [Hiệu ứng] Tăng nhanh dòng thời gian của bản thân. Trong 10 giây tiếp theo, tốc độ của bạn nhanh đến mức vạn vật xung quanh như đứng im. Thực hiện liên tiếp 5 đòn tấn công trước khi địch kịp chớp mắt.", rank: "Kim Giai", cost: { type: "HP", value: 8000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Buff siêu tốc)", combo_tag: "Time_Acceleration" },
        { name: "Ngưng Đọng Khoảnh Khắc", desc: "[Cơ chế] Đóng băng thời gian cục bộ áp dụng lên 1 chủ thể duy nhất. [Hiệu ứng] Chọn 1 mục tiêu (Địch hoặc Đồng minh). Đóng băng họ trong luồng sáng xám trong 10 giây. Người bị đóng băng sẽ bất động hoàn toàn, nhưng đồng thời BẤT KHẢ XÂM PHẠM (không nhận sát thương). Dùng để cứu đồng minh hấp hối hoặc loại bỏ Tanker địch.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tầm Trung (Đơn mục tiêu)", combo_tag: "Time_Stasis_Single" },
        { name: "Túi Không Gian Ẩn (Nuốt Chửng)", desc: "[Cơ chế] Há miệng tạo lỗ hổng không gian hút vạn vật. [Hiệu ứng] Thú há to mồm. Nuốt chửng các đòn tấn công ma pháp (hỏa cầu, lôi điện) hoặc nuốt Ký chủ vào bụng (Chiều không gian an toàn) để mang chạy trốn. Không gian trong bụng có thể tiêu hóa kim loại.", rank: "Ngân Giai", cost: { type: "Stamina", value: 1500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Cận Chiến (Nuốt đồ/Bảo vệ)", combo_tag: "Void_Devour" },
        { name: "Hoán Đổi Tọa Độ (Đánh Lừa)", desc: "[Cơ chế] Đổi chỗ tức thời với vật thể bị đánh dấu. [Hiệu ứng] Quăng một viên đá/phi tiêu không gian. Bất cứ khi nào trong vòng 5 phút, niệm chú sẽ lập tức hoán đổi vị trí của Ký Chủ với viên đá đó. Né đòn chết tuyệt hảo và tạo combo ảo diệu.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 30, unit: "Giây", display_text: "30 Giây" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Tầm Xa (Tương tác vật thể)", combo_tag: "Mark_Swap" },
        { name: "Trì Hoãn Quá Khứ (Vỏ Bọc)", desc: "[Cơ chế] Đẩy lùi thời điểm nhận sát thương về tương lai. [Hiệu ứng] Khi nhận một đòn sát thương khổng lồ (Ví dụ 10,000 HP gây chết ngay). Sát thương sẽ bị phân mảnh, chia đều ra mỗi phút trừ 1000 HP trong 10 phút. Kéo dài mạng sống chờ Medic chữa trị.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 4, unit: "Giờ", display_text: "4 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Sinh tồn cứu mạng)", combo_tag: "Damage_Delay_Beast" },
        { name: "Vòng Lặp Vô Tận (Ảo Giác Không Gian)", desc: "[Cơ chế] Cắt rãnh thời không xung quanh mục tiêu, khóa chúng vào băng chuyền vòng tròn. [Hiệu ứng] Khiến kẻ địch chạy trốn mãi nhưng thực chất chỉ đang chạy trên một máy chạy bộ không gian vô hình. Chúng không thể tiến lên một bước nào trong vòng 30 giây, kiệt sức mà gục ngã.", rank: "Kim Giai", cost: { type: "MP", value: 95000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tầm Xa (Khống chế địa hình)", combo_tag: "Endless_Treadmill" },
        { name: "Phân Thân Đa Chiều (Quần Ẩu)", desc: "[Cơ chế] Lấy ra các 'khả năng tồn tại' của bản thân ở các vũ trụ song song. [Hiệu ứng] Gọi 2 phiên bản của quái vật từ dòng thời gian khác (Một bản cầm khiên, một bản cầm kiếm) đến chiến đấu cùng trong 1 phút. Cả 3 cùng sở hữu 100% sức mạnh nguyên bản. Áp đảo kẻ địch bằng số lượng.", rank: "Kim Giai", cost: { type: "MP", value: 200000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Triệu hồi)", combo_tag: "Multiverse_Clones" },
        { name: "Vết Nứt Hút Chìm", desc: "[Cơ chế] Rạch một đường trên hư không tạo lỗ rò rỉ áp suất đa chiều. [Hiệu ứng] Tạo một vết nứt đen ngòm lơ lửng. Nó hoạt động như máy hút bụi siêu cấp, hút sạch mọi độc khí, mây sương mù, bão lửa diện rộng của địch đẩy ra vùng không gian chết. Dọn dẹp chiến trường hoàn hảo.", rank: "Ngân Giai", cost: { type: "MP", value: 4800 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "AoE Khử Ma Pháp", combo_tag: "Rift_Cleaner" },
        { name: "Gương Thời Gian", desc: "[Cơ chế] Hiển thị hình chiếu của tương lai lờ mờ đè lên hiện tại. [Hiệu ứng] Mắt quái thú phát sáng bạc. Nhìn thấy trước tàn ảnh đòn đánh của kẻ thù trong 1 giây tới. Cơ thể tự động lách qua làn đạn, né kiếm một cách nhẹ nhàng như múa. Duy trì 15 giây.", rank: "Kim Giai", cost: { type: "Sanity", value: 20 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Buff Né tuyệt đối)", combo_tag: "Foresight_Dodge" },
        { name: "Xóa Bỏ Hiện Diện", desc: "[Cơ chế] Nhét hoàn toàn thực thể vào kẽ hở hẹp vô cực giữa chiều 3 và chiều 4. [Hiệu ứng] Tàng hình tuyệt đối. Không phát ra nhiệt độ, không có mùi, không có khối lượng, không phản xạ radar. Đi dạo giữa hàng vạn quân địch mà không ai có thể phát hiện hay chạm vào. Duy trì 30 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Tàng hình)", combo_tag: "Presence_Erase" },
        { name: "Tuổi Thọ Tua Nhanh", desc: "[Cơ chế] Tấn công bằng entropy gia tốc. [Hiệu ứng] Cú cắn/đấm mang theo dòng chảy thời gian vặn xoắn. Kẻ địch trúng chiêu sẽ bị lão hóa bộ phận đó đi 50 năm. Da dẻ nhăn nheo rụng rời, xương cốt xốp giòn, giáp trụ titan vỡ nát thành rỉ sét ngay lập tức. Giảm vĩnh viễn DEF và HP Max.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Cận Chiến (Phá hủy)", combo_tag: "Age_Accelerate" },
        { name: "Sóng Âm Không Chiều", desc: "[Cơ chế] Rống lên làm rung động chính cấu trúc dây (String theory) của không gian. [Hiệu ứng] Sóng chấn động vô hình không truyền qua không khí mà truyền qua không gian. Xé nát mọi thứ trong bán kính 30m. Sát thương chuẩn, không thể chặn bằng khiên vật lý hay nút bịt tai.", rank: "Kim Giai", cost: { type: "MP", value: 125000 }, cooldown: { value: 20, unit: "Phút", display_text: "20 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "AoE Trung (Sát thương chuẩn)", combo_tag: "Spatial_Roar" },
        { name: "Bẻ Cong Lực Hấp Dẫn", desc: "[Cơ chế] Xóa bỏ liên kết của hạt Graviton với mục tiêu cụ thể. [Hiệu ứng] Chỉ tay vào kẻ địch (hoặc xe cơ giới). Xóa bỏ trọng lượng của chúng. Chúng sẽ lơ lửng, chới với giữa không trung mà không có điểm tựa để vung vũ khí. Trở thành bia tập bắn trong 15 giây.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Vật Lý"], range_type: "Tầm Xa (Khống chế nổi)", combo_tag: "Zero_Gravity" },
        { name: "Quả Cầu Bóp Méo", desc: "[Cơ chế] Nén nhiễu loạn không gian thành dạng cầu ném đi. [Hiệu ứng] Bắn quả cầu tàng hình. Khi bay qua, nó hút ánh sáng, vặn xoắn cấu trúc đường đạn, bóp méo hình dạng của kẻ địch (Gãy xương, cong nòng súng). Gây sát thương vật lý cực dị.", rank: "Ngân Giai", cost: { type: "MP", value: 5000 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không"], range_type: "Tầm Xa (Sát thương/Debuff)", combo_tag: "Distortion_Orb" },
        { name: "Làm Chậm Trọng Lực", desc: "[Cơ chế] Tăng độ nhớt của không gian kết hợp tăng cường hạt Higgs. [Hiệu ứng] Phủ một khu vực (Bán kính 20m) bằng lớp lưới thời-trọng lực. Mọi đạn pháo, tên lửa, sát thủ lao vào vùng này lập tức bị đè nặng gấp 10 lần và bay chậm như rùa bò. Tamer dễ dàng đi bộ sang bên cạnh để né.", rank: "Kim Giai", cost: { type: "MP", value: 80000 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Thời Không", "Vật Lý"], range_type: "AoE Trung (Lĩnh vực phòng ngự)", combo_tag: "Heavy_Slow_Zone" },
        { name: "Lưu Trữ Sát Thương", desc: "[Cơ chế] Dùng cơ thể làm vật chứa đa chiều để hút động năng. [Hiệu ứng] Bật khiên đen. Hút toàn bộ sát thương của kẻ địch tung ra trong 5 giây (Bao gồm lửa, đạn, đao kiếm) nhét vào hư không. Giây thứ 6, nổ tung giải phóng 100% sát thương đó dội ngược lại đội hình địch.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Tụ lực phản công)", combo_tag: "Damage_Store_Burst" },
        { name: "Miễn Nhiễm Không Gian (Bị động)", desc: "[Cơ chế] Tế bào liên tục chớp tắt tần số (Phasing) cực nhanh. [Hiệu ứng] Kỹ năng bị động tối cao. Không bị ảnh hưởng bởi vũng lầy, gai nhọn địa hình, băng trơn trượt hay các loại bẫy trói buộc vật lý (Lưới, Xích sắt). Cơ thể tự động đi xuyên qua các chướng ngại nhỏ cản đường.", rank: "Ngân Giai", cost: { type: "None", value: 0 }, cooldown: { value: 0, unit: "Tức thì", display_text: "Không" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Thời Không"], range_type: "Bản thân (Kháng tính)", combo_tag: "Terrain_Immunity" },
        { name: "Hóa Hình - Tâm Tướng", desc: "[Cơ Chế Sinh Học & Nguyên Lý] Không có cơ thể vật lý thực. Phóng chiếu một 'khái niệm con người' thẳng vào não và giác quan người nhìn. Tạo xúc giác, khứu giác giả lập hoàn hảo. [Cấu Tạo] Nội tạng là khối mô phỏng tâm linh dựa trên niềm tin. [Hình Thái] Hình dạng thay đổi tùy người nhìn (người thấy đẹp tuyệt trần, kẻ thấy quỷ dữ). Dạng người thao túng tâm lý xã hội tuyệt đối, không thể bị mổ xẻ phát hiện chân thân. [Tác dụng phụ] Nếu gặp kẻ thù bị mù hoặc không có ý thức (Robot), hình thái này vô tác dụng.", rank: "Ngân Giai", cost: { type: "MP", value: 40 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 15, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Tinh Thần", "Ảo Giác"], range_type: "Bản thân (Ngụy trang nhận thức)", combo_tag: "Concept_Form" },
        { name: "Mộng Yểm", desc: "[Cơ chế] Móc nối vào amygdala (hạch hạnh nhân) định hình nỗi sợ thuần túy. [Hiệu ứng] Đưa kẻ địch (SPI thấp) vào một giấc mơ thức tỉnh (Waking nightmare). Chúng nhìn thấy tử thần, sâu bọ bò dưới da, hoặc cái chết của người thân. Khiến địch tự sát vì sợ hãi hoặc mất trí vĩnh viễn (Sanity về 0) trong vòng 3 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 5500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Ảo Giác"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Nightmare_Cast" },
        { name: "Bẻ Cong Xác Suất", desc: "[Cơ chế] Thao túng hàm sóng lượng tử để ép buộc kết quả có lợi. [Hiệu ứng] Trong 10 giây, mọi đòn tấn công của địch dù có 'Tỉ lệ trúng 100%' cũng sẽ vi phạm vật lý mà trượt qua tóc bạn (Miss). Ngược lại, bạn ném một hòn đá bừa bãi cũng chắc chắn trúng yết hầu địch (Hit 100%, Crit 100%). Sức mạnh cực kỳ phi lý.", rank: "Kim Giai", cost: { type: "Sanity", value: 20 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Khái Niệm"], range_type: "Bản thân (Buff nhân phẩm)", combo_tag: "Probability_Twist" },
        { name: "Quên Lãng", desc: "[Cơ chế] Xóa bỏ định nghĩa của 'Kỹ năng' khỏi cơ sở dữ liệu não bộ. [Hiệu ứng] Nhắm vào 1 kẻ thù. Khiến chúng đột nhiên quên mất cách sử dụng vũ khí đang cầm trên tay (Nhìn khẩu súng mà không biết bóp cò), hoặc quên sạch cách niệm thần chú mạnh nhất của chúng trong vòng 5 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 6000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Tinh Thần"], range_type: "Tầm Xa (Khóa kỹ năng)", combo_tag: "Concept_Amnesia" },
        { name: "Luật Cấm", desc: "[Cơ chế] Áp đặt một quy tắc Khái Niệm Lĩnh Vực (Domain Rule) lên vùng không gian thực. [Hiệu ứng] Tạo vùng sáng bán kính 50m. Đặt luật 'Cấm dùng hệ Hỏa' hoặc 'Cấm di chuyển nhanh'. Bất kỳ ai (kể cả phe ta) vi phạm luật này sẽ lập tức bị Thiên phạt đánh xuống, chịu sát thương sấm sét chuẩn mất 20% Max HP. Kéo dài 2 phút.", rank: "Kim Giai", cost: { type: "MP", value: 150000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Lĩnh Vực"], range_type: "AoE Rộng (Lĩnh Vực Quy Tắc)", combo_tag: "Rule_Enforce" },
        { name: "Vận Đen", desc: "[Cơ chế] Ám một trường xui xẻo (Bad Luck Aura) dính chặt vào linh hồn. [Hiệu ứng] Nguyền rủa 1 mục tiêu. Trong vòng 1 giờ, địch sẽ liên tục vấp ngã mặt chà xuống đất, súng nổ kẹt đạn tự đứt tay, phép thuật phản phệ nổ vào mặt, đồng đội quăng lựu đạn lỗi trúng đầu nó. Sự xui xẻo mang tính tấu hài nhưng chí mạng.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Nguyền Rủa"], range_type: "Tầm Xa (Debuff may mắn)", combo_tag: "Jinx_Curse" },
        { name: "Ăn Mòn Tồn Tại", desc: "[Diệu Giai - Tác dụng phụ lớn] [Cơ chế] Sát thương không trừ HP vật lý, mà trừ thẳng vào thanh 'Sự Tồn Tại' ở chiều không gian thứ 5. [Hiệu ứng] Tung một đòn đánh xám xịt. Nếu lượng sát thương Tồn Tại tích lũy vượt quá sinh mệnh, mục tiêu sẽ bốc hơi. Không ai nhớ chúng từng tồn tại, gia đình quên mặt, văn bản lịch sử ghi tên chúng tự động bị xóa trắng. [Tác dụng phụ] Đánh đổi sự Tồn tại của chính mình. Người dùng sẽ bị mất đi 1 ký ức quan trọng nhất trong đời, dần dần trở thành cái bóng vô cảm.", rank: "Diệu Giai", cost: { type: "Sanity", value: 40 }, cooldown: { value: 30, unit: "Ngày", display_text: "30 Ngày" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm"], range_type: "Tầm Trung (Xóa sổ hiện thực)", combo_tag: "Existence_Erase" },
        { name: "Thần May Mắn", desc: "[Cơ chế] Thu hút mọi năng lượng Tích cực (Good Karma) của vũ trụ vào bản thân. [Hiệu ứng] Buff AoE nhỏ cho tổ đội. Đi thám hiểm Hoang Khu chắc chắn nhặt được Bảo vật, đập trứng 100% ra thú hiếm. Trong Combat: Tỉ lệ bạo kích (Crit) tăng 50%, tỉ lệ rớt đồ xịn từ Boss x3. Kéo dài 30 phút.", rank: "Kim Giai", cost: { type: "MP", value: 80000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 5, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm"], range_type: "AoE Đồng minh (Buff Nhân Phẩm)", combo_tag: "Aura_Fortune" },
        { name: "Hòa Bình Giả Tạo", desc: "[Cơ chế] Phủ sóng khái niệm 'Bình Yên' chép đè lên 'Sát Ý' trong não bộ. [Hiệu ứng] Lan tỏa một luồng sáng ấm áp (Bán kính 20m). Khiến mọi kẻ địch (Có SPI thấp) bất chợt rơi nước mắt, mất hoàn toàn ý chí chiến đấu, vứt bỏ vũ khí, chỉ muốn ôm lấy người bên cạnh hoặc về nhà làm nông. Dừng combat ngay lập tức trong 2 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 7000 }, cooldown: { value: 30, unit: "Phút", display_text: "30 Phút" }, cast_time: { value: 4, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Tinh Thần"], range_type: "AoE Trung (Ngừng chiến)", combo_tag: "Pacify_Mind" },
        { name: "Ký Ức Đau Thương", desc: "[Cơ chế] Đào bới thư mục 'Truma' sâu thẳm nhất dưới tiềm thức. [Hiệu ứng] Bắn một tia nhìn màu tím thẫm. Khơi gợi lại cảnh tượng cái chết của người thân, sự phản bội, hoặc nỗi đau lớn nhất của địch. Nạn nhân sụp đổ tinh thần, gào thét quỳ trên mặt đất, hoàn toàn mất khả năng tự vệ và giảm Sanity liên tục trong 1 phút.", rank: "Ngân Giai", cost: { type: "MP", value: 4000 }, cooldown: { value: 8, unit: "Phút", display_text: "8 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Ảo Giác"], range_type: "Tầm Xa (Khống chế cứng)", combo_tag: "Trauma_Trigger" },
        { name: "Đổi Mục Tiêu (Thay Đổi Nhận Thức)", desc: "[Cơ chế] Tráo đổi Khái niệm nhãn dán 'Đồng Minh' và 'Kẻ Thù' trong não quang học/sinh học. [Hiệu ứng] Bẻ cong nhận thức của bầy quái vật hoặc tổ đội địch. Chúng sẽ nhìn thấy bạn là Lãnh đạo tối cao của chúng, và nhìn thấy đồng đội của chúng là Kẻ thù truyền kiếp. Chúng sẽ quay súng cắn xé tàn sát lẫn nhau đến chết. Duy trì 3 phút.", rank: "Kim Giai", cost: { type: "MP", value: 120000 }, cooldown: { value: 1, unit: "Giờ", display_text: "1 Giờ" }, cast_time: { value: 3, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Tinh Thần"], range_type: "AoE Rộng (Phản Gián)", combo_tag: "Friend_Foe_Swap" },
        { name: "Mù Màu (Rối Loạn Giác Quan)", desc: "[Cơ chế] Phá vỡ định nghĩa màu sắc và âm thanh tiếp nhận. [Hiệu ứng] Kẻ địch trúng chiêu nhìn thấy máu là màu xanh lục, bầu trời màu đỏ đục, nghe tiếng súng thành tiếng chim hót. Sự bất đồng bộ giác quan nghiêm trọng khiến chúng nôn mửa, chóng mặt, giảm 80% độ chính xác của mọi đòn đánh tầm xa. Kéo dài 5 phút.", rank: "Thiết Giai", cost: { type: "MP", value: 500 }, cooldown: { value: 3, unit: "Phút", display_text: "3 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Ảo Giác"], range_type: "Tầm Trung (Debuff Giác quan)", combo_tag: "Sense_Scramble" },
        { name: "Hút Vận May", desc: "[Cơ chế] Chuyển dịch dòng chảy Karma từ vật chủ này sang vật chủ khác. [Hiệu ứng] Kỹ năng ngoài Combat. Đứng gần một kẻ giàu có hoặc một NPC may mắn. Hút trộm toàn bộ điểm LUCK của họ chuyển sang cho mình trong 24 giờ. Bạn đi mua vé số trúng độc đắc, còn kẻ kia ra đường bị xe đâm.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 1, unit: "Phút", is_instant: false }, elements: ["Hệ Khái Niệm"], range_type: "Tầm Gần (Tiện ích ăn cắp LUCK)", combo_tag: "Luck_Vampire" },
        { name: "Hình Nhân Thế Mạng", desc: "[Cơ chế] Chuyển giao khái niệm 'Cái chết của tôi' sang một vật vô tri. [Hiệu ứng] Làm phép lên một con búp bê rơm (Hoặc một viên đá). Mang nó theo người. Khi Ký chủ nhận đòn đánh mang sát thương tử vong, con búp bê sẽ đứt đầu/vỡ vụn thay. Ký chủ hồi phục lại 100% HP ở trạng thái hoàn hảo cách đó 10m. (Mỗi búp bê tốn nguyên liệu đắt đỏ).", rank: "Kim Giai", cost: { type: "Soul_Force", value: 10 }, cooldown: { value: 7, unit: "Ngày", display_text: "7 Ngày" }, cast_time: { value: 1, unit: "Giờ", is_instant: false }, elements: ["Hệ Khái Niệm", "Sinh Mệnh"], range_type: "Bản thân (Chuẩn bị từ trước/Hồi sinh)", combo_tag: "Voodoo_Substitute" },
        { name: "Câm Lặng Tuyệt Đối", desc: "[Cơ chế] Xóa sổ sự tồn tại của sóng âm thanh trong môi trường vật lý. [Hiệu ứng] Biến một khu vực bán kính 30m thành vùng chân không âm thanh. Cấm thuật tuyệt đối đối với các Pháp sư/Dị thú hệ Phong, hệ Âm thanh (Cần mồm để niệm chú/rống). Súng đạn nổ không phát ra tiếng. Hoàn hảo để ám sát tập thể ban đêm.", rank: "Ngân Giai", cost: { type: "MP", value: 4500 }, cooldown: { value: 10, unit: "Phút", display_text: "10 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm"], range_type: "AoE Trung (Lĩnh vực câm lặng)", combo_tag: "Absolute_Silence" },
        { name: "Lãng Quên Mục Đích", desc: "[Cơ chế] Gọt bỏ ý niệm 'Tại sao' trong động cơ hành động. [Hiệu ứng] Đánh trúng một mũi tên/tia sáng vào đầu kẻ địch. Đang giơ gươm chém, chúng khựng lại, ngơ ngác gãi đầu tự hỏi 'Ủa mình ra đây làm gì nhỉ? Tên kia là ai?'. Trạng thái ngơ ngác kéo dài 10 giây, đủ để Tamer chạy trốn hoặc phản công dễ dàng.", rank: "Ngân Giai", cost: { type: "MP", value: 3500 }, cooldown: { value: 2, unit: "Phút", display_text: "2 Phút" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Khái Niệm", "Tinh Thần"], range_type: "Tầm Xa (Đơn mục tiêu)", combo_tag: "Purpose_Erase" },
        { name: "Kết Nối Giác Quan (Khổ Nhục Kế)", desc: "[Cơ chế] Tạo cây cầu khái niệm 'Sự Đồng Điệu' giữa các cá thể. [Hiệu ứng] Khóa mục tiêu vào 1 con Boss hùng mạnh. Trong 1 phút, bạn tự rạch tay mình 1 vết, tay con Boss cũng đứt 1 vết. Bạn chặt đứt chân mình, chân con Boss đứt lìa (Dù nó bọc thép dày 10 lớp). Dùng máu thịt bản thân để phá vỡ phòng ngự tuyệt đối của kẻ địch.", rank: "Kim Giai", cost: { type: "HP", value: 5000 }, cooldown: { value: 2, unit: "Giờ", display_text: "2 Giờ" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Nguyền Rủa"], range_type: "Tầm Xa (Liên kết sát thương)", combo_tag: "Sympathy_Pain" },
        { name: "Bất Tử Giả", desc: "[Cơ chế] Tạm thời xóa bỏ khái niệm 'Tử Vong' khỏi định nghĩa của cơ thể. [Hiệu ứng] Buff lên bản thân. Kéo dài 30 giây. Trong thời gian này, HP có thể rơi xuống 0, tim bị móc ra, đầu bị chặt đứt lìa... nhưng bạn KHÔNG CHẾT. Vẫn có thể cầm đầu của mình lên, vác kiếm chém kẻ thù như một cỗ máy chiến tranh bất diệt. Hết 30 giây, nếu HP vẫn là 0, bạn sẽ chết thật.", rank: "Kim Giai", cost: { type: "Sanity", value: 30 }, cooldown: { value: 24, unit: "Giờ", display_text: "24 Giờ" }, cast_time: { value: 0, unit: "Tức thì", is_instant: true }, elements: ["Hệ Khái Niệm", "Sinh Mệnh"], range_type: "Bản thân (Chống chết cực hạn)", combo_tag: "False_Immortality" },
        { name: "Vô Hiệu Hóa Vật Lý", desc: "[Cơ chế] Chuyển đổi trạng thái Tồn tại từ Vật chất sang Thông tin lượng tử. [Hiệu ứng] Cơ thể biến thành hình chiếu Hologram trong 15 giây. Miễn nhiễm 100% mọi sát thương đâm chém, súng đạn, bom nổ, độc dược. Đổi lại, bạn cũng không thể gây sát thương vật lý lên kẻ địch (Chỉ dùng được skill hệ Tinh Thần/Khái Niệm).", rank: "Ngân Giai", cost: { type: "MP", value: 8000 }, cooldown: { value: 5, unit: "Phút", display_text: "5 Phút" }, cast_time: { value: 1, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm"], range_type: "Bản thân (Chuyển đổi trạng thái)", combo_tag: "Physical_Nullify" },
        { name: "Thay Đổi Giá Trị (Lừa Đảo)", desc: "[Cơ chế] Bóp méo khái niệm 'Giá Trị' trong mắt của người giao dịch. [Hiệu ứng] Cầm một cục đá cuội ven đường, làm phép biến nó thành 1 thỏi vàng ròng 9999 rực rỡ (Ảo ảnh hoàn hảo cả về trọng lượng và độ cứng). Dùng để mua bán, lừa gạt Thương hội Vạn Thú Các. Ảo ảnh tự biến mất sau 24 giờ. Đòi hỏi kỹ năng chạy trốn nhanh trước khi bị truy sát.", rank: "Thiết Giai", cost: { type: "MP", value: 200 }, cooldown: { value: 1, unit: "Ngày", display_text: "1 Ngày" }, cast_time: { value: 10, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Ảo Giác"], range_type: "Tiện ích (Giao dịch)", combo_tag: "Scam_Illusion" },
        { name: "Thuyết Phục Tuyệt Đối", desc: "[Cơ chế] Phủ lên lời nói tần số sóng 'Chân Lý', khiến não bộ người nghe tự động chấp nhận vô điều kiện. [Hiệu ứng] Đưa ra một câu yêu cầu. Kẻ địch/NPC (có SPI thấp) sẽ tin sái cổ và phục tùng. Ví dụ: 'Khẩu súng của mày đang bị lỗi nổ tung đấy, vứt nó đi'. Địch lập tức hoảng sợ vứt súng đi. Không có tác dụng với lệnh tự sát.", rank: "Ngân Giai", cost: { type: "MP", value: 3000 }, cooldown: { value: 15, unit: "Phút", display_text: "15 Phút" }, cast_time: { value: 2, unit: "Giây", is_instant: false }, elements: ["Hệ Khái Niệm", "Tinh Thần"], range_type: "Tầm Nghe Thấy (Giao tiếp)", combo_tag: "Absolute_Persuasion" },
