    function checkCanRoll(id) {
        if (rollCounts[id] > 0) {
            rollCounts[id]--;
            document.getElementById(id + '-count').innerText = rollCounts[id];
            return true;
        } else {
            alert("Minh Kính cảnh báo: Năng lượng cho module này đã cạn kiệt!");
            return false;
        }
    }

    function applyCheat() {
        const code = document.getElementById('cheat-code').value;
        if (code === 'lọ lọ lọ') {
            for (let key in rollCounts) {
                rollCounts[key] += 300;
                if (document.getElementById(key + '-count')) {
                    document.getElementById(key + '-count').innerText = rollCounts[key];
