    }

    // =======================================================================
    // 3. LOGIC GIAO DIỆN
    // =======================================================================
    // HÀM TỰ ĐỘNG XUỐNG DÒNG MÔ TẢ
function autoFormatDescriptions() {
    // 1. Hàm cắt chuỗi và thêm \n\n cực kỳ an toàn
    const formatStrSafe = (text) => {
        if (typeof text !== 'string') return text;

        let parts = text.split('[');
        if (parts.length <= 1) return text; 

        let result = parts[0];
        for (let i = 1; i < parts.length; i++) {
            if (result.trim().length > 0) {
                // Thêm \n\n chuẩn xác để JSON.stringify nhận diện thành ngắt dòng
                result = result.trimEnd() + '\n\n'; 
            }
            result += '[' + parts[i];
        }
        return result;
    };

    // 2. Hàm quét Đệ Quy: Tự động lùng sục mọi object để format
    const formatObjectDeep = (obj) => {
        if (!obj || typeof obj !== 'object') return;

        // Các từ khóa biến chứa văn bản dài (đảm bảo lúc xuất SillyTavern sẽ nhận)
        const textKeys = ['desc', 'description', 'effect', 'lore', 'mechanic_effect'];

        textKeys.forEach(key => {
            if (typeof obj[key] === 'string') {
                obj[key] = formatStrSafe(obj[key]);
            }
        });

        // Đào sâu vào các object/array con (áp dụng cho dbSkills, dataEquips...)
        for (let key in obj) {
            if (typeof obj[key] === 'object') {
                formatObjectDeep(obj[key]);
            }
        }
    };

    // 3. Danh sách TOÀN BỘ các mảng dữ liệu của bạn (Đã bổ sung Trang Bị, Vật Phẩm)
    const allDataSources = [
        typeof dataTalents !== 'undefined' ? dataTalents : null, 
        typeof dataBloodlines !== 'undefined' ? dataBloodlines : null, 
        typeof listBaseRaces !== 'undefined' ? listBaseRaces : null, 
        typeof dataLocationsTamer !== 'undefined' ? dataLocationsTamer : null, 
        typeof dataLocationsBeast !== 'undefined' ? dataLocationsBeast : null, 
        typeof dataProfessionsTamer !== 'undefined' ? dataProfessionsTamer : null, 
        typeof dataProfessionsBeast !== 'undefined' ? dataProfessionsBeast : null, 
        typeof dataEquips !== 'undefined' ? dataEquips : null,         // Mới thêm
        typeof dataItems !== 'undefined' ? dataItems : null,           // Mới thêm
        typeof dbSkills !== 'undefined' ? dbSkills : null,             // Mới thêm
        typeof dataElementsInfo !== 'undefined' ? dataElementsInfo : null
    ];

    // Chạy format cho toàn bộ
    allDataSources.forEach(source => formatObjectDeep(source));

    // 4. Bơm thẳng CSS vào Web để ép hiển thị xuống dòng
    const styleFix = document.createElement('style');
    styleFix.innerHTML = `
        /* Ép hiển thị dấu xuống dòng (\\n) trên diện rộng */
        .tooltip-content, 
        .desc-box, 
        [id*="desc"], 
        [class*="desc"] {
            white-space: pre-wrap !important;
            line-height: 1.6 !important;
        }

        /* Mở rộng tooltip để dễ nhìn hơn */
        .tooltip-content {
            width: 360px !important;
            font-size: 1.05em !important;
            padding: 12px !important;
        }

        .desc-box {
            font-size: 1.05em !important;
        }
    `;
    document.head.appendChild(styleFix);
}

// HÀM TỰ ĐỘNG THÊM NHẮC NHỞ PHONG ẤN CHO GIAO DIỆN
function applySealWarningToUI() {
    // Nếu không có mảng dataBloodlines thì bỏ qua
    if (typeof dataBloodlines === 'undefined' || !Array.isArray(dataBloodlines)) return;

    dataBloodlines.forEach(bl => {
        let isOverpowered = false;

        // Hàm đệ quy kiểm tra xem có bất kỳ chỉ số nào >= 1000 không
        const checkOverpowered = (obj) => {
            for (let key in obj) {
                // Kiểm tra nếu là số lớn hơn hoặc bằng 1000
                if (typeof obj[key] === 'number' && obj[key] >= 1000) {
                    isOverpowered = true;
                } else if (typeof obj[key] === 'object' && obj[key] !== null) {
                    checkOverpowered(obj[key]);
                }
            }
        };

        checkOverpowered(bl);

        // Nếu phát hiện sức mạnh > 1000 và mô tả chưa có cảnh báo phong ấn
        if (isOverpowered) {
            let descField = bl.desc ? 'desc' : (bl.description ? 'description' : null);

            if (descField && !bl[descField].includes("Phong Ấn") && !bl[descField].includes("phong ấn")) {
                let warningText = "\n\n[⚠️ CẢNH BÁO] Năng lượng huyết mạch vượt ngưỡng chịu đựng. Tự động kích hoạt [Phong Ấn]. Tạm thời phong ấn phần lớn chỉ số để tránh sụp đổ cơ thể, sẽ giải trừ dần theo Cảnh giới.";

                // Nối trực tiếp vào mô tả gốc
                bl[descField] += warningText;
            }
        }
