];

function getWeightedElement(mode = 'normal') {
    // 1. Chế độ Roll Kỹ Năng (Skill)
    if (mode === 'skill') {
        const chance = Math.random() * 100; // Random 0 - 100

        // Tỷ lệ 1% ra hệ hiếm (Bạn có thể chỉnh số 1.0 thành thấp hơn nếu muốn khó hơn)
        if (chance < 1.0) {
            const rareEl = rareElementsList[Math.floor(Math.random() * rareElementsList.length)];
            return { 
                name: rareEl.name, 
                class: rareEl.class, 
                desc: rareEl.desc,
                isRare: true // Đánh dấu là hệ hiếm
            };
        }
    }

    // 2. Chế độ Bình thường (Hệ Bản Mệnh) HOẶC Trượt 1% của Skill
    // Logic: Luôn trả về hệ thường
    const commonName = commonElementsList[Math.floor(Math.random() * commonElementsList.length)];

    // Tìm mô tả trong dataElementsInfo (nếu có)
    let desc = "Sức mạnh nguyên tố cơ bản.";
    if (typeof dataElementsInfo !== 'undefined') {
        const found = dataElementsInfo.find(e => e.name === commonName);
        if (found) desc = found.desc;
    }

    // Lấy màu sắc (CSS)
    let cssClass = "";
    if (typeof getElementClass === 'function') {
        cssClass = getElementClass(commonName).text;
    }

    return { 
        name: commonName, 
        class: cssClass, 
        desc: desc,
        isRare: false
    };
}

function calculateTotalStats() {
    // 1. Khởi tạo chỉ số gốc
    let total = { 
        STR: 10, CON: 10, AGI: 10, SPI: 10, INT: 10, BLD: 0, 
        DEF: 0, Luck: 1, 
        HP_max: 100, MP_max: 50 
    };

    // 2. Xác định Vai Trò & Cảnh Giới để lấy Base Stats
    const role = document.getElementById('char-role').value;
    let rankVal = "Man Thú";

    if (role === 'Tamer') {
        rankVal = document.getElementById('tamer-rank').value;
    } else {
        rankVal = document.getElementById('beast-self-rank').value;
    }

    if (typeof DB_RANK_STATS !== 'undefined' && DB_RANK_STATS[rankVal]) {
        const base = DB_RANK_STATS[rankVal];
        total.STR = base.STR; total.CON = base.CON; total.AGI = base.AGI;
        total.SPI = base.SPI; total.INT = base.INT; total.BLD = base.BLD;
        total.DEF = base.DEF; total.HP_max = base.HP; total.MP_max = base.MP;
    }

    // --- HÀM CỘNG CHỈ SỐ (HELPER) ---

    // Loại 1: Cộng từ Input Roll (Có data-obj)
    const addModifiers = (inputId) => {
        const el = document.getElementById(inputId);
        if (!el) return;
        const rawJson = el.getAttribute('data-obj'); 
        if (!rawJson) return;
        try {
            const data = JSON.parse(decodeURIComponent(rawJson));
            applyMods(data.mods);
        } catch (e) { console.error("Lỗi đọc chỉ số input:", e); }
    };

    // [MỚI] Loại 2: Cộng từ Dropdown Select (Tra cứu từ danh sách gốc)
    const addFromDropdown = (selectId, sourceArray) => {
        const el = document.getElementById(selectId);
        if (!el) return;
        const val = el.value;
        // Tìm item trong danh sách gốc
        const item = sourceArray.find(i => i.name === val);
        if (item && item.mods) {
            applyMods(item.mods);
        }
    };

    // Hàm cộng toán học chung
    const applyMods = (mods) => {
        if (!mods) return;
        if (mods.STR) total.STR += mods.STR;
        if (mods.AGI) total.AGI += mods.AGI;
        if (mods.CON) total.CON += mods.CON;
        if (mods.INT) total.INT += mods.INT;
        if (mods.SPI) total.SPI += mods.SPI;
        if (mods.DEF) total.DEF += mods.DEF;
        if (mods.BLD) total.BLD += mods.BLD;
        if (mods.Luck) total.Luck += mods.Luck;
        if (mods.HP) total.HP_max += mods.HP;
        if (mods.MP) total.MP_max += mods.MP;
    };

    // 3. THỰC HIỆN CỘNG DỒN

    if (role === 'Tamer') {
        addModifiers('tamer-talent'); // Thiên phú

        // [MỚI] Cộng Nghề & Địa điểm cho Tamer
        addFromDropdown('char-profession', dataProfessionsTamer);
        addFromDropdown('char-location', dataLocationsTamer);

    } else {
        addModifiers('beast-species'); // Chủng tộc
        addModifiers('beast-bloodline'); // Huyết mạch

        // [MỚI] Cộng Nghề & Địa điểm cho Beast
        addFromDropdown('char-profession', dataProfessionsBeast); // Beast dùng chung ID char-profession nhưng data khác
        addFromDropdown('char-location', dataLocationsBeast);
    }

    // Cộng chung (Trang bị/Vật phẩm)
    addModifiers('start-equip');
    addModifiers('start-equip-2');
    addModifiers('start-equip-3');

    addModifiers('start-item');
    addModifiers('start-item-2');
    addModifiers('start-item-3');

    // 4. Cập nhật UI
    const updateUI = (id, val) => {
        const el = document.getElementById(id);
        if (el) el.innerText = Math.floor(val).toLocaleString();
    };

    updateUI('val-str', total.STR);
    updateUI('val-agi', total.AGI);
    updateUI('val-int', total.INT);
    updateUI('val-con', total.CON);
    updateUI('val-spi', total.SPI);
    updateUI('val-def', total.DEF);
    updateUI('val-bld', total.BLD);
    updateUI('val-luck', total.Luck);
    updateUI('val-hp', total.HP_max);
    updateUI('val-mp', total.MP_max);

    // 5. Lưu kết quả
    const finalJsonInput = document.getElementById('final-stats-json');
    if (finalJsonInput) {
        finalJsonInput.value = JSON.stringify(total);
    }
    console.log("Stats updated:", total);
}

    // --- HÀM PHỤ TRỢ: LẤY NGẪU NHIÊN CÁC HỆ THƯỜNG (KHÔNG TRÙNG LẶP) ---
function pickRandomCommonElements(count) {
    let results = [];

    // 1. Tạo bản sao của danh sách hệ thường để thao tác (tránh làm hỏng danh sách gốc)
    // listCommonElements là biến toàn cục đã khai báo ở trên đầu file
    let pool = [...listCommonElements]; 

    for (let k = 0; k < count; k++) {
        // Nếu hồ chứa hết hệ để chọn thì dừng lại (tránh lỗi vòng lặp)
        if (pool.length === 0) break;

        // 2. Random một vị trí bất kỳ trong pool
        let randomIndex = Math.floor(Math.random() * pool.length);
        let name = pool[randomIndex];

        // 3. Xóa hệ vừa chọn ra khỏi pool (để vòng lặp sau không chọn trúng nữa)
        pool.splice(randomIndex, 1);

        // 4. Tìm thông tin mô tả và màu sắc của hệ đó
        let info = typeof dataElementsInfo !== 'undefined' 
                   ? dataElementsInfo.find(e => e.name === name) 
                   : null;

        let clsObj = getElementClass(name); // Hàm lấy màu bạn đã có sẵn
        let cls = clsObj ? clsObj.text : "";

        // 5. Thêm vào kết quả
        results.push({ 
            name: name, 
            class: cls, 
            desc: info ? info.desc : "Sức mạnh nguyên tố cơ bản." 
        });
    }

    return results;
}

