            itemData = item; // [QUAN TRỌNG] Lưu object chứa 'mods' để tính toán
        }

        // Tự động tô màu nếu chưa có class màu
        if (!res.class && (targetId.includes('affinity') || type === 'element')) {
            let autoColor = getElementClass(realValue);
            if (autoColor.text) res.class = autoColor.text;
        }

        // --- BƯỚC SERIALIZE DỮ LIỆU ---
        // Mã hóa object thành chuỗi JSON để nhét vào HTML
        if (itemData) {
            let jsonStr = encodeURIComponent(JSON.stringify(itemData));
            extraAttr += ` data-obj="${jsonStr}"`;
        }

        extraAttr += ` data-desc="${tooltipText.replace(/"/g, "'")}"`;

        html += `
            <div class="roll-item" onclick="selectRollResult('${targetId}', '${realValue}', '${type}', this)" ${extraAttr}>
                <b class="${res.class}">${res.displayName}</b>
                ${res.sub || ''}
                <span class="tooltip-content">${tooltipText}</span>
            </div>`;
    }

    container.innerHTML = `<div style="font-size:0.8em; color:var(--text-dim); margin-bottom:4px; text-align:center;">▼ Chọn 1 kết quả ▼</div>` + html + `</div>`;
    container.classList.add('active');
}

// --- [FINAL V6 - BẤT HOẠI TRÊN MỌI NỀN TẢNG] HÀM HIỂN THỊ KẾT QUẢ ROLL CHI TIẾT ---
function selectRollResult(targetId, value, type, elementRef) {
    var input = document.getElementById(targetId);
    var container = document.getElementById(targetId + "-desc");
    if (!input) return;

    // 1. Xử lý tên hiển thị
    var displayName = value;
    if (type === 'race' || targetId.indexOf('species') !== -1) {
        displayName = value.replace(/^Dòng\s+/i, '');
    }
    input.value = displayName;

    // 2. Lấy dữ liệu gốc
    var dataObjRaw = elementRef.getAttribute('data-obj');
    if (dataObjRaw) {
        input.setAttribute('data-obj', dataObjRaw);
    }

    var colorElement = displayName;
    if (displayName.indexOf('&') !== -1) colorElement = displayName.split('&')[0].trim();
    if (typeof applyElementStyle === 'function') applyElementStyle(colorElement, targetId, targetId + "-desc");

    // 3. RENDER GIAO DIỆN CHI TIẾT
    if (container && dataObjRaw) {
        var obj = {};
        try { obj = JSON.parse(decodeURIComponent(dataObjRaw)); } catch(e) {}

        // --- SỬA Ở ĐÂY: Xử lý Rank an toàn hơn ---
        var rankName = obj.rank; // Không gán mặc định "Phàm Giai" nữa

        // Chỉ gán "Thường" cho nghề nghiệp hoặc địa điểm nếu không có rank
        if (!rankName && (type === 'profession' || type === 'location')) {
            rankName = "Thường";
        }

        // Chỉ lấy màu nếu rankName có tồn tại
        var rankColor = "#a0a0a0"; 
        if (rankName && typeof getRankColor === 'function') {
            rankColor = getRankColor(rankName);
        }

        var html = "";

        // --- HEADER ---
        html += '<div style="border-bottom: 1px dashed rgba(255,255,255,0.2); padding-bottom: 5px; margin-bottom: 8px; display:flex; justify-content:space-between; align-items:center;">';
        html += '<strong style="font-size:1.1em; color:var(--accent-gold); text-shadow:0 0 2px black;">' + (obj.name || displayName) + '</strong>';

        // SỬA TIẾP: Chỉ hiển thị khung Rank nếu rankName tồn tại (khác null/undefined) VÀ không phải là "Thường"
        if (rankName && rankName !== "Thường") {
            html += '<span style="font-size:0.8em; font-weight:bold; color:' + rankColor + '; border:1px solid ' + rankColor + '; padding:1px 5px; border-radius:4px; background:rgba(0,0,0,0.3);">' + rankName + '</span>';
        }
        html += '</div>';

        // --- BODY ---
        var modStr = [];
        if (obj.mods) {
            // Thay thế Object.entries bằng for...in truyền thống
            for (var k in obj.mods) {
                if (obj.mods.hasOwnProperty(k)) {
                    var v = obj.mods[k];
                    var color = v > 0 ? "#2ecc71" : "#e74c3c"; 
                    modStr.push(k + ' <span style="color:' + color + '">' + (v > 0 ? '+'+v : v) + '</span>');
                }
            }
        }

        if (type === 'talent') {
             html += '<div style="font-size:0.85em; margin-bottom:6px;">';
             html += '<div style="color:#e67e22;">🔥 Kích hoạt: <b>' + (obj.active_effect || "Bị động") + '</b></div>';
             if (obj.cost && obj.cost.value > 0) {
                 html += '<div style="color:#e74c3c;">🩸 Trả giá: ' + obj.cost.value + ' ' + (obj.cost.type || 'Sinh Lực') + '</div>';
             }
             html += '</div>';
             if (modStr.length > 0) html += '<div style="font-size:0.8em; color:#aaa; margin-bottom:5px;">(Buff: ' + modStr.join(', ') + ')</div>';
        } 
        else if (type === 'skill') {
            var elClass = (obj.elements && obj.elements.length > 0 && typeof getElementClass === 'function') 
                          ? getElementClass(obj.elements[0]).text : "";

            // Xóa sạch ?. (Optional Chaining) thay bằng logic gán an toàn
            var cVal = obj.cost ? obj.cost.value : 0;
            var cType = obj.cost ? obj.cost.type : 'MP';
            var cdDisp = obj.cooldown ? obj.cooldown.display_text : 'N/A';
            var isInst = obj.cast_time ? obj.cast_time.is_instant : true;
            var castDisp = isInst ? 'Tức thì' : ((obj.cast_time ? obj.cast_time.value : 0) + ' ' + (obj.cast_time ? obj.cast_time.unit : ''));
            var rType = obj.range_type || 'Cận chiến';
            var elText = (obj.elements && obj.elements.length > 0) ? obj.elements.join(', ') : 'Vô Hệ';

            html += '<div style="display:grid; grid-template-columns: 1fr 1fr; gap: 4px; font-size: 0.85em; margin-bottom: 8px; color:#bbb;">';
            html += '<div>⚡ Cost: <span style="color:#3498db;">' + cVal + ' ' + cType + '</span></div>';
            html += '<div>⏳ CD: <span style="color:#f1c40f;">' + cdDisp + '</span></div>';
            html += '<div>⏱️ Cast: <span style="color:#e67e22;">' + castDisp + '</span></div>';
            html += '<div>🎯 Range: <span>' + rType + '</span></div>';
            html += '<div style="grid-column: span 2;">🔥 Hệ: <span class="' + elClass + '">' + elText + '</span></div>';
            html += '</div>';
        }
        else {
            if (modStr.length > 0) {
                html += '<div style="font-size:0.85em; color:#ddd; margin-bottom:8px; background:rgba(255,255,255,0.05); padding:4px; border-radius:3px;">';
                html += '📊 <b>Chỉ số:</b> ' + modStr.join(' | ');
                html += '</div>';
            }
            if (type === 'race' && obj.potential_grade) {
                 html += '<div style="font-size:0.85em; color:#aaa; margin-bottom:5px;">⭐ Tiềm lực gốc: <b style="color:var(--accent-purple)">' + obj.potential_grade + '</b></div>';
            }
        }

        // --- FOOTER ---
        var finalDesc = obj.desc || elementRef.getAttribute('data-desc') || "Không có mô tả.";
        finalDesc = finalDesc.replace(/⚠️ CẢNH BÁO:/g, '<br><strong style="color:#e74c3c; background:rgba(255,0,0,0.1); padding:2px;">⚠️ PHONG ẤN:</strong>');

        html += '<div style="background:rgba(0,0,0,0.3); padding:8px; border-radius:4px; font-size:0.9em; line-height:1.4; color:var(--text-dim); font-style:italic; border-left: 2px solid var(--accent-gold);">';
        html += finalDesc;
        html += '</div>';

        container.innerHTML = html;
        container.classList.add('active');

    } else {
        if (container) {
            var descRaw = elementRef.getAttribute('data-desc');
            container.innerHTML = descRaw;
            container.classList.add('active');
        }
    }
}

