    // Đưa hàm rollStatsLimited ra ngoài thành hàm độc lập
    function rollStatsLimited() {

        if (!checkCanRoll('limit-stats')) return;

        // 1. Xác định Role và Rank để lấy Base Stats
        const role = document.getElementById('char-role').value;
        let rankVal = "Man Thú";

        if (role === 'Tamer') {
            // Nếu là Tamer, ta Roll stats cho PET (Sủng thú)
            const el = document.getElementById('pet-rank');
            if (el) rankVal = el.value;
