        }

        // 2. Random dao động 85% - 115%
        const base = DB_RANK_STATS[rankVal] || DB_RANK_STATS["Man Thú"];
        const rnd = (val) => {
            const min = Math.floor(val * 0.85);
            const max = Math.ceil(val * 1.15);
            return Math.floor(Math.random() * (max - min + 1)) + min;
        };

        const finalStats = {
            STR: rnd(base.STR), CON: rnd(base.CON), AGI: rnd(base.AGI),
            SPI: rnd(base.SPI), INT: rnd(base.INT), BLD: rnd(base.BLD),
            DEF: rnd(base.DEF), // [NEW] Thêm Phòng Thủ
            HP_max: rnd(base.HP), 
            MP_max: rnd(base.MP)
        };

        // 3. Hiển thị ra UI (Thêm ô DEF vào lưới)
