    // =====================================================================
    // HÀM TẠO LỆNH KHỞI TẠO (V5 FULL - FIX LỖI KÝ TỰ "|")
    // =====================================================================
    function generateStartCommand() {
        try {
            // =================================================================
            // 1. SAFE HELPERS (CÔNG CỤ XỬ LÝ CHUỖI AN TOÀN)
            // =================================================================

            // [QUAN TRỌNG] Hàm này sẽ tiêu diệt dấu "|" gây lỗi cắt chuỗi
            const safeStr = (str) => {
                if (!str) return "";
                return String(str)
                    .replace(/\|/g, " - ")  // <--- FIX CHÍNH: Đổi "|" thành "-"
                    .replace(/"/g, "'")     // Đổi ngoặc kép thành đơn để không vỡ JSON
                    .replace(/\n/g, "\\n")  // Giữ xuống dòng cho JSON
                    .replace(/\r/g, "");
            };

            const applyBloodlineSeal = (mods) => {
                if (!mods || Object.keys(mods).length === 0) return { newMods: {}, sealText: "", isSealed: false };
                let newMods = JSON.parse(JSON.stringify(mods)); 
                let warnings = [];
                let isSealed = false;
                for (let key in newMods) {
                    let val = newMods[key];
                    if (typeof val === 'number' && val >= 500) {
                        isSealed = true;
                        let original = val;
                        let sealed = val;
                        while (sealed >= 500) { sealed = Math.floor(sealed / 10); }
                        newMods[key] = sealed;
                        let percent = ((original - sealed) / original * 100);
                        warnings.push(`Giảm ${Number.isInteger(percent) ? percent : percent.toFixed(2)}% ${key} (${original} -> ${sealed})`);
                    }
                }
                return { newMods, sealText: warnings.length > 0 ? "⚠️ CẢNH BÁO PHONG ẤN: " + warnings.join(". ") : "", isSealed };
            };

            const getVal = (id, defaultVal = "Chưa xác định") => {
                const el = document.getElementById(id);
                // Áp dụng safeStr ngay khi lấy giá trị
                return (el && el.value && el.value.trim() !== "") ? safeStr(el.value.trim()) : defaultVal;
            };

            const getDesc = (id) => {
                const el = document.getElementById(id);
                if (!el || !el.innerText || el.innerText.trim() === "") return "";
                // Lọc rác và xử lý ký tự đặc biệt
                let rawText = el.innerText.replace(/\[.*?\]\s*:?/g, '').replace(/Phân loại:\s*/g, '').replace(/\[.*?:\s*\+\d+.*?\]/g, '').replace(/(⚡ Cost:|⏳ CD:|⏱️ Cast:|🎯 Range:|🔥 Hệ:).*?(?=\n|$)/g, '').replace(/\s+/g, ' ').trim();
                return safeStr(rawText); 
            };

            const getObj = (id) => {
                const el = document.getElementById(id);
                if (!el || !el.getAttribute('data-obj')) return null;
                try { 
                    let obj = JSON.parse(decodeURIComponent(el.getAttribute('data-obj'))); 
                    // Duyệt qua object để xử lý các trường text bên trong
                    if(obj.desc) obj.desc = safeStr(obj.desc);
                    if(obj.name) obj.name = safeStr(obj.name);
                    return obj;
                } catch (e) { return null; }
            };

            const getSkillEl = (id, defaultEl = "Vô Hệ") => {
                const el = document.getElementById(id);
                return el ? (el.getAttribute('data-real-element') || defaultEl) : defaultEl;
            };

            const TAG = { uvO: "<" + "UpdateVariable" + ">", uvC: "</" + "UpdateVariable" + ">", anO: "<" + "Analysis" + ">", anC: "</" + "Analysis" + ">", jpO: "<" + "JSONPatch" + ">", jpC: "</" + "JSONPatch" + ">" };

            // =================================================================
            // 2. THU THẬP THÔNG TIN CƠ BẢN
            // =================================================================
            let name = getVal('char-name', '{{user}}');
            let gender = getVal('char-gender', 'Nam');
            let role = getVal('char-role', 'Tamer');
