                        path: "/inventory/items/-", 
                        value: { 
                            uid: "it_" + Date.now() + "_" + index, // Thêm index để tránh trùng UID
                            name: startItemObj.name || itemVal, 
                            description: startItemObj.desc || getDesc(id + '-desc'), 
                            type: startItemObj.type || "Consumable", 
                            quantity: startItemObj.quantity || 1, 
                            stats_modifiers: startItemObj.mods || {}, 
                            rank_quality: startItemObj.rank_quality || startItemObj.rank || "Phàm Giai" 
                        }
                    });
                }
            });
            // =================================================================
            // 3. XỬ LÝ THEO VAI TRÒ (TAMER) - ĐẦY ĐỦ 4 NHÓM BIẾN V5
            // =================================================================
            if (role === 'Tamer') {
                let tRank = getVal('tamer-rank', 'Học Đồ');
                let tTalentObj = getObj('tamer-talent') || {}; 
                let tTalent = tTalentObj.name || getVal('tamer-talent', 'Chưa thức tỉnh');
                let tTalentDesc = tTalentObj.desc || getDesc('tamer-talent-desc');

                let tAffinityRaw = getVal('tamer-affinity', 'Vô Hệ');
                let tAffinityObj = getObj('tamer-affinity') || {};
                let spiritAffinityData = { base_elements: [], combined_effect: { name: tAffinityRaw, description: safeStr(tAffinityObj.desc || getDesc('tamer-affinity-desc')), stability: 100 }, weaknesses: [] };

                if (tAffinityObj.elements && Array.isArray(tAffinityObj.elements)) {
                    let dom = Math.floor(100 / tAffinityObj.elements.length);
                    spiritAffinityData.base_elements = tAffinityObj.elements.map(e => ({ type: e.name, description: safeStr(e.desc || "Hệ bẩm sinh"), dominance: dom }));
                } else {
                    spiritAffinityData.base_elements.push({ type: tAffinityRaw, description: "Hồn hỏa khởi đầu", dominance: 100 });
                }

                const raceData = getObj('pet-species') || {}; 
                const pBloodlineData = getObj('pet-bloodline') || {};
                const pSealResult = applyBloodlineSeal(pBloodlineData.mods || {});

                let pSpeciesRaw = raceData.race || getVal('pet-species', 'Chó Hoang');
                let pSpeciesClean = pSpeciesRaw.split(' (')[0].trim();
                let pBloodline = pBloodlineData.name || getVal('pet-bloodline', 'Không có'); 
                let pName = getVal('pet-name', 'Tiểu Hắc');
                let pGender = getVal('pet-gender', 'Vô Tính');
                let pElement = getVal('pet-element', 'Vô hệ');
                let pRank = getVal('pet-rank', 'Nô Bộc');

                // [V5] Tạo Object Species Info
                let pSpeciesInfo = {
                    name: pSpeciesClean,
                    type_class: raceData.type || "Thú",
                    description_lore: safeStr(raceData.desc || getDesc('pet-species-desc') || "Không có mô tả chi tiết."),
                    biological_features: raceData.features || ["Hoang dã"]
                };

                // [V5] Tạo Object Bloodline Info
                let pBloodlineInfo = {
                    name: pBloodline,
                    description_lore: safeStr(pBloodlineData.desc || "Huyết mạch chưa thức tỉnh hoàn toàn."),
                    rank_quality: pBloodlineData.rank || "Phàm Giai",
                    stats_modifiers: pSealResult.newMods || {}
                };

                // Hiển thị ra màn hình (Display Part) - Phần này dùng \n để đẹp
                displayPart += `**Định Danh:** ${name} (${age} tuổi - ${gender}) - **Vai Trò:** Ngự Thú Sư\n`;
                displayPart += `**Hồn Hỏa:** ${tAffinityRaw}\n> *${tAffinityObj.desc || getDesc('tamer-affinity-desc')}*\n`;
                displayPart += `**Thiên Phú:** ${tTalent}\n> *${tTalentDesc.replace(/\\n/g, '\n')}*\n`;
                displayPart += `**Xuất Phát:** ${locName} - ${profName}\n\n`;
                displayPart += `**--- SỦNG THÚ KHỞI ĐẦU ---**\n**Tên:** ${pName} (${pGender}) - **Loài:** ${pSpeciesClean}\n**Huyết Mạch:** ${pBloodline} (${pElement}) - **Cấp:** ${pRank}\n`;
                if (pSealResult.sealText) displayPart += `> ${pSealResult.sealText}\n`;

                let arraySkills = [];
                let displaySkills = [];
                if (raceData.default_skills && Array.isArray(raceData.default_skills)) {
                    raceData.default_skills.forEach((defSkill, i) => {
                        let formattedSkill = Object.assign({}, defSkill, { uid: `innate_${Date.now()}_${i}`, mastery_level: 1, description: safeStr(defSkill.desc) });
                        arraySkills.push(formattedSkill);
                        displaySkills.push(`[Bẩm sinh] [${defSkill.name}]: ${defSkill.desc || ""}`);
                    });
                }
                ['pet-sk1', 'pet-sk2', 'pet-sk3'].forEach((id, index) => {
                    let sName = getVal(id, 'Trống');
                    if (sName !== 'Trống') {
                        let sObj = getObj(id) || {};
                        let realEl = getSkillEl(id, pElement);
                        let sDesc = sObj.desc || sObj.description || getDesc(id + '-desc');
                        arraySkills.push({
                            uid: `psk_${Date.now()}_${index}`, name: sName, rank_quality: sObj.rank || "Phàm Giai", description: safeStr(sDesc),
                            cost: sObj.cost || { type: "MP", value: 10 }, cooldown: sObj.cooldown || { value: 3, unit: "Lượt", display_text: "3 Lượt", is_instant: false },
                            cast_time: sObj.cast_time || { value: 0, unit: "Tức thì", is_instant: true }, elements: sObj.elements || [realEl.split('&')[0]],
                            range_type: sObj.range_type || "Cận chiến", combo_tag: sObj.combo_tag || "", mastery_level: 1
                        });
                        displaySkills.push(`${index + 1}. [${sName} - ${realEl}]: ${sDesc}`);
                    }
                });
                displayPart += `**Kỹ Năng:**\n` + (displaySkills.length > 0 ? displaySkills.join('\n') + `\n` : `(Chưa có)\n`);

                patches.push({ op: "replace", path: "/tamer/race_type", value: "Nhân Loại" });
                patches.push({ op: "replace", path: "/tamer/current_form", value: "Dạng Người" });
                patches.push({ op: "replace", path: "/tamer/species_root", value: "Nhân Tộc" });
                patches.push({ op: "replace", path: "/tamer/human_data/spirit_rank", value: tRank });
                patches.push({ op: "replace", path: "/tamer/human_data/spirit_power_current", value: 0 });
                patches.push({ op: "replace", path: "/tamer/human_data/spirit_power_max", value: 100 });
                patches.push({ op: "replace", path: "/tamer/human_data/spirit_affinity", value: spiritAffinityData });

                // [V5] Profession Info
                let professionObj = getObj('char-profession-obj') || {}; 
                patches.push({ op: "replace", path: "/tamer/human_data/profession", value: profName });
                patches.push({ op: "replace", path: "/tamer/human_data/profession_info", value: {
                    name: profName,
                    description_lore: safeStr(professionObj.desc || `Khởi đầu hành trình tại ${locName}.`),
                    stats_modifiers: professionObj.mods || {}
                }});

                // [V5] Soul Talent Info
                patches.push({ op: "replace", path: "/tamer/human_data/soul_talent", value: { 
                    name: tTalent, 
                    description_lore: safeStr(tTalentDesc), 
                    rank_quality: tTalentObj.rank || "Phàm Giai", 
                    active_effect: safeStr(tTalentObj.active_effect || "Tự động"), 
                    passive_effect: safeStr(tTalentDesc), 
                    activation_cost: tTalentObj.cost || { type: "None", value: 0 },
                    stats_modifiers: tTalentObj.mods || {} 
                }});

                patches.push({ op: "replace", path: "/tamer/human_data/soul_capacity/used", value: 1 });
                patches.push({ op: "replace", path: "/tamer/human_data/cultivation", value: { main_slot: { name: "Minh Tưởng Pháp Cơ Bản", rank_quality: "Phàm Giai", mastery_level: 1, current_exp: 0, max_exp: 100, cultivation_speed: 1.0, purity_bonus: 0, effect: "Tăng hồi MP." }, support_slots: [] }});

                let pElCount = pElement.split('&').length || 1;
                let stability = Math.max(10, 100 - (pElCount - 1) * 20);

// 1. Lấy Chỉ số Gốc của Sủng Thú dựa theo Cảnh Giới (Từ DB_RANK_STATS)
            let petBaseStats = typeof DB_RANK_STATS !== 'undefined' && DB_RANK_STATS[pRank] 
                                ? DB_RANK_STATS[pRank] 
                                : { STR: 10, CON: 10, AGI: 10, SPI: 10, INT: 10, BLD: 0, HP: 100, MP: 50, DEF: 0 };

            // 2. Lấy Bonus từ Chủng Tộc (Species)
            let raceMods = raceData.mods || {};

            // 3. Lấy Bonus từ Huyết Mạch (đã qua xử lý phong ấn)
            let bloodMods = pSealResult.newMods || {};

            // 4. CỘNG DỒN ĐỘC LẬP CHO SỦNG THÚ (Tuyệt đối không dính dáng đến rStats của Tamer)
            let pTotalHP = petBaseStats.HP + (raceMods.HP || raceMods.HP_max || 0) + (bloodMods.HP || bloodMods.HP_max || 0);
            let pTotalMP = petBaseStats.MP + (raceMods.MP || raceMods.MP_max || 0) + (bloodMods.MP || bloodMods.MP_max || 0);
            let pTotalSTR = petBaseStats.STR + (raceMods.STR || 0) + (bloodMods.STR || 0);
            let pTotalAGI = petBaseStats.AGI + (raceMods.AGI || 0) + (bloodMods.AGI || 0);
            let pTotalCON = petBaseStats.CON + (raceMods.CON || 0) + (bloodMods.CON || 0);
            let pTotalSPI = petBaseStats.SPI + (raceMods.SPI || 0) + (bloodMods.SPI || 0);
            let pTotalINT = petBaseStats.INT + (raceMods.INT || 0) + (bloodMods.INT || 0);
            let pTotalDEF = petBaseStats.DEF + (raceMods.DEF || 0) + (bloodMods.DEF || 0);
            let pTotalBLD = petBaseStats.BLD + (raceMods.BLD || 0) + (bloodMods.BLD || 0);

            let newPetObject = { 
                id: "pet_init_" + Date.now(), name: pName, species_name: pSpeciesClean, rank_tier: pRank, level: 1, bloodline_rank: "Phàm Giai", potential_grade: raceData.potential_grade || "F", gender: pGender, personality: "Trung thành", age: 1,

                // [V5] Gán Info vào Pet Object
                species_info: pSpeciesInfo,
                bloodline_info: pBloodlineInfo,

                // Gán đúng chỉ số đã được cộng dồn của riêng Sủng Thú
                stats: { HP: pTotalHP, MP: pTotalMP, STR: pTotalSTR, AGI: pTotalAGI, CON: pTotalCON, SPI: pTotalSPI, INT: pTotalINT, DEF: pTotalDEF, BLD: pTotalBLD },
                health_current: pTotalHP, 
                mp_current: pTotalMP,
                    stamina: { current: 100, max: 100 },
                    elemental_affinity: { base_elements: pElement.split('&').map(e => ({ type: e.trim(), description: "Hệ bẩm sinh", dominance: 100/pElCount })), weaknesses: [], combined_effect: { name: "Bản năng", description: "", stability: stability } },
                    genetic_stability: stability, bloodline_purity: 100, foundation_index: 1.0, bloodline_energy_current: 0, bloodline_energy_max: 250, breeding_status: "Sẵn sàng",
                    mutation_traits: [pBloodline], evolution_paths: [], ferocity: 0, predatory_instinct: 0, instinct_control: 100, wild_reputation: "Vô Danh",
                    combat_modifiers: { bloodline_activation_state: false, environmental_adaptation: 1.0, active_buffs_debuffs: pSealResult.isSealed ? [{ name: "Phong Ấn Huyết Mạch", type: "debuff", effect_description: "Chỉ số bị nén lại." }] : [] },
                    beast_skills: arraySkills, innate_skills: [], inventory: [], equipment_slots: { head: undefined, body: undefined, claw_weapon: undefined, core: undefined }, loyalty: 80, intimacy: 20
                };
                patches.push({ op: "add", path: "/beast_roster/-", value: newPetObject });
            } 
            // =================================================================
            // 4. XỬ LÝ THEO VAI TRÒ (BEAST MODE)
            // =================================================================
            else {
                let bRank = getVal('beast-self-rank', 'Nô Bộc');
                let bElement = getVal('beast-element', 'Vô hệ');
                let masterStatus = getVal('beast-master-status', 'Hoang Dã');

                const raceData = getObj('beast-species') || {};
                const bloodlineData = getObj('beast-bloodline') || {};
                const bSealResult = applyBloodlineSeal(bloodlineData.mods || {});

                let bSpeciesRaw = raceData.race || getVal('beast-species', 'Quái lạ');
                let bSpeciesClean = bSpeciesRaw.split(' (')[0].trim();
                let bBloodline = bloodlineData.name || getVal('beast-bloodline', 'Chưa thức tỉnh');

                // [V5] Info Beast
                let bSpeciesInfo = {
                    name: bSpeciesClean,
                    type_class: raceData.type || "Thú",
                    description_lore: safeStr(raceData.desc || getDesc('beast-species-desc') || "Không có mô tả chi tiết."),
                    biological_features: raceData.features || ["Hoang dã"]
                };

                // [V5] Info Bloodline
                let bBloodlineInfo = {
                    name: bBloodline,
                    description_lore: safeStr(bloodlineData.desc || "Huyết mạch bí ẩn."),
                    rank_quality: bloodlineData.rank || "Phàm Giai",
                    stats_modifiers: bSealResult.newMods || {}
                };

                displayPart += `{CẢNH BÁO: ${name} đang nhập vai DỊ THÚ (${bSpeciesClean}). TƯ DUY NHƯ LOÀI THÚ.}\n\n`;
                displayPart += `**Định Danh:** ${name} (${gender}) - **Giống Loài:** ${bSpeciesClean}\n> *${raceData.desc || getDesc('beast-species-desc')}*\n**Huyết Mạch:** ${bBloodline} - **Hệ:** ${bElement}\n`;
                if (bSealResult.sealText) displayPart += `> ${bSealResult.sealText}\n`;

                let arraySkills = [];
                let displaySkills = [];
                if (raceData.default_skills && Array.isArray(raceData.default_skills)) {
                    raceData.default_skills.forEach((defSkill, i) => {
                        let formattedSkill = Object.assign({}, defSkill, { uid: `innate_${Date.now()}_${i}`, mastery_level: 1, description: safeStr(defSkill.desc) });
                        arraySkills.push(formattedSkill);
                        displaySkills.push(`[Bẩm sinh] [${defSkill.name}]: ${defSkill.desc || ""}`);
                    });
                }
                ['beast-sk1', 'beast-sk2', 'beast-sk3'].forEach((id, index) => {
                    let sName = getVal(id, 'Trống');
                    if (sName !== 'Trống') {
                        let sObj = getObj(id) || {};
                        let realEl = getSkillEl(id, bElement);
                        let sDesc = sObj.desc || sObj.description || getDesc(id + '-desc');
                        arraySkills.push({
                            uid: `bsk_${Date.now()}_${index}`, name: sName, rank_quality: sObj.rank || "Phàm Giai", description: safeStr(sDesc),
                            cost: sObj.cost || { type: "MP", value: 10 }, cooldown: sObj.cooldown || { value: 3, unit: "Lượt", display_text: "3 Lượt" },
                            cast_time: sObj.cast_time || { value: 0, unit: "Tức thì", is_instant: true }, elements: sObj.elements || [realEl.split('&')[0]], range_type: sObj.range_type || "Cận chiến", combo_tag: sObj.combo_tag || "", mastery_level: 1
                        });
                        displaySkills.push(`${index + 1}. [${sName} - ${realEl}]: ${sDesc}`);
                    }
                });
                if (displaySkills.length > 0) displayPart += `**Kỹ Năng Bẩm Sinh:**\n` + displaySkills.join('\n') + `\n`;

                if (masterStatus === 'Có Chủ') {
                    displayPart += `\n**🔗 CHỦ NHÂN:** ${getVal('master-name')} - ${getVal('master-profession')}\n> *Cảnh giới: ${getVal('master-rank')}*\n`;
                } else {
                    displayPart += `\n**🌲 TRẠNG THÁI:** Hoang Dã (Tự Do)\n`;
                }

                patches.push({ op: "replace", path: "/tamer/race_type", value: "Dị Thú" });
                patches.push({ op: "replace", path: "/tamer/role_mode", value: (masterStatus === 'Có Chủ') ? 'Pet' : 'Beast' });
                patches.push({ op: "replace", path: "/tamer/current_form", value: "Beast_Mode" });
                patches.push({ op: "replace", path: "/tamer/species_root", value: bSpeciesClean });
                patches.push({ op: "replace", path: "/tamer/potential_quality", value: raceData.potential_grade || "F" });

                patches.push({ op: "replace", path: "/tamer/beast_data", value: {
                    rank_tier: bRank, level: 1, bloodline_rank: bloodlineData.rank || "Phàm Giai",

                    // [V5] Gán Info vào Beast Data
                    species_info: bSpeciesInfo,
                    bloodline_info: bBloodlineInfo,

                    bloodline_energy: 0, bloodline_energy_current: 0, bloodline_energy_max: 250, foundation_index: 1.0,
                    ferocity: 0, predatory_instinct: 0, instinct_control: 100, mutation_features: [], innate_skills: arraySkills, wild_reputation: "Vô Danh",
                    bloodline_mutation: { bloodline_name: bBloodline, mutation_type: "Gốc", awakening_percent: 10 }
                }});

                if (bSealResult.isSealed) {
                    patches.push({ op: "replace", path: "/tamer/stats", value: { HP_current: bSealResult.newMods.HP_max || rStats.HP_max, HP_max: bSealResult.newMods.HP_max || rStats.HP_max, MP_current: bSealResult.newMods.MP_max || rStats.MP_max, MP_max: bSealResult.newMods.MP_max || rStats.MP_max, STR: bSealResult.newMods.STR || rStats.STR, AGI: bSealResult.newMods.AGI || rStats.AGI, CON: bSealResult.newMods.CON || rStats.CON, SPI: bSealResult.newMods.SPI || rStats.SPI, INT: bSealResult.newMods.INT || rStats.INT, DEF: bSealResult.newMods.DEF || rStats.DEF || 0, BLD: bSealResult.newMods.BLD || rStats.BLD || 0, sanity: 100, infection_rate: 0, luck: rStats.Luck }});
                    patches.push({ op: "add", path: "/tamer/combat_modifiers/active_buffs_debuffs/-", value: { name: "Phong Ấn Huyết Mạch", type: "debuff", effect_description: "Chỉ số bị nén lại." }});
                }
                patches.push({ op: "replace", path: "/tamer/master_bond", value: { contract_type: (masterStatus === 'Có Chủ') ? 'Chủ Tớ' : 'Vô Chủ', master_id: (masterStatus === 'Có Chủ') ? "npc_master" : "none", master_name: (masterStatus === 'Có Chủ') ? getVal('master-name') : "Chưa có", master_rank: (masterStatus === 'Có Chủ') ? getVal('master-rank') : "N/A", master_personality: "Chưa rõ", binding_level: (masterStatus === 'Có Chủ') ? 50 : 0, trust_level: (masterStatus === 'Có Chủ') ? 50 : 0, favorability: 0, is_abandoned: false, affinity_level_description: "Người Lạ" }});
                patches.push({ op: "replace", path: "/tamer/obedience_stats", value: { loyalty: 50, fear: 0, intimacy: 0 }});
            }

            // =================================================================
            // 5. EXPORT - FULL CONTENT (Không nén)
            // =================================================================

            // Format JSON đẹp mắt (indent 2) như V4 bạn yêu cầu
            let variablePart = TAG.uvO + "\n" + TAG.anO + "\nInitializing character: " + name + " (" + role + "). Applying V5 Schema updates (Full).\n" + TAG.anC + "\n";
            variablePart += TAG.jpO + "\n" + JSON.stringify(patches, null, 2) + "\n" + TAG.jpC + "\n" + TAG.uvC;

            let finalOut = displayPart + `\n*...Minh Kính kích hoạt. Dữ liệu nạp vào lõi. Thế giới bắt đầu diễn hóa...*\n\n` + variablePart;

            if (typeof triggerSlash === 'function' && typeof getCurrentMessageId === 'function') {
                triggerSlash(finalOut);
                const currentMsgId = getCurrentMessageId();
                setTimeout(() => triggerSlash(`/cut ${currentMsgId}`), 2000);
            } else {
                console.log("--- MINH KÍNH V5 FULL SAFE COMMAND ---");
                console.log(finalOut);
                alert("Đã tạo lệnh V5 Full! Hãy kiểm tra Console (F12).");
            }
        } catch (error) {
            console.error("LỖI KHI TẠO LỆNH:", error);
            alert("Lỗi khi tạo lệnh: " + error.message);
        }
    }
</script>
</body>
</html>
