        background: linear-gradient(180deg, rgba(226, 183, 100, 0.1) 0%, rgba(0,0,0,0) 100%); 
    }
    .tamer-name { font-size: 1.5em; font-weight: 700; color: var(--theme-gold); text-transform: uppercase; letter-spacing: 1.5px; text-shadow: 0 0 10px var(--theme-gold-glow);}
    .tamer-sub { font-size: 0.9em; color: var(--text-dim); font-weight: 600; margin-top: 4px; }
    .system-title-text { font-size: 0.8em; letter-spacing: 2px; color: var(--theme-gold); font-weight: 700; text-align: right;}
    .system-energy { font-family: 'JetBrains Mono', monospace; font-size: 1.1em; font-weight: bold; margin-top: 4px; color: var(--accent-warm); text-align: right;}

    /* ==========================================================================
       3. KHỐI LINH CHÂU (ORBS) - KHÔI PHỤC PHẲNG GỐC, BỎ SÁNG LẤP LÁNH
       ========================================================================== */
    .bars-grid { 
        padding: 20px; 
        display: grid; grid-template-columns: repeat(4, 1fr); 
        gap: 15px; justify-items: center;
        background: rgba(0,0,0,0.2); border-bottom: 1px solid var(--border-light);
    }
    .stat-orb { 
        display: flex; flex-direction: column; align-items: center; cursor: help; 
    }
    .orb-container { position: relative; width: 80px; height: 80px; }
    .orb-svg { transform: rotate(-90deg); width: 100%; height: 100%; }
    .orb-track { fill: none; stroke: rgba(255,255,255,0.05); stroke-width: 8; }
    .orb-progress { 
        fill: none; stroke-width: 8; stroke-linecap: round; 
        stroke-dasharray: 251.3; stroke-dashoffset: 251.3; 
        transition: stroke-dashoffset 1s cubic-bezier(0.4, 0, 0.2, 1);
    }
    .orb-text {
        position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%);
        text-align: center; display: flex; flex-direction: column; align-items: center; width: 100%;
    }
    .orb-val { font-family: 'JetBrains Mono'; font-weight: 700; font-size: 1.2em; color: var(--text-main); }
    .orb-label { font-size: 0.7em; font-weight: 700; color: var(--text-dim); margin-top: 2px; text-transform: uppercase; letter-spacing: 1px;}

    .progress-track-bar { height: 8px; background: rgba(0,0,0,0.5); border: 1px solid rgba(255,255,255,0.1); border-radius: 6px; overflow: hidden; }
    .progress-fill-bar { height: 100%; width: 0%; transition: width 0.5s ease; border-radius: 4px; }

    /* ==========================================================================
       4. ĐIỀU HƯỚNG TABS
       ========================================================================== */
    .nav-tabs { 
        display: flex; flex-wrap: wrap; justify-content: center; gap: 8px;
        background: rgba(0,0,0,0.3); border-bottom: 1px solid var(--theme-gold-dim); 
        padding: 12px 15px; flex-shrink: 0; 
    }
    .tab-btn { 
        padding: 8px 16px; background: rgba(255,255,255,0.05); border: 1px solid var(--border-light); 
        color: var(--text-dim); font-family: 'Quicksand', sans-serif; font-weight: 700; 
        cursor: pointer; transition: all 0.3s; font-size: 0.85em; 
        border-radius: 20px; text-transform: uppercase; letter-spacing: 1px;
    }
    .tab-btn:hover { background: rgba(226, 183, 100, 0.1); color: var(--text-main); border-color: rgba(226, 183, 100, 0.3); }
    .tab-btn.active { 
        background: var(--theme-gold-glow); border-color: var(--theme-gold); color: var(--theme-gold); 
        box-shadow: 0 0 10px rgba(226, 183, 100, 0.2); 
    }

    /* ==========================================================================
       5. CARDS & THÔNG TIN CHUNG (LAYOUT GỐC)
       ========================================================================== */
    .tab-content { padding: 20px; flex-grow: 1; overflow-y: auto; }
    .hidden { display: none; }
    .data-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 15px; }

    .info-card { 
        background: var(--bg-card); border: 1px solid var(--border-light); 
        padding: 15px; border-radius: 8px; position: relative; 
        box-shadow: 0 4px 15px rgba(0,0,0,0.2);
    }
    .info-card::before { content: ''; position: absolute; top: 15px; left: 0; width: 4px; height: calc(100% - 30px); background: var(--theme-gold); border-radius: 0 4px 4px 0; opacity: 0.7; }
    .info-card h4 { margin: 0 0 12px 10px; font-size: 1.05em; color: var(--theme-gold); font-weight: 700; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px dashed rgba(226, 183, 100, 0.3); padding-bottom: 6px; }

    .attr-row { display: flex; justify-content: space-between; align-items: baseline; font-size: 0.95em; margin-bottom: 8px; color: var(--text-dim); border-bottom: 1px solid rgba(255,255,255,0.03); padding-bottom: 4px;}
    .attr-row:last-child { border-bottom: none; }
    .attr-row > span:first-child { color: var(--text-dim); font-weight: 600; padding-left: 10px; }
    .attr-val { color: var(--text-main); font-weight: 700; text-align: right; max-width: 60%; word-wrap: break-word; font-family: 'Quicksand', sans-serif;}

    /* DETAILS/SUMMARY (THẺ MỞ RỘNG MÔ TẢ) */
    details { background: rgba(0,0,0,0.2); border: 1px solid var(--border-light); border-radius: 6px; margin-top: 8px; padding: 8px 10px; transition: background 0.3s; margin-left: 10px;}
    details:hover { background: rgba(255,255,255,0.03); }
    summary { cursor: pointer; color: var(--theme-gold); font-size: 0.9em; font-weight: 700; outline: none; list-style: none; display: flex; align-items: center; }
    summary::-webkit-details-marker { display: none; }
    summary::before { content: '▼'; display: inline-block; margin-right: 8px; font-size: 0.8em; transition: transform 0.2s; color: var(--text-muted); transform: rotate(-90deg);}
    details[open] summary::before { transform: rotate(0deg); color: var(--theme-gold); }
    details > div { padding-top: 10px; border-top: 1px dashed rgba(255,255,255,0.1); margin-top: 8px; color: var(--text-dim); font-size: 0.9em; white-space: pre-wrap; line-height: 1.5; }

    /* ==========================================================================
       6. KHU VỰC THIẾT KẾ ĐẶC BIỆT MỚI (TRANG BỊ DROPDOWN & GENETICS)
       ========================================================================== */

    /* Box Trang bị lồng nhau giống luanhoii.html */
    .equip-grid-container { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
    .equip-slot-wrapper { display: flex; flex-direction: column; margin-bottom: 5px; }
    .equip-slot { 
        background: rgba(42, 42, 42, 0.8); padding: 8px 10px; border-radius: 4px; 
        display: flex; align-items: center; gap: 10px; border: 1px solid #3d3d3d; 
        cursor: pointer; transition: all 0.2s; 
    }
    .equip-slot:hover { background: #333; border-color: var(--theme-gold-dim); }
    .equip-slot[data-has="true"] { border-left: 3px solid var(--theme-gold); }
    .slot-label { 
        font-size: 10px; color: #95a5a6; width: 65px; text-align: center; 
        background: #1a1a1a; padding: 4px 2px; border-radius: 4px; font-weight: bold; text-transform: uppercase; 
    }
    .equip-name { font-size: 12px; font-weight: 700; flex: 1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
    .equip-toggle-icon { font-size: 10px; color: #555; transition: transform 0.3s; }
    .equip-slot.open .equip-toggle-icon { transform: rotate(180deg); color: var(--theme-gold); }

    /* Khung rớt xuống khi click trang bị */
    .item-detail-panel { 
        background: #1c1c1c; border: 1px solid #444; border-top: none; 
        padding: 12px; margin-top: -2px; margin-bottom: 5px; border-radius: 0 0 6px 6px; 
        display: none; font-size: 12px; position: relative; z-index: 10; 
    }
    .detail-header { display: flex; justify-content: space-between; border-bottom: 1px dashed #444; padding-bottom: 6px; margin-bottom: 6px; font-weight: bold; font-size: 1.1em; }
    .detail-stats-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 5px; margin-bottom: 8px; }
    .detail-stat-row { background: #252525; padding: 4px 6px; border-radius: 4px; display: flex; justify-content: space-between; font-size: 11px; }
    .detail-stat-label { color: #7f8c8d; }
    .detail-stat-val { color: var(--accent-warm); font-weight: bold; font-family: 'JetBrains Mono';}
    .detail-desc { color: #95a5a6; font-style: italic; line-height: 1.5; padding: 8px; background: rgba(0,0,0,0.3); border-left: 2px solid #555; }

    /* Box Kỹ Năng / Gen / Combat */
    .skill-list { display: flex; flex-direction: column; gap: 8px; margin-top: 6px; }
    .skill-item { padding: 0 0 0 10px; border-left: 2px solid var(--theme-gold-dim); }
    .skill-head { display: flex; align-items: center; gap: 8px; flex-wrap: wrap; margin-bottom: 2px;}
    .skill-name { font-weight: 700; color: var(--theme-gold); font-size: 0.95em; }
    .skill-meta { font-size: 0.75em; color: var(--text-dim); font-family: 'JetBrains Mono', monospace; background: rgba(255,255,255,0.05); padding: 2px 6px; border-radius: 4px;}
    .skill-desc { font-size: 0.85em; color: var(--text-main); line-height: 1.4; }

    .gen-trait-box { background: rgba(0,0,0,0.2); padding: 8px 10px; border-radius: 4px; margin-bottom: 6px; font-size: 0.85em; border-left: 2px solid var(--accent-warm); }
    .gen-trait-title { font-weight: 700; color: var(--accent-warm); display: block; margin-bottom: 2px;}

    /* Bảng thú V2 (Beast Cards) */
    .beast-card-v2 {
        background: linear-gradient(145deg, rgba(40, 35, 30, 0.95) 0%, rgba(30, 25, 20, 0.95) 100%);
        border: 1px solid rgba(226, 183, 100, 0.2); border-radius: 8px; padding: 15px; margin-bottom: 15px; box-shadow: 0 4px 15px rgba(0,0,0,0.3); position: relative; overflow: hidden;
    }
    .beast-card-v2::before { content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 2px; background: linear-gradient(90deg, transparent, var(--theme-gold), transparent);}
    .bc-header { display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 12px; border-bottom: 1px solid var(--border-light); padding-bottom: 10px; }
    .bc-name { font-size: 1.3em; font-weight: 700; color: var(--theme-gold); }
    .bc-species { font-size: 0.8em; color: var(--text-dim); font-weight: 600; margin-left: 8px; padding: 2px 6px; background: rgba(255,255,255,0.03); border-radius: 4px; }
    .bc-rank { font-size: 0.9em; font-weight: 700; padding: 4px 10px; border-radius: 4px; background: rgba(211, 84, 0, 0.15); color: var(--rank-a); border: 1px solid rgba(211, 84, 0, 0.4); text-transform: uppercase;}

    .bc-stats-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; margin-bottom: 12px; }
    .bc-stat-box { background: rgba(0,0,0,0.3); border: 1px solid rgba(255,255,255,0.05); border-radius: 6px; padding: 8px; text-align: center; }
    .bc-stat-label { font-size: 0.7em; color: var(--text-muted); text-transform: uppercase; margin-bottom: 4px; font-weight: 700; }
    .bc-stat-value { font-size: 1.1em; font-weight: 700; color: var(--text-main); font-family: 'JetBrains Mono', monospace; }
    .bc-hp-bar-wrapper { margin-bottom: 15px; }
    .bc-hp-label { font-size: 0.85em; font-weight: 700; color: var(--text-main); display: flex; justify-content: space-between; margin-bottom: 4px;}

    /* Entities Thế Giới */
    .entity-item { margin: 0 0 10px 10px; border-left: 2px solid var(--theme-gold-dim); padding: 5px 0 5px 10px; background: rgba(255,255,255,0.02); border-radius: 0 4px 4px 0; }
    .travel-label { font-size: 0.85em; color: var(--theme-gold); display: flex; justify-content: space-between; font-weight: 700; margin-bottom: 4px;}

    /* INVENTORY */
    .inv-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; margin-left: 10px; }
    .inv-item { 
        background: rgba(0,0,0,0.4); border: 1px solid var(--border-light); 
        padding: 8px; font-size: 0.9em; font-weight: 600; border-radius: 4px; 
        white-space: nowrap; overflow: hidden; text-overflow: ellipsis; color: var(--text-main); 
        display: flex; justify-content: space-between;
    }
    .inv-item .qty { color: var(--theme-gold); font-family: 'JetBrains Mono', monospace; }

    /* QUALITY COLORS */
    .q-pham { color: var(--qual-pham) !important; border-color: var(--qual-pham) !important; }
    .q-thiet { color: var(--qual-thiet) !important; border-color: var(--qual-thiet) !important; }
    .q-ngan { color: var(--qual-ngan) !important; border-color: var(--qual-ngan) !important; }
    .q-kim { color: var(--qual-kim) !important; border-color: var(--qual-kim) !important; text-shadow: 0 0 5px rgba(241, 196, 15, 0.3); }
    .q-dieu { color: var(--qual-dieu) !important; border-color: var(--qual-dieu) !important; }
    .q-thanh { color: var(--qual-thanh) !important; border-color: var(--qual-thanh) !important; text-shadow: 0 0 8px rgba(231, 76, 60, 0.4); }
    .q-than { color: var(--qual-than) !important; border-color: var(--qual-than) !important; text-shadow: 0 0 10px rgba(230, 126, 34, 0.6); animation: pulse-gold 2s infinite; }
    .q-huyen { color: var(--qual-huyen) !important; text-shadow: 0 0 12px rgba(0, 255, 255, 0.7); animation: pulse-gold 2s infinite alternate;}

    @keyframes pulse-gold { 0% { opacity: 1; } 50% { opacity: 0.7; } 100% { opacity: 1; } }

    .footer-log { margin-top: auto; font-family: 'JetBrains Mono', monospace; font-size: 0.85em; color: var(--text-muted); padding: 8px 20px; background: rgba(0, 0, 0, 0.4); border-top: 1px solid var(--border-light); display: flex; align-items: center; gap: 10px; }
    .log-icon { width: 8px; height: 8px; background: var(--theme-gold); border-radius: 50%; box-shadow: 0 0 8px var(--theme-gold); animation: blink 2s infinite; }
    @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0.3; } }

    /* ==========================================================================
       MEDIA QUERIES - ĐIỆN THOẠI
       ========================================================================== */
    @media screen and (max-width: 600px) {
        body { padding: 5px; overflow-x: hidden; }
        .minh-kinh-container { border-radius: 0; border: none; width: 100% !important; max-width: 100vw !important; }
        .header-panel { padding: 10px; flex-direction: column; align-items: flex-start; gap: 5px; }
        .system-title-text { display: none; } 
        .tamer-name { font-size: 1.2em; }
        .system-energy { text-align: left; font-size: 0.9em; margin-top: 0; }
        .bars-grid { grid-template-columns: repeat(4, 1fr) !important; gap: 4px; padding: 15px 5px; }
        .orb-container { width: 18vw; height: 18vw; max-width: 70px; max-height: 70px; }
        .orb-val { font-size: 0.85em; }
        .orb-label { font-size: 0.55em; white-space: nowrap; }
        .nav-tabs { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; padding: 8px; }
        .tab-btn { padding: 10px 2px; font-size: 0.75em; text-align: center; width: 100%; border-radius: 8px; }
        .tab-btn:last-child { grid-column: span 2; }
        .tab-content { padding: 10px; }
        .data-grid { grid-template-columns: 1fr !important; display: block !important; }
        .info-card { width: 100%; margin-bottom: 15px; box-sizing: border-box; }
        .attr-row { font-size: 0.9em; }
        .attr-val { max-width: 55%; }
        .inv-grid { grid-template-columns: 1fr; }
        .equip-grid-container { grid-template-columns: 1fr; }
    }

/* ==========================================================================
       [CUSTOM TOOLTIP] - Sửa lỗi Tooltip không hiện
       ========================================================================== */
    .custom-tooltip {
        position: absolute;
        background: rgba(20, 15, 10, 0.95);
        color: var(--theme-gold);
        padding: 8px 12px;
        border: 1px solid var(--theme-gold);
        border-radius: 6px;
        font-family: 'JetBrains Mono', monospace;
        font-size: 0.9em;
        font-weight: bold;
        box-shadow: 0 4px 15px rgba(0,0,0,0.8), 0 0 10px rgba(226, 183, 100, 0.2);
        pointer-events: none; /* Rất quan trọng: Không cản trở chuột */
        opacity: 0;
        transition: opacity 0.2s ease;
        z-index: 9999;
        white-space: nowrap;
    }

/* Tìm và thêm dòng white-space vào các class này */
.detail-desc { 
    white-space: pre-wrap; /* Giữ nguyên xuống dòng */
    color: #95a5a6; 
    line-height: 1.5; 
    padding: 8px; 
    background: rgba(0,0,0,0.3); 
    border-left: 2px solid #555; 
}

.skill-desc { 
    white-space: pre-wrap; /* Giữ nguyên xuống dòng */
    font-size: 0.85em; 
    color: var(--text-main); 
    line-height: 1.4; 
}

/* --- SỬA BỐ CỤC DETAILS (ĐÓNG/MỞ) ĐẸP HƠN --- */
    details {
        background: rgba(0, 0, 0, 0.25);
        border: 1px solid var(--border-light);
        border-radius: 8px;
        margin-top: 10px;
        overflow: hidden; /* Bo tròn cả nội dung bên trong */
        transition: all 0.3s ease;
    }

    summary {
        padding: 10px 12px;
        background: rgba(255, 255, 255, 0.03);
        font-weight: 700;
        user-select: none;
        display: flex;
        justify-content: space-between;
        align-items: center;
    }

    summary:hover {
        background: rgba(226, 183, 100, 0.1);
    }

    details[open] summary {
        border-bottom: 1px solid var(--border-light);
        background: rgba(226, 183, 100, 0.05);
    }

    /* Nội dung bên trong khi mở ra */
    details > div {
        padding: 15px;
        background: rgba(0, 0, 0, 0.2);
        color: var(--text-dim);
        line-height: 1.6;
        border-top: none; /* Xóa viền cũ */
        margin-top: 0;    /* Xóa margin cũ */
    }

    /* --- SỬA BỐ CỤC CHỈ SỐ (SỐ DƯỚI TÊN) --- */
    .stat-grid-mini {
        display: grid; 
        grid-template-columns: repeat(4, 1fr) !important; /* 4 cột cho đều */
        gap: 10px; 
        margin-top: 15px; 
        background: rgba(0,0,0,0.25); 
        padding: 15px; 
        border-radius: 8px; 
        border: 1px solid var(--border-light);
    }

    .stat-box-vertical {
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        background: rgba(255,255,255,0.03);
        padding: 8px 4px;
        border-radius: 6px;
        border: 1px solid rgba(255,255,255,0.05);
    }

    .stat-label-v {
        font-size: 0.65em;
        text-transform: uppercase;
        color: var(--text-muted);
        font-weight: 700;
        margin-bottom: 4px;
        letter-spacing: 1px;
    }

    .stat-val-v {
        font-family: 'JetBrains Mono', monospace;
        font-size: 1.1em;
        font-weight: 700;
        color: var(--text-main);
    }

/* --- 1. SỬA GRID CHỈ SỐ: CÂN ĐỐI TUYỆT ĐỐI 4 CỘT --- */
    .stat-grid-perfect {
        display: grid;
        grid-template-columns: repeat(4, 1fr); /* 4 cột đều nhau */
        gap: 8px;
        margin-top: 15px;
        background: rgba(0,0,0,0.2);
        padding: 10px;
        border-radius: 8px;
        border: 1px solid var(--border-light);
    }

    /* Ô chỉ số thường */
    .stat-box-std {
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        background: rgba(255,255,255,0.03);
        padding: 8px 2px;
        border-radius: 4px;
        border: 1px solid rgba(255,255,255,0.05);
        height: 55px; /* Cố định chiều cao để đều tăm tắp */
    }

    /* Ô chỉ số Nổi Bật (Main Stat) */
    .stat-box-highlight {
        background: rgba(226, 183, 100, 0.08);
        border: 1px dashed var(--theme-gold);
        position: relative;
        overflow: hidden;
    }

    /* Hiệu ứng nền nhẹ cho ô nổi bật */
    .stat-box-highlight::after {
        content: '';
        position: absolute;
        top:0; left:0; width:100%; height:100%;
        background: linear-gradient(45deg, transparent, rgba(255,255,255,0.05), transparent);
        pointer-events: none;
    }

    /* --- 2. GIAO DIỆN KỸ NĂNG COMPACT (CARD STYLE) --- */
    .skill-container-grid {
        display: grid;
        grid-template-columns: 1fr; /* 1 cột danh sách dọc */
        gap: 8px;
        margin-top: 10px;
    }

    .skill-card {
        background: linear-gradient(90deg, rgba(0,0,0,0.4) 0%, rgba(0,0,0,0.2) 100%);
        border-left: 3px solid var(--border-color);
        border-radius: 0 4px 4px 0;
        padding: 8px 10px;
        position: relative;
    }

    .skill-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-bottom: 4px;
    }

    .skill-name {
        font-weight: 700;
        color: var(--text-main);
        font-size: 0.95em;
    }

    .skill-cost {
        font-family: 'JetBrains Mono';
        font-size: 0.75em;
        color: var(--accent-blue);
        background: rgba(52, 152, 219, 0.1);
        padding: 1px 5px;
        border-radius: 3px;
    }

    .skill-tags {
        display: flex;
        gap: 5px;
        margin-bottom: 6px;
    }

    .skill-badge {
        font-size: 0.65em;
        text-transform: uppercase;
        padding: 1px 4px;
        border-radius: 2px;
        background: rgba(255,255,255,0.1);
        color: #bbb;
    }

    .skill-desc-compact {
        font-size: 0.95em; /* Tăng từ 0.85 lên 0.95 cho to rõ */
        color: #e0e0e0;    /* Màu xám trắng sáng (Dễ đọc trên nền tối) */
        line-height: 1.5;
        text-align: justify;
        white-space: pre-wrap;
        margin-top: 6px;
        font-weight: 500;  /* Đậm hơn một chút */
    }

    /* Thêm class mới cho dòng thông số (CD/Cast) */
    .skill-meta-row {
        display: flex;
        gap: 10px;
        font-family: 'JetBrains Mono', monospace;
        font-size: 0.8em;
        color: var(--text-dim);
        margin-bottom: 4px;
        background: rgba(0,0,0,0.2);
        padding: 2px 6px;
        border-radius: 4px;
        width: fit-content;
    }

/* --- GRID 4x2 CÂN ĐỐI TUYỆT ĐỐI --- */
    .stat-grid-ocd {
        display: grid;
        grid-template-columns: repeat(4, 1fr); /* 4 cột bằng nhau */
        gap: 10px; /* Khoảng cách giữa các ô */
        margin-top: 15px;
        padding: 5px;
    }

    /* --- Ô CHỈ SỐ CAO CẤP (STAT CARD) --- */
    .stat-card-modern {
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;

        /* Giao diện khung */
        background: linear-gradient(145deg, rgba(255,255,255,0.03) 0%, rgba(0,0,0,0.4) 100%);
        border: 1px solid rgba(226, 183, 100, 0.15); /* Viền vàng nhạt mặc định */
        border-radius: 8px;
        padding: 10px 5px;
        height: 75px; /* Chiều cao cố định để đều nhau */
        position: relative;
        overflow: hidden;
        transition: all 0.2s ease;
    }

    /* Hiệu ứng Hover nhẹ */
    .stat-card-modern:hover {
        background: rgba(255,255,255,0.06);
        border-color: rgba(226, 183, 100, 0.3);
        transform: translateY(-2px);
    }

    /* Nhãn (Tên chỉ số) */
    .stat-label-modern {
        font-family: 'Quicksand', sans-serif;
        font-size: 0.65em;
        text-transform: uppercase;
        letter-spacing: 1px;
        color: var(--text-dim);
        font-weight: 700;
        margin-bottom: 4px;
        z-index: 1;
    }

    /* Giá trị (Số) */
    .stat-val-modern {
        font-family: 'JetBrains Mono', monospace;
        font-size: 1.4em; /* Số to rõ */
        font-weight: 800;
        color: var(--text-main);
        text-shadow: 0 2px 4px rgba(0,0,0,0.5);
        z-index: 1;
    }

    /* --- BIẾN THỂ CHO CHỈ SỐ ĐẶC BIỆT --- */

    /* Chỉ số Phụ (Màu xanh/đỏ nhạt) */
    .card-sub {
        background: rgba(255, 255, 255, 0.04);
        border: 1px dashed rgba(255, 255, 255, 0.2);
    }

    /* Chỉ số CHÍNH (Glow mạnh) */
    .card-main {
        border: 1px solid var(--theme-gold); /* Viền sáng */
        background: radial-gradient(circle at center, rgba(226, 183, 100, 0.1) 0%, rgba(0,0,0,0.6) 100%);
        box-shadow: 0 0 15px rgba(226, 183, 100, 0.1) inset; /* Đổ bóng trong */
    }

/* --- KHUNG CHỨA KỸ NĂNG CÓ THỂ ĐÓNG MỞ (ĐẸP) --- */
    details.skill-collapse {
        margin-top: 15px;
        background: transparent; /* Trong suốt để không bị viền xấu */
        border: none;
        padding: 0;
    }

    /* Thanh tiêu đề đóng mở (Giả làm Header) */
    summary.skill-header-styled {
        background: linear-gradient(90deg, rgba(226, 183, 100, 0.1) 0%, transparent 100%);
        padding: 8px 12px;
        border-radius: 4px;
        border-left: 3px solid var(--theme-gold);
        color: var(--theme-gold);
        font-weight: 800;
        text-transform: uppercase;
        letter-spacing: 1px;
        font-size: 0.9em;
        cursor: pointer;
        display: flex;
        justify-content: space-between;
        align-items: center;
        transition: all 0.3s ease;
        margin-bottom: 10px; /* Tạo khoảng cách với lưới kỹ năng bên dưới */
    }

    summary.skill-header-styled:hover {
        background: rgba(226, 183, 100, 0.2);
        padding-left: 20px; /* Hiệu ứng trượt nhẹ khi hover */
    }

    /* Ẩn tam giác mặc định xấu xí */
    summary.skill-header-styled::-webkit-details-marker { display: none; }
    summary.skill-header-styled::after { 
        content: '▼'; 
        font-size: 0.8em; 
        transition: transform 0.3s; 
    }
    details[open] summary.skill-header-styled::after { transform: rotate(180deg); }

    /* --- LƯỚI KỸ NĂNG (THOÁNG HƠN) --- */
    .skill-grid-compact {
        display: grid;
        /* Tự động co giãn: Nếu màn hình nhỏ thì 1 cột, lớn thì 2 cột */
        grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); 
        gap: 15px; /* Tăng khoảng cách giữa các thẻ cho đỡ dính */
        padding: 5px; /* Đệm một chút để không bị cắt bóng đổ */
    }

    /* --- THẺ KỸ NĂNG (RÕ KHỐI HƠN) --- */
    .skill-card-item {
        background: rgba(20, 20, 20, 0.6); /* Nền tối hơn để tách biệt */
        border: 1px solid rgba(255,255,255,0.08);
        border-left-width: 4px; /* Viền trái dày hơn để nhấn mạnh phẩm chất */
        border-radius: 6px;
        padding: 12px;
        display: flex;
        flex-direction: column;
        gap: 6px;
        box-shadow: 0 4px 10px rgba(0,0,0,0.3); /* Bóng đổ giúp nổi khối */
        transition: transform 0.2s;
    }

    .skill-card-item:hover {
        transform: translateY(-2px); /* Nổi lên khi di chuột */
        background: rgba(30, 30, 30, 0.8);
    }

    /* Header của thẻ kỹ năng */
    .skill-card-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        border-bottom: 1px dashed rgba(255,255,255,0.1);
        padding-bottom: 6px;
        margin-bottom: 4px;
    }

    .skill-name-text {
        font-weight: 700;
        font-size: 1em;
        text-shadow: 0 0 10px rgba(0,0,0,0.5);
    }

/* --- GIAO DIỆN KHÔNG GIAN TÚI (INVENTORY) --- */
details.inv-card-item {
    background: rgba(20, 20, 20, 0.6);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-left-width: 4px; /* Viền trái dày để nhấn mạnh phẩm chất */
    border-radius: 6px;
    margin-left: 0; /* Xóa thụt lề cũ */
    margin-bottom: 10px;
    transition: transform 0.2s ease, background 0.2s ease;
    overflow: hidden;
    box-shadow: 0 4px 10px rgba(0,0,0,0.2);
}

details.inv-card-item:hover {
    transform: translateY(-2px);
    background: rgba(30, 30, 30, 0.8);
    box-shadow: 0 6px 15px rgba(0,0,0,0.4);
}

summary.inv-card-summary {
