    white-space: pre-wrap;  /* Giữ định dạng xuống dòng của văn bản gốc */
    text-align: left;       /* Canh trái để dễ đọc mô tả dài (hoặc để justify nếu thích) */
    margin-top: 10px;       /* Cách phần thông tin loại/slot ra một chút */
}

.qty-badge {
