<script type="module">
    // ========================================================================
    // 1. CÁC HÀM TIỆN ÍCH & TRỢ GIÚP (UTILITIES & HELPERS)
    // ========================================================================

    // Hàm truy xuất dữ liệu an toàn tránh lỗi undefined khi gọi thuộc tính lồng sâu
    const _ = {
        get: (obj, path, defaultValue) => {
            if (!obj) return defaultValue;
            const keys = path.split('.');
            let result = obj;
            for (const key of keys) {
                result = result[key];
                if (result === undefined || result === null) return defaultValue;
            }
            return result;
        }
    };

    // TỪ ĐIỂN VIỆT HÓA CHỈ SỐ
    const STAT_MAP = {
        'STR': 'Sức Mạnh', 'CON': 'Thể Chất', 'AGI': 'Nhanh Nhẹn',
        'DEF': 'Phòng Thủ', 'SPI': 'Tinh Thần', 'INT': 'Trí Tuệ',
        'BLD': 'Huyết Mạch', 'LUCK': 'Vận Khí', 'HP': 'Sinh Lực',
        'MP': 'Năng Lượng', 'HP_max': 'HP Tối Đa', 'MP_max': 'MP Tối Đa'
    };

    function transStat(key) {
        const k = key.toUpperCase();
        if (STAT_MAP[k]) return STAT_MAP[k];
        if (k === 'INFECTION_RATE') return 'Ô Nhiễm';
        if (k === 'SANITY') return 'Tỉnh Táo';
        return key;
    }

    function getRankColor(qual) {
        if (!qual) return 'q-pham';
        const q = String(qual).toLowerCase();
        if (q.includes('thần') || q.includes('ex') || q.includes('diệu nhật')) return 'q-than';
        if (q.includes('thánh') || q.includes('bán thần')) return 'q-thanh'; 
        if (q.includes('diệu') || q.includes('sử thi') || q.includes('lam ngọc')) return 'q-dieu';
        if (q.includes('kim') || q.includes('vàng') || q.includes('huyền thoại')) return 'q-kim';
        if (q.includes('ngân') || q.includes('bạch kim') || q.includes('bạc')) return 'q-ngan';
        if (q.includes('thiết') || q.includes('sắt')) return 'q-thiet';
        if (q.includes('huyền') || q.includes('cổ')) return 'q-huyen';
        return 'q-pham';
    }

    function renderWithState(containerId, newHtml) {
        const container = $(`#${containerId}`);
        if (!container.length) return;
        const openStates = {};
        container.find('details').each(function() {
            if ($(this).is('[open]')) openStates[$(this).children('summary').text().trim()] = true;
        });
        container.html(newHtml);
        container.find('details').each(function() {
            if (openStates[$(this).children('summary').text().trim()]) $(this).attr('open', '');
        });
    }

    window.toggleEquipDetail = function(el) {
        const $slot = $(el);
        const hasItem = $slot.attr('data-has') === 'true';
        if (!hasItem) return;
        const $detail = $slot.next('.item-detail-panel');
        $slot.closest('.equip-grid-container, .beast-equip-group').find('.item-detail-panel').not($detail).slideUp(150);
        $slot.closest('.equip-grid-container, .beast-equip-group').find('.equip-slot').not($slot).removeClass('open');
        $detail.slideToggle(150);
        $slot.toggleClass('open');
    };

    // ========================================================================
    // 2. CÁC HÀM RENDER COMPONENT CỐT LÕI (GRID 4x2 OCD)
    // ========================================================================

    function renderStatGrid(stats, isHuman) {
        const s = (k) => {
            if (stats[k] !== undefined) return stats[k];
            if (stats[k.toLowerCase()] !== undefined) return stats[k.toLowerCase()];
            return 0;
        };

        const L = { 
            STR: 'SỨC MẠNH', CON: 'THỂ CHẤT', AGI: 'NHANH NHẸN', 
            DEF: 'PHÒNG THỦ', SPI: 'TINH THẦN', INT: 'TRÍ TUỆ', 
            BLD: 'HUYẾT MẠCH', LUCK: 'VẬN KHÍ' 
        };

        const createCard = (key, val, type = 'normal', customColor = '', icon = '') => {
            let extraClass = '';
            let valColor = 'var(--text-main)';
            let labelColor = 'var(--text-dim)';
            let styleAttr = '';

            if (type === 'sub') {
                extraClass = 'card-sub';
            } else if (type === 'main') {
                extraClass = 'card-main';
                valColor = customColor; 
                labelColor = customColor;
                styleAttr = `border-color: ${customColor}; box-shadow: inset 0 0 15px ${customColor}30;`;
            }

            return `
            <div class="stat-card-modern ${extraClass}" style="${styleAttr}">
                <div class="stat-label-modern" style="color:${labelColor}">
                    ${icon} ${L[key] || key} ${icon}
                </div>
                <div class="stat-val-modern" style="color:${valColor}; text-shadow: 0 0 10px ${customColor}40;">
                    ${val}
                </div>
            </div>`;
        };

        let html = '';
        html += createCard('STR', s('STR'));
        html += createCard('CON', s('CON'));
        html += createCard('AGI', s('AGI'));
        html += createCard('DEF', s('DEF'));
        html += createCard('INT', s('INT'));
        html += createCard('LUCK', s('LUCK'));

        html += createCard('BLD', s('BLD')); 
        html += createCard('SPI', s('SPI'));

        return `<div class="stat-grid-ocd">${html}</div>`;
    }

    function updateSvgOrb(orbType, current, max, isBeastMode) {
        let progId, valId, tooltipId, colorVar, labelText;

        if (orbType === 'hp') { 
            progId = 'orb-hp-prog'; valId = 'val-hp'; tooltipId = 'orb-hp-tooltip';
            labelText = "Sinh Lực"; colorVar = 'var(--c-hp)'; 
        }
        else if (orbType === 'san') { 
            progId = 'orb-san-prog'; valId = 'val-san'; tooltipId = 'orb-san-tooltip';
            labelText = "Tỉnh Táo"; colorVar = 'var(--c-san)'; 
        }
        else if (orbType === 'inf') { 
            progId = 'orb-inf-prog'; valId = 'val-inf'; tooltipId = 'orb-inf-tooltip';
            labelText = "Ô Nhiễm"; colorVar = 'var(--c-inf)'; 
        }
        else if (orbType === 'mp') { 
            progId = 'orb-mp-prog'; valId = 'val-mp'; tooltipId = 'orb-mp-tooltip';
            if (isBeastMode) { 
                labelText = "Huyết Mạch"; 
                colorVar = '#c678dd'; 
            } else { 
                labelText = "Tinh Thần"; 
                colorVar = 'var(--c-mp)'; 
            }
            $('#lbl-mp').text(labelText).css('color', colorVar);
        }

        const $prog = $(`#${progId}`);
        if ($prog.length) {
            const val = parseFloat(current) || 0;
            const mx = parseFloat(max) > 0 ? parseFloat(max) : 1; 
            let pct = Math.min(100, Math.max(0, (val / mx) * 100));

            const circumference = 251.3;
            const offset = circumference - ((pct / 100) * circumference);

            $prog.css({ 'stroke-dashoffset': offset, 'stroke': colorVar });
            $(`#${valId}`).text(`${Math.round(pct)}%`);
            $(`#${tooltipId}`).removeAttr('title');
            $(`#${tooltipId}`).attr('data-tooltip', `${labelText}: ${Math.round(val)} / ${Math.round(mx)}`);
        }
    }

    $(document).ready(function() {
        if ($('#global-custom-tooltip').length === 0) {
            $('body').append('<div id="global-custom-tooltip" class="custom-tooltip"></div>');
        }
        const $tooltip = $('#global-custom-tooltip');

        $(document).on('mouseenter', '.stat-orb', function(e) {
            const text = $(this).attr('data-tooltip');
            if (text) $tooltip.html(text).css('opacity', '1');
        });

        $(document).on('mousemove', '.stat-orb', function(e) {
            let leftPos = e.pageX + 15;
            let topPos = e.pageY + 15;
            const tooltipWidth = $tooltip.outerWidth() || 150; 
            const windowWidth = $(window).width();
            if (leftPos + tooltipWidth > windowWidth - 20) leftPos = e.pageX - tooltipWidth - 15;
            $tooltip.css({ left: leftPos + 'px', top: topPos + 'px' });
        });

        $(document).on('mouseleave', '.stat-orb', function() {
            $tooltip.css('opacity', '0');
        });
    });

    function renderEquipDetailContent(item) {
        if (!item || !item.name) return '<div class="detail-desc">Dữ liệu không toàn vẹn. Lỗi thực thể.</div>';

        let statsHtml = '';
        if (item.stats_modifiers && Object.keys(item.stats_modifiers).length > 0) {
            Object.entries(item.stats_modifiers).forEach(([key, val]) => {
                if(val !== 0) statsHtml += `<div class="detail-stat-row"><span class="detail-stat-label">${transStat(key)}</span><span class="detail-stat-val">${val > 0 ? '+'+val : val}</span></div>`;
            });
        }

        let reqHtml = '';
        if (item.requirements) {
            if(item.requirements.min_level > 0) reqHtml += `<span style="background:rgba(231, 76, 60, 0.2); padding:2px 5px; border-radius:3px; margin-right:5px; border:1px solid #e74c3c;">Lv.${item.requirements.min_level}</span>`;
            if(item.requirements.allowed_species && item.requirements.allowed_species.length) reqHtml += `<span style="background:rgba(52, 152, 219, 0.2); padding:2px 5px; border-radius:3px; margin-right:5px; border:1px solid #3498db;">Chủng: ${item.requirements.allowed_species.join(',')}</span>`;
        }

        return `
            <div class="detail-header">
                <span class="${getRankColor(item.rank_quality)}" style="font-size:1.1em;">${item.name}</span>
                <span style="font-size:0.7em; color:#7f8c8d; font-family:'JetBrains Mono'; border:1px solid #444; padding:2px 6px; border-radius:4px;">UID: ${item.uid || 'Khuyết'}</span>
            </div>
            <div style="margin-bottom:10px; display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:5px;">
                <span style="font-size:0.9em;">Phẩm Chất: <b class="${getRankColor(item.rank_quality)}">${item.rank_quality || 'Vô Danh'}</b></span>
                <span style="font-family:'JetBrains Mono'; font-size:0.85em; background:rgba(0,0,0,0.5); padding:2px 6px; border-radius:4px;">Độ Bền: <b style="color:${(item.durability_current || 100) < 30 ? '#e74c3c' : '#98c379'}">${item.durability_current || 100}/${item.durability_max || 100}</b></span>
            </div>
            ${reqHtml ? `<div style="margin-bottom:10px; font-size:0.8em; color:#bdc3c7;">Yêu cầu: ${reqHtml}</div>` : ''}
            ${statsHtml ? `<div class="detail-stats-grid">${statsHtml}</div>` : '<div style="margin-bottom:10px; font-style:italic; color:#555; font-size:0.85em;">Vật phẩm này không mang lại lợi ích cơ thể.</div>'}
            <div class="detail-desc">${(item.description || '').replace(/\\n/g, '<br>')}</div>`;
    }

    // ========================================================================
    // 3. HÀM CHÍNH: XỬ LÝ TOÀN BỘ DATA (RENDER PANEL)
    // ========================================================================
    function renderPanel() {
        let data = {};
        if (typeof window.getAllVariables === 'function') data = window.getAllVariables(); 
        else if (window.MVU && typeof window.MVU.getState === 'function') data = window.MVU.getState(); 
        else if (window.preloadedData) data = window.preloadedData;

        // Bốc tách Object từ Schema V4/V5
        const tamer = data.tamer || _.get(data, 'stat_data.tamer', {});
        const system = data.minh_kinh || _.get(data, 'stat_data.minh_kinh', {});
        const beasts = data.beast_roster || _.get(data, 'stat_data.beast_roster', []);
        const world = data.world_state || _.get(data, 'stat_data.world_state', {});
        const inv = data.inventory || tamer.inventory || _.get(data, 'stat_data.inventory', {});
        const quest = data.quest_log || _.get(data, 'stat_data.quest_log', {});
        const rel = data.relationships || _.get(data, 'stat_data.relationships', {});

        // --- XÁC ĐỊNH ROLE ---
        const roleMode = tamer.role_mode || 'Tamer';
        const rType = tamer.race_type || 'Nhân Loại';
        const isBeastMode = (roleMode.includes('Pet') || roleMode.includes('Beast') || roleMode.includes('Dị Thú') || rType.includes('Dị Thú') || rType.includes('Beast'));

        // --- CẤU HÌNH GIAO DIỆN THEO ROLE ---
        if (isBeastMode) {
            $('#ui-role').text(roleMode === 'Pet' ? 'Thú Cưng Lệ Thuộc' : 'Dị Thú Hoang Dã');
            $('#sys-title').text('HỆ THỐNG TIẾN HÓA GEN');
            $('#header-human-data').text('Chỉ Số Sinh Tồn Bản Thể');
            $('#wrap-human-data').hide(); 
            $('#sec-beast-data').show(); 

            const bData = tamer.beast_data || {};
            let blCurr = bData.bloodline_energy_current || 0;
            let blMax = bData.bloodline_energy_max || 100;
            let blPct = Math.min(100, Math.max(0, (blCurr / blMax) * 100));
            $('#b-blood-val').text(`${blCurr} / ${blMax}`);
            $('#b-blood-bar').css('width', `${blPct}%`);
        } else {
            $('#ui-role').text('Ngự Thú Sư (Tamer)');
            $('#sys-title').text('HỆ THỐNG MINH KÍNH');
            $('#header-human-data').text('Năng Lực Ký Chủ');
            $('#wrap-human-data').show(); 
            $('#sec-beast-data').hide();

            const hData = tamer.human_data || {};
            let spCurr = hData.spirit_power_current || tamer.stats?.MP_current || 0;
            let spMax = hData.spirit_power_max || tamer.stats?.MP_max || 100;
            let spPct = Math.min(100, Math.max(0, (spCurr / spMax) * 100));
            $('#h-spirit-val').text(`${spCurr} / ${spMax}`);
            $('#h-spirit-bar').css('width', `${spPct}%`);
        }

        // --- HEADER CHUNG ---
        $('#ui-name').text(tamer.real_name || tamer.bio?.name || 'Vô Danh');
        // --- XỬ LÝ HIỂN THỊ CẤP BẬC (RANK) ---
        let displayRank = '';

        if (isBeastMode) {
            // Nếu đang là Thú (Beast Mode): Lấy Rank Tier từ dữ liệu thú (VD: Linh Thú)
            // Dữ liệu lấy từ: tamer.beast_data.rank_tier
            displayRank = tamer.beast_data?.rank_tier || 'Dị Thú'; 
        } else {
            // Nếu đang là Người (Tamer Mode): Lấy Spirit Rank
            // Nếu chưa có rank, mặc định hiển thị là "Phàm Giai" thay vì "Phàm Nhân"
            displayRank = tamer.human_data?.spirit_rank || 'Phàm Giai';
        }

        // Cập nhật text và màu sắc (getRankColor sẽ tự đổi màu theo chữ Kim/Ngân/Phàm...)
        $('#ui-rank').text(displayRank).attr('class', getRankColor(displayRank));
        $('#ui-energy').text(`Năng Lượng: ${system.energy_source || 0}`);

        // --- RENDER 4 LINH CHÂU ---
        const stats = tamer.stats || {};
        updateSvgOrb('hp', stats.HP_current, stats.HP_max, isBeastMode);
        updateSvgOrb('san', stats.sanity, 100, isBeastMode);
        updateSvgOrb('inf', stats.infection_rate, 100, isBeastMode);

        if (isBeastMode) {
            const bData = tamer.beast_data || {};
            updateSvgOrb('mp', bData.bloodline_energy_current || 0, bData.bloodline_energy_max || 100, isBeastMode);
        } else {
            updateSvgOrb('mp', stats.MP_current, stats.MP_max, isBeastMode);
        }

        // --- RENDER STATS GRID ---
        $('#container-tamer-stats').html(renderStatGrid(stats, !isBeastMode));

        // ========================================================================
        // TAB 1: THÔNG TIN HỒ SƠ BẢN THỂ
        // ========================================================================
        const bInfo = tamer.beast_data || {};
        const specInfo = bInfo.species_info || {};
        const profInfo = tamer.human_data?.profession_info || {};

        let displayRace = isBeastMode ? (specInfo.name || tamer.race_type) : tamer.race_type;
        if (specInfo.type_class) displayRace += ` [${specInfo.type_class}]`;

        $('#ui-race').text(displayRace || 'Nhân Loại');

        if (specInfo.description_lore) {
            $('#ui-race').css('cursor', 'help').attr('title', specInfo.description_lore.replace(/\\n/g, '\n'));
        }
        $('#ui-form').text(tamer.current_form || 'Dạng Người');

        if (isBeastMode) {
            $('#lbl-species-root').text('Gốc Loài:');
            $('#ui-species-root').text(specInfo.description_lore ? 'Xem chi tiết' : (tamer.species_root || 'Không'));
        } else {
            $('#lbl-species-root').text('Nghề Nghiệp:');
            const jobName = profInfo.name || tamer.human_data?.profession || 'Kẻ Lang Thang';
            $('#ui-species-root').html(`<span class="q-kim">${jobName}</span>`);
        }

        $('#ui-disguise').text((tamer.human_disguise_quality || 0) + '%');
        $('#ui-pot').text(tamer.potential_quality || 'E').attr('class', 'attr-val ' + getRankColor(tamer.potential_quality));
        $('#ui-pm').text(_.get(tamer, 'potential_modifier', 1.0).toFixed(1));

        const hData = tamer.human_data || {};
        $('#h-slots').text(`${hData.active_contract_slots || 1}`);
        $('#h-cap').text(`${_.get(hData, 'soul_capacity.used', 0)} / ${_.get(hData, 'soul_capacity.max', 10)}`);

        const aff = hData.spirit_affinity || {};
        let allEls = (aff.base_elements || []).map(e => e.type).filter(Boolean);

        const getElStyle = (name) => {
            const n = String(name).toLowerCase();
            if(n.includes('hỏa') || n.includes('fire')) return { icon: '🔥', color: '#ff4d4d', bg: 'rgba(255, 77, 77, 0.1)' };
            if(n.includes('thủy') || n.includes('water')) return { icon: '💧', color: '#3498db', bg: 'rgba(52, 152, 219, 0.1)' };
            if(n.includes('mộc') || n.includes('wood')) return { icon: '🌿', color: '#2ecc71', bg: 'rgba(46, 204, 113, 0.1)' };
            if(n.includes('kim') || n.includes('metal')) return { icon: '⚔️', color: '#f1c40f', bg: 'rgba(241, 196, 15, 0.1)' };
            if(n.includes('thổ') || n.includes('earth')) return { icon: '⛰️', color: '#d35400', bg: 'rgba(211, 84, 0, 0.1)' };
            if(n.includes('phong') || n.includes('wind')) return { icon: '🌪️', color: '#1abc9c', bg: 'rgba(26, 188, 156, 0.1)' };
            if(n.includes('lôi') || n.includes('lightning')) return { icon: '⚡', color: '#9b59b6', bg: 'rgba(155, 89, 182, 0.1)' };
            if(n.includes('băng') || n.includes('ice')) return { icon: '❄️', color: '#00d2d3', bg: 'rgba(0, 210, 211, 0.1)' };
            if(n.includes('quang') || n.includes('sáng')) return { icon: '☀️', color: '#f39c12', bg: 'rgba(243, 156, 18, 0.1)' };
            if(n.includes('ám') || n.includes('độc') || n.includes('tối')) return { icon: '💀', color: '#95a5a6', bg: 'rgba(149, 165, 166, 0.1)' };
            return { icon: '⚪', color: '#bdc3c7', bg: 'rgba(189, 195, 199, 0.1)' };
        };

        let tagsHtml = allEls.map(elName => {
            let cleanName = elName.replace('Hệ ', '').trim();
            let style = getElStyle(elName);
            return `<span style="display: inline-flex; align-items: center; gap: 5px; background: ${style.bg}; border: 1px solid ${style.color}; color: ${style.color}; padding: 3px 8px; border-radius: 6px; font-size: 0.9em; font-weight: bold; margin-right:5px; white-space: nowrap;">${style.icon} ${cleanName.toUpperCase()}</span>`;
        }).join('');
        $('#h-affinity-main').html(tagsHtml || '<i style="color:#777;">Vô Hệ</i>');
        $('#h-affinity-desc').text(aff.combined_effect?.description || 'Không có hiệu ứng kết hợp đặc biệt.');

        const cult = hData.cultivation?.main_slot || {};
        $('#h-cult-name').text(cult.name || 'Chưa tu luyện').attr('class', getRankColor(cult.rank_quality));
        $('#h-cult-lvl').text(`Tầng ${cult.mastery_level || 0}`);
        $('#h-cult-exp').text(`${cult.current_exp || 0} / ${cult.max_exp || 100}`);

        const talent = hData.soul_talent || {};
        let talentName = typeof talent === 'string' ? talent : (talent.name || 'Chưa Thức Tỉnh');
        let talentDesc = typeof talent === 'string' ? 'Cần kích hoạt Minh Kính.' : (talent.description_lore || talent.effect || 'Chưa rõ hiệu ứng.');
        let talentRank = talent.rank_quality ? `<span class="${getRankColor(talent.rank_quality)}" style="font-size:0.8em; border:1px solid; padding:0 4px; border-radius:3px; margin-left:5px;">${talent.rank_quality}</span>` : '';

        let talentModsHtml = '';
        if (talent.stats_modifiers && Object.keys(talent.stats_modifiers).length > 0) {
            talentModsHtml = '<div style="margin-top:10px; padding-top:8px; border-top:1px dashed #555; font-size:0.85em; display:flex; flex-wrap:wrap; gap:8px;">';
            for (let [k, v] of Object.entries(talent.stats_modifiers)) {
                if (v !== 0) {
                    talentModsHtml += `<span style="background:rgba(226,183,100,0.1); padding:2px 6px; border-radius:4px; color:var(--accent-warm);">${transStat(k)}: <b>${v > 0 ? '+' : ''}${v}</b></span>`;
                }
            }
            talentModsHtml += '</div>';
        }

        let talentHtml = `
        <details>
            <summary>Thiên Phú Linh Hồn: <span style="color:var(--text-main); margin-left:8px; font-weight:700;">${talentName}</span> ${talentRank}</summary>
            <div class="desc-no-indent">
                ${String(talentDesc).trim().replace(/\\n/g, '<br>')}
                ${talent.active_effect ? `<div style="margin-top:10px; color:var(--theme-gold); border-top: 1px dashed rgba(226, 183, 100, 0.2); padding-top: 5px;">⚡ Kích hoạt: <br>${String(talent.active_effect).trim().replace(/\\n/g, '<br>')}</div>` : ''}
                ${talentModsHtml}
            </div>
        </details>`;
        renderWithState('container-talent-details', talentHtml);

        const tSkills = tamer.active_skills || hData.tamer_skills || [];
        let tSkillHtml = '<div class="skill-list">';
        if (tSkills.length > 0) {
            tSkillHtml += tSkills.map(s => {
                const castTime = s.cast_time?.value > 0 ? `| Niệm: ${s.cast_time.value}s` : '| Tức thì';
                return `<div class="skill-item"><div class="skill-head"><span class="skill-name ${getRankColor(s.rank_quality || s.rank)}">${s.name}</span><span class="skill-meta">Lv.${s.mastery_level || 1} | Cost: ${s.cost?.value||0} ${s.cost?.type||'MP'} | CD: ${s.cooldown?.value||0}${s.cooldown?.unit||'s'} ${castTime}</span></div><div class="skill-desc">${(s.description || s.effect || '').replace(/\\n/g, '<br>')}</div></div>`;
            }).join('');
        } else {
            tSkillHtml += '<div style="font-style:italic; color:#777; padding:10px;">Ngươi quá yếu, chưa lĩnh ngộ được kỹ năng nào.</div>';
        }
        tSkillHtml += '</div>';
        renderWithState('container-tamer-skills-details', `<details><summary>Thư Viện Kỹ Năng Ký Chủ</summary>${tSkillHtml}</details>`);

        // TAB 4: DANH SÁCH SỦNG THÚ
        const bData = tamer.beast_data || {};
        const blInfo = bData.bloodline_info || {}; 

        if (isBeastMode || bData.bloodline_rank) {
            let bRankVal = blInfo.rank_quality || bData.bloodline_rank || 'Phàm Giai';
            $('#b-rank').text(bRankVal).attr('class', 'attr-val ' + getRankColor(bRankVal));
            if (blInfo.name && blInfo.name !== "Không có") {
                $('#b-rank').append(`<div style="font-size:0.6em; color:var(--text-dim); margin-top:2px;">${blInfo.name}</div>`);
            }
            $('#b-ferocity').text(bData.ferocity || 0);
            $('#b-instinct').text(bData.instinct_control || 0);
            $('#b-cci').text(`${(bData.foundation_index || 1.0).toFixed(1)}`);

            let muts = bData.bloodline_mutation || {};
            let mutHtml = `<div class="gen-trait-box"><span class="gen-trait-title">Tiến Trình Đột Biến: ${muts.bloodline_name || 'Bình thường'}</span><div style="font-size:0.9em; color:#bbb;">Phân loại: <span style="color:var(--rank-b)">${muts.mutation_type || 'Không'}</span></div><div style="font-size:0.9em; color:#bbb;">Đánh thức: <b style="color:var(--theme-gold)">${muts.awakening_percent || 0}%</b></div></div>`;
            renderWithState('container-beast-mutations', mutHtml);

            let innateHtml = '<div class="skill-list">';
            if ((bData.innate_skills || []).length > 0) {
                innateHtml += bData.innate_skills.map(s => `<div class="skill-item"><div class="skill-name" style="color:var(--qual-kim);">${typeof s === 'string' ? s : s.name}</div></div>`).join('');
            } else {
                innateHtml += '<div style="padding:10px; font-style:italic; color:#777;">Sinh vật cấp thấp không có thiên phú bẩm sinh.</div>';
            }
            innateHtml += '</div>';
            renderWithState('container-beast-innate', `<details><summary>Kỹ Năng Bẩm Sinh (Innate)</summary>${innateHtml}</details>`);
        }

        const bond = tamer.master_bond || {};
        if (roleMode.includes('Pet') || roleMode.includes('Sủng') || bond.master_id && bond.master_id !== 'none') {
            $('#sec-master').show();
            $('#m-name').text(bond.master_name || 'Chưa có');
            $('#m-rank').text(bond.master_rank || '?');
            $('#m-contract').text(bond.contract_type || 'Chủ Tớ');
            $('#m-trust').text(bond.trust_level || 0);
            $('#m-favor').text(bond.favorability || 0);
            $('#m-loyalty').text(tamer.obedience_stats?.loyalty || 0);
        } else {
            $('#sec-master').hide();
        }

        const cm = tamer.combat_modifiers || {};
        $('#cm-realm').text(`x${(cm.realm_suppression_modifier || 1.0).toFixed(1)}`);
        $('#cm-elem').text(`x${(cm.elemental_advantage_modifier || 1.0).toFixed(1)}`);
        $('#cm-tact').text(`Lv.${cm.tactical_command_level || 0}`);
        $('#cm-env').text(`x${(cm.environmental_adaptation || 1.0).toFixed(1)}`);
        if (cm.life_resonance_active) {
            $('#cm-reso').text("ĐANG KÍCH HOẠT").css("color", "var(--rank-a)").css("font-weight", "bold");
        } else {
            $('#cm-reso').text("Vô hiệu").css("color", "var(--text-muted)").css("font-weight", "normal");
        }
        let buffsHtml = `<details><summary>Trạng thái & Buffs Hiện Tại</summary><div style="padding-left:10px;">${(cm.active_buffs_debuffs || []).length ? (cm.active_buffs_debuffs || []).join('<br>• ') : '<i style="color:var(--text-muted)">Không có hiệu ứng bất thường.</i>'}</div></details>`;
        renderWithState('container-active-buffs', buffsHtml);

        $('#mk-scan').text(`Lv.${system.scan_level || 1}`);
        $('#mk-sim').text(system.simulation_points || 0);
        const evo = system.evolution_forecast || {};
        let evoStr = '';
        if (evo.scanned_paths && evo.scanned_paths.length) {
             evoStr = evo.scanned_paths.map(p => `<div style="margin-top:5px; border-left:2px solid var(--theme-gold); padding-left:5px;"><b style="color:var(--theme-gold)">${typeof p === 'object' ? p.path_name : p}</b><br><span style="font-size:0.9em; opacity:0.8;">${typeof p === 'object' ? (p.description||'') : ''}</span></div>`).join('');
        }
        let evoDet = `<details><summary>Phân Tích Tiến Hóa Dị Thú</summary><div><b>Mục tiêu định vị:</b> ${evo.target_path || 'Chưa thiết lập'}<br><b>Dữ liệu lộ trình:</b><br>${evoStr || '<i style="color:#777">Hệ thống chưa ghi nhận.</i>'}</div></details>`;
        renderWithState('container-mk-evo', evoDet);

        let sysFeat = (system.features || []).concat(system.hidden_blueprints || []);

let mkFeatHtml = `<details><summary>Công Năng Ẩn / Bản Vẽ Chế Tạo</summary><div style="padding-top: 5px;">${sysFeat.length ? sysFeat.map(f => {
    // Nếu f là object, in ra tên, level và mô tả
    if (typeof f === 'object' && f !== null) {
        return `<div style="margin-bottom: 6px; border-left: 2px solid var(--theme-gold); padding-left: 8px;">
                    <b style="color:var(--theme-gold)">${f.name || 'Chưa rõ'}</b> <span style="font-size:0.8em; color:var(--text-muted)">(Lv.${f.level || 1})</span><br>
                    <span style="font-size:0.9em; color:var(--text-dim);">${f.description || ''}</span>
                </div>`;
    }
    // Dành cho trường hợp f chỉ là một chuỗi văn bản bình thường
    return `• ${f}`;
}).join('') : '<i style="color:#777">Chưa thu thập được dữ liệu mã hóa.</i>'}</div></details>`;

renderWithState('container-mk-features', mkFeatHtml);

        const cur = tamer.currencies || {};
        const stones = cur.spirit_stones || {};
        const bStones = cur.blood_stones || {};
        $('#eco-credit').text(cur.credit_points || 0);
        $('#eco-spirit').html(`Hạ: <b style="color:var(--text-main)">${stones.low||0}</b> | Trung: <b style="color:var(--text-main)">${stones.mid||0}</b><br>Thượng: <b style="color:var(--text-main)">${stones.high||0}</b> | Cực phẩm: <b style="color:var(--qual-than)">${stones.extreme||0}</b>`);
        $('#eco-blood').html(`Hạ: <b style="color:var(--rank-s)">${bStones.low||0}</b> | Trung: <b style="color:var(--rank-s)">${bStones.mid||0}</b><br>Thượng: <b style="color:var(--rank-s)">${bStones.high||0}</b> | Cực phẩm: <b style="color:var(--rank-s)">${bStones.extreme||0}</b>`);
        $('#soc-faction').text(tamer.faction || 'Tự Do');
        $('#soc-wanted').text(tamer.wanted_status || 'An Toàn').css('color', tamer.wanted_status !== 'An Toàn' ? 'var(--rank-s)' : 'var(--c-san)');

        // TAB 2: TRANG BỊ
        const equipData = tamer.equipment_slots || {};
        const standardSlots = ['main_weapon', 'sub_weapon', 'head', 'body', 'legs', 'gloves', 'shoes', 'necklace', 'ring_1', 'ring_2', 'off_weapon', 'chest'];

        const equipMap = {
            'main_weapon': equipData.main_weapon,
            'sub_weapon': equipData.sub_weapon || equipData.off_weapon,
            'head': equipData.head,
            'body': equipData.body || equipData.chest,
            'legs': equipData.legs,
            'gloves': equipData.gloves,
            'shoes': equipData.shoes,
            'necklace': equipData.necklace,
            'ring_1': equipData.ring_1,
            'ring_2': equipData.ring_2
        };

        let totalSlots = 10;

        // Cập nhật 10 slot mặc định
        for (const [slotId, item] of Object.entries(equipMap)) {
            const hasItem = item && typeof item === 'object' && item.name && item.name !== "Chưa trang bị";
            const $slotEl = $(`#slot-${slotId}`);
            const $nameEl = $(`#name-${slotId}`);
            const $detailEl = $(`#detail-${slotId}`);

            if ($slotEl.length) {
                $slotEl.attr('data-has', hasItem ? 'true' : 'false');
                $slotEl.removeClass('open'); 
                $detailEl.hide();

                if (hasItem) {
                    $nameEl.text(item.name).attr('class', `equip-name ${getRankColor(item.rank_quality)}`);
                    $detailEl.html(renderEquipDetailContent(item));
                } else {
                    $nameEl.text("Chưa trang bị").attr('class', 'equip-name q-pham');
                    $detailEl.html('<div class="detail-desc">Vị trí này đang trống. Hãy vào kho đồ tìm vật phẩm tương thích.</div>');
                }
            }
        }

        // Tự động quét và thêm các Slot dị thường (VD: accessory_2)
        for (const [key, item] of Object.entries(equipData)) {
            if (!standardSlots.includes(key) && $(`#slot-${key}`).length === 0) {
                totalSlots++; 
                let customLabel = key.replace(/_/g, ' ');
                if (customLabel.length > 8) customLabel = customLabel.substring(0, 8) + '.';

                const hasItem = item && typeof item === 'object' && item.name && item.name !== "Chưa trang bị";
                const qClass = hasItem ? getRankColor(item.rank_quality) : 'q-pham';
                const name = hasItem ? item.name : 'Chưa trang bị';
                const detail = hasItem ? renderEquipDetailContent(item) : '<div class="detail-desc">Vị trí này đang trống...</div>';

                const newSlotHtml = `
                <div class="equip-slot-wrapper">
                    <div class="equip-slot" id="slot-${key}" data-has="${hasItem ? 'true' : 'false'}" onclick="toggleEquipDetail(this)">
                        <div class="slot-label" style="text-transform:uppercase; font-size:9px;" title="${key}">${customLabel}</div>
                        <div class="equip-name ${qClass}" id="name-${key}">${name}</div>
                        <span class="equip-toggle-icon">▼</span>
                    </div>
                    <div class="item-detail-panel" id="detail-${key}" style="display:none;">${detail}</div>
                </div>`;

                $('#tamer-equip-list').append(newSlotHtml);

            } else if (!standardSlots.includes(key) && $(`#slot-${key}`).length > 0) {
                totalSlots++;
                const hasItem = item && typeof item === 'object' && item.name && item.name !== "Chưa trang bị";
                $(`#slot-${key}`).attr('data-has', hasItem ? 'true' : 'false');
                if (hasItem) {
                    $(`#name-${key}`).text(item.name).attr('class', `equip-name ${getRankColor(item.rank_quality)}`);
                    $(`#detail-${key}`).html(renderEquipDetailContent(item));
                } else {
                    $(`#name-${key}`).text("Chưa trang bị").attr('class', 'equip-name q-pham');
                    $(`#detail-${key}`).html('<div class="detail-desc">Vị trí này đang trống...</div>');
                }
            }
        }

        $('h4:contains("Cấu Hình Trang Bị Ký Chủ")').text(`Cấu Hình Trang Bị Ký Chủ (${totalSlots} Slot)`);

        // =========================================================
        // 2. KHO TRANG BỊ SỦNG THÚ (Giữ nguyên không đổi)
        // =========================================================
        let beastsEquipHtml = '';
        if (!beasts || beasts.length === 0) {
            beastsEquipHtml = '<div style="text-align:center; padding:30px; opacity:0.5; font-style:italic;">Không có tiểu đệ nào để kiểm tra trang bị.</div>';
        } else {
            beastsEquipHtml = beasts.map((b, idx) => {
                const bEq = b.equipment_slots || {};

                // 1. Định nghĩa 5 slot chuẩn luôn hiện của thú
                const standardBeastSlots = [
                    { id: 'head', label: 'Mũ/Đầu', item: bEq.head },
                    { id: 'body', label: 'Giáp Thân', item: bEq.body || bEq.chest },
                    { id: 'claw_weapon', label: 'Răng/Vuốt', item: bEq.claw_weapon || bEq.weapon },
                    { id: 'core', label: 'Lõi (Core)', item: bEq.core },
                    { id: 'accessory', label: 'Phụ Kiện', item: bEq.accessory || bEq.accessory_1 }
                ];

                // Danh sách khóa chuẩn để lọc (tránh bị trùng lặp khi quét tự động)
                const standardKeys = ['head', 'body', 'chest', 'claw_weapon', 'weapon', 'core', 'accessory', 'accessory_1'];

                // 2. Khởi tạo mảng chứa toàn bộ Slot để render
                let allBeastSlots = [...standardBeastSlots];

                // 3. Quét TỰ ĐỘNG các slot lạ của Sủng Thú (VD: wing, tail, accessory_2...)
                for (const [key, item] of Object.entries(bEq)) {
                    if (!standardKeys.includes(key) && item && typeof item === 'object' && item.name && item.name !== "Chưa trang bị") {
                        // Rút gọn tên slot để nhét vừa UI UI
                        let customLabel = key.replace(/_/g, ' ');
                        if (customLabel.length > 8) customLabel = customLabel.substring(0, 8) + '.';

                        allBeastSlots.push({
                            id: key,
                            label: customLabel.toUpperCase(),
                            item: item
                        });
                    }
                }

                // 4. Bắt đầu Render HTML HTML cho Sủng Thú
                let slotsHtml = allBeastSlots.map(s => {
                    const hasItem = s.item && typeof s.item === 'object' && s.item.name && s.item.name !== "Chưa trang bị";
                    const qClass = hasItem ? getRankColor(s.item.rank_quality) : 'q-pham';
                    const name = hasItem ? s.item.name : 'Trống';
                    const detail = hasItem ? renderEquipDetailContent(s.item) : '<div class="detail-desc">Khe cắm này đang trống. Quái vật không cần mặc đồ cũng có sức mạnh riêng.</div>';
                    const uniqueSlotId = `b-slot-${idx}-${s.id}`; // Phải tạo ID độc nhất cho từng con thú

                    return `
                    <div class="equip-slot-wrapper">
                        <div class="equip-slot" id="${uniqueSlotId}" data-has="${hasItem ? 'true' : 'false'}" onclick="toggleEquipDetail(this)">
                            <div class="slot-label" style="font-size:9px;" title="${s.id}">${s.label}</div>
                            <div class="equip-name ${qClass}">${name}</div>
                            <span class="equip-toggle-icon">▼</span>
                        </div>
                        <div class="item-detail-panel">${detail}</div>
                    </div>`;
                }).join('');

                return `
                <div class="beast-equip-group" style="background:rgba(0,0,0,0.3); border:1px solid rgba(255,255,255,0.05); border-radius:10px; padding:15px; margin-bottom:15px;">
                    <div style="font-weight:800; color:var(--theme-gold); margin-bottom:12px; border-bottom:1px dashed #444; padding-bottom:8px; font-size:1.1em; letter-spacing:1px; text-transform:uppercase;">
                        ${b.name} <span style="font-size:0.7em; color:#777;">(${b.bio?.species || b.species_name || 'Dị Thú'})</span>
                    </div>
                    <div class="equip-grid-container">
                        ${slotsHtml}
                    </div>
                </div>`;
            }).join('');
        }
        $('#beasts-equip-list').html(beastsEquipHtml);

        // TAB 3: WORLD
        const chrono = world.chronology || {};
        const cal = chrono.calendar || {};
        if (cal.year) {
            $('#w-day').html(`Ngày ${cal.day} <span style="opacity:0.3; margin:0 8px;">|</span> Tháng ${cal.month} <span style="opacity:0.3; margin:0 8px;">|</span> Năm ${cal.year}`);
            $('#w-cycle').text(cal.time_of_day || 'Ban Ngày');
        } else {
            $('#w-day').text(`Lượt đếm (Turn): ${chrono.absolute_day_count || chrono.current_turn || 0}`);
            $('#w-cycle').text('Chưa rõ canh giờ');
        }
        $('#w-era').text(chrono.current_era || 'Kỷ Nguyên Vô Danh');
        $('#w-flow').text(`x${chrono.time_flow_rate || 1.0}`);

        const loc = world.location_hierarchy || {};
        $('#loc-dim').text(loc.current_dimension || 'Trái Đất (Dị Biến)');
        $('#loc-cont').text(loc.current_continent || 'Lục Địa Thất Lạc');
        $('#loc-reg').text(loc.current_region || 'Khu Vực Không Xác Định');
        $('#loc-spot').text(loc.specific_spot || 'Hoang Dã');
        $('#loc-terrain').text(loc.terrain_type || 'Bình Nguyên');

        const env = world.environment || world || {};
        $('#env-danger').text(env.location_danger_level || 'An Toàn').css('color', env.location_danger_level === 'Tử Vong' ? 'var(--rank-s)' : 'var(--qual-thanh)');
        $('#env-weather').text(env.weather_condition || env.weather || 'Bình thường');
        $('#env-mana').text(env.environmental_mana_density || 'Trung Bình');
        $('#env-elem').text(env.dominant_element || 'Hỗn Hợp');
        $('#env-corr').text((env.corruption_level || 0) + '%'); // Fix hiển thị ô nhiễm

        const travel = world.travel_system || {};
        $('#trav-state').text(travel.travel_state || 'Stationary (Đang cắm trại)');
        $('#trav-dest').text(_.get(travel, 'target_destination.region', 'Chưa định hướng'));
        $('#trav-method').text(travel.transport_method || 'Đi bộ');
        $('#trav-pct').text(`${travel.travel_progress || 0}%`);
        $('#bar-travel').css('width', `${travel.travel_progress || 0}%`);
        $('#trav-eta').text(`ETA: ${travel.estimated_arrival || 'N/A'}`);

        const activeHumanoids = world.active_humanoid_npcs || [];
        let humHtml = '';
        if (activeHumanoids.length === 0) {
            humHtml = '<div style="padding:15px; text-align:center; color:var(--text-muted); font-style:italic; background:rgba(0,0,0,0.3); border-radius:6px; border: 1px dashed #333;">Sóng radar yên tĩnh. Không có ai xung quanh.</div>';
        } else {
            humHtml = activeHumanoids.map(n => `
                <div class="entity-item" style="border-color:var(--theme-gold); background:rgba(226,183,100,0.05);">
                    <div class="travel-label">
                        <span style="color:var(--text-main); font-size:1.1em;">${n.name} <span style="font-size:0.7em; color:#777; font-weight:normal; text-transform:uppercase;">(${n.race})</span></span> 
                        <span style="color:var(--theme-gold); background:rgba(0,0,0,0.5); padding:2px 8px; border-radius:4px;">${n.spirit_rank || 'Phàm'}</span>
                    </div>
                    <div style="font-size:0.85em; color:var(--text-dim); border-top:1px dashed rgba(255,255,255,0.1); padding-top:6px; margin-top:4px;">
                        Thái độ: <b style="color:${n.attitude === 'Thù địch' ? '#e74c3c' : (n.attitude === 'Thân thiện' ? '#27ae60' : '#f1c40f')}">${n.attitude || 'Trung lập'}</b> | Trạng thái: ${n.status || 'Bình thường'}
                    </div>
                </div>`).join('');
        }
        renderWithState('container-world-humanoids', humHtml);

        const activeBeasts = world.active_beast_npcs || [];
        let wBeastHtml = '';
        if (activeBeasts.length === 0) {
            wBeastHtml = '<div style="padding:15px; text-align:center; color:var(--text-muted); font-style:italic; background:rgba(0,0,0,0.3); border-radius:6px; border: 1px dashed #333;">Không phát hiện năng lượng dã thú.</div>';
        } else {
            wBeastHtml = activeBeasts.map(n => `
                <div class="entity-item" style="border-color:var(--rank-s); background:rgba(192,57,43,0.05);">
                    <div class="travel-label" style="color:var(--rank-s);">
                        <span style="font-size:1.1em;">${n.name || n.species}</span> 
                        <span style="background:rgba(192,57,43,0.3); padding:2px 8px; border-radius:4px; color:white;">Lv.${n.level}</span>
                    </div>
                    <div style="font-size:0.85em; color:var(--text-dim); border-top:1px dashed rgba(255,255,255,0.1); padding-top:6px; margin-top:4px;">
                        Hệ: <b style="color:#3498db">${n.element || 'Cường hóa'}</b> | Tình trạng: ${n.health_status} <b style="color:#e67e22">[${n.aggro_state || 'Chủ động'}]</b>
                    </div>
                </div>`).join('');
        }
        renderWithState('container-world-beasts', wBeastHtml);

        const log = _.get(world, 'exploration_log.visited_locations', []);
        $('#log-visited').html(log.length ? log.map(l => `<div style="padding:4px 0; border-bottom:1px dashed rgba(255,255,255,0.05);">📍 ${l}</div>`).join('') : '<div style="opacity:0.5; font-style:italic; text-align:center; padding:10px;">Bộ nhớ trống rỗng. Ký chủ chưa từng rời khỏi vạch xuất phát.</div>');

        // TAB 4: BEAST ROSTER (SỦNG THÚ)
        let beastHtml = '';
        if (!beasts.length) {
            beastHtml = '<div style="text-align:center; padding:60px; color:var(--text-muted); font-style:italic; border: 2px dashed rgba(255,255,255,0.1); border-radius:12px; font-size:1.1em;">Hồn Ấn trống rỗng. Ngươi chưa thu phục được cường giả nào trong thiên địa.</div>';
        } else {
            beastHtml = beasts.map(b => {
                const bst = b.stats || {};
                const gen = b.genetics || {};
                const bl = b.bloodline_info || {};

                // --- XỬ LÝ HỆ NGUYÊN TỐ CHO SỦNG THÚ ---
                const bAff = b.elemental_affinity || {};
                let bEls = (bAff.base_elements || []).map(e => e.type).filter(Boolean);
                // Hỗ trợ đọc cả biến 'attribute' cũ nếu có
                if (bEls.length === 0 && b.attribute && b.attribute !== 'Không') {
                    bEls = [b.attribute];
                }

                const getBeastElStyle = (name) => {
                    const n = String(name).toLowerCase();
                    if(n.includes('hỏa') || n.includes('fire')) return { icon: '🔥', color: '#ff4d4d', bg: 'rgba(255, 77, 77, 0.1)' };
                    if(n.includes('thủy') || n.includes('water')) return { icon: '💧', color: '#3498db', bg: 'rgba(52, 152, 219, 0.1)' };
                    if(n.includes('mộc') || n.includes('wood')) return { icon: '🌿', color: '#2ecc71', bg: 'rgba(46, 204, 113, 0.1)' };
                    if(n.includes('kim') || n.includes('metal')) return { icon: '⚔️', color: '#f1c40f', bg: 'rgba(241, 196, 15, 0.1)' };
                    if(n.includes('thổ') || n.includes('earth')) return { icon: '⛰️', color: '#d35400', bg: 'rgba(211, 84, 0, 0.1)' };
                    if(n.includes('phong') || n.includes('wind')) return { icon: '🌪️', color: '#1abc9c', bg: 'rgba(26, 188, 156, 0.1)' };
                    if(n.includes('lôi') || n.includes('lightning')) return { icon: '⚡', color: '#9b59b6', bg: 'rgba(155, 89, 182, 0.1)' };
                    if(n.includes('băng') || n.includes('ice')) return { icon: '❄️', color: '#00d2d3', bg: 'rgba(0, 210, 211, 0.1)' };
                    if(n.includes('quang') || n.includes('sáng')) return { icon: '☀️', color: '#f39c12', bg: 'rgba(243, 156, 18, 0.1)' };
                    if(n.includes('ám') || n.includes('độc') || n.includes('tối')) return { icon: '💀', color: '#95a5a6', bg: 'rgba(149, 165, 166, 0.1)' };
                    return { icon: '⚪', color: '#bdc3c7', bg: 'rgba(189, 195, 199, 0.1)' };
                };

                let bTagsHtml = bEls.map(elName => {
                    let cleanName = elName.replace('Hệ ', '').trim();
                    let style = getBeastElStyle(elName);
                    return `<span style="display: inline-flex; align-items: center; gap: 4px; background: ${style.bg}; border: 1px solid ${style.color}; color: ${style.color}; padding: 1px 6px; border-radius: 4px; font-size: 0.8em; font-weight: bold; margin-right:5px; white-space: nowrap;">${style.icon} ${cleanName.toUpperCase()}</span>`;
                }).join('');

                if (!bTagsHtml) bTagsHtml = '<span style="font-size:0.8em; color:var(--text-muted); font-style:italic;">⚪ VÔ HỆ</span>';

                // --- 1. TÍNH TOÁN % CÁC THANH CHỈ SỐ ---
                const hpCur = (b.health_current !== undefined) ? b.health_current : (bst.HP || 100);
                const hpMax = bst.HP || 100;
                const hpPct = Math.min(100, Math.max(0, (hpCur / hpMax) * 100));

                const mpCur = (b.mp_current !== undefined) ? b.mp_current : (bst.MP || 100);
                const mpMax = bst.MP || 100;
                const mpPct = Math.min(100, Math.max(0, (mpCur / mpMax) * 100));

                const staCur = b.stamina?.current || 0;
                const staMax = b.stamina?.max || 100;
                const staPct = Math.min(100, Math.max(0, (staCur / staMax) * 100));

                const blCur = b.bloodline_energy_current || 0;
                const blMax = b.bloodline_energy_max || 250;
                const blPct = Math.min(100, Math.max(0, (blCur / blMax) * 100));

                // --- 2. XỬ LÝ HUYẾT MẠCH (TAB ĐÓNG MỞ) ---
                let blHtml = '';
                if(bl.name && bl.name !== 'Không có') {
                    blHtml = `<details style="margin-top:10px; border-color:rgba(192,57,43,0.3)">
                        <summary style="color:var(--qual-kim)">🩸 Huyết Mạch: ${bl.name}</summary>
                        <div class="desc-no-indent" style="border-left:2px solid var(--rank-s)">${(bl.description_lore||'').trim().replace(/\\n/g, '<br>')}</div>
                    </details>`;
                }

                // --- 3. XỬ LÝ KỸ NĂNG ---
                const allSkills = [].concat(b.innate_skills||[], b.beast_skills||[]);
                let skillSection = '';
                if(allSkills.length > 0) {
                    const skillsCards = allSkills.map(s => {
                        let rColor = 'var(--border-color)';
                        if(s.rank_quality === 'Ngân Giai') rColor = 'var(--rank-a)';
                        if(s.rank_quality === 'Kim Giai') rColor = 'var(--rank-s)';

                        let metaParts = [];
                        if(s.cost && s.cost.value > 0) {
                            let cType = s.cost.type || '';
                            let cColor = (cType === 'HP' || cType === 'Sinh Lực') ? '#e74c3c' : 'var(--accent-blue)';
                            metaParts.push(`<span style="color:${cColor}">⚡ ${s.cost.value} ${cType}</span>`);
                        }

                        let cdVal = s.cooldown?.value || 0;
                        if(cdVal > 0) metaParts.push(`<span style="color:#e67e22">⏳ ${cdVal}${s.cooldown?.unit || 's'}</span>`);
                        else metaParts.push(`<span style="color:#7f8c8d">⏳ 0s</span>`);

                        let castVal = s.cast_time?.value || 0;
                        if(castVal > 0) metaParts.push(`<span style="color:#9b59b6">⏱️ ${castVal}${s.cast_time?.unit || 's'}</span>`);
                        else metaParts.push(`<span style="color:#2ecc71">⏱️ Tức thì</span>`);

                        let metaHtml = metaParts.join('<span style="opacity:0.3; margin:0 8px">|</span>');
                        let tags = (s.elements||[]).map(e => `<span class="skill-badge" style="border:1px solid rgba(255,255,255,0.2)">${e}</span>`).join('');
                        if(s.range_type) tags += `<span class="skill-badge" style="background:rgba(255,255,255,0.1)">${s.range_type}</span>`;

                        return `
                        <div class="skill-card-item" style="border-left-color:${rColor}">
                            <div class="skill-card-header" style="margin-bottom:2px;">
                                <span class="skill-name-text" style="${s.rank_quality==='Kim Giai'?'color:var(--rank-s)':(s.rank_quality==='Ngân Giai'?'color:var(--rank-a)':'color:var(--text-main)')}">${s.name}</span>
                            </div>
                            <div class="skill-meta-row">${metaHtml}</div>
                            <div style="margin-bottom:6px; display:flex; gap:5px; flex-wrap:wrap;">${tags}</div>
                            <div class="skill-desc-compact">${(s.description||s.desc||'').trim().replace(/\\n/g, '<br>')}</div>
                        </div>`;
                    }).join('');

                    skillSection = `<details class="skill-collapse" open><summary class="skill-header-styled"><span>✦ Hồ Sơ Kỹ Năng (${allSkills.length})</span></summary><div class="skill-grid-compact">${skillsCards}</div></details>`;
                } else {
                    skillSection = `<div style="text-align:center; padding:20px; color:#777; font-style:italic; border-top:1px dashed #444; margin-top:15px;">Sinh vật này chưa học kỹ năng nào.</div>`;
                }

                // Gen & Các biến phụ
                const domGenes = (gen.dominant_genes || []).join(', ') || 'Không';
                const statusList = b.active_buffs_debuffs || b.status_effects || [];

                return `
                <div class="beast-card-v2">
                    <div class="bc-header">
                        <div>
                            <div class="bc-name">${b.name} <span class="bc-species">(${b.species_name})</span></div>
                            <div style="margin-top:6px; margin-bottom:4px;">${bTagsHtml}</div>

                            <div style="font-size:0.75em; color:var(--text-muted); margin-top:4px;">
                                ${b.personality || 'Tính cách ẩn'} <span style="opacity:0.3">|</span> ${b.gender || '?'} <span style="opacity:0.3">|</span> Tuổi: ${b.age || 1}
                            </div>
                        </div>
                        <div class="bc-rank">${b.rank_tier}</div>
                    </div>

                    <div style="display:grid; grid-template-columns: 1fr 1fr; gap:15px; margin-bottom:15px;">
                        <div>
                            <div class="bc-hp-label"><span>Sinh Lực (HP)</span> <span style="font-family:'JetBrains Mono'">${Math.round(hpCur)}/${hpMax}</span></div>
                            <div class="progress-track-bar" style="margin-bottom:8px;"><div class="progress-fill-bar" style="background:var(--c-hp); width:${hpPct}%"></div></div>
                            <div class="bc-hp-label"><span style="color:var(--c-mp)">Năng Lượng (MP)</span> <span style="font-family:'JetBrains Mono'">${Math.round(mpCur)}/${mpMax}</span></div>
                            <div class="progress-track-bar"><div class="progress-fill-bar" style="background:var(--c-mp); width:${mpPct}%"></div></div>
                        </div>
                        <div>
                            <div class="bc-hp-label"><span style="color:var(--rank-s)">Tiến Hóa (Evo)</span> <span style="font-family:'JetBrains Mono'">${Math.round(blCur)}/${blMax}</span></div>
                            <div class="progress-track-bar" style="border-color:rgba(192,57,43,0.5)"><div class="progress-fill-bar" style="background:var(--rank-s); width:${blPct}%"></div></div>

                            <div style="margin-top:12px; font-size:0.8em; color:var(--text-dim); min-height:20px;">
                                ${statusList.length ? `🔔 <b>Trạng thái:</b> ${statusList.join(', ')}` : '<i style="opacity:0.5">Trạng thái cơ thể ổn định.</i>'}
                            </div>
                        </div>
                    </div>

                    <div style="display:grid; grid-template-columns: 1fr 1fr 1fr; gap:5px; margin-bottom:15px; background:rgba(0,0,0,0.2); padding:8px; border-radius:6px; border:1px solid rgba(255,255,255,0.05);">
                        <div style="text-align:center;">
                            <div style="font-size:0.7em; color:#aaa; text-transform:uppercase; margin-bottom:2px;">Trung Thành</div>
                            <div style="font-size:1.1em; font-weight:bold; color:${(b.loyalty||50)<40 ? '#e74c3c' : '#f1c40f'}">🛡️ ${b.loyalty||50}</div>
                        </div>
                        <div style="text-align:center; border-left:1px solid rgba(255,255,255,0.1); border-right:1px solid rgba(255,255,255,0.1);">
                            <div style="font-size:0.7em; color:#aaa; text-transform:uppercase; margin-bottom:2px;">Hảo Cảm</div>
                            <div style="font-size:1.1em; font-weight:bold; color:#e91e63;">❤️ ${b.intimacy||0}</div>
                        </div>
                        <div style="text-align:center;">
                            <div style="font-size:0.7em; color:#aaa; text-transform:uppercase; margin-bottom:2px;">Độ Đói</div>
                            <div style="font-size:1.1em; font-weight:bold; color:${(b.hunger||0)>80 ? '#e74c3c' : '#2ecc71'}">🍖 ${b.hunger||0}/100</div>
                        </div>
                    </div>

                    <div class="bc-stats-grid">
                        <div class="bc-stat-box"><div class="bc-stat-label">Cấp Độ</div><div class="bc-stat-value">Lv.${b.level || 1}</div></div>
                        <div class="bc-stat-box"><div class="bc-stat-label">Tiềm Năng</div><div class="bc-stat-value" style="color:var(--qual-than);">${b.potential_grade || 'F'}</div></div>
                        <div class="bc-stat-box"><div class="bc-stat-label">Căn Cơ (CCI)</div><div class="bc-stat-value" style="color:var(--theme-gold);">${(b.foundation_index || 1.0).toFixed(1)}</div></div>
                        <div class="bc-stat-box stat-orb" data-tooltip="Thể Lực: ${Math.round(staCur)} / ${Math.round(staMax)}" style="display:block;">
                            <div class="bc-stat-label">Thể Lực</div>
                            <div class="bc-stat-value" style="color:#2ecc71;">${Math.round(staPct)}%</div>
                        </div>
                    </div>

                    ${renderStatGrid(bst, false)}

                    <div style="background:rgba(0,0,0,0.3); padding:10px; border-radius:6px; margin-top:15px; border:1px solid rgba(255,255,255,0.05)">
                        <div style="color:var(--accent-warm); font-weight:700; font-size:0.85em; margin-bottom:5px; text-transform:uppercase;">🧬 Phân Tích Gen</div>
                        <div style="font-size:0.85em; color:#bbb;">Ổn định: <b style="color:${gen.genetic_stability<50?'#e74c3c':'#2ecc71'}">${gen.genetic_stability||100}%</b> | Trội: ${domGenes}</div>
                        ${blHtml}
                    </div>

                    ${skillSection}
                </div>`;
            }).join('');
        }
        renderWithState('beast-list-container', beastHtml);

        // TAB 5: INVENTORY (ĐÃ FIX KEY ARTIFACT & MỞ RỘNG TỪ KHÓA)
        $('#ui-inv-slots').text(`${inv.used_slots || (inv.items||[]).length || 0} / ${inv.max_slots || 100}`);
        $('#ui-inv-weight').text(`${inv.current_weight || 0.0} / ${inv.weight_limit || 50.0}`);

        // GIỮ NGUYÊN HÀM RENDER HTML (Giữ màu viền, phẩm chất, thiết kế thẻ)
        const renderI = (id, list) => {
            if(!list || !list.length) return $(`#${id}`).html('<div style="opacity:0.4; padding:20px; text-align:center; font-style:italic;">Khoang chứa trống không...</div>');

            $(`#${id}`).html(list.map(i => {
                // Phân tích màu viền trái dựa trên phẩm chất
                let rColor = 'var(--qual-pham)';
                const q = (i.rank_quality || i.rank || '').toLowerCase();
                if (q.includes('thần') || q.includes('ex')) rColor = 'var(--qual-than)';
                else if (q.includes('thánh')) rColor = 'var(--qual-thanh)'; 
                else if (q.includes('diệu')) rColor = 'var(--qual-dieu)';
                else if (q.includes('kim')) rColor = 'var(--qual-kim)';
                else if (q.includes('ngân')) rColor = 'var(--qual-ngan)';
                else if (q.includes('thiết')) rColor = 'var(--qual-thiet)';
                else if (q.includes('huyền')) rColor = 'var(--qual-huyen)';

                // Ép chuỗi và xóa khoảng cách đầu dòng (trim) để fix lỗi thụt lề
                const descStr = String(i.description || i.desc || 'Không có mô tả chi tiết.').trim().replace(/\\n/g, '<br>');

                return `
                <details class="inv-card-item" style="border-left-color: ${rColor}">
                    <summary class="inv-card-summary">
                        <span class="${getRankColor(i.rank_quality || i.rank)}" style="font-weight:700; font-size:1.05em; text-shadow: 0 0 10px rgba(0,0,0,0.5);">${i.name}</span>
                        <span class="qty-badge">x${i.quantity||1}</span>
                    </summary>
                    <div class="inv-card-content">
                        <div class="inv-meta-row">
                            <span>Loại: <span class="inv-meta-item">${i.type || 'Vật phẩm'}</span></span>
                            <span style="opacity:0.3;">|</span>
                            <span>Slot: <span class="inv-meta-item">${i.slot || i.slot_type || 'N/A'}</span></span>
                        </div>
                        <div class="inv-desc">${descStr}</div>
                        ${i.mods ? `<div style="margin-top:10px; color:var(--accent-warm); font-size:0.85em; background:rgba(255,255,255,0.05); padding:6px 10px; border-radius:4px; border-left:2px solid var(--accent-warm);">${JSON.stringify(i.mods).replace(/"/g,'').replace(/{|}/g,'')}</div>` : ''}
                    </div>
                </details>`;
            }).join(''));
        };

        const allItems = inv.items || [];

        // SỬ DỤNG .includes() LÀM TRUNG TÂM PHÂN LOẠI
        const mats = allItems.filter(i => {
            const t = String(i.type || '').toLowerCase();
            return t.includes('material') || t.includes('vật liệu') || t.includes('nguyên liệu') || t.includes('tài nguyên');
        });

        const cons = allItems.filter(i => {
            const t = String(i.type || '').toLowerCase();
            return t.includes('consumable') || t.includes('tiêu hao') || t.includes('thuốc') || t.includes('food') || t.includes('thực phẩm') || t.includes('thức ăn') || t.includes('đan dược') || t.includes('linh dược');
        });

        const keysAndArts = allItems.filter(i => {
            const t = String(i.type || '').toLowerCase();
            return t.includes('key') || t.includes('nhiệm vụ') || t.includes('artifact') || t.includes('cổ vật') || t.includes('đạo cụ') || t.includes('tool') || t.includes('pháp bảo');
        });

        const gearInBag = allItems.filter(i => {
            const t = String(i.type || '').toLowerCase();
            return t.includes('vũ khí') || t.includes('giáp') || t.includes('trang bị') || t.includes('phụ kiện') || t.includes('weapon') || t.includes('armor') || t.includes('accessory') || t.includes('trang phục');
        });

        const skillsInBag = allItems.filter(i => {
            const t = String(i.type || '').toLowerCase();
            return t.includes('công pháp') || t.includes('bí kíp') || t.includes('bộ bài') || t.includes('niêm phong') || t.includes('skill');
        });

        // Xử lý đồ rác/lạ (những thứ không lọt vào các mảng trên)
        const classifiedItems = [...mats, ...cons, ...keysAndArts, ...gearInBag, ...skillsInBag];
        allItems.forEach(i => {
            if (!classifiedItems.includes(i)) {
                mats.push(i); // Ném tạm vào ngăn nguyên liệu để không bị mất đồ
            }
        });

        // RENDER RA CÁC ID CỦA HTML
        renderI('container-inv-mats', mats);
        renderI('container-inv-cons', cons);

        renderI('container-inv-keys', keysAndArts);
        if (keysAndArts.length > 0) $('#container-inv-keys').prev('h4').text('Vật Phẩm Nhiệm Vụ & Cổ Vật (Artifacts)');

        if (gearInBag.length > 0) {
             renderI('container-inv-cards', gearInBag);
             $('#container-inv-cards').prev('h4').text('Trang Bị, Vũ Khí & Phụ Kiện');
        } else {
             renderI('container-inv-cards', []);
        }

        // Tự động render cho ngăn Công Pháp (Nếu HTML của bạn có ID này)
        if ($('#container-inv-skills').length) {
             renderI('container-inv-skills', skillsInBag);
        }

        // TAB 6: QUESTS
        const mQuest = typeof quest.main_quest === 'object' ? quest.main_quest.name : quest.main_quest;
        $('#q-main').html(mQuest || 'Hệ thống chưa ghi nhận chỉ lệnh lõi nào.');

        const sideQs = quest.side_quests || quest.active_quests || [];
        if (sideQs.length) {
            $('#q-side').html(sideQs.map(q => {
                const name = typeof q === 'object' ? q.title || q.name : q;
                const prog = typeof q === 'object' && q.progress ? ` <span style="font-size:0.85em; color:var(--theme-gold); font-family:'JetBrains Mono';">[${q.progress}]</span>` : '';
                const desc = typeof q === 'object' && q.description ? `<div style="font-size:0.85em; color:var(--text-muted); margin-top:4px;">${q.description}</div>` : '';
                return `<li style="margin-bottom:12px; padding-bottom:8px; border-bottom:1px dashed rgba(255,255,255,0.05);"><b style="color:var(--text-main); font-size:1.05em;">${name}</b>${prog}${desc}</li>`;
            }).join(''));
        } else {
            $('#q-side').html('<li style="font-style:italic; opacity:0.6;">Không có nhiệm vụ phụ tuyến. Tự do sinh tồn.</li>');
        }

        const renderRel = (id, list, scoreKey, reverseColor = false) => {
            if (!list || !list.length) return $(`#${id}`).html('<div style="opacity:0.4; font-style:italic; padding:10px 15px; border:1px dashed #444; border-radius:6px; margin-bottom:15px;">Chưa thiết lập liên kết nhân quả nào.</div>');
            $(`#${id}`).html(list.map(r => {
                const name = r.name || r.faction_name || r.character || 'Ẩn danh';
                const score = r[scoreKey] || r.score || r.affinity || r.aggro_level || 0;
                let color = 'var(--text-main)';
                if (!reverseColor) {
                    if (score > 50) color = 'var(--rank-c)'; 
                    if (score < 0) color = 'var(--rank-s)';  
                } else {
                    color = 'var(--rank-s)'; 
                }
                const desc = r.affinity_level_description ? `<div style="font-size:0.7em; color:#888; text-transform:uppercase;">${r.affinity_level_description}</div>` : '';
                return `
                <div style="display:flex; justify-content:space-between; align-items:center; border-bottom:1px dashed #333; padding:8px 12px; background:rgba(255,255,255,0.02); margin-bottom:4px; border-radius:6px; transition:background 0.2s;">
                    <div><div style="font-weight:700; color:var(--text-main);">${name}</div>${desc}</div>
                    <b style="color:${color}; font-family:'JetBrains Mono'; font-size:1.2em;">${score}</b>
                </div>`;
            }).join(''));
        };

        renderRel('rel-team', rel.teammates, 'affinity');
        renderRel('rel-fac', rel.factions, 'reputation_score');
        renderRel('rel-npc', rel.npcs, 'affinity');
        renderRel('rel-enemies', rel.enemy_list, 'aggro_level', true);

        const alerts = system.alert_log || [];
        if (alerts.length) $('#ui-alert').text(alerts[alerts.length - 1]);
    } 

    $(document).ready(() => {
        renderPanel();
    });

    window.switchTab = function(evt, tabName) {
        $('.tab-content').addClass("hidden");
        $('.tab-btn').removeClass("active");
        $(`#tab-${tabName}`).removeClass("hidden");
        $(evt.currentTarget).addClass("active");
    }
</script>
</body>
</html>
