    .terminal-container::before,.terminal-container::after,.terminal-container > .corner-bottom-left::before,.terminal-container > .corner-bottom-right::after{content:'';position:absolute;width:20px;height:20px;border-color:var(--accent-color);border-style:solid}
    .terminal-container::before{top:-2px;left:-2px;border-width:2px 0 0 2px; border-radius: 12px 0 0 0;}
    .terminal-container::after{top:-2px;right:-2px;border-width:2px 2px 0 0; border-radius: 0 12px 0 0;}
    .terminal-container > .corner-bottom-left::before{bottom:-2px;left:-2px;border-width:0 0 2px 2px; border-radius: 0 0 0 12px;}
