import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// [FIX 1] Khai báo biến z an toàn để tương thích với môi trường SillyTavern / trình duyệt
const z = window.z || window.Zod?.z;

// =============================================================================
// 1. HELPER: CÔNG CỤ XỬ LÝ DỮ LIỆU CỐT LÕI (PREPROCESSORS)
// =============================================================================

/**
 * Helper xử lý kiểu Number (Số học).
 * Ngăn chặn tuyệt đối các lỗi Crash hệ thống do nhận vào giá trị null, undefined, 
 * hoặc chuỗi rỗng từ file HTML. Trả về 0 trong mọi trường hợp lỗi để bảo toàn dữ liệu.
 */
const zNum = z.preprocess((val) => {
  if (val === null || val === undefined || val === '') return 0;
  const n = parseFloat(val);
  return isNaN(n) ? 0 : n;
}, z.number().default(0));

/**
 * Helper xử lý kiểu String (Chuỗi văn bản).
 * Tự động chuyển đổi các Mảng (Array) hoặc Đối tượng (Object) bị nhầm lẫn định dạng 
 * thành chuỗi JSON tiêu chuẩn. Rất hữu ích khi xử lý dữ liệu Lore khổng lồ.
 */
const zStr = z.preprocess((val) => {
  if (Array.isArray(val)) return val.join(", ");
  if (typeof val === 'object' && val !== null) return JSON.stringify(val);
  return val == null ? "" : String(val);
}, z.string().default(''));

/**
 * Helper xử lý kiểu Boolean (Đúng/Sai).
 * Quy chuẩn hóa mọi giá trị truthy/falsy về chuẩn boolean mặc định.
 */
const zBool = z.preprocess((val) => {
    return Boolean(val);
}, z.boolean().default(false));

/**
 * Helper xử lý kiểu Mảng (Array) mặc định.
 * Đảm bảo mọi mảng danh sách (túi đồ, kỹ năng, hiệu ứng) luôn khởi tạo là rỗng 
 * thay vì undefined để tránh lỗi vòng lặp map/forEach trong UI.
 */
const zArr = z.array(z.any()).default([]);

// =============================================================================
// 2. SCHEMA DEFINITIONS (KHUÔN MẪU DỮ LIỆU DÙNG CHUNG - SUB-SCHEMAS)
// =============================================================================

/**
 * --- Cấu trúc: Thời Gian & Cooldown (Advanced Time Logic) ---
 * Quản lý hệ thống thời gian đa chiều. Hỗ trợ đơn vị từ Giây cho đến Năm.
 * Quyết định trực tiếp đến cơ chế Casting (Niệm chú) trong chiến đấu.
 */
const TimeValueSchema = z.object({
    value: zNum.default(0), // Giá trị thời gian
    unit: zStr.default("Lượt"), // Các đơn vị hợp lệ: Giây, Phút, Giờ, Ngày, Năm, Lượt
    display_text: zStr.default(""), // Text hiển thị UI
    is_instant: zBool.default(false) // Nếu False và Value > 0 -> Áp dụng trạng thái Channelling (Niệm chú). Có thể bị Interrupt.
}).passthrough().default({});

/**
 * --- Cấu trúc: Kỹ Năng (Skill Structure v2 - Combat Mechanics) ---
 * Khuôn mẫu cho mọi kỹ năng của Ký chủ, Sủng thú, NPC, và Dị thú hoang dã.
 */
const SkillStructure = z.object({
    uid: zStr, // Định danh duy nhất để code dễ xử lý (vd: skill_fireball_01)
    name: zStr, // Tên kỹ năng hiển thị
    rank_quality: zStr.default("Phàm Giai"), // Thang bậc: Phàm, Thiết, Ngân, Vàng, Kim Cương, Thần...
    description: zStr, // Mô tả chi tiết. Tự động được định dạng ngắt dòng \n\n qua hàm autoFormat.

    // Tiêu hao đa dạng: Cơ chế sinh tồn cốt lõi. Không chỉ MP, một kỹ năng tà ác có thể tiêu hao Sanity (Tỉnh táo) 
    // hoặc HP (Sinh mệnh), thậm chí Hunger (Độ đói khát).
    cost: z.object({
        type: zStr.default("MP"), 
        value: zNum.default(0)
    }).passthrough().default({}),

    cooldown: TimeValueSchema, // Thời gian phải chờ sau khi thi triển xong
    cast_time: TimeValueSchema, // Thời gian phải đứng niệm chú. Nếu bị tấn công mạnh trong lúc này -> Ngắt chiêu, mất cost.

    elements: z.array(zStr).default([]), // Đa hệ nguyên tố: ["Hỏa", "Không Gian"]
    range_type: zStr.default("Cận chiến"), // Tầm đánh: Melee, Ranged, AOE, Aura
    interruptible: zBool.default(true), // Kỹ năng bá đạo (Bá Thể) có thể set thành false để không bị ngắt
    combo_tag: zStr.default(""), // Tag chuỗi chiêu thức. VD: Mục tiêu có tag "Wet" dính chiêu tag "Lightning" -> x2 Damage
    mastery_level: zNum.default(1) // Độ thông thạo kỹ năng. Dùng càng nhiều càng mạnh.
}).passthrough();

/**
 * --- Cấu trúc: Vật Phẩm & Trang Bị (Item Structure v2 - UI & Inventory Ready) ---
 * Cơ sở dữ liệu cho mọi thực thể tồn tại dưới dạng vật chất trong game.
 */
const ItemSchema = z.object({
    uid: zStr, // Định danh duy nhất. Bắt buộc để thực hiện các hàm Equip/Unequip/Drop/Sell
    name: zStr, // Tên vật phẩm
    description: zStr, // Lore hoặc hướng dẫn sử dụng vật phẩm
    type: zStr.default("Material"), // Phân loại: Weapon, Armor, Consumable, Core, Artifact, Blueprint...

    // Logic Trang bị (Gear System)
    slot_type: zStr.default("none"), // Vị trí đeo: head, body, legs, weapon_main, sub_weapon, beast_claw, core...
    is_equipped: zBool.default(false), // True: Đang mặc trên người. False: Nằm trong túi đồ.

    rank_quality: zStr.default("Phàm Giai"), // Độ hiếm của trang bị
    durability_current: zNum.default(100), // Độ bền hiện tại. Bị trừ đi khi chịu sát thương vật lý mạnh
    durability_max: zNum.default(100),     // Giới hạn độ bền. Khi current = 0 -> Trang bị vỡ nát, mất toàn bộ Stats Bonus.

    // Bảng chỉ số cộng thêm. Thiết kế dạng Object tĩnh để Engine dễ dàng cộng dồn (Math sum) vào Base Stats.
    stats_modifiers: z.object({
        STR: zNum.default(0),
        AGI: zNum.default(0),
        INT: zNum.default(0),
        DEF: zNum.default(0),
        HP: zNum.default(0),
        MP: zNum.default(0)
    }).passthrough().default({}),

    // Điều kiện tiên quyết. Ký chủ không thể mặc đồ của Thú và ngược lại. Khắc hệ cũng không được mặc.
    requirements: z.object({
        min_level: zNum.default(0),
        allowed_species: zArr, // Mảng loài được dùng (VD: ["Rồng", "Ác Quỷ"])
        allowed_elements: zArr // Mảng hệ tương thích
    }).passthrough().default({}),

    quantity: zNum.default(1) // Tính năng cộng dồn đồ đạc (Stack) để tiết kiệm max_slots của túi.
}).passthrough();

/**
 * --- Cấu trúc: Hệ Thuộc Tính Tinh Thần & Nguyên Tố (Elemental Affinity v2) ---
 * Quy định sự tương sinh tương khắc vạn vật.
 */
const ElementalSystem = z.object({
    base_elements: z.array(z.object({
        type: zStr, // Thuộc tính gốc: Hỏa, Thủy, Lôi, Ánh Sáng, Sinh Mệnh, Vong Linh...
        description: zStr,
        dominance: zNum.default(100) // Độ thuần khiết/Ưu thế của gen nguyên tố. Quyết định sức mạnh kỹ năng cùng hệ.
    }).passthrough()).default([]),

    // Hệ tổ hợp (Combined Effect): Sự dung hợp của 2 nguyên tố trở lên sinh ra biến dị.
    combined_effect: z.object({ 
        name: zStr.default(""), // VD: Hỏa + Thủy = Hơi Nước Bộc Phá, Hỏa + Thổ = Dung Nham
        description: zStr.default(""),
        stability: zNum.default(100) // Nếu độ ổn định thấp, tổ hợp có thể phản phệ gây sát thương cho người dùng.
    }).passthrough().default({}),

    weaknesses: zArr // Danh sách các nguyên tố khắc chế. Khi dính sát thương khắc chế -> x1.5 hoặc x2 Damage.
}).passthrough().default({});

