/**
 * --- [MỚI] Cấu trúc: Huyết Mạch (Bloodline Info) ---
 * Hỗ trợ khả năng lưu trữ hàng ngàn biến thể Huyết mạch Siêu Cấp.
 * Nếu chỉ số > 1000, hệ thống UI sẽ tự động kích hoạt [Đạo Luật Phong Ấn Thiên Đạo].
 */
const BloodlineSchema = z.object({
    name: zStr, // Tên huyết mạch (VD: Hỗn Độn Ma Long, Cửu Vĩ Thiên Hồ)
    description_lore: zStr, // Lưu trữ trọn vẹn: [Cơ chế Sinh học], [Hiệu ứng Thức tỉnh], [Tác dụng phụ].
    rank_quality: zStr,     // Kim Giai, Diệu Giai, Thần Thoại...

    // Quản lý khối lượng sức mạnh khổng lồ cộng thêm vào nhân vật.
    // Nếu chỉ số lớn bất thường (VD: 5000 HP), sẽ bị khóa 99% ở giai đoạn đầu game.
    stats_modifiers: z.object({
        STR: zNum.default(0), 
        AGI: zNum.default(0), 
        INT: zNum.default(0), 
        CON: zNum.default(0), 
        SPI: zNum.default(0),
        DEF: zNum.default(0), 
        BLD: zNum.default(0), 
        luck: zNum.default(0), 
        HP_max: zNum.default(0), 
        MP_max: zNum.default(0)
    }).passthrough().default({})
}).passthrough();

/**
 * --- [MỚI] Cấu trúc: Chủng Tộc (Species Info) ---
 * Định nghĩa chi tiết nguồn gốc và đặc điểm sinh học để AI tạo Roleplay chính xác.
 */
const SpeciesInfoSchema = z.object({
    name: zStr,             // Tên loài (VD: Sói Bạc, Rồng Đất Ngục Hỏa, Lục Tinh Bọ Ngựa)
    type_class: zStr,       // Phân loại chủng loài (VD: Lục Thú, Không Thú, Hải Thú, Thực Vật, Vong Linh)
    description_lore: zStr, // Cốt truyện, thói quen sinh hoạt, và khu vực phân bố.
    biological_features: zArr // Cực kỳ quan trọng: Quy định bản năng sinh tồn. VD: ["Dạ hành", "Ăn xác thối", "Phục kích"]
}).passthrough();

/**
 * --- [MỚI] Cấu trúc: Nghề Nghiệp / Thân Phận Khởi Đầu (Profession Info) ---
 * Lưu trữ bối cảnh quá khứ của Ký Chủ. Tạo xuất phát điểm đa dạng (Nghèo khó, Phế vật, Quý tộc...)
 */
const ProfessionInfoSchema = z.object({
    name: zStr, // VD: Kẻ Nhặt Rác Vùng Zero, Phế Nhân Trọng Sinh, Thiếu Gia Lạc Lối
    description_lore: zStr, // Kể lại nguyên nhân dẫn đến hoàn cảnh hiện tại.

    // Điểm cộng/trừ chỉ số khởi đầu đặc thù. 
    // VD: Kẻ nhặt rác có CON rất cao nhưng INT thấp. Quý tộc có INT cao, nhiều tiền nhưng thể chất (CON) yếu.
    stats_modifiers: z.object({
        STR: zNum.default(0), 
        AGI: zNum.default(0), 
        INT: zNum.default(0), 
        CON: zNum.default(0), 
        SPI: zNum.default(0),
        DEF: zNum.default(0), 
        BLD: zNum.default(0), 
        luck: zNum.default(0), 
        HP_max: zNum.default(0), 
        MP_max: zNum.default(0)
    }).passthrough().default({})
}).passthrough();

